window.HADITH_CACHE["bukhari_7"] = {"3501":{"ar":"حَدَّثَنَا إِسْحَاقُ بْنُ إِبْرَاهِيمَ الصَّوَّافُ حَدَّثَنَا يُوسُفُ بْنُ يَعْقُوبَ كَانَ يَنْزِلُ فِي بَنِي ضُبَيْعَةَ وَهُوَ مَوْلًى لِبَنِي سَدُوسَ حَدَّثَنَا سُلَيْمَانُ التَّيْمِيُّ عَنْ أَبِي مِجْلَزٍ عَنْ قَيْسِ بْنِ عُبَادٍ قَالَ قَالَ عَلِيٌّ رَضِيَ اللَّهُ عَنْهُفِينَا نَزَلَتْ هَذِهِ الْآيَةُ{ هَذَانِ خَصْمَانِ اخْتَصَمُوا فِي رَبِّهِمْ }","id":"Telah menceritakan kepada kami [Ishaq bin Ibrahim Ash Shawwaf] telah menceritakan kepada kami [Yusuf bin Ya'qub, dia pernah menetap tinggal di Bani Dlubai'ah, dia adalah maula Bani Sudus] telah menceritakan kepada kami [Sulaiman at-Taymiy] dari [Abu Mijlaz] dari [Qais bin 'Ubad] berkata, ['Ali] radliallahu 'anhu berkata; \"Ayat ini turun tentang kami, yaitu QS al-Hajj ayat 19. yang artinya; \"Inilah dua golongan (Mu'min dan kafir) yang bertengkar, mereka saling bertengkar mengenai Rabb mereka\"."},"3502":{"ar":"حَدَّثَنَا يَحْيَى بْنُ جَعْفَرٍ أَخْبَرَنَا وَكِيعٌ عَنْ سُفْيَانَ عَنْ أَبِي هَاشِمٍ عَنْ أَبِي مِجْلَزٍ عَنْ قَيْسِ بْنِ عُبَادٍ سَمِعْتُ أَبَا ذَرٍّ رَضِيَ اللَّهُ عَنْهُيُقْسِمُ لَنَزَلَتْ هَؤُلَاءِ الْآيَاتُ فِي هَؤُلَاءِ الرَّهْطِ السِّتَّةِ يَوْمَ بَدْرٍ نَحْوَهُ","id":"Telah menceritakan kepada kami [Yahya bin Ja'far] telah mengabarkan kepada kami [Waki'] dari [Sufyan] dari [Abu Hasyim] dari [Abu Mijlaz] dari [Qais bin 'Ubad] aku mendengar [Abu Dzarr] radliallahu 'anhu bersumpah; \"Sungguh ayat itu turun tentang enam orang itu pada perang Badar\". Atau semisalnya."},"3503":{"ar":"حَدَّثَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ الدَّوْرَقِيُّ حَدَّثَنَا هُشَيْمٌ أَخْبَرَنَا أَبُو هَاشِمٍ عَنْ أَبِي مِجْلَزٍ عَنْ قَيْسِ بْنِ عُبَادٍ قَالَ سَمِعْتُ أَبَا ذَرٍّيُقْسِمُ قَسَمًا إِنَّ هَذِهِ الْآيَةَ{ هَذَانِ خَصْمَانِ اخْتَصَمُوا فِي رَبِّهِمْ }نَزَلَتْ فِي الَّذِينَ بَرَزُوا يَوْمَ بَدْرٍ حَمْزَةَ وَعَلِيٍّ وَعُبَيْدَةَ بْنِ الْحَارِثِ وَعُتْبَةَ وَشَيْبَةَ ابْنَيْ رَبِيعَةَ وَالْوَلِيدِ بْنِ عُتْبَةَ","id":"Telah menceritakan kepada kami [Ya'qub bin Ibrahim ad-Dawraqiy] telah menceritakan kepada kami [Husyaim] telah mengabarkan kepada kami [Abu Hasyim] dari [Abu Mijlaz] dari [Qais bin 'Ubad] berkata, aku mendengar [Abu Dzarr] bersumpah dengan suatu sumpah yang isinya bahwa sesungguhnya ayat ini: \"Inilah dua golongan (Mu'min dan kafir) yang bertengkar, mereka saling bertengkar mengenai Rabb mereka\" (QS al-Hajj ayat 19) diturunkan untuk mereka yang melakukan perang tanding pada perang Badar. Mereka adalah Hamzah, Ali, 'Ubaidah bin Al Harits, 'Utbah dan Syaibah, dua putra Rabi'ah dan Al Walid bin 'Utbah\"."},"3504":{"ar":"حَدَّثَنِي أَحْمَدُ بْنُ سَعِيدٍ أَبُو عَبْدِ اللَّهِ حَدَّثَنَا إِسْحَاقُ بْنُ مَنْصُورٍ السَّلُولِيُّ حَدَّثَنَا إِبْرَاهِيمُ بْنُ يُوسُفَ عَنْ أَبِيهِ عَنْ أَبِي إِسْحَاقَ سَأَلَ رَجُلٌ الْبَرَاءَوَأَنَا أَسْمَعُ قَالَ أَشَهِدَ عَلِيٌّ بَدْرًا قَالَ بَارَزَ وَظَاهَرَ","id":"Telah menceritakan kepadaku [Ahmad bin Sa'id Abu 'Abdullah] telah menceritakan kepada kami [Ishaq bin Manshur As-Saluliy] telah menceritakan kepada kami [Ibrahim bin Yusuf] dari [bapaknya] dari [Abu Ishaq]; Ada seseorang yang bertanya kepada [Al Bara'] dan aku mendengarnya. Al Bara' berkata; \"Aku menyaksikan 'Ali pada perang Badar melakukan perang tanding dan dia menang\"."},"3505":{"ar":"حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ عَبْدِ اللَّهِ قَالَ حَدَّثَنِي يُوسُفُ بْنُ الْمَاجِشُونِ عَنْ صَالِحِ بْنِ إِبْرَاهِيمَ بْنِ عَبْدِ الرَّحْمَنِ بْنِ عَوْفٍ عَنْ أَبِيهِ عَنْ جَدِّهِ عَبْدِ الرَّحْمَنِ قَالَكَاتَبْتُ أُمَيَّةَ بْنَ خَلَفٍ فَلَمَّا كَانَ يَوْمَ بَدْرٍ فَذَكَرَ قَتْلَهُ وَقَتْلَ ابْنِهِ فَقَالَ بِلَالٌ لَا نَجَوْتُ إِنْ نَجَا أُمَيَّةُ","id":"Telah menceritakan kepada kami ['Abdul 'Aziz bin 'Abdullah] berkata, telah menceritakan kepadaku [Yusuf bin Al Majisyun] dari [Shalih bin Ibrahim bin 'Abdur Rahman bin 'Auf] dari [bapaknya] dari [kakeknya, 'Abdur Rahman] berkata; \"Aku menulis surat kepada Umayyah bin Khalaf (untuk saling melindungi). Ketika terjadi perang Badar, dia menyebutkan tentang akan terbunuhnya dirinya dan anaknya. Maka Bilal berkata; \"Aku tidak akan selamat seandainya Umayyah selamat\"."},"3506":{"ar":"حَدَّثَنِي عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ حَدَّثَنَا مُعَاوِيَةُ بْنُ عَمْرٍو حَدَّثَنَا أَبُو إِسْحَاقَ عَنْ حُمَيْدٍ قَالَ سَمِعْتُ أَنَسًا رَضِيَ اللَّهُ عَنْهُ يَقُولُأُصِيبَ حَارِثَةُ يَوْمَ بَدْرٍ وَهُوَ غُلَامٌ فَجَاءَتْ أُمُّهُ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ يَا رَسُولَ اللَّهِ قَدْ عَرَفْتَ مَنْزِلَةَ حَارِثَةَ مِنِّي فَإِنْ يَكُنْ فِي الْجَنَّةِ أَصْبِرْ وَأَحْتَسِبْ وَإِنْ تَكُ الْأُخْرَى تَرَى مَا أَصْنَعُ فَقَالَ وَيْحَكِ أَوَهَبِلْتِ أَوَجَنَّةٌ وَاحِدَةٌ هِيَ إِنَّهَا جِنَانٌ كَثِيرَةٌ وَإِنَّهُ فِي جَنَّةِ الْفِرْدَوْسِ","id":"Telah menceritakan kepadaku [Abdullah bin Muhammad] telah menceritakan kepada kami [Mu'awiyah bin 'Amru] telah menceritakan kepada kami [Abu Ishaq] dari [Humaid] berkata, aku mendengar [Anas] radliallahu 'anhu berkata; \"Pada perang Badar, Haritsah mendapat luka padahal dia masih kecil. Kemudian ibunya datang kepada Nabi shallallahu 'alaihi wasallam dan berkata; \"Wahai Rasulullah, anda mengetahui kedudukan Haritsah di sisiku. Seandainya dia berada di surga aku akan sabar dan berharap memperoleh pahala. Namun kalau keadaannya lain, anda akan lihat apa yang aku lakukan\". Maka beliau berkata: \"Janganlah begitu. Atau apakah kamu merasa berat ditinggal oleh anakmu atau kamu kira surga itu hanya satu? Sesungguhnya surga itu banyak dan anakmu sekarang berada di dalam surga Firdaus\"."},"3507":{"ar":"حَدَّثَنِي إِسْحَاقُ بْنُ إِبْرَاهِيمَ أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ إِدْرِيسَ قَالَ سَمِعْتُ حُصَيْنَ بْنَ عَبْدِ الرَّحْمَنِ عَنْ سَعْدِ بْنِ عُبَيْدَةَ عَنْ أَبِي عَبْدِ الرَّحْمَنِ السُّلَمِيِّ عَنْ عَلِيٍّ رَضِيَ اللَّهُ عَنْهُ قَالَبَعَثَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَبَا مَرْثَدٍ الْغَنَوِيَّ وَالزُّبَيْرَ بْنَ الْعَوَّامِ وَكُلُّنَا فَارِسٌ قَالَ انْطَلِقُوا حَتَّى تَأْتُوا رَوْضَةَ خَاخٍ فَإِنَّ بِهَا امْرَأَةً مِنْ الْمُشْرِكِينَ مَعَهَا كِتَابٌ مِنْ حَاطِبِ بْنِ أَبِي بَلْتَعَةَ إِلَى الْمُشْرِكِينَ فَأَدْرَكْنَاهَا تَسِيرُ عَلَى بَعِيرٍ لَهَا حَيْثُ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْنَا الْكِتَابُ فَقَالَتْ مَا مَعَنَا كِتَابٌ فَأَنَخْنَاهَا فَالْتَمَسْنَا فَلَمْ نَرَ كِتَابًا فَقُلْنَا مَا كَذَبَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَتُخْرِجِنَّ الْكِتَابَ أَوْ لَنُجَرِّدَنَّكِ فَلَمَّا رَأَتْ الْجِدَّ أَهْوَتْ إِلَى حُجْزَتِهَا وَهِيَ مُحْتَجِزَةٌ بِكِسَاءٍ فَأَخْرَجَتْهُ فَانْطَلَقْنَا بِهَا إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ عُمَرُ يَا رَسُولَ اللَّهِ قَدْ خَانَ اللَّهَ وَرَسُولَهُ وَالْمُؤْمِنِينَ فَدَعْنِي فَلِأَضْرِبَ عُنُقَهُ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا حَمَلَكَ عَلَى مَا صَنَعْتَ قَالَ حَاطِبٌ وَاللَّهِ مَا بِي أَنْ لَا أَكُونَ مُؤْمِنًا بِاللَّهِ وَرَسُولِهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَرَدْتُ أَنْ يَكُونَ لِي عِنْدَ الْقَوْمِ يَدٌ يَدْفَعُ اللَّهُ بِهَا عَنْ أَهْلِي وَمَالِي وَلَيْسَ أَحَدٌ مِنْ أَصْحَابِكَ إِلَّا لَهُ هُنَاكَ مِنْ عَشِيرَتِهِ مَنْ يَدْفَعُ اللَّهُ بِهِ عَنْ أَهْلِهِ وَمَالِهِ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَدَقَ وَلَا تَقُولُوا لَهُ إِلَّا خَيْرًا فَقَالَ عُمَرُ إِنَّهُ قَدْ خَانَ اللَّهَ وَرَسُولَهُ وَالْمُؤْمِنِينَ فَدَعْنِي فَلِأَضْرِبَ عُنُقَهُ فَقَالَ أَلَيْسَ مِنْ أَهْلِ بَدْرٍ فَقَالَ لَعَلَّ اللَّهَ اطَّلَعَ إِلَى أَهْلِ بَدْرٍ فَقَالَ اعْمَلُوا مَا شِئْتُمْ فَقَدْ وَجَبَتْ لَكُمْ الْجَنَّةُ أَوْ فَقَدْ غَفَرْتُ لَكُمْ فَدَمَعَتْ عَيْنَا عُمَرَ وَقَالَ اللَّهُ وَرَسُولُهُ أَعْلَمُ","id":"Telah menceritakan kepadaku [Ishaq bin Ibrahim] telah mengabarkan kepada kami [Abdullah bin Idris] berkata, aku mendengar [Hushain bin 'Abdur Rahman] dari [Sa'ad bin 'Ubadah] dari [Abu 'Abdur Rahman as-Sulamiy] dari ['Ali] radliallahu 'anhu berkata; Rasulullah shallallahu 'alaihi wasallam mengutus aku, Abu Martsad Al Ghanawiy dan Az Zubair bin Al 'Awwam, yang mana kami adalah penunggang kuda yang ulung. Beliau berkata: \"Berangkatlah kalian hingga sampai di sebuah taman yang bernama Khakh, disana ada seorang wanita dari kaum Musyrikin yang membawa sepucuk surat dari Hathib in Abi Balta'ah yang ditujukan untuk kaum Musyrikin\". Maka kami dapati wanita itu sedang berjalan dengan untanya persis seperti apa yang disampaikan Rasulullah shallallahu 'alaihi wasallam. Maka kami bertanya; \"Mana surat itu?\". Wanita itu menjawab; \"Tidak ada surat pada kami\". Maka kami memeriksanya, namun kami tidak melihat adanya sepucuk suratpun. Kami katakan; \"Tidak mungkin Rasulullah shallallahu 'alaihi wasallam berdusta. Kamu keluarkan surat itu atau kami akan menggeladah kamu\". Setelah wanita melihat kesungguhan kami, dia melirik pada kain ikat pinggangnya, yaitu yang ternyata surat itu disembunyikan dibalik kain ikat pinggangnya. Akhirnya dia mengeluarkan surat itu. Kemudian kami berangkat menemui Nabi shallallahu 'alaihi wasallam dengan membawa surat itu. Lalu 'Umar berkata; \"Wahai Rasulullah, dia telah berkhianat kepada Allah dan Rasul-Nya dan juga kaum m'uminin. Biarkan aku memenggal leher orang ini\". Kemudian beliau bertanya: \"Apa yang mendorongmu berbuat seperti?\". Hathib menjawab; \"Demi Allah, tidaklah aku bermaksud untuk tidak beriman kepada Allah dan Rasul-Nya. Maksudku, hanyalah agar aku memiliki penjamin di tengah kaum (musyrikin) yang dengannya Allah melindungi keluarga dan hartaku. Juga tidak ada satupun dari shahabat anda melainkan dia punya kerabat di sana yang dengannya Allah akan melindungi keluarga dan hartanya\". Maka Nabi shallallahu 'alaihi wasallam berkata: \"Dia benar. Dan janganlah kalian katakan padanya kecuali kebaikan\". Namun 'Umar tetap berkata; \"Dia telah berkhianat kepada Allah dan Rasul-Nya dan juga kaum m'uminin. Biarkan aku memenggal leher orang ini\"Maka beliau bersabda: \"Bukankan dia termasuk ahlu Badar. Dan Allah telah mendatangi Ahlu Badar dan berfirman: \"Silakan kalian berbuat apa yang kalian suka karena telah wajib bagi kalian untuk masuk ke dalam surga\" atau: \"Sungguh Aku telah mengampuni kalian\". Maka air mata 'Umar bercucuran lalu berkata; \"Allah dan Rasul-Nya lebih mengetahui\"."},"3508":{"ar":"بَاب حَدَّثَنِي عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ الْجُعْفِيُّ حَدَّثَنَا أَبُو أَحْمَدَ الزُّبَيْرِيُّ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ الْغَسِيلِ عَنْ حَمْزَةَ بْنِ أَبِي أُسَيْدٍ وَالزُّبَيْرِ بْنِ الْمُنْذِرِ بْنِ أَبِي أُسَيْدٍ عَنْ أَبِي أُسَيْدٍ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ لَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ بَدْرٍ إِذَا أَكْثَبُوكُمْ فَارْمُوهُمْ وَاسْتَبْقُوا نَبْلَكُمْ","id":"Bab. Telah menceritakan kepadaku [Abdullah bin Muhammad Al Ju'fiy] telah menceritakan kepada kami [Abu Ahmad Az Zubairiy] telah menceritakan kepada kami ['Abdur Rahman bin Al Ghasil] dari [Hamzah bin Abu Usaid] dan [Az Zubair bin Al Mundzir bin Abu Usaid] dari [Abu Usaid] radliallahu 'anhu berkata; \"Rasulullah shallallahu 'alaihi wasallam berkata kepada kami ketika perang Badar: \"Jika mereka telah mendekati kalian, lemparlah mereka dan tetap serang dengan anak panah kalian\"."},"3509":{"ar":"حَدَّثَنِي مُحَمَّدُ بْنُ عَبْدِ الرَّحِيمِ حَدَّثَنَا أَبُو أَحْمَدَ الزُّبَيْرِيُّ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ الْغَسِيلِ عَنْ حَمْزَةَ بْنِ أَبِي أُسَيْدٍ وَالْمُنْذِرِ بْنِ أَبِي أُسَيْدٍ عَنْ أَبِي أُسَيْدٍ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ لَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ بَدْرٍ إِذَا أَكْثَبُوكُمْ يَعْنِي كَثَرُوكُمْ فَارْمُوهُمْ وَاسْتَبْقُوا نَبْلَكُمْ","id":"Telah menceritakan kepadaku [Muhammad bin 'Abdur Rahim] telah menceritakan kepada kami [Abu Ahmad Az Zubairiy] telah menceritakan kepada kami ['Abdur Rahman bin Al Ghasil] dari [Hamzah bin Abu Usaid] dan [Al Mundzir bin Abu Usaid] dari [Abu Usaid] radliallahu 'anhu berkata; \"Rasulullah shallallahu 'alaihi wasallam berkata kepada kami ketika perang Badar: \"Jika mereka telah mendekati kalian, maksudnya lebih banyak dari jumlah kalian, panah dan terus serang dengan anak panah kalian\"."},"3510":{"ar":"حَدَّثَنِي عَمْرُو بْنُ خَالِدٍ حَدَّثَنَا زُهَيْرٌ حَدَّثَنَا أَبُو إِسْحَاقَ قَالَ سَمِعْتُ الْبَرَاءَ بْنَ عَازِبٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَجَعَلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى الرُّمَاةِ يَوْمَ أُحُدٍ عَبْدَ اللَّهِ بْنَ جُبَيْرٍ فَأَصَابُوا مِنَّا سَبْعِينَ وَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَصْحَابُهُ أَصَابُوا مِنْ الْمُشْرِكِينَ يَوْمَ بَدْرٍ أَرْبَعِينَ وَمِائَةً سَبْعِينَ أَسِيرًا وَسَبْعِينَ قَتِيلًا قَالَ أَبُو سُفْيَانَ يَوْمٌ بِيَوْمِ بَدْرٍ وَالْحَرْبُ سِجَالٌ","id":"Telah menceritakan kepadaku ['Amru bin Khalid] telah menceritakan kepada kami [Zuhair] telah menceritakan kepada kami [Abu Ishaq] berkata, aku mendengar [Al Bara' bin \"Azib RAa] berkata; \"Nabi shallallahu 'alaihi wasallam menjadikan Abdullah bin Jubair sebagai komandan pasukan pemanah pada perang Uhud. Kemudian sebanyak tujuh puluh orang dari kami terbunuh. Sedangkan pada perang Badar Nabi shallallahu 'alaihi wasallam dan para shahabat beliau menewaskan kaum Musyrikin sebanyak seratus empat puluh orang, tujuh puluh orang sebagai tawanan dan tujuh puluhnya lagi tewas. Lalu Abu Sufyan berkata; \"Hari ini sebagai balasan perang Badar, peperangan itu silih berganti\"."},"3511":{"ar":"حَدَّثَنِي مُحَمَّدُ بْنُ الْعَلَاءِ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ بُرَيْدٍ عَنْ جَدِّهِ أَبِي بُرْدَةَ عَنْ أَبِي مُوسَى أُرَاهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ وَإِذَا الْخَيْرُ مَا جَاءَ اللَّهُ بِهِ مِنْ الْخَيْرِ بَعْدُ وَثَوَابُ الصِّدْقِ الَّذِي آتَانَا بَعْدَ يَوْمِ بَدْرٍ","id":"Telah menceritakan kepadaku [Muhammad bin Al 'Alaa'] telah menceritakan kepada kami [Abu Usamah] dari [Buraid] dari [kakeknya. Abu Burdah] dari [Abu Musa] dia menganggapnya dari Nabi shallallahu 'alaihi wasallam yang (setelah menceritakan mimpi beliau) beliau bersabda: \"Ternyata itu berarti Kaum Mu'minin pada perang Uhud yang akan mendapatkan kebaikan seperti yang Allah datangkan berupa kebaikan dan pahala, sebagai janji yang benar, yang telah Allah berikan kepada kita pada perang Badar\"."},"3512":{"ar":"حَدَّثَنِي يَعْقُوبُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا إِبْرَاهِيمُ بْنُ سَعْدٍ عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَ قَالَ عَبْدُ الرَّحْمَنِ بْنُ عَوْفٍإِنِّي لَفِي الصَّفِّ يَوْمَ بَدْرٍ إِذْ الْتَفَتُّ فَإِذَا عَنْ يَمِينِي وَعَنْ يَسَارِي فَتَيَانِ حَدِيثَا السِّنِّ فَكَأَنِّي لَمْ آمَنْ بِمَكَانِهِمَا إِذْ قَالَ لِي أَحَدُهُمَا سِرًّا مِنْ صَاحِبِهِ يَا عَمِّ أَرِنِي أَبَا جَهْلٍ فَقُلْتُ يَا ابْنَ أَخِي وَمَا تَصْنَعُ بِهِ قَالَ عَاهَدْتُ اللَّهَ إِنْ رَأَيْتُهُ أَنْ أَقْتُلَهُ أَوْ أَمُوتَ دُونَهُ فَقَالَ لِي الْآخَرُ سِرًّا مِنْ صَاحِبِهِ مِثْلَهُ قَالَ فَمَا سَرَّنِي أَنِّي بَيْنَ رَجُلَيْنِ مَكَانَهُمَا فَأَشَرْتُ لَهُمَا إِلَيْهِ فَشَدَّا عَلَيْهِ مِثْلَ الصَّقْرَيْنِ حَتَّى ضَرَبَاهُ وَهُمَا ابْنَا عَفْرَاءَ","id":"Telah menceritakan kepadaku [Ya'qub bin Ibrahim] telah menceritakan kepada kami [Ibrahim bin Sa'ad] dari [bapaknya] dari [kakeknya] berkata; ['Abdur Rahman bin 'Auf] berkata; \"Aku berada dalam barisan pasukan di perang Badar dan ketika aku menoleh ke samping kanan dan kiriku. Aku melihat dua anak laki-laki yang masih belia. Aku merasa tidak percaya dengan keberadaan keduanya ketika salah seorang dari keduanya berkata kepadaku secara pelan agar tidak didengar temannya; \"Wahai paman, tunjukkan kepadaku Abu Jahal\" Aku tanya; \"Wahai anak saudaraku, apa yang akan kamu lakukan terhadapnya?\"Dia menjawab; \"Aku telah berjanji kepada Allah. Jika aku melihatnya, aku akan membunuhnya\". Anak yang satu lagi juga mengatakan hal yang sama kepadaku secara pelan pula. 'Abdur Rahman bin 'Auf berkata; \"Keberadaan keduanya tersebut sangat membahagiakan aku, lalu aku menunjukkan Abu Jahal kepada keduanya. Kedua anak itu melesat bagaikan dua ekor burung elang kemudian membunuh Abu Jahal. Kedua anak belia tadi adalah dua putra 'Afra'."},"3513":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ حَدَّثَنَا إِبْرَاهِيمُ أَخْبَرَنَا ابْنُ شِهَابٍ قَالَ أَخْبَرَنِي عُمَرُ بْنُ أَسِيدِ بْنِ جَارِيَةَ الثَّقَفِيُّ حَلِيفُ بَنِي زُهْرَةَ وَكَانَ مِنْ أَصْحَابِ أَبِي هُرَيْرَةَ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَبَعَثَ رَسُولُ اللَّهِ صَلَّى اللَّهُ ع��لَيْهِ وَسَلَّمَ عَشَرَةً عَيْنًا وَأَمَّرَ عَلَيْهِمْ عَاصِمَ بْنَ ثَابِتٍ الْأَنْصَارِيَّ جَدَّ عَاصِمِ بْنِ عُمَرَ بْنِ الْخَطَّابِ حَتَّى إِذَا كَانُوا بِالْهَدَةِ بَيْنَ عَسْفَانَ وَمَكَّةَ ذُكِرُوا لِحَيٍّ مِنْ هُذَيْلٍ يُقَالُ لَهُمْ بَنُو لِحْيَانَ فَنَفَرُوا لَهُمْ بِقَرِيبٍ مِنْ مِائَةِ رَجُلٍ رَامٍ فَاقْتَصُّوا آثَارَهُمْ حَتَّى وَجَدُوا مَأْكَلَهُمْ التَّمْرَ فِي مَنْزِلٍ نَزَلُوهُ فَقَالُوا تَمْرُ يَثْرِبَ فَاتَّبَعُوا آثَارَهُمْ فَلَمَّا حَسَّ بِهِمْ عَاصِمٌ وَأَصْحَابُهُ لَجَئُوا إِلَى مَوْضِعٍ فَأَحَاطَ بِهِمْ الْقَوْمُ فَقَالُوا لَهُمْ انْزِلُوا فَأَعْطُوا بِأَيْدِيكُمْ وَلَكُمْ الْعَهْدُ وَالْمِيثَاقُ أَنْ لَا نَقْتُلَ مِنْكُمْ أَحَدًا فَقَالَ عَاصِمُ بْنُ ثَابِتٍ أَيُّهَا الْقَوْمُ أَمَّا أَنَا فَلَا أَنْزِلُ فِي ذِمَّةِ كَافِرٍ ثُمَّ قَالَ اللَّهُمَّ أَخْبِرْ عَنَّا نَبِيَّكَ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَرَمَوْهُمْ بِالنَّبْلِ فَقَتَلُوا عَاصِمًا وَنَزَلَ إِلَيْهِمْ ثَلَاثَةُ نَفَرٍ عَلَى الْعَهْدِ وَالْمِيثَاقِ مِنْهُمْ خُبَيْبٌ وَزَيْدُ بْنُ الدَّثِنَةِ وَرَجُلٌ آخَرُ فَلَمَّا اسْتَمْكَنُوا مِنْهُمْ أَطْلَقُوا أَوْتَارَ قِسِيِّهِمْ فَرَبَطُوهُمْ بِهَا قَالَ الرَّجُلُ الثَّالِثُ هَذَا أَوَّلُ الْغَدْرِ وَاللَّهِ لَا أَصْحَبُكُمْ إِنَّ لِي بِهَؤُلَاءِ أُسْوَةً يُرِيدُ الْقَتْلَى فَجَرَّرُوهُ وَعَالَجُوهُ فَأَبَى أَنْ يَصْحَبَهُمْ فَانْطُلِقَ بِخُبَيْبٍ وَزَيْدِ بْنِ الدَّثِنَةِ حَتَّى بَاعُوهُمَا بَعْدَ وَقْعَةِ بَدْرٍ فَابْتَاعَ بَنُو الْحَارِثِ بْنِ عَامِرِ بْنِ نَوْفَلٍ خُبَيْبًا وَكَانَ خُبَيْبٌ هُوَ قَتَلَ الْحَارِثَ بْنَ عَامِرٍ يَوْمَ بَدْرٍ فَلَبِثَ خُبَيْبٌ عِنْدَهُمْ أَسِيرًا حَتَّى أَجْمَعُوا قَتْلَهُ فَاسْتَعَارَ مِنْ بَعْضِ بَنَاتِ الْحَارِثِ مُوسًى يَسْتَحِدُّ بِهَا فَأَعَارَتْهُ فَدَرَجَ بُنَيٌّ لَهَا وَهِيَ غَافِلَةٌ حَتَّى أَتَاهُ فَوَجَدَتْهُ مُجْلِسَهُ عَلَى فَخِذِهِ وَالْمُوسَى بِيَدِهِ قَالَتْ فَفَزِعْتُ فَزْعَةً عَرَفَهَا خُبَيْبٌ فَقَالَ أَتَخْشَيْنَ أَنْ أَقْتُلَهُ مَا كُنْتُ لِأَفْعَلَ ذَلِكَ قَالَتْ وَاللَّهِ مَا رَأَيْتُ أَسِيرًا قَطُّ خَيْرًا مِنْ خُبَيْبٍ وَاللَّهِ لَقَدْ وَجَدْتُهُ يَوْمًا يَأْكُلُ قِطْفًا مِنْ عِنَبٍ فِي يَدِهِ وَإِنَّهُ لَمُوثَقٌ بِالْحَدِيدِ وَمَا بِمَكَّةَ مِنْ ثَمَرَةٍ وَكَانَتْ تَقُولُ إِنَّهُ لَرِزْقٌ رَزَقَهُ اللَّهُ خُبَيْبًا فَلَمَّا خَرَجُوا بِهِ مِنْ الْحَرَمِ لِيَقْتُلُوهُ فِي الْحِلِّ قَالَ لَهُمْ خُبَيْبٌ دَعُونِي أُصَلِّي رَكْعَتَيْنِ فَتَرَكُوهُ فَرَكَعَ رَكْعَتَيْنِ فَقَالَ وَاللَّهِ لَوْلَا أَنْ تَحْسِبُوا أَنَّ مَا بِي جَزَعٌ لَزِدْتُ ثُمَّ قَالَ اللَّهُمَّ أَحْصِهِمْ عَدَدًا وَاقْتُلْهُمْ بَدَدًا وَلَا تُبْقِ مِنْهُمْ أَحَدًا ثُمَّ أَنْشَأَ يَقُولُ فَلَسْتُ أُبَالِي حِينَ أُقْتَلُ مُسْلِمًاعَلَى أَيِّ جَنْبٍ كَانَ لِلَّهِ مَصْرَعِيوَذَلِكَ فِي ذَاتِ الْإِلَهِ وَإِنْ يَشَأْيُبَارِكْ عَلَى أَوْصَالِ شِلْوٍ مُمَزَّعِثُمَّ قَامَ إِلَيْهِ أَبُو سِرْوَعَةَ عُقْبَةُ بْنُ الْحَارِثِ فَقَتَلَهُ وَكَانَ خُبَيْبٌ هُوَ سَنَّ لِكُلِّ مُسْلِمٍ قُتِلَ صَبْرًا الصَّلَاةَ وَأَخْبَرَ أَصْحَابَهُ يَوْمَ أُصِيبُوا خَبَرَهُمْ وَبَعَثَ نَاسٌ مِنْ قُرَيْشٍ إِلَى عَاصِمِ بْنِ ثَابِتٍ حِينَ حُدِّثُوا أَنَّهُ قُتِلَ أَنْ يُؤْتَوْا بِشَيْءٍ مِنْهُ يُعْرَفُ وَكَانَ قَتَلَ رَجُلًا عَظِيمًا مِنْ عُظَمَائِهِمْ فَبَعَثَ اللَّهُ لِعَاصِمٍ مِثْلَ الظُّلَّةِ مِنْ الدَّبْرِ فَحَمَتْهُ مِنْ رُسُلِهِمْ فَلَمْ يَقْدِرُوا أَنْ يَقْطَعُوا مِنْهُ شَيْئًاوَقَالَ كَعْبُ بْنُ مَالِكٍ ذَكَرُوا مَرَارَةَ بْنَ الرَّبِيعِ الْعَمْرِيَّ وَهِلَالَ بْنَ أُمَيَّةَ الْوَاقِفِيَّ رَجُلَيْنِ صَالِحَيْنِ قَدْ شَهِدَا بَدْرًا","id":"Telah menceritakan kepada kami [Musa bin Isma'il] telah menceritakan kepada kami [Ibrahim] telah mengabarkan kepada kami [Ibnu Syihab] berkata, telah mengabarkan kepadaku ['Umar bin Asid bin Jariyah Ats-Tsaqafiy], orang yag membuat perjanjian dengan Bani Zuhrah dan dia termasuk shahabatnya Abu Hurairah radliallahu 'anhu, dari [Abu Hurairah radliallahu 'anhu] berkata; \"Rasulullah shallallahu 'alaihi wasallam mengutus sepuluh orang sebagai sariyah (pasukan) mata-mata dan beliau mengangkat 'Ashim bin Tsabit Al Anshariy, kakek 'Ashim bin 'Umar bin Al Khaththab sebagai pemimpin pasukan tersebut. (Mereka berangkat) hingga ketika sampai di al-Hada', suatu tempat antara 'Ashfan dan Makkah, keberadaan mereka diceritakan kepada penduduk dari suku Hudzail yang biasa disebut dengan Banu Lahyan. Maka suku tersebut mengerahkan hampir seratus orang yang kesemuanya pemanah yang ahli. Mereka mencari jejak keberadaan pasukan sariyah hingga dapat menemukan tempat makan kurma mereka dimana mereka singgah. Mereka berseru; \"Ini kurma Yatsrib\". Maka suku itu mengikuti jejak pasukan sariyah. Ketika 'Ashim dan pasukannya merasa ada kehadiran musuh, mereka bersembunyi di balik bukit kecil. Namun suku itu langsung mengepung mereka dan berseru kepada mereka; \"Turun dan serahkanlah kepada kami apa yang kalian miliki. Bagi kalian ada jaminan dan perjanjian. Kami tidak akan membunuh seorangpun dari kalian\". Maka 'Ashim bin Tsabit berkata: \"Aku, demi Allah, Aku tidak akan turun dengan jaminan orang kafir\". Lalu dia berdo'a: \"Ya Allah, beritahukanlah keadaan kami kepada Nabi-Mu shallallahu 'alaihi wasallam\". Maka suku itu menyerang mereka dengan anak panah hingga mereka dapat membunuh 'Ashim (beserta tujuh orang anak buahnya). Akhirnya tiga orang anggota sariyah yang masih hidup turun dengan menyetujui jaminan dan perjanjian. Diantara mereka ada Khubaib Al Anshariy dan Zaid bin ad-Datsinah serta seorang lagi. (Setelah ketiganya turun) mereka menangkapnya dan melepas tali busur panah mereka untuk mengikat ketiganya. Orang ketiga berkata: \"Ini merupakan awal pengkhianatan. Demi Allah, aku tidak akan mengikuti kalian. Sungguh mereka bagiku sebagai teladan\". Yang dia maksud adalah shahabat mereka yang sudah terbunuh. Mereka menyeretnya dan memaksanya agar mengikuti mereka namun dia menolaknya hingga akhirnya mereka membunuhnya. Kemudian mereka pergi dengan membawa Khubaib dan Zaid bin ad-Datsinah hingga akhirnya mereka menjual keduanya di Makkah sesudah perang Badar. Banu Al Harits bin 'Amir bin Nawfal bin 'Abdu Manaf membeli Khubaib. Sebelumnya Khubaib adalah orang yang telah membunuh Al Harits bin 'Amir saat perang Badar. Maka jadilah Khubaib di tangan mereka sebagai tawanan. Hingga akhirnya mereka sepakat akan membunuhnya. (Pada suatu hari dalam masa tahanannya), Khubaib meminjam kepada salah satu anak perempuan Al Harits sebilah pisau cukur untuk mencukur bulu kemaluannya maka anak perempuan itu meminjamkannya. (Kata Zainab); \"Kemudian Khubaib memangku anakku saat aku lengah ketika anakku menghampirinya. Hingga dia menemuinya dan dia dapatkannya sedang dipangku sementara pisau cukur berada di tangan Khubaib.\" (Zainab) berkata; \"Aku sangat terperanjat seketika itu dan Khubaib mengetahui hal itu\". Maka dia (Khubaib) berkata: \"Kamu khawatir bila aku akan membunuhnya?.. Sungguh aku tidak akan melakukannya\". (Zainab berkata); \"Demi Allah, belum pernah aku melihat ada seorang tawanan sebaik Khubaib. Demi Allah, aku pernah mendapatkan dia pada suatu hari sedang memakan buah anggur di tangannya padahal tangannya sedang dibelenggu dengan besi dan di Makkah saat itu bukan musim buah-buahan\". Dia berkata: \"Sungguh itu merupakan rezeki dari Allah yang Dia berikan kepada Khubaib\". Ketika mereka hendak keluar dari tanah Haram untuk membunuh Khubaib di daerah halal, Khubaib berkata kepada mereka: \"Biarkanlah aku untuk melaksanakan shalat dua raka'at\". Maka mereka mempersilahkanya. Khubaib shalat dua reka'at kemudian berkata: \"Seandainya bukan karena sangkaan kalian bahwa aku takut, niscaya aku akan memanjangkan shalatku ini\". Kemudian dia melanjutkan; \"Ya Allah, binasakanlah mereka semuanya dan bunuhlah mereka dan jangan Engkau sisakan seorangpun dari mereka\". Kemudian dia bersya'ir; \"Aku tidak peduli selama aku dibunuh sebagai muslim. Pada kondisi apapun aku tersungkur yang penting di jalan Allah. Semuanya itu pada Dzat Ilah, jika Dia berkendak. Dia dapat memberkahi urat-urat yang tercabik-cabik\". Akhirnya Abu Sirwa'ah 'Uqbah bin Al Harits bangkit dan membunuhnya. Khubaib adalah orang pertama yang mencontohkan shalat dua raka'at bagi setiap muslim yang akan dibunuh sebagai wujud kesabaran. Lalu Nabi shallallahu 'alaihi wasallam mengabarkan kepada para sahabat beliau tentang berita mereka dan apa yang mereka alami. Orang-orang kafir Quraisy mengirim beberapa orang mendatangi 'Ashim bin Tsabit setelah mereka diberitakan tentang terbunuhnya Khubaib untuk mengambil sesuatu dari bagian jasad 'Ashim, apa yang dapat menjadi pengenal. Sebelumnya memang 'Ashim telah membunuh seorang dari pembesar mereka saat perang Badar. (Ketika mereka hendak membalaskan dendam kepada 'Ashim), Allah mengirim kepada 'Ashim pasukan lebah yang melindunginya dari para utusan kafir Quraisy sehingga mereka tidak mampu untuk mengambil secuilpun daging dari jasad 'Ashim. Dan Ka'ab bin Malik berkata; \"Mereka telah menceritakan bahwa Mararah bin ar-Rabi' Al 'Amriy dan Hilal bin Umayyah Al Waqifiy adalah dua orang shalih yang turut serta dalam perang Badar\"."},"3514":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا لَيْثٌ عَنْ يَحْيَى عَنْ نَافِعٍ أَنَّ ابْنَ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا ذُكِرَ لَهُ أَنَّ سَعِيدَ بْنَ زَيْدِ بْنِ عَمْرِو بْنِ نُفَيْلٍ وَكَانَ بَدْرِيًّا مَرِضَ فِي يَوْمِ جُمُعَةٍ فَرَكِبَ إِلَيْهِ بَعْدَ أَنْ تَعَالَى النَّهَارُ وَاقْتَرَبَتْ الْجُمُعَةُ وَتَرَكَ الْجُمُعَةَ وَقَالَ اللَّيْثُ حَدَّثَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ قَالَ حَدَّثَنِي عُبَيْدُ اللَّهِ بْنُ عَبْدِ اللَّهِ بْنِ عُتْبَةَ أَنَّ أَبَاهُ كَتَبَ إِلَى عُمَرَ بْنِ عَبْدِ اللَّهِ بْنِ الْأَرْقَمِ الزُّهْرِيِّ يَأْمُرُهُ أَنْ يَدْخُلَ عَلَى سُبَيْعَةَ بِنْتِ الْحَارِثِ الْأَسْلَمِيَّةِ فَيَسْأَلَهَا عَنْ حَدِيثِهَا وَعَنْ مَا قَالَ لَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِينَ اسْتَفْتَتْهُ فَكَتَبَ عُمَرُ بْنُ عَبْدِ اللَّهِ بْنِ الْأَرْقَمِ إِلَى عَبْدِ اللَّهِ بْنِ عُتْبَةَ يُخْبِرُهُ أَنَّ سُبَيْعَةَ بِنْتَ الْحَارِثِ أَخْبَرَتْهُأَنَّهَا كَانَتْ تَحْتَ سَعْدِ بْنِ خَوْلَةَ وَهُوَ مِنْ بَنِي عَامِرِ بْنِ لُؤَيٍّ وَكَانَ مِمَّنْ شَهِدَ بَدْرًا فَتُوُفِّيَ عَنْهَا فِي حَجَّةِ الْوَدَاعِ وَهِيَ حَامِلٌ فَلَمْ تَنْشَبْ أَنْ وَضَعَتْ حَمْلَهَا بَعْدَ وَفَاتِهِ فَلَمَّا تَعَلَّتْ مِنْ نِفَاسِهَا تَجَمَّلَتْ لِلْخُطَّابِ فَدَخَلَ عَلَيْهَا أَبُو السَّنَابِلِ بْنُ بَعْكَكٍ رَجُلٌ مِنْ بَنِي عَبْدِ الدَّارِ فَقَالَ لَهَا مَا لِي أَرَاكِ تَجَمَّلْتِ لِلْخُطَّابِ تُرَجِّينَ النِّكَاحَ فَإِنَّكِ وَاللَّهِ مَا أَنْتِ بِنَاكِحٍ حَتَّى تَمُرَّ عَلَيْكِ أَرْبَعَةُ أَشْهُرٍ وَعَشْرٌ قَالَتْ سُبَيْعَةُ فَلَمَّا قَالَ لِي ذَلِكَ جَمَعْتُ عَلَيَّ ثِيَابِي حِينَ أَمْسَيْتُ وَأَتَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَأَلْتُهُ عَنْ ذَلِكَ فَأَفْتَانِي بِأَنِّي قَدْ حَلَلْتُ حِينَ وَضَعْتُ حَمْلِي وَأَمَرَنِي بِالتَّزَوُّجِ إِنْ بَدَا لِيتَابَعَهُ أَصْبَغُ عَنْ ابْنِ وَهْبٍ عَنْ يُونُسَ وَقَالَ اللَّيْثُ حَدَّثَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ وَسَأَلْنَاهُ فَقَالَ أَخْبَرَنِي مُحَمَّدُ بْنُ عَبْدِ الرَّحْمَنِ بْنِ ثَوْبَانَ مَوْلَى بَنِي عَامِرِ بْنِ لُؤَيٍّ أَنَّ مُحَمَّدَ بْنَ إِيَاسِ بْنِ الْبُكَيْرِ وَكَانَ أَبُوهُ شَهِدَ بَدْرًا أَخْبَرَهُ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Laits] dari [Yahya] dari [Nafi'] bahwa [Ibnu 'Umar RAa] diceritakan kepadanya bahwa Sa'id bin Zaid bin 'Amru bin Nufail, salah serang yang ikut perang Badar sedang menderita sakit pada hari Jum'at. Maka Ibnu 'Umar RAa mendatanginya dengan berkendaraan saat tengah hari dan waktu shalat Jumat sudah dekat dan dia meninggalkan shalat Jum'at\". Dan telah berkata [Al Laits] telah menceritakan kepadaku [Yunus] dari [Ibnu Syihab] berkata, telah menceritakan kepadaku ['Ubaidullah bin Abdullah bin 'Utbah] bahwa bapaknya menulis surat kepada ['Umar bin Abdullah bin Al Arqam Az Zuhriy] untuk menyuruhnya menemui [Subai'ah binti Al Harits Al Aslamiyyah] dan menanyakannya tentang hadits yang disampaikannya dan tentang apa yang disampaikan Rasulullah shallallahu 'alaihi wasallam kepadanya ketika dia meminta fatwa kepada beliau. Maka 'Umar bin Abdullah bin Al Arqam menulis surat balasan kepada Abdullah bin 'Utbah dan mengabarkan bahwa Subai'ah binti Al Harits telah mengabarkan kepadanya bahwa dia dahulu berada dalam tanggungan Sa'ad bin Khawlah, dia adalah dari keturunan Bani 'Amir bin Lu'ay dan dia juga termasuk orang yang ikut dalam perang Badar. Lalu Sa'ad meninggal dunia ketika Hajji Wada' dan Subai'ah dalam keadaan mengandung dan kemudian dia melahirkan tidak lama setelah kematian Sa'ad. Setelah masa nifasnya berakhir, dia berhias diri kepada orang yang hendak meminangnya. Maka Abu as-Sanabil bin Ba'kak, laki-laki dari Bani 'Abdid Dar datang menemuinya dan berkata kepadanya; \"Aku memandang, kamu tidak patut bersoleh di hadapan orang yang meminangmu dengan tujuan menikah. Karena, demi Allah, kamu tidak boleh menikah hingga kamu melewati masa empat bulan sepuluh hari\". Subai'ah berkata; \"Setelah dia mengatakan itu, aku mengemas pakaianku ketika sore hari lalu aku menemui Rasulullah shallallahu 'alaihi wasallam lantas aku bertanya kepada beliau tentang masalah tadi. Beliau memberikan fatwa jawaban kepadaku bahwa aku telah halal ketika aku melahirkan dan beliau menyatakan bahwa aku boleh menikah jika aku mau\". Hadits ini juga diikuti oleh [Ashbagh] dari [Ibnu Wahb] dari [Yunus]. Dan Al Laits berkata, telah menceritakan kepadaku Yunus dari Ibnu Syihab; \"dan kami bertanya kepadanya lalu dia berkata; telah mengabarkan kepadaku Muhammad bin 'Abdur Rahman bin Tsauban, maula Bani 'Amir bin Lu'ay bahwa Muhammad bin Iyas bin Al Bukair, yang bapaknya adalah salah seorang yang ikut perang Badar, telah mengabarkan kerpadanya\"."},"3515":{"ar":"حَدَّثَنِي إِسْحَاقُ بْنُ إِبْرَاهِيمَ أَخْبَرَنَا جَرِيرٌ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ مُعَاذِ بْنِ رِفَاعَةَ بْنِ رَافِعٍ الزُّرَقِيِّ عَنْ أَبِيهِوَكَانَ أَبُوهُ مِنْ أَهْلِ بَدْرٍ قَالَ جَاءَ جِبْرِيلُ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ مَا تَعُدُّونَ أَهْلَ بَدْرٍ فِيكُمْ قَالَ مِنْ أَفْضَلِ الْمُسْلِمِينَ أَوْ كَلِمَةً نَحْوَهَا قَالَ وَكَذَلِكَ مَنْ شَهِدَ بَدْرًا مِنْ الْمَلَائِكَةِ","id":"Telah menceritakan kepadaku [Ishaq bin Ibrahim] telah mengabarkan kepada kami [Jarir] dari [Yahya bin Sa'id] dari [Mu'adz bin Rifa'ah bin Rafi' Az Zuraqiy] dari [bapaknya] dimana bapaknya adalah orang yang ikut perangBAdar, berkata; \"Jibril 'alaihis salam datang kepada Nabi shallallahu 'alaihi wasallam lalu berkata; \"Siapakah diantara kalian yang kamu siapkan untuk pasukan Badar?\"Beliau menjawab: \"Mereka adalah kalangan muslim yang terbaik\". Atau kalimat serupa itu. Maka Jibril berkata: \"Begitu juga yang ikut perang Badar dari kalangan malaikat\"."},"3516":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا حَمَّادٌ عَنْ يَحْيَى عَنْ مُعَاذِ بْنِ رِفَاعَةَ بْنِ رَافِعٍوَكَانَ رِفَاعَةُ مِنْ أَهْلِ بَدْرٍ وَكَانَ رَافِعٌ مِنْ أَهْلِ الْعَقَبَةِ فَكَانَ يَقُولُ لِابْنِهِ مَا يَسُرُّنِي أَنِّي شَهِدْتُ بَدْرًا بِالْعَقَبَةِ قَالَ سَأَلَ جِبْرِيلُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِهَذَاحَدَّثَنَا إِسْحَاقُ بْنُ مَنْصُورٍ أَخْبَرَنَا يَزِيدُ أَخْبَرَنَا يَحْيَى سَمِعَ مُعَاذَ بْنَ رِفَاعَةَ أَنَّ مَلَكًا سَأَلَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ وَعَنْ يَحْيَى أَنَّ يَزِيدَ بْنَ الْهَادِ أَخْبَرَهُ أَنَّهُ كَانَ مَعَهُ يَوْمَ حَدَّثَهُ مُعَاذٌ هَذَا الْحَدِيثَ فَقَالَ يَزِيدُ فَقَالَ مُعَاذٌ إِنَّ السَّائِلَ هُوَ جِبْرِيلُ عَلَيْهِ السَّلَام","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] telah menceritakan kepada kami [Hammad] dari [Yahya] dari [Mu'adz bin Rifa'ah bin Rafi']. Rifa'ah adalah salah seorang Ahlu Badar sedangkan [Rafi'] adalah Ahlu (orang yang ikut dalam bai'at) al 'Aqabah. Dia (Rafi') pernah berkata kepada anaknya; \"Tidaklah membahagiakan aku jika ikut perang Badar dijadikan sebagai ganti keikut-sertaan aku dalam bai'at al 'Aqabah. Dia berkata; \"Jibril 'alaihis salam pernah bertanya kepada Nabi shallallahu 'alaihi wasallam tentang perkara ini\". Telah menceritakan kepada kami [Ishaq bin Manshur] telah mengabarkan kepada kami [Yazid] telah mengabarkan kepada kami [Yahya] dia mendengar [Mu'adz bin Rifa'ah] bahwa; \"Ada malaikat yang bertanya kepada Nabi shallallahu 'alaihi wasallam yang semisalnya\" Dan dari [Yahya] bahwa [Yazid bin Al Hadi] mengabarkan kepadanya bahwa dia pernah bersamanya pada hari [Mu'adz] menceritakan hadits ini. Maka Yazid bercerita dimana Mu'adz berkata; \"Yang bertanya adalah Jibril 'alaihis salam."},"3517":{"ar":"حَدَّثَنِي إِبْرَاهِيمُ بْنُ مُوسَى أَخْبَرَنَا عَبْدُ الْوَهَّابِ حَدَّثَنَا خَالِدٌ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يَوْمَ بَدْرٍ هَذَا جِبْرِيلُ آخِذٌ بِرَأْسِ فَرَسِهِ عَلَيْهِ أَدَاةُ الْحَرْبِ","id":"Telah menceritakan kepadaku [Ibrahim binMusa] telah mengabarkan kepada kami ['Abdul Wahhab] telah menceritakan kepada kami [Khalid] dari ['Ikrimah] dari [Ibnu 'Abbas RAa] bahwa Nabi shallallahu 'alaihi wasallam berkata pada saat perang Badar: \"Ini Jibril 'alaihis salam sedang memegang kepala kudanya dan dirinya dilengkapi peralatan perang\"."},"3518":{"ar":"بَاب حَدَّثَنِي خَلِيفَةُ حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ الْأَنْصَارِيُّ حَدَّثَنَا سَعِيدٌ عَنْ قَتَادَةَ عَنْ أَنَسٍ رَضِيَ اللَّهُ عَنْهُ قَالَمَاتَ أَبُو زَيْدٍ وَلَمْ يَتْرُكْ عَقِبًا وَكَانَ بَدْرِيًّا","id":"Bab. Telah menceritakan kepadaku [Khalifah] telah menceritakan kepada kami [Muhammad bin Abdullah Al Anshariy] telah menceritakan kepada kami [Sa'id] dari [Qatadah] dari [Anas] radliallahu 'anhu berkata; \"Abu Zaid meninggal dunia dan tidak meninggalkan apapun. Dan dia termasuk orang yang ikut perang Badar\"."},"3519":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ حَدَّثَنَا اللَّيْثُ قَالَ حَدَّثَنِي يَحْيَى بْنُ سَعِيدٍ عَنْ الْقَاسِمِ بْنِ مُحَمَّدٍ عَنْ ابْنِ خَبَّابٍ أَنَّ أَبَا سَعِيدِ بْنَ مَالِكٍ الْخُدْرِيَّ رَضِيَ اللَّهُ عَنْهُقَدِمَ مِنْ سَفَرٍ فَقَدَّمَ إِلَيْهِ أَهْلُهُ لَحْمًا مِنْ لُحُومِ الْأَضْحَى فَقَالَ مَا أَنَا بِآكِلِهِ حَتَّى أَسْأَلَ فَانْطَلَقَ إِلَى أَخِيهِ لِأُمِّهِ وَكَانَ بَدْرِيًّا قَتَادَةَ بْنِ النُّعْمَانِ فَسَأَلَهُ فَقَالَ إِنَّهُ حَدَثَ بَعْدَكَ أَمْرٌ نَقْضٌ لِمَا كَانُوا يُنْهَوْنَ عَنْهُ مِنْ أَكْلِ لُحُومِ الْأَضْحَى بَعْدَ ثَلَاثَةِ أَيَّامٍ","id":"Telah menceritakan kepada kami [Abdullah bin Yusuf] telah menceritakan kepada kami [Al Laits] berkata, telah menceritakan kepadaku [Yahya bin Sa'id] dari [Al Qasim bin Muhammad] dari [Ibnu Khabbab] bahwa [Abu Sa'id bin Malik Al Khudriy] radliallahu 'anhu baru tiba dari perjalanannya lalu keluarganya membawakan daging hewan qurban untuknya. Maka dia berkata; \"Aku tidak akan memakannya sebelum aku bertanya (kehalalannya) \". Maka dia berangkat menemui saudara seibunya yang merupakan Ahlu Badar, yang bernama [Qatadah bin an-Nu'man] lalu dia bertanya kepadanya. Saudaranya itu berkata; \"Sesungguhnya telah terjadi suatu hal yang membatalkan apa yang dahulunya dilarang, yaitu memakan daging qurban setelah tiga hari\"."},"3520":{"ar":"حَدَّثَنِي عُبَيْدُ بْنُ إِسْمَاعِيلَ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ قَالَ قَالَ الزُّبَيْرُلَقِيتُ يَوْمَ بَدْرٍ عُبَيْدَةَ بْنَ سَعِيدِ بْنِ الْعَاصِ وَهُوَ مُدَجَّجٌ لَا يُرَى مِنْهُ إِلَّا عَيْنَاهُ وَهُوَ يُكْنَى أَبُو ذَاتِ الْكَرِشِ فَقَالَ أَنَا أَبُو ذَاتِ الْكَرِشِ فَحَمَلْتُ عَلَيْهِ بِالْعَنَزَةِ فَطَعَنْتُهُ فِي عَيْنِهِ فَمَاتَ قَالَ هِشَامٌ فَأُخْبِرْتُ أَنَّ الزُّبَيْرَ قَالَ لَقَدْ وَضَعْتُ رِجْلِي عَلَيْهِ ثُمَّ تَمَطَّأْتُ فَكَانَ الْجَهْدَ أَنْ نَزَعْتُهَا وَقَدْ انْثَنَى طَرَفَاهَا قَالَ عُرْوَةُ فَسَأَلَهُ إِيَّاهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَعْطَاهُ فَلَمَّا قُبِضَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَخَذَهَا ثُمَّ طَلَبَهَا أَبُو بَكْرٍ فَأَعْطَاهُ فَلَمَّا قُبِضَ أَبُو بَكْرٍ سَأَلَهَا إِيَّاهُ عُمَرُ فَأَعْطَاهُ إِيَّاهَا فَلَمَّا قُبِضَ عُمَرُ أَخَذَهَا ثُمَّ طَلَبَهَا عُثْمَانُ مِنْهُ فَأَعْطَاهُ إِيَّاهَا فَلَمَّا قُتِلَ عُثْمَانُ وَقَعَتْ عِنْدَ آلِ عَلِيٍّ فَطَلَبَهَا عَبْدُ اللَّهِ بْنُ الزُّبَيْرِ فَكَانَتْ عِنْدَهُ حَتَّى قُتِلَ","id":"Telah menceritakan kepadaku ['Ubaid bin Isma'il] telah menceritakan kepada kami [Abu Usamah] dari [Hisyam bin \"urwah] dari [bapaknya] berkata, [Az Zubair] berkata; \"Pada peperangan Badar aku berhadapan dengan 'Ubaidah bin Sa'id bin Al 'Ash yang saat itu tubuhnya ditutupi dengan perlengkapan perang sehingga tidak terlihat dari tubuhnya melainkan kedua matanya. Dia biasa dipanggil dengan Abu Dzat Al Karisy. Aku menyerangnya dengan tombak lalu aku tusuk salah satu matanya hingga tewas. Hisyam berkata, aku pernah dikabarkan bahwa Az Zubair berkata; \"Aku meletakkan kakiku pada badannya kemudian aku bentangkan. Sungguh sulit baginya untuk mencabut tombak itu karena ujungnya sudah bengkok\". 'Urwah berkata; \"Kemudian Rasulullah shallallahu 'alaihi wasallam meminta tombak itu darinya lalu dia memberikannya. Setelah Rasulullah shallallahu 'alaihi wasallam meninggal dunia tombak itu diambilnya kembali. Kemudian Abu Bakr mencarinya dan dia memberikan kepadanya. Tatkala Abu Bakr telah meninggal dunia, 'Umar meminta kepadanya lalu dia memberikannya kepada 'Umar. Dan setelah 'Umar meninggal dunia, tombak itu kembali diambilnya. Kemudian 'Utsman mencarinya darinya lalu dia memberikannya kepada 'Utsman. Setelah 'utsman terbunuh, tombak itu tersimpan pada keluarga 'Ali lalu Abdullah bin Az Zubair mengambilnya. Dan tombak itu terus bersamanya hingga Abdullah bin Az Zubair terbunuh\"."},"3521":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي أَبُو إِدْرِيسَ عَائِذُ اللَّهِ بْنُ عَبْدِ اللَّهِ أَنَّ عُبَادَةَ بْنَ الصَّامِتِوَكَانَ شَهِدَ بَدْرًا أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ بَايِعُونِي","id":"Telah menceritakan kepada kami [Abu Al Yaman] telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhriy] berkata, telah mengabarkan kepadaku [Abu Idris 'Aidzullah bin Abdullah] bahwa ['Ubadah bin ash Shamit], salah seorang shahabat ahlu Badar, berkata bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Berbai'atlah kepadaku\"."},"3522":{"ar":"حَدَّثَنَا يَحْيَى بْنُ بُكَيْرٍ حَدَّثَنَا اللَّيْثُ عَنْ عُقَيْلٍ عَنْ ابْنِ شِهَابٍ أَخْبَرَنِي عُرْوَةُ بْنُ الزُّبَيْرِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَأَنَّ أَبَا حُذَيْفَةَ وَكَانَ مِمَّنْ شَهِدَ بَدْرًا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَبَنَّى سَالِمًا وَأَنْكَحَهُ بِنْتَ أَخِيهِ هِنْدَ بِنْتَ الْوَلِيدِ بْنِ عُتْبَةَ وَهُوَ مَوْلًى لِامْرَأَةٍ مِنْ الْأَنْصَارِ كَمَا تَبَنَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ زَيْدًا وَكَانَ مَنْ تَبَنَّى رَجُلًا فِي الْجَاهِلِيَّةِ دَعَاهُ النَّاسُ إِلَيْهِ وَوَرِثَ مِنْ مِيرَاثِهِ حَتَّى أَنْزَلَ اللَّهُ تَعَالَى{ ادْعُوهُمْ لِآبَائِهِمْ }فَجَاءَتْ سَهْلَةُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَ الْحَدِيثَ","id":"Telah menceritakan kepada kami [Yahya bin Bukair] telah menceritakan kepada kami [Al Laits] dari ['Uqail] dari [Ibnu Syihab] telah mengabarkan kepadaku ['Urwah bin Az Zubair] dari ['Aisyah, istri Nabi shallallahu 'alaihi wasallam]; \"Bahwa Abu Hudzaifah, salah seorang yang ikut perang Badar bersama Rasulullah shallallahu 'alaihi wasallam menjadikan Salim sebagai anak angkatnya lalu menikahkannya dengan putri saudaranya yang bernama Hindun binti Al Walid bin 'Utbah. Dia adalah mantan budak seorang wanita kaum Anshar sebagaimana Rasulullah shallallahu 'alaihi wasallam menjadikan Zaid sebagai anak angkat beliau. Dahulu pada zaman Jahiliyyah, siapa yang menjadikan seseorang sebagai anak angkatnya, orang-orang memanggil sebutan ayah anak angkat itu dengan nama bapak angkatnya dan mendapatkan hak warisan dari harta warisan (ayah angkatnya) hingga Allah Ta'ala menurunkan firman-Nya dalam QS al-Ahzab ayat 5 yang artinya: \"Panggilah mereka (anak angkat kalian) dengan nama bapak-bapak kandung mereka...\". Kemudian Sahlah mendatangi Nabi shallallahu 'alaihi wasallam. Lalu perawi menceritakan hadits ini."},"3523":{"ar":"حَدَّثَنَا عَلِيٌّ حَدَّثَنَا بِشْرُ بْنُ الْمُفَضَّلِ حَدَّثَنَا خَالِدُ بْنُ ذَكْوَانَ عَنْ الرُّبَيِّعِ بِنْتِ مُعَوِّذٍ قَالَتْدَخَلَ عَلَيَّ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ غَدَاةَ بُنِيَ عَلَيَّ فَجَلَسَ عَلَى فِرَاشِي كَمَجْلِسِكَ مِنِّي وَجُوَيْرِيَاتٌ يَضْرِبْنَ بِالدُّفِّ يَنْدُبْنَ مَنْ قُتِلَ مِنْ آبَائِهِنَّ يَوْمَ بَدْرٍ حَتَّى قَالَتْ جَارِيَةٌ وَفِينَا نَبِيٌّ يَعْلَمُ مَا فِي غَدٍ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَقُولِي هَكَذَا وَقُولِي مَا كُنْتِ تَقُولِينَ","id":"Telah menceritakan kepada kami ['Ali] telah menceritakan kepada kami [Bisyir bin Al Mufadldlal] telah menceritakan kepada kami [Khalid bin Dzakwan] dari [ar-Robi' binti Mu'awwidz] berkata; Nabi shallallahu 'alaihi wasallam datang menemuiku pada pagi hari dan membangunkan aku. Lalu beliau duduk di atas tikarku seperti posisi dudukmu di hadapanku ini. Saat itu, ada dua budak wanita sedang menabuh gendang sambil bersenandung mencela orang-orang yang terbunuh dari kalangan orangtua mereka pada perang Badar. Hingga berkata salah seorang dari budak itu; \"Bersama kami ada Nabi yang mengetahui apa yang bakal terjadi besok\". Maka Nabi shallallahu 'alaihi wasallam segera berkata: \"Janganlah kamu mengatakan begitu. Tapi cukup katakan apa yang kamu katakan sebelumnya\". "},"3524":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ مُوسَى أَخْبَرَنَا هِشَامٌ عَنْ مَعْمَرٍ عَنْ الزُّهْرِيِّ ح حَدَّثَنَا إِسْمَاعِيلُ قَالَ حَدَّثَنِي أَخِي عَنْ سُلَيْمَانَ عَنْ مُحَمَّدِ بْنِ أَبِي عَتِيقٍ عَنْ ابْنِ شِهَابٍ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ عُتْبَةَ بْنِ مَسْعُودٍ أَنَّ ابْنَ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَ أَخْبَرَنِي أَبُو طَلْحَةَ رَضِيَ اللَّهُ عَنْهُصَاحِبُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَكَانَ قَدْ شَهِدَ بَدْرًا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ لَا تَدْخُلُ الْمَلَائِكَةُ بَيْتًا فِيهِ كَلْبٌ وَلَا صُورَةٌ يُرِيدُ التَّمَاثِيلَ الَّتِي فِيهَا الْأَرْوَاحُ","id":"Telah menceritakan kepada kami [Ibrahim bin Musa] telah mengabarkan kepada kami [Hisyam] dari [Ma'mar] dari [Az Zuhri]. (dan diriwayatkan dari jalur lain), telah menceritakan kepada kami [Isma'il] dia berkata, telah menceritakan kepadaku [Saudaraku] dari [Sulaiman] dari [Muhammad bin 'Atiq] dari [Ibnu Syihab] dari ['Ubaidullah bin Abdullah bin 'Utbah bin Mas'ud] bahwa [Ibnu Abbas] radliallahu 'anhuma berkata, telah mengabarkan kepadaku [Abu Thalhah] radliallahu 'anhu -seorang sahabat Rasulullah shallallahu 'alaihi wasallam, dan seseorang yang pernah ikut serta dalam perang Badr bersama Rasulullah shallallahu 'alaihi wasallam- bahwa beliau bersabda: \"Malaikat tidak akan masuk ke dalam rumah yang di dalamnya terdapat anjing dan gambar.\" Maksudnya adalah gambar yang bernyawa."},"3525":{"ar":"حَدَّثَنَا إِسْحَاقُ بْنُ نَصْرٍ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا ابْنُ جُرَيْجٍ عَنْ مُوسَى بْنِ عُقْبَةَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا قَالَحَارَبَتْ النَّضِيرُ وَقُرَيْظَةُ فَأَجْلَى بَنِي النَّضِيرِ وَأَقَرَّ قُرَيْظَةَ وَمَنَّ عَلَيْهِمْ حَتَّى حَارَبَتْ قُرَيْظَةُ فَقَتَلَ رِجَالَهُمْ وَقَسَمَ نِسَاءَهُمْ وَأَوْلَادَهُمْ وَأَمْوَالَهُمْ بَيْنَ الْمُسْلِمِينَ إِلَّا بَعْضَهُمْ لَحِقُوا بِالنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَآمَنَهُمْ وَأَسْلَمُوا وَأَجْلَى يَهُودَ الْمَدِينَةِ كُلَّهُمْ بَنِي قَيْنُقَاعَ وَهُمْ رَهْطُ عَبْدِ اللَّهِ بْنِ سَلَامٍ وَيَهُودَ بَنِي حَارِثَةَ وَكُلَّ يَهُودِ الْمَدِينَةِ","id":"Telah menceritakan kepada kami [Ishaq bin Nahsr] telah menceritakan kepada kami [Abdurrazaq] telah mengabarkan kepada kami [Ibnu Juraij] dari [Musa bin 'Uqbah] dari [Nafi'] dari [Ibnu Umar] radliallahu 'anhuma, dia berkata, \"Bani Nadlir dan Bani Quraidzah pernah hendak menyerang (Nabi). Maka Bani Nadlir diusir, dan Bani Quraidzah tetap (berada di Madinah-pent) sampai akhirnya bani Quraidlah memerangi beliau setelah itu. Maka pun beliau membunuh kaum laki-laki mereka, membagi-bagikan para wanita dan anak-anak, serta harta benda mereka kepada kaum muslimin. Namun sebagian mereka ada yang menemui Nabi shallallahu 'alaihi wasallam untuk meminta jaminan keamanan dan masuk Islam. Dan beliau juga mengeluarkan seluruh kaum Yahudi yang ada di Madinah, baik itu Bani Qainuqa' para pengikut Abdullah bin Salam, Bani Haritsah, dan semua kaum Yahudi yang ada di Madinah tanpa terkecuali.\""},"3526":{"ar":"حَدَّثَنِي الْحَسَنُ بْنُ مُدْرِكٍ حَدَّثَنَا يَحْيَى بْنُ حَمَّادٍ أَخْبَرَنَا أَبُو عَوَانَةَ عَنْ أَبِي بِشْرٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ قَالَ قُلْتُ لِابْنِ عَبَّاسٍسُورَةُ الْحَشْرِ قَالَ قُلْ سُورَةُ النَّضِيرِتَابَعَهُ هُشَيْمٌ عَنْ أَبِي بِشْرٍ","id":"Telah menceritakan kepadaku [Al Hasan bin Mudrik] telah menceritakan kepada kami [Yahya bin Hammad] telah mengabarkan kepada kami [Abu 'Awanah] dari [Abu Bisyr] dari [Sa'id bin Jubair] dia berkata, aku berkata kepada [Ibnu Abbas] mengenai surat Al Hasyr, dia berkata, \"Katakanlah surat An Nadlir.\" Riwayat ini juga dikuatkan oleh [Husyaim] dari [Abu Bisyr]."},"3527":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ أَبِي الْأَسْوَدِ حَدَّثَنَا مُعْتَمِرٌ عَنْ أَبِيهِ سَمِعْتُ أَنَسَ بْنَ مَالِكٍ رَضِيَ اللَّهُ عَنْهُ قَالَكَانَ الرَّجُلُ يَجْعَلُ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ النَّخَلَاتِ حَتَّى افْتَتَحَ قُرَيْظَةَ وَالنَّضِيرَ فَكَانَ بَعْدَ ذَلِكَ يَرُدُّ عَلَيْهِمْ","id":"Telah menceritakan kepada kami [Abdullah bin Abu Al Aswad] telah menceritakan kepada kami [Mu'tamir] dari [Ayahnya] aku mendengar [Anas bin Malik] radliallahu 'anhu berkata, \"Seorang laki-laki pernah memberikan sebagian kebun kurmanya kepada Nabi shallallahu 'alaihi wasallam, sampai beliau menaklukkan Bani Quraizhah dan Bani Nadlir. Setelah penaklukan tersebut, maka beliau mengembalikan sebagian kebun kurma kepada laki-laki itu.\""},"3528":{"ar":"حَدَّثَنَا آدَمُ حَدَّثَنَا اللَّيْثُ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا قَالَحَرَّقَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَخْلَ بَنِي النَّضِيرِ وَقَطَعَ وَهِيَ الْبُوَيْرَةُ فَنَزَلَتْ{ مَا قَطَعْتُمْ مِنْ لِينَةٍ أَوْ تَرَكْتُمُوهَا قَائِمَةً عَلَى أُصُولِهَا فَبِإِذْنِ اللَّهِ }","id":"Telah menceritakan kepada kami [Adam] telah menceritakan kepada kami [Al Laits] dari [An Nafi'] dari [Ibnu Umar] radliallahu 'anhuma dia berkata, \"Rasulullah shallallahu 'alaihi wasallam pernah membakar kebun kurma Bani Nadlir dan memotongnya, yaitu yang ada di Buwairah. Kemudian turunlah ayat: '(Apa saja yang kamu tebang dari pohon kurma (milik orang-orang kafir) atau yang kamu biarkan (tumbuh) berdiri di atas pokoknya. Maka (semua itu) adalah dengan izin Allah) ' (Qs. Al Hasyr: 5)."},"3529":{"ar":"حَدَّثَنِي إِسْحَاقُ أَخْبَرَنَا حَبَّانُ أَخْبَرَنَا جُوَيْرِيَةُ بْنُ أَسْمَاءَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَرَّقَ نَخْلَ بَنِي النَّضِيرِ قَالَ وَلَهَا يَقُولُ حَسَّانُ بْنُ ثَابِتٍ وَهَانَ عَلَى سَرَاةِ بَنِي لُؤَيٍّحَرِيقٌ بِالْبُوَيْرَةِ مُسْتَطِيرُقَالَ فَأَجَابَهُ أَبُو سُفْيَانَ بْنُ الْحَارِثِ أَدَامَ اللَّهُ ذَلِكَ مِنْ صَنِيعٍوَحَرَّقَ فِي نَوَاحِيهَا السَّعِيرُسَتَعْلَمُ أَيُّنَا مِنْهَا بِنُزْهٍوَتَعْلَمُ أَيُّ أَرْضَيْنَا تَضِيرُ","id":"Telah menceritakan kepadaku [Ishaq] telah mengabarkan kepada kami [Habban] telah mengabarkan kepada kami [Juwairiyah bin Asma`] dari [Nafi'] dari [Ibnu Umar] radliallahu 'anhuma, bahwa Nabi shallallahu 'alaihi wasallam pernah membakar kebun kurma Bani Nadlir, ia mengatakan, \"Untuk itulah Hassan bin Tsabit mengatakan, 'Dan telah hina pemimpin Bani Lu'ai, kebakaran di Buwairah telah menyala-nyala.' Lantas Abu Sufyan bin Al Harits menjawab, 'Allah melanggengkan hal itu, semua sisi terbakar oleh api, kamu akan mengetahui siapa di antara kita yang terdampar, dan kamu akan mengetahui mana dari kedua tanah kami yang membahayakan'.\""},"3530":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي مَالِكُ بْنُ أَوْسِ بْنِ الْحَدَثَانِ النَّصْرِيُّ أَنَّ عُمَرَ بْنَ الْخَطَّابِ رَضِيَ اللَّهُ عَنْهُدَعَاهُ إِذْ جَاءَهُ حَاجِبُهُ يَرْفَا فَقَالَ هَلْ لَكَ فِي عُثْمَانَ وَعَبْدِ الرَّحْمَنِ وَالزُّبَيْرِ وَسَعْدٍ يَسْتَأْذِنُونَ فَقَالَ نَعَمْ فَأَدْخِلْهُمْ فَلَبِثَ قَلِيلًا ثُمَّ جَاءَ فَقَالَ هَلْ لَكَ فِي عَبَّاسٍ وَعَلِيٍّ يَسْتَأْذِنَانِ قَالَ نَعَمْ فَلَمَّا دَخَلَا قَالَ عَبَّاسٌ يَا أَمِيرَ الْمُؤْمِنِينَ اقْضِ بَيْنِي وَبَيْنَ هَذَا وَهُمَا يَخْتَصِمَانِ فِي الَّذِي أَفَاءَ اللَّهُ عَلَى رَسُولِهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ بَنِي النَّضِيرِ فَاسْتَبَّ عَلِيٌّ وَعَبَّاسٌ فَقَالَ الرَّهْطُ يَا أَمِيرَ الْمُؤْمِنِينَ اقْضِ بَيْنَهُمَا وَأَرِحْ أَحَدَهُمَا مِنْ الْآخَرِ فَقَالَ عُمَرُ اتَّئِدُوا أَنْشُدُكُمْ بِاللَّهِ الَّذِي بِإِذْنِهِ تَقُومُ السَّمَاءُ وَالْأَرْضُ هَلْ تَعْلَمُونَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا نُورَثُ مَا تَرَكْنَا صَدَقَةٌ يُرِيدُ بِذَلِكَ نَفْسَهُ قَالُوا قَدْ قَالَ ذَلِكَ فَأَقْبَلَ عُمَرُ عَلَى عَبَّاسٍ وَعَلِيٍّ فَقَالَ أَنْشُدُكُمَا بِاللَّهِ هَلْ تَعْلَمَانِ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ قَالَ ذَلِكَ قَالَا نَعَمْ قَالَ فَإِنِّي أُحَدِّثُكُمْ عَنْ هَذَا الْأَمْرِ إِنَّ اللَّهَ سُبْحَانَهُ كَانَ خَصَّ رَسُولَهُ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي هَذَا الْفَيْءِ بِشَيْءٍ لَمْ يُعْطِهِ أَحَدًا غَيْرَهُ فَقَالَ جَلَّ ذِكْرُهُ{ وَمَا أَفَاءَ اللَّهُ عَلَى رَسُولِهِ مِنْهُمْ فَمَا أَوْجَفْتُمْ عَلَيْهِ مِنْ خَيْلٍ وَلَا رِكَابٍ إِلَى قَوْلِهِ قَدِيرٌ }فَكَانَتْ هَذِهِ خَالِصَةً لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ وَاللَّهِ مَا احْتَازَهَا دُونَكُمْ وَلَا اسْتَأْثَرَهَا عَلَيْكُمْ لَقَدْ أَعْطَاكُمُوهَا وَقَسَمَهَا فِيكُمْ حَتَّى بَقِيَ هَذَا الْمَالُ مِنْهَا فَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُنْفِقُ عَلَى أَهْلِهِ نَفَقَةَ سَنَتِهِمْ مِنْ هَذَا الْمَالِ ثُمَّ يَأْخُذُ مَا بَقِيَ فَيَجْعَلُهُ مَجْعَلَ مَالِ اللَّهِ فَعَمِلَ ذَلِكَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَيَاتَهُ ثُمَّ تُوُفِّيَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَبُو بَكْرٍ فَأَنَا وَلِيُّ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَبَضَهُ أَبُو بَكْرٍ فَعَمِلَ فِيهِ بِمَا عَمِلَ بِهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنْتُمْ حِينَئِذٍ فَأَقْبَلَ عَلَى عَلِيٍّ وَعَبَّاسٍ وَقَالَ تَذْكُرَانِ أَنَّ أَبَا بَكْرٍ فِيهِ كَمَا تَقُولَانِ وَاللَّهُ يَعْلَمُ إِنَّهُ فِيهِ لَصَادِقٌ بَارٌّ رَاشِدٌ تَابِعٌ لِلْحَقِّ ثُمَّ تَوَفَّى اللَّهُ أَبَا بَكْرٍ فَقُلْتُ أَنَا وَلِيُّ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَبِي بَكْرٍ فَقَبَضْتُهُ سَنَتَيْنِ مِنْ إِمَارَتِي أَعْمَلُ فِيهِ بِمَا عَمِلَ فِيهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَبُو بَكْرٍ وَاللَّهُ يَعْلَمُ أَنِّي فِيهِ صَادِقٌ بَارٌّ رَاشِدٌ تَابِعٌ لِلْحَقِّ ثُمَّ جِئْتُمَانِي كِلَاكُمَا وَكَلِمَتُكُمَا وَاحِدَةٌ وَأَمْرُكُمَا جَمِيعٌ فَجِئْتَنِي يَعْنِي عَبَّاسًا فَقُلْتُ لَكُمَا إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا نُورَثُ مَا تَرَكْنَا صَدَقَةٌ فَلَمَّا بَدَا لِي أَنْ أَدْفَعَهُ إِلَيْكُمَا قُلْتُ إِنْ شِئْتُمَا دَفَعْتُهُ إِلَيْكُمَا عَلَى أَنَّ عَلَيْكُمَا عَهْدَ اللَّهِ وَمِيثَاقَهُ لَتَعْمَلَانِ فِيهِ بِمَا عَمِلَ فِيهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَبُو بَكْرٍ وَمَا عَمِلْتُ فِيهِ مُنْذُ وَلِيتُ وَإِلَّا فَلَا تُكَلِّمَانِي فَقُلْتُمَا ادْفَعْهُ إِلَيْنَا بِذَلِكَ فَدَفَعْتُهُ إِلَيْكُمَا أَفَتَلْتَمِسَانِ مِنِّي قَضَاءً غَيْرَ ذَلِكَ فَوَاللَّهِ الَّذِي بِإِذْنِهِ تَقُومُ السَّمَاءُ وَالْأَرْضُ لَا أَقْضِي فِيهِ بِقَضَاءٍ غَيْرِ ذَلِكَ حَتَّى تَقُومَ السَّاعَةُ فَإِنْ عَجَزْتُمَا عَنْهُ فَادْفَعَا إِلَيَّ فَأَنَا أَكْفِيكُمَاهُقَالَ فَحَدَّثْتُ هَذَا الْحَدِيثَ عُرْوَةَ بْنَ الزُّبَيْرِ فَقَالَ صَدَقَ مَالِكُ بْنُ أَوْسٍ أَنَا سَمِعْتُ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا زَوْجَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَقُولُ أَرْسَلَ أَزْوَاجُ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عُثْمَانَ إِلَى أَبِي بَكْرٍ يَسْأَلْنَهُ ثُمُنَهُنَّ مِمَّا أَفَاءَ اللَّهُ عَلَى رَسُولِهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَكُنْتُ أَنَا أَرُدُّهُنَّ فَقُلْتُ لَهُنَّ أَلَا تَتَّقِينَ اللَّهَ أَلَمْ تَعْلَمْنَ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَقُولُ لَا نُورَثُ مَا تَرَكْنَا صَدَقَةٌ يُرِيدُ بِذَلِكَ نَفْسَهُ إِنَّمَا يَأْكُلُ آلُ مُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي هَذَا الْمَالِ فَانْتَهَى أَزْوَاجُ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى مَا أَخْبَرَتْهُنَّ قَالَ فَكَانَتْ هَذِهِ الصَّدَقَةُ بِيَدِ عَلِيٍّ مَنَعَهَا عَلِيٌّ عَبَّاسًا فَغَلَبَهُ عَلَيْهَا ثُمَّ كَانَ بِيَدِ حَسَنِ بْنِ عَلِيٍّ ثُمَّ بِيَدِ حُسَيْنِ بْنِ عَلِيٍّ ثُمَّ بِيَدِ عَلِيِّ بْنِ حُسَيْنٍ وَحَسَنِ بْنِ حَسَنٍ كِلَاهُمَا كَانَا يَتَدَاوَلَانِهَا ثُمَّ بِيَدِ زَيْدِ بْنِ حَسَنٍ وَهِيَ صَدَقَةُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَقًّا","id":"Telah menceritakan kepada kami [Abu Al Yaman] telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhri] dia berkata, telah mengabarkan kepadaku [Malik bin Aus bin Al Hadatsan] bahwa [Umar bin Al Khattab] radliallahu 'anhu pernah memanggilnya, setelah itu penjaga pintunya, Yarfa, datang melapor, \"Apakah anda mengizinkan [Utsman], [Abdurrahman], [Zubair] dan [Sa'd] untuk masuk?\" Umar menjawab, \"Ya.\" Kemudian penjaga pintu menyuruh mereka masuk, tidak lama kemudian penjaga pintu datang lagi dan berkata, 'Apakah anda mengizinkan [Abbas] dan [Ali] untuk masuk?\" Umar menjawab, \"Ya.\" Ketika keduanya telah masuk, Abbas berkata, \"Wahai Amirul Mukminin, putuskanlah antara kami dengan orang ini.\" Ketika itu mereka tengah berselisih masalah harta yang Allah karuniakan kepada Rasul-Nya shallallahu 'alaihi wasallam, yakni berupa harta milik Bani Nadlir hingga keduanya saling mencela. Sebagian kelompok berkata, \"Wahai Amirul mukminin, buatlah keputusan untuk keduanya, dan legakanlah salah seorang di antara keduanya.\" 'Umar pun berkata, \"Tenanglah kalian! Dan aku minta kepada kalian, demi Allah yang dengan izin-Nya langit dan bumi tegak, apakah kalian mengetahui bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kami tidak mewariskan. Dan apa-apa yang kami tinggalkan menjadi sedekah.\" Yang beliau maksudkan (dengan kata kami) adalah diri beliau sendiri. Mereka menjawab, \"Ya, beliau telah bersabda demikian.\" Maka 'Umar kembali menghadap dan berbicara kepada 'Ali dan 'Abbas, \"Aku minta kepada kalian berdua, demi Allah, apakah kalian berdua mengetahui bahwa Rasulullah shallallahu 'alaihi wasallam telah bersabda seperti itu?\" Keduanya menjawab, \"Ya, beliau telah bersabda seperti itu.\" Umar kemudian melanjutkan, \"Untuk itu aku akan menyampaikan kepada kalian tentang masalah ini. Sesungguhnya Allah telah mengkhususkan Rasul-Nya shallallahu 'alaihi wasallam dalam masalah fa'i ini sebagai sesuatu yang tidak Dia berikan kepada siapapun selain beliau.\" Lalu Umar membaca firman Allah: '(Dan apa saja yang dikaruniakan Allah berupa fa'i (rampasan perang) kepada Rasul-Nya dari (harta benda) mereka… -hingga firmanNya- dan Allah Maha berkuasa atas segala sesuatu) ' (Qs. Al Hasyr: 6), ayat ini merupakan pengkhususan untuk Rasulullah shallallahu 'alaihi wasallam. Demi Allah, tidaklah beliau mengumpulkannya dengan tidak memperhatikan kalian dan juga tidak untuk lebih mementingkan diri kalian. Sungguh, beliau telah memberikannya kepada kalian dan menyebarkannya di tengah-tengah kalian (kaum Muslimin) hingga sekarang masih ada yang tersisa dari harta tersebut. Dan Rasulullah shallallahu 'alaihi wasallam telah memberi nafkah belanja kepada keluarga beliau sebagai nafkah tahunan mereka dari harta fa'i ini, lalu sisanya beliau ambil dan dijadikannya sebagai harta Allah, beliau sudah menerapkan semua ini samasa hidup beliau. Kemudian Nabi shallallahu 'alaihi wasallam wafat, lalu Abu Bakr berkata, 'Akulah wali Rasulullah shallallahu 'alaihi wasallam.' Maka Abu Bakr pun mewenangi harta itu, kemudian ia mengelolanya seperti apa yang dilaksanakan oleh Rasulullah shallallahu 'alaihi wasallam, saat itu kalian juga ada.\" Kemudian Umar menghadap ke arah arah Ali dan Abbas, dia berkata, \"Kalian berdua juga ingat bahwa dalam mengelola harta itu sebagaimana yang kalian berdua katakan, sungguh Allah juga Maha tahu, bahwa dia adalah orang yang jujur, bijak, lurus dan pengikut kebenaran. Kemudian Allah mewafatkan Abu Bakr, lalu aku berkata, 'Aku adalah pengganti Rasulullah shallallahu 'alaihi wasallam dan Abu Bakr, ' dan aku berwenang untuk mengelola harta tersebut hingga dua tahun dari kepemimpinanku, aku mengelolanya sebagaimana yang dikelola Rasulullah shallallahu 'alaihi wasallam dan Abu Bakr. Dan Allah juga mengetahui bila aku adalah sosok yang jujur, bijak, lurus dan pengikut kebenaran, lalu kenapa kalian datang kepadaku dan berbicara kepadaku padahal ucapan kalian satu dan maksud urusan kalian juga satu. Engkau, wahai 'Abbas, kau datang kepadaku lalu aku katakan kepada kalian berdua, 'Sesungguhnya Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kami tidak mewariskan. Apa-apa yang kami tinggalkan menjadi sedekah.\" Setelah jelas bagiku bahwa aku harus memberikannya kepada kalian berdua, maka aku akan katakan, Jika memang kalian menghendakinya aku akan berikan kepada kalian berdua, namun kalian berdua harus ingat akan janji Allah dan ketentuan-Nya, yaitu kalian harus mengelola sebagaimana yang pernah dikelola Rasulullah shallallahu 'alaihi wasallam, Abu Bakr lakukan dan juga apa yang telah aku lakukan sejak aku memegang kekuasaan ini, jika tidak, maka kalian jangan mengatakan sesuatu kepadaku, jika kalian berdua mengatakan, \"Berikanlah kepada kami, \" maka dengan ketentuan seperti itu, aku akan berikan kepada kalian berdua. Apakah kalian berdua hendak merubah ketentuan selain dari itu? Demi Allah, yang dengan izin-Nya langit dan bumi bias tegak, aku tidak akan memutuskan dengan keputusan selain itu sampai tiba hari Kiamat, seandainya kalian berdua tidak sanggup atasnya maka serahkanlah kepadaku karena sungguh aku akan mencukupkan kalian berdua dengannya (harta itu).\" Perawi berkata, \"Lalu aku sampaikan hadits ini kepada ['Urwah bin Az Zubair], dia menjawab, \"Malik bin Aus benar, aku juga pernah mendengar ['Aisyah] radliallahu 'anha, isteri Nabi shallallahu 'alaihi wasallam, berkata, \"Para isteri Nabi shallallahu 'alaihi wasallam pernah mengutus Utsman menemui Abu Bakr untuk meminta seperdelapan dari harta yang telah Allah karuniakan kepada Rasul-Nya shallallahu 'alaihi wasallam, lalu aku menolak mereka, aku katakan kepada mereka, \"Apakah kalian tidak takut kepada Allah? Apakah kalian tidak mengetahui bahwa Nabi shallallahu 'alaihi wasallam pernah bersabda: \"Kami tidak mewarisi, dan yang kami tinggalkan adalah sedekah -yang beliau maksud dengan (kami) adalah diri beliau sendiri-, sesungguhnya keluarga Muhammad makan dari harta ini.\" Maka para isteri Nabi shallallahu 'alaihi wasallam berhenti pada apa yang telah disampaikan oleh Aisyah kepada mereka.\" Urwah berkata, \"Maka harta sedekah ini ada di tangan Ali, sementara Ali mencegah Abbas dari harta tersebut, dan dapat mengalahkannya, kemudian beralih ditangan Hasan bin Ali, kemudian berpindah ketangan Husain bin Ali, kemudian berpindah ke tangan Ali bin Husain, kemudian Al Hasan bin Al Hasan, keduanya saling bergantian, kemudian berpindah ke tangan Zaid bin Hasan, dan sesungguhnya itu merupakan sedekah Rasulullah shallallahu 'alaihi wasallam.\""},"3531":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ مُوسَى أَخْبَرَنَا هِشَامٌ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ عَائِشَةَأَنَّ فَاطِمَةَ عَلَيْهَا السَّلَام وَالْعَبَّاسَ أَتَيَا أَبَا بَكْرٍ يَلْتَمِسَانِ مِيرَاثَهُمَا أَرْضَهُ مِنْ فَدَكٍ وَسَهْمَهُ مِنْ خَيْبَرَ فَقَالَ أَبُو بَكْرٍ سَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا نُورَثُ مَا تَرَكْنَا صَدَقَةٌ إِنَّمَا يَأْكُلُ آلُ مُحَمَّدٍ فِي هَذَا الْمَالِ وَاللَّهِ لَقَرَابَةُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَحَبُّ إِلَيَّ أَنْ أَصِلَ مِنْ قَرَابَتِي","id":"Telah menceritakan kepada kami [Ibrahim bin Musa] telah mengabarkan kepada kami [Hisyam] telah mengabarkan kepada kami [Ma'mar] dari [Az Zuhri] dari ['Urwah] dari ['Aisyah] bahwa Fatimah 'alaihis salam dan 'Abbas menemui [Abu Bakr], keduanya menuntut bagian harta warisan mereka, yaitu berupa tanah di Fadak dan saham dari perang Khaibar, maka Abu Bakar berkata, \"Aku mendengar Nabi shallallahu 'alaihi wasallam bersabda: \"Kami tidak diwarisi, harta yang kami tinggalkan menjadi sedekah, keluarga Muhammad hanya makan dari harta ini.\" Maka demi Allah, kerabat Rasulullah shallallahu 'alaihi wasallam lebih aku cintai untuk aku jalin hubungan dengannya daripada kerabatku sendiri.\""},"3532":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا سُفْيَانُ قَالَ عَمْرٌو سَمِعْتُ جَابِرَ بْنَ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُمَا يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ لِكَعْبِ بْنِ الْأَشْرَفِ فَإِنَّهُ قَدْ آذَى اللَّهَ وَرَسُولَهُ فَقَامَ مُحَمَّدُ بْنُ مَسْلَمَةَ فَقَالَ يَا رَسُولَ اللَّهِ أَتُحِبُّ أَنْ أَقْتُلَهُ قَالَ نَعَمْ قَالَ فَأْذَنْ لِي أَنْ أَقُولَ شَيْئًا قَالَ قُلْ فَأَتَاهُ مُحَمَّدُ بْنُ مَسْلَمَةَ فَقَالَ إِنَّ هَذَا الرَّجُلَ قَدْ سَأَلَنَا صَدَقَةً وَإِنَّهُ قَدْ عَنَّانَا وَإِنِّي قَدْ أَتَيْتُكَ أَسْتَسْلِفُكَ قَالَ وَأَيْضًا وَاللَّهِ لَتَمَلُّنَّهُ قَالَ إِنَّا قَدْ اتَّبَعْنَاهُ فَلَا نُحِبُّ أَنْ نَدَعَهُ حَتَّى نَنْظُرَ إِلَى أَيِّ شَيْءٍ يَصِيرُ شَأْنُهُ وَقَدْ أَرَدْنَا أَنْ تُسْلِفَنَا وَسْقًا أَوْ وَسْقَيْنِو حَدَّثَنَا عَمْرٌو غَيْرَ مَرَّةٍ فَلَمْ يَذْكُرْ وَسْقًا أَوْ وَسْقَيْنِ أَوْ فَقُلْتُ لَهُ فِيهِ وَسْقًا أَوْ وَسْقَيْنِ فَقَالَ أُرَى فِيهِ وَسْقًا أَوْ وَسْقَيْنِ فَقَالَ نَعَمِ ارْهَنُونِي قَالُوا أَيَّ شَيْءٍ تُرِيدُ قَالَ ارْهَنُونِي نِسَاءَكُمْ قَالُوا كَيْفَ نَرْهَنُكَ نِسَاءَنَا وَأَنْتَ أَجْمَلُ الْعَرَبِ قَالَ فَارْهَنُونِي أَبْنَاءَكُمْ قَالُوا كَيْفَ نَرْهَنُكَ أَبْنَاءَنَا فَيُسَبُّ أَحَدُهُمْ فَيُقَالُ رُهِنَ بِوَسْقٍ أَوْ وَسْقَيْنِ هَذَا عَارٌ عَلَيْنَا وَلَكِنَّا نَرْهَنُكَ اللَّأْمَةَ قَالَ سُفْيَانُ يَعْنِي السِّلَاحَ فَوَاعَدَهُ أَنْ يَأْتِيَهُ فَجَاءَهُ لَيْلًا وَمَعَهُ أَبُو نَائِلَةَ وَهُوَ أَخُو كَعْبٍ مِنْ الرَّضَاعَةِ فَدَعَاهُمْ إِلَى الْحِصْنِ فَنَزَلَ إِلَيْهِمْ فَقَالَتْ لَهُ امْرَأَتُهُ أَيْنَ تَخْرُجُ هَذِهِ السَّاعَةَ فَقَالَ إِنَّمَا هُوَ مُحَمَّدُ بْنُ مَسْلَمَةَ وَأَخِي أَبُو نَائِلَةَ وَقَالَ غَيْرُ عَمْرٍو قَالَتْ أَسْمَعُ صَوْتًا كَأَنَّهُ يَقْطُرُ مِنْهُ الدَّمُ قَالَ إِنَّمَا هُوَ أَخِي مُحَمَّدُ بْنُ مَسْلَمَةَ وَرَضِيعِي أَبُو نَائِلَةَ إِنَّ الْكَرِيمَ لَوْ دُعِيَ إِلَى طَعْنَةٍ بِلَيْلٍ لَأَجَابَ قَالَ وَيُدْخِلُ مُحَمَّدُ بْنُ مَسْلَمَةَ مَعَهُ رَجُلَيْنِ قِيلَ لِسُفْيَانَ سَمَّاهُمْ عَمْرٌو قَالَ سَمَّى بَعْضَهُمْ قَالَ عَمْرٌو جَاءَ مَعَهُ بِرَجُلَيْنِ وَقَالَ غَيْرُ عَمْرٍو أَبُو عَبْسِ بْنُ جَبْرٍ وَالْحَارِثُ بْنُ أَوْسٍ وَعَبَّادُ بْنُ بِشْرٍ قَالَ عَمْرٌو جَاءَ مَعَهُ بِرَجُلَيْنِ فَقَالَ إِذَا مَا جَاءَ فَإِنِّي قَائِلٌ بِشَعَرِهِ فَأَشَمُّهُ فَإِذَا رَأَيْتُمُونِي اسْتَمْكَنْتُ مِنْ رَأْسِهِ فَدُونَكُمْ فَاضْرِبُوهُ وَقَالَ مَرَّةً ثُمَّ أُشِمُّكُمْ فَنَزَلَ إِلَيْهِمْ مُتَوَشِّحًا وَهُوَ يَنْفَحُ مِنْهُ رِيحُ الطِّيبِ فَقَالَ مَا رَأَيْتُ كَالْيَوْمِ رِيحًا أَيْ أَطْيَبَ وَقَالَ غَيْرُ عَمْرٍو قَالَ عِنْدِي أَعْطَرُ نِسَاءِ الْعَرَبِ وَأَكْمَلُ الْعَرَبِ قَالَ عَمْرٌو فَقَالَ أَتَأْذَنُ لِي أَنْ أَشُمَّ رَأْسَكَ قَالَ نَعَمْ فَشَمَّهُ ثُمَّ أَشَمَّ أَصْحَابَهُ ثُمَّ قَالَ أَتَأْذَنُ لِي قَالَ نَعَمْ فَلَمَّا اسْتَمْكَنَ مِنْهُ قَالَ دُونَكُمْ فَقَتَلُوهُ ثُمَّ أَتَوْا النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَخْبَرُوهُ","id":"Telah menceritakan kepada kami [Ali bin Abdullah] telah menceritakan kepada kami [Sufyan] [Amr] berkata, aku mendengar [Jabir bin Abdullah] radliallahu 'anhuma berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Siapakah yang akan membunuh Ka'b bin Asyraf yang telah durhaka kepada Allah dan melukai Rasul-Nya?\" Maka Muhammad bin Maslamah berdiri dan berkata, \"Wahai Rasulullah, sukakah anda jika aku yang akan membunuhnya?\" beliau menjawab: \"Ya.\" Muhammad bin Maslamah berkata, \"Izinkan aku untuk mengatakan sesuatu.\" Beliau bersabda: \"Katakanlah.\" Setelah itu Maslamah mendatangi Ka'b, lalu dia berkata, \"Sesungguhnya laki-laki itu (maksudnya Nabi shallallahu 'alaihi wasallam -pent) telah meminta sedekah kepada kami padahal kami dalam keadaan susah, oleh karena itu aku datang kepadamu untuk berhutang.\" Ka'b berkata, \"Dan juga -demi Allah- kalian akan bosan kepadanya.\" Maslamah berkata, \"Sesungguhnya kami telah mengikutinya, dan kami tidak suka meninggalkannya hingga kami mengetahui akhir kesudahannya, dan kami hendak meminjam satu atau dua wasaq.\" 'Amru tidak hanya sekali menceritakan kepada kami, namun ia tidak menyebutkan 'satu atau dua wasaq'. Atau, aku berkata kepadanya, 'satu atau dua wasaq'.\" Perawi berkata, \"Seingatku dalam hadits tersebut disebutkan 'satu atau dua wasaq'.\" - Ka'b bin Al Asyraf menjawab, \"Baiklah, akan tetapi kalian harus memberikan jaminan kepadaku.\" Mereka menjawab, \"Engkau harus kami beri jaminan apa?\" Ka'b menjawab, \"Gadaikanlah isteri-isteri kalian.\" Mereka menjawab, \"Bagaimana kami harus menggadaikan isteri-isteri kami, sementara kamu adalah orang yang paling rupawan di Arab.\" Ka'b berkata, \"Kalau begitu, gadaikanlah puteri-puteri kalian.\" Mereka berkata, \"Bagaimana kami harus menggadaikan puteri-puteri kami, nantinya mereka akan dihina orang-orang dan dikatakan, 'Mereka telah digadaikan dengan satu atau dua wasaq, ' hal ini akan membuat kami terhina, akan tetapi kami akan menggadaikan la'mah kami.\" -Sufyan mengatakan; maksudnya adalah senjata- Kemudian mereka membuat perjanjian untuk bertemu kembali, di suatu malam Maslamah bersama Abu Na`ilah -ia adalah saudara sepersusuan Ka'b- datang menemui Ka'b, lalu Ka'b mengundangnya untuk masuk ke dalam benteng, setelah itu Ka'b turun menemui mereka. Isteri Ka'b berkata kepadanya, \"Kemana engkau hendak keluar pada saat seperti ini?\" Ka'b menjawab, \"Dia adalah Muhammad bin Maslamah dan saudaraku Abu Na`ilah.\" -Selain 'Amru menyebutkan, \"Isteri Ka'b berkata, \"Aku mendengar suara seperti darah menetes.\" Ka'b menjawab, \"Dia hanyalah saudaraku, Muhammad bin Maslamah dan saudara sepersusuanku Abu Na`ilah. Sesungguhnya sebagai seorang yang terhormat, apabila dipanggil, maka ia akan menemuinya walaupun di malam hari.\" Perawi berkata, \"Kemudian Muhammad bin Maslamah memasukkan (ke dalam benteng) dua orang bersamanya.\" -Dikatakan kepada Sufyan, \"Apakah 'Amru menyebutkan nama mereka?\" Ia menjawab, \"Amru hanya menyebutkan nama sebagian dari mereka.\" 'Amru berkata, \"Ia datang dengan dua laki-laki.\" Sementara yang lain mengatakan, \"Abu Abs bin Jabr, Al Harits bin Aus dan 'Abbad bin Bisyr.\" 'Amru mengatakan- Ia datang bersama dua orang laki-laki.\" Maslamah melanjutkan, \"Sungguh, aku akan meraih rambut kepalanya dan menciumnya, jika kalian melihatku telah berhasil menguasai kepalanya, maka mendekatlah dan tebaslah dia.\" Sesekali Maslamah berkata, \"Kemudian aku akan memberikan kesempatan kepada kalian untuk menciumnya.\" Ketika Ka'b turun untuk menemui mereka, dan bau minyak wanginya mulai tersebar, Maslamah berkata, \"Aku belum pernah mencium aroma wangi yang lebih bagus dari ini.\" Selain 'Amru menyebutkan, \"Aku memiliki minyak wangi wanita arab dan lebih sempurna dikalangan Arab.\" 'Amru mengatakan, \"Maslamah berkata, \"Apakah engkau mengizinkanku untuk mencium kepalamu?\" Ka'b menjawab, \"Silahkan.\" Kemudian Maslamah menciumnya dan diikuti oleh sahabat-sahabatnya.\" Setelah itu Maslamah berkata lagi, \"Apakah engkau mengizinkanku lagi?\" Ka'b menjawab, \"Silahkan.\" Ketika ia telah berhasil menguasainya, Maslamah berkata, \"Mendekatlah.\" Maka mereka langsung membuhnya, setelah itu mereka menemui Nabi shallallahu 'alaihi wasallam dan mengabarkan kepada beliau.\""},"3533":{"ar":"حَدَّثَنِي إِسْحَاقُ بْنُ نَصْرٍ حَدَّثَنَا يَحْيَى بْنُ آدَمَ حَدَّثَنَا ابْنُ أَبِي زَائِدَةَ عَنْ أَبِيهِ عَنْ أَبِي إِسْحَاقَ عَنْ الْبَرَاءِ بْنِ عَازِبٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَبَعَثَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَهْطًا إِلَى أَبِي رَافِعٍ فَدَخَلَ عَلَيْهِ عَبْدُ اللَّهِ بْنُ عَتِيكٍ بَيْتَهُ لَيْلًا وَهُوَ نَائِمٌ فَقَتَلَهُ","id":"Telah menceritakan kepadaku [Ishaq bin Nashr] telah menceritakan kepada kami [Yahya bin Adam] telah menceritakan kepada kami [Ibnu Abu Za`idah] dari [Ayahnya] dari [Abu Ishaq] dari [Al Barra` bin 'Azib] radliallahu 'anhuma, dia berkata, \"Rasulullah shallallahu 'alaihi wasallam pernah mengutus sekelompok orang kepada Abu Rafi', kemudian pada malam hari Abdullah bin 'Atik masuk ke dalam rumahnya dan membunuhnya saat ia sedang terlelap tidur.\""},"3534":{"ar":"حَدَّثَنَا يُوسُفُ بْنُ مُوسَى حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى عَنْ إِسْرَائِيلَ عَنْ أَبِي إِسْحَاقَ عَنْ الْبَرَاءِ بْنِ عَازِبٍ قَالَبَعَثَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى أَبِي رَافِعٍ الْيَهُودِيِّ رِجَالًا مِنْ الْأَنْصَارِ فَأَمَّرَ عَلَيْهِمْ عَبْدَ اللَّهِ بْنَ عَتِيكٍ وَكَانَ أَبُو رَافِعٍ يُؤْذِي رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَيُعِينُ عَلَيْهِ وَكَانَ فِي حِصْنٍ لَهُ بِأَرْضِ الْحِجَازِ فَلَمَّا دَنَوْا مِنْهُ وَقَدْ غَرَبَتْ الشَّمْسُ وَرَاحَ النَّاسُ بِسَرْحِهِمْ فَقَالَ عَبْدُ اللَّهِ لِأَصْحَابِهِ اجْلِسُوا مَكَانَكُمْ فَإِنِّي مُنْطَلِقٌ وَمُتَلَطِّفٌ لِلْبَوَّابِ لَعَلِّي أَنْ أَدْخُلَ فَأَقْبَلَ حَتَّى دَنَا مِنْ الْبَابِ ثُمَّ تَقَنَّعَ بِثَوْبِهِ كَأَنَّهُ يَقْضِي حَاجَةً وَقَدْ دَخَلَ النَّاسُ فَهَتَفَ بِهِ الْبَوَّابُ يَا عَبْدَ اللَّهِ إِنْ كُنْتَ تُرِيدُ أَنْ تَدْخُلَ فَادْخُلْ فَإِنِّي أُرِيدُ أَنْ أُغْلِقَ الْبَابَ فَدَخَلْتُ فَكَمَنْتُ فَلَمَّا دَخَلَ النَّاسُ أَغْلَقَ الْبَابَ ثُمَّ عَلَّقَ الْأَغَالِيقَ عَلَى وَتَدٍ قَالَ فَقُمْتُ إِلَى الْأَقَالِيدِ فَأَخَذْتُهَا فَفَتَحْتُ الْبَابَ وَكَانَ أَبُو رَافِعٍ يُسْمَرُ عِنْدَهُ وَكَانَ فِي عَلَالِيَّ لَهُ فَلَمَّا ذَهَبَ عَنْهُ أَهْلُ سَمَرِهِ صَعِدْتُ إِلَيْهِ فَجَعَلْتُ كُلَّمَا فَتَحْتُ بَابًا أَغْلَقْتُ عَلَيَّ مِنْ دَاخِلٍ قُلْتُ إِنْ الْقَوْمُ نَذِرُوا بِي لَمْ يَخْلُصُوا إِلَيَّ حَتَّى أَقْتُلَهُ فَانْتَهَيْتُ إِلَيْهِ فَإِذَا هُوَ فِي بَيْتٍ مُظْلِمٍ وَسْطَ عِيَالِهِ لَا أَدْرِي أَيْنَ هُوَ مِنْ الْبَيْتِ فَقُلْتُ يَا أَبَا رَافِعٍ قَالَ مَنْ هَذَا فَأَهْوَيْتُ نَحْوَ الصَّوْتِ فَأَضْرِبُهُ ضَرْبَةً بِالسَّيْفِ وَأَنَا دَهِشٌ فَمَا أَغْنَيْتُ شَيْئًا وَصَاحَ فَخَرَجْتُ مِنْ الْبَيْتِ فَأَمْكُثُ غَيْرَ بَعِيدٍ ثُمَّ دَخَلْتُ إِلَيْهِ فَقُلْتُ مَا هَذَا الصَّوْتُ يَا أَبَا رَافِعٍ فَقَالَ لِأُمِّكَ الْوَيْلُ إِنَّ رَجُلًا فِي الْبَيْتِ ضَرَبَنِي قَبْلُ بِالسَّيْفِ قَالَ فَأَضْرِبُهُ ضَرْبَةً أَثْخَنَتْهُ وَلَمْ أَقْتُلْهُ ثُمَّ وَضَعْتُ ظِبَةَ السَّيْفِ فِي بَطْنِهِ حَتَّى أَخَذَ فِي ظَهْرِهِ فَعَرَفْتُ أَنِّي قَتَلْتُهُ فَجَعَلْتُ أَفْتَحُ الْأَبْوَابَ بَابًا بَابًا حَتَّى انْتَهَيْتُ إِلَى دَرَجَةٍ لَهُ فَوَضَعْتُ رِجْلِي وَأَنَا أُرَى أَنِّي قَدْ انْتَهَيْتُ إِلَى الْأَرْضِ فَوَقَعْتُ فِي لَيْلَةٍ مُقْمِرَةٍ فَانْكَسَرَتْ سَاقِي فَعَصَبْتُهَا بِعِمَامَةٍ ثُمَّ انْطَلَقْتُ حَتَّى جَلَسْتُ عَلَى الْبَابِ فَقُلْتُ لَا أَخْرُجُ اللَّيْلَةَ حَتَّى أَعْلَمَ أَقَتَلْتُهُ فَلَمَّا صَاحَ الدِّيكُ قَامَ النَّاعِي عَلَى السُّورِ فَقَالَ أَنْعَى أَبَا رَافِعٍ تَاجِرَ أَهْلِ الْحِجَازِ فَانْطَلَقْتُ إِلَى أَصْحَابِي فَقُلْتُ النَّجَاءَ فَقَدْ قَتَلَ اللَّهُ أَبَا رَافِعٍ فَانْتَهَيْتُ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَحَدَّثْتُهُ فَقَالَ ابْسُطْ رِجْلَكَ فَبَسَطْتُ رِجْلِي فَمَسَحَهَا فَكَأَنَّهَا لَمْ أَشْتَكِهَا قَطُّ","id":"Telah menceritakan kepada kami [Yusuf bin Musa] telah menceritakan kepada kami ['Ubaidullah bin Musa] dari [Israil] dari [Abu Ishaq] dari [Al Barra bin 'Azib] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam pernah mengutus beberapa sahabat Anshar kepada seorang Yahudi bernama Abu Rafi', dan beliau menunjuk Abdullah bin 'Atik untuk memimpin mereka. Abu Rafi' adalah seorang laki-laki yang selalu menyakiti Rasulullah shallallahu 'alaihi wasallam dan membantu musuh untuk menyerang beliau, dia tengah berada di bentengnya yang berada di wilayah Hijaz. Ketika para sahabat tersebut telah dekat dengan (bentengnya) -yaitu ketika matahari hampir terbenam dan orang-orang telah kembali dari gembalaannya-, maka Abdullah berkata kepada para sahabatnya, \"Diamlah kalian di tempat kalian masing-masing, sesungguhnya aku akan berusaha masuk tanpa sepengetahuan penjaga pintu, mudah-mudahan aku bisa masuk.\" Setelah itu dia pergi hingga mendekati pintu (gerbang), ia menutup kepalanya seolah-olah orang yang sedang buang hajat. Ketika orang-orang telah masuk, maka penjaga pintu berkata kepadanya, \"Wahai Abdullah, jika kamu ingin masuk, maka masuklah, sesungguhnya aku akan menutup pintu gerbang.\" Lalu aku masuk dan bersembunyi, ketika orang-orang telah masuk, pintu gerbang pun ditutup, kemudian kunci pintu gerbang digantungkan di atas gantungan kunci.\" Abdullah berkata, \"Lalu aku bangun ke tempat mereka meletakkan gantungan kunci, aku pun megambilnya, dengan cepat aku membuka pintu gerbang. Sementara itu Abu Rafi' sedang bergadang bersama orang-orang, yaitu dalam sebuah kamar miliknya di tempat yang agak tinggi. Ketika orang-orang yang bergadang bersamanya telah pulang, aku langsung naik ke rumahnya, setiap kali aku membuka pintu, maka aku langsung menutupnya dari dalam, aku berujar, \"Jika mereka memergokiku, maka mereka tidak akan menemukanku hingga aku berhasil membunuhnya.\" Lalu aku mendapatinya ia berada di tengah keluarganya, yaitu di rumah yang sangat gelap, sampai aku tidak tahu dimanakah dia berada.\" Aku pun berseru, \"Wahai Abu Rafi'!\" dia berkata, \"Siapakah itu?\" ia lalu bergerak ke arah suara, dan aku langsung menebasnya dengan pedang, karena saat itu aku sangat gugup, maka tebasanku tidak sampai membunuhnya dan ia berteriak sekeras-kerasnya. Lalu aku keluar dari rumah dan aku menunggu dari luar tidak terlalu jauh, kemudian aku masuk menemuinya kembali. Aku bertanya, \"Aku mendengarmu berteriak, ada apa sebenarnya wahai Abu Rafi'?\" dia menjawab, \"Kecelakaan bagi ibumu! Sungguh, seseorang masuk ke dalam rumahku dan berusaha menebasku dengan pedang.\" Abdullah berkata, \"Kemudian aku kembali menebasnya hingga ia terluka parah, namun aku belum sempat membunuhnya, kemudian aku tusukkan pedang ke perutnya hingga tembus ke punggungnya, setelah itu aku yakin bahwa aku telah membunuhnya. Kemudian aku pergi lewat pintu demi pintu hingga aku sampai ke anak tangga hingga kakiku merasa telah menyentuh permukaan tanah. Dan pada malam itu aku terjatuh di malam yang cahaya bulan sangat terang, dan kakiku pun patah, kemudian aku pun membalutnya dengan kain surbanku. Setelah itu aku pergi perlahan sampai aku duduk di depan pintu gerbang, aku berkata kepada sahabat-sahabatku, \"Aku tidak akan keluar dari benteng ini sampai aku tahu bila aku benar-benar telah membunuhnya.\" Ketika ayam jantan mulai berkokok, seseorang pembawa berita kematian berdiri dan berkata, \"Aku umumkan bahwa Abu Rafi', saudagar dari Hijaz telah meninggal dunia.\" Lalu aku menemui sahabat-sahabatku dan berkata, \"Mari kita pergi menyelamatkan diri, karena Allah telah membunuh Abu Rafi'.\" Setelah sampai di hadapan Nabi shallallahu 'alaihi wasallam hal itu pun aku beritahukan kepada beliau, lantas beliau pun bersabda: \"Bentangkanlah kakimu.\" Lalu aku membentangkannya, lalu beliau mengusapnya, seakan-akan kakiku tidak merasakan sakit.\" "},"3535":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ عُثْمَانَ حَدَّثَنَا شُرَيْحٌ هُوَ ابْنُ مَسْلَمَةَ حَدَّثَنَا إِبْرَاهِيمُ بْنُ يُوسُفَ عَنْ أَبِيهِ عَنْ أَبِي إِسْحَاقَ قَالَ سَمِعْتُ الْبَرَاءَ بْنَ عَازِبٍ رَضِيَ اللَّهُ عَنْهُ قَالَبَعَثَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى أَبِي رَافِعٍ عَبْدَ اللَّهِ بْنَ عَتِيكٍ وَعَبْدَ اللَّهِ بْنَ عُتْبَةَ فِي نَاسٍ مَعَهُمْ فَانْطَلَقُوا حَتَّى دَنَوْا مِنْ الْحِصْنِ فَقَالَ لَهُمْ عَبْدُ اللَّهِ بْنُ عَتِيكٍ امْكُثُوا أَنْتُمْ حَتَّى أَنْطَلِقَ أَنَا فَأَنْظُرَ قَالَ فَتَلَطَّفْتُ أَنْ أَدْخُلَ الْحِصْنَ فَفَقَدُوا حِمَارًا لَهُمْ قَالَ فَخَرَجُوا بِقَبَسٍ يَطْلُبُونَهُ قَالَ فَخَشِيتُ أَنْ أُعْرَفَ قَالَ فَغَطَّيْتُ رَأْسِي وَجَلَسْتُ كَأَنِّي أَقْضِي حَاجَةً ثُمَّ نَادَى صَاحِبُ الْبَابِ مَنْ أَرَادَ أَنْ يَدْخُلَ فَلْيَدْخُلْ قَبْلَ أَنْ أُغْلِقَهُ فَدَخَلْتُ ثُمَّ اخْتَبَأْتُ فِي مَرْبِطِ حِمَارٍ عِنْدَ بَابِ الْحِصْنِ فَتَعَشَّوْا عِنْدَ أَبِي رَافِعٍ وَتَحَدَّثُوا حَتَّى ذَهَبَتْ سَاعَةٌ مِنْ اللَّيْلِ ثُمَّ رَجَعُوا إِلَى بُيُوتِهِمْ فَلَمَّا هَدَأَتْ الْأَصْوَاتُ وَلَا أَسْمَعُ حَرَكَةً خَرَجْتُ قَالَ وَرَأَيْتُ صَاحِبَ الْبَابِ حَيْثُ وَضَعَ مِفْتَاحَ الْحِصْنِ فِي كَوَّةٍ فَأَخَذْتُهُ فَفَتَحْتُ بِهِ بَابَ الْحِصْنِ قَالَ قُلْتُ إِنْ نَذِرَ بِي الْقَوْمُ انْطَلَقْتُ عَلَى مَهَلٍ ثُمَّ عَمَدْتُ إِلَى أَبْوَابِ بُيُوتِهِمْ فَغَلَّقْتُهَا عَلَيْهِمْ مِنْ ظَاهِرٍ ثُمَّ صَعِدْتُ إِلَى أَبِي رَافِعٍ فِي سُلَّمٍ فَإِذَا الْبَيْتُ مُظْلِمٌ قَدْ طَفِئَ سِرَاجُهُ فَلَمْ أَدْرِ أَيْنَ الرَّجُلُ فَقُلْتُ يَا أَبَا رَافِعٍ قَالَ مَنْ هَذَا قَالَ فَعَمَدْتُ نَحْوَ الصَّوْتِ فَأَضْرِبُهُ وَصَاحَ فَلَمْ تُغْنِ شَيْئًا قَالَ ثُمَّ جِئْتُ كَأَنِّي أُغِيثُهُ فَقُلْتُ مَا لَكَ يَا أَبَا رَافِعٍ وَغَيَّرْتُ صَوْتِي فَقَالَ أَلَا أُعْجِبُكَ لِأُمِّكَ الْوَيْلُ دَخَلَ عَلَيَّ رَجُلٌ فَضَرَبَنِي بِالسَّيْفِ قَالَ فَعَمَدْتُ لَهُ أَيْضًا فَأَضْرِبُهُ أُخْرَى فَلَمْ تُغْنِ شَيْئًا فَصَاحَ وَقَامَ أَهْلُهُ قَالَ ثُمَّ جِئْتُ وَغَيَّرْتُ صَوْتِي كَهَيْئَةِ الْمُغِيثِ فَإِذَا هُوَ مُسْتَلْقٍ عَلَى ظَهْرِهِ فَأَضَعُ السَّيْفَ فِي بَطْنِهِ ثُمَّ أَنْكَفِئُ عَلَيْهِ حَتَّى سَمِعْتُ صَوْتَ الْعَظْمِ ثُمَّ خَرَجْتُ دَهِشًا حَتَّى أَتَيْتُ السُّلَّمَ أُرِيدُ أَنْ أَنْزِلَ فَأَسْقُطُ مِنْهُ فَانْخَلَعَتْ رِجْلِي فَعَصَبْتُهَا ثُمَّ أَتَيْتُ أَصْحَابِي أَحْجُلُ فَقُلْتُ انْطَلِقُوا فَبَشِّرُوا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَإِنِّي لَا أَبْرَحُ حَتَّى أَسْمَعَ النَّاعِيَةَ فَلَمَّا كَانَ فِي وَجْهِ الصُّبْحِ صَعِدَ النَّاعِيَةُ فَقَالَ أَنْعَى أَبَا رَافِعٍ قَالَ فَقُمْتُ أَمْشِي مَا بِي قَلَبَةٌ فَأَدْرَكْتُ أَصْحَابِي قَبْلَ أَنْ يَأْتُوا النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَبَشَّرْتُهُ","id":"Telah menceritakan kepada kami [Ahmad bin Utsman] telah menceritakan kepada kami [Syuraikh] -yaitu Ibnu Maslamah- telah menceritakan kepada kami [Ibrahim bin Yusuf] dari [Ayahnya] dari [Abu Ishaq] dia berkata, aku mendengar [Al Barra bin 'Azib] radliallahu 'anhu, dia berkata, \"Rasulullah shallallahu 'alaihi wasallam pernah mengutus beberapa orang, sementara Abdullah bin Atik dan Abdullah bin 'Utbah ikut bersama mereka. Kemudian mereka berangkat hingga mendekati benteng pertahanan, Abdullah bin 'Atik lalu berkata kepada mereka, \"Diamlah kalian di sini, aku akan berusaha masuk (benteng) dan mengintai mereka.\" Abdullah bin 'Atik melanjutkan, \"Maka aku bergerak mendekati supaya bisa masuk benteng, ternyata mereka kehilangan keledai-keledai mereka, lalu mereka keluar (benteng) sambil membawa lentera untuk mecarinya. Karena khawatir ketahuan, maka aku pun menutup kepalaku dan duduk seolah-olah seperti orang yang sedang buang hajat. Penjaga pintu (mereka) berseru, \"Barangsiapa ingin masuk, masuklah, sebelum kami menutup pintu.\" Aku langsung masuk dan bersembunyi di kandang keledai persis di samping pintu gerbang. Ternyata orang-orang tengah makan malam bersama Abu Rafi', mereka berbincang-bincang hinga larut malam, setelah itu mereka kembali ke rumah mereka masing-masing. Ketika keadaan menjadi lengang dan aku tidak lagi mendengarkan adanya gerakan, akupun keluar.\" Abdullah melanjutkan, \"Aku sempat melihat penjaga pintu meletakkan kunci gerbang di lubang dinding, aku langsung megambilnya dan membuka pintu gerbang.\" Abdullah berkata, \"Aku sempat berkata, \"Sekiranya orang-orang memergokiku, maka aku akan bergerak mengendap-endap.\" Setelah itu aku menuju ke pintu rumah-rumah mereka dan menutup pintu dari dalam, aku lalu naik ke rumah Abu Rafi' melalui tangga, dan ternyata rumahnya sangat gelap sebab lampu-lampunya telah dipadamkan, hingga aku tidak tahu dimanakah posisi Abu Rafi' berada. Aku kemudian berseru, \"Wahai Abu Rafi'!\" dia menyahut, \"Siapa itu?\", dia kemudian pergi menuju sumber suara, dan aku pun langsung menebasnya, namun tebasanku tidak berpengaruh apa-apa hingga dia dapat berteriak.\" Abdullah melanjutkan perkataannya, \"Setelah itu aku menemuinya kembali seolah-olah aku baru saja bangun tidur, aku (pura-pura) bertanya, \"Kenapa denganmu wahai Abu Rafi'?\" -ketika itu aku merubah suaraku- dia menjawab, \"Celaka, aku heran ada seseorang yang masuk dan ingin menebasku dengan pedang.\" Kemudian aku menghadapnya dan langsung menebasnya sekali lagi, namun tidak sampai membunuhnya, dia langsung berteriak hingga isterinya terbangun.\" Abdullah melanjutkan, \"Aku merubah suaraku, seperti orang yang baru saja bangun tidur, ternyata Abu Rafi' telah terlentang, aku langsung menusukkan pedang ke perutnya hingga tembus ke punggungnya, lalu aku putar (pedang tersebut) hingga aku mendengar suara tulangnya, setelah itu aku keluar dengan sempoyongan sampai tiba ditangga. Saat aku hendak turun (lewat anak tangga), aku terjatuh hingga kakiku cidera. Setelah membalut kakiku yang terluka, aku kemudian menemui para sahabatku dengan berjalan pincang, kukatakan kepada mereka, \"Pergi dan sampikanlah berita ini kepada Rasulullah shallallahu 'alaihi wasallam, sungguh aku akan tetap di sini sampai aku mendengar langsung orang yang mengumumkan berita kematian.\" Ketika waktu subuh tiba, seorang pembawa berita kematian naik ke tempat yang agak tinggi dan berseru, \"Aku umumkan kematian Abu Rafi'.\" Lalu aku berdiri dan berjalan tanpa ada sedikitpun ganjalan di hatiku, aku menjumpai para sahabatku sebelum mereka datang menemui Nabi shallallahu 'alaihi wasallam, lalu aku memberitahukan kabar gembira ini kepada beliau.\""},"3536":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ مُوسَى أَخْبَرَنَا عَبْدُ الْوَهَّابِ حَدَّثَنَا خَالِدٌ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ أُحُدٍ هَذَا جِبْرِيلُ آخِذٌ بِرَأْسِ فَرَسِهِ عَلَيْهِ أَدَاةُ الْحَرْبِ","id":"Telah menceritakan kepada kami [Ibrahim bin Musa] telah mengabarkan kepada kami [Abdul Wahhab] telah menceritakan kepada kami [Khalid] dari [Ikrimah] dari [Ibnu Abbas] radliallahu 'anhuma, dia berkata, \"Nabi shallallahu 'alaihi wasallam bersabda pada perang Uhud: \"Ini Jibril, ia sedang memegang kepala kudanya yang dilengkapi dengan peralatan perang.\""},"3537":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ الرَّحِيمِ أَخْبَرَنَا زَكَرِيَّاءُ بْنُ عَدِيٍّ أَخْبَرَنَا ابْنُ الْمُبَارَكِ عَنْ حَيْوَةَ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ عَنْ أَبِي الْخَيْرِ عَنْ عُقْبَةَ بْنِ عَامِرٍ قَالَصَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى قَتْلَى أُحُدٍ بَعْدَ ثَمَانِي سِنِينَ كَالْمُوَدِّعِ لِلْأَحْيَاءِ وَالْأَمْوَاتِ ثُمَّ طَلَعَ الْمِنْبَرَ فَقَالَ إِنِّي بَيْنَ أَيْدِيكُمْ فَرَطٌ وَأَنَا عَلَيْكُمْ شَهِيدٌ وَإِنَّ مَوْعِدَكُمْ الْحَوْضُ وَإِنِّي لَأَنْظُرُ إِلَيْهِ مِنْ مَقَامِي هَذَا وَإِنِّي لَسْتُ أَخْشَى عَلَيْكُمْ أَنْ تُشْرِكُوا وَلَكِنِّي أَخْشَى عَلَيْكُمْ الدُّنْيَا أَنْ تَنَافَسُوهَا قَالَ فَكَانَتْ آخِرَ نَظْرَةٍ نَظَرْتُهَا إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Muhammad bin Abdurrahim] telah mengabarkan kepada kami [Zakariya bin 'Adi] telah mengabarkan kepada kami [Ibnu Al Mubarrak] dari [Haiwah] dari [Yazid bin Abu Habib] dari [Abu Al Khair] dari ['Uqbah bin 'Amir] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam menshalati para korban Uhud setelah delapan tahun, seolah-olah seperti perpisahan antara orang yang hidup dengan orang yang telah mati. Kemudian beliau naik mimbar seraya bersabda: \"Sesungguhnya aku mendahului kalian, dan aku adalah saksi atas kalian. Sungguh, yang dijanjikan bagi kalian adalah telaga, dan aku benar-benar telah melihatnya di tempatku ini. Aku tidak lebih khawatir terhadap syirik yang kalian perbuat, akan tetapi aku sangat khawatir terhadap dunia yang akan kalian perebutkan.\" 'Uqbah berkata, \"Dan itu adalah terakhir kali aku melihat Rasulullah shallallahu 'alaihi wasallam.\""},"3538":{"ar":"حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى عَنْ إِسْرَائِيلَ عَنْ أَبِي إِسْحَاقَ عَنْ الْبَرَاءِ رَضِيَ اللَّهُ عَنْهُ قَالَلَقِينَا الْمُشْرِكِينَ يَوْمَئِذٍ وَأَجْلَسَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جَيْشًا مِنْ الرُّمَاةِ وَأَمَّرَ عَلَيْهِمْ عَبْدَ اللَّهِ وَقَالَ لَا تَبْرَحُوا إِنْ رَأَيْتُمُونَا ظَهَرْنَا عَلَيْهِمْ فَلَا تَبْرَحُوا وَإِنْ رَأَيْتُمُوهُمْ ظَهَرُوا عَلَيْنَا فَلَا تُعِينُونَا فَلَمَّا لَقِينَا هَرَبُوا حَتَّى رَأَيْتُ النِّسَاءَ يَشْتَدِدْنَ فِي الْجَبَلِ رَفَعْنَ عَنْ سُوقِهِنَّ قَدْ بَدَتْ خَلَاخِلُهُنَّ فَأَخَذُوا يَقُولُونَ الْغَنِيمَةَ الْغَنِيمَةَ فَقَالَ عَبْدُ اللَّهِ عَهِدَ إِلَيَّ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ لَا تَبْرَحُوا فَأَبَوْا فَلَمَّا أَبَوْا صُرِفَ وُجُوهُهُمْ فَأُصِيبَ سَبْعُونَ قَتِيلًا وَأَشْرَفَ أَبُو سُفْيَانَ فَقَالَ أَفِي الْقَوْمِ مُحَمَّدٌ فَقَالَ لَا تُجِيبُوهُ فَقَالَ أَفِي الْقَوْمِ ابْنُ أَبِي قُحَافَةَ قَالَ لَا تُجِيبُوهُ فَقَالَ أَفِي الْقَوْمِ ابْنُ الْخَطَّابِ فَقَالَ إِنَّ هَؤُلَاءِ قُتِلُوا فَلَوْ كَانُوا أَحْيَاءً لَأَجَابُوا فَلَمْ يَمْلِكْ عُمَرُ نَفْسَهُ فَقَالَ كَذَبْتَ يَا عَدُوَّ اللَّهِ أَبْقَى اللَّهُ عَلَيْكَ مَا يُخْزِيكَ قَالَ أَبُو سُفْيَانَ اعْلُ هُبَلُ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَجِيبُوهُ قَالُوا مَا نَقُولُ قَالَ قُولُوا اللَّهُ أَعْلَى وَأَجَلُّ قَالَ أَبُو سُفْيَانَ لَنَا الْعُزَّى وَلَا عُزَّى لَكُمْ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَجِيبُوهُ قَالُوا مَا نَقُولُ قَالَ قُولُوا اللَّهُ مَوْلَانَا وَلَا مَوْلَى لَكُمْ قَالَ أَبُو سُفْيَانَ يَوْمٌ بِيَوْمِ بَدْرٍ وَالْحَرْبُ سِجَالٌ وَتَجِدُونَ مُثْلَةً لَمْ آمُرْ بِهَا وَلَمْ تَسُؤْنِي","id":"Telah menceritakan kepada kami ['Ubaidullah bin Musa] dari [Israil] dari [Abu Ishaq] dari [Al Barra] radliallahu 'anhu, dia berkata, \"Suatu ketika kami bertemu pasukan Musyrikin, lalu Nabi shallallahu 'alaihi wasallam menempatkan pasukan pemanah di bawah komando Abdullah. Beliau berpesan: \"Diamlah kalian di sini, walaupun kalian melihat kami menang atas mereka, janganlah kalian meninggalkan tempat ini, dan jika kalian melihat kami kalah, janganlah kalian (pindah tempat) untuk menolong kami.\" Ketika perang mulai berkecamuk, maka pasukan musuh dapat dipukul mundur hingga aku melihat para wanita berlarian ke gunung hingga tersingkap betis mereka dan tampaklah gelang kaki mereka. Lalu kaum Muslimin (pasukan pemanah) berebut mengambil (ghanimah) sambil berkata, \"Ghanimah, ghanimah!\" Abdullah pun akhirnya berteriak, \"Nabi shallallahu 'alaihi wasallam telah berpesan, janganlah kalian meninggalkan tempat kalian!\" Namun mereka tidak peduli, ketika mereka tidak memperdulikan wasiat Nabi, maka wajah mereka menjadi terseret (kocar kacir) hingga menyebabkan tujuh puluh sahabat gugur, kemudian Abu Sufyan naik ke tempat yang tinggi dan berseru, \"Apakah di antara kalian ada Muhammad?\" beliau bersabda: \"Jangan dijawab.\" Abu Sufyan kembali bertanya, \"Apakah di antara kalian terdapat Abu Quhafah?\" Beliau bersabda: \"Jangan dijawab.\" Dia kembali bertanya, \"Apakah di antara kalian terdapat Ibnul Khattab?\" Abu Sufyan melanjutkan, \"Sesungguhnya mereka telah tewas, sekiranya mereka masih hidup, tentu mereka akan menjawabnya.\" Ternyata Umar tidak dapat menahan dirinya dan berkata, \"Kamu telah berdusta wahai musuh Allah, Allah akan tetap membuat kalian terhina.\" Abu Sufyan berkata, \"Tinggilah Hubal.\" Maka Nabi shallallahu 'alaihi wasallam bersabda: \"Jawablah.\" Para sahabat bertanya, \"Apa yang harus kami katakan?\" Beliau bersabda: \"Katakanlah, 'Allah lebih tinggi dan lebih mulia'.\" Abu Sufyan kemudian berkata, \"Kami memiliki 'Uzza sementara kalian tidak memilikinya.\" Maka Nabi shallallahu 'alaihi wasallam bersabda: \"Jawablah.\" Para sahabat bertanya, \"Apa yang harus kami katakan?\" Beliau bersabda: \"Katakanlah, 'Allah adalah penolong kami dan kalian tidak memiliki penolong'.\" Abu Sufyan kembali berkata, \"Hari ini adalah hari pembalasan untuk hari Badr, dan perang silih berganti, dan kalian akan menemukan penyincangan yang tidak aku perintahkan, namun aku tidak membencinya.\""},"3539":{"ar":"أَخْبَرَنِي عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ حَدَّثَنَا سُفْيَانُ عَنْ عَمْرٍو عَنْ جَابِرٍ قَالَاصْطَبَحَ الْخَمْرَ يَوْمَ أُحُدٍ نَاسٌ ثُمَّ قُتِلُوا شُهَدَاءَ","id":"Telah menceritakan kepadaku [Abdullah bin Muhammad] telah menceritakan kepada kami [Sufyan] dari ['Amru] dari [Jabir] dia berkata, \"Para sahabat pernah membuat khamer pada saat perang Uhud, lalu mereka gugur sebagai syuhada.\" (hal itu terjadi sebelum pengharaman khamer -pent)."},"3540":{"ar":"حَدَّثَنَا عَبْدَانُ حَدَّثَنَا عَبْدُ اللَّهِ أَخْبَرَنَا شُعْبَةُ عَنْ سَعْدِ بْنِ إِبْرَاهِيمَ عَنْ أَبِيهِ إِبْرَاهِيمَ أَنَّ عَبْدَ الرَّحْمَنِ بْنَ عَوْفٍأُتِيَ بِطَعَامٍ وَكَانَ صَائِمًا فَقَالَ قُتِلَ مُصْعَبُ بْنُ عُمَيْرٍ وَهُوَ خَيْرٌ مِنِّي كُفِّنَ فِي بُرْدَةٍ إِنْ غُطِّيَ رَأْسُهُ بَدَتْ رِجْلَاهُ وَإِنْ غُطِّيَ رِجْلَاهُ بَدَا رَأْسُهُ وَأُرَاهُ قَالَ وَقُتِلَ حَمْزَةُ وَهُوَ خَيْرٌ مِنِّي ثُمَّ بُسِطَ لَنَا مِنْ الدُّنْيَا مَا بُسِطَ أَوْ قَالَ أُعْطِينَا مِنْ الدُّنْيَا مَا أُعْطِينَا وَقَدْ خَشِينَا أَنْ تَكُونَ حَسَنَاتُنَا عُجِّلَتْ لَنَا ثُمَّ جَعَلَ يَبْكِي حَتَّى تَرَكَ الطَّعَامَ","id":"Telah menceritakan kepada kami ['Abdan] telah menceritakan kepada kami [Abdullah] telah mengabarkan kepada kami [Syu'bah] dari [Sa'd bin Ibrahim] dari ayahnya [Ibrahim] bahwa saat [Abdurrahman bin 'Auf] sedang berpusa ia pernah diberi hidangan makanan, kemudiandia berkata, \"Muhs'ab bin 'Umari telah gugur, padahal dia lebih mulia daripadaku, dia di kafani dengan kain burdah, apabila kepalanya ditutup maka kakinya akan tersingkap, dan jika kakinya ditutup maka kepalanya akan tersingkap. -dan seingatku dia mengatakan- Hamzah gugur padahal dia lebih baik daripadaku, setelah itu (kenikmatan) dunia dibentangkan untuk kami -atau dia mengatakan-, Kami telah diberi (kenikmatan) dunia sebagaimana yang telah diberikan kepada kami, aku khawatir bahwa itu adalah (balasan) kebaikan kami yang didahulukan, \" kemudian ia menangis dan meninggalkan hidangan tersebut.\""},"3541":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ حَدَّثَنَا سُفْيَانُ عَنْ عَمْرٍو سَمِعَ جَابِرَ بْنَ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُمَا قَالَقَالَ رَجُلٌ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ أُحُدٍ أَرَأَيْتَ إِنْ قُتِلْتُ فَأَيْنَ أَنَا قَالَ فِي الْجَنَّةِ فَأَلْقَى تَمَرَاتٍ فِي يَدِهِ ثُمَّ قَاتَلَ حَتَّى قُتِلَ","id":"Telah menceritakan kepada kami [Abdullah bin Muhammad] telah menceritakan kepada kami [Sufyan] dari ['Amru] dia mendengar [Jabir bin Abdullah] radliallahu 'anhuma dia berkata, \"Seorang laki-laki berkata kepada Nabi shallallahu 'alaihi wasallam pada perang Uhud, \"Bagaimana menurutmu, jika aku mati terbunuh, dimanakah tempatku?\" beliau menjawab: \"Di surga.\" Mendengar itu, dia langsung melempar kurma yang ada di tangannya, kemudian dia berperang hingga terbunuh.\""},"3542":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ يُونُسَ حَدَّثَنَا زُهَيْرٌ حَدَّثَنَا الْأَعْمَشُ عَنْ شَقِيقٍ عَنْ خَبَّابِ بْنِ الْأَرَتِّ رَضِيَ اللَّهُ عَنْهُ قَالَهَاجَرْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَبْتَغِي وَجْهَ اللَّهِ فَوَجَبَ أَجْرُنَا عَلَى اللَّهِ وَمِنَّا مَنْ مَضَى أَوْ ذَهَبَ لَمْ يَأْكُلْ مِنْ أَجْرِهِ شَيْئًا كَانَ مِنْهُمْ مُصْعَبُ بْنُ عُمَيْرٍ قُتِلَ يَوْمَ أُحُدٍ لَمْ يَتْرُكْ إِلَّا نَمِرَةً كُنَّا إِذَا غَطَّيْنَا بِهَا رَأْسَهُ خَرَجَتْ رِجْلَاهُ وَإِذَا غُطِّيَ بِهَا رِجْلَاهُ خَرَجَ رَأْسُهُ فَقَالَ لَنَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ غَطُّوا بِهَا رَأْسَهُ وَاجْعَلُوا عَلَى رِجْلِهِ الْإِذْخِرَ أَوْ قَالَ أَلْقُوا عَلَى رِجْلِهِ مِنْ الْإِذْخِرِ وَمِنَّا مَنْ قَدْ أَيْنَعَتْ لَهُ ثَمَرَتُهُ فَهُوَ يَهْدِبُهَا","id":"Telah menceritakan kepada kami [Ahmad bin Yunus] telah menceritakan kepada kami [Zuhair] telah menceritakan kepada kami [Al A'masy] dari [Syaqiq] dari [Khabbab bin Al Art] radliallahu 'anhu, dia berkata, \"Kami hijrah bersama Rasulullah shallallahu 'alaihi wasallam dengan mengharap ridla Allah, maka Allah memberi balasan kepada kami, diantara kami ada yang meninggal dan belum mendapatkan balasan (dunia) sedikitpun, di antaranya adalah Mush'ab bin Umair yang terbunuh pada perang Uhud, dan kami tidak mendapatkan sesuatu untuk mengkafaninya kecuali sepotong kain, jika kami menutup kepalanya, kedua kakinya tersingkap dan jika kami menutup kakinya, kepalanya tersingkap. Maka Nabi shallallahu 'alaihi wasallam bersabda: \"Tutuplah kepalanya dengan kain dan dan tutuplah kakinya dengan idzkhir (rumput-rumputan berbau harum), \" atau beliau mengatakan: \"Jadikanlah idzkhir untuk menutupi kakinya.\" Juga diantara kami ada yang telah memiliki buah yang masak dan ia memetiknya.\""},"3543":{"ar":"أَخْبَرَنَا حَسَّانُ بْنُ حَسَّانَ حَدَّثَنَا مُحَمَّدُ بْنُ طَلْحَةَ حَدَّثَنَا حُمَيْدٌ عَنْ أَنَسٍ رَضِيَ اللَّهُ عَنْهُأَنَّ عَمَّهُ غَابَ عَنْ بَدْرٍ فَقَالَ غِبْتُ عَنْ أَوَّلِ قِتَالِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَئِنْ أَشْهَدَنِي اللَّهُ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيَرَيَنَّ اللَّهُ مَا أُجِدُّ فَلَقِيَ يَوْمَ أُحُدٍ فَهُزِمَ النَّاسُ فَقَالَ اللَّهُمَّ إِنِّي أَعْتَذِرُ إِلَيْكَ مِمَّا صَنَعَ هَؤُلَاءِ يَعْنِي الْمُسْلِمِينَ وَأَبْرَأُ إِلَيْكَ مِمَّا جَاءَ بِهِ الْمُشْرِكُونَ فَتَقَدَّمَ بِسَيْفِهِ فَلَقِيَ سَعْدَ بْنَ مُعَاذٍ فَقَالَ أَيْنَ يَا سَعْدُ إِنِّي أَجِدُ رِيحَ الْجَنَّةِ دُونَ أُحُدٍ فَمَضَى فَقُتِلَ فَمَا عُرِفَ حَتَّى عَرَفَتْهُ أُخْتُهُ بِشَامَةٍ أَوْ بِبَنَانِهِ وَبِهِ بِضْعٌ وَثَمَانُونَ مِنْ طَعْنَةٍ وَضَرْبَةٍ وَرَمْيَةٍ بِسَهْمٍ","id":"Telah mengabarkan kepada kami [Hasan bin Hasan] telah menceritakan kepada kami [Muhammad bin Thalhah] telah menceritakan kepada kami [Humaid] dari [Anas] radliallahu 'anhu, bahwa pamannya tidak ikut serta dalam perang Badr, dia berkata, \"Aku tidak ikut awal peperangan yang dilakukan Nabi shallallahu 'alaihi wasallam, sekiranya Allah memberiku kesempatan untuk ikut serta (berperang) bersama Nabi shallallahu 'alaihi wasallam, maka Allah akan melihatku apa yang akan kulakukan.\" Lalu dia menjumpai perang Uhud, ketika itu orang-orang porak poranda. Maka paman Anas berkata, \"Ya Allah, aku minta permaafan dari yang mereka lakukan -maksudnya para sahabatnya-, dan aku serahkan kepada-Mu apa yang diperbuat oleh orang-orang musyrik.\" Lalu ia maju dengan sebilah pedangnya hingga ia bertemu Sa'ad bin Mu'adz, dia lalu berujar, \"Dimanakah wahai Sa'd, sungguh aku mendapati bau surga di belakang Uhud.\" Saat perang usai, ia terbunuh, dan tidak ada yang mengenali jasadnya selain saudara perempuannya dengan tanda atau jari-jemari yang ada pada dirinya, dan didapati (dalam jasadnya) sebanyak delapan puluh lebih tikaman tombak, sabetan pedang, dan tusukan panah.\""},"3544":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ حَدَّثَنَا إِبْرَاهِيمُ بْنُ سَعْدٍ حَدَّثَنَا ابْنُ شِهَابٍ أَخْبَرَنِي خَارِجَةُ بْنُ زَيْدِ بْنِ ثَابِتٍ أَنَّهُ سَمِعَ زَيْدَ بْنَ ثَابِتٍ رَضِيَ اللَّهُ عَنْهُ يَقُولُفَقَدْتُ آيَةً مِنْ الْأَحْزَابِ حِينَ نَسَخْنَا الْمُصْحَفَ كُنْتُ أَسْمَعُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْرَأُ بِهَا فَالْتَمَسْنَاهَا فَوَجَدْنَاهَا مَعَ خُزَيْمَةَ بْنِ ثَابِتٍ الْأَنْصَارِيِّ{ مِنْ الْمُؤْمِنِينَ رِجَالٌ صَدَقُوا مَا عَاهَدُوا اللَّهَ عَلَيْهِ فَمِنْهُمْ مَنْ قَضَى نَحْبَهُ وَمِنْهُمْ مَنْ يَنْتَظِرُ }فَأَلْحَقْنَاهَا فِي سُورَتِهَا فِي الْمُصْحَفِ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] telah menceritakan kepada kami [Ibrahim bin Sa'd] telah menceritakan kepada kami [Ibnu Syihab] telah mengabarkan kepadaku [Kharijah bin Zaid bin Tsabit] bahwa dia mendengar [Zaid bin Tsabit] radliallahu 'anhu berkata, \"Satu ayat hilang dari surat Al Ahzab saat kami menyalinnya ke dalam Mushhaf, padahal aku telah mendengarnya langsung dari Rasulullah shallallahu 'alaihi wasallam saat beliau membacanya. Lalu kami pun mencarinya, ternyata kami menemukannya pada Khuzaimah bin Tsabit Al Anshari. Yakni ayat: '(Di antara orang-orang Mukmin itu ada orang-orang yang menepati apa yang Telah mereka janjikan kepada Allah; Maka di antara mereka ada yang gugur. dan di antara mereka ada (pula) yang menunggu- nunggu) ' (Qs. Al Ahzab: 23), maka kami pun menggabungkannya di dalam Mushhaf.\""},"3545":{"ar":"حَدَّثَنَا أَبُو الْوَلِيدِ حَدَّثَنَا شُعْبَةُ عَنْ عَدِيِّ بْنِ ثَابِتٍ سَمِعْتُ عَبْدَ اللَّهِ بْنَ يَزِيدَ يُحَدِّثُ عَنْ زَيْدِ بْنِ ثَابِتٍ رَضِيَ اللَّهُ عَنْهُ قَالَلَمَّا خَرَجَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى أُحُدٍ رَجَعَ نَاسٌ مِمَّنْ خَرَجَ مَعَهُ وَكَانَ أَصْحَابُ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِرْقَتَيْنِ فِرْقَةً تَقُولُ نُقَاتِلُهُمْ وَفِرْقَةً تَقُولُ لَا نُقَاتِلُهُمْ فَنَزَلَتْ{ فَمَا لَكُمْ فِي الْمُنَافِقِينَ فِئَتَيْنِ وَاللَّهُ أَرْكَسَهُمْ بِمَا كَسَبُوا }وَقَالَ إِنَّهَا طَيْبَةُ تَنْفِي الذُّنُوبَ كَمَا تَنْفِي النَّارُ خَبَثَ الْفِضَّةِ","id":"Telah menceritakan kepada kami [Abu Al Walid] telah menceritakan kepada kami [Syu'bah] dari ['Adi bin Tsabit] aku mendengar [Abdullah bin Yazid] bercerita dari [Zaid bin Tsabit] radliallahu 'anhu, dia berkata, \"Ketika Nabi shallallahu 'alaihi wasallam berangkat ke medan Uhud, di tengah perjalanan beberapa orang yang ikut bersama beliau kembali pulang, dan sebab itu sahabat Nabi shallallahu 'alaihi wasallam terpecah menjadi dua kelompok; kelompok yang mengatakan, \"Kami akan memerangi mereka, \" dan kelompok yang mengatakan, \"Kami tidak akan memerangi mereka.\" Maka turunlah ayat: '(Maka Mengapa kamu (terpecah) menjadi dua golongan dalam (menghadapi) orang-orang munafik, padahal Allah Telah membalikkan mereka kepada kekafiran, disebabkan usaha mereka sendiri?) ' (Qs. An Nisaa: 88), beliau bersabda: \"Sesungguhnya hal itu terdapat suatu kebaikan, yang dapat menghapuskan dosa sebagaimana api menghilangkan karat pada perak.\""},"3546":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يُوسُفَ عَنْ ابْنِ عُيَيْنَةَ عَنْ عَمْرٍو عَنْ جَابِرٍ رَضِيَ اللَّهُ عَنْهُ قَالَنَزَلَتْ هَذِهِ الْآيَةُ فِينَا{ إِذْ هَمَّتْ طَائِفَتَانِ مِنْكُمْ أَنْ تَفْشَلَا }بَنِي سَلِمَةَ وَبَنِي حَارِثَةَ وَمَا أُحِبُّ أَنَّهَا لَمْ تَنْزِلْ وَاللَّهُ يَقُولُ{ وَاللَّهُ وَلِيُّهُمَا }","id":"Telah menceritakan kepada kami [Muhammad bin Yusuf] dari [Ibnu Uyainah] dari ['Amru] dari [Jabir] radliallahu 'anhu, dia berkata, \"Ayat ini turun kepada kami: '(Ketika dua golongan dari padamu ingin (mundur) Karena takut..) ' (Qs. Ali Imran: 122), yaitu bani Salimah dan Bani Haritsah, dan aku lebih suka jika ayat tersebut tidak turun, Allah berfirman: '(padahal Allah adalah penolong bagi kedua golongan itu) '."},"3547":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا سُفْيَانُ أَخْبَرَنَا عَمْرٌو عَنْ جَابِرٍ قَالَقَالَ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَلْ نَكَحْتَ يَا جَابِرُ قُلْتُ نَعَمْ قَالَ مَاذَا أَبِكْرًا أَمْ ثَيِّبًا قُلْتُ لَا بَلْ ثَيِّبًا قَالَ فَهَلَّا جَارِيَةً تُلَاعِبُكَ قُلْتُ يَا رَسُولَ اللَّهِ إِنَّ أَبِي قُتِلَ يَوْمَ أُحُدٍ وَتَرَكَ تِسْعَ بَنَاتٍ كُنَّ لِي تِسْعَ أَخَوَاتٍ فَكَرِهْتُ أَنْ أَجْمَعَ إِلَيْهِنَّ جَارِيَةً خَرْقَاءَ مِثْلَهُنَّ وَلَكِنْ امْرَأَةً تَمْشُطُهُنَّ وَتَقُومُ عَلَيْهِنَّ قَالَ أَصَبْتَ","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Sufyan] telah mengabarkan kepada kami ['Amru] dari [Jabir] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bertanya kepadaku: \"Apakah kamu sudah menikah wahai Jabir?\" aku menjawab, \"Ya, sudah.\" Beliau lalu bertanya: \"Kamu menikah dengan gadis ataukah janda?\" Aku menjawab, \"Dengan seorang janda.\" Beliau bertanya lagi: \"Kenapa tidak gadis saja, yang dapat mencumbumu?\" Aku menjawab, \"Wahai Rasulullah, sesungguhnya ayahku telah terbunuh pada perang uhud, sementara dia meninggalkan sembilan putri, jadi aku memiliki sembilan saudara perempuan, dan aku tidak suka jika aku bersama gadis yang sebaya dengan mereka, akan tetapi (aku lebih memilih) seseorang yang dapat merawat dan mendidik mereka.\" Beliau bersabda: \"Engkau benar.\""},"3548":{"ar":"حَدَّثَنِي أَحْمَدُ بْنُ أَبِي سُرَيْجٍ أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى حَدَّثَنَا شَيْبَانُ عَنْ فِرَاسٍ عَنْ الشَّعْبِيِّ قَالَ حَدَّثَنِي جَابِرُ بْنُ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ أَبَاهُ اسْتُشْهِدَ يَوْمَ أُحُدٍ وَتَرَكَ عَلَيْهِ دَيْنًا وَتَرَكَ سِتَّ بَنَاتٍ فَلَمَّا حَضَرَ جِزَازُ النَّخْلِ قَالَ أَتَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ قَدْ عَلِمْتَ أَنَّ وَالِدِي قَدْ اسْتُشْهِدَ يَوْمَ أُحُدٍ وَتَرَكَ دَيْنًا كَثِيرًا وَإِنِّي أُحِبُّ أَنْ يَرَاكَ الْغُرَمَاءُ فَقَالَ اذْهَبْ فَبَيْدِرْ كُلَّ تَمْرٍ عَلَى نَاحِيَةٍ فَفَعَلْتُ ثُمَّ دَعَوْتُهُ فَلَمَّا نَظَرُوا إِلَيْهِ كَأَنَّهُمْ أُغْرُوا بِي تِلْكَ السَّاعَةَ فَلَمَّا رَأَى مَا يَصْنَعُونَ أَطَافَ حَوْلَ أَعْظَمِهَا بَيْدَرًا ثَلَاثَ مَرَّاتٍ ثُمَّ جَلَسَ عَلَيْهِ ثُمَّ قَالَ ادْعُ لِي أَصْحَابَكَ فَمَا زَالَ يَكِيلُ لَهُمْ حَتَّى أَدَّى اللَّهُ عَنْ وَالِدِي أَمَانَتَهُ وَأَنَا أَرْضَى أَنْ يُؤَدِّيَ اللَّهُ أَمَانَةَ وَالِدِي وَلَا أَرْجِعَ إِلَى أَخَوَاتِي بِتَمْرَةٍ فَسَلَّمَ اللَّهُ الْبَيَادِرَ كُلَّهَا وَحَتَّى إِنِّي أَنْظُرُ إِلَى الْبَيْدَرِ الَّذِي كَانَ عَلَيْهِ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَأَنَّهَا لَمْ تَنْقُصْ تَمْرَةً وَاحِدَةً","id":"Telah menceritakan kepadaku [Ahmad bin Abu Suraij] telah mengabarkan kepada kami ['Ubaidullah bin Musa] telah menceritakan kepada kami [Syaiban] dari [Firas] dari [Asy Sya'bi] dia berkata, telah menceritakan kepadaku [Jabir bin Abdullah] radliallahu 'anhuma, bahwa ayahnya syahid pada perang Uhud dan meninggalkan hutang serta enam orang putri, ketika datang masa panen kurma Jabir berkata, \"Aku menemui Rasulullah shallallahu 'alaihi wasallam dan berkata, \"Wahai Rasulullah, anda mengetahui bahwa ayahku syahid pada perang Uhud, ia meninggalkan hutang yang banyak, dan aku ingin agar orang-orang yang memberi hutang melihatmu.\" Beliau bersabda: \"Pergi dan kumpulkanlah kurma-kurma disetiap ujung, \" lalu saya melakukannya, aku kemudian memanggil beliau, ketika mereka melihat beliau, seakan-akan mereka terus memintaku saat itu, ketika beliau melihat apa yang mereka perbuat, beliau mengelilingkan tempat menebah di sekitar tumpukan kurma yang paling banyak, sebanyak tiga kali, lalu beliau duduk di atasnya dan bersabda: \"Panggillah para sahabatmu, \" maka beliau masih menakar untuk mereka hingga Allah menunaikan amanat ayahku dan aku ridla jika Allah menunaikan amanat ayahku, (meski) aku kembali ke saudara-saudara perempuanku tanpa membawa kurma, lalu Allah memberikan tumpukan kurma semuanya, sehingga aku melihat pada tumpukan kurma yang ada di sisi Nabi shallallahu 'alaihi wasallam, seakan-akan tidak terkurangi satu kurmapun.\""},"3549":{"ar":"حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا إِبْرَاهِيمُ بْنُ سَعْدٍ عَنْ أَبِيهِ عَنْ جَدِّهِ عَنْ سَعْدِ بْنِ أَبِي وَقَّاصٍ رَضِيَ اللَّهُ عَنْهُ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ أُحُدٍ وَمَعَهُ رَجُلَانِ يُقَاتِلَانِ عَنْهُ عَلَيْهِمَا ثِيَابٌ بِيضٌ كَأَشَدِّ الْقِتَالِ مَا رَأَيْتُهُمَا قَبْلُ وَلَا بَعْدُ","id":"Telah menceritakan kepada kami [Abdul Aziz bin Abdullah] telah menceritakan kepada kami [Ibrahim bin Sa'd] dari [Ayahnya] dari [Kakeknya] dari [Sa'd bin Abu Waqash] radliallahu 'anhu, dia berkata, \"Pada perang Uhud, aku melihat Rasulullah shallallahu 'alaihi wasallam bersama dua orang laki-laki yang sedang bertempur, keduanya mengenakan pakaian putih, seolah-olah singa dalam medan pertempuran, aku belum pernah melihatnya baik sebelum mamupun sesudahnya.\""},"3550":{"ar":"حَدَّثَنِي عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ حَدَّثَنَا مَرْوَانُ بْنُ مُعَاوِيَةَ حَدَّثَنَا هَاشِمُ بْنُ هَاشِمٍ السَّعْدِيُّ قَالَ سَمِعْتُ سَعِيدَ بْنَ الْمُسَيَّبِ يَقُولُ سَمِعْتُ سَعْدَ بْنَ أَبِي وَقَّاصٍ يَقُولُنَثَلَ لِي النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كِنَانَتَهُ يَوْمَ أُحُدٍ فَقَالَ ارْمِ فِدَاكَ أَبِي وَأُمِّي","id":"Telah menceritakan kepada kami [Abdullah bin Muhammad] telah menceritakan kepada kami [Marwan bin Mu'awiyah] telah menceritakan kepada kami [Hasyim bin Hasyim As Sa'di] dia berkata, aku mendengar [Sa'id bin Musayyab] berkata, aku mendengar [Sa'd bin Abu Waqash] berkata, \"Pada saat perang Uhud, Nabi shallallahu 'alaihi wasallam mengambilkan anak panah dari wadahnya untukku, lalu beliau bersabda: \"Lemparlah, demi ayah dan ibuku sebagai tebusanmu.\""},"3551":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ يَحْيَى بْنِ سَعِيدٍ قَالَ سَمِعْتُ سَعِيدَ بْنَ الْمُسَيَّبِ قَالَ سَمِعْتُ سَعْدًا يَقُولُجَمَعَ لِي النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَبَوَيْهِ يَوْمَ أُحُدٍ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Yahya] dari [Yahya bin Sa'id] dia berkata, aku mendengar [Sa'id bin Al Musayyab] berkata, aku mendengar [Sa'd] berkata, \"Nabi shallallahu 'alaihi wasallam menyertakan kedua orangtua beliau (sebagai tebusanku) pada perang Uhud.\""},"3552":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا لَيْثٌ عَنْ يَحْيَى عَنْ ابْنِ الْمُسَيَّبِ أَنَّهُ قَالَ قَالَ سَعْدُ بْنُ أَبِي وَقَّاصٍ رَضِيَ اللَّهُ عَنْهُلَقَدْ جَمَعَ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ أُحُدٍ أَبَوَيْهِ كِلَيْهِمَا يُرِيدُ حِينَ قَالَ فِدَاكَ أَبِي وَأُمِّي وَهُوَ يُقَاتِلُ","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Laits] dari [Yahya] dari [Ibnu Al Musayyab] bahwa dia berkata, [Sa'd bin Abu Waqash] radliallahu 'anhu berkata, \"Sungguh, Rasulullah shallallahu 'alaihi wasallam pernah menyertakan kedua orangtuanya (sebagai tebusanku) pada perang Uhud.\""},"3553":{"ar":"حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا مِسْعَرٌ عَنْ سَعْدٍ عَنْ ابْنِ شَدَّادٍ قَالَ سَمِعْتُ عَلِيًّا رَضِيَ اللَّهُ عَنْهُ يَقُولُمَا سَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَجْمَعُ أَبَوَيْهِ لِأَحَدٍ غَيْرَ سَعْدٍ","id":"Telah menceritakan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Mis'ar] dari [Sa'd] dari [Ibnu Syaddad] dia berkata, aku mendengar ['Ali] radliallahu 'anhu berkata, \"Aku belum pernah mendengar Nabi shallallahu 'alaihi wasallam menyertakan kedua orangtuanya sebagai tebusan kepada seseorang selain Sa'd.\""},"3554":{"ar":"حَدَّثَنَا يَسَرَةُ بْنُ صَفْوَانَ حَدَّثَنَا إِبْرَاهِيمُ عَنْ أَبِيهِ عَنْ عَبْدِ اللَّهِ بْنِ شَدَّادٍ عَنْ عَلِيٍّ رَضِيَ اللَّهُ عَنْهُ قَالَمَا سَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جَمَعَ أَبَوَيْهِ لِأَحَدٍ إِلَّا لِسَعْدِ بْنِ مَالِكٍ فَإِنِّي سَمِعْتُهُ يَقُولُ يَوْمَ أُحُدٍ يَا سَعْدُ ارْمِ فِدَاكَ أَبِي وَأُمِّي","id":"Telah menceritakan kepada kami [Yasharah bin Shafwan] telah menceritakan kepada kami [Ibrahim] dari [Ayahnya] dari [Abdullah bin Syaddad] dari [Ali] radliallahu 'anhu, dia berkata, \"Aku belum pernah mendengar Nabi shallallahu 'alaihi wasallam menyertakan kedua orangtua beliau sebagai tebusan kepada seseorang selain Sa'd bin Malik, sesungguhnya aku pernah mendengar beliau bersabda pada perang Uhud: \"Wahai Sa'd, lemparlah demi ayah dan ibuku sebagai tebusanmu.\""},"3555":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ عَنْ مُعْتَمِرٍ عَنْ أَبِيهِ قَالَ زَعَمَ أَبُو عُثْمَانَأَنَّهُ لَمْ يَبْقَ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي بَعْضِ تِلْكَ الْأَيَّامِ الَّتِي يُقَاتِلُ فِيهِنَّ غَيْرُ طَلْحَةَ وَسَعْدٍ عَنْ حَدِيثِهِمَا","id":"Telah menceritakan kepada kami [Musa bin Isma'il] dari [Mu'tamir] dari [Ayahnya] dua berkata, [Abu Utsman] meyakini bahwa tidak ada yang tetap bersama Nabi shallallahu 'alaihi wasallam pada sebagian hari-hari dimana Rasulullah shallallahu 'alaihi wasallam berperang didalamya (perang Uhud) kecuali [Thalhah] dan [Sa'ad] \". Cerita ini diperoleh dari keduanya."},"3556":{"ar":"حَدَّثَنَا عَبْدَانُ أَخْبَرَنَا أَبُو حَمْزَةَ عَنْ عُثْمَانَ بْنِ مَوْهَبٍ قَالَجَاءَ رَجُلٌ حَجَّ الْبَيْتَ فَرَأَى قَوْمًا جُلُوسًا فَقَالَ مَنْ هَؤُلَاءِ الْقُعُودُ قَالُوا هَؤُلَاءِ قُرَيْشٌ قَالَ مَنْ الشَّيْخُ قَالُوا ابْنُ عُمَرَ فَأَتَاهُ فَقَالَ إِنِّي سَائِلُكَ عَنْ شَيْءٍ أَتُحَدِّثُنِي قَالَ أَنْشُدُكَ بِحُرْمَةِ هَذَا الْبَيْتِ أَتَعْلَمُ أَنَّ عُثْمَانَ بْنَ عَفَّانَ فَرَّ يَوْمَ أُحُدٍ قَالَ نَعَمْ قَالَ فَتَعْلَمُهُ تَغَيَّبَ عَنْ بَدْرٍ فَلَمْ يَشْهَدْهَا قَالَ نَعَمْ قَالَ فَتَعْلَمُ أَنَّهُ تَخَلَّفَ عَنْ بَيْعَةِ الرِّضْوَانِ فَلَمْ يَشْهَدْهَا قَالَ نَعَمْ قَالَ فَكَبَّرَ قَالَ ابْنُ عُمَرَ تَعَالَ لِأُخْبِرَكَ وَلِأُبَيِّنَ لَكَ عَمَّا سَأَلْتَنِي عَنْهُ أَمَّا فِرَارُهُ يَوْمَ أُحُدٍ فَأَشْهَدُ أَنَّ اللَّهَ عَفَا عَنْهُ وَأَمَّا تَغَيُّبُهُ عَنْ بَدْرٍ فَإِنَّهُ كَانَ تَحْتَهُ بِنْتُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَكَانَتْ مَرِيضَةً فَقَالَ لَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ لَكَ أَجْرَ رَجُلٍ مِمَّنْ شَهِدَ بَدْرًا وَسَهْمَهُ وَأَمَّا تَغَيُّبُهُ عَنْ بَيْعَةِ الرِّضْوَانِ فَإِنَّهُ لَوْ كَانَ أَحَدٌ أَعَزَّ بِبَطْنِ مَكَّةَ مِنْ عُثْمَانَ بْنِ عَفَّانَ لَبَعَثَهُ مَكَانَهُ فَبَعَثَ عُثْمَانَ وَكَانَتْ بَيْعَةُ الرِّضْوَانِ بَعْدَمَا ذَهَبَ عُثْمَانُ إِلَى مَكَّةَ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِيَدِهِ الْيُمْنَى هَذِهِ يَدُ عُثْمَانَ فَضَرَبَ بِهَا عَلَى يَدِهِ فَقَالَ هَذِهِ لِعُثْمَانَ اذْهَبْ بِهَذَا الْآنَ مَعَكَ","id":"Telah menceritakan kepada kami ['Abdan] telah mengabarkan kepada kami [Abu Hamzah] dari ['Utsman bin Mauhab] dia berkata, \"Seorang laki-laki pernah pergi haji, kemudian dia melihat orang-orang tengah duduk-duduk, lalu dia berkata, \"Siapakah yang tengah duduk-duduk itu?\" mereka menjawab, \"Mereka adalah orang-orang Quraisy.\" Laki-laki itu bertanya lagi, \"Siapakah syaikh itu?\" mereka menjawab, \"Dia adalah [Ibnu Umar].\" Lantas dia mendatangi Ibnu Umar seraya berkata, \"Aku ingin bertanya kepadamu tentang sesuatu, oleh karena itu, jelaskanlah kepadaku. Laki-laki itu berkata, \"Aku nasehatkan kepadamu demi kesucian rumah ini (Ka'bah), apakah kamu tahu bahwa 'Utsman lari dari perag Uhud?\" Ibnu 'Umar menjawab, \"Ya.\" Orang itu bertanya lagi, \"Apakah kamu juga tahu bahwa dia tidak ikut perang Badar?\" Ibnu 'Umar menjawab, \"Ya.\" Orang itu bertanya lagi, \"Apakah kamu juga tahu bahwa dia tidak hadir dan tidak ikut Bai'atur Ridlwan?\" Ibnu 'Umar menjawab, \"Ya\". Orang itu berkata, \"Allahu Akbar.\" Kemudian Ibnu 'Umar berkata, \"Kamarilah, aku akan menjelaskan semua yang kamu tanyakan kepadaku! Mengenai larinya 'Utsman pada perang Uhud, sungguh aku bersaksi bahwa Allah telah memaafkan dan mengampuninya. Sedangkan tidak ikutnya dia pada perang Badar, sebab saat itu dia sedang merawat putri Rasulullah shallallahu 'alaihi wasallam yang tengah sakit, dimana Nabi shallallahu 'alaihi wasallam bersabda kepadanya: \"Kamu mendapat pahala dan bagian sebagaimana mereka yang ikut perang Badar.\" Sedangkan tidak hadirnya dia saat Bai'atur Ridlwan, sungguh seandainya ada orang lain di kota Makkah yang lebih mulia dari 'Utsman bin 'Affan, tentu beliau shallallahu 'alaihi wasallam akan mengutusnya untuk menggantikan posisi Utsman. Namun Rasulullah shallallahu 'alaihi wasallam mengutus 'Utsman, sementara peristiwa Bai'atur Ridlwan terjadi setelah 'Utsman berangkat menuju Makkah, Nabi shallallahu 'alaihi wasallam bersabda dengan membuka telapak tanganya yang kanan: \"Ini tangannya 'Utsman\" lalu beliau menggenggamkan telapak tagannya yang kanan ke telapak tangan kiri, lalu bersabda: \"Ini untuk 'Utsman.\" Kemudian Ibnu 'Umar berkata kepada orang itu, \"Sekarang pergilah kamu dengan membawa keterangan tadi.\""},"3557":{"ar":"حَدَّثَنِي عَمْرُو بْنُ خَالِدٍ حَدَّثَنَا زُهَيْرٌ حَدَّثَنَا أَبُو إِسْحَاقَ قَالَ سَمِعْتُ الْبَرَاءَ بْنَ عَازِبٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَجَعَلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى الرَّجَّالَةِ يَوْمَ أُحُدٍ عَبْدَ اللَّهِ بْنَ جُبَيْرٍ وَأَقْبَلُوا مُنْهَزِمِينَ فَذَاكَ إِذْ يَدْعُوهُمْ الرَّسُولُ فِي أُخْرَاهُمْ","id":"Telah menceritakan kepadaku ['Amru bin Khalid] telah menceritakan kepada kami [Zuhair] telah menceritakan kepada kami [Abu Ishaq] dia berkata, aku mendengar [Al Barra` bin 'Azib] radliallahu 'anhuma berkata, \"Nabi shallallahu 'alaihi wasallam pernah menjadikan Abdullah bin Jubair sebagai komandan pasukan pejalan kaki pada perang Uhud. Lalu mereka lari berpencar, itulah (peristiwa) ketika Rasul yang berada di antara kawan-kawanmu yang lain menyeru pasukan belakang kalian.\""},"3558":{"ar":"و قَالَ لِي خَلِيفَةُ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ حَدَّثَنَا سَعِيدٌ عَنْ قَتَادَةَ عَنْ أَنَسٍ عَنْ أَبِي طَلْحَةَ رَضِيَ اللَّهُ عَنْهُمَا قَالَكُنْتُ فِيمَنْ تَغَشَّاهُ النُّعَاسُ يَوْمَ أُحُدٍ حَتَّى سَقَطَ سَيْفِي مِنْ يَدِي مِرَارًا يَسْقُطُ وَآخُذُهُ وَيَسْقُطُ فَآخُذُهُ","id":"Dan [Khalifah] berkata kepadaku; telah menceritakan kepada kami [Yazid bin Zurai'] telah menceritakan kepada kami [Sa'id] dari [Qatadah] dari [Anas] dari [Abu Thalhah] radliallahu 'anhuma, dia berkata, \"Aku termasuk orang yang terserang rasa kantuk pada perang Uhud, hingga pedangku selalu terjatuh dari tanganku, lalu aku mengambilnya, setelah itu terjatuh lagi, akupun mengambilnya (hingga berulang kali).\""},"3559":{"ar":"حَدَّثَنَا يَحْيَى بْنُ عَبْدِ اللَّهِ السُّلَمِيُّ أَخْبَرَنَا عَبْدُ اللَّهِ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ حَدَّثَنِي سَالِمٌ عَنْ أَبِيهِأَنَّهُ سَمِعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا رَفَعَ رَأْسَهُ مِنْ الرُّكُوعِ مِنْ الرَّكْعَةِ الْآخِرَةِ مِنْ الْفَجْرِ يَقُولُ اللَّهُمَّ الْعَنْ فُلَانًا وَفُلَانًا وَفُلَانًا بَعْدَ مَا يَقُولُ سَمِعَ اللَّهُ لِمَنْ حَمِدَهُ رَبَّنَا وَلَكَ الْحَمْدُ فَأَنْزَلَ اللَّهُ{ لَيْسَ لَكَ مِنْ الْأَمْرِ شَيْءٌ إِلَى قَوْلِهِ فَإِنَّهُمْ ظَالِمُونَ }وَعَنْ حَنْظَلَةَ بْنِ أَبِي سُفْيَانَ سَمِعْتُ سَالِمَ بْنَ عَبْدِ اللَّهِ يَقُولُ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَدْعُو عَلَى صَفْوَانَ بْنِ أُمَيَّةَ وَسُهَيْلِ بْنِ عَمْرٍو وَالْحَارِثِ بْنِ هِشَامٍ فَنَزَلَتْ{ لَيْسَ لَكَ مِنْ الْأَمْرِ شَيْءٌ إِلَى قَوْلِهِ فَإِنَّهُمْ ظَالِمُونَ }","id":"Telah menceritakan kepada kami [Yahya bin Abdullah As Sulami] telah mengabarkan kepada kami [Abdullah] telah mengabarkan kepada kami [Ma'mar] dari [Az Zuhri] telah menceritakan kepadaku [Salim] dari [Ayahnya] bahwa dia mendengar saat Rasulullah shallallahu 'alaihi wasallam mengangkat kepalanya dari rukuk di rakaat terakhir shalat shubuh, beliau mengucapkan: \"Ya Allah, laknatlah fulan, fulan dan fulan, \" yaitu setelah beliau mengucapkan: \"Sami'allahu liman hamidah, rabbanaa walakalhamdu.\" Setelah itu Allah menurunkan ayat: '(Tak ada sedikitpun campur tanganmu dalam urusan mereka itu -hingga firmanNya- Sesungguhnya mereka itu orang-orang yang zalim) ' (Qs. Ali Imran: 128). Dan dari [Hanzhalah bin Abu Sufyan] aku mendengar [Salim bin Abdullah] berkata, \"Rasulullah shallallahu 'alaihi wasallam pernah mendo'akan (kejelekkan) kepada Shofwan bin Umayyah, Suhail bin 'Amru dan Harits bin Hisyam, lalu turunlah ayat: '(Tak ada sedikitpun campur tanganmu dalam urusan mereka itu -hingga firmanNya- Sesungguhnya mereka itu orang-orang yang zalim) ' (Qs. Ali Imran: 128)."},"3560":{"ar":"حَدَّثَنَا يَحْيَى بْنُ بُكَيْرٍ حَدَّثَنَا اللَّيْثُ عَنْ يُونُسَ عَنْ ابْنِ شِهَابٍ وَقَالَ ثَعْلَبَةُ بْنُ أَبِي مَالِكٍ إِنَّ عُمَرَ بْنَ الْخَطَّابِ رَضِيَ اللَّهُ عَنْهُقَسَمَ مُرُوطًا بَيْنَ نِسَاءٍ مِنْ نِسَاءِ أَهْلِ الْمَدِينَةِ فَبَقِيَ مِنْهَا مِرْطٌ جَيِّدٌ فَقَالَ لَهُ بَعْضُ مَنْ عِنْدَهُ يَا أَمِيرَ الْمُؤْمِنِينَ أَعْطِ هَذَا بِنْتَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الَّتِي عِنْدَكَ يُرِيدُونَ أُمَّ كُلْثُومٍ بِنْتَ عَلِيٍّ فَقَالَ عُمَرُ أُمُّ سَلِيطٍ أَحَقُّ بِهِ وَأُمُّ سَلِيطٍ مِنْ نِسَاءِ الْأَنْصَارِ مِمَّنْ بَايَعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ عُمَرُ فَإِنَّهَا كَانَتْ تُزْفِرُ لَنَا الْقِرَبَ يَوْمَ أُحُدٍ","id":"Telah menceritakan kepada kami [Yahya bin Bukair] telah menceritakan kepada kami [Al Laits] dari [Yunus] dari [Ibnu Syihab], [Tsa'labah bin Abu Malik] pernah mengatakan, \"Sesungguhnya [Umar bin Al Khatthab] pernah membagi-bagikan kain kepada para wanita penduduk Madinah, hingga tersisa satu kain yang sangat bagus, lalu orang-orang yang ada di sisinya berkata, \"Wahai Amirul Mukminin, berikan saja kain tersebut kepada putri (cucu) Rasulullah shallallahu 'alaihi wasallam!\" Maksud mereka adalah Ummu Kultsum binti Ali, lalu Umar berkata, \"Ummu Salith lebih berhak mendapatkan kain ini, -Ummu Salith adalah seorang wanita Anshar yang pernah berbaiat kepada Rasulullah shallallahu 'alaihi wasallam-, Umar berkata, \"Sesungguhnya dia pernah membawakan air minum kami pada perang Uhud.\""},"3561":{"ar":"حَدَّثَنِي أَبُو جَعْفَرٍ مُحَمَّدُ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا حُجَيْنُ بْنُ الْمُثَنَّى حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ عَبْدِ اللَّهِ بْنِ أَبِي سَلَمَةَ عَنْ عَبْدِ اللَّهِ بْنِ الْفَضْلِ عَنْ سُلَيْمَانَ بْنِ يَسَارٍ عَنْ جَعْفَرِ بْنِ عَمْرِو بْنِ أُمَيَّةَ الضَّمْرِيِّ قَالَخَرَجْتُ مَعَ عُبَيْدِ اللَّهِ بْنِ عَدِيِّ بْنِ الْخِيَارِ فَلَمَّا قَدِمْنَا حِمْصَ قَالَ لِي عُبَيْدُ اللَّهِ بْنُ عَدِيٍّ هَلْ لَكَ فِي وَحْشِيٍّ نَسْأَلُهُ عَنْ قَتْلِ حَمْزَةَ قُلْتُ نَعَمْ وَكَانَ وَحْشِيٌّ يَسْكُنُ حِمْصَ فَسَأَلْنَا عَنْهُ فَقِيلَ لَنَا هُوَ ذَاكَ فِي ظِلِّ قَصْرِهِ كَأَنَّهُ حَمِيتٌ قَالَ فَجِئْنَا حَتَّى وَقَفْنَا عَلَيْهِ بِيَسِيرٍ فَسَلَّمْنَا فَرَدَّ السَّلَامَ قَالَ وَعُبَيْدُ اللَّهِ مُعْتَجِرٌ بِعِمَامَتِهِ مَا يَرَى وَحْشِيٌّ إِلَّا عَيْنَيْهِ وَرِجْلَيْهِ فَقَالَ عُبَيْدُ اللَّهِ يَا وَحْشِيُّ أَتَعْرِفُنِي قَالَ فَنَظَرَ إِلَيْهِ ثُمَّ قَالَ لَا وَاللَّهِ إِلَّا أَنِّي أَعْلَمُ أَنَّ عَدِيَّ بْنَ الْخِيَارِ تَزَوَّجَ امْرَأَةً يُقَالُ لَهَا أُمُّ قِتَالٍ بِنْتُ أَبِي الْعِيصِ فَوَلَدَتْ لَهُ غُلَامًا بِمَكَّةَ فَكُنْتُ أَسْتَرْضِعُ لَهُ فَحَمَلْتُ ذَلِكَ الْغُلَامَ مَعَ أُمِّهِ فَنَاوَلْتُهَا إِيَّاهُ فَلَكَأَنِّي نَظَرْتُ إِلَى قَدَمَيْكَ قَالَ فَكَشَفَ عُبَيْدُ اللَّهِ عَنْ وَجْهِهِ ثُمَّ قَالَ أَلَا تُخْبِرُنَا بِقَتْلِ حَمْزَةَ قَالَ نَعَمْ إِنَّ حَمْزَةَ قَتَلَ طُعَيْمَةَ بْنَ عَدِيِّ بْنِ الْخِيَارِ بِبَدْرٍ فَقَالَ لِي مَوْلَايَ جُبَيْرُ بْنُ مُطْعِمٍ إِنْ قَتَلْتَ حَمْزَةَ بِعَمِّي فَأَنْتَ حُرٌّ قَالَ فَلَمَّا أَنْ خَرَجَ النَّاسُ عَامَ عَيْنَيْنِ وَعَيْنَيْنِ جَبَلٌ بِحِيَالِ أُحُدٍ بَيْنَهُ وَبَيْنَهُ وَادٍ خَرَجْتُ مَعَ النَّاسِ إِلَى الْقِتَالِ فَلَمَّا أَنْ اصْطَفُّوا لِلْقِتَالِ خَرَجَ سِبَاعٌ فَقَالَ هَلْ مِنْ مُبَارِزٍ قَالَ فَخَرَجَ إِلَيْهِ حَمْزَةُ بْنُ عَبْدِ الْمُطَّلِبِ فَقَالَ يَا سِبَاعُ يَا ابْنَ أُمِّ أَنْمَارٍ مُقَطِّعَةِ الْبُظُورِ أَتُحَادُّ اللَّهَ وَرَسُولَهُ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ ثُمَّ شَدَّ عَلَيْهِ فَكَانَ كَأَمْسِ الذَّاهِبِ قَالَ وَكَمَنْتُ لِحَمْزَةَ تَحْتَ صَخْرَةٍ فَلَمَّا دَنَا مِنِّي رَمَيْتُهُ بِحَرْبَتِي فَأَضَعُهَا فِي ثُنَّتِهِ حَتَّى خَرَجَتْ مِنْ بَيْنِ وَرِكَيْهِ قَالَ فَكَانَ ذَاكَ الْعَهْدَ بِهِ فَلَمَّا رَجَعَ النَّاسُ رَجَعْتُ مَعَهُمْ فَأَقَمْتُ بِمَكَّةَ حَتَّى فَشَا فِيهَا الْإِسْلَامُ ثُمَّ خَرَجْتُ إِلَى الطَّائِفِ فَأَرْسَلُوا إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَسُولًا فَقِيلَ لِي إِنَّهُ لَا يَهِيجُ الرُّسُلَ قَالَ فَخَرَجْتُ مَعَهُمْ حَتَّى قَدِمْتُ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمَّا رَآنِي قَالَ آنْتَ وَحْشِيٌّ قُلْتُ نَعَمْ قَالَ أَنْتَ قَتَلْتَ حَمْزَةَ قُلْتُ قَدْ كَانَ مِنْ الْأَمْرِ مَا بَلَغَكَ قَالَ فَهَلْ تَسْتَطِيعُ أَنْ تُغَيِّبَ وَجْهَكَ عَنِّي قَالَ فَخَرَجْتُ فَلَمَّا قُبِضَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَخَرَجَ مُسَيْلِمَةُ الْكَذَّابُ قُلْتُ لَأَخْرُجَنَّ إِلَى مُسَيْلِمَةَ لَعَلِّي أَقْتُلُهُ فَأُكَافِئَ بِهِ حَمْزَةَ قَالَ فَخَرَجْتُ مَعَ النَّاسِ فَكَانَ مِنْ أَمْرِهِ مَا كَانَ قَالَ فَإِذَا رَجُلٌ قَائِمٌ فِي ثَلْمَةِ جِدَارٍ كَأَنَّهُ جَمَلٌ أَوْرَقُ ثَائِرُ الرَّأْسِ قَالَ فَرَمَيْتُهُ بِحَرْبَتِي فَأَضَعُهَا بَيْنَ ثَدْيَيْهِ حَتَّى خَرَجَتْ مِنْ بَيْنِ كَتِفَيْهِ قَالَ وَوَثَبَ إِلَيْهِ رَجُلٌ مِنْ الْأَنْصَارِ فَضَرَبَهُ بِالسَّيْفِ عَلَى هَامَتِهِقَالَ قَالَ عَبْدُ اللَّهِ بْنُ الْفَضْلِ فَأَخْبَرَنِي سُلَيْمَانُ بْنُ يَسَارٍ أَنَّهُ سَمِعَ عَبْدَ اللَّهِ بْنَ عُمَرَ يَقُولُ فَقَالَتْ جَارِيَةٌ عَلَى ظَهْرِ بَيْتٍ وَا أَمِيرَ الْمُؤْمِنِينَ قَتَلَهُ الْعَبْدُ الْأَسْوَدُ","id":"Telah menceritakan kepadaku [Abu Ja'far Muhammad bin Abdullah] telah menceritakan kepada kami [Hujain bin Al Mutsanna] telah menceritakan kepada kami [Abdul Aziz bin Abdullah bin Abu Salamah] dari [Abdullah bin Al Fadl] dari [Sulaiman bin Yasar] dari [Ja'far bin 'Amru bin Umayyah Adl Dlamri] dia berkata, \"Aku keluar bersama 'Ubaidullah bin 'Ady bin Hiyar ke Syam. Ketika kami sampai ke Himsh, 'Ubaidullah bin 'Adi berkata kepadaku, \"Bagaimana kalau kita menemui [Wahsyi] dan bertanya tentang (peristiwa) terbunuhnya Hamzah?\" aku menjawab, \"Baiklah.\" Wahsyi ketika itu tinggal di Himsh, saat kami bertanya tentang dia, maka ditunjukkanlah kepada kami bahwa Wahsyi saat itu berada di bawah bayang-bayang rumahnya, seakan-akan dia adalah seseorang yang berkulit hitam.\" Ja'far bin 'Amru Ad-Dlamry berkata, \"Kami lalu mendatanginya hingga berada di hadapannya, kami mengucapkan salam, dan dia membalasnya. 'Ubaidullah ketika itu melipat penutup kepalanya, sehingga Wahsyi tidak dapat melihatnya kecuali kedua mata Ubaidullah dan kedua kakinya. 'Ubaidullah bertanya, \"Wahai Wahsyi, apa engkau mengenaliku?\" Wahsyi pun memperhatikannya, lalu dia berkata, \"Demi Allah, tidak! Aku tidak mengenalimu, kecuali aku tahu bahwa 'Ady bin Khiyar menikah dengan seorang perempuan yang disebut dengan Ummu Qital, putri Abu Al 'Ish. Darinya lahirlah seorang anak di Makkah, maka dia dimintakan untuk disusukan kepada orang lain lalu aku membawa anak kecil itu sama ibunya, aku pun menyerahkan kepadanya, seakan-akan aku melihatnya sama, jika aku melihat ke kedua kakimu.\" Ja'far bin 'Amru Ad-Dlamry berkata, setelah itu 'Ubaidullah menyingkapkan wajahnya, lalu dia berkata, \"Maukah engkau menceritakan kepada kami tentang terbunuhnya Hamzah?\" Wahsyi menjawab, \"Baiklah, ketika itu Hamzah membunuh Tu'aimah bin 'Ady pada Perang Badar, lalu tuanku, Zubair bin Muth'im, berkata kepadaku, \"Jika kamu berhasil membunuh Hamzah sebagai balas dendam kematian pamanku, maka kamu akan bebas.\" Ketika orang-orang serentak keluar ke 'Ainain, -suatu gunung kecil di bawah Uhud yang terpisah dengan bukit- saya keluar bersama mereka untuk ikut berperang, ketika pasukan telah berhadap-hadapan untuk berperang, keluarlah Siba' sambil berkata, \"Siapakah yang berani bertanding?\" mendengar itu Hamzah bin Abdul Al Munthalib keluar sambil berkata, \"Wahai anak (yang keluar dari) potongan daging kemaluan perempuan (bahasa celaan dan hinaan terhadap seseorang -pent), apakah kamu akan menantang Allah dan Rasul-Nya shallallahu 'alaihi wasallam?\" kemudian Hamzah berhasil menghabisinya. Kemudian secara diam-diam aku mengincar Hamzah di balik bebatuan yang besar, hingga ketika dia melewatiku, dan dia sangat dekat denganku, akupun langsung melemparkan tombakku dan tepat mengenai daerah bawah perutnya, hingga keluarlah apa yang di dalam daerah yang terkena lemparan tombak tersebut.\" Wahsyi melanjutkan, \"Dan itulah apa yang akan menjadi janjiku.\" Ketika orang-orang kembali pulang, akupun kembali bersama mereka.\" Wahsyi melanjutkan, \"Aku tinggal di Makkah sampai Islam tersebar di sana, aku lalu keluar menuju Thaif, ketika penduduk Tha'if mengutus beberapa utusan kepada Rasulullah shallallahu 'alaihi wasallam, maka salah seorang utusan berkata kepadaku, \"Beliau tidak akan menyakiti utusan.\" Wahsyi melanajutkan, \"Aku pun pergi bersama mereka sampai aku menemui Rasulullah shallallahu 'alaihi wasallam. Ketika beliau melihatku, beliau bertanya: \"Apakah engkau wahsyi?\" aku menjawab, \"Benar.\" Beliau bersabda: \"Apakah kamu yang telah membunuh Hamzah?\" Wahsyi menjawab, \"Perkara itu sebagaimana yang telah sampai kepada anda.\" Beliau bersabda: \"Dapatkah kamu menjauhkan wajahmu dariku?\" Wahsyi berkata, \"Lalu aku kembali pulang. Ketika Rasulullah shallallahu 'alaihi wasallam meninggal, muncullah Musailamah Al Kadzab, aku berkata, \"Aku akan berusaha mencari Musailamah, semoga aku dapat membunuhnya dan menebus kesalahanku karena membunuh Hamzah, \" lalu aku keluar bersama orang-orang yang akan memerangi Musailamah. Sebuah kesempatan yang kutunggu-tunggu. Aku lalu melihat seorang laki-laki berdiri di salah satu dinding rumah seakan-akan unta abu-abu yang berambut kusut.\" Wahsyi melanjutkan, \"Lalu kulemparkan tombakku hingga tepat mengenai di tengah dadanya sampai tembus ke bahunya.\" Wahsyi berkata, \"Kemudian seorang laki-laki Anshar menyerangnya dan berhasil memenggal kepalanya dengan pedang.\" [Abdullah bin Al Fadl] berkata, telah mengabarkan kepadaku [Sulaiman bin Yasar] bahwa dia mendengar [Abdullah bin 'Umar] berkata, \"Lalu seorang wanita yang berada diloteng rumahnya mengatakan, \"Amirul Mukminin telah dibunuh oleh seorang budak hitam (maksdunya Wahsyi -pent).\""},"3562":{"ar":"حَدَّثَنَا إِسْحَاقُ بْنُ نَصْرٍ حَدَّثَنَا عَبْدُ الرَّزَّاقِ عَنْ مَعْمَرٍ عَنْ هَمَّامٍ سَمِعَ أَبَا هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اشْتَدَّ غَضَبُ اللَّهِ عَلَى قَوْمٍ فَعَلُوا بِنَبِيِّهِ يُشِيرُ إِلَى رَبَاعِيَتِهِ اشْتَدَّ غَضَبُ اللَّهِ عَلَى رَجُلٍ يَقْتُلُهُ رَسُولُ اللَّهِ فِي سَبِيلِ اللَّهِ","id":"Telah menceritakan kepada kami [Ishaq bin Nashr] telah menceritakan kepada kami [Abdurrazaq] dari [Ma'mar] dari [Hammam] dia mendengar [Abu Hurairah] radliallahu 'anhu, dia berkata, \"Rasulullah Shallallahu 'alahi wasallam bersabda: \"Allah sangat murka kepada suatu kaum yang telah memperlakukan Nabi-Nya seperti ini -seraya menunjuk ke gigi serinya-, Allah sangat murka kepada seseorang yang telah diperangi oleh Rasulullah dijalan Allah.\""},"3563":{"ar":"حَدَّثَنِي مَخْلَدُ بْنُ مَالِكٍ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ الْأُمَوِيُّ حَدَّثَنَا ابْنُ جُرَيْجٍ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَاشْتَدَّ غَضَبُ اللَّهِ عَلَى مَنْ قَتَلَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي سَبِيلِ اللَّهِ اشْتَدَّ غَضَبُ اللَّهِ عَلَى قَوْمٍ دَمَّوْا وَجْهَ نَبِيِّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepadaku [Makhlad bin Malik] telah menceritakan kepada kami [Yahya bin Sa'id Al Amawy] telah menceritakan kepada kami [Ibnu Juraij] dari ['Amru bin Dinar] dari [Ikrimah] dari [Ibnu Abbas] radliallahu 'anhuma, dia berkata, \"Allah sangat murka kepada seseorang yang telah dibunuh oleh Nabi Shallallahu 'alahi wasallam (yang berperang) di jalan Allah, Allah sangat murka kepada suatu kaum yang telah membuat wajah Nabiyullah Shallallahu 'alahi wasallam berdarah.\""},"3564":{"ar":"بَاب حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا يَعْقُوبُ عَنْ أَبِي حَازِمٍ أَنَّهُ سَمِعَ سَهْلَ بْنَ سَعْدٍوَهُوَ يُسْأَلُ عَنْ جُرْحِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَمَا وَاللَّهِ إِنِّي لَأَعْرِفُ مَنْ كَانَ يَغْسِلُ جُرْحَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَمَنْ كَانَ يَسْكُبُ الْمَاءَ وَبِمَا دُووِيَ قَالَ كَانَتْ فَاطِمَةُ عَلَيْهَا السَّلَام بِنْتُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَغْسِلُهُ وَعَلِيُّ بْنُ أَبِي طَالِبٍ يَسْكُبُ الْمَاءَ بِالْمِجَنِّ فَلَمَّا رَأَتْ فَاطِمَةُ أَنَّ الْمَاءَ لَا يَزِيدُ الدَّمَ إِلَّا كَثْرَةً أَخَذَتْ قِطْعَةً مِنْ حَصِيرٍ فَأَحْرَقَتْهَا وَأَلْصَقَتْهَا فَاسْتَمْسَكَ الدَّمُ وَكُسِرَتْ رَبَاعِيَتُهُ يَوْمَئِذٍ وَجُرِحَ وَجْهُهُ وَكُسِرَتْ الْبَيْضَةُ عَلَى رَأْسِهِ","id":"Bab telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Ya'qub] dari [Abu Hazim] bahwa dia mendengar [Sahl bin Sa'd] bertanya tentang luka Rasulullah Shallallahu 'alahi wasallam, dia berkata, \"Demi Allah, sungguh aku telah mengetahui orang yang telah mengobati luka Rasulullah Shallallahu 'alahi wasallam, orang yang menuangkan air, dan dengan apa beliau diobati.\" Dia melanjutkan, \"Fatimah, putri Rasulullah Shallallahu 'alahi wasallam lah yang telah mencuci (luka beliau), sementara Ali bin Abu Thalib menuangkan air dengan menggunakan perisai, ketika Fatimah melihat darah semakin mengalir deras, dia langsung mengambil potongan tikar dan membakarnya, setelah itu dia menempelkan (bekas pembakaran tersebut) pada luka beliau hingga darahnya terhenti, pada waktu itu gigi seri beliau tanggal, wajah beliau terluka dan topi baja beliau pecah.\""},"3565":{"ar":"حَدَّثَنِي عَمْرُو بْنُ عَلِيٍّ حَدَّثَنَا أَبُو عَاصِمٍ حَدَّثَنَا ابْنُ جُرَيْجٍ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَاشْتَدَّ غَضَبُ اللَّهِ عَلَى مَنْ قَتَلَهُ نَبِيٌّ وَاشْتَدَّ غَضَبُ اللَّهِ عَلَى مَنْ دَمَّى وَجْهَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepadaku ['Amru bin Ali] telah menceritakan kepada kami [Abu 'Ashim] telah menceritakan kepada kami [Ibnu Juraij] dari ['Amru bin Dinar] dari [Ikrimah] dari [Ibnu Abbas] dia berkata, \"Allah sangat murka terhadap orang yang telah dibunuh Nabi, dan Allah sangat murka kepada seseorang yang membuat wajah Rasulullah Shallallahu 'alahi wasallam terluka.\""},"3566":{"ar":"حَدَّثَنَا مُحَمَّدٌ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ هِشَامٍ عَنْ أَبِيهِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا{ الَّذِينَ اسْتَجَابُوا لِلَّهِ وَالرَّسُولِ مِنْ بَعْدِ مَا أَصَابَهُمْ الْقَرْحُ لِلَّذِينَ أَحْسَنُوا مِنْهُمْ وَاتَّقَوْا أَجْرٌ عَظِيمٌ }قَالَتْ لِعُرْوَةَ يَا ابْنَ أُخْتِي كَانَ أَبَوَاكَ مِنْهُمْ الزُّبَيْرُ وَأَبُو بَكْرٍ لَمَّا أَصَابَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا أَصَابَ يَوْمَ أُحُدٍ وَانْصَرَفَ عَنْهُ الْمُشْرِكُونَ خَافَ أَنْ يَرْجِعُوا قَالَ مَنْ يَذْهَبُ فِي إِثْرِهِمْ فَانْتَدَبَ مِنْهُمْ سَبْعُونَ رَجُلًا قَالَ كَانَ فِيهِمْ أَبُو بَكْرٍ وَالزُّبَيْرُ","id":"Telah menceritakan kepada kami [Muhammad] telah menceritakan kepada kami [Abu Mu'awiyah] dari [Hisyam] dari [Ayahnya] dari ['Aisyah] radliallahu 'anha mengenai ayat: '((yaitu) orang-orang yang mentaati perintah Allah dan rasul-Nya sesudah mereka mendapat luka (dalam peperangan Uhud). bagi orang-orang yang berbuat kebaikan diantara mereka dan yang bertakwa ada pahala yang besar) ' (Qs. Ali Imran: 172). Aisyah berkata kepada 'Urwah, \"Wahai keponakanku, sesungguhnya ayahmu termasuk dari mereka (yang diterangkan dalam ayat), yaitu Az Zubair dan Abu Bakr. Ketika Rasulullah Shallallahu 'alahi wasallam terluka pada perang Uhud, disaat beliau khawatir kaum Musyrikin yang telah pergi akan kembali, beliau bersabda: \"Siapakah yang akan mengintai mereka?\", lalu beliau memilih tujuh puluh orang.\" Perawi berkata, \"Termasuk diantara mereka adalah Abu Bakr dan Az Zubair.\""},"3567":{"ar":"حَدَّثَنِي عَمْرُو بْنُ عَلِيٍّ حَدَّثَنَا مُعَاذُ بْنُ هِشَامٍ قَالَ حَدَّثَنِي أَبِي عَنْ قَتَادَةَ قَالَ مَا نَعْلَمُ حَيًّا مِنْ أَحْيَاءِ الْعَرَبِ أَكْثَرَ شَهِيدًا أَعَزَّ يَوْمَ الْقِيَامَةِ مِنْ الْأَنْصَارِ قَالَ قَتَادَةُ وَحَدَّثَنَا أَنَسُ بْنُ مَالِكٍأَنَّهُ قُتِلَ مِنْهُمْ يَوْمَ أُحُدٍ سَبْعُونَ وَيَوْمَ بِئْرِ مَعُونَةَ سَبْعُونَ وَيَوْمَ الْيَمَامَةِ سَبْعُونَ قَالَ وَكَانَ بِئْرُ مَعُونَةَ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَيَوْمُ الْيَمَامَةِ عَلَى عَهْدِ أَبِي بَكْرٍ يَوْمَ مُسَيْلِمَةَ الْكَذَّابِ","id":"Telah menceritakan kepada kami ['Amru bin Ali] telah menceritakan kepada kami [Mu'adz bin Hisyam] dia berkata, telah menceritakan kepadaku [Ayahku] dari [Qatadah] dia berkata, \"Aku belum pernah mendapati diperkampungan orang Arab yang penduduknya lebih banyak mati syahid dan lebih mulia (kedudukannya) pada hari Kiamat daripada orang-orang Anshar.\" [Qatadah] berkata; telah menceritakan kepada kami [Anas bin Malik] bahwa di antara mereka yang gugur pada perang Uhud sejumlah tujuh puluh orang, pada peristiwa Bi'rul Ma'unah sejumlah tujuh puluh orang, dan pada perang Yamamah berjumlah tujuh puluh orang.\" Anas melanjutkan, \"Peristiwa Bi'rul Ma'unah terjadi pada masa Rasulullah Shallallahu 'alahi wasallam, sementara perang Yamamah terjadi pada masa Abu Bakr, yaitu peristiwa (pembangkangan) Musailamah Al Kaddzab.\""},"3568":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا اللَّيْثُ عَنْ ابْنِ شِهَابٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ كَعْبِ بْنِ مَالِكٍ أَنَّ جَابِرَ بْنَ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُمَا أَخْبَرَهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَجْمَعُ بَيْنَ الرَّجُلَيْنِ مِنْ قَتْلَى أُحُدٍ فِي ثَوْبٍ وَاحِدٍ ثُمَّ يَقُولُ أَيُّهُمْ أَكْثَرُ أَخْذًا لِلْقُرْآنِ فَإِذَا أُشِيرَ لَهُ إِلَى أَحَدٍ قَدَّمَهُ فِي اللَّحْدِ وَقَالَ أَنَا شَهِيدٌ عَلَى هَؤُلَاءِ يَوْمَ الْقِيَامَةِ وَأَمَرَ بِدَفْنِهِمْ بِدِمَائِهِمْ وَلَمْ يُصَلِّ عَلَيْهِمْ وَلَمْ يُغَسَّلُواوَقَالَ أَبُو الْوَلِيدِ عَنْ شُعْبَةَ عَنْ ابْنِ الْمُنْكَدِرِ قَالَ سَمِعْتُ جَابِرَ بْنَ عَبْدِ اللَّهِ قَالَ لَمَّا قُتِلَ أَبِي جَعَلْتُ أَبْكِي وَأَكْشِفُ الثَّوْبَ عَنْ وَجْهِهِ فَجَعَلَ أَصْحَابُ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَنْهَوْنِي وَالنَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَمْ يَنْهَ وَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَبْكِيهِ أَوْ مَا تَبْكِيهِ مَا زَالَتْ الْمَلَائِكَةُ تُظِلُّهُ بِأَجْنِحَتِهَا حَتَّى رُفِعَ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Al Laits] dari [Ibnu Syihab] dari [Abdurrahman bin Ka'b bin Malik] bahwa [Jabir bin Abdullah] radliallahu 'anhuma telah mengabarkan kepadanya, bahwa Rasulullah shallallahu 'alaihi wasallam menggabungkan (menghimpun) dua orang yang gugur pada perang Uhud dalam satu kain, kemudian beliau bersabda: \"Manakah diantara keduanya yang paling banyak hapalan Al Qur'an?\" ketika diisyaratkan kepada salah satu dari keduanya, beliau mendahulukannya ketika memasukkan kedalam lahd, beliau bersabda: \"Aku adalah saksi atas mereka.\" Dan beliau menyuruh mereka untuk menguburkan mereka dengan darah yang ada pada diri mereka, mereka tidak dishalatkan dan tidak dimandikan. [Abu Al Walid] mengatakan dari [Syu'bah] dari [Ibnu Al Munkadir] dia berkata, aku mendengar [Jabir bin Abdullah] dia berkata, \"Dihari dibunuhnya ayahku, aku pun menangis sambil menyingkap kain diwajahnya, sementara para sahabat Nabi shallallahu 'alaihi wasallam melarangku, namun Nabi shallallahu 'alaihi wasallam tidak melarangku, Nabi shallallahu 'alaihi wasallam bersabda: \"Janganlah kamu menangisinya -atau kenapa kamu menangisinya? - Para malaikat senantiasa menaungi dengan sayapnya hingga (ruhnya) diangkat.\""},"3569":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْعَلَاءِ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ بُرَيْدِ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي بُرْدَةَ عَنْ جَدِّهِ أَبِي بُرْدَةَ عَنْ أَبِي مُوسَى رَضِيَ اللَّهُ عَنْهُ أُرَىعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ رَأَيْتُ فِي رُؤْيَايَ أَنِّي هَزَزْتُ سَيْفًا فَانْقَطَعَ صَدْرُهُ فَإِذَا هُوَ مَا أُصِيبَ مِنْ الْمُؤْمِنِينَ يَوْمَ أُحُدٍ ثُمَّ هَزَزْتُهُ أُخْرَى فَعَادَ أَحْسَنَ مَا كَانَ فَإِذَا هُوَ مَا جَاءَ بِهِ اللَّهُ مِنْ الْفَتْحِ وَاجْتِمَاعِ الْمُؤْمِنِينَ وَرَأَيْتُ فِيهَا بَقَرًا وَاللَّهُ خَيْرٌ فَإِذَا هُمْ الْمُؤْمِنُونَ يَوْمَ أُحُدٍ","id":"Telah menceritakan kepada kami [Muhammad bin Al 'Ala`] telah menceritakan kepada kami [Abu Usamah] dari [Buraid bin Abdullah bin Abu Burdah] dari kakeknya yaitu [Abu Burdah] dari [Abu Musa] radliallahu 'anhu, seingatku dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Aku melihat dalam mimpiku bahwa diriku terlihat menghunus pedang, tiba-tiba bagian tengah pedang itu patah dan ternyata itu adalah musibah yang menimpa orang-orang mukmin pada perang Uhud. Setelah itu aku pun terlihat menghunus pedang lagi dan ternyata pedang itu lebih baik dari yang pertama. Itulah kemenangan yang diberikan Allah dan bersatunya orang-orang Mukmin. Dan dalam mimpiku juga, aku melihat sapi -dan Allah Maha Baik- ternyata tafsiran mimpi itu adalah orang-orang mukmin yang mati syahid dalam perang Uhud.\""},"3570":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ يُونُسَ حَدَّثَنَا زُهَيْرٌ حَدَّثَنَا الْأَعْمَشُ عَنْ شَقِيقٍ عَنْ خَبَّابٍ رَضِيَ اللَّهُ عَنْهُ قَالَهَاجَرْنَا مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَنَحْنُ نَبْتَغِي وَجْهَ اللَّهِ فَوَجَبَ أَجْرُنَا عَلَى اللَّهِ فَمِنَّا مَنْ مَضَى أَوْ ذَهَبَ لَمْ يَأْكُلْ مِنْ أَجْرِهِ شَيْئًا كَانَ مِنْهُمْ مُصْعَبُ بْنُ عُمَيْرٍ قُتِلَ يَوْمَ أُحُدٍ فَلَمْ يَتْرُكْ إِلَّا نَمِرَةً كُنَّا إِذَا غَطَّيْنَا بِهَا رَأْسَهُ خَرَجَتْ رِجْلَاهُ وَإِذَا غُطِّيَ بِهَا رِجْلَاهُ خَرَجَ رَأْسُهُ فَقَالَ لَنَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ غَطُّوا بِهَا رَأْسَهُ وَاجْعَلُوا عَلَى رِجْلَيْهِ الْإِذْخِرَ أَوْ قَالَ أَلْقُوا عَلَى رِجْلَيْهِ مِنْ الْإِذْخِرِ وَمِنَّا مَنْ أَيْنَعَتْ لَهُ ثَمَرَتُهُ فَهُوَ يَهْدِبُهَا","id":"Telah menceritakan kepada kami [Ahmad bin Yunus] telah menceritakan kepada kami [Zuhair] telah menceritakan kepada kami [Al A'masy] dari [Syaqiq] dari [Khabbab] radliallahu 'anhu dia berkata, \"Kami pernah berhijrah bersama Nabi shallallahu 'alaihi wasallam demi mengharap ridla Allah, dan balasan kami telah ditulis di sisi Allah, diantara kami sudah ada yang berlalu atau pergi sebelum menikmati balasan (dunia) sedikitpun, diantara mereka adalah Mush'ab bin Umair, ia terbunuh pada saat perang Uhud dan tidak meninggalkan apa-apa melainkan sehelai kain, apabila kami menutup bagian kepala, maka kedua kakinya tersingkap, dan jika kami menutupi kakinya, maka bagian kepalanya tersingkap, lalu Nabi shallallahu 'alaihi wasallam bersabda: \"Tutuplah bagian kepalanya, dan jadikanlah (sesuatu dari) idzkir untuk menutup kedua kakinya.\" Atau beliau bersabda: \"Letakkanlah al idzkir untuk menutupi kedua kakinya.\" Dan diantara kami ada yang buahnya telah matang, lalu ia pun memetiknya."},"3571":{"ar":"حَدَّثَنِي نَصْرُ بْنُ عَلِيٍّ قَالَ أَخْبَرَنِي أَبِي عَنْ قُرَّةَ بْنِ خَالِدٍ عَنْ قَتَادَةَ سَمِعْتُ أَنَسًا رَضِيَ اللَّهُ عَنْهُأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ هَذَا جَبَلٌ يُحِبُّنَا وَنُحِبُّهُ","id":"Telah menceritakan kepadaku [Nashr bin Ali] dia berkata, telah mengabarkan kepadaku [Ayahku] dari [Qurrah bin Khalid] dari [Qatadah] aku mendengar [Anas] radliallahu 'anhu bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Ini adalah gunung yang mencintai kami dan kamipun mencintainya.\""},"3572":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ عَمْرٍو مَوْلَى الْمُطَّلِبِ عَنْ أَنَسِ بْنِ مَالِكٍ رَضِيَ اللَّهُ عَنْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ طَلَعَ لَهُ أُحُدٌ فَقَالَ هَذَا جَبَلٌ يُحِبُّنَا وَنُحِبُّهُ اللَّهُمَّ إِنَّ إِبْرَاهِيمَ حَرَّمَ مَكَّةَ وَإِنِّي حَرَّمْتُ مَا بَيْنَ لَابَتَيْهَا","id":"Telah menceritakan kepada kami [Abdullah bin Yusuf] telah mengabarkan kepada kami [Malik] dari ['Amru] mantan budak Al Mutthalib, dari [Anas bin Malik] radliallahu 'anhu, bahwa Rasulullah shallallahu 'alaihi wasallam menengol kea radliallahu 'anha bukit Uhud, lalu beliau bersabda: \"Ini adalah gunung yang mencintai kami, dan kami pun mencintainya, ya Allah sesungguhnya Ibrahim telah mensucikan kota Makkah, dan akupun mensucikan kota yang berada diantara dua batu hitam (yaitu Madinah).\""},"3573":{"ar":"حَدَّثَنِي عَمْرُو بْنُ خَالِدٍ حَدَّثَنَا اللَّيْثُ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ عَنْ أَبِي الْخَيْرِ عَنْ عُقْبَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَرَجَ يَوْمًا فَصَلَّى عَلَى أَهْلِ أُحُدٍ صَلَاتَهُ عَلَى الْمَيِّتِ ثُمَّ انْصَرَفَ إِلَى الْمِنْبَرِ فَقَالَ إِنِّي فَرَطٌ لَكُمْ وَأَنَا شَهِيدٌ عَلَيْكُمْ وَإِنِّي لَأَنْظُرُ إِلَى حَوْضِي الْآنَ وَإِنِّي أُعْطِيتُ مَفَاتِيحَ خَزَائِنِ الْأَرْضِ أَوْ مَفَاتِيحَ الْأَرْضِ وَإِنِّي وَاللَّهِ مَا أَخَافُ عَلَيْكُمْ أَنْ تُشْرِكُوا بَعْدِي وَلَكِنِّي أَخَافُ عَلَيْكُمْ أَنْ تَنَافَسُوا فِيهَا","id":"Telah menceritakan kepadaku ['Amru bin Khalid] telah menceritakan kepada kami [Al Laits] dari [Yazid bin Abu Habib] dari [Abu Al Khair] dari ['Uqbah] bahwa suatu hari Nabi shallallahu 'alaihi wasallam keluar lalu mengerjakan shalat untuk para syuhada perang Uhud, yaitu shalat jenazah, setelah itu beliau menuju mimbar dan bersabda: \"Aku akan mendahului kalian dan aku menjadi saksi atas kalian, bahwa aku, demi Allah, sekarang sedang melihat telagaku (di surga) dan sungguh aku telah diberikan kunci-kunci perbendaharaan bumi -atau kekayaan bumi- dan aku demi Allah, tidak lebih takut bahwa kalian akan berbuat syirik sepeninggalku, tapi yang lebih aku takutkan adalah kalian akan saling memperebutkannya (harta dunia).\""},"3574":{"ar":"حَدَّثَنِي إِبْرَاهِيمُ بْنُ مُوسَى أَخْبَرَنَا هِشَامُ بْنُ يُوسُفَ عَنْ مَعْمَرٍ عَنْ الزُّهْرِيِّ عَنْ عَمْرِو بْنِ أَبِي سُفْيَانَ الثَّقَفِيِّ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَبَعَثَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَرِيَّةً عَيْنًا وَأَمَّرَ عَلَيْهِمْ عَاصِمَ بْنَ ثَابِتٍ وَهُوَ جَدُّ عَاصِمِ بْنِ عُمَرَ بْنِ الْخَطَّابِ فَانْطَلَقُوا حَتَّى إِذَا كَانَ بَيْنَ عُسْفَانَ وَمَكَّةَ ذُكِرُوا لِحَيٍّ مِنْ هُذَيْلٍ يُقَالُ لَهُمْ بَنُو لَحْيَانَ فَتَبِعُوهُمْ بِقَرِيبٍ مِنْ مِائَةِ رَامٍ فَاقْتَصُّوا آثَارَهُمْ حَتَّى أَتَوْا مَنْزِلًا نَزَلُوهُ فَوَجَدُوا فِيهِ نَوَى تَمْرٍ تَزَوَّدُوهُ مِنْ الْمَدِينَةِ فَقَالُوا هَذَا تَمْرُ يَثْرِبَ فَتَبِعُوا آثَارَهُمْ حَتَّى لَحِقُوهُمْ فَلَمَّا انْتَهَى عَاصِمٌ وَأَصْحَابُهُ لَجَئُوا إِلَى فَدْفَدٍ وَجَاءَ الْقَوْمُ فَأَحَاطُوا بِهِمْ فَقَالُوا لَكُمْ الْعَهْدُ وَالْمِيثَاقُ إِنْ نَزَلْتُمْ إِلَيْنَا أَنْ لَا نَقْتُلَ مِنْكُمْ رَجُلًا فَقَالَ عَاصِمٌ أَمَّا أَنَا فَلَا أَنْزِلُ فِي ذِمَّةِ كَافِرٍ اللَّهُمَّ أَخْبِرْ عَنَّا نَبِيَّكَ فَقَاتَلُوهُمْ حَتَّى قَتَلُوا عَاصِمًا فِي سَبْعَةِ نَفَرٍ بِالنَّبْلِ وَبَقِيَ خُبَيْبٌ وَزَيْدٌ وَرَجُلٌ آخَرُ فَأَعْطَوْهُمْ الْعَهْدَ وَالْمِيثَاقَ فَلَمَّا أَعْطَوْهُمْ الْعَهْدَ وَالْمِيثَاقَ نَزَلُوا إِلَيْهِمْ فَلَمَّا اسْتَمْكَنُوا مِنْهُمْ حَلُّوا أَوْتَارَ قِسِيِّهِمْ فَرَبَطُوهُمْ بِهَا فَقَالَ الرَّجُلُ الثَّالِثُ الَّذِي مَعَهُمَا هَذَا أَوَّلُ الْغَدْرِ فَأَبَى أَنْ يَصْحَبَهُمْ فَجَرَّرُوهُ وَعَالَجُوهُ عَلَى أَنْ يَصْحَبَهُمْ فَلَمْ يَفْعَلْ فَقَتَلُوهُ وَانْطَلَقُوا بِخُبَيْبٍ وَزَيْدٍ حَتَّى بَاعُوهُمَا بِمَكَّةَ فَاشْتَرَى خُبَيْبًا بَنُو الْحَارِثِ بْنِ عَامِرِ بْنِ نَوْفَلٍ وَكَانَ خُبَيْبٌ هُوَ قَتَلَ الْحَارِثَ يَوْمَ بَدْرٍ فَمَكَثَ عِنْدَهُمْ أَسِيرًا حَتَّى إِذَا أَجْمَعُوا قَتْلَهُ اسْتَعَارَ مُوسًى مِنْ بَعْضِ بَنَاتِ الْحَارِثِ لِيَسْتَحِدَّ بِهَا فَأَعَارَتْهُ قَالَتْ فَغَفَلْتُ عَنْ صَبِيٍّ لِي فَدَرَجَ إِلَيْهِ حَتَّى أَتَاهُ فَوَضَعَهُ عَلَى فَخِذِهِ فَلَمَّا رَأَيْتُهُ فَزِعْتُ فَزْعَةً عَرَفَ ذَاكَ مِنِّي وَفِي يَدِهِ الْمُوسَى فَقَالَ أَتَخْشَيْنَ أَنْ أَقْتُلَهُ مَا كُنْتُ لِأَفْعَلَ ذَاكِ إِنْ شَاءَ اللَّهُ وَكَانَتْ تَقُولُ مَا رَأَيْتُ أَسِيرًا قَطُّ خَيْرًا مِنْ خُبَيْبٍ لَقَدْ رَأَيْتُهُ يَأْكُلُ مِنْ قِطْفِ عِنَبٍ وَمَا بِمَكَّةَ يَوْمَئِذٍ ثَمَرَةٌ وَإِنَّهُ لَمُوثَقٌ فِي الْحَدِيدِ وَمَا كَانَ إِلَّا رِزْقٌ رَزَقَهُ اللَّهُ فَخَرَجُوا بِهِ مِنْ الْحَرَمِ لِيَقْتُلُوهُ فَقَالَ دَعُونِي أُصَلِّي رَكْعَتَيْنِ ثُمَّ انْصَرَفَ إِلَيْهِمْ فَقَالَ لَوْلَا أَنْ تَرَوْا أَنَّ مَا بِي جَزَعٌ مِنْ الْمَوْتِ لَزِدْتُ فَكَانَ أَوَّلَ مَنْ سَنَّ الرَّكْعَتَيْنِ عِنْدَ الْقَتْلِ هُوَ ثُمَّ قَالَ اللَّهُمَّ أَحْصِهِمْ عَدَدًا ثُمَّ قَالَ مَا أُبَالِي حِينَ أُقْتَلُ مُسْلِمًاعَلَى أَيِّ شِقٍّ كَانَ لِلَّهِ مَصْرَعِيوَذَلِكَ فِي ذَاتِ الْإِلَهِ وَإِنْ يَشَأْيُبَارِكْ عَلَى أَوْصَالِ شِلْوٍ مُمَزَّعِثُمَّ قَامَ إِلَيْهِ عُقبَةُ بْنُ الْحَارِثِ فَقَتَلَهُ وَبَعَثَتْ قُرَيْشٌ إِلَى عَاصِمٍ لِيُؤْتَوْا بِشَيْءٍ مِنْ جَسَدِهِ يَعْرِفُونَهُ وَكَانَ عَاصِمٌ قَتَلَ عَظِيمًا مِنْ عُظَمَائِهِمْ يَوْمَ بَدْرٍ فَبَعَثَ اللَّهُ عَلَيْهِ مِثْلَ الظُّلَّةِ مِنْ الدَّبْرِ فَحَمَتْهُ مِنْ رُسُلِهِمْ فَلَمْ يَقْدِرُوا مِنْهُ عَلَى شَيْءٍ","id":"Telah menceritakan kepada kami [Ibrahim bin Musa] telah mengabarkan kepada kami [Hisyam bin Yusuf] dari [Ma'mar] dari [Az Zuhri] dari ['Amru bin Abu Sufyan Ats Tsaqafi] dari [Abu Hurairah] radliallahu 'anhu, dia berkata, Rasulullah shallallahu 'alaihi wasallam pernah mengutus sekelompok pasukan pengintai yang dipimpin oleh 'Ashim bin Tsabit -dia adalah kakek 'Ashim bin Umar- Lalu mereka berangkat, mereka kemudian singgah disuatu tempat antara 'Usfan dan Makkah, keberadaan mereka diberitahukan kepada suatu perkampungan dari suku Hudzail, mereka biasa disebut dengan Bani Lahyan. Maka mereka diikuti oleh orang-orang dari perkampuangan tersebut, yaitu sekitar seratus orang pemanah, mereka mengiuti jejak para sahabat tersebut, sesampainya mereka di suatu persinggahan yang pernah disinggahi oleh para sahabat, mereka mendapati biji kurma Madinah yang dibawa oleh para sahabat sebagai perbekalan mereka, mereka berkata, \"Ini adalah kurma Madinah.\" Mereka terus mengikuti para sahabat sehingga berhasil menyusulnya, ketika 'Ashim bin Tsabit dan para sahabatnya merasakan kehadiran orang-orang itu, para sahabat langsung berlindung dibalik bukit, orang-orang itu datang dan langsung mengepung, mereka berkata, \"Turunlah kalian, kalian dapat membuat perjanjian dan kesepakatan, supaya kami tidak membunuh seorangpun dari kalian, \" 'Ashim bin Tsabit menimpali; \"Demi Allah, aku tidak akan berada dalam lindungan orang kafir, ya Allah beritahukanlah kabar kami kepada Nabi-Mu shallallahu 'alaihi wasallam, \" Lalu mereka menyerang para sahabat hingga berhasil membunuh 'Ashim bersama tujuh pemanah lainnya, tinggal tersisa Khubaib, Zaid dan seorang sahabat lagi. Lalu mereka membuat perjanjian dan kesepakatan dengan mereka jika bersedia untuk turun dan menyerahkan diri. Tatkala pasukan tersebut telah menyandera tiga utusan Nabi, mereka memudar tali anak panah mereka untuk mengikat sandra mereka dengan tali itu, maka laki-laki yang ketiga berkata, \"Ini adalah pengkhinatan pertama, demi Allah aku tidak akan menjadi teman kalian, \" lalu mereka menyeretnya, namun ia tetap berontak, akhirnya mereka membunuhnya dan mereka pergi dengan membawa Khubaib dan Zaid hingga mereka menjualnya di Makkah. Bani Harits bin 'Amir bin Naufal lalu membeli Khubaib. -Khubaib adalah orang yang telah membunuh Al Harits ketika perang badar- Khubaib menjadi tawanan bagi mereka hingga mereka sepakat untuk membunuhnya, lalu Khubaib meminjam pisau kecil dari salah satu anak perempuan Al Harits untuk membersihkan bulu kemaluannya, lalu ia meminjamkannya kepada Khubaib. Wanita itu berkata, \"Namun aku lalai dengan anak laki-laki kecilku, anak itu datang kepadanya, lalu ia mengambilnya dan mendudukkanya diatas pangkuannya. Ketika aku melihatnya, aku sangat takut dengan rasa takut yang bisa ia pahami, sedangkan pisau kecil masih ada dalam tangannya. Khubaib berkata, \"Apakah kamu takut kalau aku akan membunuhnya?, Insya Allah aku tidak akan melakukan itu.\" Wanita itu berkata, \"Demi Allah aku tidak pernah melihat tawanan yang sangat baik seperti Khubaib, aku pernah melihatnya memakan setangkai anggur di tangannya dalam keadaan terikat dengan rantai besi, padahal di Makkah tidak ada buah anggur, tidaklah hal itu melainkan rizqi yang Allah berikan kepada Khubaib.\" Lalu mereka membawa Khubaib keluar dari Haram untuk membunuhnya. Khubaib berkata, \" \"Berikanlah kesempatan kepadaku untuk mengerjakan (shalat) dua raka'at!\" Setelah itu Khubaib kembali kepada mereka dan berkata, \"Sekiranya aku tidak kuwatir kalian menganggapku takut dari kematian, niscaya aku akan menambah bilangan raka'atku.\" Dan dialah orang yang pertama kali melakukan shalat dua raka'at sebelum menghadapi kematian, kemudian ia berkata, \"Ya Allah hitunglah jumlah mereka, \" kemudian dia melanjutkan; \"Aku tak peduli bila terbunuh sebagai seorang muslim, di bagian manapun hanya untuk Allah kematianku, yang demikian bagi Sang Ilah, jika Dia berkehendak akan memberkahi semua persendian jasad yang terpisah.\" Lalu berdirilah 'Uqbah bin Al Harits dan membunuhnya. Orang-orang Quraisy kemudian mengutus utusan kepada 'Ashim untuk mendapatkan sebagian jasadnya sebagai bukti, sebab ia telah membunuh sebagian besar dari para pembesar mereka pada perang badar, ternyata Allah mengutus semacam gulungan debu yang menggulung utusan mereka hingga mereka tidak berhasil mengambil sedikitpun dari jasad Khubaib.\""},"3575":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ حَدَّثَنَا سُفْيَانُ عَنْ عَمْرٍو سَمِعَ جَابِرًا يَقُولُالَّذِي قَتَلَ خُبَيْبًا هُوَ أَبُو سِرْوَعَةَ","id":"Telah menceritakan kepada kami [Abdullah bin Muhammad] telah menceritakan kepada kami [Sufyan] dari ['Amru] dia mendengar [Jabir] berkata, \"Yang membunuh Khubaib adalah Abu Sirwa'ah.\""},"3576":{"ar":"حَدَّثَنَا أَبُو مَعْمَرٍ حَدَّثَنَا عَبْدُ الْوَارِثِ حَدَّثَنَا عَبْدُ الْعَزِيزِ عَنْ أَنَسٍ رَضِيَ اللَّهُ عَنْهُ قَالَبَعَثَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَبْعِينَ رَجُلًا لِحَاجَةٍ يُقَالُ لَهُمْ الْقُرَّاءُ فَعَرَضَ لَهُمْ حَيَّانِ مِنْ بَنِي سُلَيْمٍ رِعْلٌ وَذَكْوَانُ عِنْدَ بِئْرٍ يُقَالُ لَهَا بِئْرُ مَعُونَةَ فَقَالَ الْقَوْمُ وَاللَّهِ مَا إِيَّاكُمْ أَرَدْنَا إِنَّمَا نَحْنُ مُجْتَازُونَ فِي حَاجَةٍ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَتَلُوهُمْ فَدَعَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَيْهِمْ شَهْرًا فِي صَلَاةِ الْغَدَاةِ وَذَلِكَ بَدْءُ الْقُنُوتِ وَمَا كُنَّا نَقْنُتُقَالَ عَبْدُ الْعَزِيزِ وَسَأَلَ رَجُلٌ أَنَسًا عَنْ الْقُنُوتِ أَبَعْدَ الرُّكُوعِ أَوْ عِنْدَ فَرَاغٍ مِنْ الْقِرَاءَةِ قَالَ لَا بَلْ عِنْدَ فَرَاغٍ مِنْ الْقِرَاءَةِ","id":"Telah menceritakan kepada kami [Abu Ma'mar] telah menceritakan kepada kami [Abdul Warits] telah menceritakan kepada kami [Abdul Aziz] dari [Anas] radliallahu 'anhu, dia berkata, Nabi shallallahu 'alaihi wasallam pernah mengutus tujuhpuluh orang untuk suatu keperluan, mereka disebut sebagai qurra` (para ahli al Qur'an), mereka di hadang oleh penduduk dari bani Sulaim, Ri'l dan Dzakwan dekat mata air yang disebut dengan Bi'r Ma'unah, mereka berkata, \"Demi Allah, bukan kalian yang kami inginkan, kami hanya ada perlu dengan Nabi shallallahu 'alaihi wasallam.\" Mereka akhirnya membunuh para sahabat tersebut, maka Nabi shallallahu 'alaihi wasallam mendo'akan kecelakan kepada mereka (Sulaim, Ri'l dan Dzakwan) selama sebulan pada shalat shubuh, itu adalah awal kali dilakukannya qunut, sebelumnya kami tida pernah melakukan do'a qunut.\" [Abdul Aziz] mengatakan; seseorang bertanya kepada [Anas] tentang qunut, apakah ia dikerjakan setelah rukuk ataukah setelah selesai membaca ayat?\" Anas menjawab; \"Tidak, bahkan dikerjakan setelah selesai membaca ayat.\""},"3577":{"ar":"حَدَّثَنَا مُسْلِمٌ حَدَّثَنَا هِشَامٌ حَدَّثَنَا قَتَادَةُ عَنْ أَنَسٍ قَالَقَنَتَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ شَهْرًا بَعْدَ الرُّكُوعِ يَدْعُو عَلَى أَحْيَاءٍ مِنْ الْعَرَبِ","id":"Telah menceritakan kepada kami [Muslim] telah menceritakan kepada kami [Hisyam] telah menceritakan kepada kami [Qatadah] dari [Anas] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam pernah qunut selama sebulan setelah rukuk, beliau mendo'akan (kecelakaan atas) penduduk sekitar arab.\""},"3578":{"ar":"حَدَّثَنِي عَبْدُ الْأَعْلَى بْنُ حَمَّادٍ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ حَدَّثَنَا سَعِيدٌ عَنْ قَتَادَةَ عَنْ أَنَسِ بْنِ مَالِكٍ رَضِيَ اللَّهُ عَنْهُأَنَّ رِعْلًا وَذَكْوَانَ وَعُصَيَّةَ وَبَنِي لَحْيَانَ اسْتَمَدُّوا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى عَدُوٍّ فَأَمَدَّهُمْ بِسَبْعِينَ مِنْ الْأَنْصَارِ كُنَّا نُسَمِّيهِمْ الْقُرَّاءَ فِي زَمَانِهِمْ كَانُوا يَحْتَطِبُونَ بِالنَّهَارِ وَيُصَلُّونَ بِاللَّيْلِ حَتَّى كَانُوا بِبِئْرِ مَعُونَةَ قَتَلُوهُمْ وَغَدَرُوا بِهِمْ فَبَلَغَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَنَتَ شَهْرًا يَدْعُو فِي الصُّبْحِ عَلَى أَحْيَاءٍ مِنْ أَحْيَاءِ الْعَرَبِ عَلَى رِعْلٍ وَذَكْوَانَ وَعُصَيَّةَ وَبَنِي لَحْيَانَ قَالَ أَنَسٌ فَقَرَأْنَا فِيهِمْ قُرْآنًا ثُمَّ إِنَّ ذَلِكَ رُفِعَ بَلِّغُوا عَنَّا قَوْمَنَا أَنَّا لَقِينَا رَبَّنَا فَرَضِيَ عَنَّا وَأَرْضَانَا وَعَنْ قَتَادَةَ عَنْ أَنَسِ بْنِ مَالِكٍ حَدَّثَهُ أَنَّ نَبِيَّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَنَتَ شَهْرًا فِي صَلَاةِ الصُّبْحِ يَدْعُو عَلَى أَحْيَاءٍ مِنْ أَحْيَاءِ الْعَرَبِ عَلَى رِعْلٍ وَذَكْوَانَ وَعُصَيَّةَ وَبَنِي لِحْيَانَزَادَ خَلِيفَةُ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ حَدَّثَنَا سَعِيدٌ عَنْ قَتَادَةَ حَدَّثَنَا أَنَسٌ أَنَّ أُولَئِكَ السَّبْعِينَ مِنْ الْأَنْصَارِ قُتِلُوا بِبِئْرِ مَعُونَةَ قُرْآنًا كِتَابًا نَحْوَهُ","id":"Telah menceritakan kepadaku [Abdul A'la bin Hammad] telah menceritakan kepada kami [Yazid bin Zurai'] telah menceritakan kepada kami [Sa'id] dari [Qatadah] dari [Anas bin Malik] radliallahu 'anhu, bahwa Dzakwan, 'Ushayyah dan bani Lahyan meminta bantuan kepada Rasulullah shallallahu 'alaihi wasallam untuk menghadapi musuh, lalu beliau mengirim bala bantuan tujuh puluh sahabat Anshar, kami menyebut mereka sebagai al Qurra' di zaman mereka. Mereka biasa mencari kayu bakar di siang hari dan shalat malam di malam harinya, ketika mereka tiba di Bi'rul Ma'unah, mereka (orang-orang kafir) membunuh dan mengkhianati mereka. Ketika peristiwa itu sampai kepada Nabi shallallahu 'alaihi wasallam, beliau melaksanakan qunut selama sebulan dalam shalat shubuh, beliau mendo'akan kecelakaan terhadap penduduk di antara penduduk-penduduk Arab, yaitu Ri'l, Dzakwan, 'Ushayyah serta bani Lahyan.\" Anas berkata, \"Maka kami membaca (kisah mereka yang diabadikan) dalam al Quran, namun kemudian itu dimasukh (dihapus), yaitu ayat yang berbunyi 'Sampaikanlah kisah kami kepada kaum kami, bahwa kami telah berjumpa dengan Rabb kami, Dia meridlai kami dan kamipun ridla dengan-Nya'.\" Dan dari [Qatadah] dari [Anas bin Malik] dia menceritakan kepadanya, bahwa Nabiyullah shallallahu 'alaihi wasallam melaksanakan qunut dishalat shubuh selama sebulan, beliau mendo'akan kebinasaan beberapa perampungan Arab seperti Ri'l, Dzakwan, 'Ushayyah dan bani Lahyan.\" [Khalifah] menambahkan; telah menceritakan kepada kami [Yazid bin Zurai'] telah menceritakan kepada kami [Sa'id] dari [Qatadah] telah menceritakan kepada kami [Anas] bahwa ketujuh puluh sahabat Anshar tersebut dibunuh di Bi'rul Ma'unah (kami membaca) dalam Al Qur'an...sebagaimana riwayat di atas.\""},"3579":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ حَدَّثَنَا هَمَّامٌ عَنْ إِسْحَاقَ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي طَلْحَةَ قَالَ حَدَّثَنِي أَنَسٌأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعَثَ خَالَهُ أَخٌ لِأُمِّ سُلَيْمٍ فِي سَبْعِينَ رَاكِبًا وَكَانَ رَئِيسَ الْمُشْرِكِينَ عَامِرُ بْنُ الطُّفَيْلِ خَيَّرَ بَيْنَ ثَلَاثِ خِصَالٍ فَقَالَ يَكُونُ لَكَ أَهْلُ السَّهْلِ وَلِي أَهْلُ الْمَدَرِ أَوْ أَكُونُ خَلِيفَتَكَ أَوْ أَغْزُوكَ بِأَهْلِ غَطَفَانَ بِأَلْفٍ وَأَلْفٍ فَطُعِنَ عَامِرٌ فِي بَيْتِ أُمِّ فُلَانٍ فَقَالَ غُدَّةٌ كَغُدَّةِ الْبَكْرِ فِي بَيْتِ امْرَأَةٍ مِنْ آلِ فُلَانٍ ائْتُونِي بِفَرَسِي فَمَاتَ عَلَى ظَهْرِ فَرَسِهِ فَانْطَلَقَ حَرَامٌ أَخُو أُمِّ سُلَيْمٍ وَهُوَ رَجُلٌ أَعْرَجُ وَرَجُلٌ مِنْ بَنِي فُلَانٍ قَالَ كُونَا قَرِيبًا حَتَّى آتِيَهُمْ فَإِنْ آمَنُونِي كُنْتُمْ وَإِنْ قَتَلُونِي أَتَيْتُمْ أَصْحَابَكُمْ فَقَالَ أَتُؤْمِنُونِي أُبَلِّغْ رِسَالَةَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَجَعَلَ يُحَدِّثُهُمْ وَأَوْمَئُوا إِلَى رَجُلٍ فَأَتَاهُ مِنْ خَلْفِهِ فَطَعَنَهُ قَالَ هَمَّامٌ أَحْسِبُهُ حَتَّى أَنْفَذَهُ بِالرُّمْحِ قَالَ اللَّهُ أَكْبَرُ فُزْتُ وَرَبِّ الْكَعْبَةِ فَلُحِقَ الرَّجُلُ فَقُتِلُوا كُلُّهُمْ غَيْرَ الْأَعْرَجِ كَانَ فِي رَأْسِ جَبَلٍ فَأَنْزَلَ اللَّهُ عَلَيْنَا ثُمَّ كَانَ مِنْ الْمَنْسُوخِ إِنَّا قَدْ لَقِينَا رَبَّنَا فَرَضِيَ عَنَّا وَأَرْضَانَا فَدَعَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَيْهِمْ ثَلَاثِينَ صَبَاحًا عَلَى رِعْلٍ وَذَكْوَانَ وَبَنِي لَحْيَانَ وَعُصَيَّةَ الَّذِينَ عَصَوْا اللَّهَ وَرَسُولَهُ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] telah menceritakan kepada kami [Hammam] dari [Ishaq bin Abdullah bin Abu Thalhah] dia berkata, telah menceritakan kepadaku [Anas], bahwa Nabi shallallahu 'alaihi wasallam pernah mengutus paman beliau, yaitu saudara laki-laki Ummu Sulaim, untuk menyertai tujuh puluh orang sahabatnya yang kemudian terbunuh di Bi'rul Ma'unah. Pemimpin musyrik pada saat itu adalah 'Amir bin Thufail, ia memberikan tiga pilihan. Thufail mengatakan, 'Bagimu penduduk Sahl dan untukku penduduk Madar, atau aku menjadi pemimpin bagimu atau aku akan memerangimu dengan mengerahkan penduduk Ghathafan sebanyak seribu dan seribu.' Amir ditikam di rumah Ummu Fulan, lalu dia berkata, 'Penyakit seperti penyakit unta, di rumah seorang wanita dari keluarga bani fulan, datangkan kudaku kepadaku.' Maka ia meninggal di atas kudanya. Lalu berangkatlah Haram, yaitu saudara Ummu Sulaim -dia adalah seorang laki-laki yang cacat- dan dia berangkat bersama seorang laki-laki dari Bani Fulan, dia berkata, \"Hendaknya posisi kalian berada dekat denganku, hingga aku dapat mendatangi mereka, jika mereka memberikan jaminan keamanan kepadaku, kalian dekat, namun jika mereka membunuhku, maka mereka dapat mendatangi sahabat kalian.\" Haram lalu angkat bicara, \"Apakah kalian mempercayaiku jika aku akan menyampaikan risalah Rasulullah shallallahu 'alaihi wasallam?\" kemudian Haram mengajak bicara mereka, ternyata mereka memberi isyarat kepada salah seorang di antara mereka, lantas laki-laki tersebut mendatangi dari belakang dan menikamnya dengan tombak hingga tembus, \" Haram berkata, \"Allahu akbar, demi Rabb Ka'bah aku menang.\" Akhirnya semua sahabat ditangkap dan dibunuh selain laki-laki yang cacat, ketika itu ia tengah berada di puncak gunung, maka Allah menurunkan ayat-Nya kepada kami, kemudian ayat tersebut termasuk yang dimansukh, yaitu ayat: \"Sesungguhnya kami telah menemui Rabb kami, maka Dia meridlai kami dan kamipun ridla terhadap-Nya.\" Setelah itu Nabi shallallahu 'alaihi wasallam mendo'akan kebinasaan kaum tersebut selama tigapuluh hari, yaitu terhadap Ri'l, Dzakwan, Lahyan dan 'Ushayyah yang telah mendurhakai Allah dan Rasul-Nya shallallahu 'alaihi wasallam.\""},"3580":{"ar":"حَدَّثَنِي حِبَّانُ أَخْبَرَنَا عَبْدُ اللَّهِ أَخْبَرَنَا مَعْمَرٌ قَالَ حَدَّثَنِي ثُمَامَةُ بْنُ عَبْدِ اللَّهِ بْنِ أَنَسٍ أَنَّهُ سَمِعَ أَنَسَ بْنَ مَالِكٍ رَضِيَ اللَّهُ عَنْهُ يَقُولُلَمَّا طُعِنَ حَرَامُ بْنُ مِلْحَانَ وَكَانَ خَالَهُ يَوْمَ بِئْرِ مَعُونَةَ قَالَ بِالدَّمِ هَكَذَا فَنَضَحَهُ عَلَى وَجْهِهِ وَرَأْسِهِ ثُمَّ قَالَ فُزْتُ وَرَبِّ الْكَعْبَةِ","id":"Telah menceritakan kepadaku [Hibban] telah mengabarkan kepada kami [Abdullah] telah mengabarkan kepada kami [Ma'mar] dia berkata, telah menceritakan kepadaku [Tsumamah bin Abdullah bin Anas] bahwa dia mendengar [Anas bin Malik] radliallahu 'anhu berkata, \"Ketika Haram bin Milhan ditikam -dia adalah paman beliau- pada peristiwa Bi'rul Ma'unah, dia memercikkan darahnya ke wajah dan kepalanya, lalu dia berkata, \"Demi Rabb pemilik Ka'bah, aku telah menang.\""},"3581":{"ar":"حَدَّثَنَا عُبَيْدُ بْنُ إِسْمَاعِيلَ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ هِشَامٍ عَنْ أَبِيهِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْاسْتَأْذَنَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَبُو بَكْرٍ فِي الْخُرُوجِ حِينَ اشْتَدَّ عَلَيْهِ الْأَذَى فَقَالَ لَهُ أَقِمْ فَقَالَ يَا رَسُولَ اللَّهِ أَتَطْمَعُ أَنْ يُؤْذَنَ لَكَ فَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنِّي لَأَرْجُو ذَلِكَ قَالَتْ فَانْتَظَرَهُ أَبُو بَكْرٍ فَأَتَاهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذَاتَ يَوْمٍ ظُهْرًا فَنَادَاهُ فَقَالَ أَخْرِجْ مَنْ عِنْدَكَ فَقَالَ أَبُو بَكْرٍ إِنَّمَا هُمَا ابْنَتَايَ فَقَالَ أَشَعَرْتَ أَنَّهُ قَدْ أُذِنَ لِي فِي الْخُرُوجِ فَقَالَ يَا رَسُولَ اللَّهِ الصُّحْبَةَ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الصُّحْبَةَ قَالَ يَا رَسُولَ اللَّهِ عِنْدِي نَاقَتَانِ قَدْ كُنْتُ أَعْدَدْتُهُمَا لِلْخُرُوجِ فَأَعْطَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِحْدَاهُمَا وَهِيَ الْجَدْعَاءُ فَرَكِبَا فَانْطَلَقَا حَتَّى أَتَيَا الْغَارَ وَهُوَ بِثَوْرٍ فَتَوَارَيَا فِيهِ فَكَانَ عَامِرُ بْنُ فُهَيْرَةَ غُلَامًا لِعَبْدِ اللَّهِ بْنِ الطُّفَيْلِ بْنِ سَخْبَرَةَ أَخُو عَائِشَةَ لِأُمِّهَا وَكَانَتْ لِأَبِي بَكْرٍ مِنْحَةٌ فَكَانَ يَرُوحُ بِهَا وَيَغْدُو عَلَيْهِمْ وَيُصْبِحُ فَيَدَّلِجُ إِلَيْهِمَا ثُمَّ يَسْرَحُ فَلَا يَفْطُنُ بِهِ أَحَدٌ مِنْ الرِّعَاءِ فَلَمَّا خَرَجَ خَرَجَ مَعَهُمَا يُعْقِبَانِهِ حَتَّى قَدِمَا الْمَدِينَةَ فَقُتِلَ عَامِرُ بْنُ فُهَيْرَةَ يَوْمَ بِئْرِ مَعُونَةَوَعَنْ أَبِي أُسَامَةَ قَالَ قَالَ هِشَامُ بْنُ عُرْوَةَ فَأَخْبَرَنِي أَبِي قَالَ لَمَّا قُتِلَ الَّذِينَ بِبِئْرِ مَعُونَةَ وَأُسِرَ عَمْرُو بْنُ أُمَيَّةَ الضَّمْرِيُّ قَالَ لَهُ عَامِرُ بْنُ الطُّفَيْلِ مَنْ هَذَا فَأَشَارَ إِلَى قَتِيلٍ فَقَالَ لَهُ عَمْرُو بْنُ أُمَيَّةَ هَذَا عَامِرُ بْنُ فُهَيْرَةَ فَقَالَ لَقَدْ رَأَيْتُهُ بَعْدَ مَا قُتِلَ رُفِعَ إِلَى السَّمَاءِ حَتَّى إِنِّي لَأَنْظُرُ إِلَى السَّمَاءِ بَيْنَهُ وَبَيْنَ الْأَرْضِ ثُمَّ وُضِعَ فَأَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَبَرُهُمْ فَنَعَاهُمْ فَقَالَ إِنَّ أَصْحَابَكُمْ قَدْ أُصِيبُوا وَإِنَّهُمْ قَدْ سَأَلُوا رَبَّهُمْ فَقَالُوا رَبَّنَا أَخْبِرْ عَنَّا إِخْوَانَنَا بِمَا رَضِينَا عَنْكَ وَرَضِيتَ عَنَّا فَأَخْبَرَهُمْ عَنْهُمْ وَأُصِيبَ يَوْمَئِذٍ فِيهِمْ عُرْوَةُ بْنُ أَسْماءَ بْنِ الصَّلْتِ فَسُمِّيَ عُرْوَةُ بِهِ وَمُنْذِرُ بْنُ عَمْرٍو سُمِّيَ بِهِ مُنْذِرًا","id":"Telah menceritakan kepada kami ['Ubaidullah bin Isma'il] telah menceritakan kepada kami [Abu Usamah] dari [Hisyam] dari [Ayahnya] dari ['Aisyah] radliallahu 'anha, dia berkata, \"Abu Bakr pernah meminta izin kepada Nabi shallallahu 'alaihi wasallam untuk hijrah ketika gangguan (orang-orang Quraisy) semakin menjadi-jadi, lalu beliau bersabda kepadanya: \"Berdiam aja dulu.\" Abu Bakar berkata, \"Wahai Rasulullah, apakah anda hendak menunggu perintah?\" Rasulullah shallallahu 'alaihi wasallam bersabda: \"Aku berharap hal itu.\" Aisyah melanjutkan, \"Abu Bakr lalu menunggu (perintah hijrah), suatu hari yaitu diwaktu siang, Rasulullah shallallahu 'alaihi wasallam datang menemuinya, beliau lalu menyerunya: \"Suruhlah orang-orang yang ada di sisimu untuk keluar.\" Abu Bakr menjawab, \"Sesungguhnya dia adalah kedua puteriku.\" Beliau bersabda: \"Apakah kamu merasa bahwa diriku telah diizinkan untuk berhijrah?\" Abu Bakr berkata, \"Apa perlu ditemani?\" Maka Nabi shallallahu 'alaihi wasallam menjawab: \"Benar, aku perlu ditemani.\" Abu Bakr berkata, \"Wahai Rasulullah, sesungguhnya aku memiliki dua ekor unta yang telah aku persiapkan untuk berhijrah.\" Kemudian Abu Bakr memberi salah satu hewan tunggannya, yaitu al Jad'a`, keduanya pun berangkat hingga sampai di gua Tsur lalu keduanya bersembunyi di dalamnya. Sementara Amir bin Fuhairah adalah seorang budak milik Abdullah bin Thufail bin Sahbarah, saudara seibu 'Aisyah, dan Abu Bakr juga memiliki beberapa ekor kambing perah, yang setiap pagi dan sore dibawa oleh Amir bin Fuhrairah untuk keduanya. Kemudian ia pergi dimalam hari untuk menemui keduanya, selepas itu Amir bin Fuhairah pergi merumput sehingga tak satupun dari para penggembala yang tahu, tatkala Amir bin Fuhairah berangkat, maka Abu Bakr dan Nabi keluar mengikuti dari belakang hingga keduanya tiba di Madinah. Dan Amir bin Fuhairah gugur pada peristiwa Bi'rul Ma'unah.\" Dan dari Abu Usamah dia berkata, Hisyam bin 'urwah mengatakan; telah mengabarkan kepadaku Ayahku dia berkata, \"Ketika para sahabat dibunuh di Bi'rul Ma'unah dan 'Amr bin Umayyah Adh Dlamri ditawan, Amir bin Thufail kemudian berkata kepadanya, \"Ini adalah Amir bin Fuhairah.\" Ia berkata, \"Sungguh aku telah melihatnya setelah dibunuh dia diangkat ke langit hingga aku melihat ke langit, dia berada di antara langit dan bumi, lalu dia diturunkan. Ketika berita (kematian) mereka sampai kepada Nabi shallallahu 'alaihi wasallam, maka beliau pun mengabarkan berita kematian mereka sambil bersabda: \"Sesungguhnya sahabat-sahabat kalian telah terbunuh, mereka meminta kepada Rabb mereka dengan mengatakan, \"Wahai Rabb kami, sampaikan berita kami kepada saudara-saudara kami tentang apa yang membuat kami ridla terhadap-Mu dan Engkau ridla terhadap kami, \" maka Allah mengabarkan berita mereka.\" Diantara mereka yang terbunuh pada peristiwa tersebut adalah Urwah bin Asma' bin Ash Shalt, lantas 'Urwah pun diberi nama sesuai dengan namanya, begitu juga dengan Mundzir bin Amir yang kemudian diberikan sebagai nama bagi Mundzir.\""},"3582":{"ar":"حَدَّثَنَا مُحَمَّدٌ أَخْبَرَنَا عَبْدُ اللَّهِ أَخْبَرَنَا سُلَيْمَانُ التَّيْمِيُّ عَنْ أَبِي مِجْلَزٍ عَنْ أَنَسٍ رَضِيَ اللَّهُ عَنْهُ قَالَقَنَتَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعْدَ الرُّكُوعِ شَهْرًا يَدْعُو عَلَى رِعْلٍ وَذَكْوَانَ وَيَقُولُ عُصَيَّةُ عَصَتْ اللَّهَ وَرَسُولَهُ","id":"Telah menceritakan kepada kami [Muhammad] telah mengabarkan kepada kami [Abdullah] telah mengabarkan kepada kami [Sulaiman At Taimi] dari [Abu Mijlaz] dari [Anas] radliallahu 'anhu, dia berkata, \"Nabi shallallahu 'alaihi wasallam melaksanakan qunut setelah rukuk selama sebulan, beliau mendo'akan kebinasaan terhadap Ri'l, Dzakwan, beliau bersabda: \"'Ushayyah adalah kaum yang durhaka kepada Allah dan Rasul-Nya.\""},"3583":{"ar":"حَدَّثَنَا يَحْيَى بْنُ بُكَيْرٍ حَدَّثَنَا مَالِكٌ عَنْ إِسْحَاقَ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي طَلْحَةَ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَدَعَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى الَّذِينَ قَتَلُوا يَعْنِي أَصْحَابَهُ بِبِئْرِ مَعُونَةَ ثَلَاثِينَ صَبَاحًا حِينَ يَدْعُو عَلَى رِعْلٍ وَلَحْيَانَ وَعُصَيَّةَ عَصَتْ اللَّهَ وَرَسُولَهُ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَنَسٌ فَأَنْزَلَ اللَّهُ تَعَالَى لِنَبِيِّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الَّذِينَ قُتِلُوا أَصْحَابِ بِئْرِ مَعُونَةَ قُرْآنًا قَرَأْنَاهُ حَتَّى نُسِخَ بَعْدُ بَلِّغُوا قَوْمَنَا فَقَدْ لَقِينَا رَبَّنَا فَرَضِيَ عَنَّا وَرَضِينَا عَنْهُ","id":"Telah menceritakan kepada kami [Yahya bin Bukair] telah menceritakan kepada kami [Malik] dari [Ishaq bin Abdullah bin Abu Thalhah] dari [Anas bin Malik] dia berkata, \"Nabi shallallahu 'alaihi wasallam mendo'akan kebinasaan terhadap kaum yang telah membunuh para sahabat beliau di Bi'rul Ma'unah selama tiga puluh hari, beliau mendo'akan (kebinasaan) terhadap Ri'l, Lahyan dan 'Ushayyah yang durhaka kepada Allah dan Rasul-Nya shallallahu 'alaihi wasallam.\" Anas mengatakan, \"Lalu Allah Ta'ala menurunkan ayat untuk memberitahukan kepada Nabi-Nya shallallahu 'alaihi wasallam mengenai orang-orang yang terbunuh di peristiwa Bi'rul Ma'unah, dan ayat tersebut sempat kami baca hingga akhirnya dimansukh, ayat itu adalah '(Sesungguhnya kami telah berjumpa dengan Rabb kami, dan Rabb kamipun ridla terhadap kami, dan kamipun ridla terhadap-Nya) '.\""},"3584":{"ar":"حَدَّثَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ عُبَيْدِ اللَّهِ قَالَ أَخْبَرَنِي نَافِعٌ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَرَضَهُ يَوْمَ أُحُدٍ وَهُوَ ابْنُ أَرْبَعَ عَشْرَةَ سَنَةً فَلَمْ يُجِزْهُ وَعَرَضَهُ يَوْمَ الْخَنْدَقِ وَهُوَ ابْنُ خَمْسَ عَشْرَةَ سَنَةً فَأَجَازَهُ","id":"Telah menceritakan kepada kami [Ya'qub bin Ibrahim] telah menceritakan kepada kami [Yahya bin Sa'id] dari ['Ubaidullah] dia berkata, telah mengabarkan kepadaku [Nafi'] dari [Ibnu Umar] radliallahu 'anhuma bahwa Nabi shallallahu 'alaihi wasallam pernah mendapatinya dalam barisan perang Uhud ketika berusia empat belas tahun, namun beliau tidak mengizinkannya, dan kemudian beliau kembali menemukannya dalam barisan perang Khandaq, ketika ia berusia lima belas tahun, beliau akhirnya mengizinkannya.\""},"3585":{"ar":"حَدَّثَنِي قُتَيْبَةُ حَدَّثَنَا عَبْدُ الْعَزِيزِ عَنْ أَبِي حَازِمٍ عَنْ سَهْلِ بْنِ سَعْدٍ رَضِيَ اللَّهُ عَنْهُ قَالَكُنَّا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الْخَنْدَقِ وَهُمْ يَحْفِرُونَ وَنَحْنُ نَنْقُلُ التُّرَابَ عَلَى أَكْتَادِنَا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اللَّهُمَّ لَا عَيْشَ إِلَّا عَيْشُ الْآخِرَهْ فَاغْفِرْ لِلْمُهَاجِرِينَ وَالْأَنْصَارِ","id":"Telah menceritakan kepadaku [Qutaibah] telah menceritakan kepada kami [Abdul Aziz] dari [Abu Hazim] dari [Sahl bin Sa'd] radliallahu 'anhu, dia berkata, \"Kami pernah bersama Rasulullah shallallahu 'alaihi wasallam pada perang Khandaq, sementara para sahabat tengah menggali parit, sedangkan kami yang mengangkuti tanah di atas pundak kami. Rasulullah shallallahu 'alaihi wasallam kemudian bersabda: \"Ya Allah, tidak ada kehidupan (yang hakiki) kecuali kehidupan akhirat, maka ampunilah kaum Muhajirin dan Anshar.\""},"3586":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ حَدَّثَنَا مُعَاوِيَةُ بْنُ عَمْرٍو حَدَّثَنَا أَبُو إِسْحَاقَ عَنْ حُمَيْدٍ سَمِعْتُ أَنَسًا رَضِيَ اللَّهُ عَنْهُ يَقُولُخَرَجَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى الْخَنْدَقِ فَإِذَا الْمُهَاجِرُونَ وَالْأَنْصَارُ يَحْفِرُونَ فِي غَدَاةٍ بَارِدَةٍ فَلَمْ يَكُنْ لَهُمْ عَبِيدٌ يَعْمَلُونَ ذَلِكَ لَهُمْ فَلَمَّا رَأَى مَا بِهِمْ مِنْ النَّصَبِ وَالْجُوعِ قَالَ اللَّهُمَّ إِنَّ الْعَيْشَ عَيْشُ الْآخِرَهْفَاغْفِرْ لِلْأَنْصَارِ وَالْمُهَاجِرَهْفَقَالُوا مُجِيبِينَ لَهُ نَحْنُ الَّذِينَ بَايَعُوا مُحَمَّدَاعَلَى الْجِهَادِ مَا بَقِينَا أَبَدَا","id":"Telah menceritakan kepadaku [Abdullah bin Muhammad] telah menceritakan kepada kami [Mu'awiyah bin 'Amru] telah menceritakan kepada kami [Abu Ishaq] dari [Humaid] aku mendengar [Anas] radliallahu 'anhu berkata, \"Rasulullah shallallahu 'alaihi wasallam keluar menuju khandaq (parit), sementara kaum Muhajirin dan Anshar tengah menggali parit dipagi hari yang sangat dingin, sementara mereka tidak memiliki budak-budak yang membantu mereka bekerja, ketika beliau melihat mereka kepayahan dan kelaparan, beliau bersabda: \"Ya Allah, sesungguhnya kehidupan (yang hakiki) adalah kehidupan akhirat, maka ampunilah kaum Anshar dan Muhajirin.\" Mendengar itu, para sahabat menjawab, \"Kami adalah orang-orang yang telah berba'iat kepada Muhammad atas Jihad, dan kami masih tetap seperti itu selama-lamanya.\""},"3587":{"ar":"حَدَّثَنَا أَبُو مَعْمَرٍ حَدَّثَنَا عَبْدُ الْوَارِثِ عَنْ عَبْدِ الْعَزِيزِ عَنْ أَنَسٍ رَضِيَ اللَّهُ عَنْهُ قَالَجَعَلَ الْمُهَاجِرُونَ وَالْأَنْصَارُ يَحْفِرُونَ الْخَنْدَقَ حَوْلَ الْمَدِينَةِ وَيَنْقُلُونَ التُّرَابَ عَلَى مُتُونِهِمْ وَهُمْ يَقُولُونَ نَحْنُ الَّذِينَ بَايَعُوا مُحَمَّدَاعَلَى الْإِسْلَامِ مَا بَقِينَا أَبَدَاقَالَ يَقُولُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ يُجِيبُهُمْ اللَّهُمَّ إِنَّهُ لَا خَيْرَ إِلَّا خَيْرُ الْآخِرَهْفَبَارِكْ فِي الْأَنْصَارِ وَالْمُهَاجِرَهْقَالَ يُؤْتَوْنَ بِمِلْءِ كَفِّي مِنْ الشَّعِيرِ فَيُصْنَعُ لَهُمْ بِإِهَالَةٍ سَنِخَةٍ تُوضَعُ بَيْنَ يَدَيْ الْقَوْمِ وَالْقَوْمُ جِيَاعٌ وَهِيَ بَشِعَةٌ فِي الْحَلْقِ وَلَهَا رِيحٌ مُنْتِنٌ","id":"Telah menceritakan kepada kami [Abu Ma'mar] telah menceritakan kepada kami [Abdul Warits] dari [Abdul Aziz] dari [Anas] radliallahu 'anhu, dia berkata, \"Ketika kaum Muhajirin dan Anshar tengah menggali parit di sekeliling Madinah, dan memikul tanah di atas pundak-pundak, mereka bersenandung, \"Kami adalah orang-orang yang telah berbai'at kepada Muhamamd atas Islam, dan kami masih tetap seperti itu selama-lamanya.\" Anas melanjutkan, \"Ketika Nabi shallallahu 'alaihi wasallam mendengar itu, maka beliau membalasnya: \"Ya Allah, sesungguhnya tidak ada kebaikan (yang hakiki) kecuali kebaikan akhirat, maka berkahilah kaum Anshar dan Muhajirin.\""},"3588":{"ar":"حَدَّثَنَا خَلَّادُ بْنُ يَحْيَى حَدَّثَنَا عَبْدُ الْوَاحِدِ بْنُ أَيْمَنَ عَنْ أَبِيهِ قَالَ أَتَيْتُ جَابِرًا رَضِيَ اللَّهُ عَنْهُ فَقَالَإِنَّا يَوْمَ الْخَنْدَقِ نَحْفِرُ فَعَرَضَتْ كُدْيَةٌ شَدِيدَةٌ فَجَاءُوا النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالُوا هَذِهِ كُدْيَةٌ عَرَضَتْ فِي الْخَنْدَقِ فَقَالَ أَنَا نَازِلٌ ثُمَّ قَامَ وَبَطْنُهُ مَعْصُوبٌ بِحَجَرٍ وَلَبِثْنَا ثَلَاثَةَ أَيَّامٍ لَا نَذُوقُ ذَوَاقًا فَأَخَذَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمِعْوَلَ فَضَرَبَ فَعَادَ كَثِيبًا أَهْيَلَ أَوْ أَهْيَمَ فَقُلْتُ يَا رَسُولَ اللَّهِ ائْذَنْ لِي إِلَى الْبَيْتِ فَقُلْتُ لِامْرَأَتِي رَأَيْتُ بِالنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ شَيْئًا مَا كَانَ فِي ذَلِكَ صَبْرٌ فَعِنْدَكِ شَيْءٌ قَالَتْ عِنْدِي شَعِيرٌ وَعَنَاقٌ فَذَبَحَتْ الْعَنَاقَ وَطَحَنَتْ الشَّعِيرَ حَتَّى جَعَلْنَا اللَّحْمَ فِي الْبُرْمَةِ ثُمَّ جِئْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالْعَجِينُ قَدْ انْكَسَرَ وَالْبُرْمَةُ بَيْنَ الْأَثَافِيِّ قَدْ كَادَتْ أَنْ تَنْضَجَ فَقُلْتُ طُعَيِّمٌ لِي فَقُمْ أَنْتَ يَا رَسُولَ اللَّهِ وَرَجُلٌ أَوْ رَجُلَانِ قَالَ كَمْ هُوَ فَذَكَرْتُ لَهُ قَالَ كَثِيرٌ طَيِّبٌ قَالَ قُلْ لَهَا لَا تَنْزِعْ الْبُرْمَةَ وَلَا الْخُبْزَ مِنْ التَّنُّورِ حَتَّى آتِيَ فَقَالَ قُومُوا فَقَامَ الْمُهَاجِرُونَ وَالْأَنْصَارُ فَلَمَّا دَخَلَ عَلَى امْرَأَتِهِ قَالَ وَيْحَكِ جَاءَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالْمُهَاجِرِينَ وَالْأَنْصَارِ وَمَنْ مَعَهُمْ قَالَتْ هَلْ سَأَلَكَ قُلْتُ نَعَمْ فَقَالَ ادْخُلُوا وَلَا تَضَاغَطُوا فَجَعَلَ يَكْسِرُ الْخُبْزَ وَيَجْعَلُ عَلَيْهِ اللَّحْمَ وَيُخَمِّرُ الْبُرْمَةَ وَالتَّنُّورَ إِذَا أَخَذَ مِنْهُ وَيُقَرِّبُ إِلَى أَصْحَابِهِ ثُمَّ يَنْزِعُ فَلَمْ يَزَلْ يَكْسِرُ الْخُبْزَ وَيَغْرِفُ حَتَّى شَبِعُوا وَبَقِيَ بَقِيَّةٌ قَالَ كُلِي هَذَا وَأَهْدِي فَإِنَّ النَّاسَ أَصَابَتْهُمْ مَجَاعَةٌ","id":"Telah menceritakan kepada kami [Khallad bin Yahya] telah menceritakan kepada kami [Abdul Wahid bin Aiman] dari [Ayahnya] dia berkata, aku pernah menemui [Jabir] radliallahu 'anhu, \"Ketika kami menggali parit pada peristiwa khandaq, sebongkah batu yang sangat keras menghalangi kami, lalu para sahabat menemui Nabi shallallahu 'alaihi wasallam, mereka berkata, \"Batu yang sangat keras ini telah menghalangi kami dalam menggali parit, lalu beliau bersabda: \"Aku sendiri yang akan turun.\" Kemudian beliau berdiri (di dalam parit), semntara perut beliau tengah diganjal dengan batu (karena lapar). Semenjak tiga hari kami lalu tanpa ada makanan yang dapat kami rasakan, lalu Nabi shallallahu 'alaihi wasallam mengambil kampak dan memukulkan pada batu tersebut hingga ia menjadi pecah berantakan -atau hancur-. Aku lalu berkata, \"Wahai Rasulullah, izinkanlah aku untuk ke rumah.\" Setelah itu kukatakan kepada isteriku, \"Aku melihat pada diri Nabi shallallahu 'alaihi wasallam sesuatu yang aku sendiri tidak tega melihatnya, apakah kamu memiliki sesuatu (makanan)?\" isteriku menjawab, \"Aku memiliki gandum dan anak kambing.\" Kemudian ia meyembelih anak kambing tersebut dan membuat adonan gandum hngga menjadi makanan dalam tungku, setelah itu aku menemui Nabi shallallahu 'alaihi wasallam, sementara adonan mulai matang, dan periuk berada diantara dua tungku api dan hampir masak, maka aku berkata, \"Aku memiliki sedikit makanan, \" maka berdirilah wahai Rasulullah shallallahu 'alaihi wasallam bersama dengan satu atau dua orang saja. Beliau bersabda: \"Untuk berapa orang?\" Lalu aku memberitahukan kepada beliau, beliau bersabda: \"Tidak mengapa orang banyak untuk datang.\" Beliau bersabda lagi: \"Katakan kepada isterimu, jangan ia angkat periuknya dan adonan roti dari tungku api hingga aku datang.\" Setelah itu beliau bersabda: \"Bangunlah kalian semua.\" Bergegas kaum Muhajirin dan Anshar berdiri berangkat, ketika Jabir menemui Isterinya, dia berkata, \"Waduh, Nabi shallallahu 'alaihi wasallam telah datang bersama kaum Muhajirin dan Anshar serta orang-orang yang bersama mereka.\" Isteri Jabir berkata, \"Memang beliau (Rasulullah) memintamu yang demikian?\" Jabir menjawab, \"Ya, begitu.\" Lalu Rasulullah berkata: \"Masuklah dan jangan berdesak-desakan.\" Kemudian Rasulullah mencuil-cuil roti dan ia tambahkan dengan daging, dan ia tutup periuk dan tungku api. Selanjutnya beliau ambil dan beliau dekatkan kepada para sahabatnya. Lantas beliau ambil kembali periuk itu dan terus menerus beliau lakukan antara mencuili roti dan menciduknya hingga semua sahabat kenyang dan masih menyisakan sisa. Setelah itu beliau bersabda: \"Sekarang makanlah engkau (maksudnya isteri Jabir) dan kalau bisa, hadiahkanlah kepada yang lain, sebab orang-orang, banyak yang masih kelaparan.\""},"3589":{"ar":"حَدَّثَنِي عَمْرُو بْنُ عَلِيٍّ حَدَّثَنَا أَبُو عَاصِمٍ أَخْبَرَنَا حَنْظَلَةُ بْنُ أَبِي سُفْيَانَ أَخْبَرَنَا سَعِيدُ بْنُ مِينَاءَ قَالَ سَمِعْتُ جَابِرَ بْنَ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُمَا قَالَلَمَّا حُفِرَ الْخَنْدَقُ رَأَيْتُ بِالنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَمَصًا شَدِيدًا فَانْكَفَأْتُ إِلَى امْرَأَتِي فَقُلْتُ هَلْ عِنْدَكِ شَيْءٌ فَإِنِّي رَأَيْتُ بِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَمَصًا شَدِيدًا فَأَخْرَجَتْ إِلَيَّ جِرَابًا فِيهِ صَاعٌ مِنْ شَعِيرٍ وَلَنَا بُهَيْمَةٌ دَاجِنٌ فَذَبَحْتُهَا وَطَحَنَتْ الشَّعِيرَ فَفَرَغَتْ إِلَى فَرَاغِي وَقَطَّعْتُهَا فِي بُرْمَتِهَا ثُمَّ وَلَّيْتُ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ لَا تَفْضَحْنِي بِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَبِمَنْ مَعَهُ فَجِئْتُهُ فَسَارَرْتُهُ فَقُلْتُ يَا رَسُولَ اللَّهِ ذَبَحْنَا بُهَيْمَةً لَنَا وَطَحَنَّا صَاعًا مِنْ شَعِيرٍ كَانَ عِنْدَنَا فَتَعَالَ أَنْتَ وَنَفَرٌ مَعَكَ فَصَاحَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا أَهْلَ الْخَنْدَقِ إِنَّ جَابِرًا قَدْ صَنَعَ سُورًا فَحَيَّ هَلًا بِهَلّكُمْ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تُنْزِلُنَّ بُرْمَتَكُمْ وَلَا تَخْبِزُنَّ عَجِينَكُمْ حَتَّى أَجِيءَ فَجِئْتُ وَجَاءَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْدُمُ النَّاسَ حَتَّى جِئْتُ امْرَأَتِي فَقَالَتْ بِكَ وَبِكَ فَقُلْتُ قَدْ فَعَلْتُ الَّذِي قُلْتِ فَأَخْرَجَتْ لَهُ عَجِينًا فَبَصَقَ فِيهِ وَبَارَكَ ثُمَّ عَمَدَ إِلَى بُرْمَتِنَا فَبَصَقَ وَبَارَكَ ثُمَّ قَالَ ادْعُ خَابِزَةً فَلْتَخْبِزْ مَعِي وَاقْدَحِي مِنْ بُرْمَتِكُمْ وَلَا تُنْزِلُوهَا وَهُمْ أَلْفٌ فَأُقْسِمُ بِاللَّهِ لَقَدْ أَكَلُوا حَتَّى تَرَكُوهُ وَانْحَرَفُوا وَإِنَّ بُرْمَتَنَا لَتَغِطُّ كَمَا هِيَ وَإِنَّ عَجِينَنَا لَيُخْبَزُ كَمَا هُوَ","id":"Telah menceritakan kepadaku ['Amru bin Ali] telah menceritakan kepada kami [Abu 'Ashim] telah mengabarkan kepada kami [Hanzhalah bin Abu Sufyan] telah mengabarkan kepada kami [Sa'id bin Mina'] dia berkata, aku mendengar [Jabir bin Abdullah] radliallahu 'anhuma berkata, \"Tatkala penggalian parit pertahanan Khandaq sedang dilaksanakan, aku melihat Rasulullah shallallahu 'alaihi wasallam dalam keadaan lapar. Karena itu aku kembali kepada isteriku, menanyakan kepadanya, 'Apakah engkau mempunyai makanan? Aku melihat Rasulullah shallallahu 'alaihi wasallam sedang lapar.' Maka dikeluarkannya suatu karung, di dalamnya terdapat satu sha' (segantang) gandum. Di samping itu kami mempunyai seekor anak kambing. Lalu aku sembelih kambing itu, sementara isteriku membuat adonan tepung. Ketika aku selesai mengerjakan pekerjaanku, aku lalu memotong-motong kecil daging kambing tersebut dan aku masukkan ke dalam periuk. Setelah itu aku pergi menemui Rasulullah shallallahu 'alaihi wasallam. Isteriku berkata kepadaku, 'Janganlah kamu mempermalukanku dihadapan Rasulullah shallallahu 'alaihi wasallam dan para sahabat beliau.' Aku langusng menemui beliau seraya berbisik kepadanya, 'Wahai Rasulullah! Aku menyembelih seekor anak kambing milikku, dan isteriku telah membuat adonan segantang gandum yang kami miliki. Karena itu sudilah kiranya anda datang bersama-sama dengan beberapa orang sahabat.' Maka Rasulullah shallallahu 'alaihi wasallam berteriak: 'Hai para penggali Khandaq! Jabir telah membuat hidangan untuk kalian semua. Marilah kita makan bersama-sama!\" Rasulullah shallallahu 'alaihi wasallam lalu berkata kepada Jabir: 'Jangan kamu menurunkan periukmu dan janganlah kamu memasak adonan rotimu sebelum aku datang.' Lalu aku pulang. Tidak lama kemudian Rasulullah datang mendahului para sahabat. Ketika aku temui isteriku, dia berkata, 'Bagaimana engkau ini! Bagaimana engkau ini! ' Jawabku, 'Aku telah melakukan apa yang engkau pesankan kepadaku.' Maka aku mengeluarkan adonan roti kami, kemudian nabi meludahi adonan itu untuk memberi keberkahan. Setelah itu beliau menuju periuk (tempat memasak kambing), maka beliau meludahi dan mendo'akan keberkahan kepadanya, sesudah itu beliau berkata kepada isteriku: 'Panggillah tukang roti untuk membantumu memasak. Nanti isikan gulai ke mangkok langsung dari kuali dan sekali-kali jangan kamu menurunkan periukmu. 'Kala itu para sahabat semuanya berjumlah seribu orang. Demi Allah, semuanya turut makan dan setelah itu mereka pergi. Tetapi periuk kami masih tetap penuh berisi seperti semula. Sedangkan adonan masih seperti semula.\""},"3590":{"ar":"حَدَّثَنِي عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدَةُ عَنْ هِشَامٍ عَنْ أَبِيهِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا{ إِذْ جَاءُوكُمْ مِنْ فَوْقِكُمْ وَمِنْ أَسْفَلَ مِنْكُمْ وَإِذْ زَاغَتْ الْأَبْصَارُ وَبَلَغَتْ الْقُلُوبُ الْحَنَاجِرَ }قَالَتْ كَانَ ذَاكَ يَوْمَ الْخَنْدَقِ","id":"Telah menceritakan kepadaku [Utsman bin Abu Syaibah] telah menceritakan kepada kami ['Abdah] dari [Hisyam] dari [Ayahnya] dari ['Aisyah] radliallahu 'anha mengenai ayat: '(ketika mereka datang kepadamu dari atas dan dari bawahmu, dan ketika tidak tetap lagi penglihatan(mu) dan hatimu naik menyesak sampai ke tenggorokan dan kamu menyangka terhadap Allah dengan bermacam-macam purbasangka) ' (Qs. Al Ahzab: 10), dia berkata, \"Hal itu terjadi ketika perang Khandaq.\""},"3591":{"ar":"حَدَّثَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي إِسْحَاقَ عَنْ الْبَرَاءِ رَضِيَ اللَّهُ عَنْهُ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَنْقُلُ التُّرَابَ يَوْمَ الْخَنْدَقِ حَتَّى أَغْمَرَ بَطْنَهُ أَوْ اغْبَرَّ بَطْنُهُ يَقُولُ وَاللَّهِ لَوْلَا اللَّهُ مَا اهْتَدَيْنَاوَلَا تَصَدَّقْنَا وَلَا صَلَّيْنَافَأَنْزِلَنْ سَكِينَةً عَلَيْنَاوَثَبِّتْ الْأَقْدَامَ إِنْ لَاقَيْنَاإِنَّ الْأُلَى قَدْ بَغَوْا عَلَيْنَاإِذَا أَرَادُوا فِتْنَةً أَبَيْنَاوَرَفَعَ بِهَا صَوْتَهُ أَبَيْنَا أَبَيْنَا","id":"Telah menceritakan kepada kami [Muslim bin Ibrahim] telah menceritakan kepada kami [Syu'bah] dari [Abu Ishaq] dari [Al Barra`] radliallahu 'anhu dia berkata, \"Nabi shallallahu 'alaihi wasallam ikut mengangkuti tanah pada perang Khandaq, hingga perutnya penuh debu -atau perutnya berdebu-, beliau bersabda: 'Ya Allah, seandainya bukan karena-Mu, maka kami tidak akan mendapatkan petunjuk, tidak akan bersedekah dan tidak akan melakukan shalat, maka turunkanlah ketenangan kepada kami, serta kokohkan kaki-kaki kami apabila bertemu dengan musuh. Sesungguhnya orang-orang musyrik telah berlaku semena-mena kepada kami, apabila mereka menghendaki fitnah, maka kami menolaknya.' Beliau menyenandungkan itu sambil mengeraskan suaranya.\""},"3592":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ شُعْبَةَ قَالَ حَدَّثَنِي الْحَكَمُ عَنْ مُجَاهِدٍ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَاعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ نُصِرْتُ بِالصَّبَا وَأُهْلِكَتْ عَادٌ بِالدَّبُورِ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Yahya bin Sa'id] dari [Syu'bah] dia berkata, telah menceritakan kepadaku [Al Hakam] dari [Mujahid] dari [Ibnu Abbas] radliallahu 'anhuma dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Aku ditolong dengan bantuan angin (yang bertiup dari timur) sedangkan kaum 'Aad dihancurkan dengan angin (yang bertiup dari barat).\""},"3593":{"ar":"حَدَّثَنِي أَحْمَدُ بْنُ عُثْمَانَ حَدَّثَنَا شُرَيْحُ بْنُ مَسْلَمَةَ قَالَ حَدَّثَنِي إِبْرَاهِيمُ بْنُ يُوسُفَ قَالَ حَدَّثَنِي أَبِي عَنْ أَبِي إِسْحَاقَ قَالَ سَمِعْتُ الْبَرَاءَ بْنَ عَازِبٍ يُحَدِّثُ قَالَلَمَّا كَانَ يَوْمُ الْأَحْزَابِ وَخَنْدَقَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَأَيْتُهُ يَنْقُلُ مِنْ تُرَابِ الْخَنْدَقِ حَتَّى وَارَى عَنِّي الْغُبَارُ جِلْدَةَ بَطْنِهِ وَكَانَ كَثِيرَ الشَّعَرِ فَسَمِعْتُهُ يَرْتَجِزُ بِكَلِمَاتِ ابْنِ رَوَاحَةَ وَهُوَ يَنْقُلُ مِنْ التُّرَابِ يَقُولُ اللَّهُمَّ لَوْلَا أَنْتَ مَا اهْتَدَيْنَاوَلَا تَصَدَّقْنَا وَلَا صَلَّيْنَافَأَنْزِلَنْ سَكِينَةً عَلَيْنَاوَثَبِّتْ الْأَقْدَامَ إِنْ لَاقَيْنَاإِنَّ الْأُلَى قَدْ بَغَوْا عَلَيْنَاوَإِنْ أَرَادُوا فِتْنَةً أَبَيْنَاقَالَ ثُمَّ يَمُدُّ صَوْتَهُ بِآخِرِهَا","id":"Telah menceritakan kepadaku [Ahmad bin Utsman] telah menceritakan kepada kami [Syuraih bin Maslamah] dia berkata, telah menceritakan kepadaku [Ibrahim bin Yusuf] dia berkata, telah menceritakan kepadaku [Ayahku] dari [Abu Ishaq] dia berkata, aku mendengar [Al Barra` bin Azib] bercerita, dia berkata, \"Pada waktu perang Ahzab atau Khandaq, aku melihat Rasulullah shallallahu 'alaihi wasallam mengangkat tanah parit, sehingga debu-debu itu menutupi kulit beliau dari (pandangan) ku, saat itu beliau bersenandung dengan bait-bait syair yang pernah diucapkan oleh Ibnu Rawahah, sambil mengangkat tanah beliau bersabda: 'Ya Allah, seandainya bukan karena-Mu, maka kami tidak akan mendapatkan petunjuk, tidak akan bersedekah dan tidak akan melakukan shalat, maka turunkanlah ketenangan kepada kami, serta kokohkan kaki-kaki kami apabila bertemu dengan musuh. Sesungguhnya orang-orang musyrik telah berlaku semena-mena kepada kami, apabila mereka menghendaki fitnah, maka kami menolaknya.' Beliau menyenandungkan itu sambil mengeraskan suara diakhir baitnya.\""},"3594":{"ar":"حَدَّثَنِي عَبْدُ اللَّهِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا ابْنُ نُمَيْرٍ عَنْ هِشَامٍ عَنْ أَبِيهِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْلَمَّا رَجَعَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ الْخَنْدَقِ وَوَضَعَ السِّلَاحَ وَاغْتَسَلَ أَتَاهُ جِبْرِيلُ عَلَيْهِ السَّلَام فَقَالَ قَدْ وَضَعْتَ السِّلَاحَ وَاللَّهِ مَا وَضَعْنَاهُ فَاخْرُجْ إِلَيْهِمْ قَالَ فَإِلَى أَيْنَ قَالَ هَا هُنَا وَأَشَارَ إِلَى بَنِي قُرَيْظَةَ فَخَرَجَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَيْهِمْ","id":"Telah menceritakan kepadaku [Abdullah bin Abu Syaibah] telah menceritakan kepada kami [Ibnu Numair] dari [Hisyam] dari [Bapaknya] dari ['Aisyah radliallahu 'anha], ia berkata; Ketika Nabi shallallahu 'alaihi wasallam kembali dari perang Khandaq, setelah beliau meletakkan senjata dan mandi, malaikat Jibril 'alaihis salam datang menemui beliau seraya berkata: \"Apakah anda hendak meletakan senjata? Demi Allah kami tidak akan meletakkannya. Keluarlah anda (untuk memerangi) mereka.\" Beliau bertanya: \"Kemana?\" Jibrilmenjawab: \"Kesana.\" Jibril memberi isyarat (untuk pergi memerangi) Bani Quraizhah. Maka Nabi shallallahu 'alaihi wasallam berangkat menyerbu mereka.\""},"3595":{"ar":"حَدَّثَنَا مُوسَى حَدَّثَنَا جَرِيرُ بْنُ حَازِمٍ عَنْ حُمَيْدِ بْنِ هِلَالٍ عَنْ أَنَسٍ رَضِيَ اللَّهُ عَنْهُ قَالَكَأَنِّي أَنْظُرُ إِلَى الْغُبَارِ سَاطِعًا فِي زُقَاقِ بَنِي غَنْمٍ مَوْكِبَ جِبْرِيلَ صَلَوَاتُ اللَّهِ عَلَيْهِ حِينَ سَارَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى بَنِي قُرَيْظَةَ","id":"Telah menceritakan kepada kami [Musa] telah menceritakan kepada kami [Jarir bin Hazim] dari [Humaid bin Hilal] dari [Anas radliallahu 'anhu], ia berkata; \"Seolah-olah aku melihat debu-debu beterbangan di lorong-lorong jalan suku Bani Ghanmin. Hal ini sebagi bukti keterlibatan malaikat Jibril -shalawatullah 'alaihi- ketika Rasulullah shallallahu 'alaihi wasallam menyerbu perkampungan Bani Quraizhah.\""},"3596":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدِ بْنِ أَسْمَاءَ حَدَّثَنَا جُوَيْرِيَةُ بْنُ أَسْمَاءَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ الْأَحْزَابِ لَا يُصَلِّيَنَّ أَحَدٌ الْعَصْرَ إِلَّا فِي بَنِي قُرَيْظَةَ فَأَدْرَكَ بَعْضُهُمْ الْعَصْرَ فِي الطَّرِيقِ فَقَالَ بَعْضُهُمْ لَا نُصَلِّي حَتَّى نَأْتِيَهَا وَقَالَ بَعْضُهُمْ بَلْ نُصَلِّي لَمْ يُرِدْ مِنَّا ذَلِكَ فَذُكِرَ ذَلِكَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمْ يُعَنِّفْ وَاحِدًا مِنْهُمْ","id":"Telah menceritakan kepada kami [Abdullah bin Muhammad bin Asma'] telah menceritakan kepada kami [Juwairiyah bin Asma'] dari [Nafi'] dari [Ibnu 'Umar radliallahu 'anhuma], ia berkata; Nabi shallallahu 'alaihi wasallam bersabda ketika perang al-Ahzab: \"Janganlah seseorang melaksanakan shalat 'Ashar kecuali di perkampungan Bani Quraizhah.\" Setelah berangkat, sebagian dari pasukan melaksanakan shalat 'Ashar di perjalanan sementara sebagian yang lain berkata; \"Kami tidak akan shalat kecuali setelah sampai di perkampungan itu.\" Sebagian yang lain beralasan; \"Justru kita harus shalat, karena maksud beliau bukan seperti itu.\" Setelah kejadian ini diberitahukan kepada Nabi shallallahu 'alaihi wasallam, beliau tidak menyalahkan satu pihakpun.\""},"3597":{"ar":"حَدَّثَنَا ابْنُ أَبِي الْأَسْوَدِ حَدَّثَنَا مُعْتَمِرٌ ح و حَدَّثَنِي خَلِيفَةُ حَدَّثَنَا مُعْتَمِرٌ قَالَ سَمِعْتُ أَبِي عَنْ أَنَسٍ رَضِيَ اللَّهُ عَنْهُ قَالَكَانَ الرَّجُلُ يَجْعَلُ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ النَّخَلَاتِ حَتَّى افْتَتَحَ قُرَيْظَةَ وَالنَّضِيرَ وَإِنَّ أَهْلِي أَمَرُونِي أَنْ آتِيَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَسْأَلَهُ الَّذِي كَانُوا أَعْطَوْهُ أَوْ بَعْضَهُ وَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ أَعْطَاهُ أُمَّ أَيْمَنَ فَجَاءَتْ أُمُّ أَيْمَنَ فَجَعَلَتْ الثَّوْبَ فِي عُنُقِي تَقُولُ كَلَّا وَالَّذِي لَا إِلَهَ إِلَّا هُوَ لَا يُعْطِيكَهُمْ وَقَدْ أَعْطَانِيهَا أَوْ كَمَا قَالَتْ وَالنَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَكِ كَذَا وَتَقُولُ كَلَّا وَاللَّهِ حَتَّى أَعْطَاهَا حَسِبْتُ أَنَّهُ قَالَ عَشَرَةَ أَمْثَالِهِ أَوْ كَمَا قَالَ","id":"Telah menceritakan kepada kami [Ibnu Abu Al Aswad] telah menceritakan kepada kami [Mu'tamir]. -Dan diriwayatkan dari jalur lain- telah menceritakan kepadaku [Khalifah] telah menceritakan kepada kami [Mu'tamir], ia berkata; aku mendengar [Bapakku] dari [Anas radliallahu 'anhu], ia berkata; 'Seseorang memberikan kebun kurma kepada Nabi shallallahu 'alaihi wasallam, ketika Bani Quraizhah dan Bani Nazhir dapat ditaklukkan. Orang itu berkata; \"Sesungguhnya keluargaku menyuruh aku untuk menemui Nabi shallallahu 'alaihi wasallam lalu meminta apa yang telah aku berikan atau sebagiannya.\" Sementara Nabi shallallahu 'alaihi wasallam telah memberikan kebun kurma itu kepada Ummu Aiman. Lalu Ummu Aiman datang dan meletakkan kain di leherku seraya berkata; \"Sekali-kali tidak. Demi Dzat Yang tidak ada sesembahan selain Dia, janganlah tuan berikan kepada mereka karena tuan telah memberikannya kepadaku.\" Atau sebagaimana yang telah dikatakan. Maka Nabi shallallahu 'alaihi wasallam bersabda: \"Kamu mendapatkan bagian segini.\" Ummu Aiman berkata; \"Tidak, demi Allah.\" Akhirnya beliau memberikan kepadanya. Perawi berkata; \"Aku kira dia Anas berkata; \"Sepuluh kali lipat atau sekitar itu atau sebagaimana yang telah dikatakan.\""},"3598":{"ar":"حَدَّثَنِي مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا غُنْدَرٌ حَدَّثَنَا شُعْبَةُ عَنْ سَعْدٍ قَالَ سَمِعْتُ أَبَا أُمَامَةَ قَالَ سَمِعْتُ أَبَا ��َعِيدٍ الْخُدْرِيَّ رَضِيَ اللَّهُ عَنْهُ يَقُولُنَزَلَ أَهْلُ قُرَيْظَةَ عَلَى حُكْمِ سَعْدِ بْنِ مُعَاذٍ فَأَرْسَلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى سَعْدٍ فَأَتَى عَلَى حِمَارٍ فَلَمَّا دَنَا مِنْ الْمَسْجِدِ قَالَ لِلْأَنْصَارِ قُومُوا إِلَى سَيِّدِكُمْ أَوْ خَيْرِكُمْ فَقَالَ هَؤُلَاءِ نَزَلُوا عَلَى حُكْمِكَ فَقَالَ تَقْتُلُ مُقَاتِلَتَهُمْ وَتَسْبِي ذَرَارِيَّهُمْ قَالَ قَضَيْتَ بِحُكْمِ اللَّهِ وَرُبَّمَا قَالَ بِحُكْمِ الْمَلِكِ","id":"Telah menceritakan kepadaku [Muhammad bin Basysyar] telah menceritakan kepada kami [Ghundar] telah menceritakan kepada kami [Syu'bah] dari [Sa'ad], ia berkata; aku mendengar [Abu Umamah] berkata; aku mendengar [Abu Sa'id Al Khudri radliallahu 'anhu] berkata; \"Penduduk Quraizhah setuju dengan ketetapan hukum yang akan diputuskan oleh Sa'ad bin Mu'adz. Lalu Nabi shallallahu 'alaihi wasallam mengutus seseorang untuk memanggilnya, dia lalu datang dengan mengendarai keledai. Ketika dekat dengan masjid, beliau berkata kepada kaum Anshar: \"Berdirilah kalian untuk pemimpin kalian atau orang terbaik kalian\". Beliau melanjutkan sabdanya: \"Mereka telah setuju dengan keputusanmu.\" Sa'ad berkata; \"Aku akan memutuskan kepada mereka, bunuhlah para tentara perang mereka dan tawanlah anak-anak dan wanita mereka.\" Beliau bersabda: \"Sungguh kamu telah memutuskan hukum kepada mereka dengan hukum Allah.\" -Atau bersabda- \"Dengan hukum Raja diraja\"."},"3599":{"ar":"حَدَّثَنَا زَكَرِيَّاءُ بْنُ يَحْيَى حَدَّثَنَا عَبْدُ اللَّهِ بْنُ نُمَيْرٍ حَدَّثَنَا هِشَامٌ عَنْ أَبِيهِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْأُصِيبَ سَعْدٌ يَوْمَ الْخَنْدَقِ رَمَاهُ رَجُلٌ مِنْ قُرَيْشٍ يُقَالُ لَهُ حِبَّانُ بْنُ الْعَرِقَةِ وَهُوَ حِبَّانُ بْنُ قَيْسٍ مِنْ بَنِي مَعِيصِ بْنِ عَامِرِ بْنِ لُؤَيٍّ رَمَاهُ فِي الْأَكْحَلِ فَضَرَبَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَيْمَةً فِي الْمَسْجِدِ لِيَعُودَهُ مِنْ قَرِيبٍ فَلَمَّا رَجَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ الْخَنْدَقِ وَضَعَ السِّلَاحَ وَاغْتَسَلَ فَأَتَاهُ جِبْرِيلُ عَلَيْهِ السَّلَام وَهُوَ يَنْفُضُ رَأْسَهُ مِنْ الْغُبَارِ فَقَالَ قَدْ وَضَعْتَ السِّلَاحَ وَاللَّهِ مَا وَضَعْتُهُ اخْرُجْ إِلَيْهِمْ قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَيْنَ فَأَشَارَ إِلَى بَنِي قُرَيْظَةَ فَأَتَاهُمْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَنَزَلُوا عَلَى حُكْمِهِ فَرَدَّ الْحُكْمَ إِلَى سَعْدٍ قَالَ فَإِنِّي أَحْكُمُ فِيهِمْ أَنْ تُقْتَلَ الْمُقَاتِلَةُ وَأَنْ تُسْبَى النِّسَاءُ وَالذُّرِّيَّةُ وَأَنْ تُقْسَمَ أَمْوَالُهُمْقَالَ هِشَامٌ فَأَخْبَرَنِي أَبِي عَنْ عَائِشَةَ أَنَّ سَعْدًا قَالَ اللَّهُمَّ إِنَّكَ تَعْلَمُ أَنَّهُ لَيْسَ أَحَدٌ أَحَبَّ إِلَيَّ أَنْ أُجَاهِدَهُمْ فِيكَ مِنْ قَوْمٍ كَذَّبُوا رَسُولَكَ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَخْرَجُوهُ اللَّهُمَّ فَإِنِّي أَظُنُّ أَنَّكَ قَدْ وَضَعْتَ الْحَرْبَ بَيْنَنَا وَبَيْنَهُمْ فَإِنْ كَانَ بَقِيَ مِنْ حَرْبِ قُرَيْشٍ شَيْءٌ فَأَبْقِنِي لَهُ حَتَّى أُجَاهِدَهُمْ فِيكَ وَإِنْ كُنْتَ وَضَعْتَ الْحَرْبَ فَافْجُرْهَا وَاجْعَلْ مَوْتَتِي فِيهَا فَانْفَجَرَتْ مِنْ لَبَّتِهِ فَلَمْ يَرُعْهُمْ وَفِي الْمَسْجِدِ خَيْمَةٌ مِنْ بَنِي غِفَارٍ إِلَّا الدَّمُ يَسِيلُ إِلَيْهِمْ فَقَالُوا يَا أَهْلَ الْخَيْمَةِ مَا هَذَا الَّذِي يَأْتِينَا مِنْ قِبَلِكُمْ فَإِذَا سَعْدٌ يَغْذُو جُرْحُهُ دَمًا فَمَاتَ مِنْهَا رَضِيَ اللَّهُ عَنْهُ","id":"Telah menceritakan kepadaku [Zakariya' bin Yahya] telah menceritakan kepada kami [Abdullah bin Numair] telah menceritakan kepada kami [Hisyam] dari [Bapaknya] dari ['Aisyah radliallahu 'anha], ia berkata; \"Sa'ad terluka pada perang Khandaq karena panah seorang Quraisy bernama Hibban bin 'Ariqah, -dia adalah Hibban bin Qais dari Bani Ma'ish bin 'Amir bin Lu'ay- Dia memanahnya tepat mengenai urat bahu Sa'ad. Kemudian Nabi shallallahu 'alaihi wasallam membuatkan kemah dekat masjid supaya mudah menjenguknya. Ketika Rasulullah shallallahu 'alaihi wasallam kembali dari perang Khandaq, beliau meletakkan senjata lalu mandi, Malaikat Jibril 'alaihis salam datang menemui belaiu sambil mengibaskan debu dari kepalanya seraya berkata: \"Apakah anda hendak meletakan senjata? Demi Allah, kami tidak akan meletakkannya. Keluarlah anda (untuk menyerbu) mereka.\" Beliau bertanya: \"Kemana?\" Jibril 'alaihis salam memberi isyarat (untuk menyerbu) Bani Quraizhah. Maka Nabi shallallahu 'alaihi wasallam berangkat menyerbu mereka. Akhirnya Bani Quraizhah sepakat tunduk pada hukum beliau. Namun beliau menyerahkannya kepada Sa'ad. Sa'ad lantas berkata; \"Aku akan memutuskan (hukuman) kepada mereka, agar tuan membunuh para tentara perang mereka dan menawan wanita dan anak-anak mereka serta membagi-bagikan harta mereka.\" Hisyam berkata; Bapakku telah mengabarkan kepadaku dari 'Aisyah bahwa Sa'ad berkata; \"Ya Allah, sesungguhnya Engkau mengetahui bahwa tidak ada yang lebih aku sukai untuk berjihad (berperang) di jalan-Mu daripada memerangi kaum yang mendustakan Rasul-Mu shallallahu 'alaihi wasallam dan telah mengusir beliau. Ya Allah, aku mengira bahwa Engkau telah menghentikan perang antara kami dan mereka. Seandainya masih ada perang melawan Quraisy, panjangkanlah umurku supaya aku dapat berjihad melawan mereka di jalan-Mu. Sekiranya memang benar Engkau telah menghentikan perang, pancarkanlah lukaku ini dan matikanlah aku karenanya.\" Maka memancarlah darah dari dadanya. Dan tidak ada yang mencengangkan mereka saat dimasjid di dalam tenda Bani Ghifar, kecuali darah yang mengalir. Mereka berkata; \"Wahai penghuni tenda, apakah yang datang kepada kami ini dari arah kalian?.\" Ternyata luka Sa'ad menyemburkan darah lalu dia meninggal karena lukanya itu. Semoga Allah meridlainya\".."},"3600":{"ar":"حَدَّثَنَا الْحَجَّاجُ بْنُ مِنْهَالٍ أَخْبَرَنَا شُعْبَةُ قَالَ أَخْبَرَنِي عَدِيٌّ أَنَّهُ سَمِعَ الْبَرَاءَ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِحَسَّانَ اهْجُهُمْ أَوْ هَاجِهِمْ وَجِبْرِيلُ مَعَكَوَزَادَ إِبْرَاهِيمُ بْنُ طَهْمَانَ عَنْ الشَّيْبَانِيِّ عَنْ عَدِيِّ بْنِ ثَابِتٍ عَنْ الْبَرَاءِ بْنِ عَازِبٍ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ قُرَيْظَةَ لِحَسَّانَ بْنِ ثَابِتٍ اهْجُ الْمُشْرِكِينَ فَإِنَّ جِبْرِيلَ مَعَكَ","id":"Telah menceritakan kepada kami [Al Hajjaj bin Minhal] telah mengabarkan kepada kami [Syu'bah] ia berkata; telah mengabarkan kepadaku ['Adi] dia mendengar [Al Bara' radliallahu 'anhu] berkata; Nabi shallallahu 'alaihi wasallam bersabda kepada Hassan: \"Seranglah mereka, atau hancurkanlah mereka, karena jibril selalu bersamamu\". Dan [Ibrahim bin Thahman] menambahkan dari [Asy Syaibani] dari ['Adi bin Tsabit] dari [Al Bara` bin 'Azib] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda kepada Hasaan bin Tsabit pada perang Quraizhah: \"Seranglah kaum musyrikin, karena jibril selalu bersamamu.\""},"3601":{"ar":"قَالَ أَبُو عَبْد اللَّهِ و قَالَ لِي عَبْدُ اللَّهِ بْنُ رَجَاءٍ أَخْبَرَنَا عِمْرَانُ الْقَطَّانُ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ أَبِي سَلَمَةَ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى بِأَصْحَابِهِ فِي الْخَوْفِ فِي غَزْوَةِ السَّابِعَةِ غَزْوَةِ ذَاتِ الرِّقَاعِقَالَ ابْنُ عَبَّاسٍ صَلَّى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْخَوْفَ بِذِي قَرَدٍ وَقَالَ بَكْرُ بْنُ سَوَادَةَ حَدَّثَنِي زِيَادُ بْنُ نَافِعٍ عَنْ أَبِي مُوسَى أَنَّ جَابِرًا حَدَّثَهُمْ صَلَّى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِهِمْ يَوْمَ مُحَارِبٍ وَثَعْلَبَةَ وَقَالَ ابْنُ إِسْحَاقَ سَمِعْتُ وَهْبَ بْنَ كَيْسَانَ سَمِعْتُ جَابِرًا خَرَجَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى ذَاتِ الرِّقَاعِ مِنْ نَخْلٍ فَلَقِيَ جَمْعًا مِنْ غَطَفَانَ فَلَمْ يَكُنْ قِتَالٌ وَأَخَافَ النَّاسُ بَعْضُهُمْ بَعْضًا فَصَلَّى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَكْعَتَيْ الْخَوْفِ وَقَالَ يَزِيدُ عَنْ سَلَمَةَ غَزَوْتُ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ الْقَرَدِ","id":"Abu Abdullah dan [Abdullah bin Raja'] berkata kepadaku; telah mengabarkan kepada kami ['Imran Al Qaththan] dari [Yahya bin Abu Katsir] dari [Abu Salamah] dari [Jabir bin Abdullah radliallahu 'anhuma] bahwa Nabi shallallahu 'alaihi wasallam dan para shahabat beliau merasa khawatir (serangan musuh) pada perang ketujuh yaitu perang Dzatur Riqa'. Ibnu 'Abbas berkata; Maka Nabi shallallahu 'alaihi wasallam melaksanakan shalat khauf di Dzi Qarad.\" [Bakr bin Sawadah] mengatakan; telah menceritakan kepadaku [Ziyad bin Nafi'] dari [Abu Musa] bahwa [Jabir] menceritakan kepada mereka; Nabi shallallahu 'alaihi wasallam melaksanakan shalat bersama mereka pada perang Muharib dan Tsa'labah\". Dan berkata [Ibnu Ishaq] aku mendengar [Wahb bin Kaisan] aku mendengar [Jabir]; Nabi shallallahu 'alaihi wasallam keluar menuju Dzatur Riqa' dan melewati daerah Nakhl. Beliau bertemu dengan rombongan dari suku Ghathafan namun tidak terjadi peperangan, ternyata satu sama lain dari kedua kelompok saling dihinggapi rasa takut. Lalu Nabi shallallahu 'alaihi wasallam melaksanakan shalat khauf dua raka'at.\" [Yazid] mengatakan dari [Salamah]; \"Aku ikut perang bersama Nabi shallallahu 'alaihi wasallam saat perang Al Qard.\""},"3602":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْعَلَاءِ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ بُرَيْدِ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي بُرْدَةَ عَنْ أَبِي بُرْدَةَ عَنْ أَبِي مُوسَى رَضِيَ اللَّهُ عَنْهُ قَالَخَرَجْنَا مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي غَزْوَةٍ وَنَحْنُ سِتَّةُ نَفَرٍ بَيْنَنَا بَعِيرٌ نَعْتَقِبُهُ فَنَقِبَتْ أَقْدَامُنَا وَنَقِبَتْ قَدَمَايَ وَسَقَطَتْ أَظْفَارِي وَكُنَّا نَلُفُّ عَلَى أَرْجُلِنَا الْخِرَقَ فَسُمِّيَتْ غَزْوَةَ ذَاتِ الرِّقَاعِ لِمَا كُنَّا نَعْصِبُ مِنْ الْخِرَقِ عَلَى أَرْجُلِنَا وَحَدَّثَ أَبُو مُوسَى بِهَذَا ثُمَّ كَرِهَ ذَاكَ قَالَ مَا كُنْتُ أَصْنَعُ بِأَنْ أَذْكُرَهُ كَأَنَّهُ كَرِهَ أَنْ يَكُونَ شَيْءٌ مِنْ عَمَلِهِ أَفْشَاهُ","id":"Telah menceritakan kepada kami [Muhammad bin Al Ala`] telah menceritakan kepada kami [Abu Usamah] dari [Buraid bin Abdullah bin Abu Burdah] dari [Abu Burdah] dari [Abu Musa radliallahu 'anhu] berkata; \"Kami keluar bersama Nabi shallallahu 'alaihi wasallam dalam suatu peperangan. Saat itu kami berjumlah enam orang dan kami hanya memiliki satu ekor unta yang kami gunakan secara bergantian. Kaki-kaki kami menjadi tipis (kerena berjalan) begitu juga kuku menjadi tipis hingga kuku-kuku kakiku tercabut. Kami lalu membungkus kaki-kaki kami dengan khiraq (sobekan-sobekan kain), oleh karena itu perang itu dinamakan perang Dzatur Riqa', karena kami membalut kaki-kaki kami dengan khiraq.\" Abu Musa telah menceritakan kepada kami hadits ini, namun dia tidak menyukainya. Dia berkata; \"Apa yang telah aku lakukan dengan menceritakannya?\". Seakan-akan ia tidak suka menampakkan amalannya."},"3603":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ عَنْ مَالِكٍ عَنْ يَزِيدَ بْنِ رُومَانَ عَنْ صَالِحِ بْنِ خَوَّاتٍ عَمَّنْ شَهِدَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَيَوْمَ ذَاتِ الرِّقَاعِ صَلَّى صَلَاةَ الْخَوْفِ أَنَّ طَائِفَةً صَفَّتْ مَعَهُ وَطَائِفَةٌ وِجَاهَ الْعَدُوِّ فَصَلَّى بِالَّتِي مَعَهُ رَكْعَةً ثُمَّ ثَبَتَ قَائِمًا وَأَتَمُّوا لِأَنْفُسِهِمْ ثُمَّ انْصَرَفُوا فَصَفُّوا وِجَاهَ الْعَدُوِّ وَجَاءَتْ الطَّائِفَةُ الْأُخْرَى فَصَلَّى بِهِمْ الرَّكْعَةَ الَّتِي بَقِيَتْ مِنْ صَلَاتِهِ ثُمَّ ثَبَتَ جَالِسًا وَأَتَمُّوا لِأَنْفُسِهِمْ ثُمَّ سَلَّمَ بِهِمْوَقَالَ مُعَاذٌ حَدَّثَنَا هِشَامٌ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍ قَالَ كُنَّا مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِنَخْلٍ فَذَكَرَ صَلَاةَ الْخَوْفِ قَالَ مَالِكٌ وَذَلِكَ أَحْسَنُ مَا سَمِعْتُ فِي صَلَاةِ الْخَوْفِ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] dari [Malik] dari [Yazid bin Ruman] dari [Shalih bin Khawwat] dari [orang yang menyaksikan Rasulullah] shallallahu 'alaihi wasallam melaksanakan shalat khauf saat perang Dzatur Riqa', bahwa sekelompok pasukan berbaris dalam shaf bersama beliau, sedangkan kelompok lain berjaga-jaga menghadap musuh. Beliau lalu shalat beserta kelompok pertama satu raka'at, beliau tetap berdiri sementara kelompok tersebut menyelesaikan shalat mereka masing-masing, setelah itu mereka beranjak dan berjaga-jaga menghadap musuh (menggantikan kelompok kedua). Kemudian datang kelompok lain yang semula berjaga-jada lalu shalat satu raka'at bersama beliau dari shalat beliau yang masih kurang, kemudian beliau duduk. Sedangkan kelompok kedua, menyelesaikan kekurangan raka'at mereka masing-masing, setelah itu beliau salam bersama mereka.\" [Mu'adz] mengatakan; telah menceritakan kepada kami [Hisyam] dari [Abu Az Zubair] dari [Jabir] ia berkata; \"Kami bersama Nabi shallallahu 'alaihi wasallam di wilayah Nakhl\". Lalu Jabir menceritakan tentang shalat khauf. Malik berkata; \"Ini adalah keterangan yang paling baik yang pernah aku dengar tentang shalat khauf.\""},"3604":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ الْقَطَّانُ عَنْ يَحْيَى بْنِ سَعِيدٍ الْأَنْصَارِيِّ عَنْ الْقَاسِمِ بْنِ مُحَمَّدٍ عَنْ صَالِحِ بْنِ خَوَّاتٍ عَنْ سَهْلِ بْنِ أَبِي حَثْمَةَ قَالَيَقُومُ الْإِمَامُ مُسْتَقْبِلَ الْقِبْلَةِ وَطَائِفَةٌ مِنْهُمْ مَعَهُ وَطَائِفَةٌ مِنْ قِبَلِ الْعَدُوِّ وُجُوهُهُمْ إِلَى الْعَدُوِّ فَيُصَلِّي بِالَّذِينَ مَعَهُ رَكْعَةً ثُمَّ يَقُومُونَ فَيَرْكَعُونَ لِأَنْفُسِهِمْ رَكْعَةً وَيَسْجُدُونَ سَجْدَتَيْنِ فِي مَكَانِهِمْ ثُمَّ يَذْهَبُ هَؤُلَاءِ إِلَى مَقَامِ أُولَئِكَ فَيَرْكَعُ بِهِمْ رَكْعَةً فَلَهُ ثِنْتَانِ ثُمَّ يَرْكَعُونَ وَيَسْجُدُونَ سَجْدَتَيْنِحَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ شُعْبَةَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْقَاسِمِ عَنْ أَبِيهِ عَنْ صَالِحِ بْنِ خَوَّاتٍ عَنْ سَهْلِ بْنِ أَبِي حَثْمَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِثْلَهُ حَدَّثَنِي مُحَمَّدُ بْنُ عُبَيْدِ اللَّهِ قَالَ حَدَّثَنِي ابْنُ أَبِي حَازِمٍ عَنْ يَحْيَى سَمِعَ الْقَاسِمَ أَخْبَرَنِي صَالِحُ بْنُ خَوَّاتٍ عَنْ سَهْلٍ حَدَّثَهُ قَوْلَهُ تَابَعَهُ اللَّيْثُ عَنْ هِشَامٍ عَنْ زَيْدِ بْنِ أَسْلَمَ أَنَّ الْقَاسِمَ بْنَ مُحَمَّدٍ حَدَّثَهُ صَلَّى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي غَزْوَةِ بَنِي أَنْمَارٍ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Yahya bin Sa'id Al Qaththan] dari [Yahya bin Sa'id Al Anshari] dari [Al Qasim bin Muhammad] dari [Shalih bin Khawwat] dari [Sahal bin Abu Hatsmah] ia berkata; \"(Dalam shalat khauf), imam berdiri menghadap qiblat, sedangkan satu kelompok shalat bersama imam dan sekelompok lainnya menghadap ke arah musuh. Imam shalat bersama kelompok orang yang bersamanya (kelompok pertama) satu raka'at, setelah itu mereka berdiri dan ruku' untuk diri mereka masing-masing satu kali ruku' dan dua kali sujud ditempatnya. Lalu kelompok yang satu (kelompok kedua) pergi menempati kelompok yang lain (kelompok pertama), seterusnya mereka (kelompok kadua) shalat satu raka'at bersama imam, maka imam telah mengerjakan dua raka'at, kemudian kelompok kedua melanjutkan sekali ruku' dan dua kali sujud.\" Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Yahya] dari [Syu'bah] dari [Abdurrahman bin Al Qasim] dari [Bapaknya] dari [Shalih] dari [Sahal bin Abu Hatsmah] dari Nabi shallallahu 'alaihi wasallam seperti hadits diatas. Telah menceritakan kepadaku [Muhammad bin Ubaidullah] ia berkata; telah menceritakan kepadaku [Ibnu Abu Hazim] dari [Yahya] dia mendengar [Al Qasim] telah mengabarkan kepadaku [Shalih bin Khawwat] dari [Sahal] dia menceritakan kepadanya dengan ucapannya ini. Hadits ini juga diriwayatkan oleh [Al Laits] dari [Hisyam] dari [Zaid bin Aslam] bahwa [Al Qasim bin Muhammad] menceritakan kepadanya bahwa Nabi shallallahu 'alaihi wasallam malaksanakan shalat (khauf) saat terjadi perang Bani Anmar.\""},"3605":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي سَالِمٌ أَنَّ ابْنَ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا قَالَغَزَوْتُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قِبَلَ نَجْدٍ فَوَازَيْنَا الْعَدُوَّ فَصَافَفْنَا لَهُمْ","id":"Telah menceritakan kepada kami [Abu Al Yaman] telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhri] ia berkata; telah mengabarkan kepadaku [Salim] bahwa [Ibnu Umar radliallahu 'anhuma] berkata; 'Aku pernah ikut perang bersama Rasulullah shallallahu 'alaihi wasallam ke arah Najed, ketika posisi kami berhadapan dengan musuh, kami mengerjakan shalat sambil menghadap ke arah musuh.\""},"3606":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ حَدَّثَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ سَالِمِ بْنِ عَبْدِ اللَّهِ بْنِ عُمَرَ عَنْ أَبِيهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى بِإِحْدَى الطَّائِفَتَيْنِ وَالطَّائِفَةُ الْأُخْرَى مُوَاجِهَةُ الْعَدُوِّ ثُمَّ انْصَرَفُوا فَقَامُوا فِي مَقَامِ أَصْحَابِهِمْ أُولَئِكَ فَجَاءَ أُولَئِكَ فَصَلَّى بِهِمْ رَكْعَةً ثُمَّ سَلَّمَ عَلَيْهِمْ ثُمَّ قَامَ هَؤُلَاءِ فَقَضَوْا رَكْعَتَهُمْ وَقَامَ هَؤُلَاءِ فَقَضَوْا رَكْعَتَهُمْ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Yazid bin Zurai'] telah menceritakan kepada kami [Ma'mar] dari [Az Zuhri] dari [Salim bin Abdullah bin Umar] dari [Bapaknya] bahwa Rasulullah shallallahu 'alaihi wasallam shalat bersama salah satu kelompok, sementara kelompok yang lain (berjaga-jaga) menghadapi musuh. Kemudian kelompok yang shalat bersama beliau beranjak dan menempati posisi kelompok yang semula menghadap musuh, lalu kelompok yang semula berjaga-jaga (menghadapi musuh) datang, kemudian beliau shalat bersama mereka satu raka'at lalu salam. Selanjutnya satu kelompok menyelesaikan raka'at mereka begitu juga kelompok yang satu lagi menyelesaikan raka'at mereka.\""},"3607":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ حَدَّثَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ قَالَ حَدَّثَنِي سِنَانٌ وَأَبُو سَلَمَةَ أَنَّ جَابِرًا أَخْبَرَأَنَّهُ غَزَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قِبَلَ نَجْدٍ","id":"Telah menceritakan kepada kami [Abu Al Yaman] telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhri] ia berkata; telah mengabarkan kepadaku [Sinan] dan [Abu Salamah] bahwa [Jabir] mengabarkan bahwa dia pernah ikut perang bersama Rasulullah shallallahu 'alaihi wasallam ke arah Najed.\""},"3608":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ قَالَ حَدَّثَنِي أَخِي عَنْ سُلَيْمَانَ عَنْ مُحَمَّدِ بْنِ أَبِي عَتِيقٍ عَنْ ابْنِ شِهَابٍ عَنْ سِنَانِ بْنِ أَبِي سِنَانٍ الدُّؤَلِيِّ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُمَا أَخْبَرَهُأَنَّهُ غَزَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قِبَلَ نَجْدٍ فَلَمَّا قَفَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَفَلَ مَعَهُ فَأَدْرَكَتْهُمْ الْقَائِلَةُ فِي وَادٍ كَثِيرِ الْعِضَاهِ فَنَزَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَتَفَرَّقَ النَّاسُ فِي الْعِضَاهِ يَسْتَظِلُّونَ بِالشَّجَرِ وَنَزَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَحْتَ سَمُرَةٍ فَعَلَّقَ بِهَا سَيْفَهُ قَالَ جَابِرٌ فَنِمْنَا نَوْمَةً ثُمَّ إِذَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَدْعُونَا فَجِئْنَاهُ فَإِذَا عِنْدَهُ أَعْرَابِيٌّ جَالِسٌ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ هَذَا اخْتَرَطَ سَيْفِي وَأَنَا نَائِمٌ فَاسْتَيْقَظْتُ وَهُوَ فِي يَدِهِ صَلْتًا فَقَالَ لِي مَنْ يَمْنَعُكَ مِنِّي قُلْتُ اللَّهُ فَهَا هُوَ ذَا جَالِسٌ ثُمَّ لَمْ يُعَاقِبْهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَوَقَالَ أَبَانُ حَدَّثَنَا يَحْيَى بْنُ أَبِي كَثِيرٍ عَنْ أَبِي سَلَمَةَ عَنْ جَابِرٍ قَالَ كُنَّا مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِذَاتِ الرِّقَاعِ فَإِذَا أَتَيْنَا عَلَى شَجَرَةٍ ظَلِيلَةٍ تَرَكْنَاهَا لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَجَاءَ رَجُلٌ مِنْ الْمُشْرِكِينَ وَسَيْفُ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُعَلَّقٌ بِالشَّجَرَةِ فَاخْتَرَطَهُ فَقَالَ تَخَافُنِي قَالَ لَا قَالَ فَمَنْ يَمْنَعُكَ مِنِّي قَالَ اللَّهُ فَتَهَدَّدَهُ أَصْحَابُ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأُقِيمَتْ الصَّلَاةُ فَصَلَّى بِطَائِفَةٍ رَكْعَتَيْنِ ثُمَّ تَأَخَّرُوا وَصَلَّى بِالطَّائِفَةِ الْأُخْرَى رَكْعَتَيْنِ وَكَانَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَرْبَعٌ وَلِلْقَوْمِ رَكْعَتَانِ وَقَالَ مُسَدَّدٌ عَنْ أَبِي عَوَانَةَ عَنْ أَبِي بِشْرٍ اسْمُ الرَّجُلِ غَوْرَثُ بْنُ الْحَارِثِ وَقَاتَلَ فِيهَا مُحَارِبَ خَصَفَةَ وَقَالَ أَبُو الزُّبَيْرِ عَنْ جَابِرٍ كُنَّا مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِنَخْلٍ فَصَلَّى الْخَوْفَ وَقَالَ أَبُو هُرَيْرَةَ صَلَّيْتُ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ غَزْوَةَ نَجْدٍ صَلَاةَ الْخَوْفِ وَإِنَّمَا جَاءَ أَبُو هُرَيْرَةَ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَيَّامَ خَيْبَرَ","id":"Telah menceritakan kepada kami [Isma'il] ia berkata; telah menceritakan kepadaku [Saudaraku] dari [Sulaiman] dari [Muhammad bin Abu 'Atiq] dari [Ibnu Syihab] dari [Sinan bin Abu Sinan Ad Du`ali] dari [Jabir bin Abdullah radliallahu 'anhuma], dia mengabarkan kepadanya bahwa dia pernah ikut perang bersama Rasulullah shallallahu 'alaihi wasallam ke arah Najed. Ketika Rasulullah shallallahu 'alaihi wasallam kembali, dia ikut kembali. Sewaktu hari mulai siang, mereka tiba di dekat lembah yang banyak pepohonan berduri. Lalu Rasulullah shallallahu 'alaihi wasallam singgah, sementara para shahabat berpencar mencari pepohonan untuk berteduh. Rasulullah shallallahu 'alaihi wasallam sendiri singgah di bawah pohon sambil menggantungkan pedangnya di pohon tersebut. Jabir melanjutkan; \"Maka kami tidur sejenak. Tidak lama kemudian Rasulullah shallallahu 'alaihi wasallam memanggil kami, ketika kami mnemui beliau, ternyata dihadapan beliau ada seorang Arab Badui sedang terduduk. Rasulullah shallallahu 'alaihi wasallam bersabda: \"Orang ini telah mengambil pedangku saat aku tidur, lalu aku bangun sedangkan tangannya telah memegang pedang yang terhunus, dia berkata kepadaku: \"Siapa yang dapat melindungimu dariku?\". Aku jawab: \"Allah\". Namun sekarang dia tengah terduduk lesu.\" Rasulullah Shallallhu 'alaihi wa salam tidak menghukum orang tersebut. [Aban] berkata; telah menceritakan kepada kami [Yahya bin Abu Katsir] dari [Abu Salamah] dari [Jabir] ia berkata; \"Kami pernah bersama Nabi shallallahu 'alaihi wasallam dalam perang Dzatur Riqa'. Ketika kami mendapatkan pohon sebagai tempat berteduh, kami peruntukkan pohon itu untuk istirahat Nabi shallallahu 'alaihi wasallam. Tiba-tiba seorang laki-laki musyrik datang, sementara pedang Nabi shallallahu 'alaihi wasallam tergantung di pohon tersebut. Laki-laki itu langsung mengambil pedang tersebut sambil berkata; \"Apakah engkau tidak takut kepadaku?\". Beliau menjawab: \"Tidak\". Orang i tu berkata lagi; \"Siapa yang dapat melindungimu dariku?\". Beliau menjawab: \"Allah\". Kemudian para shahabat mengancam orang itu. Tidak lama kemudian shalat didirikan, maka beliau shalat dengan satu kelompok sebanyak dua raka'at lalu kelompok ini mundur, Kemudian beliau melanjutkan shalat dua raka'at dengan nelompok lain, sehingga Nabi shallallahu 'alaihi wasallam melaksanakan shalat empat raka'at, sementara masing-masing kelompok shalat dua raka'at.\" Musaddad mengatakan dari Abu 'Awanah dari Abu Bisyir; \"Nama laki-laki musyrik itu adalah Ghawrats bin Al Harits.\" Saat itu dia tengah mengikuti perang Khashafah.\" [Abu Az Zubair] mengatakan dari [Jabir]; \"Kami bersama Nabi shallallahu 'alaihi wasallam di daerah Nakhl lalu beliau shalat khauf.\" Abu Hurairah mengatakan; \"Aku shalat bersama Nabi shallallahu 'alaihi wasallam pada perang Najed yaitu shalat Khauf. Padahal Abu Hurairah datang kepada Nabi shallallahu 'alaihi wasallam (masuk Islam) pada saat perang Khaibar.\""},"3609":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ أَخْبَرَنَا إِسْمَاعِيلُ بْنُ جَعْفَرٍ عَنْ رَبِيعَةَ بْنِ أَبِي عَبْدِ الرَّحْمَنِ عَنْ مُحَمَّدِ بْنِ يَحْيَى بْنِ حَبَّانَ عَنْ ابْنِ مُحَيْرِيزٍ أَنَّهُ قَالَدَخَلْتُ الْمَسْجِدَ فَرَأَيْتُ أَبَا سَعِيدٍ الْخُدْرِيَّ فَجَلَسْتُ إِلَيْهِ فَسَأَلْتُهُ عَنْ الْعَزْلِ قَالَ أَبُو سَعِيدٍ خَرَجْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي غَزْوَةِ بَنِي الْمُصْطَلِقِ فَأَصَبْنَا سَبْيًا مِنْ سَبْيِ الْعَرَبِ فَاشْتَهَيْنَا النِّسَاءَ وَاشْتَدَّتْ عَلَيْنَا الْعُزْبَةُ وَأَحْبَبْنَا الْعَزْلَ فَأَرَدْنَا أَنْ نَعْزِل�� وَقُلْنَا نَعْزِلُ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَيْنَ أَظْهُرِنَا قَبْلَ أَنْ نَسْأَلَهُ فَسَأَلْنَاهُ عَنْ ذَلِكَ فَقَالَ مَا عَلَيْكُمْ أَنْ لَا تَفْعَلُوا مَا مِنْ نَسَمَةٍ كَائِنَةٍ إِلَى يَوْمِ الْقِيَامَةِ إِلَّا وَهِيَ كَائِنَةٌ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah mengabarkan kepada kami [Isma'il bin Ja'far] dari [Rabi'ah bin Abu Abdurrahman] dari [Muhammad bin Yahya bin Habban] dari [Ibnu Muhayriz] bahwa dia berkata; \"Ketika aku masuk masjid, aku melihat Abu Sa'id Al Khudri, lalu aku duduk di sampingnya. Aku bertanya kepadanya tentang 'azal (senggama terputus). [Abu Sa'id] menjawab; \"Kami bersama Rasulullah shallallahu 'alaihi wasallam pernah keluar pada perang Bani Al Mushtahaliq, kemudian kami berhasil menawan para wanita dari keturunan 'Arab, kami tertarik dengan para wanitanya hingga kami merasa ingin memilikinya, sementara kami lebih menyukai untuk melakukan 'azal. Lalu kami saling berkata; \"Kita melakukan 'azal padahal Rasulullah shallallahu 'alaihi wasallam berada di tengah-tengah kita, sementara kita belum menyanyakannya kepada beliau.\" Akhirnya kami bertanya kepada beliau tentang masalah ini. Beliau menjawab: \"Tidak sebaiknyakah kalian untuk tidak melakukannya? Sebab tidak ada satu jiwapun yang telah Allah tetapkan akan tercipta hingga hari kiamat kecuali dia pasti akan tercipta.\""},"3610":{"ar":"حَدَّثَنَا مَحْمُودٌ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ أَبِي سَلَمَةَ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَغَزَوْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ غَزْوَةَ نَجْدٍ فَلَمَّا أَدْرَكَتْهُ الْقَائِلَةُ وَهُوَ فِي وَادٍ كَثِيرِ الْعِضَاهِ فَنَزَلَ تَحْتَ شَجَرَةٍ وَاسْتَظَلَّ بِهَا وَعَلَّقَ سَيْفَهُ فَتَفَرَّقَ النَّاسُ فِي الشَّجَرِ يَسْتَظِلُّونَ وَبَيْنَا نَحْنُ كَذَلِكَ إِذْ دَعَانَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَجِئْنَا فَإِذَا أَعْرَابِيٌّ قَاعِدٌ بَيْنَ يَدَيْهِ فَقَالَ إِنَّ هَذَا أَتَانِي وَأَنَا نَائِمٌ فَاخْتَرَطَ سَيْفِي فَاسْتَيْقَظْتُ وَهُوَ قَائِمٌ عَلَى رَأْسِي مُخْتَرِطٌ صَلْتًا قَالَ مَنْ يَمْنَعُكَ مِنِّي قُلْتُ اللَّهُ فَشَامَهُ ثُمَّ قَعَدَ فَهُوَ هَذَا قَالَ وَلَمْ يُعَاقِبْهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Mahmud] telah menceritakan kepada kami [Abdurrazzaq] telah mengabarkan kepada kami [Ma'mar] dari [Az Zuhri] dari [Abu Salamah] dari [Jabir bin Abdullah] ia berkata; \"Kami pernah ikut perang bersama Rasulullah shallallahu 'alaihi wasallam di wilayah Najed. Ketika waktu isirahat siang tiba, di saat beliau berada dekat lembah yang banyak pepohonan berduri, beliau singgah di bawah pohon untuk berteduh di bawahnya sambil menggantungkan pedangnya di pohon tersebut. Sedangkan orang-orang berpencar mencari pohon untuk berteduh. Tatkala kami sedang beristirahat, tiba-tiba Rasulullah shallallahu 'alaihi wasallam menyeru kami, kami langsung bergegas mendatangi beliau. Ternyata seorang Arab badui tengah terduduk lemah dihadapan beliau. Beliau bersabda: \"Orang ini mendatangiku saat aku tertidur lalu mengambil pedangku. Ketika aku terjaga, dia sudah berada di kepalaku dengan menghunuskan pedang seraya berkata; \"Siapa yang dapat melindungimu dariku?\". Aku menjawab: \"Allah.\" Kemudian dia memasukkan pedang itu ke sarungnya sambil tertududuk lemas seperti ini.\" Jabir berkata; \"Dan Rasulullah Shallallhu 'alaihi wa salam tidak menghukum orang itu.\""},"3611":{"ar":"حَدَّثَنَا آدَمُ حَدَّثَنَا ابْنُ أَبِي ذِئْبٍ حَدَّثَنَا عُثْمَانُ بْنُ عَبْدِ اللَّهِ بْنِ سُرَاقَةَ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ الْأَنْصَارِيِّ قَالَرَأَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي غَزْوَةِ أَنْمَارٍ يُصَلِّي عَلَى رَاحِلَتِهِ مُتَوَجِّهًا قِبَلَ الْمَشْرِقِ مُتَطَوِّعًا","id":"Telah menceritakan kepada kami [Adam] telah menceritakan kepada kami [Ibnu Abu Dzi'b] telah menceritakan kepada kami ['Utsman bin Abdullah bin Suraqah] dari [Jabir bin Abdullah Al Anshari] ia berkata; \"Pada saat perang Anmar, aku melihat Nabi shallallahu 'alaihi wasallam shalat sunnah di atas tunggangannya menghadap ke arah timur.\""},"3612":{"ar":"حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا إِبْرَاهِيمُ بْنُ سَعْدٍ عَنْ صَالِحٍ عَنْ ابْنِ شِهَابٍ قَالَ حَدَّثَنِي عُرْوَةُ بْنُ الزُّبَيْرِ وَسَعِيدُ بْنُ الْمُسَيَّبِ وَعَلْقَمَةُ بْنُ وَقَّاصٍ وَعُبَيْدُ اللَّهِ بْنُ عَبْدِ اللَّهِ بْنِ عُتْبَةَ بْنِ مَسْعُودٍ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَحِينَ قَالَ لَهَا أَهْلُ الْإِفْكِ مَا قَالُوا وَكُلُّهُمْ حَدَّثَنِي طَائِفَةً مِنْ حَدِيثِهَا وَبَعْضُهُمْ كَانَ أَوْعَى لِحَدِيثِهَا مِنْ بَعْضٍ وَأَثْبَتَ لَهُ اقْتِصَاصًا وَقَدْ وَعَيْتُ عَنْ كُلِّ رَجُلٍ مِنْهُمْ الْحَدِيثَ الَّذِي حَدَّثَنِي عَنْ عَائِشَةَ وَبَعْضُ حَدِيثِهِمْ يُصَدِّقُ بَعْضًا وَإِنْ كَانَ بَعْضُهُمْ أَوْعَى لَهُ مِنْ بَعْضٍ قَالُوا قَالَتْ عَائِشَةُ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أَرَادَ سَفَرًا أَقْرَعَ بَيْنَ أَزْوَاجِهِ فَأَيُّهُنَّ خَرَجَ سَهْمُهَا خَرَجَ بِهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَعَهُ قَالَتْ عَائِشَةُ فَأَقْرَعَ بَيْنَنَا فِي غَزْوَةٍ غَزَاهَا فَخَرَجَ فِيهَا سَهْمِي فَخَرَجْتُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعْدَ مَا أُنْزِلَ الْحِجَابُ فَكُنْتُ أُحْمَلُ فِي هَوْدَجِي وَأُنْزَلُ فِيهِ فَسِرْنَا حَتَّى إِذَا فَرَغَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ غَزْوَتِهِ تِلْكَ وَقَفَلَ دَنَوْنَا مِنْ الْمَدِينَةِ قَافِلِينَ آذَنَ لَيْلَةً بِالرَّحِيلِ فَقُمْتُ حِينَ آذَنُوا بِالرَّحِيلِ فَمَشَيْتُ حَتَّى جَاوَزْتُ الْجَيْشَ فَلَمَّا قَضَيْتُ شَأْنِي أَقْبَلْتُ إِلَى رَحْلِي فَلَمَسْتُ صَدْرِي فَإِذَا عِقْدٌ لِي مِنْ جَزْعِ ظَفَارِ قَدْ انْقَطَعَ فَرَجَعْتُ فَالْتَمَسْتُ عِقْدِي فَحَبَسَنِي ابْتِغَاؤُهُ قَالَتْ وَأَقْبَلَ الرَّهْطُ الَّذِينَ كَانُوا يُرَحِّلُونِي فَاحْتَمَلُوا هَوْدَجِي فَرَحَلُوهُ عَلَى بَعِيرِي الَّذِي كُنْتُ أَرْكَبُ عَلَيْهِ وَهُمْ يَحْسِبُونَ أَنِّي فِيهِ وَكَانَ النِّسَاءُ إِذْ ذَاكَ خِفَافًا لَمْ يَهْبُلْنَ وَلَمْ يَغْشَهُنَّ اللَّحْمُ إِنَّمَا يَأْكُلْنَ الْعُلْقَةَ مِنْ الطَّعَامِ فَلَمْ يَسْتَنْكِرْ الْقَوْمُ خِفَّةَ الْهَوْدَجِ حِينَ رَفَعُوهُ وَحَمَلُوهُ وَكُنْتُ جَارِيَةً حَدِيثَةَ السِّنِّ فَبَعَثُوا الْجَمَلَ فَسَارُوا وَوَجَدْتُ عِقْدِي بَعْدَ مَا اسْتَمَرَّ الْجَيْشُ فَجِئْتُ مَنَازِلَهُمْ وَلَيْسَ بِهَا مِنْهُمْ دَاعٍ وَلَا مُجِيبٌ فَتَيَمَّمْتُ مَنْزِلِي الَّذِي كُنْتُ بِهِ وَظَنَنْتُ أَنَّهُمْ سَيَفْقِدُونِي فَيَرْجِعُونَ إِلَيَّ فَبَيْنَا أَنَا جَالِسَةٌ فِي مَنْزِلِي غَلَبَتْنِي عَيْنِي فَنِمْتُ وَكَانَ صَفْوَانُ بْنُ الْمُعَطَّلِ السُّلَمِيُّ ثُمَّ الذَّكْوَانِيُّ مِنْ وَرَاءِ الْجَيْشِ فَأَصْبَحَ عِنْدَ مَنْزِلِي فَرَأَى سَوَادَ إِنْسَانٍ نَائِمٍ فَعَرَفَنِي حِينَ رَآنِي وَكَانَ رَآنِي قَبْلَ الْحِجَابِ فَاسْتَيْقَظْتُ بِاسْتِرْجَاعِهِ حِينَ عَرَفَنِي فَخَمَّرْتُ وَجْهِي بِجِلْبَابِي وَ وَاللَّهِ مَا تَكَلَّمْنَا بِكَلِمَةٍ وَلَا سَمِعْتُ مِنْهُ كَلِمَةً غَيْرَ اسْتِرْجَاعِهِ وَهَوَى حَتَّى أَنَاخَ رَاحِلَتَهُ فَوَطِئَ عَلَى يَدِهَا فَقُمْتُ إِلَيْهَا فَرَكِبْتُهَا فَانْطَلَقَ يَقُودُ بِي الرَّاحِلَةَ حَتَّى أَتَيْنَا الْجَيْشَ مُوغِرِينَ فِي نَحْرِ الظَّهِيرَةِ وَهُمْ نُزُولٌ قَالَتْ فَهَلَكَ مَنْ هَلَكَ وَكَانَ الَّذِي تَوَلَّى كِبْرَ الْإِفْكِ عَبْدُ اللَّهِ بْنُ أُبَيٍّ ابْنُ سَلُولَ قَالَ عُرْوَةُ أُخْبِرْتُ أَنَّهُ كَانَ يُشَاعُ وَيُتَحَدَّثُ بِهِ عِنْدَهُ فَيُقِرُّهُ وَيَسْتَمِعُهُ وَيَسْتَوْشِيهِ وَقَالَ عُرْوَةُ أَيْضًا لَمْ يُسَمَّ مِنْ أَهْلِ الْإِفْكِ أَيْضًا إِلَّا حَسَّانُ بْنُ ثَابِتٍ وَمِسْطَحُ بْنُ أُثَاثَةَ وَحَمْنَةُ بِنْتُ جَحْشٍ فِي نَاسٍ آخَرِينَ لَا عِلْمَ لِي بِهِمْ غَيْرَ أَنَّهُمْ عُصْبَةٌ كَمَا قَالَ اللَّهُ تَعَالَى وَإِنَّ كِبْرَ ذَلِكَ يُقَالُ لَهُ عَبْدُ اللَّهِ بْنُ أُبَيٍّ ابْنُ سَلُولَ قَالَ عُرْوَةُ كَانَتْ عَائِشَةُ تَكْرَهُ أَنْ يُسَبَّ عِنْدَهَا حَسَّانُ وَتَقُولُ إِنَّهُ الَّذِي قَالَ فَإِنَّ أَبِي وَوَالِدَهُ وَعِرْضِيلِعِرْضِ مُحَمَّدٍ مِنْكُمْ وِقَاءُقَالَتْ عَائِشَةُ فَقَدِمْنَا الْمَدِينَةَ فَاشْتَكَيْتُ حِينَ قَدِمْتُ شَهْرًا وَالنَّاسُ يُفِيضُونَ فِي قَوْلِ أَصْحَابِ الْإِفْكِ لَا أَشْعُرُ بِشَيْءٍ مِنْ ذَلِكَ وَهُوَ يَرِيبُنِي فِي وَجَعِي أَنِّي لَا أَعْرِفُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اللُّطْفَ الَّذِي كُنْتُ أَرَى مِنْهُ حِينَ أَشْتَكِي إِنَّمَا يَدْخُلُ عَلَيَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَيُسَلِّمُ ثُمَّ يَقُولُ كَيْفَ تِيكُمْ ثُمَّ يَنْصَرِفُ فَذَلِكَ يَرِيبُنِي وَلَا أَشْعُرُ بِالشَّرِّ حَتَّى خَرَجْتُ حِينَ نَقَهْتُ فَخَرَجْتُ مَعَ أُمِّ مِسْطَحٍ قِبَلَ الْمَنَاصِعِ وَكَانَ مُتَبَرَّزَنَا وَكُنَّا لَا نَخْرُجُ إِلَّا لَيْلًا إِلَى لَيْلٍ وَذَلِكَ قَبْلَ أَنْ نَتَّخِذَ الْكُنُفَ قَرِيبًا مِنْ بُيُوتِنَا قَالَتْ وَأَمْرُنَا أَمْرُ الْعَرَبِ الْأُوَلِ فِي الْبَرِّيَّةِ قِبَلَ الْغَائِطِ وَكُنَّا نَتَأَذَّى بِالْكُنُفِ أَنْ نَتَّخِذَهَا عِنْدَ بُيُوتِنَا قَالَتْ فَانْطَلَقْتُ أَنَا وَأُمُّ مِسْطَحٍ وَهِيَ ابْنَةُ أَبِي رُهْمِ بْنِ الْمُطَّلِبِ بْنِ عَبْدِ مَنَافٍ وَأُمُّهَا بِنْتُ صَخْرِ بْنِ عَامِرٍ خَالَةُ أَبِي بَكْرٍ الصِّدِّيقِ وَابْنُهَا مِسْطَحُ بْنُ أُثَاثَةَ بْنِ عَبَّادِ بْنِ الْمُطَّلِبِ فَأَقْبَلْتُ أَنَا وَأُمُّ مِسْطَحٍ قِبَلَ بَيْتِي حِينَ فَرَغْنَا مِنْ شَأْنِنَا فَعَثَرَتْ أُمُّ مِسْطَحٍ فِي مِرْطِهَا فَقَالَتْ تَعِسَ مِسْطَحٌ فَقُلْتُ لَهَا بِئْسَ مَا قُلْتِ أَتَسُبِّينَ رَجُلًا شَهِدَ بَدْرًا فَقَالَتْ أَيْ هَنْتَاهْ وَلَمْ تَسْمَعِي مَا قَالَ قَالَتْ وَقُلْتُ مَا قَالَ فَأَخْبَرَتْنِي بِقَوْلِ أَهْلِ الْإِفْكِ قَالَتْ فَازْدَدْتُ مَرَضًا عَلَى مَرَضِي فَلَمَّا رَجَعْتُ إِلَى بَيْتِي دَخَلَ عَلَيَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَلَّمَ ثُمَّ قَالَ كَيْفَ تِيكُمْ فَقُلْتُ لَهُ أَتَأْذَنُ لِي أَنْ آتِيَ أَبَوَيَّ قَالَتْ وَأُرِيدُ أَنْ أَسْتَيْقِنَ الْخَبَرَ مِنْ قِبَلِهِمَا قَالَتْ فَأَذِنَ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ لِأُمِّي يَا أُمَّتَاهُ مَاذَا يَتَحَدَّثُ النَّاسُ قَالَتْ يَا بُنَيَّةُ هَوِّنِي عَلَيْكِ فَوَاللَّهِ لَقَلَّمَا كَانَتْ امْرَأَةٌ قَطُّ وَضِيئَةً عِنْدَ رَجُلٍ يُحِبُّهَا لَهَا ضَرَائِرُ إِلَّا كَثَّرْنَ عَلَيْهَا قَالَتْ فَقُلْتُ سُبْحَانَ اللَّهِ أَوَلَقَدْ تَحَدَّثَ النَّاسُ بِهَذَا قَالَتْ فَبَكَيْتُ تِلْكَ اللَّيْلَةَ حَتَّى أَصْبَحْتُ لَا يَرْقَأُ لِي دَمْعٌ وَلَا أَكْتَحِلُ بِنَوْمٍ ثُمَّ أَصْبَحْتُ أَبْكِي قَالَتْ وَدَعَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلِيَّ بْنَ أَبِي طَالِبٍ وَأُسَامَةَ بْنَ زَيْدٍ حِينَ اسْتَلْبَثَ الْوَحْيُ يَسْأَلُهُمَا وَيَسْتَشِيرُهُمَا فِي فِرَاقِ أَهْلِهِ قَالَتْ فَأَمَّا أُسَامَةُ فَأَشَارَ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالَّذِي يَعْلَمُ مِنْ بَرَاءَةِ أَهْلِهِ وَبِالَّذِي يَعْلَمُ لَهُمْ فِي نَفْسِهِ فَقَالَ أُسَامَةُ أَهْلَكَ وَلَا نَعْلَمُ إِلَّا خَيْرًا وَأَمَّا عَلِيٌّ فَقَالَ يَا رَسُولَ اللَّهِ لَمْ يُضَيِّقْ اللَّهُ عَلَيْكَ وَالنِّسَاءُ سِوَاهَا كَثِيرٌ وَسَلْ الْجَارِيَةَ تَصْدُقْكَ قَالَتْ فَدَعَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَرِيرَةَ فَقَالَ أَيْ بَرِيرَةُ هَلْ رَأَيْتِ مِنْ شَيْءٍ يَرِيبُكِ قَالَتْ لَهُ بَرِيرَةُ وَالَّذِي بَعَثَكَ بِالْحَقِّ مَا رَأَيْتُ عَلَيْهَا أَمْرًا قَطُّ أَغْمِصُهُ غَيْرَ أَنَّهَا جَارِيَةٌ حَدِيثَةُ السِّنِّ تَنَامُ عَنْ عَجِينِ أَهْلِهَا فَتَأْتِي الدَّاجِنُ فَتَأْكُلُهُ قَالَتْ فَقَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ يَوْمِهِ فَاسْتَعْذَرَ مِنْ عَبْدِ اللَّهِ بْنِ أُبَيٍّ وَهُوَ عَلَى الْمِنْبَرِ فَقَالَ يَا مَعْشَرَ الْمُسْلِمِينَ مَنْ يَعْذِرُنِي مِنْ رَجُلٍ قَدْ بَلَغَنِي عَنْهُ أَذَاهُ فِي أَهْلِي وَاللَّهِ مَا عَلِمْتُ عَلَى أَهْلِي إِلَّا خَيْرًا وَلَقَدْ ذَكَرُوا رَجُلًا مَا عَلِمْتُ عَلَيْهِ إِلَّا خَيْرًا وَمَا يَدْخُلُ عَلَى أَهْلِي إِلَّا مَعِي قَالَتْ فَقَامَ سَعْدُ بْنُ مُعَاذٍ أَخُو بَنِي عَبْدِ الْأَشْهَلِ فَقَالَ أَنَا يَا رَسُولَ اللَّهِ أَعْذِرُكَ فَإِنْ كَانَ مِنْ الْأَوْسِ ضَرَبْتُ عُنُقَهُ وَإِنْ كَانَ مِنْ إِخْوَانِنَا مِنْ الْخَزْرَجِ أَمَرْتَنَا فَفَعَلْنَا أَمْرَكَ قَالَتْ فَقَامَ رَجُلٌ مِنْ الْخَزْرَجِ وَكَانَتْ أُمُّ حَسَّانَ بِنْتَ عَمِّهِ مِنْ فَخِذِهِ وَهُوَ سَعْدُ بْنُ عُبَادَةَ وَهُوَ سَيِّدُ الْخَزْرَجِ قَالَتْ وَكَانَ قَبْلَ ذَلِكَ رَجُلًا صَالِحًا وَلَكِنْ احْتَمَلَتْهُ الْحَمِيَّةُ فَقَالَ لِسَعْدٍ كَذَبْتَ لَعَمْرُ اللَّهِ لَا تَقْتُلُهُ وَلَا تَقْدِرُ عَلَى قَتْلِهِ وَلَوْ كَانَ مِنْ رَهْطِكَ مَا أَحْبَبْتَ أَنْ يُقْتَلَ فَقَامَ أُسَيْدُ بْنُ حُضَيْرٍ وَهُوَ ابْنُ عَمِّ سَعْدٍ فَقَالَ لِسَعْدِ بْنِ عُبَادَةَ كَذَبْتَ لَعَمْرُ اللَّهِ لَنَقْتُلَنَّهُ فَإِنَّكَ مُنَافِقٌ تُجَادِلُ عَنْ الْمُنَافِقِينَ قَالَتْ فَثَارَ الْحَيَّانِ الْأَوْسُ وَالْخَزْرَجُ حَتَّى هَمُّوا أَنْ يَقْتَتِلُوا وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَائِمٌ عَلَى الْمِنْبَرِ قَالَتْ فَلَمْ يَزَلْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُخَفِّضُهُمْ حَتَّى سَكَتُوا وَسَكَتَ قَالَتْ فَبَكَيْتُ يَوْمِي ذَلِكَ كُلَّهُ لَا يَرْقَأُ لِي دَمْعٌ وَلَا أَكْتَحِلُ بِنَوْمٍ قَالَتْ وَأَصْبَحَ أَبَوَايَ عِنْدِي وَقَدْ بَكَيْتُ لَيْلَتَيْنِ وَيَوْمًا لَا يَرْقَأُ لِي دَمْعٌ وَلَا أَكْتَحِلُ بِنَوْمٍ حَتَّى إِنِّي لَأَظُنُّ أَنَّ الْبُكَاءَ فَالِقٌ كَبِدِي فَبَيْنَا أَبَوَايَ جَالِسَانِ عِنْدِي وَأَنَا أَبْكِي فَاسْتَأْذَنَتْ عَلَيَّ امْ","id":"Telah menceritakan kepada kami [Abdul Aziz bin Abdullah] telah menceritakan kepada kami [Ibrahim bin Sa'ad] dari [Shalih] dari [Ibnu Syihab] ia berkata; telah menceritakan kepadaku ['Urwah bin Az Zubair] dan [Sa'id bin Al Musayyab] dan ['Alqamah bin Waqash Al Laitsi] dan ['Ubaidullah bin Abdullah bin 'Uqbah bin Mas'ud] dari ['Aisyah radliallahu 'anha] istri Nabi shallallahu 'alaihi wasallam, yaitu ketika orang-orang penuduh berkata kepadanya seperti apa yang telah mereka katakan. Mereka semuanya bercerita kepadaku, sekelompok orang becerita berdasarkan apa yang disampaikan 'Aisyah dan sebagian lagi hanya perkiraan mereka, lalu aku menetapkan hadits dari kisah-kisah yang berkenaan dengan peristiwa ini dan aku juga memasukkan hadits-hadits dari mereka yang diceritakan kepadaku dari 'Aisyah dan sebagian lagi hadits saling menguatkan satu sama lain, dimana mereka menduga kepada sebagian yang lain, mereka berkata 'Aisyah berkata: \"Apabila Rasulullah shallallahu 'alaihi wasallam hendak mengadakan suatu perjalanan, beliau biasa mengundi diantara istri-istri beliau, jika nama seorang dari mereka keluar, berarti dia ikut bepergian bersama beliau. Pada suatu hari beliau mengundi nama-nama kami untuk suatu peperangan yang beliau lakukan, maka keluar namaku hingga aku turut serta bersama Rasulullah shallallahu 'alaihi wasallam setelah turun ayat hijab. Aku dibawa didalam sekedup dan ditempatkan didalamnya. Kami lalu berangkat, ketika Rasulullah shallallahu 'alaihi wasallam selesai dari peperangan tersebut, kamipun kembali pulang. Tatkala kami dekat dengan Madinah, beliau mengumumkan untuk beristirahat malam. Maka aku keluar dari sekedup saat beliau dan rombongan berhenti, lalu aku berjalan hingga meninggalkan pasukan. Setelah aku selesai menunaikan keperluanku, aku kembali menuju rombongan, betapa terkejutnya aku, ketika aku meraba dadaku ternyata kalungku yang terbuat dari negeri Zhafar terjatuh. Maka aku kembali untuk mencari kalungku. Aisyah melanjutkan; \"Kemudian orang-orang yang membawaku datang dan membawa sekedupku, dan menaikkannya di atas unta yang aku tunggangi. Mereka menduga aku sudah berada didalam sekedup itu. Memang masa itu para wanita berbadan ringan, tidak terlalu berat, dan mereka tidak banyak daging, mereka hanya makan sesuap makanan. Oleh karena itu orang-orang yang membawa sekedupku tidak curiga dengan ringannya sekedupku ketika mereka mengangkatnya. Saat itu aku adalah wanita yang masih muda. Lalu mereka menggiring unta dan berjalan. Sementara aku baru mendapatkan kembali kalungku setelah pasukan telah berlalu. Aku lalu mendatangi tempat rombongan berhenti, namun tidak ada seorangpun yang tertinggal. Setelah itu aku kembali ke tempatku semula dengan harapan mereka merasa kehilangan aku lalu kembali ke tempatku. Ketika aku duduk, aku terserang rasa kantuk hingga akhirnya aku tertidur. Shafwan bin Al Mu'aththal As Sulami Adz Dzakwan datang menyusuk dari belakang pauskan, kemudian dia menghampiri tempatku dan dia melihat ada bayangan hitam seperti orang yang sedang tidur. Dia mengenaliku saat melihat aku. Dia memang pernah melihat aku sebelum turun ayat hijab. Aku langsung terbangun ketika mendengar kalimat istirja'nya, (ucapan innaa lillahi wa inanaa ilaihi raji'un), saat dia mengenali aku. Aku langsung menutup mukaku dengan jilbabku. Demi Allah, tidaklah kami berbicara sepatah katapun dan aku juga tidak mendengar sepatah katapun darinya kecuali kalimat istirja'nya, dia lalu menghentikan hewan tunggangannya dan merundukkannya hingga berlutut. Maka aku menghampiri tunggangannya itu lalu aku menaikinya. Dia kemudian berjalan sambil menuntun tunggangannya itu hingga kami dapat menyusul pasukan setelah mereka berhenti di tepian sungai Azh Zhahirah untuk singgah di tengah panasnya siang. Aisyah berkata; \"Maka binasalah orang yang binasa.\" Dan orang yang berperan besar menyebarkan berita bohong ini adalah Abdullah bin Ubay bin Salul.\" - 'Urwah berkata; Dikabarkan kepadaku bahwa Abdullah bin Ubay menyebarkan berita bohong itu, menceritakannya, membenarkannya dan menyampaikannya kepada orang-orang sambil menambah-nambahinya- 'Urwah juga berkata; \"Tidak disebutkan orang-orang yang juga terlibat menyebarkan berita bohong itu selain Hasaan bin Tsabit, Misthah bin Utsatsah dan Hamnah binti Jahsyi. Aku tidak tahu tentang mereka melainkan mereka adalah sekelompk orang sebagaimana Allah Ta'ala firmankan. Dan yang paling berperan diantara mereka adalah Abdullah bin Ubay bin Salul. 'Urwah berkata; 'Aisyah tidak suka mencela Hassan, dia berkata bahwa Hassan adalah orang yang pernah bersya'ir: \"Sesungguhnya ayahku, dan ayahnya serta kehormatanku adalah untuk kehormatan Muhammad sebagai tameng dari kalian.\" Selanjutnya 'Aisyah berkata; \"Setibanya kami di Madinah, aku menderita sakit selama satu bulan sejak kedatanganku, sementara orang-orang sibuk dengan berita bohong yang diucapankan oleh orang-orang yang membawa berita bohong. Sementara aku sama sekali tidak menyadari sedikitpun adanya berita tersebut. Namun aku curiga, bila beliau shallallahu 'alaihi wasallam hanya menjengukku saat sakitku dan aku tidak merasakan kelembutan Rasulullah shallallahu 'alaihi wasallam seperti yang biasa aku dapatkan dari beliau ketika aku sedang sakit. Rasulullah shallallahu 'alaihi wasallam hanya masuk menemuiku dan memberi salam lalu bertanya: \"Bagaimana keadaanmu\", lantas pergi. Inilah yang membuat aku gelisah, namun aku tidak menyadari adanya keburukan yang sedang terjadi. Pada suatu hari, aku keluar (dari rumahku) saat aku merasa sudah sembuh. Aku keluar bersama Ummu Misthah menuju Al Manashi', tempat kami biasa membuang hajat dan kami tidak keluar kesana kecuali di malam hari, Hal itu sebelum kami membuat tempat buang hajat di dekat rumah kami. 'Aisyah berkata; \"Dan kebiasaan kami sama seperti kebiasaan orang-orang Arab dahulu, bila buang hajat diluar rumah (atau di lapangan terbuka). Kami merasa tidak nyaman bila membuat tempat buang hajat dekat dengan rumah-rumah kami\". 'Aisyah melanjutkan; \"Maka aku dan Ummu Misthah, -dia adalah anak Abu Ruhum bin Al Muthallib bin Abdu Manaf, sementara ibunya adalah anak dari Shakhar bin 'Amir, bibi dari ibu Abu Bakr Ash Shiddiq, sedangkan anaknya bernama Misthah bin Utsatsah bin 'Abbad bin Al Mutahllib- setelah selesai dari urusan kami, aku dan Ummu Misthah kembali menuju rumahku. Tiba-tiba Ummu Misthah tersandung kainnya seraya berkata; \"Celakalah Misthah.\" Aku katakan kepadanya; \"Sungguh buruk apa yang kamu ucapkan tadi. Apakah kamu mencela seorang laki-laki yang pernah ikut perang Badar?\" Dia berkata; \"Wahai putri, apakah anda belum mendengar apa yang dia ucapkan?\". Aku bertanya; \"Apa yang telah diucapkannya?\" Ummu Misthah menceritakan kepadaku tentang ucapan orang-orang yang membawa berita bohong (tuduhan keji). Kejadian ini semakin menambah sakitku diatas sakit yang sudah aku rasakan. Ketika aku kembali ke rumahku, Rasulullah shallallahu 'alaihi wasallam masuk menemuiku lalu memberi salam dan bersabda: \"Bagaimana keadaanmu?\". Aku bertanya kepada beliau; \"Apakah engkau mengizinkanku untuk pulang ke rumah kedua orangtuaku.\" 'Aisyah berkata: \"Saat itu aku ingin mencari kepastian berita dari pihak kedua orang tuaku.\" Maka Rasulullah shallallahu 'alaihi wasallam memberiku izin, lalu aku bertanya kepada ibuku; \"Wahai ibu, apa yang sedang dibicarakan oleh orang-orang?\" Ibuku menjawab: \"Wahai putriku, tenanglah. Demi Allah, sangat sedikit seorang wanita yang tinggal bersama seorang laki-laki yang dia mencintainya serta memiliki para madu melainkan mereka akan mengganggunya.\" 'Aisyah berkata; aku berkata; \"Subhanallah, apakah benar orang-orang tengah memperbincangkan masalah ini.\" 'Aisyah berkata; \"Maka aku menangis sepanjang malam hingga pagi hari dengan penuh linangan air mata dan aku tidak dapat tidur dan tidak bercelak karena terus menangis, hingga pagi hari aku masih menangis. 'Aisyah melanjutkan; \"Rasulullah shallallahu 'alaihi wasallam memanggil 'Ali bin Abi Thalib dan Usamah bin Zaid ketika wahyu belum turun, beliau bertanya kepada keduanya dan meminta pandangan perihal rencana untuk berpisah dengan istri beliau. 'Aisyah melanjutkan; Usamah memberi isyarat kepada beliau tentang apa yang diketahuinya berupa kebersihan keluarga beliau dan apa yang dia ketahui tentang mereka pada dirinya. Usamah berkata: \"Keluarga anda, tidaklah kami mengenalnya melainkan kebaikan.\" Sedangkan 'Ali bin Abi Thalib berkata; \"Wahai Rasulullah, Allah tidak akan menyusahkan anda, sebab masih banyak wanita-wanita lain. Tanyakanlah kepada sahaya wanitanya yang akan membenarkan anda.\" Maka Rasulullah shallallahu 'alaihi wasallam memanggil Barirah dan bersabda: \"Wahai Barirah, apakah kamu pernah melihat sesuatu yang meragukan pada diri Aisyah?\". Barirah menjawab: \"Demi Dzat Yang mengutus anda dengan benar, aku tidak pernah melihatnya sesuatu yang meragukan. Kalaupun aku melihat sesuatu padanya tidak lebih dari sekedar perkara kecil, dia juga masih sangat muda, dia pernah tidur di atas adonan milik keluargaya lalu dia memakan adonan tersebut.\" 'Aisyah melanjutkan; \"Suatu hari, di saat beliau berdiri di atas mimbar, Rasulullah shallallahu 'alaihi wasallam berdiri untuk mengingatkan Abdullah bin Ubay bin Salul. Beliau bersabda: \"Wahai sekalian kaum Muslimin, siapa orang yang dapat membebaskan aku dari orang yang aku dengar telah menyakiti keluargaku. Demi Allah, aku tidak mengetahui keluargaku melainkan kebaikan. Sungguh mereka telah menyebut-nyebut seseorang (maksudnya Shafwan) yang aku tidak mengenalnya melainkan kebaikan, tidaklah dia mendatangi keluargaku melainkan selalu bersamaku.\" 'Aisyah berkata; \"Maka Sa'ad bin Mu'adz, saudara dari Bani 'Abdul Ashal berdiri seraya berkata: \"Aku wahai Rasulullah, aku akan membalaskan penghinaan ini buat anda. Seandainya orang itu dari kalangan suku Aus, aku akan memenggal batang lehernya dan seandainya dari saudara kami dari suku Khazraj, maka perintahkanlah kepada kami, pasti kami akan melaksanakan apa yang anda perintahkan.\" 'Aisyah melanjutkan; Lalu beridirilah seorang laki-laki dari suku Khazraj -Ibunya Hassan adalah anak dari pamannya- dia adalah Sa'ad bin 'Ubadah, pimpinan suku Khazraj. 'Aisyah melanjutkan; \"Dia adalah orang yang shalih, namun hari itu terbawa oleh sikap kesukuan sehingga berkata kepada Sa'ad bin Mu'adz; \"Dusta kamu, demi Allah yang mengetahui umur hamba-Nya, kamu tidak akan membunuhnya dan tidak akan dapat membunuhnya. Seandainya dia dari sukumu, kamu tentu tidak akan mau membunuhnya.\" Kemudian Usaid bin Hudlair, anak pamannya Sa'ad bin Mu'adz, berdiri seraya berkata; \"Justru kamu yang dusta, demi Allah yang mengetahui umur hamba-Nya, kami pasti akan membunuhnya. Sungguh kamu telah menjadi seorang munafiq karena membela orang-orang munafiq.\" Maka suasana pertemuan menjadi semakin memanas, antara dua suku, Aus dan Khazraj hingga mereka hendak saling membunuh, padahal Rasulullah shallallahu 'alaihi wasallam masih berdiri di atas mimbar. 'Aisyah melanjutkan; \"Rasulullah shallallahu 'alaihi wasallam terus menenangkan mereka hingga akhirnya mereka terdiam dan beliau pun diam. 'Aisyah berkata; \"Maka aku menangis sepanjang hariku, air mataku terus berlinang dan aku tidak bisa tidur tenang karenanya hingga akhirnya kedua orangtuaku berada di sisiku, sementara aku telah menangis selama dua malam satu hari, hingga aku menyangka air mataku telah kering.\" Ketika kedua orangtuaku sedang duduk di dekatku, dan aku terus saja menangis, tiba-tiba seorang wanita Anshar datang meminta izin menemuiku, lalu aku mengizinkannya. Kemudian dia duduk sambil menangis bersamaku. Ketika kami seperti itu, tiba-tiba Rasulullah shallallahu 'alaihi wasallam datang lalu duduk. 'Aisyah berkata; \"Namun beliau tidak duduk di dekatku sejak berita bohong ini tersiar. Sudah satu bulan lamanya peristiwa ini berlangsung sedangkan wahyu belum juga turun untuk menjelaskan perkara yang menimpaku ini.\" Aisyah berkata; \"Rasulullah shallallahu 'alaihi wasallam lalu membaca syahadat ketika duduk, kemudian bersabda: \"Wahai 'Aisyah, sungguh telah sampai kepadaku berita tentang dirimu begini dan begini. Jika kamu bersih, tidak bersalah pasti Allah akan membersihkanmu. Namun jika kamu telah melakukan dosa, maka mohonlah ampun kepada Allah dan bertaubatlah kepada-Nya, karena seorang hamba bila dia mengakui telah berbuat dosa lalu bertaubat, Allah pasti akan menerima taubatnya.\" Setelah Rasulullah shallallahu 'alaihi wasallam menyelesaikan kalimat yang disampaikan, aku membersihkan air mataku agar tidak nampak tersisa setetespun, lalu aku katakan kepada ayahku; \"Belalah aku terhadap apa yang di katakan Rasulullah shallallahu 'alaihi wasallam tentang diriku.\" Ayahku berkata; \"Demi Allah, aku tidak tahu apa yang harus aku katakan kepada Rasulullah shallallahu 'alaihi wasallam.\" Lalu aku katakan kepada ibuku: \"Belalah aku terhadap apa yang di katakan Rasulullah shallallahu 'alaihi wasallam tentang diriku.\" Ibuku pun menjawab; \"Demi Allah, aku tidak mengetahui apa yang harus aku katakan kepada Rasulullah shallallahu 'alaihi wasallam.\" 'Aisyah berkata; \"Aku hanyalah seorang wanita yang masih muda belia, memang aku belum banyak membaca Al Qur'an. Demi Allah, sesungguhnya aku telah mengetahui bahwa kalian telah mendengar apa yang diperbincangkan oleh orang-orang, hingga kalian pun telah memasukkannya dalam hati kalian lalu membenarkan berita tersebut. Seandainya aku katakan kepada kalian bahwa aku bersih dan demi Allah, Dia Maha Mengetahui bahwa aku bersih, kalian pasti tidak akan membenarkan aku. Seandainya aku mengakui (dan membenarkan fitnah tersebut) kepada kalian, padahal Allah Maha Mengetahui bahwa aku bersih, kalian pasti membenarkannya. Demi Allah, aku tidak menemukan antara aku dan kalian suatu perumpamaan melainkan seperti ayahnya Nabi Yusuf 'alaihis salam ketika dia berkata: (\"Bershabarlah dengan shabar yang baik karena Allah akan mengungkap apa yang kalian\") QS Yusuf ayat 18. Setelah itu aku pergi menuju tempat tidurku dan Allah mengetahui hari itu aku memang benar-benar bersih dan Allah-lah yang akan membebaskanku dari tuduhan itu. Akan tetapi, demi Allah, aku tidak menduga kalau Allah akan menurunkan wahyu yang menerangkan tentang urusan yang menimpaku. Karena menurutku tidak pantas bila wahyu turun lalu dibaca orang hanya karena menceritakan masalah peribadiku ini. Aku terlalu rendah bila Allah membicarakan masalahku ini. Tetapi aku hanya berharap Rasulullah shallallahu 'alaihi wasallam mendapatkan wahyu lewat mimpi bahwa Allah membersihkan diriku. Dan demi Allah, sungguh Rasulullah shallallahu 'alaihi wasallam tidak ingin beranjak dari tempat duduknya dan tidak pula seorang pun dari keluarganya yang keluar melainkan telah turun wahyu kepada beliau. Beliau menerima wahyu tersebut sebagaimana beliau biasa menerimanya dalam keadaan yang sangat berat dengan bercucuran keringat seperti butiran mutiara, padahal hari itu adalah musim dingin. Ini karena beratnya wahyu yang diturunkan kepada beliau. 'Aisyah berkata; Setelah itu nampak muka beliau berseri dan dalam keadaan tertawa. Kalimat pertama yang beliau ucapkan adalah: \"Wahai 'Aisyah, sungguh Allah telah membersihkan dirimu.\" 'Aisyah berkata; \"Lalu ibuku berkata kepadaku: \"Bangkitlah untuk menemui beliau.\" Aku berkata: \"Demi Allah, aku tidak akan berdiri kepadanya dan aku tidak akan memuji siapapun selain Allah 'azza wajalla. Maka Allah menurunkan ayat \"Sesungguhnya orang-orang yang menyebarkan berita bohong diantata kalian adalah masih golongan kalian juga…\" QS An Nuur; 11 dan seterusnya sebanyak sepuluh ayat. Selanjutnya turun ayat yang menjelaskan terlepasnya diriku dari segala tuduhan. Abu Bakar Ash Shiddiq yang selalu menanggung hidup Misthah bin Utsatsah karena memang masih kerabatnya berkata: \"Demi Allah, setelah ini aku tidak akan lagi memberi nafkah kepada Misthah untuk selamanya, karena dia telah ikut menyebarkan berita bohong tentang 'Aisyah.\" Kemudian Allah menurunkan ayat; \"Dan janganlah orang-orang yang memiliki kelebihan dan kelapangan diantara kalian bersumpah untuk tidak lagi memberikan kepada …..hingga ayat…. Allah Maha Pengampun lagi Maha Penyayang.\" QS An Nuur; 22. Lantas Abu Bakar berkata; \"Ya, demi Allah, sungguh aku lebih mencintai bila Allah mengampuniku.\" Maka dia kembali memberi nafkah kepada Misthah sebagaimana sebelumnya dan berkata; \"Aku tidak akan mencabut nafkah kepadanya untuk selama-lamanya.\" 'Aisyah berkata; \"Dan Rasulullah shallallahu 'alaihi wasallam pernah bertanya kepada Za"},"3613":{"ar":"حَدَّثَنِي عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ قَالَ أَمْلَى عَلَيَّ هِشَامُ بْنُ يُوسُفَ مِنْ حِفْظِهِ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ قَالَ قَالَ لِي الْوَلِيدُ بْنُ عَبْدِ الْمَلِكِ أَبَلَغَكَ أَنَّ عَلِيًّا كَانَ فِيمَنْ قَذَفَ عَائِشَةَ قُلْتُ لَا وَلَكِنْ قَدْ أَخْبَرَنِي رَجُلَانِ مِنْ قَوْمِكَ أَبُو سَلَمَةَ بْنُ عَبْدِ الرَّحْمَنِ وَأَبُو بَكْرِ بْنُ عَبْدِ الرَّحْمَنِ بْنِ الْحَارِثِ أَنَّ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْ لَهُمَاكَانَ عَلِيٌّ مُسَلِّمًا فِي شَأْنِهَا فَرَاجَعُوهُ فَلَمْ يَرْجِعْ وَقَالَ مُسَلِّمًا بِلَا شَكٍّ فِيهِ وَعَلَيْهِ كَانَ فِي أَصْلِ الْعَتِيقِ كَذَلِكَ","id":"Telah menceritakan kepadaku [Abdullah bin Muhammad] berkata; [Hisyam bin Yusuf] membacakan kepadaku apa yang dihafalnya, telah mengabarkan kepada kami [Ma'mar] dari [Az Zuhriy] ia berkata; Al Walid bin Abdul Malik telah bertanya kepadaku; 'Apakah 'Ali adalah termasuk orang yang menuduh 'Aisyah (berselingkuh)? ' Aku jawab; \"Tidak. Akan tetapi dua orang dari kaummu yang mengabarkan kepadaku, yaitu [Abu Salamah bin Abdurrahman] dan [Abu Bakr bin Abdurrahman bin Al Harits] bahwa ['Aisyah radliallahu 'anha] pernah berkata kepada keduanya bahwa 'Ali menerima. Lalu mereka kembali bertanya tapi Az Zuhri tidak menjawabnya. Dia berkata; \"Musalliman (menerima) tanpa diragukan lagi\". Demikian juga makna pada asal katanya."},"3614":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ حُصَيْنٍ عَنْ أَبِي وَائِلٍ قَالَ حَدَّثَنِي مَسْرُوقُ بْنُ الْأَجْدَعِ قَالَ حَدَّثَتْنِي أُمُّ رُومَانَ وَهِيَ أُمُّ عَائِشَةَ رَضِيَ اللَّهُ عَنْهُمَا قَالَتْبَيْنَا أَنَا قَاعِدَةٌ أَنَا وَعَائِشَةُ إِذْ وَلَجَتْ امْرَأَةٌ مِنْ الْأَنْصَارِ فَقَالَتْ فَعَلَ اللَّهُ بِفُلَانٍ وَفَعَلَ فَقَالَتْ أُمُّ رُومَانَ وَمَا ذَاكَ قَالَتْ ابْنِي فِيمَنْ حَدَّثَ الْحَدِيثَ قَالَتْ وَمَا ذَاكَ قَالَتْ كَذَا وَكَذَا قَالَتْ عَائِشَةُ سَمِعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْ نَعَمْ قَالَتْ وَأَبُو بَكْرٍ قَالَتْ نَعَمْ فَخَرَّتْ مَغْشِيًّا عَلَيْهَا فَمَا أَفَاقَتْ إِلَّا وَعَلَيْهَا حُمَّى بِنَافِضٍ فَطَرَحْتُ عَلَيْهَا ثِيَابَهَا فَغَطَّيْتُهَا فَجَاءَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ مَا شَأْنُ هَذِهِ قُلْتُ يَا رَسُولَ اللَّهِ أَخَذَتْهَا الْحُمَّى بِنَافِضٍ قَالَ فَلَعَلَّ فِي حَدِيثٍ تُحُدِّثَ بِهِ قَالَتْ نَعَمْ فَقَعَدَتْ عَائِشَةُ فَقَالَتْ وَاللَّهِ لَئِنْ حَلَفْتُ لَا تُصَدِّقُونِي وَلَئِنْ قُلْتُ لَا تَعْذِرُونِي مَثَلِي وَمَثَلُكُمْ كَيَعْقُوبَ وَبَنِيهِ{ وَاللَّهُ الْمُسْتَعَانُ عَلَى مَا تَصِفُونَ }قَالَتْ وَانْصَرَفَ وَلَمْ يَقُلْ شَيْئًا فَأَنْزَلَ اللَّهُ عُذْرَهَا قَالَتْ بِحَمْدِ اللَّهِ لَا بِحَمْدِ أَحَدٍ وَلَا بِحَمْدِكَ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] telah menceritakan kepada kami [Abu 'Awanah] dari [Hushain] dari [Abu Wa'il] ia berkata; telah menceritakan kepadaku [Masruq bin Al Ajda'] ia berkata; telah menceritakan kepadaku [Ummu Ruman] ibunya 'Aisyah radliallahu 'anhuma, ia berkata; \"Saat aku dan 'Aisyah duduk, tiba-tiba datang seorang wanita Anshar seraya berkata; \"Semoga Allah berbuat terhadap fulan dan pasti berbuat.\" Maka Ummu Ruman bertanya; \"Ada apa sebenarnya?\". Wanita itu berkata; \"Putraku termasuk orang yang menyebarkan berita ini.\" 'Aisyah bertanya; \"Berita apa itu?\". Wanita itu menjawab; \"Begini dan begini\". 'Aisyah bertanya; \"Apakah Rasulullah shallallahu 'alaihi wasallam telah mendengarnya?\". Dia menjawab; \"Ya\". 'Aisyah bertanya lagi; \"Dan Abu Bakr?\". Dia menjawab; \"Ya\". Maka 'Aisyah jatuh pingsan dan tidak sadarkan diri melainkan setelah menderita demam yang sangat tinggi. Aku lalu menyelimutinya dengan pakainnya dan menutupinya hingga Nabi shallallahu 'alaihi wasallam datang dan bertanya: \"Ada apa dengannya?\". Aku jawab; \"Wahai Rasulullah, dia terserang demam.\" Beliau bersabda: \"Ini pasti karena berita bohong yang engkau ceritakan.\" Ummu Ruman berkata; \"Ya benar.\" Kemudian 'Aisyah duduk dan berkata; \"Demi Allah, seandainya aku bersumpah, engkau tidak akan mempercayaiku dan seandainya aku katakan tidak, maka kalian akan menuduhku, permisalanku dengan kalian seperti Ya'qub 'alaihis salam dengan anak-anaknya ketika dia berkata: \"Dan Allah sajalah yang dimohon pertolongan-Nya terhadap apa yang kamu ceritakan.\" QS Yusuf; 18. Ummu Ruman berkata; \"Lalu beliau berlalu tnpa mengucapkan sepatah katapun. Kemudian Allah menurunkan firman-Nya yang menjelaskan bukti sucinya diri 'Aisyah dari segala tuduhan. Saat itu 'Aisyah berkata; \"(Segala puji bagi Allah) dan ini karena Allah Yang Maha Terpuji dan seseorang tidak layak mendapat pujian dan tidak pula engkau.\""},"3615":{"ar":"حَدَّثَنِي يَحْيَى حَدَّثَنَا وَكِيعٌ عَنْ نَافِعِ بْنِ عُمَرَ عَنْ ابْنِ أَبِي مُلَيْكَةَ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاكَانَتْ تَقْرَأُ إِذْ تَلِقُونَهُ بِأَلْسِنَتِكُمْ وَتَقُولُ الْوَلْقُ الْكَذِبُقَالَ ابْنُ أَبِي مُلَيْكَةَ وَكَانَتْ أَعْلَمَ مِنْ غَيْرِهَا بِذَلِكَ لِأَنَّهُ نَزَلَ فِيهَا","id":"Telah menceritakan kepadaku [Yahya] telah menceritakan kepada kami [Waki'] dari [Nafi' bin Umar] dari [Ibnu Abu Mulaikah] dari ['Aisyah radliallahu 'anha] ketika ia membaca (firman Allah) \"idz talaqqaunahu bi alsinatakum\" (Ketika kalian menerima berita bohong itu dari mulut-mulut kalian\"), dia berkata; \"(talaqqau dari kata) al walqu artinya kedustaan.\" Ibnu Abu Mulaikah berkata; 'Aisyah adalah orang yang paling tahu (tentang hal itu) daripada orang lain, karena memang ayat itu turun tentang dirinya.\""},"3616":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدَةُ عَنْ هِشَامٍ عَنْ أَبِيهِ قَالَ ذَهَبْتُ أَسُبُّ حَسَّانَ عِنْدَ عَائِشَةَ فَقَالَتْلَا تَسُبَّهُ فَإِنَّهُ كَانَ يُنَافِحُ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَالَتْ عَائِشَةُ اسْتَأْذَنَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي هِجَاءِ الْمُشْرِكِينَ قَالَ كَيْفَ بِنَسَبِي قَالَ لَأَسُلَّنَّكَ مِنْهُمْ كَمَا تُسَلُّ الشَّعَرَةُ مِنْ الْعَجِينِحَدَّثَنَا مُحَمَّدُ بْنُ عُقْبَةَ حَدَّثَنَا عُثْمَانُ بْنُ فَرْقَدٍ سَمِعْتُ هِشَامًا عَنْ أَبِيهِ قَالَ سَبَبْتُ حَسَّانَ وَكَانَ مِمَّنْ كَثَّرَ عَلَيْهَا","id":"Telah menceritakan kepada kami ['Utsman bin Abu Syaibah] telah menceritakan kepada kami ['Abdah] dari [Hisyam] dari [Bapaknya] ia berkata; Aku pernah datang untuk mencela Hassan di hadapan ['Aisyah], maka dia berkata; \"Janganlah kamu mencelanya karena dia termasuk orang yang pernah melindungi Rasulullah shallallahu 'alaihi wasallam. 'Aisyah berkata; \"Dia pernah meminta izin kepada Nabi shallallahu 'alaihi wasallam untuk mencela kaum Musyrikin, beliau bertanya; \"Bagaimana dengan nasabku (keturunanku)?\". Hassan berkata; \"Aku akan mengeluarkan tuan dari mereka sebagaimana tercabutnya rambut dari adonan.\" Telah menceritakan kepada kami [Muhammad bin 'Uqbah] telah menceritakan kepada kami ['Utsman bin Farqad]; aku mendengar [Hisyam] dari [Bapaknya] ia berkata; \"Aku pernah mencela Hassan, karena ia termasuk orang yang memiliki peran besar dalam menyebarkan berita bohong.\""},"3617":{"ar":"حَدَّثَنِي بِشْرُ بْنُ خَالِدٍ أَخْبَرَنَا مُحَمَّدُ بْنُ جَعْفَرٍ عَنْ شُعْبَةَ عَنْ سُلَيْمَانَ عَنْ أَبِي الضُّحَى عَنْ مَسْرُوقٍ قَالَدَخَلْنَا عَلَى عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا وَعِنْدَهَا حَسَّانُ بْنُ ثَابِتٍ يُنْشِدُهَا شِعْرًا يُشَبِّبُ بِأَبْيَاتٍ لَهُ وَقَالَ حَصَانٌ رَزَانٌ مَا تُزَنُّ بِرِيبَةٍوَتُصْبِحُ غَرْثَى مِنْ لُحُومِ الْغَوَافِلِفَقَالَتْ لَهُ عَائِشَةُ لَكِنَّكَ لَسْتَ كَذَلِكَ قَالَ مَسْرُوقٌ فَقُلْتُ لَهَا لِمَ تَأْذَنِينَ لَهُ أَنْ يَدْخُلَ عَلَيْكِ وَقَدْ قَالَ اللَّهُ تَعَالَى{ وَالَّذِي تَوَلَّى كِبْرَهُ مِنْهُمْ لَهُ عَذَابٌ عَظِيمٌ }فَقَالَتْ وَأَيُّ عَذَابٍ أَشَدُّ مِنْ الْعَمَى قَالَتْ لَهُ إِنَّهُ كَانَ يُنَافِحُ أَوْ يُهَاجِي عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepadaku [Bisyir bin Khalid] telah mengabarkan kepada kami [Muhammad bin Ja'far] dari [Syu'bah] dari [Sulaiman] dari [Abu Adl Dluha] dari [Masruq] ia berkata; \"Aku menemui 'Aisyah sementara Hassan bin Tsabit di sampingnya tengah melantunkan bait-bait sya'ir untuk memujinya. Hassan bersya'ir; \"Yang memelihara dirinya, teguh dan tidak mudah terperdaya, Jadilah ia sasaran orang-orang yang lalai.\" ['Aisyah] berkata kepadanya; \"Tetapi kamu tidak termasuk seperti itu.\" Masruq berkata; aku bertanya kepada 'Aisyah; \"Mengapa anda mengizinkan dia menemuimu, padahal Allah telah berfirman; \"Dan orang yang berperan besar diantara mereka baginya akan mendapatkan siksa yang besar\". QS An Nur; 11. 'Aisyah berkata; \"Siksa apakah yang lebih berat dari kebutaan?.\" 'Aisyah melanjutkan; \"Sungguh dia pernah membela Rasulullah shallallahu 'alaihi wasallam untuk mencaci musuh.\""},"3618":{"ar":"حَدَّثَنَا خَالِدُ بْنُ مَخْلَدٍ حَدَّثَنَا سُلَيْمَانُ بْنُ بِلَالٍ قَالَ حَدَّثَنِي صَالِحُ بْنُ كَيْسَانَ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ عَنْ زَيْدِ بْنِ خَالِدٍ رَضِيَ اللَّهُ عَنْهُ قَالَخَرَجْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَامَ الْحُدَيْبِيَةِ فَأَصَابَنَا مَطَرٌ ذَاتَ لَيْلَةٍ فَصَلَّى لَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الصُّبْحَ ثُمَّ أَقْبَلَ عَلَيْنَا فَقَالَ أَتَدْرُونَ مَاذَا قَالَ رَبُّكُمْ قُلْنَا اللَّهُ وَرَسُولُهُ أَعْلَمُ فَقَالَ قَالَ اللَّهُ أَصْبَحَ مِنْ عِبَادِي مُؤْمِنٌ بِي وَكَافِرٌ بِي فَأَمَّا مَنْ قَالَ مُطِرْنَا بِرَحْمَةِ اللَّهِ وَبِرِزْقِ اللَّهِ وَبِفَضْلِ اللَّهِ فَهُوَ مُؤْمِنٌ بِي كَافِرٌ بِالْكَوْكَبِ وَأَمَّا مَنْ قَالَ مُطِرْنَا بِنَجْمِ كَذَا فَهُوَ مُؤْمِنٌ بِالْكَوْكَبِ كَافِرٌ بِي","id":"Telah menceritakan kepada kami [Khalid bin Makhlad] telah menceritakan kepada kami [Sulaiman bin Bilal] berkata; telah menceritakan kepadaku [Shalih bin Kaisan] dari ['Ubaidullah bin Abdullah] dari [Zaid bin Khalid radliallahu 'anhu] ia berkata; \"Kami keluar bersama Rasulullah shallallahu 'alaihi wasallam saat perang Hudaibiyyah, suatu malam hujan turun. Setelah Rasulullah shallallahu 'alaihi wasallam memimpin kami shalat Shubuh, beliau menghadapkan wajahnya kepada orang-orang seraya bersabda: \"Tahukah kalian apa yang sudah difirmankan oleh Rabb kalian?\". Para sahabat menjawab; \"Allah dan Rasul-Nya yang lebih mengetahui.\" Beliau bersabda: \"Allah berfirman: \"Di pagi ini ada hamba-hambaKu yang mukmin kepadaKu dan ada pula yang kafir kepadaKu. Orang yang berkata; \"Hujan turun karena karunia Allah dan rahmatNya, berarti dia telah beriman kepada-Ku dan kafir kepada bintang-bintang, sedangkan orang yang berkata; \"Hujan turun disebabkan bintang ini atau itu, maka dia telah beriman kepada bintang-bintang dan kafir kepadaKu.\""},"3619":{"ar":"حَدَّثَنَا هُدْبَةُ بْنُ خَالِدٍ حَدَّثَنَا هَمَّامٌ عَنْ قَتَادَةَ أَنَّ أَنَسًا رَضِيَ اللَّهُ عَنْهُ أَخْبَرَهُ قَالَاعْتَمَرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَرْبَعَ عُمَرٍ كُلَّهُنَّ فِي ذِي الْقَعْدَةِ إِلَّا الَّتِي كَانَتْ مَعَ حَجَّتِهِ عُمْرَةً مِنْ الْحُدَيْبِيَةِ فِي ذِي الْقَعْدَةِ وَعُمْرَةً مِنْ الْعَامِ الْمُقْبِلِ فِي ذِي الْقَعْدَةِ وَعُمْرَةً مِنْ الْجِعْرَانَةِ حَيْثُ قَسَمَ غَنَائِمَ حُنَيْنٍ فِي ذِي الْقَعْدَةِ وَعُمْرَةً مَعَ حَجَّتِهِ","id":"Telah menceritakan kepada kami [Hudbah bin Khalid] telah menceritakan kepada kami [Hammam] dari [Qatadah] bahwa [Anas radliallahu 'anhu] mengabarkan kepadanya, ia berkata; Rasulullah shallallahu 'alaihi wasallam melaksanakan 'umrah sebanyak empat kali, semuanya pada bulan Dzul Qa'dah kecuali 'umrah yang beliau laksanakan bersama hajji beliau, yaitu 'umrah beliau dari Hudaibiyyah pada bulan Dzul Qa'dah dan 'umrah pada tahun berikutnya pada bulan Dzul Qa'dah dan 'umrah dari Al Ji'ranah ketika beliau membagi-bagikan harta rampasan perang (ghanimah) Hunain pada bulan Dzul Qa'dah dan 'Umrah bersama hajji yang beliau.\""},"3620":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ الرَّبِيعِ حَدَّثَنَا عَلِيُّ بْنُ الْمُبَارَكِ عَنْ يَحْيَى عَنْ عَبْدِ اللَّهِ بْنِ أَبِي قَتَادَةَ أَنَّ أَبَاهُ حَدَّثَهُ قَالَانْطَلَقْنَا مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَامَ الْحُدَيْبِيَةِ فَأَحْرَمَ أَصْحَابُهُ وَلَمْ أُحْرِمْ","id":"Telah menceritakan kepada kami [Sa'id bin Ar Rabi'] telah menceritakan kepada kami ['Ali bin Al Mubarak] dari [Yahya] dari [Abdullah bin Abu Qatadah] bahwa [Bapaknya] telah menceritakan kepadanya, katanya; \"Kami berangkat bersama Nabi shallallahu 'alaihi wasallam saat perang Hudaibiyyah, lalu para shahabat berihram sementara beliau tidak.\""},"3621":{"ar":"حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى عَنْ إِسْرَائِيلَ عَنْ أَبِي إِسْحَاقَ عَنْ الْبَرَاءِ رَضِيَ اللَّهُ عَنْهُ قَالَتَعُدُّونَ أَنْتُمْ الْفَتْحَ فَتْحَ مَكَّةَ وَقَدْ كَانَ فَتْحُ مَكَّةَ فَتْحًا وَنَحْنُ نَعُدُّ الْفَتْحَ بَيْعَةَ الرِّضْوَانِ يَوْمَ الْحُدَيْبِيَةِ كُنَّا مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَرْبَعَ عَشْرَةَ مِائَةً وَالْحُدَيْبِيَةُ بِئْرٌ فَنَزَحْنَاهَا فَلَمْ نَتْرُكْ فِيهَا قَطْرَةً فَبَلَغَ ذَلِكَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَتَاهَا فَجَلَسَ عَلَى شَفِيرِهَا ثُمَّ دَعَا بِإِنَاءٍ مِنْ مَاءٍ فَتَوَضَّأَ ثُمَّ مَضْمَضَ وَدَعَا ثُمَّ صَبَّهُ فِيهَا فَتَرَكْنَاهَا غَيْرَ بَعِيدٍ ثُمَّ إِنَّهَا أَصْدَرَتْنَا مَا شِئْنَا نَحْنُ وَرِكَابَنَا","id":"Telah menceritakan kepada kami ['Ubaidullah bin Musa] dari [Isra'il] dari [Abu Ishaq], dari [Al Bara' radliallahu 'anhu] ia berkata; \"Kalian mengira penaklukan kota Makkah adalah kemenangan dan memang itu suatu kemenangan. Namun kami menganggap kemenganan itu bermula saat Bai'atur Ridlwan pada peristiwa Hudaibiyyah. Saat itu kami bersama Nabi shallallahu 'alaihi wasallam berjumlah seribu empat ratus orang. Hudaybiyah adalah sebuah sumur lalu kami mengambil airnya hingga tak bersisa setetespun. Setelah kejadian itu terdengar oleh Nabi shallallahu 'alaihi wasallam, beliau segera mendatangi sumur itu dan duduk di tepi sumur tersebut, selanjutnya beliau minta diambilkan bejana, beliau berwudlu' sambil berkumur-kumur, kemudian beliau berdo'a dan menuangkan airnya ke dalam sumur tersebut. Setelah kami mendiamkan sejenak, akhirnya kami dapat minum sesuka kami hingga puas, begitu juga dengan hewan-hewan tungangan kami.\""},"3622":{"ar":"حَدَّثَنِي فَضْلُ بْنُ يَعْقُوبَ حَدَّثَنَا الْحَسَنُ بْنُ مُحَمَّدِ بْنِ أَعْيَنَ أَبُو عَلِيٍّ الْحَرَّانِيُّ حَدَّثَنَا زُهَيْرٌ حَدَّثَنَا أَبُو إِسْحَاقَ قَالَ أَنْبَأَنَا الْبَرَاءُ بْنُ عَازِبٍ رَضِيَ اللَّهُ عَنْهُمَاأَنَّهُمْ كَانُوا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ الْحُدَيْبِيَةِ أَلْفًا وَأَرْبَعَ مِائَةٍ أَوْ أَكْثَرَ فَنَزَلُوا عَلَى بِئْرٍ فَنَزَحُوهَا فَأَتَوْا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَتَى الْبِئْرَ وَقَعَدَ عَلَى شَفِيرِهَا ثُمَّ قَالَ ائْتُونِي بِدَلْوٍ مِنْ مَائِهَا فَأُتِيَ بِهِ فَبَصَقَ فَدَعَا ثُمَّ قَالَ دَعُوهَا سَاعَةً فَأَرْوَوْا أَنْفُسَهُمْ وَرِكَابَهُمْ حَتَّى ارْتَحَلُوا","id":"Telah menceritakan kepadaku [Fadlal bin Ya'qub] telah menceritakan kepada kami [Al Hasan bin Muhammad bin A'yun Abu 'Ali Al Harrani] telah menceritakan kepada kami [Zuhair] telah menceritakan kepada kami [Abu Ishaq] ia berkata; telah memberitakan kepada kami [Al Bara' bin 'Azib radliallahu 'anhuma] bahwa mereka pernah bersama Rasulullah shallallahu 'alaihi wasallam pada peristiwa Hudaibiyyah berjumlah seribu empat ratus orang atau lebih. Kami lalu singgah dan mengambil airnya (hingga tak bersisa setetespun) \". Setelah orang-orang menemui Rasulullah shallallahu 'alaihi wasallam, beliau segera mendatangi sumur itu dan duduk di tepinya, beliau bersabda; \"Bawakan aku bejana berisi air.\" Setelah bejana diberikan kepada beliau, beliau meludahinya kemudian berdo'a. Selanjutnya beliau bersabda: \"Biarkanlah sejenak\". Setelah itu mereka dapat memuaskan diri mereka (meminumnya) begitu pula hewan-hewan tungangan mereka hingga mereka berangkat.\""},"3623":{"ar":"حَدَّثَنَا يُوسُفُ بْنُ عِيسَى حَدَّثَنَا ابْنُ فُضَيْلٍ حَدَّثَنَا حُصَيْنٌ عَنْ سَالِمٍ عَنْ جَابِرٍ رَضِيَ اللَّهُ عَنْهُ قَالَعَطِشَ النَّاسُ يَوْمَ الْحُدَيْبِيَةِ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَيْنَ يَدَيْهِ رَكْوَةٌ فَتَوَضَّأَ مِنْهَا ثُمَّ أَقْبَلَ النَّاسُ نَحْوَهُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا لَكُمْ قَالُوا يَا رَسُولَ اللَّهِ لَيْسَ عِنْدَنَا مَاءٌ نَتَوَضَّأُ بِهِ وَلَا نَشْرَبُ إِلَّا مَا فِي رَكْوَتِكَ قَالَ فَوَضَعَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَدَهُ فِي الرَّكْوَةِ فَجَعَلَ الْمَاءُ يَفُورُ مِنْ بَيْنِ أَصَابِعِهِ كَأَمْثَالِ الْعُيُونِ قَالَ فَشَرِبْنَا وَتَوَضَّأْنَا فَقُلْتُ لِجَابِرٍ كَمْ كُنْتُمْ يَوْمَئِذٍ قَالَ لَوْ كُنَّا مِائَةَ أَلْفٍ لَكَفَانَا كُنَّا خَمْسَ عَشْرَةَ مِائَةً","id":"Telah menceritakan kepada kami [Yusuf bin Isa] telah menceritakan kepada kami [Ibnu Fudlail] telah menceritakan kepada kami [Hushain] dari [Salim] dari [Jabir radliallahu 'anhu] ia berkata; \"Para shahabat mengalami kehausan pada peristiwa Hudaibiyyah, sementara Rasulullah shallallahu 'alaihi wasallam hanya memiliki kantung air terbuat dari kulit, lalu beliau wudlu' dengan air tersebut. Setelah itu Rasulullah shallallahu 'alaihi wasallam mendatangi para shahabat dan bertanya: \"Ada apa dengan kalian?.\" Mereka menajwab; \"Wahai Rasulullah, kami tidak punya air untuk berwudlu' dan juga tidak ada untuk minum kecuali air yang ada pada kantung air tuan.\" Jabir berkata; \"Maka Nabi shallallahu 'alaihi wasallam meletakkan tangan beliau pada kantung air tersebut lalu air mengalir melalui sela-sela jari beliau bagaikan mata air yang mengalir.\" Jabir melanjutkan; \"Lalu kami minum dan berwudlu'.\" Aku bertanya kepada Jabir; \"Berapa jumlah kalian saat itu?.\" Jabir menjawab; \"Seandainya jumlah kami ratusan ribu tentu air itu masih cukup. Jumlah kami saat itu seribu lima ratus orang.\""},"3624":{"ar":"حَدَّثَنَا الصَّلْتُ بْنُ مُحَمَّدٍ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ عَنْ سَعِيدٍ عَنْ قَتَادَةَ قُلْتُ لِسَعِيدِ بْنِ الْمُسَيَّبِ بَلَغَنِي أَنَّ جَابِرَ بْنَ عَبْدِ اللَّهِكَانَ يَقُولُ كَانُوا أَرْبَعَ عَشْرَةَ مِائَةً فَقَالَ لِي سَعِيدٌ حَدَّثَنِي جَابِرٌ كَانُوا خَمْسَ عَشْرَةَ مِائَةً الَّذِينَ بَايَعُوا النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ الْحُدَيْبِيَةِتَابَعَهُ أَبُو دَاوُدَ حَدَّثَنَا قُرَّةُ عَنْ قَتَادَةَ","id":"Telah menceritakan kepada kami [Ash Shalt bin Muhammad] telah menceritakan kepada kami [Yazid bin Zurai'] dari [Sa'id] dari [Qatadah]; \"Aku berkata kepada [Sa'id bin Al Musayyab]; \"Telah sampai kepadaku berita bahwa [Jabir bin Abdullah] berkata, bahwa saat itu (peristiwa Hudaibiyyah) mereka berjumlah seribu empat ratus orang.\" Lantas Sa'id berkata kepadaku; telah menceritakan kepadaku Jabir bahwa jumlah mereka seribu lima ratus orang, yaitu mereka yang berbai'at kepada Nabi shallallahu 'alaihi wasallam pada peristiwa Hudaibiyyah.\" Hadits ini juga diperkuat oleh [Abu Daud] telah menceritakan kepada kami [Qurrah] dari [Qatadah]."},"3625":{"ar":"حَدَّثَنَا عَلِيٌّ حَدَّثَنَا سُفْيَانُ قَالَ عَمْرٌو سَمِعْتُ جَابِرَ بْنَ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُمَا قَالَقَالَ لَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ الْحُدَيْبِيَةِ أَنْتُمْ خَيْرُ أَهْلِ الْأَرْضِوَكُنَّا أَلْفًا وَأَرْبَعَ مِائَةٍ وَلَوْ كُنْتُ أُبْصِرُ الْيَوْمَ لَأَرَيْتُكُمْ مَكَانَ الشَّجَرَةِ تَابَعَهُ الْأَعْمَشُ سَمِعَ سَالِمًا سَمِعَ جَابِرًا أَلْفًا وَأَرْبَعَ مِائَةٍ وَقَالَ عُبَيْدُ اللَّهِ بْنُ مُعَاذٍ حَدَّثَنَا أَبِي حَدَّثَنَا شُعْبَةُ عَنْ عَمْرِو بْنِ مُرَّةَ حَدَّثَنِي عَبْدُ اللَّهِ بْنُ أَبِي أَوْفَى رَضِيَ اللَّهُ عَنْهُمَا كَانَ أَصْحَابُ الشَّجَرَةِ أَلْفًا وَثَلَاثَ مِائَةٍ وَكَانَتْ أَسْلَمُ ثُمْنَ الْمُهَاجِرِينَ تَابَعَهُ مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا أَبُو دَاوُدَ حَدَّثَنَا شُعْبَةُ","id":"Telah menceritakan kepada kami [Ali] telah menceritakan kepada kami [Sufyan] berkata ['Amru]; aku mendengar [Jabir bin Abdullah radliallahu 'anhu] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda kepada kami pada peristiwa Hudaibiyyah: \"Kalian adalah sebaik-baiknya penduduk bumi.\" Saat itu kami berjumlah seribu empat ratus orang. Seandainya hari ini aku dapat melihat, pasti aku akan tunjukkan kepada kalian posisi pohon tersebut.\" Hadits ini juga diperkuat oleh [Al A'masy] dia mendengar [Salim] yang mendengar [Jabir] berkata; \"Jumlah kami seribu empat ratus orang.\" ['Ubaidullah bin Mu'adz] mengatakan; telah menceritakan kepada kami [ayahku] telah menceritakan kepada kami [Syu'bah] dari ['Amru bin Murrah] telah menceritakan kepadaku [Abdullah bin Abu Aufa radliallahu 'anhuma]; \"Sahabat yang pernah berbai'at di bawah pohon (bai'atur ridlwan) berjumlah seribu tiga ratus orang. Sedangkan dari suku Aslam berjumlah seperdelapan dari jumlah shahabat Muhajirin.\" Hadits ini juga diperkuat oleh [Muhammad bin Basysyar] telah menceritakan kepada kami [Abu Daud] telah menceritakan kepada kami [Syu'bah]."},"3626":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ مُوسَى أَخْبَرَنَا عِيسَى عَنْ إِسْمَاعِيلَ عَنْ قَيْسٍ أَنَّهُ سَمِعَ مِرْدَاسًا الْأَسْلَمِيَّ يَقُولُوَكَانَ مِنْ أَصْحَابِ الشَّجَرَةِ يُقْبَضُ الصَّالِحُونَ الْأَوَّلُ فَالْأَوَّلُ وَتَبْقَى حُفَالَةٌ كَحُفَالَةِ التَّمْرِ وَالشَّعِيرِ لَا يَعْبَأُ اللَّهُ بِهِمْ شَيْئًا","id":"Telah menceritakan kepada kami [Ibrahim bin Musa] telah mengabarkan kepada kami [Isa] dari [Isma'il] dari [Qais] bahwa dia mendengar [Mirdas Al Aslami] -dia adalah sahabat yang pernah ikut berbai'at di bawah pohon- ia berkata; \"Orang-orang shalih dari generasi-generasi awal (yang ikut bai'at di bawah pohon) telah meninggal dunia dan yang tersisa hanya ampas bagaikan ampas kurma dan gandum yang Allah tidak mempertimbangkan mereka sedikitpun.\""},"3627":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ مَرْوَانَ وَالْمِسْوَرِ بْنِ مَخْرَمَةَ قَالَاخَرَجَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَامَ الْحُدَيْبِيَةِ فِي بِضْعَ عَشْرَةَ مِائَةً مِنْ أَصْحَابِهِ فَلَمَّا كَانَ بِذِي الْحُلَيْفَةِ قَلَّدَ الْهَدْيَ وَأَشْعَرَ وَأَحْرَمَ مِنْهَالَا أُحْصِي كَمْ سَمِعْتُهُ مِنْ سُفْيَانَ حَتَّى سَمِعْتُهُ يَقُولُ لَا أَحْفَظُ مِنْ الزُّهْرِيِّ الْإِشْعَارَ وَالتَّقْلِيدَ فَلَا أَدْرِي يَعْنِي مَوْضِعَ الْإِشْعَارِ وَالتَّقْلِيدِ أَوْ الْحَدِيثَ كُلَّهُ","id":"Telah menceritakan kepada kami [Ali bin Abdullah] telah menceritakan kepada kami [Sufyan] dari [Az Zuhri] dari ['Urwah] dari [Marwan] dan [Al Miswar bin Makhramah] keduanya berkata; \"Pada peristiwa Hudaibiyyah, Nabi shallallahu 'alaihi wasallam berangkat dari Madinah bersama para sahabat yang berjumlah sekitar seribu orang lebih. Ketika sampai di Dzul Hulaifah, Nabi shallallahu 'alaihi wasallam mengikat dan menandai hewan qurban beliau, lalu memulai ihram dari san`a.\" Sudah tidak terhitung berapa kali aku mendengarnya dari Sufyan hingga akhirnya aku mendengar dia berkata; \"Aku tidak hafal hadits dari Az Zuhri tentang memberi tanda dan mengikat hewan qurban. Aku tidak tahu yaitu tempat menandai dan mengikat hewan qurban atau redaksi hadits keseluruhannya.\""},"3628":{"ar":"حَدَّثَنِي عَبْدُ الْأَعْلَى بْنُ حَمَّادٍ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ حَدَّثَنَا سَعِيدٌ عَنْ قَتَادَةَ أَنَّ أَنَسًا رَضِيَ اللَّهُ عَنْهُ حَدَّثَهُمْأَنَّ نَاسًا مِنْ عُكْلٍ وَعُرَيْنَةَ قَدِمُوا الْمَدِينَةَ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَتَكَلَّمُوا بِالْإِسْلَامِ فَقَالُوا يَا نَبِيَّ اللَّهِ إِنَّا كُنَّا أَهْلَ ضَرْعٍ وَلَمْ نَكُنْ أَهْلَ رِيفٍ وَاسْتَوْخَمُوا الْمَدِينَةَ فَأَمَرَ لَهُمْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِذَوْدٍ وَرَاعٍ وَأَمَرَهُمْ أَنْ يَخْرُجُوا فِيهِ فَيَشْرَبُوا مِنْ أَلْبَانِهَا وَأَبْوَالِهَا فَانْطَلَقُوا حَتَّى إِذَا كَانُوا نَاحِيَةَ الْحَرَّةِ كَفَرُوا بَعْدَ إِسْلَامِهِمْ وَقَتَلُوا رَاعِيَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَاسْتَاقُوا الذَّوْدَ فَبَلَغَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَبَعَثَ الطَّلَبَ فِي آثَارِهِمْ فَأَمَرَ بِهِمْ فَسَمَرُوا أَعْيُنَهُمْ وَقَطَعُوا أَيْدِيَهُمْ وَتُرِكُوا فِي نَاحِيَةِ الْحَرَّةِ حَتَّى مَاتُوا عَلَى حَالِهِمْقَالَ قَتَادَةُ بَلَغَنَا أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعْدَ ذَلِكَ كَانَ يَحُثُّ عَلَى الصَّدَقَةِ وَيَنْهَى عَنْ الْمُثْلَةِ وَقَالَ شُعْبَةُ وَأَبَانُ وَحَمَّادٌ عَنْ قَتَادَةَ مِنْ عُرَيْنَةَ وَقَالَ يَحْيَى بْنُ أَبِي كَثِيرٍ وَأَيُّوبُ عَنْ أَبِي قِلَابَةَ عَنْ أَنَسٍ قَدِمَ نَفَرٌ مِنْ عُكْلٍ","id":"Telah menceritakan kepadaku [Abdul A'la bin Hammad] telah menceritakan kepada kami [Yazid bin Zurai'] telah menceritakan kepada kami [Sa'id] dari [Qatadah] bahwa [Anas radliallahu 'anhu] bercerita kepada mereka, bahwa serombongan dari suku 'Ukail dan 'Urainah mengunjungi Madinah untuk bertemu Nabi shallallahu 'alaihi wasallam untuk menyatakan keIslamannya. Mereka berkata; \"Wahai Nabiyullah, sesungguhnya kami adalah orang-orang yang pandai memerah susu (beternak) dan bukan pandai bercocok tanam.\" Ternyata mereka tidak suka tinggal di Madinah karena suhunya (hingga menyebabkan sakit). Akhirnya Rasulullah shallallahu 'alaihi wasallam menunjuki mereka untuk menemui pengembala dan beberapa ekor untanya supaya dapat minum susu dan air seni unta-unta tersebut. Sesampainya mereka di distrik Harrat, mereka kembali kufur setelah keIslamannya, membunuh pengembala Nabi shallallahu 'alaihi wasallam dan merampas unta-unta beliau. Ketika peristiwa ini sampai kepada Nabi shallallahu 'alaihi wasallam, beliau langsung mengutus seseorang untuk mengejar mereka melalui jejak perjalanan mereka. (Setelah berhasil ditangkap), beliau memerintahkan agar mencungkil mata mereka dengan besi panas, memotong tangan-tangan mereka dan membiarkan mereka di bawah sengatan matahari sampai mati dalam kondisi seperti itu.\" Qatadah berkata; telah sampai kepada kami, bahwa setelah peristiwa itu, Nabi shallallahu 'alaihi wasallam menganjurkan untuk bersedekah (membagikan harta-harta mereka) dan melarang memutilasi.\" [Syu'bah], [Aban] dan [Hammad] mengatakan dari [Qatadah]; \"...rombongan dari 'Urainah\". Sedangkan [Yahya bin Abu Katsir] dan [Ayyub] mengatakan dari [Abu Qilabah] dari [Anas]; \"..datang rombongan dari suku 'Ukul.\""},"3629":{"ar":"حَدَّثَنِي مُحَمَّدُ بْنُ عَبْدِ الرَّحِيمِ حَدَّثَنَا حَفْصُ بْنُ عُمَرَ أَبُو عُمَرَ الْحَوْضِيُّ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ حَدَّثَنَا أَيُّوبُ وَالْحَجَّاجُ الصَّوَّافُ قَالَ حَدَّثَنِي أَبُو رَجَاءٍ مَوْ��َى أَبِي قِلَابَةَوَكَانَ مَعَهُ بِالشَّأْمِ أَنَّ عُمَرَ بْنَ عَبْدِ الْعَزِيزِ اسْتَشَارَ النَّاسَ يَوْمًا قَالَ مَا تَقُولُونَ فِي هَذِهِ الْقَسَامَةِ فَقَالُوا حَقٌّ قَضَى بِهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَضَتْ بِهَا الْخُلَفَاءُ قَبْلَكَ قَالَ وَأَبُو قِلَابَةَ خَلْفَ سَرِيرِهِ فَقَالَ عَنْبَسَةُ بْنُ سَعِيدٍ فَأَيْنَ حَدِيثُ أَنَسٍ فِي الْعُرَنِيِّينَقَالَ أَبُو قِلَابَةَ إِيَّايَ حَدَّثَهُ أَنَسُ بْنُ مَالِكٍ قَالَ عَبْدُ الْعَزِيزِ بْنُ صُهَيْبٍ عَنْ أَنَسٍ مِنْ عُرَيْنَةَ وَقَالَ أَبُو قِلَابَةَ عَنْ أَنَسٍ مِنْ عُكْلٍ ذَكَرَ الْقِصَّةَ","id":"Telah menceritakan kepadaku [Muhammad bin Abdurrahim] telah menceritakan kepada kami [Hafsh bin Umar Abu 'Umar Al Hawdli] telah menceritakan kepada kami [Hammad bin Zaid] telah menceritakan kepada kami [Ayyub] dan [Al Hajjaj Ash Shawwaf] ia berkata; telah menceritakan kepadaku [Abu Raja'] mantan budak Abu Qilabah -dia pernah bersamanya di Syam- pada suatu hari Umar bin Abdul 'Aziz bermusyawarah dengan orang-orang. Katanya; \"Apa pendapat kalian tentang pembagian ini?\". Mereka menjawab; \"Benar. Sebagaimana Rasulullah shallallahu 'alaihi wasallam telah menerapkannya begitu juga para khalifah sebelum anda\". Abu Raja' berkata; Saat itu Abu Qilabah berada di tempat tidurnya, lalu 'Anbasah bin Sa'id berkata; \"Mana hadits Anas tentang suku 'Urainah\". Maka [Abu Qilabah] berkata dari [Anas bin Malik], berkata [Abdul Aziz bin Shubaih] dari [Anas];...dari suku Uraniyah. Dan berkata Abu Qilabah dari Anas;.....dari suku 'Ukul.\" Lalu dia menceritakan kisah tersebut.\""},"3630":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا حَاتِمٌ عَنْ يَزِيدَ بْنِ أَبِي عُبَيْدٍ قَالَ سَمِعْتُ سَلَمَةَ بْنَ الْأَكْوَعِ يَقُولُخَرَجْتُ قَبْلَ أَنْ يُؤَذَّنَ بِالْأُولَى وَكَانَتْ لِقَاحُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَرْعَى بِذِي قَرَدَ قَالَ فَلَقِيَنِي غُلَامٌ لِعَبْدِ الرَّحْمَنِ بْنِ عَوْفٍ فَقَالَ أُخِذَتْ لِقَاحُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قُلْتُ مَنْ أَخَذَهَا قَالَ غَطَفَانُ قَالَ فَصَرَخْتُ ثَلَاثَ صَرَخَاتٍ يَا صَبَاحَاهْ قَالَ فَأَسْمَعْتُ مَا بَيْنَ لَابَتَيْ الْمَدِينَةِ ثُمَّ انْدَفَعْتُ عَلَى وَجْهِي حَتَّى أَدْرَكْتُهُمْ وَقَدْ أَخَذُوا يَسْتَقُونَ مِنْ الْمَاءِ فَجَعَلْتُ أَرْمِيهِمْ بِنَبْلِي وَكُنْتُ رَامِيًا وَأَقُولُ أَنَا ابْنُ الْأَكْوَعْوَالْيَوْمُ يَوْمُ الرُّضَّعْوَأَرْتَجِزُ حَتَّى اسْتَنْقَذْتُ اللِّقَاحَ مِنْهُمْ وَاسْتَلَبْتُ مِنْهُمْ ثَلَاثِينَ بُرْدَةً قَالَ وَجَاءَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالنَّاسُ فَقُلْتُ يَا نَبِيَّ اللَّهِ قَدْ حَمَيْتُ الْقَوْمَ الْمَاءَ وَهُمْ عِطَاشٌ فَابْعَثْ إِلَيْهِمْ السَّاعَةَ فَقَالَ يَا ابْنَ الْأَكْوَعِ مَلَكْتَ فَأَسْجِحْ قَالَ ثُمَّ رَجَعْنَا وَيُرْدِفُنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى نَاقَتِهِ حَتَّى دَخَلْنَا الْمَدِينَةَ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Hatim bin Yazid] dari [Yazid bin Abu 'Ubaid] ia berkata; aku mendengar [Salamah bin Al Akwa'] berkata; \"Aku keluar sebelum adzan pertama shalat Shubuh (dikumandangkan). Saat itu unta betina bunting milik Rasulullah shallallahu 'alaihi wasallam sedang digembalakan di Dzi Qarad.\" Dia melanjutkan; \"Lalu aku berjumpa dengan budak Abdurrahman bin 'Auf, dia berkata; \"Unta Rasulullah shallallahu 'alaihi wasallam telah dicuri orang.\" Aku bertanya; \"Siapa yang mencurinya?\". Dia berkata: \"(Suku) Ghathafan\". Maka aku berteriak sebanyak tiga kali dengan teriakan yang dapat diperdengarkan diantara dua bukit Madinah. Maka aku hadapkan wajahku (tidak menoleh ke kanan dan kiri) hingga aku dapat menemukan mereka hendak memberikan minum unta itu. Aku meluncurkan anak panah kepada mereka. Aku adalah orang yang ahli memanah. Aku katakan; \"Akulah putra Al Akwa'. Hari ini adalah hari kebinasaan orang-orang yang hina\" Dan aku terus bersya'ir hingga aku merebut kembali unta tersebut dari mereka (sebelum mereka meminum air susunya). Aku juga berhasil merampas sebanyak tiga puluh burdah (kain selimut).\" Dia melanjutkan; \"Kemudian Nabi shallallahu 'alaihi wasallam beserta para shahabat datang. Aku katakan; \"Wahai Nabiyullah, aku dapat mendahului kaum itu dari mata air sehingga mereka kehausan. Untuk itu, utuslah aku sejenak (untuk memberi pelajaran kepada mereka).\" Maka beliau bersabda: \"Wahai Ibnu Al Akwa', tahanlah emosimu dan bersikap lembutlah.\" Dia berkata; \"Kemudian kami kembali dan aku dibonceng di atas unta beliau hingga kami memasuki kota Madinah.\""},"3631":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ عَنْ مَالِكٍ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ بُشَيْرِ بْنِ يَسَارٍ أَنَّ سُوَيْدَ بْنَ النُّعْمَانِ أَخْبَرَهُأَنَّهُ خَرَجَ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَامَ خَيْبَرَ حَتَّى إِذَا كُنَّا بِالصَّهْبَاءِ وَهِيَ مِنْ أَدْنَى خَيْبَرَ صَلَّى الْعَصْرَ ثُمَّ دَعَا بِالْأَزْوَادِ فَلَمْ يُؤْتَ إِلَّا بِالسَّوِيقِ فَأَمَرَ بِهِ فَثُرِّيَ فَأَكَلَ وَأَكَلْنَا ثُمَّ قَامَ إِلَى الْمَغْرِبِ فَمَضْمَضَ وَمَضْمَضْنَا ثُمَّ صَلَّى وَلَمْ يَتَوَضَّأْ","id":"Telah menceritakan kepada kami [Abdullah bin Maslamah] dari [Malik] dari [Yahya bin Sa'id] dari [Busyair bin Yasar] bahwa [Suwaid bin An Nu'man] mengabarkannya bahwa dia pernah keluar bersama Rasulullah shallallahu 'alaihi wasallam ketika perang Khaibar, ketika mereka sampai di Shahba' yaitu pinggiran Khaibar, beliau mengerjakan shalat 'Ashar. Setelah itu beliau minta perbekalan, namun beliau tidak diberi kecuali makanan yang terbuat dari tepung. Maka beliau memintanya lalu memakannya dan kami pun ikut memakannya. Setelah itu beliau berdiri untuk melaksanakan shalat Maghrib, beliau berkumur-kumur, dan kami juga berkumur-kumur, lalu mengerjakan shalat tanpa berwudlu' lagi.\""},"3632":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ حَدَّثَنَا حَاتِمُ بْنُ إِسْمَاعِيلَ عَنْ يَزِيدَ بْنِ أَبِي عُبَيْدٍ عَنْ سَلَمَةَ بْنِ الْأَكْوَعِ رَضِيَ اللَّهُ عَنْهُ قَالَخَرَجْنَا مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى خَيْبَرَ فَسِرْنَا لَيْلًا فَقَالَ رَجُلٌ مِنْ الْقَوْمِ لِعَامِرٍ يَا عَامِرُ أَلَا تُسْمِعُنَا مِنْ هُنَيْهَاتِكَ وَكَانَ عَامِرٌ رَجُلًا شَاعِرًا فَنَزَلَ يَحْدُو بِالْقَوْمِ يَقُولُ اللَّهُمَّ لَوْلَا أَنْتَ مَا اهْتَدَيْنَاوَلَا تَصَدَّقْنَا وَلَا صَلَّيْنَافَاغْفِرْ فِدَاءً لَكَ مَا أَبْقَيْنَاوَثَبِّتْ الْأَقْدَامَ إِنْ لَاقَيْنَاوَأَلْقِيَنْ سَكِينَةً عَلَيْنَاإِنَّا إِذَا صِيحَ بِنَا أَبَيْنَاوَبِالصِّيَاحِ عَوَّلُوا عَلَيْنَافَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ هَذَا السَّائِقُ قَالُوا عَامِرُ بْنُ الْأَكْوَعِ قَالَ يَرْحَمُهُ اللَّهُ قَالَ رَجُلٌ مِنْ الْقَوْمِ وَجَبَتْ يَا نَبِيَّ اللَّهِ لَوْلَا أَمْتَعْتَنَا بِهِ فَأَتَيْنَا خَيْبَرَ فَحَاصَرْنَاهُمْ حَتَّى أَصَابَتْنَا مَخْمَصَةٌ شَدِيدَةٌ ثُمَّ إِنَّ اللَّهَ تَعَالَى فَتَحَهَا عَلَيْهِمْ فَلَمَّا أَمْسَى النَّاسُ مَسَاءَ الْيَوْمِ الَّذِي فُتِحَتْ عَلَيْهِمْ أَوْقَدُوا نِيرَانًا كَثِيرَةً فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا هَذِهِ النِّيرَانُ عَلَى أَيِّ شَيْءٍ تُوقِدُونَ قَالُوا عَلَى لَحْمٍ قَالَ عَلَى أَيِّ لَحْمٍ قَالُوا لَحْمِ حُمُرِ الْإِنْسِيَّةِ قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَهْرِيقُوهَا وَاكْسِرُوهَا فَقَالَ رَجُلٌ يَا رَسُولَ اللَّهِ أَوْ نُهَرِيقُهَا وَنَغْسِلُهَا قَالَ أَوْ ذَاكَ فَلَمَّا تَصَافَّ الْقَوْمُ كَانَ سَيْفُ عَامِرٍ قَصِيرًا فَتَنَاوَلَ بِهِ سَاقَ يَهُودِيٍّ لِيَضْرِبَهُ وَيَرْجِعُ ذُبَابُ سَيْفِهِ فَأَصَابَ عَيْنَ رُكْبَةِ عَامِرٍ فَمَاتَ مِنْهُ قَالَ فَلَمَّا قَفَلُوا قَالَ سَلَمَةُ رَآنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ آخِذٌ بِيَدِي قَالَ مَا لَكَ قُلْتُ لَهُ فَدَاكَ أَبِي وَأُمِّي زَعَمُوا أَنَّ عَامِرًا حَبِطَ عَمَلُهُ قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَذَبَ مَنْ قَالَهُ إِنَّ لَهُ لَأَجْرَيْنِ وَجَمَعَ بَيْنَ إِصْبَعَيْهِ إِنَّهُ لَجَاهِدٌ مُجَاهِدٌ قَلَّ عَرَبِيٌّ مَشَى بِهَا مِثْلَهُحَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا حَاتِمٌ قَالَ نَشَأَ بِهَا","id":"Telah menceritakan kepada kami [Abdullah bin Maslamah] telah menceritakan kepada kami [Hatim bin Isma'il] dari [Yazid bin Abu 'Ubaid] dari [Salamah bin Al Akwa' radliallahu 'anhu] ia berkata; \"Kami mengadakan perjalanan malam bersama Nabi shallallahu 'alaihi wasallam menuju Khaibar, lalu seorang laki-laki dari rombongan berkata kepada 'Amir; \"Wahai 'Amir, apakah tidak sebaiknya engkau perdengarkan kepada kami bait-bait sya'irmu?\" -'Amir adalah seorang ahli penyair- Maka dia mulai melantunkan sya'ir kepada rombongan itu. Katanya; \"Ya Alah, kalau nukan karena Engkau, tentu kami tidak akan mendapat petunjuk. Kami tidak akan bershadaqah dan juga tidak akan shalat. Berilah ampunan sebagai tebusan untuk-Mu atas apa yang telah kami lalaikan. Teguhkan kaki-kaki kami bila bertemu musuh. Berikanlah ketenangan atas kami. Sesungguhnya jika diserukan kepada kami, niscaya kami enggan mengikutinya Namun dengan seruan itu mereka datang kepada kami.\" Rasulullah shallallahu 'alaihi wasallam bertanya: \"Siapakah yang sedang bersenandung itu?. Mereka menjawab; \"'Amir bin Al Akwa'.\" Beliau bersabda: \"Semoga Alah merahmatinya\". Tiba-tiba seorang laki-laki berkata; \"Sudah semestinya wahai Nabiyullah. (Bagaimana jadinya) sekiranya engkau tidak menyenangkan kami dengannya.\" Lalu kami mengepung Khaibar, hingga kami ditimpa rasa lapar yang sangat. Kemudian Allah Ta'ala menaklukannya. Di sore harinya, yaitu di hari (pertama) Khaibar ditaklukkan, orang-orang menyalakan api, melihat itu Nabi shallallahu 'alaihi wasallam bertanya: \"Apakah api-apai itu. Untuk apa dinyalakan?\". Mereka menjawab; \"Untuk memasak daging.\" Beliau bertanya: \"Daging apa?\". Mereka menjawab; \"Daging keledai jinak.\" Maka Nabi shallallahu 'alaihi wasallam bersabda: \"Tumpahkan dan pecahkanlah (periuk-periuknya).\" Seorang laki-laki bertanya; \"Wahai Rasulullah, tidakkah kita menumpahkannya lalu mencucinya?.\" Beliau bersabda: \"Atau seperti itu\". Ketika rombongan pasukan sudah saling berhadapan, saat itu 'Amir membawa pedangnya yang pendek, lalu dia mengayunkannya untuk menebas betis kaki seorang Yahudi. Namun pedangnya berbalik mengenai kakinya dan tepat melukai mata kaki 'Amir hingga menyebabkan dia gugur.\" Salamah berkata; \"Ketika mereka kembali, Salamah berkata; \"Rasulullah shallallahu 'alaihi wasallam melihatku lalu memegang tanganku seraya berkata; \"Ada apa denganmu?.\" Aku berkata kepada beliau; \"Demi bapak ibuku sebagai tebusan tuan. Orang-orang menganggap bahwa 'Amir telah melakukan amalan yang sia-sia.\" Nabi shallallahu 'alaihi wasallam bertanya: \"Mereka berdusta. Siapa yang mengatakannya? Sesungguhnya dia mendapatkan dua pahala.\" -Beliau mengumpulkan dua jarinya- \"Sungguh dia seorang mujahid yang telah berjuang dengan gigih. Sedikit sekali orang Arab yang dapat melakukan seperti yang dia lakukan.\" Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Hatim] ia berkata; (Dalam riwayat lain menggunakan kalimat) nasya'a bihaa, artinya mencontohkannya."},"3633":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ حُمَيْدٍ الطَّوِيلِ عَنْ أَنَسٍ رَضِيَ اللَّهُ عَنْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَتَى خَيْبَرَ لَيْلًا وَكَانَ إِذَا أَتَى قَوْمًا بِلَيْلٍ لَمْ يُغِرْ بِهِمْ حَتَّى يُصْبِحَ فَلَمَّا أَصْبَحَ خَرَجَتْ الْيَهُودُ بِمَسَاحِيهِمْ وَمَكَاتِلِهِمْ فَلَمَّا رَأَوْهُ قَالُوا مُحَمَّدٌ وَاللَّهِ مُحَمَّدٌ وَالْخَمِيسُ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَرِبَتْ خَيْبَرُ إِنَّا إِذَا نَزَلْنَا بِسَاحَةِ قَوْمٍ{ فَسَاءَ صَبَاحُ الْمُنْذَرِينَ }","id":"Telah menceritakan kepada kami [Abdullah bin Yusuf] telah mengabarkan kepada kami [Malik] dari [Humaid Ath Thawil] dari [Anas radliallahu 'anhu] bahwa Rasulullah shallallahu 'alaihi wasallam mendatangi Khaibar pada malam hari. Apabila beliau menyerang suatu kaum di malam hari, beliau tidak menyerangnya hingga datang waktu pagi. Ketika pagi telah tiba, orang-orang Yahudi pun keluar rumah dengan membawa sekop-sekop dan keranjang mereka. Tatkala mereka melihat beliau, mereka berkata; \"Muhammad Demi Allah, Muhammad dan pasukannya.\" Maka Nabi shallallahu 'alaihi wasallam bersabda: \"Hancurlah Khaibar. Sesungguhnya kami apabila mendatangi perkampungan suatu kaum, (\"maka amat buruklah pagi hari yang dialami orang-orang yang diperingatkan tersebut\"). QS Ash Shaffat; 177."},"3634":{"ar":"أَخْبَرَنَا صَدَقَةُ بْنُ الْفَضْلِ أَخْبَرَنَا ابْنُ عُيَيْنَةَ حَدَّثَنَا أَيُّوبُ عَنْ مُحَمَّدِ بْنِ سِيرِينَ عَنْ أَنَسِ بْنِ مَالِكٍ رَضِيَ اللَّهُ عَنْهُ قَالَصَبَّحْنَا خَيْبَرَ بُكْرَةً فَخَرَجَ أَهْلُهَا بِالْمَسَاحِي فَلَمَّا بَصُرُوا بِالنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالُوا مُحَمَّدٌ وَاللَّهِ مُحَمَّدٌ وَالْخَمِيسُ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اللَّهُ أَكْبَرُ خَرِبَتْ خَيْبَرُ إِنَّا إِذَا نَزَلْنَا بِسَاحَةِ قَوْمٍ{ فَسَاءَ صَبَاحُ الْمُنْذَرِينَ }فَأَصَبْنَا مِنْ لُحُومِ الْحُمُرِ فَنَادَى مُنَادِي النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ اللَّهَ وَرَسُولَهُ يَنْهَيَانِكُمْ عَنْ لُحُومِ الْحُمُرِ فَإِنَّهَا رِجْسٌ","id":"Telah mengabarkan kepada kami [Shadaqah bin Al Fadlal] telah mengabarkan kepada kami [Ibnu 'Uyainah] telah menceritakan kepada kami [Ayyub] dari [Muhammad bin Sirin] dari [Anas bin Malik radliallahu 'anhu] ia berkata; \"Kami hendak menyerang Khaibar hingga awal pagi. Ketika penduduk Khaibar keluar dengan membawa keranjang-keranjang mereka, dan mereka melihat Nabi shallallahu 'alaihi wasallam, mereka berkata; \"Muhammad, demi Allah Muhammad dan pasukannya.\" Maka Nabi shallallahu 'alaihi wasallam bersabda: \"Allahu Akbar. Hancurlah Khaibar. Sesungguhnya kami apabila mendatangi perkampungan suatu kaum, (\"maka amat buruklah pagi hari yang dialami orang-orang yang diperingatkan tersebut\"). QS Ash Shaffat; 177. Selanjutnya kami berhasil mendapatkan daging-daging keledai, tiba-tiba seorang penyeru Nabi shallallahu 'alaihi wasallam berseru; \"Sesungguhnya Allah dan Rasul-Nya melarang kalian memakan daging keledai, karena dia najis.\""},"3635":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عَبْدِ الْوَهَّابِ حَدَّثَنَا عَبْدُ الْوَهَّابِ حَدَّثَنَا أَيُّوبُ عَنْ مُحَمَّدٍ عَنْ أَنَسِ بْنِ مَالِكٍ رَضِيَ اللَّهُ عَنْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جَاءَهُ جَاءٍ فَقَالَ أُكِلَتْ الْحُمُرُ فَسَكَتَ ثُمَّ أَتَاهُ الثَّانِيَةَ فَقَالَ أُكِلَتْ الْحُمُرُ فَسَكَتَ ثُمَّ أَتَاهُ الثَّالِثَةَ فَقَالَ أُفْنِيَتْ الْحُمُرُ فَأَمَرَ مُنَادِيًا فَنَادَى فِي النَّاسِ إِنَّ اللَّهَ وَرَسُولَهُ يَنْهَيَانِكُمْ عَنْ لُحُومِ الْحُمُرِ الْأَهْلِيَّةِ فَأُكْفِئَتْ الْقُدُورُ وَإِنَّهَا لَتَفُورُ بِاللَّحْمِ","id":"Telah menceritakan kepada kami [Abdullah bin 'Abdul Wahhab] telah menceritakan kepada kami [Abdul Wahhab] telah menceritakan kepada kami [Ayyub] dari [Muhammad] dari [Anas bin Malik radliallahu 'anhu] bahwa Rasulullah shallallahu 'alaihi wasallam didatangi seseorang, seraya bertanya; \"Apakah daging keledai boleh dimakan?\". Beliau diam. Kemudian orang itu datang lagi untuk kedua kalianya dan bertanya; \"Apakah daging keledai boleh dimakan?\". Beliau tetap diam. Kemudian orang itu datang lagi untuk ketiga kalianya dan bertanya; \"Apakah daging keledai dimusnahkan saja?\". Maka beliau memerintahkan seorang penyeru, lalu penyeru itu berseru di hadapan orang banyak; \"Sesungguhnya Allah dan Rasul-Nya melarang kalian memakan daging keledai jinak.\" Mendengar itu periuk-periuk ditumpahkan, padahal isinya penuh dengan daging keledai."},"3636":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ ثَابِتٍ عَنْ أَنَسٍ رَضِيَ اللَّهُ عَنْهُ قَالَصَلَّى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الصُّبْحَ قَرِيبًا مِنْ خَيْبَرَ بِغَلَسٍ ثُمَّ قَالَ اللَّهُ أَكْبَرُ خَرِبَتْ خَيْبَرُ إِنَّا إِذَا نَزَلْنَا بِسَاحَةِ قَوْمٍ{ فَسَاءَ صَبَاحُ الْمُنْذَرِينَ }فَخَرَجُوا يَسْعَوْنَ فِي السِّكَكِ فَقَتَلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمُقَاتِلَةَ وَسَبَى الذُّرِّيَّةَ وَكَانَ فِي السَّبْيِ صَفِيَّةُ فَصَارَتْ إِلَى دَحْيَةَ الْكَلْبِيِّ ثُمَّ صَارَتْ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَجَعَلَ عِتْقَهَا صَدَاقَهَا فَقَالَ عَبْدُ الْعَزِيزِ بْنُ صُهَيْبٍ لِثَابِتٍ يَا أَبَا مُحَمَّدٍ آنْتَ قُلْتَ لِأَنَسٍ مَا أَصْدَقَهَا فَحَرَّكَ ثَابِتٌ رَأْسَهُ تَصْدِيقًا لَهُ","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] telah menceritakan kepada kami [Hammad bin Zaid] dari [Tsabit] dari [Anas bin Malik radliallahu 'anhu] berkata; bahwa Nabi shallallahu 'alaihi wasallam pernah melaksanakan shalat Shubuh dekat Khaibar ketika hari masih gelap, kemudian bersabda: \"Allahu Akbar, hancurlah Khoibar. Sesungguhnya kami apabila mendatangi perkampungan suatu kaum, (maka amat buruklah pagi hari yang dialami orang-orang yang diperingatkan tersebut).\" QS Ash Shaffat; 177. Ketika penduduk Khaibar keluar dan berjalan dalam kegelapan. Maka Nabi shallallahu 'alaihi wasallam membunuh para pasukan mereka dan menawan anak-anak mereka. Dan diantara tawanan tersebut terdapat seorang wanita bernama Shafiyah, semula ia tawanan milik Dihyah Al Kalbi lalu diberikan kepada Nabi shallallahu 'alaihi wasallam, kemudian beliau menikahinya dan menjadikan pembebasannya sebagai mahar pernikahannya.\" Abdul 'Aziz berkata kepada Tsabit: \"Wahai Abu Muhammad, apakah kamu pernah bertanya kepada Anas, \"Apa yang beliau jadikan maharnya?\". Maka Tsabit menganggukkan kepalanya tanda membenarkan."},"3637":{"ar":"حَدَّثَنَا آدَمُ حَدَّثَنَا شُعْبَةُ عَنْ عَبْدِ الْعَزِيزِ بْنِ صُهَيْبٍ قَالَ سَمِعْتُ أَنَسَ بْنَ مَالِكٍ رَضِيَ اللَّهُ عَنْهُ يَقُولُسَبَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَفِيَّةَ فَأَعْتَقَهَا وَتَزَوَّجَهَا فَقَالَ ثَابِتٌ لِأَنَسٍ مَا أَصْدَقَهَا قَالَ أَصْدَقَهَا نَفْسَهَا فَأَعْتَقَهَا","id":"Telah menceritakan kepada kami [Adam] telah menceritakan kepada kami [Syu'bah] dari [Abdul 'Aziz bin Shuhaib] ia berkata; aku mendengar [Anas bin Malik radliallahu 'anhu] berkata; \"Nabi shallallahu 'alaihi wasallam menawan Shafiyyah lalu membebaskannya kemudian menikahinya.\" Tsabit bertanya kepada Anas; \"Apa maharnya?\". Anas menjawab; \"Maharnya adalah dirinya, lalu beliau memerdekakannya\"."},"3638":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا يَعْقُوبُ عَنْ أَبِي حَازِمٍ عَنْ سَهْلِ بْنِ سَعْدٍ السَّاعِدِيِّ رَضِيَ اللَّهُ عَنْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْتَقَى هُوَ وَالْمُشْرِكُونَ فَاقْتَتَلُوا فَلَمَّا مَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى عَسْكَرِهِ وَمَالَ الْآخَرُونَ إِلَى عَسْكَرِهِمْ وَفِي أَصْحَابِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَجُلٌ لَا يَدَعُ لَهُمْ شَاذَّةً وَلَا فَاذَّةً إِلَّا اتَّبَعَهَا يَضْرِبُهَا بِسَيْفِهِ فَقِيلَ مَا أَجْزَأَ مِنَّا الْيَوْمَ أَحَدٌ كَمَا أَجْزَأَ فُلَانٌ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَا إِنَّهُ مِنْ أَهْلِ النَّارِ فَقَالَ رَجُلٌ مِنْ الْقَوْمِ أَنَا صَاحِبُهُ قَالَ فَخَرَجَ مَعَهُ كُلَّمَا وَقَفَ وَقَفَ مَعَهُ وَإِذَا أَسْرَعَ أَسْرَعَ مَعَهُ قَالَ فَجُرِحَ الرَّجُلُ جُرْحًا شَدِيدًا فَاسْتَعْجَلَ الْمَوْتَ فَوَضَعَ سَيْفَهُ بِالْأَرْضِ وَذُبَابَهُ بَيْنَ ثَدْيَيْهِ ثُمَّ تَحَامَلَ عَلَى سَيْفِهِ فَقَتَلَ نَفْسَهُ فَخَرَجَ الرَّجُلُ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَشْهَدُ أَنَّكَ رَسُولُ اللَّهِ قَالَ وَمَا ذَاكَ قَالَ الرَّجُلُ الَّذِي ذَكَرْتَ آنِفًا أَنَّهُ مِنْ أَهْلِ النَّارِ فَأَعْظَمَ النَّاسُ ذَلِكَ فَقُلْتُ أَنَا لَكُمْ بِهِ فَخَرَجْتُ فِي طَلَبِهِ ثُمَّ جُرِحَ جُرْحًا شَدِيدًا فَاسْتَعْجَلَ الْمَوْتَ فَوَضَعَ نَصْلَ سَيْفِهِ فِي الْأَرْضِ وَذُبَابَهُ بَيْنَ ثَدْيَيْهِ ثُمَّ تَحَامَلَ عَلَيْهِ فَقَتَلَ نَفْسَهُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عِنْدَ ذَلِكَ إِنَّ الرَّجُلَ لَيَعْمَلُ عَمَلَ أَهْلِ الْجَنَّةِ فِيمَا يَبْدُو لِلنَّاسِ وَهُوَ مِنْ أَهْلِ النَّارِ وَإِنَّ الرَّجُلَ لَيَعْمَلُ عَمَلَ أَهْلِ النَّارِ فِيمَا يَبْدُو لِلنَّاسِ وَهُوَ مِنْ أَهْلِ الْجَنَّةِ","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Ya'qub] dari [Abu Hazim] dari [Sahal bin Sa'ad As Sa'idi radliallahu 'anhu] bahwa Rasulullah shallallahu 'alaihi wasallam berhadapan dengan Kaum Musyrikin, kemudian keduanya saling menyerang. Ketika Rasulullah shallallahu 'alaihi wasallam bergabung dengan bala tentara dan musuhnya pun bergabung kepada bala tentara mereka. Dan diantara shahabat Rasulullah shallallahu 'alaihi wasallam ada seseorang yang tidak menyisakan musuh pun kecuali terus ia mengejarnya untuk dipenggal dengan pedangnya. Setelah itu seseorang berkata; \"Hari ini tidak ada seorangpun dari kita yang mendapat ganjaran pahala sebagaimana yang didapat si fulan orang tadi).\" Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya orang itu termasuk dari penduduk neraka.\" Seorang laki-laki dari kaumnya berkata; \"Aku adalah sahabatnya.\" Sahal berkata; \"Kemudian dia berangkat bersama orang itu, apabila dia berhenti orang itu pun berhenti dan bilamana dia bergegas maka orang itupun bergegas bersamanya. Sahal melanjutkan; \"Kemudian laki-laki itu (orang yang berperang tadi) ditemukan dalam keadaan terluka sangat parah hingga mengharapkan segera mati. Lalu ia itu meletakkan pedangnya di tanah dan ujung pedangnya diletakkah diantara dua dadanya lalu dia membunuh dirinya sendiri. Maka orang yang bersamanya tadi pergi menemui Rasulullah shallallahu 'alaihi wasallam sambil berkata; \"Aku bersaksi bahwa tuan adalah benar-benar utusan Allah\". Beliau bertanya: \"Kenapa kamu berkata seperti itu?\". Orang itu menjawab; \"Orang yang tuan sebutkan tadi benar-benar penghuni neraka.\" Mendengar perkataanya, para sahabat merasa heran. Aku lalu berkata; \"Aku menjadi saksinya. Aku telah keluar bersamanya dimana aku mencarinya kemudian aku dapatkan dia dalam keadaan luka parah, hingga ia berkeinginan supaya cepat mati, lalu dia meletakkan pedangnya di tanah dan ujung pedangnya diletakkah diantara dua dadanya setelah itu dia membunuh dirinya sendiri. Pada kesempatan itu juga Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya ada seseorang yang mengamalkan amalan penduduk surga berdasarkan yang nampak oleh manusia padahal dia adalah dari golongan penduduk neraka. Dan ada seseorang yang mengamalkan amalan penduduk neraka berdasarkan yang nampak oleh manusia padahal dia sebenarnya dari golongan penduduk surga.\""},"3639":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي سَعِيدُ بْنُ الْمُسَيَّبِ أَنَّ أَبَا هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَشَهِدْنَا خَيْبَرَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِرَجُلٍ مِمَّنْ مَعَهُ يَدَّعِي الْإِسْلَامَ هَذَا مِنْ أَهْلِ النَّارِ فَلَمَّا حَضَرَ الْقِتَالُ قَاتَلَ الرَّجُلُ أَشَدَّ الْقِتَالِ حَتَّى كَثُرَتْ بِهِ الْجِرَاحَةُ فَكَادَ بَعْضُ النَّاسِ يَرْتَابُ فَوَجَدَ الرَّجُلُ أَلَمَ الْجِرَاحَةِ فَأَهْوَى بِيَدِهِ إِلَى كِنَانَتِهِ فَاسْتَخْرَجَ مِنْهَا أَسْهُمًا فَنَحَرَ بِهَا نَفْسَهُ فَاشْتَدَّ رِجَالٌ مِنْ الْمُسْلِمِينَ فَقَالُوا يَا رَسُولَ اللَّهِ صَدَّقَ اللَّهُ حَدِيثَكَ انْتَحَرَ فُلَانٌ فَقَتَلَ نَفْسَهُ فَقَالَ قُمْ يَا فُلَانُ فَأَذِّنْ أَنَّهُ لَا يَدْخُلُ الْجَنَّةَ إِلَّا مُؤْمِنٌ إِنَّ اللَّهَ يُؤَيِّدُ الدِّينَ بِالرَّجُلِ الْفَاجِرِتَابَعَهُ مَعْمَرٌ عَنْ الزُّهْرِيِّ وَقَالَ شَبِيبٌ عَنْ يُونُسَ عَنْ ابْنِ شِهَابٍ أَخْبَرَنِي ابْنُ الْمُسَيَّبِ وَعَبْدُ الرَّحْمَنِ بْنُ عَبْدِ اللَّهِ بْنِ كَعْبٍ أَنَّ أَبَا هُرَيْرَةَ قَالَ شَهِدْنَا مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حُنَيْنًا وَقَالَ ابْنُ الْمُبَارَكِ عَنْ يُونُسَ عَنْ الزُّهْرِيِّ عَنْ سَعِيدٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَابَعَهُ صَالِحٌ عَنْ الزُّهْرِيِّ وَقَالَ الزُّبَيْدِيُّ أَخْبَرَنِي الزُّهْرِيُّ أَنَّ عَبْدَ الرَّحْمَنِ بْنَ كَعْبٍ أَخْبَرَهُ أَنَّ عُبَيْدَ اللَّهِ بْنَ كَعْبٍ قَالَ أَخْبَرَنِي مَنْ شَهِدَ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَيْبَرَ قَالَ الزُّهْرِيُّ وَأَخْبَرَنِي عُبَيْدُ اللَّهِ بْنُ عَبْدِ اللَّهِ وَسَعِيدٌ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Abu Al Yaman] telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhri] ia berkata; telah mengabarkan kepadaku [Sa'id bin Al Musayyab] bahwa [Abu Hurairah radliallahu 'anhu] berkata; \"Kami ikut perang Khaibar. Lalu Rasulullah shallallahu 'alaihi wasallam berkata kepada seseorang yang bersama beliau dan mengaku telah memeluk Islam: \"Orang ini termasuk penduduk neraka\". Ketika terjadi peperangan, orang tadi berperang dengan sangat berani hingga orang-orang ragu (dengan apa yang diucapkan beliau). Ternyata laki-laki itu mendapatkan luka yang sangat serius. Lalu tanganya berusaha menggapai sarung panahnya, kemudian dia mengeluarkan anak panah dan menusuk dirinya sendiri. Lantas para pejuang Muslimin berkumpul dan berkata;; \"Wahai Rasulullah, Allah telah membenarkan ucapan tuan. Si fulan membunuh dirinya hinga gugur.\" Beliau bersabda; \"Berdirilah kamu hai fulan dan umumkan bahwa tidak akan masuk surga kecuali orang yang beriman. Sesungguhnya Allah mengokohkan agama ini (diantaranya) dengan perantaraan seorang yang fajir (berdosa).\" Hadits ini juga di perkuat oleh [Ma'mar] dari [Az Zuhri]. Dan [Syabib] mengatakan; dari [Yunus] dari [Ibnu Syihab] telah mengabarkan kepadaku [Ibnu Al Musayyab] dan [Abdurrahman bin Abdullah bin Ka'ab] bahwa [Abu Hurairah] berkata; \"Kami ikut bersama Nabi shallallahu 'alaihi wasallam pada perang Hunain.\" Dan [Ibnu Al Mubarak] mengatakan dari [Yunus] dari [Az Zuhri] dari [Sa'id] dari Nabi shallallahu 'alaihi wasallam. Hadits ini juga diperkuat oleh [Shalih] dari [Az Zuhri]. [Az Zubaidiy] mengatakan; telah mengabarkan kepadaku [Az Zuhri] bahwa [Abdurrahman bin Ka'ab] mengabarkan kepadanya bahwa ['Ubaidullah bin Ka'ab] berkata; telah mengabarkan kepadaku [orang yang] ikut dalam perang Khaibar bersama Nabi shallallahu 'alaihi wasallam. [Az Zuhri] berkata; dan telah mengabarkan kepadaku ['Ubaidullah bin Abdullah] dan [Sa'id] dari Nabi shallallahu 'alaihi wasallam.\""},"3640":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ حَدَّثَنَا عَبْدُ الْوَاحِدِ عَنْ عَاصِمٍ عَنْ أَبِي عُثْمَانَ عَنْ أَبِي مُوسَى الْأَشْعَرِيِّ رَضِيَ اللَّهُ عَنْهُ قَالَلَمَّا غَزَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَيْبَرَ أَوْ قَالَ لَمَّا تَوَجَّهَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَشْرَفَ النَّاسُ عَلَى وَادٍ فَرَفَعُوا أَصْوَاتَهُمْ بِالتَّكْبِيرِ اللَّهُ أَكْبَرُ اللَّهُ أَكْبَرُ لَا إِلَهَ إِلَّا اللَّهُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ارْبَعُوا عَلَى أَنْفُسِكُمْ إِنَّكُمْ لَا تَدْعُونَ أَصَمَّ وَلَا غَائِبًا إِنَّكُمْ تَدْعُونَ سَمِيعًا قَرِيبًا وَهُوَ مَعَكُمْ وَأَنَا خَلْفَ دَابَّةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَمِعَنِي وَأَنَا أَقُولُ لَا حَوْلَ وَلَا قُوَّةَ إِلَّا بِاللَّهِ فَقَالَ لِي يَا عَبْدَ اللَّهِ بْنَ قَيْسٍ قُلْتُ لَبَّيْكَ يَا رَسُولَ اللَّهِ قَالَ أَلَا أَدُلُّكَ عَلَى كَلِمَةٍ مِنْ كَنْزٍ مِنْ كُنُوزِ الْجَنَّةِ قُلْتُ بَلَى يَا رَسُولَ اللَّهِ فَدَاكَ أَبِي وَأُمِّي قَالَ لَا حَوْلَ وَلَا قُوَّةَ إِلَّا بِاللَّهِ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] telah menceritakan kepada kami ['Abdul Wahid] dari ['Ashim] dari [Abu 'Utsman] dari [Abu Musa Al Asy'ari radliallahu 'anhu] ia berkata; Ketika Rasulullah shallallahu 'alaihi wasallam perang melawan (penduduk) Khaibar, -atau dia berkata- Ketika Rasulullah shallallahu 'alaihi wasallam melihat orang-orang menuruni lembah sambil meninggikan suara dengan bertakbir, Allahu Akbar, Allahu Akbar laa ilaaha illallah (Allah Maha Besar, Allah Maha Besar, tidak ada ilah yang berhak disembah selain Allah), maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Rendahkanlah, karena kalian tidak menyeru kepada Dzat yang tuli dan Dzat yang ghaib. Sesungguhnya kalian menyeru Dzat yang Maha Mendengar lagi Maha Dekat dan Dia selalu bersama kalian\". Saat itu aku berada di belakang hewan tunggangan Rasulullah shallallahu 'alaihi wasallam dan beliau mendengar apa yang aku ucapkan. Saat itu aku membaca; \"laa hawla wa laa quwwata illa billah (Tidak ada daya dan upaya melainkan dari Allah) \", maka beliau berkata kepadaku: \"Wahai Abdullah bin Qais\". Aku jawab; \"Aku penuhi panggilanmu wahai Rasulullah.\" Beliau melanjutkan: \"Maukah aku tunjukkan kepadamu satu kalimat yang termasuk perbendaharaan surga?\". Aku jawab; \"Tentu wahai Rasulullah, demi bapak ibuku sebagai tebusan tuan.\" Beliau bersabda: \"laa hawla wa laa quwwata illa billah.\""},"3641":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ قَالَ حَدَّثَنِي مَالِكٌ عَنْ عَبْدِ الْمَجِيدِ بْنِ سُهَيْلٍ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ وَأَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اسْتَعْمَلَ رَجُلًا عَلَى خَيْبَرَ فَجَاءَهُ بِتَمْرٍ جَنِيبٍ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَكُلُّ تَمْرِ خَيْبَرَ هَكَذَا فَقَالَ لَا وَاللَّهِ يَا رَسُولَ اللَّهِ إِنَّا لَنَأْخُذُ الصَّاعَ مِنْ هَذَا بِالصَّاعَيْنِ بِالثَّلَاثَةِ فَقَالَ لَا تَفْعَلْ بِعْ الْجَمْعَ بِالدَّرَاهِمِ ثُمَّ ابْتَعْ بِالدَّرَاهِمِ جَنِيبًاوَقَالَ عَبْدُ الْعَزِيزِ بْنُ مُحَمَّدٍ عَنْ عَبْدِ الْمَجِيدِ عَنْ سَعِيدٍ أَنَّ أَبَا سَعِيدٍ وَأَبَا هُرَيْرَةَ حَدَّثَاهُ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعَثَ أَخَا بَنِي عَدِيٍّ مِنْ الْأَنْصَارِ إِلَى خَيْبَرَ فَأَمَّرَهُ عَلَيْهَا وَعَنْ عَبْدِ الْمَجِيدِ عَنْ أَبِي صَالِحٍ السَّمَّانِ عَنْ أَبِي هُرَيْرَةَ وَأَبِي سَعِيدٍ مِثْلَهُ","id":"Telah menceritakan kepada kami [Ismail], katanya; telah menceritakan kepadaku [Malik] dari [Abdul Majid bin Suhail] dari [Said bin Musayyab] dari [Abu Sa'id Al Khudri] dan [Abu Hurairah] radliallahu 'anhuma, Rasulullah shallallahu 'alaihi wasallam pernah mempekerjakan seseorang untuk mengelola tanah Khaibar, kemudian ia membawa kurma \"Janib\" (kurma yang berasal bukan dari Khaibar), maka Rasulullah bertanya: 'Apakah kurma Khaibar seperti ini? ' Ia menjawab; 'Tidak, demi Allah ya Rasulullah, kami memperoleh satu sha' kurma Janib ini dengan menukar dua sha' kurma Khaibar atau tiga! ' Nabi mengingatkan: 'Jangan seperti itu kamu lakukan, namun juallah semua dahulu dengan beberapa dirham, kemudian uangnya kau belikan kurma Janib.' Kata [Abdul Aziz bin Muhammad], dari [Abdul Majid] dari [Said], bahwasanya [Abu Said] dan [Abu Hurairah] menceritakan kepadanya, bahwasanya Nabi shallallahu 'alaihi wasallam pernah mengutus saudara Bani 'Adi dari Anshar ke Khaibar, lalu mengangkatnya sebagai pejabat Khaibar, dan dari [Abdul Majid] dari [Abu Shalih As Siman] dari [Abu Hurairah] dan [Abu Sa'id] dengan Hadits yang serupa."},"3642":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ حَدَّثَنَا جُوَيْرِيَةُ عَنْ نَافِعٍ عَنْ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُ قَالَأَعْطَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَيْبَرَ الْيَهُودَ أَنْ يَعْمَلُوهَا وَيَزْرَعُوهَا وَلَهُمْ شَطْرُ مَا يَخْرُجُ مِنْهَا","id":"Telah menceritakan kepada kami [Musa bin Ismail]; Telah menceritakan kepada kami [Juwairiyah] dari [Nafi'] dari [Abdullah] radliallahu 'anhu, katanya; Nabi shallallahu 'alaihi wasallam Pernah memberi orang yahudi hak kelola tanah Khaibar, caranya, agar mereka kelola, mereka tanam, dan mereka peroleh separuh hasilnya."},"3643":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ حَدَّثَنَا اللَّيْثُ حَدَّثَنِي سَعِيدٌ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَلَمَّا فُتِحَتْ خَيْبَرُ أُهْدِيَتْ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ شَاةٌ فِيهَا سُمٌّ","id":"Telah menceritakan kepada kami [Abdullah bin Yusuf]; Telah menceritakan kepada kami [Al Laits]; telah menceritakan kepadaku [Said] dari [Abu Hurairah] radliallahu 'anhu, katanya; Ketika Khaibar ditaklukkan, Rasulullah diberi kambing yang diberi racun."},"3644":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ حَدَّثَنَا سُفْيَانُ بْنُ سَعِيدٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ دِينَارٍ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا قَالَأَمَّرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أُسَامَةَ عَلَى قَوْمٍ فَطَعَنُوا فِي إِمَارَتِهِ فَقَالَ إِنْ تَطْعَنُوا فِي إِمَارَتِهِ فَقَدْ طَعَنْتُمْ فِي إِمَارَةِ أَبِيهِ مِنْ قَبْلِهِ وَايْمُ اللَّهِ لَقَدْ كَانَ خَلِيقًا لِلْإِمَارَةِ وَإِنْ كَانَ مِنْ أَحَبِّ النَّاسِ إِلَيَّ وَإِنَّ هَذَا لَمِنْ أَحَبِّ النَّاسِ إِلَيَّ بَعْدَهُ","id":"Telah menceritakan kepada kami [Musaddad] Telah menceritakan kepada kami [Yahya bin Said] Telah menceritakan kepada kami [Sufyan bin Said] Telah menceritakan kepada kami [Abdullah bin Dinar] dari [Ibnu Umar] radliallahu 'anhuma, katanya, Rasulullah shallallahu 'alaihi wasallam pernah mengangkat Usamah bin Zaid sebagai pimpinan suatu kaum, dan mereka mengkritik atas kepemimpinanya. Maka Rasulullah bersabda; \"Jika kalian mengkritik habis-habisan kepemimpinanya, berarti kalian juga mengkritik habis-habisan kepemimpinan ayahnya sebelum ini. Demi Allah, dia sangat layak untuk memimpin, dahulu ayahnya diantara manusia yang paling aku cintai, dan ia (Usamah) sekarang diantara manusia yang paling aku cintai setelahnya.\""},"3645":{"ar":"حَدَّثَنِي عُبَيْدُ اللَّهِ بْنُ مُوسَى عَنْ إِسْرَائِيلَ عَنْ أَبِي إِسْحَاقَ عَنْ الْبَرَاءِ رَضِيَ اللَّهُ عَنْهُ قَالَلَمَّا اعْتَمَرَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي ذِي الْقَعْدَةِ فَأَبَى أَهْلُ مَكَّةَ أَنْ يَدَعُوهُ يَدْخُلُ مَكَّةَ حَتَّى قَاضَاهُمْ عَلَى أَنْ يُقِيمَ بِهَا ثَلَاثَةَ أَيَّامٍ فَلَمَّا كَتَبُوا الْكِتَابَ كَتَبُوا هَذَا مَا قَاضَى عَلَيْهِ مُحَمَّدٌ رَسُولُ اللَّهِ قَالُوا لَا نُقِرُّ لَكَ بِهَذَا لَوْ نَعْلَمُ أَنَّكَ رَسُولُ اللَّهِ مَا مَنَعْنَاكَ شَيْئًا وَلَكِنْ أَنْتَ مُحَمَّدُ بْنُ عَبْدِ اللَّهِ فَقَالَ أَنَا رَسُولُ اللَّهِ وَأَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ ثُمَّ قَالَ لِعَلِيِّ بْنِ أَبِي طَالِبٍ رَضِيَ اللَّهُ عَنْهُ امْحُ رَسُولَ اللَّهِ قَالَ عَلِيٌّ لَا وَاللَّهِ لَا أَمْحُوكَ أَبَدًا فَأَخَذَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْكِتَابَ وَلَيْسَ يُحْسِنُ يَكْتُبُ فَكَتَبَ هَذَا مَا قَاضَى عَلَيْهِ مُحَمَّدُ بْنُ عَبْدِ اللَّهِ لَا يُدْخِلُ مَكَّةَ السِّلَاحَ إِلَّا السَّيْفَ فِي الْقِرَابِ وَأَنْ لَا يَخْرُجَ مِنْ أَهْلِهَا بِأَحَدٍ إِنْ أَرَادَ أَنْ يَتْبَعَهُ وَأَنْ لَا يَمْنَعَ مِنْ أَصْحَابِهِ أَحَدًا إِنْ أَرَادَ أَنْ يُقِيمَ بِهَا فَلَمَّا دَخَلَهَا وَمَضَى الْأَجَلُ أَتَوْا عَلِيًّا فَقَالُوا قُلْ لِصَاحِبِكَ اخْرُجْ عَنَّا فَقَدْ مَضَى الْأَجَلُ فَخَرَجَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَتَبِعَتْهُ ابْنَةُ حَمْزَةَ تُنَادِي يَا عَمِّ يَا عَمِّ فَتَنَاوَلَهَا عَلِيٌّ فَأَخَذَ بِيَدِهَا وَقَالَ لِفَاطِمَةَ عَلَيْهَا السَّلَام دُونَكِ ابْنَةَ عَمِّكِ حَمَلَتْهَا فَاخْتَصَمَ فِيهَا عَلِيٌّ وَزَيْدٌ وَجَعْفَرٌ قَالَ عَلِيٌّ أَنَا أَخَذْتُهَا وَهِيَ بِنْتُ عَمِّي وَقَالَ جَعْفَرٌ ابْنَةُ عَمِّي وَخَالَتُهَا تَحْتِي وَقَالَ زَيْدٌ ابْنَةُ أَخِي فَقَضَى بِهَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِخَالَتِهَا وَقَالَ الْخَالَةُ بِمَنْزِلَةِ الْأُمِّ وَقَالَ لِعَلِيٍّ أَنْتَ مِنِّي وَأَنَا مِنْكَ وَقَالَ لِجَعْفَرٍ أَشْبَهْتَ خَلْقِي وَخُلُقِي وَقَالَ لِزَيْدٍ أَنْتَ أَخُونَا وَمَوْلَانَا وَقَالَ عَلِيٌّ أَلَا تَتَزَوَّجُ بِنْتَ حَمْزَةَ قَالَ إِنَّهَا ابْنَةُ أَخِي مِنْ الرَّضَاعَةِ","id":"Telah menceritakan kepadaku ['Ubaidullah bin Musa] dari [Israil] dari [Abu Ishaq] dari [Albarra\"] radliallahu 'anhu, katanya, Ketika Nabi shallallahu 'alaihi wasallam berumrah di bulan Dzul qa'dah, dan penduduk Makkah enggan membiarkan beliau memasuki Makkah hingga memperkarakan mereka untuk tinggal hanya selama tiga hari, ketika itu kaum muslimin menulis surat perjanjian, mereka tulis dengan redaksi \"Inilah ketetapan yang diterima Rasulullah\". Orang-orang Quraisy pun mengajukan protes \"Kami tidak mengakui ini, kalaulah kami sadar bahwa engkau adalah Rasulullah, kami sama sekali tidak melarangmu, namun engkau hanyalah Muhammad bin Abdullah\". Rasulullah pun berujar 'Aku Rasulullah, sekaligus aku juga Muhammad bin Abdullah. Kemudian beliau katakan kepada 'Ali bin Abu thalib radliallahu 'anhu \"Tolong hapuslah redaksi Rasulullah.\" Ali katakan \"Demi Allah, saya tidak akan menghapusnya selama-lamanya.\" Rasulullah shallallahu 'alaihi wasallam kemudian mengambil kertas tersebut -padahal beliau tidak bisa menulis dengan baik-dan beliau tulis 'Inilah ketetapan yang diterima Muhammad bin Abdullah agar ia tidak memasuki Makkah dengan senjata, selain pedang yang terbungkus dalam sarung, dan agar jangan sampai penduduk Makkah menghalangi siapapun yang ingin mengikuti beliau melakukan thawaf, dan untuk tidak menghalangi salah seorangpun dari sahabatnya yang ingin bermukim disana. Tatkala Nabi sudah memasuki Makkah dan waktu sudah selesai, Orang-orang Quraisy menemui Ali dan berujar \"Katakan kepada kawanmu (maksudnya Muhammad), masa tinggal di Makkah telah habis! Maka Nabi shallallahu 'alaihi wasallam keluar dari Makkah kemudian anak perempuan Hamzah mengikuti beliau seraya memanggil \"Wahai paman, wahai paman\" Ali kemudian menggandengnya, dan ia tarik tangannya dan berujar kepada Fathimah 'alaihimassalam \"Tolong rawatlah anak perempuan pamanmu\", Maka Fathimah menggendongnya. Kemudian Ali, Zaid, dan Ja'far mempersengketakan anak perempuan Hamzah (maksudnya, masing-masing menginginkan agar anak itu dirumahnya). Ali mengatakan; 'Akulah yang mengambilnya dan dia anak perempuan pamanku.\" Sedang Ja'far mengatakan \"Dia adalah anak perempuan pamanku dan bibinya adalah isteriku sendiri.\" Sedang Zaid mengatakan \"Ia adalah anak perempuan saudaraku.\" Maka Nabi shallallahu 'alaihi wasallam memutuskannya untuk bibinya dan berujar: 'Bibi adalah pengganti ibu'. Dan beliau katakan kepada Ali: \"Engkau bagian dariku, dan aku bagian darimu.\" Dan beliau katakan kepada Ja'far: \"Akhlakku menyerupai akhlakmu.\" Dan beliau katakan kepada Zaid: 'Engkau adalah saudara dan maula kami.\" Ali katakan kepada Rasulullah; \"Tidakkah engkau nikahi anak perempuan Hamzah? Nabi menjawab: \"Dia adalah anak perempuan saudaraku sepersusuan.\""},"3646":{"ar":"حَدَّثَنِي مُحَمَّدُ بْنُ رَافِعٍ حَدَّثَنَا سُرَيْجٌ حَدَّثَنَا فُلَيْحٌ ح و حَدَّثَنِي مُحَمَّدُ بْنُ الْحُسَيْنِ بْنِ إِبْرَاهِيمَ قَالَ حَدَّثَنِي أَبِي حَدَّثَنَا فُلَيْحُ بْنُ سُلَيْمَانَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَرَجَ مُعْتَمِرًا فَحَالَ كُفَّارُ قُرَيْشٍ بَيْنَهُ وَبَيْنَ الْبَيْتِ فَنَحَرَ هَدْيَهُ وَحَلَقَ رَأْسَهُ بِالْحُدَيْبِيَةِ وَقَاضَاهُمْ عَلَى أَنْ يَعْتَمِرَ الْعَامَ الْمُقْبِلَ وَلَا يَحْمِلَ سِلَاحًا عَلَيْهِمْ إِلَّا سُيُوفًا وَلَا يُقِيمَ بِهَا إِلَّا مَا أَحَبُّوا فَاعْتَمَرَ مِنْ الْعَامِ الْمُقْبِلِ فَدَخَلَهَا كَمَا كَانَ صَالَحَهُمْ فَلَمَّا أَنْ أَقَامَ بِهَا ثَلَاثًا أَمَرُوهُ أَنْ يَخْرُجَ فَخَرَجَ","id":"Telah menceritakan kepadaku [Muhammad bin Rafi'] Telah menceritakan kepada kami [Suraij] Telah menceritakan kepada kami [Fulaih] -lewat jalur periwayatan lain- telah menceritakan kepadaku [Muhammad bin Husain bin Ibrahim] katanya, telah menceritakan kepadaku [ayahku] Telah menceritakan kepada kami [Fulaih bin Sulaiman] dari [Nafi'] dari [Ibnu Umar] radliallahu 'anhuma, bahwasanya Rasulullah shallallahu 'alaihi wasallam berangkat umrah, kemudian orang kafir quraisy menghalangi antara beliau dan Baitullah, lantas beliau sembelih sembelihannya, beliau cukur kepalanya di Hudaibiyah, dan beliau putuskan kepada mereka agar beliau berumrah tahun berikutnya, dan tidak membawa senjata selain pedang dan tidak berdiam di Makkah selain yang Quraisy inginkan. Tahun selanjutnya beliau melakukan umrah, dan beliau memasuki Makkah sebagaimana perdamaian yang beliau janjikan, setelah beliau bermukim disana selama tiga hari, orang-orang Quraisy menyuruhnya agar beliau keluar. Beliaupun keluar."},"3647":{"ar":"حَدَّثَنِي عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا جَرِيرٌ عَنْ مَنْصُورٍ عَنْ مُجَاهِدٍ قَالَدَخَلْتُ أَنَا وَعُرْوَةُ بْنُ الزُّبَيْرِ الْمَسْجِدَ فَإِذَا عَبْدُ اللَّهِ بْنُ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا جَالِسٌ إِلَى حُجْرَةِ عَائِشَةَ ثُمَّ قَالَ كَمْ اعْتَمَرَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَرْبَعًا ثُمَّ سَمِعْنَا اسْتِنَانَ عَائِشَةَ قَالَ عُرْوَةُ يَا أُمَّ الْمُؤْمِنِينَ أَلَا تَسْمَعِينَ مَا يَقُولُ أَبُو عَبْدِ الرَّحْمَنِ إِنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اعْتَمَرَ أَرْبَعَ عُمَرٍ فَقَالَتْ مَا اعْتَمَرَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عُمْرَةً إِلَّا وَهُوَ شَاهِدُهُ وَمَا اعْتَمَرَ فِي رَجَبٍ قَطُّ","id":"Telah menceritakan kepadaku [Ustman bin Abu Syaibah] Telah menceritakan kepada kami [Jarir] dari [Manshur] dari [Mujahid], katanya, aku dan Urwah bin Zubair memasuki sebuah masjid, ternyata [Abdullah bin Umar radliallahu 'anhuma] sedang duduk di sebelah kamar Aisyah, kemudian Urwah bin Zubair bertanya; \"Berapa kali Nabi shallallahu 'alaihi wasallam berumrah? Ibnu Umar menjawab; \"Empat kali.\" [Aisyah] terus berujar \"Nabi shallallahu 'alaihi wasallam tak pernah berumrah kecuali Ibnu Umar turut menyertainya, dan beliau sama sekali tidak pernah berumrah pada bulan rajab.\""},"3648":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا سُفْيَانُ عَنْ إِسْمَاعِيلَ بْنِ أَبِي خَالِدٍ سَمِعَ ابْنَ أَبِي أَوْفَى يَقُولُلَمَّا اعْتَمَرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَتَرْنَاهُ مِنْ غِلْمَانِ الْمُشْرِكِينَ وَمِنْهُمْ أَنْ يُؤْذُوا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Ali bin Abdullah] Telah menceritakan kepada kami [Sufyan] dari [Ismail bin Abu Khalid] ia mendengar [Abu Aufa] mengatakan, ketika Rasulullah shallallahu 'alaihi wasallam melakukan umrah, kami menutupinya dari anak-anak kaum musyrikin, dan diantara mereka ada yang menyakiti Rasulullah Shallallahu'alaihiwasallam."},"3649":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا حَمَّادٌ هُوَ ابْنُ زَيْدٍ عَنْ أَيُّوبَ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَقَدِمَ رَسُولُ اللَّه صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَصْحَابُهُ فَقَالَ الْمُشْرِكُونَ إِنَّهُ يَقْدَمُ عَلَيْكُمْ وَفْدٌ وَهَنَهُمْ حُمَّى يَثْرِبَ وَأَمَرَهُمْ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يَرْمُلُوا الْأَشْوَاطَ الثَّلَاثَةَ وَأَنْ يَمْشُوا مَا بَيْنَ الرُّكْنَيْنِ وَلَمْ يَمْنَعْهُ أَنْ يَأْمُرَهُمْ أَنْ يَرْمُلُوا الْأَشْوَاطَ كُلَّهَا إِلَّا الْإِبْقَاءُ عَلَيْهِمْقَالَ أَبُو عَبْد اللَّهِ وَزَادَ ابْنُ سَلَمَةَ عَنْ أَيُّوبَ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ قَالَ لَمَّا قَدِمَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِعَامِهِ الَّذِي اسْتَأْمَنَ قَالَ ارْمُلُوا لِيَرَى الْمُشْرِكُونَ قُوَّتَهُمْ وَالْمُشْرِكُونَ مِنْ قِبَلِ قُعَيْقِعَانَ","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] Telah menceritakan kepada kami [Hammad alias Ibnu Zaid] dari [Ayyub] dari [Said bin Jubair] dari [Ibnu Abbas] radliallahu 'anhuma, katanya, ketika Rasulullah shallallahu 'alaihi wasallam dan para sahabatnya tiba di (Makkah), kaum musyrikin mencemooh; \"Telah datang kepada kalian para utusan yang \"lembek\" karena flu Yatsrib (Madinah), maka Nabi shallallahu 'alaihi wasallam perintahkan para sahabat agar berlari-lari kecil ketika melakukan tiga putaran thawaf pertama dan agar mereka berjalan diantara dua rukun yamani. Tak ada yang menghalangi beliau untuk menyuruh mereka berlari dalam semua putaran selain karena kasih sayang beliau kepada mereka. Kata Abu Abdullah, [Ibnu Salamah] menambahkan dari [Ayyub] dari [Sa'id bin Jubair] dari [Ibnu Abbas] katanya, ketika Nabi shallallahu 'alaihi wasallam tiba pada tahun berikutnya, yang telah beliau minta jaminan keamanannya, beliau bersabda: \"Berlarilah kalian agar orang musyrik melihat kekuatan kalian.\" Dan ketika itu kaum musyrikin berada di suatu lokasi yang namanya Quaiqi'an."},"3650":{"ar":"حَدَّثَنِي مُحَمَّدٌ عَنْ سُفْيَانَ بْنِ عُيَيْنَةَ عَنْ عَمْرٍو عَنْ عَطَاءٍ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَإِنَّمَا سَعَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالْبَيْتِ وَبَيْنَ الصَّفَا وَالْمَرْوَةِ لِيُرِيَ الْمُشْرِكِينَ قُوَّتَهُ","id":"Telah menceritakan kepadaku [Muhammad] dari [Sufyan bin Uyainah] dari [Amru] dari ['Atha'] dari [Ibnu Abbas] radliallahu 'anhuma, katanya, Nabi shallallahu 'alaihi wasallam berlari-lari di Baitullah dan antara Shafa dan Marwa, untuk memperlihatkan kekuatannya kepada orang-orang musyrik."},"3651":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ حَدَّثَنَا وُهَيْبٌ حَدَّثَنَا أَيُّوبُ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَتَزَوَّجَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَيْمُونَةَ وَهُوَ مُحْرِمٌ وَبَنَى بِهَا وَهُوَ حَلَالٌ وَمَاتَتْ بِسَرِفَقَالَ أَبُو عَبْد اللَّهِ وَزَادَ ابْنُ إِسْحَاقَ حَدَّثَنِي ابْنُ أَبِي نَجِيحٍ وَأَبَانُ بْنُ صَالِحٍ عَنْ عَطَاءٍ وَمُجَاهِدٍ عَنْ ابْنِ عَبَّاسٍ قَالَ تَزَوَّجَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَيْمُونَةَ فِي عُمْرَةِ الْقَضَاءِ","id":"Telah menceritakan kepada kami [Musa bin Ismail] Telah menceritakan kepada kami [Wuhaib] Telah menceritakan kepada kami [Ayyub] dari [Ikrimah] dari [Ibnu Abbas] katanya, Nabi shallallahu 'alaihi wasallam menikahi Maimunah ketika beliau ihram, dan beliau menggaulinya ketika beliau telah bertahallul dan Maimunah meninggal di Sarif. Kata Abu Abdullah, [Ibnu Ishaq] menambahkan, telah menceritakan kepadaku [Ibnu Abu Najih] dan [Abban bin Shalih] dari [Atha'] dan [Mujahid] dari [Ibnu Abbas], katanya, Nabi shallallahu 'alaihi wasallam menikahi Maimunah ketika Umratul qadla'."},"3652":{"ar":"حَدَّثَنَا أَحْمَدُ حَدَّثَنَا ابْنُ وَهْبٍ عَنْ عَمْرٍو عَنْ ابْنِ أَبِي هِلَالٍ قَالَ وَأَخْبَرَنِي نَافِعٌ أَنَّ ابْنَ عُمَرَ أَخْبَرَهُأَنَّهُ وَقَفَ عَلَى جَعْفَرٍ يَوْمَئِذٍ وَهُوَ قَتِيلٌ فَعَدَدْتُ بِهِ خَمْسِينَ بَيْنَ طَعْنَةٍ وَضَرْبَةٍ لَيْسَ مِنْهَا شَيْءٌ فِي دُبُرِهِ يَعْنِي فِي ظَهْرِهِ","id":"Telah menceritakan kepada kami [Ahmad] Telah menceritakan kepada kami [Ibnu Wahb] dari [Amru] dari [Ibnu Abu Hilal] katanya, telah mengabarkan kepadaku [Nafi'] bahwasanya [Ibnu Umar] mengabarinya bahwa ia berhenti mengamati Ja'far yang ketika itu dalam keadaan terbunuh, dan kuhitung ternyata ada padanya lima puluh luka akibat sabetan pedang atau tancapan tombak, dan tak ada lagi sisa daging pada punggungnya."},"3653":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ أَبِي بَكْرٍ حَدَّثَنَا مُغِيرَةُ بْنُ عَبْدِ الرَّحْمَنِ عَنْ عَبْدِ اللَّهِ بْنِ سَعِيدٍ عَنْ نَافِعٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا قَالَأَمَّرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي غَزْوَةِ مُؤْتَةَ زَيْدَ بْنَ حَارِثَةَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنْ قُتِلَ زَيْدٌ فَجَعْفَرٌ وَإِنْ قُتِلَ جَعْفَرٌ فَعَبْدُ اللَّهِ بْنُ رَوَاحَةَ قَالَ عَبْدُ اللَّهِ كُنْتُ فِيهِمْ فِي تِلْكَ الْغَزْوَةِ فَالْتَمَسْنَا جَعْفَرَ بْنَ أَبِي طَالِبٍ فَوَجَدْنَاهُ فِي الْقَتْلَى وَوَجَدْنَا مَا فِي جَسَدِهِ بِضْعًا وَتِسْعِينَ مِنْ طَعْنَةٍ وَرَمْيَةٍ","id":"Telah menceritakan kepada kami [Ahmad bin Abu Bakar] Telah menceritakan kepada kami [Mughirah bin Abdurrahman] dari [Abdullah bin Said] dari [Nafi'] dari [Abdullah bin Umar] radliallahu 'anhuma, katanya, Rasulullah shallallahu 'alaihi wasallam dalam perang Mu'tah mengangkat Zaid bin Haritsah sebagai komandan, lantas Rasulullah shallallahu 'alaihi wasallam berpesan: \"Jika Zaid bin Haritsah gugur, maka Ja'far yang mengganti, jika Ja'far gugur, maka Abdullah bin Rawahah sebagai penggantinya.\" Kata Abdullah, aku berada ditengah-tengah pasukan dalam peperangan itu. Lantas kami mencari-cari Ja'far bin Abu Thalib, dan kami temukan ia diantara para prajurit yang terbunuh dan kudapati di tubuhnya ada sekitar sembilan puluh lebih luka karena tombak atau panah."},"3654":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ وَاقِدٍ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ أَيُّوبَ عَنْ حُمَيْدِ بْنِ هِلَالٍ عَنْ أَنَسٍ رَضِيَ اللَّهُ عَنْهُأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَعَى زَيْدًا وَجَعْفَرًا وَابْنَ رَوَاحَةَ لِلنَّاسِ قَبْلَ أَنْ يَأْتِيَهُمْ خَبَرُهُمْ فَقَالَ أَخَذَ الرَّايَةَ زَيْدٌ فَأُصِيبَ ثُمَّ أَخَذَ جَعْفَرٌ فَأُصِيبَ ثُمَّ أَخَذَ ابْنُ رَوَاحَةَ فَأُصِيبَ وَعَيْنَاهُ تَذْرِفَانِ حَتَّى أَخَذَ الرَّايَةَ سَيْفٌ مِنْ سُيُوفِ اللَّهِ حَتَّ�� فَتَحَ اللَّهُ عَلَيْهِمْ","id":"Telah menceritakan kepada kami [Ahmad bin Waqid] Telah menceritakan kepada kami [Hammad bin Zaid] dari [Ayyub] dai [Humaid bin Hilal] dari [Anas] radliallahu 'anhu, bahwasanya Nabi shallallahu 'alaihi wasallam pernah mengumumkan kematian Zaid bin Haritsah, Ja'far bin Abi Thalib dan Abdullah bin Rawahah kepada para sahabat sebelum berita kematian mereka sampai. Nabi sabdakan: \"Bendera perang diambil oleh Zaid, lantas ia gugur, kemudian Ja'far mengambil alih benderanya, ia pun gugur, lantas diambil alih oleh Abdullah bin Rawahah dan ia pun gugur -seraya kedua mata beliau berlinang-, lantas bendera diambil oleh \"si pedang Allah\", Khalid bin Al Walid hingga Allah membuka kemenangan bagi mereka."},"3655":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا عَبْدُ الْوَهَّابِ قَالَ سَمِعْتُ يَحْيَى بْنِ سَعِيدٍ قَالَ أَخْبَرَتْنِي عَمْرَةُ قَالَتْ سَمِعْتُ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا تَقُولُلَمَّا جَاءَ قَتْلُ ابْنِ حَارِثَةَ وَجَعْفَرِ بْنِ أَبِي طَالِبٍ وَعَبْدِ اللَّهِ بْنِ رَوَاحَةَ رَضِيَ اللَّهُ عَنْهُمْ جَلَسَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُعْرَفُ فِيهِ الْحُزْنُ قَالَتْ عَائِشَةُ وَأَنَا أَطَّلِعُ مِنْ صَائِرِ الْبَابِ تَعْنِي مِنْ شَقِّ الْبَابِ فَأَتَاهُ رَجُلٌ فَقَالَ أَيْ رَسُولَ اللَّهِ إِنَّ نِسَاءَ جَعْفَرٍ قَالَ وَذَكَرَ بُكَاءَهُنَّ فَأَمَرَهُ أَنْ يَنْهَاهُنَّ قَالَ فَذَهَبَ الرَّجُلُ ثُمَّ أَتَى فَقَالَ قَدْ نَهَيْتُهُنَّ وَذَكَرَ أَنَّهُ لَمْ يُطِعْنَهُ قَالَ فَأَمَرَ أَيْضًا فَذَهَبَ ثُمَّ أَتَى فَقَالَ وَاللَّهِ لَقَدْ غَلَبْنَنَا فَزَعَمَتْ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فَاحْثُ فِي أَفْوَاهِهِنَّ مِنْ التُّرَابِ قَالَتْ عَائِشَةُ فَقُلْتُ أَرْغَمَ اللَّهُ أَنْفَكَ فَوَاللَّهِ مَا أَنْتَ تَفْعَلُ وَمَا تَرَكْتَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ الْعَنَاءِ","id":"Telah menceritakan kepada kami [Qutaibah] Telah menceritakan kepada kami [Abdul Wahhab] Katanya, kudengar [Yahya bin Said] mengatakan, telah mengabarkan kepadaku ['Amrah] katanya, aku mendengar [Aisyah] radliallahu 'anha mengatakan, ketika datang berita kematian Zaid bin Haritsah, Ja'far bin Abu Thalib dan Abdullah bin Rawahah radliallahu 'anhum, Rasulullah shallallahu 'alaihi wasallam duduk dan nampak tanda kesedihan. Kata Aisyah, dan aku mengintip dari lubang pintu, kemudian ada seseorang datang dan berujar; \"Wahai Rasulullah, isteri-isteri Ja'far, -laki-laki tadi lantas menceritakan tangis mereka-, maka beliau suruh orang tadi untuk melarang mereka. Kata Ibnu Said, si laki-laki lantas pergi, kemudian datang lagi dengan mengatakan; \"Telah kularang mereka\", lalu ia ceritakan kepada beliau bahwa isteri-isterinya tidak menaatinya dan berujar; \"Demi Allah, wanita-wanita itu telah membuat saya kewalahan. Kata Aisyah, sepertinya Rasulullah shallallahu 'alaihi wasallam berujar: \"Kalau begitu, taburkan tanah di mulut mereka.\" Kata Aisyah, saya katakan; \"Kiranya Allah yang justru menaburimu tanah -kalimat ini untuk penghinaan atau sindirian atas ketidakbecusan seseorang tadi-, demi Allah, kamu belum melakukannya dengan baik, dan kamu belum mengentaskan Rasulullah shallallahu 'alaihi wasallam dari tugasnya yang berat."},"3656":{"ar":"حَدَّثَنِي مُحَمَّدُ بْنُ أَبِي بَكْرٍ حَدَّثَنَا عُمَرُ بْنُ عَلِيٍّ عَنْ إِسْمَاعِيلَ بْنِ أَبِي خَالِدٍ عَنْ عَامِرٍ قَالَ كَانَ ابْنُ عُمَرَإِذَا حَيَّا ابْنَ جَعْفَرٍ قَالَ السَّلَامُ عَلَيْكَ يَا ابْنَ ذِي الْجَنَاحَيْنِ","id":"Telah menceritakan kepada kami [Muhammad bin Abu Bakr] Telah menceritakan kepada kami [Umar bin Ali] dari [Ismail bin Abu Khalid] dari [Amir] katanya, [Ibnu Umar] jika memberi salam penghormatan kepada anak Ja'far ia mengatakan; ASSALAMU'ALAIKA YA IBNU DZIL JANAHAINI ' Salam sejahtera untukmu wahai putera yang mempunyai dua sayap. "},"3657":{"ar":"حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا سُفْيَانُ عَنْ إِسْمَاعِيلَ عَنْ قَيْسِ بْنِ أَبِي حَازِمٍ قَالَ سَمِعْتُ خَالِدَ بْنَ الْوَلِيدِ يَقُولُلَقَدْ انْقَطَعَتْ فِي يَدِي يَوْمَ مُؤْتَةَ تِسْعَةُ أَسْيَافٍ فَمَا بَقِيَ فِي يَدِي إِلَّا صَفِيحَةٌ يَمَانِيَةٌ","id":"Telah menceritakan kepada kami [Abu Nu'aim] Telah menceritakan kepada kami [Sufyan] dari [Ismail] dari [Qais bin Abu Hazim], katanya, kudengar [Khalid bin Walid] mengatakan, pada perang Mu'tah, pedang yang putus ditanganku sebanyak sembilan pedang, dan tidak tersisa di tanganku selain pedang Yamani."},"3658":{"ar":"حَدَّثَنِي مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا يَحْيَى عَنْ إِسْمَاعِيلَ قَالَ حَدَّثَنِي قَيْسٌ قَالَ سَمِعْتُ خَالِدَ بْنَ الْوَلِيدِ يَقُولُلَقَدْ دُقَّ فِي يَدِي يَوْمَ مُؤْتَةَ تِسْعَةُ أَسْيَافٍ وَصَبَرَتْ فِي يَدِي صَفِيحَةٌ لِي يَمَانِيَةٌ","id":"Telah menceritakan kepadaku [Muhammad bin Al Mutsanna] Telah menceritakan kepada kami [Yahya] dari [Ismail] katanya, Telah menceritakan kepadaku [Qais], katanya, aku mendengar [Khalid bin Walid] mengatakan, \"Pada perang Mu'tah ada Sembilan pedang putus di tanganku, namun yang tertinggal di tanganku hanya sebilah pedang buatan Yaman.\""},"3659":{"ar":"حَدَّثَنِي عِمْرَانُ بْنُ مَيْسَرَةَ حَدَّثَنَا مُحَمَّدُ بْنُ فُضَيْلٍ عَنْ حُصَيْنٍ عَنْ عَامِرٍ عَنْ النُّعْمَانِ بْنِ بَشِيرٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَأُغْمِيَ عَلَى عَبْدِ اللَّهِ بْنِ رَوَاحَةَ فَجَعَلَتْ أُخْتُهُ عَمْرَةُ تَبْكِي وَا جَبَلَاهْ وَا كَذَا وَا كَذَا تُعَدِّدُ عَلَيْهِ فَقَالَ حِينَ أَفَاقَ مَا قُلْتِ شَيْئًا إِلَّا قِيلَ لِي آنْتَ كَذَلِكَحَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا عَبْثَرُ عَنْ حُصَيْنٍ عَنْ الشَّعْبِيِّ عَنْ النُّعْمَانِ بْنِ بَشِيرٍ قَالَ أُغْمِيَ عَلَى عَبْدِ اللَّهِ بْنِ رَوَاحَةَ بِهَذَا فَلَمَّا مَاتَ لَمْ تَبْكِ عَلَيْهِ","id":"Telah menceritakan kepadaku [Imran bin Maisarah] Telah menceritakan kepada kami [Muhammad bin Fudlail] dari [Hushain] dari [Amir] dari [Nu'man bin Basyir] radliallahu 'anhuma, katanya, dahulu aku pingsan mendengar kematian Abdullah bin Rawahah. Seketika itu pula saudara perempuannya (saudara perempuan Nu'man, maksudnya) menangis dan mengatakan; \"Aduuh, telah binasa orang yang mulia.\" Demikian ia katakan secara berulang-ulang. Maka ketika Nu'man siuman, Num'an katakan kepada saudara perempuannya; \"Semua yang kamu katakan tadi, kecuali terdengar ditanyakan kepadaku; \"Apakah engkau juga seperti itu pula?\" Telah menceritakan kepada kami [Qutaibah], Telah menceritakan kepada kami ['Abtsar] dari [Husain] dari [Asy Sya'bi] dari [Nu'man bin Basyir] katanya, aku jatuh pingsan ketika Abdullah bin Rawahah meninggal, namun engkau tidak menangis."},"3660":{"ar":"حَدَّثَنِي عَمْرُو بْنُ مُحَمَّدٍ حَدَّثَنَا هُشَيْمٌ أَخْبَرَنَا حُصَيْنٌ أَخْبَرَنَا أَبُو ظَبْيَانَ قَالَ سَمِعْتُ أُسَامَةَ بْنَ زَيْدٍ رَضِيَ اللَّهُ عَنْهُمَا يَقُولُبَعَثَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى الْحُرَقَةِ فَصَبَّحْنَا الْقَوْمَ فَهَزَمْنَاهُمْ وَلَحِقْتُ أَنَا وَرَجُلٌ مِنْ الْأَنْصَارِ رَجُلًا مِنْهُمْ فَلَمَّا غَشِينَاهُ قَالَ لَا إِلَهَ إِلَّا اللَّهُ فَكَفَّ الْأَنْصَارِيُّ فَطَعَنْتُهُ بِرُمْحِي حَتَّى قَتَلْتُهُ فَلَمَّا قَدِمْنَا بَلَغَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا أُسَامَةُ أَقَتَلْتَهُ بَعْدَ مَا قَالَ لَا إِلَهَ إِلَّا اللَّهُ قُلْتُ كَانَ مُتَعَوِّذًا فَمَا زَالَ يُكَرِّرُهَا حَتَّى تَمَنَّيْتُ أَنِّي لَمْ أَكُنْ أَسْلَمْتُ قَبْلَ ذَلِكَ الْيَوْمِ","id":"Telah menceritakan kepadaku [Amru bin Muhammad] Telah menceritakan kepada kami [Husyaim] Telah mengabarkan kepada kami [Hushain] Telah mengabarkan kepada kami [Abu Zhabyan] katanya, aku mendengar [Usamah bin Zaid] radliallahu 'anhuma mengatakan, Rasulullah shallallahu 'alaihi wasallam mengirim kami ke Khurqah, lantas kami melakukan penyerbuan ketika pagi buta, kemudian kami mengobrak abrik mereka. Aku dan seorang laki-laki Anshar kebetulan berhasil memergoki seorang laki-laki dari mereka, ketika kami bisa mengepungnya, tiba-tiba ia mengucapkan syahadat \"laa-ilaaha-illallah\". Si laki-laki Anshar rupanya menahan diri dari penyerbuannya, namun aku nekad menusuknya dengan tombakku hingga aku berhasil membunuhnya. Ketika kami tiba, berita ini sampai kepada Nabi shallallahu 'alaihi wasallam. Lantas beliau berujar kepadaku: \"Wahai Usamah, apakah engkau membunuhnya setelah mengucapkan laa-ilaaha-illallah? Saya jawab; \"Dia mengucapkan kalimat itu hanya untuk mencari selamat saja!\" Rasul tidak henti melancarkan kritiknya padaku hingga aku berangan-angan kalaulah aku belum masuk Islam sebelum hari itu."},"3661":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا حَاتِمٌ عَنْ يَزِيدَ بْنِ أَبِي عُبَيْدٍ قَالَ سَمِعْتُ سَلَمَةَ بْنَ الْأَكْوَعِ يَقُولُغَزَوْتُ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَبْعَ غَزَوَاتٍ وَخَرَجْتُ فِيمَا يَبْعَثُ مِنْ الْبُعُوثِ تِسْعَ غَزَوَاتٍ مَرَّةً عَلَيْنَا أَبُو بَكْرٍ وَمَرَّةً عَلَيْنَا أُسَامَةُوَقَالَ عُمَرُ بْنُ حَفْصِ بْنِ غِيَاثٍ حَدَّثَنَا أَبِي عَنْ يَزِيدَ بْنِ أَبِي عُبَيْدٍ قَالَ سَمِعْتُ سَلَمَةَ يَقُولُ غَزَوْتُ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَبْعَ غَزَوَاتٍ وَخَرَجْتُ فِيمَا يَبْعَثُ مِنْ الْبَعْثِ تِسْعَ غَزَوَاتٍ عَلَيْنَا مَرَّةً أَبُو بَكْرٍ وَمَرَّةً أُسَامَةُ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] Telah menceritakan kepada kami [Hatim] dari [Yazid bin Abu Ubaid] katanya, aku mendengar [Salamah bin Al Akwa'] mengatakan, aku berperang (ghazawah) bersama Nabi shallallahu 'alaihi wasallam sebanyak tujuh kali, dan aku berangkat dalam sebuah ekspedisi militer (Sariyah) yang beliau lakukan sebanyak Sembilan kali. Adakalanya kami dipimpin oleh Abu bakar dan ada kalanya kami dipimpin oleh Usamah. Sedang [Umar bin Hafs bin Ghiyats] mengatakan, Telah menceritakan kepada kami [Ayahku] dari [Yazid bin Abu Ubaid] katanya, aku mendengar [Salamah] mengatakan, aku berperang (ghazawah) bersama Nabi shallallahu 'alaihi wasallam sebanyak tujuh kali, dan aku pernah berangkat pada sebuah ekspedisi militer (sariyah) yang beliau lakukan sebanyak sembilan kali, terkadang kami dikomandani oleh Abu bakar, namun terkadang dikomandani Usamah bin Zaid."},"3662":{"ar":"حَدَّثَنَا أَبُو عَاصِمٍ الضَّحَّاكُ بْنُ مَخْلَدٍ حَدَّثَنَا يَزِيدُ بْنُ أَبِي عُبَيْدٍ عَنْ سَلَمَةَ بْنِ الْأَكْوَعِ رَضِيَ اللَّهُ عَنْهُ قَالَغَزَوْتُ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَبْعَ غَزَوَاتٍ وَغَزَوْتُ مَعَ ابْنِ حَارِثَةَ اسْتَعْمَلَهُ عَلَيْنَا","id":"Telah menceritakan kepada kami [Abu \"Ashim Adh Dhahak bin Makhlad] Telah menceritakan kepada kami [Yazid bin Abu Ubaid] dari [Salamah bin Al Akwa'] katanya, aku pernah berperang bersama Nabi shallallahu 'alaihi wasallam sebanyak tujuh kali dan beliau pernah mengangkat Ibnu Haritsah sebagai komandan kami.\""},"3663":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا حَمَّادُ بْنُ مَسْعَدَةَ عَنْ يَزِيدَ بْنِ أَبِي عُبَيْدٍ عَنْ سَلَمَةَ بْنِ الْأَكْوَعِ قَالَغَزَوْتُ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَبْعَ غَزَوَاتٍ فَذَكَرَ خَيْبَرَ وَالْحُدَيْبِيَةَ وَيَوْمَ حُنَيْنٍ وَيَوْمَ الْقَرَدِ قَالَ يَزِيدُ وَنَسِيتُ بَقِيَّتَهُمْ","id":"Telah menceritakan kepada kami [Muhammad bin Abdullah] Telah menceritakan kepada kami [Hammad bin Mas'adah] dari [Yazid bin Abu Ubaid] dari [Salamah bin Al Akwa'] katanya, aku pernah berperang bersama Nabi shallallahu 'alaihi wasallam sebanyak tujuh kali peperangan, dan ia sebutkan Khaibar, Hudaibiyah, Hunain, Dzatu qarad, kata Yazid, yang lain aku lupa.\""},"3664":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا سُفْيَانُ عَنْ عَمْرِ�� بْنِ دِينَارٍ قَالَ أَخْبَرَنِي الْحَسَنُ بْنُ مُحَمَّدٍ أَنَّهُ سَمِعَ عُبَيْدَ اللَّهِ بْنَ أَبِي رَافِعٍ يَقُولُ سَمِعْتُ عَلِيًّا رَضِيَ اللَّهُ عَنْهُيَقُولُ بَعَثَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَا وَالزُّبَيْرَ وَالْمِقْدَادَ فَقَالَ انْطَلِقُوا حَتَّى تَأْتُوا رَوْضَةَ خَاخٍ فَإِنَّ بِهَا ظَعِينَةً مَعَهَا كِتَابٌ فَخُذُوا مِنْهَا قَالَ فَانْطَلَقْنَا تَعَادَى بِنَا خَيْلُنَا حَتَّى أَتَيْنَا الرَّوْضَةَ فَإِذَا نَحْنُ بِالظَّعِينَةِ قُلْنَا لَهَا أَخْرِجِي الْكِتَابَ قَالَتْ مَا مَعِي كِتَابٌ فَقُلْنَا لَتُخْرِجِنَّ الْكِتَابَ أَوْ لَنُلْقِيَنَّ الثِّيَابَ قَالَ فَأَخْرَجَتْهُ مِنْ عِقَاصِهَا فَأَتَيْنَا بِهِ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَإِذَا فِيهِ مِنْ حَاطِبِ بْنِ أَبِي بَلْتَعَةَ إِلَى نَاسٍ بِمَكَّةَ مِنْ الْمُشْرِكِينَ يُخْبِرُهُمْ بِبَعْضِ أَمْرِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا حَاطِبُ مَا هَذَا قَالَ يَا رَسُولَ اللَّهِ لَا تَعْجَلْ عَلَيَّ إِنِّي كُنْتُ امْرَأً مُلْصَقًا فِي قُرَيْشٍ يَقُولُ كُنْتُ حَلِيفًا وَلَمْ أَكُنْ مِنْ أَنْفُسِهَا وَكَانَ مَنْ مَعَكَ مِنْ الْمُهَاجِرِينَ مَنْ لَهُمْ قَرَابَاتٌ يَحْمُونَ أَهْلِيهِمْ وَأَمْوَالَهُمْ فَأَحْبَبْتُ إِذْ فَاتَنِي ذَلِكَ مِنْ النَّسَبِ فِيهِمْ أَنْ أَتَّخِذَ عِنْدَهُمْ يَدًا يَحْمُونَ قَرَابَتِي وَلَمْ أَفْعَلْهُ ارْتِدَادًا عَنْ دِينِي وَلَا رِضًا بِالْكُفْرِ بَعْدَ الْإِسْلَامِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَا إِنَّهُ قَدْ صَدَقَكُمْ فَقَالَ عُمَرُ يَا رَسُولَ اللَّهِ دَعْنِي أَضْرِبْ عُنُقَ هَذَا الْمُنَافِقِ فَقَالَ إِنَّهُ قَدْ شَهِدَ بَدْرًا وَمَا يُدْرِيكَ لَعَلَّ اللَّهَ اطَّلَعَ عَلَى مَنْ شَهِدَ بَدْرًا فَقَالَ اعْمَلُوا مَا شِئْتُمْ فَقَدْ غَفَرْتُ لَكُمْ فَأَنْزَلَ اللَّهُ السُّورَةَ{ يَا أَيُّهَا الَّذِينَ آمَنُوا لَا تَتَّخِذُوا عَدُوِّي وَعَدُوَّكُمْ أَوْلِيَاءَ تُلْقُونَ إِلَيْهِمْ بِالْمَوَدَّةِ وَقَدْ كَفَرُوا بِمَا جَاءَكُمْ مِنْ الْحَقِّ إِلَى قَوْلِهِ فَقَدْ ضَلَّ سَوَاءَ السَّبِيلِ }","id":"Telah menceritakan kepada kami [Qutaibah bin Said] Telah menceritakan kepada kami [Sufyan] dari [Amru bin Dinar], katanya telah mengabarkan kepadaku [Al Hasan bin Muhammad] ia mendengar [Ubaidullah bin Abu Rafi'] mengatakan, aku mendengar [Ali] radliallahu 'anhu berujar, Rasulullah shallallahu 'alaihi wasallam mengutusku, Zubair, dan Miqdad, pesan beliau: \"Berangkatlah kalian hingga kalian sampai \"Raudhah Khakh\", sebab disana ada seorang wanita penunggang unta yang membawa surat, rebutlah surat itu.\" Kata Ubaidullah bin Rafi', kami pun berangkat dan kuda kami pacu secepat-cepatnya hingga kami tiba di Raudah Khakh, disana telah ada ada seorang wanita menunggang unta. Kami katakan kepadanya; \"Tolong keluarkan suratmu.\" \"Aku tak membawa surat.\" Jawab si wanita tersebut. Maka terpaksa kami katakana; \"Kamu harus keluarkan surat itu, atau kami yang akan menelanjangi pakaianmu!\" Kata Ubaidullah, maka si wanita itu akhirnya mau mengeluarkan suratnya dari gelung rambutnya, dan kami bawa surat tersebut kepada Rasulullah Shallallahu'alaihiwasallam. Ternyata surat tersebut berasal dari Khatib bin Abu Balta'ah Al Ansahri untuk beberapa orang musyrik Makkah, memberitakan mereka beberapa kebijakan Rasulullah yang akan beliau lakukan. Maka Rasulullah shallallahu 'alaihi wasallam menginterogasi Hatib bin Abu Balta'ah dengan berujar \"Wahai Hathib, apa maksudmu menulis surat seperti ini?\" Jawab Hathib \"Wahai Rasulullah, jangan engkau terburu-buru menghukumku, aku adalah seseorang yang dahulu terdampar di Quraisy, -lantas ia jelaskan, dia adalah sekutunya, namun bukan berasal dari cucu keturunannya-. Orang-orang muhajirin yang bersamamu mempunyai banyak kerabat yang menjaga keluarga dan harta mereka, maka aku juga pingin jika aku tak punya nasab, aku cari pelindung disisi mereka sehingga menjaga keakrabanku. Aku lakukan bukan karena aku murtad dari agamaku, bukan pula berarti aku ridla terhadap kekafiran setelah keIslaman.\" Rasulullah memberi komentar \"Hatib memang telah jujur kepada kalian.\" Umar namun menyampaikan sikap kerasnya \"Wahai Rasulullah, biarkan aku untuk memenggal leher si munafik ini.\" Rasulullah mencegahnya seraya berujar \"Dia, Hatib, telah ikut perang badar, siapa tahu Allah telah mengintip semua pengikut perang Badar dan bertitah \"lakukan yang kalian suka, AKU telah mengampuni kalian, maka turunlah ayat: \"Wahai orang-orang yang beriman, janganlah kalian ambil musuh-Ku dan musuh kalian sebagai pelindung, kamu nampakkan kecintaan kepada mereka, padahal, mereka mengkufuri kebenaran yang datang kepada kalian.\" -sampai ayat \"Telah sesat dari jalan yang lurus- (QS. Mumtahanah ayat 1)."},"3665":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ حَدَّثَنَا اللَّيْثُ قَالَ حَدَّثَنِي عُقَيْلٌ عَنْ ابْنِ شِهَابٍ قَالَ أَخْبَرَنِي عُبَيْدُ اللَّهِ بْنُ عَبْدِ اللَّهِ بْنِ عُتْبَةَ أَنَّ ابْنَ عَبَّاسٍ أَخْبَرَهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ غَزَا غَزْوَةَ الْفَتْحِ فِي رَمَضَانَ قَالَ وَسَمِعْتُ سَعِيدَ بْنَ الْمُسَيَّبِ يَقُولُ مِثْلَ ذَلِكَ وَعَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ أَخْبَرَهُ أَنَّ ابْنَ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَ صَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى إِذَا بَلَغَ الْكَدِيدَ الْمَاءَ الَّذِي بَيْنَ قُدَيْدٍ وَعُسْفَانَ أَفْطَرَ فَلَمْ يَزَلْ مُفْطِرًا حَتَّى انْسَلَخَ الشَّهْرُ","id":"Telah menceritakan kepada kami [Abdullah bin Yusuf] Telah menceritakan kepada kami [Al Laits] katanya, Telah menceritakan kepadaku [Uqail] dari [Ibnu Syihab] katanya, telah menceritakan kepadaku [Ubaidullah bin Abdullah bin Utbah], bahwa Ibnu Abbas memberitakannya, Rasulullah shallallahu 'alaihi wasallam melakukan penaklukan Makkah pada bulan Ramadhan. Kata [Ibnu Abbas], kudengar Said bin Musayyab juga seperti itu. Dan dari Ubaidullah bin Abdullah ia mengabarinya, bahwsanya Ibnu Abbas radliallahu 'anhu mengatakan, Rasulullah shallallahu 'alaihi wasallam pernah berpuasa, hingga ketika beliau sampai Kadid, sebuah mata air antara Qudaid dan Usfan, beliau membatalkan puasanya dan terus beliau tidak puasa hingga bulan yang dijadikan beliau puasa selesai."},"3666":{"ar":"حَدَّثَنِي مَحْمُودٌ أَخْبَرَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ قَالَ أَخْبَرَنِي الزُّهْرِيُّ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَرَجَ فِي رَمَضَانَ مِنْ الْمَدِينَةِ وَمَعَهُ عَشَرَةُ آلَافٍ وَذَلِكَ عَلَى رَأْسِ ثَمَانِ سِنِينَ وَنِصْفٍ مِنْ مَقْدَمِهِ الْمَدِينَةَ فَسَارَ هُوَ وَمَنْ مَعَهُ مِنْ الْمُسْلِمِينَ إِلَى مَكَّةَ يَصُومُ وَيَصُومُونَ حَتَّى بَلَغَ الْكَدِيدَ وَهُوَ مَاءٌ بَيْنَ عُسْفَانَ وَقُدَيْدٍ أَفْطَرَ وَأَفْطَرُواقَالَ الزُّهْرِيُّ وَإِنَّمَا يُؤْخَذُ مِنْ أَمْرِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْآخِرُ فَالْآخِرُ","id":"Telah menceritakan kepadaku [Mahmud], Telah mengabarkan kepada kami ['Abdurrazaq] Telah mengabarkan kepada kami [Ma'mar] katanya, telah mengabarkan kepadaku [Azzuhri] dari [Ubaidullah bin Abdullah] dari [Ibnu Abbas] radliallahu 'anhuma, bahwasanya Nabi shallallahu 'alaihi wasallam pernah berangkat di bulan Ramadhan dari Madinah bersama sepuluh ribu sahabatnya, itu terjadi tahun kedelapan setengah semenjak tiba beliau di Madinah. Beliau dan kaum muslimin yang bersamanya berangkat ke Makkah berpuasa dan para sahabat juga turut berpuasa, hingga ketika beliau sampai di Kadid yaitu sebuah sumber mata air antara 'Usfan dan Qudaid beliau membatalkan puasanya dan para sahabat juga turut membatalkan puasanya. Komentar Azzuhri, perintah Rasulullah shallallahu 'alaihi wasallam yang diambil (dijadikan pedoman) adalah yang akhir, maka yang terakhir itulah yang dijadikan pedoman amal."},"3667":{"ar":"حَدَّثَنِي عَيَّاشُ بْنُ الْوَلِيدِ حَدَّثَنَا عَبْدُ الْأَعْلَى حَدَّثَنَا خَالِدٌ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَخَرَجَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي رَمَضَانَ إِلَى حُنَيْنٍ وَالنَّاسُ مُخْتَلِفُونَ فَصَائِمٌ وَمُفْطِرٌ فَلَمَّا اسْتَوَى عَلَى رَاحِلَتِهِ دَعَا بِإِنَاءٍ مِنْ لَبَنٍ أَوْ مَاءٍ فَوَضَعَهُ عَلَى رَاحَتِهِ أَوْ عَلَى رَاحِلَتِهِ ثُمَّ نَظَرَ إِلَى النَّاسِ فَقَالَ الْمُفْطِرُونَ لِلصُّوَّامِ أَفْطِرُواوَقَالَ عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ أَيُّوبَ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا خَرَجَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَامَ الْفَتْحِ وَقَالَ حَمَّادُ بْنُ زَيْدٍ عَنْ أَيُّوبَ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepadaku [Ayyats bin Al Walid] Telah menceritakan kepada kami [Abdul A'la] Telah menceritakan kepada kami [Khalid] dari [Ikrimah] dari [Ibnu Abbas] katanya, Nabi shallallahu 'alaihi wasallam berangkat pada bulan Ramadhan menuju Hunain sedang para sahabat ketika itu terpecah menjadi dua kubu, kubu pertama berpuasa sedang kubu kedua tidak puasa. Ketika beliau sudah siap diatas hewan tunggangannya, beliau meminta sebaskom air dan beliau letakkan diatas untanya atau tempat peristirahatannya, kemudian beliau mencermati pasukannya, lalu para sahabat yang tidak puasa berkata kepada para sahabat yang puasa; \"Batalkanlah puasa kalian! [Abdurrazaq] mengatakan, Telah mengabarkan kepada kami [Ma'mar] dari [Ayyub] dari [Ikrimah] dari [Ibnu Abbas] radliallahu 'anhuma, Nabi shallallahu 'alaihi wasallam berangkat di tahun penaklukan Makkah, sedang [Hammad bin Zaid] mengatakan dari [Ayyub] dari [Ikrimah] dari [Ibnu Abbas] dari Nabi shallallahu 'alaihi wasallam."},"3668":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا جَرِيرٌ عَنْ مَنْصُورٍ عَنْ مُجَاهِدٍ عَنْ طَاوُسٍ عَنْ ابْنِ عَبَّاسٍ قَالَسَافَرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي رَمَضَانَ فَصَامَ حَتَّى بَلَغَ عُسْفَانَ ثُمَّ دَعَا بِإِنَاءٍ مِنْ مَاءٍ فَشَرِبَ نَهَارًا لِيُرِيَهُ النَّاسَ فَأَفْطَرَ حَتَّى قَدِمَ مَكَّةَ قَالَ وَكَانَ ابْنُ عَبَّاسٍ يَقُولُ صَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي السَّفَرِ وَأَفْطَرَ فَمَنْ شَاءَ صَامَ وَمَنْ شَاءَ أَفْطَرَ","id":"Telah menceritakan kepada kami [Ali bin Abdullah] Telah menceritakan kepada kami [Jarir] dari [Manshur] dari [Mujahid] dari [Thawus] dari [Ibnu Abbas] katanya, Nabi shallallahu 'alaihi wasallam melakukan safar di bulan Ramadhan lantas beliau puasa, hingga beliau sampai di Usfan, beliau meminta diambilkan sebaskom air dan beliau minum tepat siang hari, ini beliau maksudkan agar para sahabat melihatnya, maka para sahabat pun membatalkan puasanya hingga beliau tiba di Makkah. Kata Thawus, kata Ibnu Abbas, Rasulullah shallallahu 'alaihi wasallam pernah \"Berpuasa\" ketika \"Safar\", pernah juga \"Tidak puasa\", siapa yang puasa, silahkan, siapa yang tidak, juga \"silahkan\", terserah."},"3669":{"ar":"حَدَّثَنَا عُبَيْدُ بْنُ إِسْمَاعِيلَ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ هِشَامٍ عَنْ أَبِيهِ قَالَلَمَّا سَارَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَامَ الْفَتْحِ فَبَلَغَ ذَلِكَ قُرَيْشًا خَرَجَ أَبُو سُفْيَانَ بْنُ حَرْبٍ وَحَكِيمُ بْنُ حِزَامٍ وَبُدَيْلُ بْنُ وَرْقَاءَ يَلْتَمِسُونَ الْخَبَرَ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَقْبَلُوا يَسِيرُونَ حَتَّى أَتَوْا مَرَّ الظَّهْرَانِ فَإِذَا هُمْ بِنِيرَانٍ كَأَنَّهَا نِيرَانُ عَرَفَةَ فَقَالَ أَبُو سُفْيَانَ مَا هَذِهِ لَكَأَنَّهَا نِيرَانُ عَرَفَةَ فَقَالَ بُدَيْلُ بْنُ وَرْقَاءَ نِيرَانُ بَنِي عَمْرٍو فَقَالَ أَبُو سُفْيَانَ عَمْرٌو أَقَلُّ مِنْ ذَلِكَ فَرَآهُمْ نَاسٌ مِنْ حَرَسِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَدْرَكُوهُمْ فَأَخَذُوهُمْ فَأَتَوْا بِهِمْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَسْلَمَ أَبُو سُفْيَانَ فَلَمَّا سَارَ قَالَ لِلْعَبَّاسِ احْبِسْ أَبَا ��ُفْيَانَ عِنْدَ حَطْمِ الْخَيْلِ حَتَّى يَنْظُرَ إِلَى الْمُسْلِمِينَ فَحَبَسَهُ الْعَبَّاسُ فَجَعَلَتْ الْقَبَائِلُ تَمُرُّ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَمُرُّ كَتِيبَةً كَتِيبَةً عَلَى أَبِي سُفْيَانَ فَمَرَّتْ كَتِيبَةٌ قَالَ يَا عَبَّاسُ مَنْ هَذِهِ قَالَ هَذِهِ غِفَارُ قَالَ مَا لِي وَلِغِفَارَ ثُمَّ مَرَّتْ جُهَيْنَةُ قَالَ مِثْلَ ذَلِكَ ثُمَّ مَرَّتْ سَعْدُ بْنُ هُذَيْمٍ فَقَالَ مِثْلَ ذَلِكَ وَمَرَّتْ سُلَيْمُ فَقَالَ مِثْلَ ذَلِكَ حَتَّى أَقْبَلَتْ كَتِيبَةٌ لَمْ يَرَ مِثْلَهَا قَالَ مَنْ هَذِهِ قَالَ هَؤُلَاءِ الْأَنْصَارُ عَلَيْهِمْ سَعْدُ بْنُ عُبَادَةَ مَعَهُ الرَّايَةُ فَقَالَ سَعْدُ بْنُ عُبَادَةَ يَا أَبَا سُفْيَانَ الْيَوْمَ يَوْمُ الْمَلْحَمَةِ الْيَوْمَ تُسْتَحَلُّ الْكَعْبَةُ فَقَالَ أَبُو سُفْيَانَ يَا عَبَّاسُ حَبَّذَا يَوْمُ الذِّمَارِ ثُمَّ جَاءَتْ كَتِيبَةٌ وَهِيَ أَقَلُّ الْكَتَائِبِ فِيهِمْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَصْحَابُهُ وَرَايَةُ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَعَ الزُّبَيْرِ بْنِ الْعَوَّامِ فَلَمَّا مَرَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِأَبِي سُفْيَانَ قَالَ أَلَمْ تَعْلَمْ مَا قَالَ سَعْدُ بْنُ عُبَادَةَ قَالَ مَا قَالَ قَالَ كَذَا وَكَذَا فَقَالَ كَذَبَ سَعْدٌ وَلَكِنْ هَذَا يَوْمٌ يُعَظِّمُ اللَّهُ فِيهِ الْكَعْبَةَ وَيَوْمٌ تُكْسَى فِيهِ الْكَعْبَةُ قَالَ وَأَمَرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ تُرْكَزَ رَايَتُهُ بِالْحَجُونِقَالَ عُرْوَةُ وَأَخْبَرَنِي نَافِعُ بْنُ جُبَيْرِ بْنِ مُطْعِمٍ قَالَ سَمِعْتُ الْعَبَّاسَ يَقُولُ لِلزُّبَيْرِ بْنِ الْعَوَّامِ يَا أَبَا عَبْدِ اللَّهِ هَا هُنَا أَمَرَكَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ تَرْكُزَ الرَّايَةَ قَالَ وَأَمَرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَئِذٍ خَالِدَ بْنَ الْوَلِيدِ أَنْ يَدْخُلَ مِنْ أَعْلَى مَكَّةَ مِنْ كَدَاءٍ وَدَخَلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ كُدَا فَقُتِلَ مِنْ خَيْلِ خَالِدِ بْنِ الْوَلِيدِ رَضِيَ اللَّهُ عَنْهُ يَوْمَئِذٍ رَجُلَانِ حُبَيْشُ بْنُ الْأَشْعَرِ وَكُرْزُ بْنُ جابِرٍ الْفِهْرِيُّ","id":"Telah menceritakan kepada kami [Ubaid bin Ismail] Telah menceritakan kepada kami [Abu Usamah] dari [Hisyam] dari [Ayahnya], katanya, ketika Rasulullah shallallahu 'alaihi wasallam melakukan perjalanan pada penaklukan Makkah, orang-orang Quraisy mendengar berita kepergiannya. Maka Abu Sufyan bin Harb, Hakim bin Hizam dan Budail bin Warqa' langsung memburu berita Rasulullah Shallallahu'alaihiwasallam. Mereka terus melakukan perjalanan hingga sampai Marru Zhahran. Tiba-tiba mereka lihat perapian seolah-olah perapian Arafah. Abu Sufyan berkomentar \"Apa ini, rupanya ia adalah perapian Arafah.\" Sedang Budail bin Warqa' mengtakan \"Itu perapian Banu Amru.\" Sedang Abu Sufyan mengatakan; 'Perapian Banu Amru lebih kecil daripada itu.\" Para penjaga Rasulullah shallallahu 'alaihi wasallam kemudian melihat pembesar-pembesar Quraisy ini, mereka memburunya dan menangkapnya, serta meringkusnya ke hadapan Rasulullah Shallallahu'alaihiwasallam. Rupanya Abu Sufyan kemudian masuk Islam. Ketika Rauslullah shallallahu 'alaihi wasallam melakukan inspeksi pasukan, beliau katakan kepada Abbas; \"Tolong Abu Sufyan engkau tahan di lokasi unta-unta yang dilubangi hidungnya itu sehingga ia bisa bebas mengamati kegiatan kaum muslimin.\" Abbas pun menahan Abu Sufyan, selanjutnya beberapa kabilah lewat bersama Nabi shallallahu 'alaihi wasallam, mereka lewat regu demi regu melewati Abu Sufyan. Sebuah regu kemudian melewatinya dan Abu Sufyan bertanya \"Wahai Abbas, Siapa ini? Abbas menjawab; \"Ini bani Ghifar. Kata Abu Sufyan; Apa urusanku dengan ghifar, aku dan mereka belum pernah terlibat perang.\" Kemudian bani Juhainah lewat dan Abu Sufyan memberi komentar yang sama, Bani Sa'd bin Hudzaim lewat dan Abu Sufyan berkomentar yang sama, bani Sulaim lewat dan Abu Sufyan berkomentar yang sama, hingga lewatlah sebuah regu yang Abu Sufyan belum pernah melihatnya sama sekali.\"Dan siapakah ini?\" Tanya Abu Sufyan. Jawab Abbas; \"Mereka adalah sahabat anshar, yang dipimpin oleh Sa'd bin Ubadah dengan membawa bendera. Sa'd bin Ubadah berujar; \"Wahai Abu Sufyan, hari ini adalah hari peperangan, hari ini ka'bah dihalalkan (tercederai karena perang).\" Lantas Abu Sufyan mengatakan \"Alangkah indah hari pembelaan ini! Kemudian datang sebuah regu yang anggotanya paling sedikit yang diikuti oleh Rasulullah Shallallahu'alaihiwasallam, para sahabatnya, dan bendera Nabi shallallahu 'alaihi wasallam bersama Zubair bin Awwam. Ketika Rasulullah shallallahu 'alaihi wasallam melewati Abu Sufyan, Abu Sufyan berujar \"Tidakkah engkau dengar ucapan Sa'd bin Ubadah?\"Apa yang diucapkannya? Tanya Nabi shallallahu 'alaihi wasallam. Rasulullah shallallahu 'alaihi wasallam menjawab \"Bohong si Sa'd itu, namun yang benar hari ini adalah hari Allah mengagungkan ka'bah, dan hari saat ka'bah agar diberi kiswah (kain penutup ka'bah).\" Lantas Rasulullah shallallahu 'alaihi wasallam memberi intruksi agar bendera kaum muslimin ditancapkan di Hujun. Kata ['Urwah], dan telah mengabarkan kepadaku [Nafi' bin Jubair bin Muth'im] katanya, aku mendengar [Abbas] berujar kepada Zubair bin Awwam; \"Wahai Abu Abdullah, disinilah Rasulullah memerintahkanmu agar bendera ditancapkan.\" Dan Rasulullah shallallahu 'alaihi wasallam perintahkan Khalid bin Walid agar masuk Makkah lewat bagian atas dari Kada\", dan Nabi shallallahu 'alaihi wasallam masuk Makkah melewati Kuda -nama tempat-, pasukan berkuda Khalid bin Walid radliallahu 'anhu ketika itu terbunuh dua orang, Hubaisy bin Al Asy'ar dan Kurz bin Jabir Al Fihri."},"3670":{"ar":"حَدَّثَنَا أَبُو الْوَلِيدِ حَدَّثَنَا شُعْبَةُ عَنْ مُعَاوِيَةَ بْنِ قُرَّةَ قَالَ سَمِعْتُ عَبْدَ اللَّهِ بْنَ مُغَفَّلٍ يَقُولُرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ فَتْحِ مَكَّةَ عَلَى نَاقَتِهِ وَهُوَ يَقْرَأُ سُورَةَ الْفَتْحِ يُرَجِّعُ وَقَالَ لَوْلَا أَنْ يَجْتَمِعَ النَّاسُ حَوْلِي لَرَجَّعْتُ كَمَا رَجَّعَ","id":"Telah menceritakan kepada kami [Abul Walid] Telah menceritakan kepada kami [Syu'bah] dari [Mu'awiyah bin Qurrah] katanya, kudengar [Abdullah bin Mughaffal] mengatakan; aku Pernah melihat Rasulullah shallallahu 'alaihi wasallam pada hari penaklukan Makkah diatas hewan tunggangannya membaca surat Al Fath dan beliau ulang-ulang. Dan Mu'awiyah berkata; \"Kalaulah para sahabat tidak berkumpul di sekitarku, niscaya akan kuulang-ulang sebagaimana Rasulullah mengulang-ulanginya.\""},"3671":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ عَبْدِ الرَّحْمَنِ حَدَّثَنَا سَعْدَانُ بْنُ يَحْيَى حَدَّثَنَا مُحَمَّدُ بْنُ أَبِي حَفْصَةَ عَنْ الزُّهْرِيِّ عَنْ عَلِيِّ بْنِ حُسَيْنٍ عَنْ عَمْرِو بْنِ عُثْمَانَ عَنْ أُسَامَةَ بْنِ زَيْدٍأَنَّهُ قَالَ زَمَنَ الْفَتْحِ يَا رَسُولَ اللَّهِ أَيْنَ تَنْزِلُ غَدًا قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهَلْ تَرَكَ لَنَا عَقِيلٌ مِنْ مَنْزِلٍ ثُمَّ قَالَ لَا يَرِثُ الْمُؤْمِنُ الْكَافِرَ وَلَا يَرِثُ الْكَافِرُ الْمُؤْمِنَقِيلَ لِلزُّهْرِيِّ وَمَنْ وَرِثَ أَبَا طَالِبٍ قَالَ وَرِثَهُ عَقِيلٌ وَطَالِبٌ قَالَ مَعْمَرٌ عَنْ الزُّهْرِيِّ أَيْنَ تَنْزِلُ غَدًا فِي حَجَّتِهِ وَلَمْ يَقُلْ يُونُسُ حَجَّتِهِ وَلَا زَمَنَ الْفَتْحِ","id":"Telah menceritakan kepada kami [Sulaiman bin Abdurrahman] Telah menceritakan kepada kami [Sa'dan bin Yahya] Telah menceritakan kepada kami [Muhammad bin Abu Hafsah] dari [Azzuhri] dari [Ali bin Husain] dari [Amru bin Utsman] dari [Usamah bin Zaid], katanya; \"Sekarang telah tiba penaklukan ya Rasulullah, dimana engkau singgah esok?\" Nabi shallallahu 'alaihi wasallam bersabda: Apakah Aqil meninggalkan persinggahan untuk kita? Lantas beliau sabdakan \"Seorang mukmin tidak mewarisi orang kafir, dan orang kafir tidak mewarisi orang mukmin.\" Ditanyakan kepada Az Zuhri; Lantas siapa yang mewarisi Abu Thalib? Nabi menjawab: \"Yang mewarisinya 'Aqil dan Thalib.\" Kata [Ma'mar] dari [Az Zuhri] dengan redaksi; 'Dimana engkau singgah esok -maksudnya ketika hajinya-? sedang [Yunus] tidak mengatakan lafadz \"Dalam hajinya\" tidak pula ada redaksi \"Jaman penaklukan Makkah.\""},"3672":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ حَدَّثَنَا شُعَيْبٌ حَدَّثَنَا أَبُو الزِّنَادِ عَنْ عَبْدِ الرَّحْمَنِ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْزِلُنَا إِنْ شَاءَ اللَّهُ إِذَا فَتَحَ اللَّهُ الْخَيْفُ حَيْثُ تَقَاسَمُوا عَلَى الْكُفْرِ","id":"Telah menceritakan kepada kami [Abul Yaman] Telah menceritakan kepada kami [Syu'aib] Telah menceritakan kepada kami [Abu Zinad] dari [Abdurrahman] dari [Abu Hurairah] radliallahu 'anhu, katanya Rasulullah shallallahu 'alaihi wasallam bersabda, jika Allah memberi kemenangan, insya Allah persinggahan kita adalah al khaif, tempat yang dahulu dipergunakan orang Quraisy bersumpah untuk melakukan kekafiran."},"3673":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ حَدَّثَنَا إِبْرَاهِيمُ بْنُ سَعْدٍ أَخْبَرَنَا ابْنُ شِهَابٍ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِينَ أَرَادَ حُنَيْنًا مَنْزِلُنَا غَدًا إِنْ شَاءَ اللَّهُ بِخَيْفِ بَنِي كِنَانَةَ حَيْثُ تَقَاسَمُوا عَلَى الْكُفْرِ","id":"Telah menceritakan kepada kami [Musa bin Ismail] Telah menceritakan kepada kami [Ibrahim bin Sa'd] Telah mengabarkan kepada kami [Ibnu Syihab] dari [Abu Salamah] dari [Abu Hurairah] radliallahu 'anhu, katanya, Rasulullah shallallahu 'alaihi wasallam bersabda ketika menuju Hunain; \"Tempat persinggahan kita esok insya Allah di Khaif Bani Kinanah, tempat yang dipergunakan Quraisy untuk bersumpah diatas kekufuran.\""},"3674":{"ar":"حَدَّثَنَا يَحْيَى بْنُ قَزَعَةَ حَدَّثَنَا مَالِكٌ عَنْ ابْنِ شِهَابٍ عَنْ أَنَسِ بْنِ مَالِكٍ رَضِيَ اللَّهُ عَنْهُأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَخَلَ مَكَّةَ يَوْمَ الْفَتْحِ وَعَلَى رَأْسِهِ الْمِغْفَرُ فَلَمَّا نَزَعَهُ جَاءَ رَجُلٌ فَقَالَ ابْنُ خَطَلٍ مُتَعَلِّقٌ بِأَسْتَارِ الْكَعْبَةِ فَقَالَ اقْتُلْهُقَالَ مَالِكٌ وَلَمْ يَكُنْ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِيمَا نُرَى وَاللَّهُ أَعْلَمُ يَوْمَئِذٍ مُحْرِمًا","id":"Telah menceritakan kepada kami [Yahya bin Qaza'ah] Telah menceritakan kepada kami [Malik] Telah mengabarkan kepada kami [Ibnu Syihab] dari [Anas bin Malik] radliallahu 'anhu, katanya Nabi shallallahu 'alaihi wasallam memasuki Makkah pada hari penaklukan Makkah dengan memakai topi besi diatas kepalanya, ketika beliau melepasnya, seorang laki-laki datang dan berujar; \"Itu, si Ibnu Khathal bersembunyi dibalik tirai Ka'bah.\" Spontan Rasulullah shallallahu 'alaihi wasallam berujar \"Bunuhlah dia.\" Kata Malik, setahu kami, Nabi shallallahu 'alaihi wasallam ketika itu tidak dalam keadan ihram, wallahu A'lam."},"3675":{"ar":"حَدَّثَنَا صَدَقَةُ بْنُ الْفَضْلِ أَخْبَرَنَا ابْنُ عُيَيْنَةَ عَنْ ابْنِ أَبِي نَجِيحٍ عَنْ مُجَاهِدٍ عَنْ أَبِي مَعْمَرٍ عَنْ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُ قَالَدَخَلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَكَّةَ يَوْمَ الْفَتْحِ وَحَوْلَ الْبَيْتِ سِتُّونَ وَثَلَاثُ مِائَةِ نُصُبٍ فَجَعَلَ يَطْعُنُهَا بِعُودٍ فِي يَدِهِ وَيَقُولُ{ جَاءَ الْحَقُّ وَزَهَقَ الْبَاطِلُ }{ جَاءَ الْحَقُّ وَمَا يُبْدِئُ الْبَاطِلُ وَمَا يُعِيدُ }","id":"Telah menceritakan kepada kami [Shadaqah bin Fadhl] Telah mengabarkan kepada kami [Ibnu 'Uyainah] dari [Ibnu Abu Najih] dari [Mujahid] dari [Abu Ma'mar] dari [Abdullah] radliallahu 'anhu, katanya, Nabi shallallahu 'alaihi wasallam memasuki Makkah pada penaklukan Makkah yang ketika itu di sekitar ka'bah ada tiga ratus enam puluh patung, lantas beliau porak-porandakan dengan sebongkah kayu di tangannya seraya beliau serukan \"Sekarang telah datang kebenaran dan kebatilan telah musnah.\" (QS. Isra'; 81), \"Sekarang kebenaran telah datang dan kebatilan tak akan terulang dan kembali lagi.\" (QS. Saba': 49)."},"3676":{"ar":"حَدَّثَنِي إِسْحَاقُ حَدَّثَنَا عَبْدُ الصَّمَدِ قَالَ حَدَّثَنِي أَبِي حَدَّثَنَا أَيُّوبُ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَمَّا قَدِمَ مَكَّةَ أَبَى أَنْ يَدْخُلَ الْبَيْتَ وَفِيهِ الْآلِهَةُ فَأَمَرَ بِهَا فَأُخْرِجَتْ فَأُخْرِجَ صُورَةُ إِبْرَاهِيمَ وَإِسْمَاعِيلَ فِ�� أَيْدِيهِمَا مِنْ الْأَزْلَامِ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَاتَلَهُمْ اللَّهُ لَقَدْ عَلِمُوا مَا اسْتَقْسَمَا بِهَا قَطُّ ثُمَّ دَخَلَ الْبَيْتَ فَكَبَّرَ فِي نَوَاحِي الْبَيْتِ وَخَرَجَ وَلَمْ يُصَلِّ فِيهِتَابَعَهُ مَعْمَرٌ عَنْ أَيُّوبَ وَقَالَ وُهَيْبٌ حَدَّثَنَا أَيُّوبُ عَنْ عِكْرِمَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepadaku [Ishaq] Telah menceritakan kepada kami [Abdush Shamad] katanya, telah menceritakan kepadaku [ayahku] Telah menceritakan kepada kami [Ayyub] dari [Ikrimah] dari [Ibnu Abbas] radliallahu 'anhuma, Rasulullah shallallahu 'alaihi wasallam ketika tiba di Makkah, beliau enggan masuk Baitullah (ka'bah) yang ketika itu banyak arca (patung), maka beliau perintahkan agar semua gambar-gambar dibuang, maka dikeluarkanlah gambar Ibrahim dan Ismail yang keduanya digambarkan mengundi nasib dengan anak panah. Lantas Nabi shallallahu 'alaihi wasallam berkomentar: \"Kiranya Allah membinasakan mereka, mereka tahu bahwa Ibrahim dan Ismail sama sekali tak pernah mengundi nasib dengan anak panah.\" Kemudian beliau memasuki Ka'bah dan beliau bertakbir di seluruh penjuru baitullah, lalu beliau keluar dan tidak shalat di dalamnya. Hadist ini dikuatkan jalur perawinya oleh [Ma'mar] dari [Ayyub] dan [Wuhaib] mengatakan, Telah menceritakan kepada kami [Ayyub] dari [Ikrimah] dari Nabi shallallahu 'alaihi wasallam."},"3677":{"ar":"حَدَّثَنَا الْهَيْثَمُ بْنُ خَارِجَةَ حَدَّثَنَا حَفْصُ بْنُ مَيْسَرَةَ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ أَنَّ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا أَخْبَرَتْهُأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَخَلَ عَامَ الْفَتْحِ مِنْ كَدَاءٍ الَّتِي بِأَعْلَى مَكَّةَتَابَعَهُ أَبُو أُسَامَةَ وَوُهَيْبٌ فِي كَدَاءٍ","id":"Telah menceritakan kepada kami [Al Haitsam bin Kharijah] Telah menceritakan kepada kami [Hafs bin Maisarah] dari [Hisyam bin Urwah] dari [ayahnya] bahwasanya [Aisyah] radliallahu 'anhu mengabarinya, Nabi shallallahu 'alaihi wasallam pada tahun penaklukan Makkah masuk melalui Kada' yang terletak di atas Makkah. Hadist ini dikuatkan jalur perawinya oleh [Abu Usamah] dan [Wuhaib] dan khususnya tentang Kada'."},"3678":{"ar":"حَدَّثَنَا عُبَيْدُ بْنُ إِسْمَاعِيلَ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ هِشَامٍ عَنْ أَبِيهِدَخَلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَامَ الْفَتْحِ مِنْ أَعْلَى مَكَّةَ مِنْ كَدَاءٍ","id":"Telah menceritakan kepada kami [Ubaid bin Ismail] Telah menceritakan kepada kami [Abu usamah] dari [Hisyam] dari [ayahnya], Nabi shallallahu 'alaihi wasallam pada tahun penaklukan Makkah masuk dari atas Makkah dari Kada'."},"3679":{"ar":"حَدَّثَنَا أَبُو الْوَلِيدِ حَدَّثَنَا شُعْبَةُ عَنْ عَمْرٍو عَنْ ابْنِ أَبِي لَيْلَىمَا أَخْبَرَنَا أَحَدٌ أَنَّهُ رَأَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي الضُّحَى غَيْرَ أُمِّ هَانِئٍ فَإِنَّهَا ذَكَرَتْ أَنَّهُ يَوْمَ فَتْحِ مَكَّةَ اغْتَسَلَ فِي بَيْتِهَا ثُمَّ صَلَّى ثَمَانِيَ رَكَعَاتٍ قَالَتْ لَمْ أَرَهُ صَلَّى صَلَاةً أَخَفَّ مِنْهَا غَيْرَ أَنَّهُ يُتِمُّ الرُّكُوعَ وَالسُّجُودَ","id":"Telah menceritakan kepada kami [Abul Walid] Telah menceritakan kepada kami [Syu'bah] dari ['Amru] dari [Ibnu Abu Laila], tak seorangpun memberitakan kepada kami bahwa ia melihat Nabi shallallahu 'alaihi wasallam shalat dluha selain ummu Hani\", ialah yang menyebutkan bahwa beliau shallallahu 'alaihi wasallam pada hari penaklukan Makkah mandi di rumahnya kemudian shalat delapan rakaat. Kata [Ummu Hani] \", belum pernah kulihat beliau shalat lebih ringan daripadanya selain beliau menyempurnakan ruku' dan sujud."},"3680":{"ar":"بَاب حَدَّثَنِي مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا غُنْدَرٌ حَدَّثَنَا شُعْبَةُ عَنْ مَنْصُورٍ عَنْ أَبِي الضُّحَى عَنْ مَسْرُوقٍ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ فِي رُكُوعِهِ وَسُجُودِهِ سُبْحَانَكَ اللَّهُمَّ رَبَّنَا وَبِحَمْدِكَ اللَّهُمَّ اغْفِرْ لِي","id":"Telah menceritakan kepadaku [Muhammad bin Basyar] Telah menceritakan kepada kami [Ghundar] Telah menceritakan kepada kami [Syu'bah] dari [Manshur] dari [Abu Dluha] dari [Masruq] dari [Aisyah] radliallahu 'anhuma, katanya, Pernah Nabi shallallahu 'alaihi wasallam dalam ruku'nya dan sujudnya membaca doa SUBHAANAKALLAAHUMMA RABBANAA WABIHAMDIKA ALLAAHUMMAGH FIRLII (Maha Suci ya Allah, Tuhan kami, dan dengan pujian kepada-Mu, ya Allah, ampunilah aku.\""},"3681":{"ar":"حَدَّثَنَا أَبُو النُّعْمَانِ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ أَبِي بِشْرٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَكَانَ عُمَرُ يُدْخِلُنِي مَعَ أَشْيَاخِ بَدْرٍ فَقَالَ بَعْضُهُمْ لِمَ تُدْخِلُ هَذَا الْفَتَى مَعَنَا وَلَنَا أَبْنَاءٌ مِثْلُهُ فَقَالَ إِنَّهُ مِمَّنْ قَدْ عَلِمْتُمْ قَالَ فَدَعَاهُمْ ذَاتَ يَوْمٍ وَدَعَانِي مَعَهُمْ قَالَ وَمَا رُئِيتُهُ دَعَانِي يَوْمَئِذٍ إِلَّا لِيُرِيَهُمْ مِنِّي فَقَالَ مَا تَقُولُونَ فِي{ إِذَا جَاءَ نَصْرُ اللَّهِ وَالْفَتْحُ وَرَأَيْتَ النَّاسَ يَدْخُلُونَ فِي دِينِ اللَّهِ أَفْوَاجًا }حَتَّى خَتَمَ السُّورَةَ فَقَالَ بَعْضُهُمْ أُمِرْنَا أَنْ نَحْمَدَ اللَّهَ وَنَسْتَغْفِرَهُ إِذَا نُصِرْنَا وَفُتِحَ عَلَيْنَا وَقَالَ بَعْضُهُمْ لَا نَدْرِي أَوْ لَمْ يَقُلْ بَعْضُهُمْ شَيْئًا فَقَالَ لِي يَا ابْنَ عَبَّاسٍ أَكَذَاكَ تَقُولُ قُلْتُ لَا قَالَ فَمَا تَقُولُ قُلْتُ هُوَ أَجَلُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَعْلَمَهُ اللَّهُ لَهُ{ إِذَا جَاءَ نَصْرُ اللَّهِ وَالْفَتْحُ }فَتْحُ مَكَّةَ فَذَاكَ عَلَامَةُ أَجَلِكَ{ فَسَبِّحْ بِحَمْدِ رَبِّكَ وَاسْتَغْفِرْهُ إِنَّهُ كَانَ تَوَّابًا }قَالَ عُمَرُ مَا أَعْلَمُ مِنْهَا إِلَّا مَا تَعْلَمُ","id":"Telah menceritakan kepada kami [Abu Nu'man] Telah menceritakan kepada kami [Abu 'Awanah] dari [Abu Bisyr] dari [Said bin Jubair] dari [Ibnu Abbas] radliallahu 'anhuma, Umar Pernah mengajakku dalam sebuah majlis orang dewasa, sehingga sebagian sahabat bertanya \"Mengapa si anak kecil ini kau ikut sertakan, kami juga punya anak-anak kecil seperti dia?\" Umar menjawab; \"Kalian maklum, anak ini punya \"kualitas\" tersendiri.\" Kata Ibnu Umar, maka suatu hari Umar mengundang mereka dan mengajakku bersama mereka. Seingatku, Umar tidak mengajakku saat itu selain untuk mempertontonkan kepada mereka kualitas keilmuanku. Lantas Umar bertanyal; \"Bagaimana komentar kalian tentang ayat \"Seandainya pertolongan Allah dan kemenangan datang (1) dan kau lihat manusia masuk agama Allah dengan berbondong-bondong (2) -hingga ahkir surat (QS. Alfath 1-3). Sebagian sahabat berkomentar; \"Tentang ayat ini, setahu kami, kita diperintahkan agar memuji Allah dan meminta ampunan kepada-Nya, tepatnya ketika kita diberi pertolongan dan diberi kemenangan.\" Sebagian lagi berkomentar; \"kalau kami nggak tahu.\" Atau bahkan tidak berkomentar sama sekali. Lantas Umar bertanya kepadaku; \"Wahai Ibnu Abbas, beginikah kamu berkomentar mengenai ayat tadi?\"TIDAK\" Jawabku.\"Lalu komentarmu? Tanya Umar. Ibnu Abbas menjawab; \"Surat tersebut adalah pertanda wafat Rasulullah shallallahu 'alaihi wasallam sudah dekat, Allah memberitahunya dengan ayatnya: \"Jika telah datang pertolongan Allah dan kemenangan', itu berarti penaklukan Makkah dan itulah tanda ajalmu (Muhammad), karenanya \"Bertasbihlah dengan memuji Tuhanmu dan mohonlah ampunan, sesungguhnya Dia Maha Menerima taubat. Kata Umar, \"Aku tidak tahu penafsiran ayat tersebut selain seperti yang kamu (Ibnu Abbas) ketahui.\""},"3682":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ شُرَحْبِيلَ حَدَّثَنَا اللَّيْثُ عَنْ الْمَقْبُرِيِّ عَنْ أَبِي شُرَيْحٍ الْعَدَوِيِّأَنَّهُ قَالَ لِعَمْرِو بْنِ سَعِيدٍ وَهُوَ يَبْعَثُ الْبُعُوثَ إِلَى مَكَّةَ ائْذَنْ لِي أَيُّهَا الْأَمِيرُ أُحَدِّثْكَ قَوْلًا قَامَ بِهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْغَدَ يَوْمَ الْفَتْحِ سَمِعَتْهُ أُذُنَايَ وَوَعَاهُ قَلْبِي وَأَبْصَرَتْهُ عَيْنَايَ حِينَ تَكَلَّمَ بِهِ إِنَّهُ حَمِدَ اللَّهَ وَأَثْنَى عَلَيْهِ ثُمَّ قَالَ إِنْ مَكَّةَ حَرَّمَهَا اللَّهُ وَلَمْ يُحَرِّمْهَا النَّاسُ لَا يَحِلُّ لِامْرِئٍ يُؤْمِنُ بِاللَّهِ وَالْيَوْمِ الْآخِرِ أَنْ يَسْفِكَ بِهَا دَمًا وَلَا يَعْضِدَ بِهَا شَجَرًا فَإِنْ أَحَدٌ تَرَخَّصَ لِقِتَالِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِيهَا فَقُولُوا لَهُ إِنَّ اللَّهَ أَذِنَ لِرَسُولِهِ وَلَمْ يَأْذَنْ لَكُمْ وَإِنَّمَا أَذِنَ لِي فِيهَا سَاعَةً مِنْ نَهَارٍ وَقَدْ عَادَتْ حُرْمَتُهَا الْيَوْمَ كَحُرْمَتِهَا بِالْأَمْسِ وَلْيُبَلِّغْ الشَّاهِدُ الْغَائِبَ فَقِيلَ لِأَبِي شُرَيْحٍ مَاذَا قَالَ لَكَ عَمْرٌو قَالَ قَالَ أَنَا أَعْلَمُ بِذَلِكَ مِنْكَ يَا أَبَا شُرَيْحٍ إِنَّ الْحَرَمَ لَا يُعِيذُ عَاصِيًا وَلَا فَارًّا بِدَمٍ وَلَا فَارًّا بِخَرْبَةٍ قَالَ أَبُو عَبْد اللَّهِ الْخَرْبَةُ الْبَلِيَّةُ","id":"Telah menceritakan kepada kami [Sa'id bin Syurahbil] Telah menceritakan kepada kami [Al Laits] dari [Al Maqburi] dari [Abu Syuraikh Al'Adawi], ia berkata kepada Amru bin Said yang ketika itu ia mengirim beberapa utusan ke Makkah; \"Wahai Amir, izinkanlah aku mengajakmu bicara suatu hal yang akan diucapkan Rasulullah shallallahu 'alaihi wasallam besok pada penaklukan Makkah, yang kudengar dengan kedua telingaku dan diperhatikan oleh hatiku serta dilihat oleh kedua mataku ketika beliau mengucapkannya. Beliau memanjatkan pujian dan sanjungan kepada Allah lantas berujar: \"Sesungguhnya Makkah telah Allah sucikan dan manusia tidak mensucikannya sebelumnya, tidak halal bagi seseorang yang beriman kepada Allah dan hari akhir untuk menumpahkan darah di sana, tidak pula menebang pohon, kalaulah seorang berkilah bahwa Rasulullah pernah memberi keringanan untuk perang, katakan padanya: 'Allah mengijznkan khusus untuk Rasul-Nya dan tidak mengizinkan untuk kalian, dan Allah pun mengizinkannya hanya beberapa saat ketika siang, dan kesuciannya telah kembali hari ini sebagaimana kesucian kemarin, hendaklah yang menyaksikan untuk menyampaikan yang tidak hadir.\" Ditanyakan kepada Abu Syuraikh; \"Apa yang Amru ucapkan kepadamu? Jawabnya; \"Aku lebih tahu terhadapnya wahai Abu Syuraikh, sesungguhnya tanah haram tidak akan melindungi pelaku kemaksiatan dan tidak pula manusia yang lari menumpahkan darah dan tidak pula yang lari melakukan penghancuran-penghancuran.\" Kata Abu Abdullah, makna Kharibah adalah bencana (kehancuran)."},"3683":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا اللَّيْثُ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ عَنْ عَطَاءِ بْنِ أَبِي رَبَاحٍ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُمَاأَنَّهُ سَمِعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ عَامَ الْفَتْحِ وَهُوَ بِمَكَّةَ إِنَّ اللَّهَ وَرَسُولَهُ حَرَّمَ بَيْعَ الْخَمْرِ","id":"Telah menceritakan kepada kami [Qutaibah] Telah menceritakan kepada kami [Al Laits] dari [Yazid bin Abu Habib] dari ['Atha' bin Abu Rabah] dari [Jabir bin Abdullah] radliallahu 'anhuma, ia mendengar Rasulullah shallallahu 'alaihi wasallam bersabda pada tahun penaklukan Makkah yang ketika itu beliau di Makkah: \"Allah dan Rasulnya mengharamkan jual beli Khamar (minuman keras)."},"3684":{"ar":"حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا سُفْيَانُ ح حَدَّثَنَا قَبِيصَةُ حَدَّثَنَا سُفْيَانُ عَنْ يَحْيَى بْنِ أَبِي إِسْحَاقَ عَنْ أَنَسٍ رَضِيَ اللَّهُ عَنْهُ قَالَأَقَمْنَا مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَشْرًا نَقْصُرُ الصَّلَاةَ","id":"Telah menceritakan kepada kami [Abu Nu'aim] Telah menceritakan kepada kami [Sufyan] -lewat jalur periwayatan lain-Telah menceritakan kepada kami [Qabishah] telah menceritakan kepada kami [Sufyan] dari [Yahya bin Abu Ishaq] dari [Anas] radliallahu 'anhu, katanya, kami bermukim bersama Nabi shallallahu 'alaihi wasallam sepuluh hari, dan sekian hari itu kami melakukan qashar."},"3685":{"ar":"حَدَّثَنَا عَبْدَانُ أَخْبَرَنَا عَبْدُ اللَّهِ أَخْبَرَنَا عَاصِمٌ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَأَقَامَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمَكَّةَ تِسْعَةَ عَشَرَ يَوْمًا يُصَلِّي رَكْعَتَيْنِ","id":"Telah menceritakan kepada kami [Abdan] Telah mengabarkan kepada kami [Abdullah] Telah mengabarkan kepada kami ['Ashim] dari [Ikrimah] dari [Ibnu Abbas] radliallahu 'anhu katanya, Nabi shallallahu 'alaihi wasallam pernah diam di Makkah selama sembilan belas hari dan selama itu pula beliau lakukan shalat dua rakaat."},"3686":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ يُونُسَ حَدَّثَنَا أَبُو شِهَابٍ عَنْ عَاصِمٍ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَأَقَمْنَا مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي سَفَرٍ تِسْعَ عَشْرَةَ نَقْصُرُ الصَّلَاةَ وَقَالَ ابْنُ عَبَّاسٍ وَنَحْنُ نَقْصُرُ مَا بَيْنَنَا وَبَيْنَ تِسْعَ عَشْرَةَ فَإِذَا زِدْنَا أَتْمَمْنَا","id":"Telah menceritakan kepada kami [Ahmad bin Yunus] Telah menceritakan kepada kami [Abu Syihab] dari ['Ashim] dari [Ikrimah] dari [Ibnu Abbas] katanya, kami tinggal bersama Nabi shallallahu 'alaihi wasallam dalam sebuah safar selama sembilan belas hari, yang sekian lama itu pula kami lakukan qashar. Kata Ibnu Abbas, dan kami melakukan qashar ketika kami bermukim sekitar selama sembilan belas hari, namun apabila lebih, tentu kami lakukan shalat dengan sempurna.\""},"3687":{"ar":"حَدَّثَنِي إِبْرَاهِيمُ بْنُ مُوسَى أَخْبَرَنَا هِشَامٌ عَنْ مَعْمَرٍ عَنْ الزُّهْرِيِّ عَنْ سُنَيْنٍ أَبِي جَمِيلَةَ قَالَ أَخْبَرَنَاوَنَحْنُ مَعَ ابْنِ الْمُسَيَّبِ قَالَ وَزَعَمَ أَبُو جَمِيلَةَ أَنَّهُ أَدْرَكَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَخَرَجَ مَعَهُ عَامَ الْفَتْحِ","id":"Telah menceritakan kepadaku [Ibrahim bin Musa] Telah mengabarkan kepada kami [Hisyam] dari [Ma'mar] dari [Az Zuhri] dari [Sunain Abu Jamilah] katanya, Telah mengabarkan kepada kami yang ketika itu kami bersama Ibnul Musayyab, kata Sunain, dan Abu Jamilah berpendapat bahwa ia temui Nabi shallallahu 'alaihi wasallam dan ia berangkat bersama beliau ketika tahun penaklukan Makkah."},"3688":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ أَيُّوبَ عَنْ أَبِي قِلَابَةَ عَنْ عَمْرِو بْنِ سَلَمَةَ قَالَقَالَ لِي أَبُو قِلَابَةَ أَلَا تَلْقَاهُ فَتَسْأَلَهُ قَالَ فَلَقِيتُهُ فَسَأَلْتُهُ فَقَالَ كُنَّا بِمَاءٍ مَمَرَّ النَّاسِ وَكَانَ يَمُرُّ بِنَا الرُّكْبَانُ فَنَسْأَلُهُمْ مَا لِلنَّاسِ مَا لِلنَّاسِ مَا هَذَا الرَّجُلُ فَيَقُولُونَ يَزْعُمُ أَنَّ اللَّهَ أَرْسَلَهُ أَوْحَى إِلَيْهِ أَوْ أَوْحَى اللَّهُ بِكَذَا فَكُنْتُ أَحْفَظُ ذَلِكَ الْكَلَامَ وَكَأَنَّمَا يُقَرُّ فِي صَدْرِي وَكَانَتْ الْعَرَبُ تَلَوَّمُ بِإِسْلَامِهِمْ الْفَتْحَ فَيَقُولُونَ اتْرُكُوهُ وَقَوْمَهُ فَإِنَّهُ إِنْ ظَهَرَ عَلَيْهِمْ فَهُوَ نَبِيٌّ صَادِقٌ فَلَمَّا كَانَتْ وَقْعَةُ أَهْلِ الْفَتْحِ بَادَرَ كُلُّ قَوْمٍ بِإِسْلَامِهِمْ وَبَدَرَ أَبِي قَوْمِي بِإِسْلَامِهِمْ فَلَمَّا قَدِمَ قَالَ جِئْتُكُمْ وَاللَّهِ مِنْ عِنْدِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَقًّا فَقَالَ صَلُّوا صَلَاةَ كَذَا فِي حِينِ كَذَا وَصَلُّوا صَلَاةَ كَذَا فِي حِينِ كَذَا فَإِذَا حَضَرَتْ الصَّلَاةُ فَلْيُؤَذِّنْ أَحَدُكُمْ وَلْيَؤُمَّكُمْ أَكْثَرُكُمْ قُرْآنًا فَنَظَرُوا فَلَمْ يَكُنْ أَحَدٌ أَكْثَرَ قُرْآنًا مِنِّي لِمَا كُنْتُ أَتَلَقَّى مِنْ الرُّكْبَانِ فَقَدَّمُونِي بَيْنَ أَيْدِيهِمْ وَأَنَا ابْنُ سِتٍّ أَوْ سَبْعِ سِنِينَ وَكَانَتْ عَلَيَّ بُرْدَةٌ كُنْتُ إِذَا سَجَدْتُ تَقَلَّصَتْ عَنِّي فَقَالَتْ امْرَأَةٌ مِنْ الْحَيِّ أَلَا تُغَطُّوا عَنَّا اسْتَ قَارِئِكُمْ فَاشْتَزَوْا فَقَطَعُوا لِي قَمِيصًا فَمَا فَرِحْتُ بِشَيْءٍ فَرَحِي بِذَلِكَ الْقَمِيصِ","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] Telah menceritakan kepada kami [Hammad bin Zaid] dari [Ayyub] dari [Abu Qilabah] dari [Amru bin Salamah] katanya, Abu Qilabah mengatakan kepadaku; \"Tidakkah engkau temui Abu Qilabah dan kamu tanyai? maka aku tanyai Abu Qilabah dan ia berujar: \"Kami Pernah di sebuah mata air tempat berlalu lalang manusia, para pengendara sering melewati kami, maka kami menanyai mereka; \"Apa yang terjadi pada orang-orang, dan bagaimana kabar sebenarnya tentang si laki-laki itu (maksudnya Muhammad)? Mereka jawab; Ia (Muhammad) telah mengaku bahwa Allah telah mengutusnya dan memberi wahyu kepadanya, Allah memberinya wahyu dengan demikian. Dan aku lebih hafal terhadap pembicaraan itu. Seolah-olah pembicaran itu mengesankan dalam hatiku dan orang arab mencela habis-habisan kemenangan karena keIslaman mereka. Lantas mereka katakana; \"Biarkan saja dia (Muhammad) dan kaumnya, kalaulah dia menang terhadap kaumnya, berarti ia betul-betul Nabi shallallahu 'alaihi wasallam yang jujur, ketika pelaku-pelaku kemenangan (kaum muslimin) singgah sebentar lantas berangkat, setiap kaum bergegas berangkat dengan keIslaman mereka, dan ayahku bergegas menemui kaumku dengan keIslaman mereka, ketika ayahku datang, ujarnya: \"Demi Allah, sungguh aku baru saja menemui Nabi shallallahu 'alaihi wasallam dan beliau sabdakan: \"Shalatlah kalian sedemikian, di waktu sedemikian. Jika waktu shalat tiba, hendaklah salah seorang diantara kalian mengumandangkan adzan, dan yang mengimami kalian yang banyak hapalan alqurannya. Lantas mereka saling mencermati, dan tak ada yang lebih banyak hapalan al Qurannya selain diriku disebabkan aku bertemu dengan pengendara, maka kemudian mereka menyuruhku maju (memimpin shalat di depan mereka), padahal umurku ketika itu baru enam atau tujuh tahun, ketika itu aku memakai kain apabila aku bersujud, kain itu tersingkap dariku. Maka salah seorang wanita kampung mengajukan saran; \"Tidak sebaiknya kalian tutup dubur ahli-ahli qira'ah kalian?\" Maka mereka langsung membeli dan memotong gamis untukku, sehingga tak ada yang menandingi kegembiraanku daripada kegembiraanku terhadap gamis itu."},"3689":{"ar":"حَدَّثَنِي عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ عَنْ مَالِكٍ عَنْ ابْنِ شِهَابٍ عَنْ عُرْوَةَ بْنِ الزُّبَيْرِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَالَ اللَّيْثُ حَدَّثَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ أَخْبَرَنِي عُرْوَةُ بْنُ الزُّبَيْرِ أَنَّ عَائِشَةَ قَالَتْكَانَ عُتْبَةُ بْنُ أَبِي وَقَّاصٍ عَهِدَ إِلَى أَخِيهِ سَعْدٍ أَنْ يَقْبِضَ ابْنَ وَلِيدَةِ زَمْعَةَ وَقَالَ عُتْبَةُ إِنَّهُ ابْنِي فَلَمَّا قَدِمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَكَّةَ فِي الْفَتْحِ أَخَذَ سَعْدُ بْنُ أَبِي وَقَّاصٍ ابْنَ وَلِيدَةِ زَمْعَةَ فَأَقْبَلَ بِهِ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَقْبَلَ مَعَهُ عَبْدُ بْنُ زَمْعَةَ فَقَالَ سَعْدُ بْنُ أَبِي وَقَّاصٍ هَذَا ابْنُ أَخِي عَهِدَ إِلَيَّ أَنَّهُ ابْنُهُ قَالَ عَبْدُ بْنُ زَمْعَةَ يَا رَسُولَ اللَّهِ هَذَا أَخِي هَذَا ابْنُ زَمْعَةَ وُلِدَ عَلَى فِرَاشِهِ فَنَظَرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى ابْنِ وَلِيدَةِ زَمْعَةَ فَإِذَا أَشْبَهُ النَّاسِ بِعُتْبَةَ بْنِ أَبِي وَقَّاصٍ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هُوَ لَكَ هُوَ أَخُوكَ يَا عَبْدُ بْنَ زَمْعَةَ مِنْ أَجْلِ أَنَّهُ وُلِدَ عَلَى فِرَاشِهِ وَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ احْتَجِبِي مِنْهُ يَا سَوْدَةُ لِمَا رَأَى مِنْ شَبَهِ عُتْبَةَ بْنِ أَبِي وَقَّاصٍ قَالَ ابْنُ شِهَابٍ قَالَتْ عَائِشَةُ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْوَلَدُ لِلْفِرَاشِ وَلِلْعَاهِرِ الْحَجَرُوَقَالَ ابْنُ شِهَابٍ وَكَانَ أَبُو هُرَيْرَةَ يَصِيحُ بِذَلِكَ","id":"Telah menceritakan kepadaku [Abdullah bin Maslamah] dari [Malik] dari [Ibnu Syihab] dari [Urwah bin Zubair] dari [Aisyah] radliallahu 'anhuma, dari Nabi shallallahu 'alaihi wasallam, kata [Al Laits], telah menceritakan kepadaku [Yunus] dari [Ibnu Syihab] Telah mengabarkan kepada kami ['Urwah bin Zubair] bahwasanya ['Aisyah] mengatakan, Utbah bin Abu Waqash berpesan serius kepada saudaranya Sa'd bin Abi Waqqash agar mengambil anak hamba sahaya Zam'ah. Utbah berujar \"Anak laki-laki hamba sahaya Zam'ah adalah sebenarnya anakku. Maka ketika Sa'd bin Abu Waqqash tiba di Makkah saat penaklukan makkah, Sa'd bin Abu Waqqash mengambil anak hamba sahaya Zam'ah dan membawanya kepada Rasulullah shallallahu 'alaihi wasallam sekaligus Abd bin Zam'ah (anak laki-laki Zam'ah) juga menghadirinya. Sa'd bin Abu Waqqash menyampaikan; \"Ini adalah anak saudaraku, ia berpesan serius kepadaku (agar mengambilnya, sebab) anak itu adalah anaknya. Maka Abd bin Zam'ah (anak laki-laki Zam'ah) tak mau kalah dengan mengatakan \"Wahai Rasulullah, ini adalah saudara laki-lakiku, dia dilahirkan diatas kasurnya (kasur Zam'ah). Lantas Rasulullah shallallahu 'alaihi wasallam mencermati anak hamba sahaya Zam'ah yang menyerupai Utbah bin Abu Waqqash. Namun anehnya Rasulullah terus mengatakan kepada abd bin Zam'ah \"Anak itu justru bagimu, dia adalah saudara laki-lakimu wahai Abd bin Zam'ah sebab dia dilahirkan diatas kasurnya (kasur Zam'ah) \". Lantas Rasulullah shallallahu 'alaihi wasallam bersabda: \"Berrhijablah engkau daripadanya wahai Saudah, yang demikian karena beliau lihat ada kemiripan dengan Utbah bin Abu Waqqash. Kata Ibnu Syihab, kata Aisyah; Rasulullah shallallahu 'alaihi wasallam bersabda; \"Anak adalah pemilik kasur, pezina harus dihukum batu (rajam). Kata [Ibnu Syihab], dan [Abu Hurairah] berteriak ketika menyampaikan hadits ini."},"3690":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ مُقَاتِلٍ أَخْبَرَنَا عَبْدُ اللَّهِ أَخْبَرَنَا يُونُسُ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي عُرْوَةُ بْنُ الزُّبَيْرِأَنَّ امْرَأَةً سَرَقَتْ فِي عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي غَزْوَةِ الْفَتْحِ فَفَزِعَ قَوْمُهَا إِلَى أُسَامَةَ بْنِ زَيْدٍ يَسْتَشْفِعُونَهُ قَالَ عُرْوَةُ فَلَمَّا كَلَّمَهُ أُسَامَةُ فِيهَا تَلَوَّنَ وَجْهُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَتُكَلِّمُنِي فِي حَدٍّ مِنْ حُدُودِ اللَّهِ قَالَ أُسَامَةُ اسْتَغْفِرْ لِي يَا رَسُولَ اللَّهِ فَلَمَّا كَانَ الْعَشِيُّ قَامَ رَسُولُ اللَّهِ خَطِيبًا فَأَثْنَى عَلَى اللَّهِ بِمَا هُوَ أَهْلُهُ ثُمَّ قَالَ أَمَّا بَعْدُ فَإِنَّمَا أَهْلَكَ النَّاسَ قَبْلَكُمْ أَنَّهُمْ كَانُوا إِذَا سَرَقَ فِيهِمْ الشَّرِيفُ تَرَكُوهُ وَإِذَا سَرَقَ فِيهِمْ الضَّعِيفُ أَقَامُوا عَلَيْهِ الْحَدَّ وَالَّذِي نَفْسُ مُحَمَّدٍ بِيَدِهِ لَوْ أَنَّ فَاطِمَةَ بِنْتَ مُحَمَّدٍ سَرَقَتْ لَقَطَعْتُ يَدَهَا ثُمَّ أَمَرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِتِلْكَ الْمَرْأَةِ فَقُطِعَتْ يَدُهَا فَحَسُنَتْ تَوْبَتُهَا بَعْدَ ذَلِكَ وَتَزَوَّجَتْ قَالَتْ عَائِشَةُ فَكَانَتْ تَأْتِي بَعْدَ ذَلِكَ فَأَرْفَعُ حَاجَتَهَا إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Muhammad bin Muqatil] Telah mengabarkan kepada kami [Abdullah] Telah mengabarkan kepada kami [Yunus] dari [Az Zuhri] katanya, Telah mengabarkan kepada kami [Urwah bin Zubair], ada seorang wanita mencuri di masa Rasulullah shallallahu 'alaihi wasallam tepatnya ketika terjadi penaklukan Makkah. Kaumnya merasa gelisah atas kasus ini sehingga melakukan perundingan dengan Usamah bin Zaid dengan harapan mereka bisa minta keringanan hukuman melalui perantaranya. Kata Urwah, ketika Usamah melaporkan kasusnya kepada Rasulullah dan meminta keringanan, wajah Rasulullah nampak berubah (pertanda bangkit emosinya). Lantas Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apakah kalian akan mengajakku melakukan \"kompromi\" terhadap hukum Allah? Usamah langsung insaf dengan mengatakan \"Mintalah ampunan untukku wahai Rasulullah? Sore harinya, Rasulullah shallallahu 'alaihi wasallam berpidato, memuji Allah dengan pujian yang semestinya bagi-Nya kemudian berujar: \"Hadirin yang dihormati, manusia sebelum kalian telah celaka sebab jika yang mencuri kalangan atas (pejabat, bangsawan, elit politik) maka mereka membiarkannya, sebaliknya jika yang mencuri masyarakat biasa (golongan rendah, borjuis, tak berpangkat), mereka menegakkan hukuman. Demi Dzat yang diri-ku berada di tangan-NYA, kalaulah Fathimah binti Muhammad mencuri, niscaya kupotong tangannya. Kemudian Rasulullah shallallahu 'alaihi wasallam memerintahkan wanita itu sehingga dipotong tangannya, dikemudian hari ia menindaklanjuti taubatnya dengan baik dan menikah. Kata [Aisyah], dikemudian hari si wanita datang dan kulaporkan keperluannya kepada Rasulullah Shallallahu'alaihiwasallam."},"3691":{"ar":"حَدَّثَنَا عَمْرُو بْنُ خَالِدٍ حَدَّثَنَا زُهَيْرٌ حَدَّثَنَا عَاصِمٌ عَنْ أَبِي عُثْمَانَ قَالَ حَدَّثَنِي مُجَاشِعٌ قَالَأَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِأَخِي بَعْدَ الْفَتْحِ قُلْتُ يَا رَسُولَ اللَّهِ جِئْتُكَ بِأَخِي لِتُبَايِعَهُ عَلَى الْهِجْرَةِ قَالَ ذَهَبَ أَهْلُ الْهِجْرَةِ بِمَا فِيهَا فَقُلْتُ عَلَى أَيِّ شَيْءٍ تُبَايِعُهُ قَالَ أُبَايِعُهُ عَلَى الْإِسْلَامِ وَالْإِيمَانِ وَالْجِهَادِفَلَقِيتُ مَعْبَدًا بَعْدُ وَكَانَ أَكْبَرَهُمَا فَسَأَلْتُهُ فَقَالَ صَدَقَ مُجَاشِعٌ","id":"Telah menceritakan kepada kami [Amru bin Khalid] Telah menceritakan kepada kami [Zuhair] Telah menceritakan kepada kami ['Ashim] dari [Abu Utsman] katanya, telah menceritakan kepadaku [Mujasyi'] katanya, aku menemui Nabi shallallahu 'alaihi wasallam dengan sauadaraku setelah penaklukan Makkah, kukatakan: \"Wahai Rasulullah, aku menemuimu dengan saudaraku agar engkau membaiatnya untuk hijrah. Jawab Nabi; \"Pelaku-pelaku hijrah telah membawa semua ganjarannya.\" Lantas saya bertanya; \"Lalu untuk apa engkau membaiatnya? beliau jawab; \"Saya membaiatnya untuk Islam, iman dan jihad. diKemudian hari kutemui [Ma'bad] yang ia lebih dewasa diantara keduanya. Ia menjawab \"Mujasyi' memang benar.\""},"3692":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ أَبِي بَكْرٍ حَدَّثَنَا الْفُضَيْلُ بْنُ سُلَيْمَانَ حَدَّثَنَا عَاصِمٌ عَنْ أَبِي عُثْمَانَ النَّهْدِيِّ عَنْ مُجَاشِعِ بْنِ مَسْعُودٍانْطَلَقْتُ بِأَبِي مَعْبَدٍ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِيُبَايِعَهُ عَلَى الْهِجْرَةِ قَالَ مَضَتْ الْهِجْرَةُ لِأَهْلِهَا أُبَايِعُهُ عَلَى الْإِسْلَامِ وَالْجِهَادِفَلَقِيتُ أَبَا مَعْبَدٍ فَسَأَلْتُهُ فَقَالَ صَدَقَ مُجَاشِعٌ وَقَالَ خَالِدٌ عَنْ أَبِي عُثْمَانَ عَنْ مُجَاشِعٍ أَنَّهُ جَاءَ بِأَخِيهِ مُجَالِدٍ","id":"Telah menceritakan kepada kami [Muhammad bin Abu Bakar] Telah menceritakan kepada kami [Fudhail bin Sulaiman] Telah menceritakan kepada kami ['Ashim] dari [Abu Utsman An Nahdi] dari [Mujasyi' bin Mas'ud] aku berangkat bersama Abu Ma'bad menemui Nabi shallallahu 'alaihi wasallam dengan niat agar beliau membai'atnya untuk hijrah. Kata Nabi; \"Hijrah telah berlalu bagi pelaku-pelakunya, saya memba'iatnya untuk Islam dan jihad.\" diKemudian hari kutemui [Abu Ma'bad] dan aku menanyainya, lantas ia berujar \" [Mujasyi'] benar.\" Sedang [Khalid] mengatakan dari [Abu Utsman] dari [Mujasyi'], bahwa ia datang bersama saudaranya, Mujalid."},"3693":{"ar":"حَدَّثَنِي مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا غُنْدَرٌ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي بِشْرٍ عَنْ مُجَاهِدٍ قُلْتُ لِابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاإِنِّي أُرِيدُ أَنْ أُهَاجِرَ إِلَى الشَّأْمِ قَالَ لَا هِجْرَةَ وَلَكِنْ جِهَادٌ فَانْطَلِقْ فَاعْرِضْ نَفْسَكَ فَإِنْ وَجَدْتَ شَيْئًا وَإِلَّا رَجَعْتَوَقَالَ النَّضْرُ أَخْبَرَنَا شُعْبَةُ أَخْبَرَنَا أَبُو بِشْرٍ سَمِعْتُ مُجَاهِدًا قُلْتُ لِابْنِ عُمَرَ فَقَالَ لَا هِجْرَةَ الْيَوْمَ أَوْ بَعْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِثْلَهُ","id":"Telah menceritakan kepadaku [Muhammad bin Basyar] Telah menceritakan kepada kami [Ghundar] Telah menceritakan kepada kami [Syu'bah] dari [Abu Bisyr] dari [Mujahid] saya berkata kepada [Ibnu Umar] radliallahu 'anhuma, saya ingin hijrah ke Syam, lantas beliau mengatakan; \"Tak ada hijrah lagi, namun yang ada adalah jihad, maka pergilah sana siapa tahu engkau mendapat sesuatu yang mengganjal, kalaulah tidak, silahkan kembali.\" Kata [An Nadhr], Telah mengabarkan kepada kami [Syu'bah] Telah mengabarkan kepada kami [Abu Bisyr] aku mendengar [Mujahid], saya bertanya [Ibnu Umar] dan beliau jawab; \"Tak ada hijrah lagi setelah hari ini\" atau setelah Rasulullah shallallahu 'alaihi wasallam -semisalnya-."},"3694":{"ar":"حَدَّثَنِي إِسْحَاقُ بْنُ يَزِيدَ حَدَّثَنَا يَحْيَى بْنُ حَمْزَةَ قَالَ حَدَّثَنِي أَبُو عَمْرٍو الْأَوْزَاعِيُّ عَنْ عَبْدَةَ بْنِ أَبِي لُبَابَةَ عَنْ مُجَاهِدِ بْنِ جَبْرٍ الْمَكِّيِّ أَنَّ عَبْدَ اللَّهِ بْنَ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاكَانَ يَقُولُ لَا هِجْرَةَ بَعْدَ الْفَتْحِ","id":"Telah menceritakan kepadaku [Ishaq bin Yazid] Telah menceritakan kepada kami [Yahya bin Hamzah] katanya, Telah menceritakan kepadaku [Abu Amru, Auza'i] dari [Abdah bin Abu Lubabah] dari [Mujahid bin Jabr Al Makki] bahwasanya [Abdullah bin Umar] radliallahu 'anhuma mengatakan; \"Tak ada lagi hijrah setelah kemenangan.\""},"3695":{"ar":"حَدَّثَنَا إِسْحَاقُ بْنُ يَزِيدَ حَدَّثَنَا يَحْيَى بْنُ حَمْزَةَ قَالَ حَدَّثَنِي الْأَوْزَاعِيُّ عَنْ عَطَاءِ بْنِ أَبِي رَبَاحٍ قَالَ زُرْتُ عَائِشَةَمَعَ عُبَيْدِ بْنِ عُمَيْرٍ فَسَأَلَهَا عَنْ الْهِجْرَةِ فَقَالَتْ لَا هِجْرَةَ الْيَوْمَ كَانَ الْمُؤْمِنُ يَفِرُّ أَحَدُهُمْ بِدِينِهِ إِلَى اللَّهِ وَإِلَى رَسُولِهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَخَافَةَ أَنْ يُفْتَنَ عَلَيْهِ فَأَمَّا الْيَوْمَ فَقَدْ أَظْهَرَ اللَّهُ الْإِسْلَامَ فَالْمُؤْمِنُ يَعْبُدُ رَبَّهُ حَيْثُ شَاءَ وَلَكِنْ جِهَادٌ وَنِيَّةٌ","id":"Telah menceritakan kepada kami [Ishaq bin Yazid] Telah menceritakan kepada kami [Yahya bin Hamzah], katanya, Telah menceritakan kepadaku [Auza'i] dari [Atha\" bin Abu Rabah] katanya, aku menemui [Aisyah] bersama Ubaid bin Umair, ia pun bertanya kepada Aisyah tentang hijrah, kata Aisyah; \"Tak ada lagi hijrah hari ini, dahulu seorang mukmin lari menyelamatkan agamanya menuju Allah dan Rasul-Nya Shallallahu'alaihiwasallam, karena khawatir terkena fitnah. Adapun hari ini Allah telah memenangkan Islam sehingga setiap mukmin bisa beribadah kepada Rabbnya sekehendaknya sehingga yang ada adalah jihad dan niyat."},"3696":{"ar":"حَدَّثَنَا إِسْحَاقُ حَدَّثَنَا أَبُو عَاصِمٍ عَنْ ابْنِ جُرَيْجٍ قَالَ أَخْبَرَنِي حَسَنُ بْنُ مُسْلِمٍ عَنْ مُجَاهِدٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَامَ يَوْمَ الْفَتْحِ فَقَالَ إِنَّ اللَّهَ حَرَّمَ مَكَّةَ يَوْمَ خَلَقَ السَّمَوَاتِ وَالْأَرْضَ فَهِيَ حَرَامٌ بِحَرَامِ اللَّهِ إِلَى يَوْمِ الْقِيَامَةِ لَمْ تَحِلَّ لِأَحَدٍ قَبْلِي وَلَا تَحِلُّ لِأَحَدٍ بَعْدِي وَلَمْ تَحْلِلْ لِي قَطُّ إِلَّا سَاعَةً مِنْ الدَّهْرِ لَا يُنَفَّرُ صَيْدُهَا وَلَا يُعْضَدُ شَوْكُهَا وَلَا يُخْتَلَى خَلَاهَا وَلَا تَحِلُّ لُقَطَتُهَا إِلَّا لِمُنْشِدٍ فَقَالَ الْعَبَّاسُ بْنُ عَبْدِ الْمُطَّلِبِ إِلَّا الْإِذْخِرَ يَا رَسُولَ اللَّهِ فَإِنَّهُ لَا بُدَّ مِنْهُ لِلْقَيْنِ وَالْبُيُوتِ فَسَكَتَ ثُمَّ قَالَ إِلَّا الْإِذْخِرَ فَإِنَّهُ حَلَالٌوَعَنْ ابْنِ جُرَيْجٍ أَخْبَرَنِي عَبْدُ الْكَرِيمِ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ بِمِثْلِ هَذَا أَوْ نَحْوِ هَذَا رَوَاهُ أَبُو هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Ishaq] Telah menceritakan kepada kami [Abu 'Ashim] dari [Ibnu Juraij] katanya, Telah menceritakan kepadaku [Hasan bin Muslim] dari [Mujahid] bahwasanya Rasulullah shallallahu 'alaihi wasallam pada saat penaklukan Makkah berdiri dan berpidato: \"Allah Ta'ala telah mensucikan Makkah pada hari ketika Dia mencipta langit dan bumi, maka Makkah adalah suci dengan rekomendasi kesucian Allah hingga kiamat tiba, tidak dihalalkan bagi seorangpun sebelumku maupun sesudahku, dan sama sekali tidak dihalalkan bagiku sama sekali selain hanya beberapa saat siang saja, binatangnya tak boleh diburu, durinya tak boleh dicongkel, rumputnya tak boleh dipotong, dan barang yang hilang tidak dihalalkan kecuali bagi yang mengumumkan. Lantas Abbas bin Abdul Muththalib berujar; \"Selain rumput idkhir ya Rasulullah, sebab rumput itu harus dipergunakan untuk kuburan dan rumah?\" Kemudian Rasulullah shallallahu 'alaihi wasallam diam dan berujar: \"Bolehlah, kecuali idzkhir, sesungguhnya ia halal.\" Dan dari [Ibnu Juraij] telah mengabarkan kepadaku [Abdul karim] dari [Ikrimah] dari [Ibnu Abbas] dengan hadits semisal ini atau seperti ini, diriwayatkan oleh Abu Hurairah dari Nabi shallallahu 'alaihi wasallam."},"3697":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا إِسْمَاعِيلُرَأَيْتُ بِيَدِ ابْنِ أَبِي أَوْفَىضَرْبَةً قَالَ ضُرِبْتُهَا مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ حُنَيْنٍ قُلْتُ شَهِدْتَ حُنَيْنًا قَالَ قَبْلَ ذَلِكَ","id":"Telah menceritakan kepada kami [Muhammad bin Abdullah bin Numair] Telah menceritakan kepada kami [Yazid bin Harun] Telah mengabarkan kepada kami [Ismail] pernah kulihat ditangan [Ibnu Abu Aufa] ada bekas-bekas sabetan. Kata Ibnu Abu Aufa, aku terkena sabetan itu bersama Nabi shallallahu 'alaihi wasallam pada perang Hunain, saya tanyakan; \"Engkau ikut perang Hunain? Jawabnya; \"Sebelum itu.\""},"3698":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ حَدَّثَنَا سُفْيَانُ عَنْ أَبِي إِسْحَاقَ قَالَ سَمِعْتُ الْبَرَاءَ رَضِيَ اللَّهُ عَنْهُوَجَاءَهُ رَجُلٌ فَقَالَ يَا أَبَا عُمَارَةَ أَتَوَلَّيْتَ يَوْمَ حُنَيْنٍ فَقَالَ أَمَّا أَنَا فَأَشْهَدُ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ لَمْ يُوَلِّ وَلَكِنْ عَجِلَ سَرَعَانُ الْقَوْمِ فَرَشَقَتْهُمْ هَوَازِنُ وَأَبُو سُفْيَانَ بْنُ الْحَارِثِ آخِذٌ بِرَأْسِ بَغْلَتِهِ الْبَيْضَاءِ يَقُولُ أَنَا النَّبِيُّ لَا كَذِبْأَنَا ابْنُ عَبْدِ الْمُطَّلِبْ","id":"Telah menceritakan kepada kami [Muhammad bin Katsir] Telah menceritakan kepada kami [Sufyan] dari [Abu Ishaq] katanya, pernah kudengar [Al Bara'] radliallahu 'anhu yang ketika itu ada seseorang yang datang lantas berujar; \"Wahai Abu Umarah, apakah engkau melarikan diri pada perang Hunain? Jawabannya; \"Adapun aku, dan aku bersaksi atas diri Nabi shallallahu 'alaihi wasallam bahwa beliau tidak melarikan diri, namun kemudian para sahabat sedemikian cepat dihujani anak panah oleh Bani Hawazin sedang Abu Sufyan bin Al Harits memegang kepala bighalnya yang putih dan Nabi berseru: ' Aku adalah seorang Nabi yang tak dusta # Aku anak Ibnul Abdul Muththalib."},"3699":{"ar":"حَدَّثَنَا أَبُو الْوَلِيدِ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي إِسْحَاقَ قِيلَ لِلْبَرَاءِوَأَنَا أَسْمَعُ أَوَلَّيْتُمْ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ حُنَيْنٍ فَقَالَ أَمَّا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَا كَانُوا رُمَاةً فَقَالَ أَنَا النَّبِيُّ لَا كَذِبْأَنَا ابْنُ عَبْدِ الْمُطَّلِبْ","id":"Telah menceritakan kepada kami [Abul Walid] Telah menceritakan kepada kami [Syu'bah] dari [Abu Ishaq], ditanyakan kepada [Al Barra'] -dan saya mendengar langsung- apakah engkau melarikan diri bersama Nabi shallallahu 'alaihi wasallam pada perang hunain? Barra' menjawab; \"Adapun Nabi shallallahu 'alaihi wasallam, beliau pantang melarikan diri dan berujar; \"Aku Nabi yang tidak pernah berdusta # Aku anak Abdul Muththalib."},"3700":{"ar":"حَدَّثَنِي مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا غُنْدَرٌ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي إِسْحَاقَ سَمِعَ الْبَرَاءَوَسَأَلَهُ رَجُلٌ مِنْ قَيْسٍ أَفَرَرْتُمْ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ حُنَيْنٍ فَقَالَ لَكِنْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَمْ يَفِرَّ كَانَتْ هَوَازِنُ رُمَاةً وَإِنَّا لَمَّا حَمَلْنَا عَلَيْهِمْ انْكَشَفُوا فَأَكْبَبْنَا عَلَى الْغَنَائِمِ فَاسْتُقْبِلْنَا بِالسِّهَامِ وَلَقَدْ رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى بَغْلَتِهِ الْبَيْضَاءِ وَإِنَّ أَبَا سُفْيَانَ بْنَ الْحَارِثِ آخِذٌ بِزِمَامِهَا وَهُوَ يَقُولُ أَنَا النَّبِيُّ لَا كَذِبْقَالَ إِسْرَائِيلُ وَزُهَيْرٌ نَزَلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ بَغْلَتِهِ","id":"Telah menceritakan kepadaku [Muhammad bin Basyar] Telah menceritakan kepada kami [Ghundar] Telah menceritakan kepada kami [Syu'bah] dari [Abu Ishaq], ia mendengar [Al Barra'] yang ketika itu seseorang dari Qais bertanya kepadanya \"Apakah kalian melarikan diri dari Rasulullah shallallahu 'alaihi wasallam pada perang hunain? Jawab Al Barra; \"Adapun Nabi shallallahu 'alaihi wasallam, beliau pantang melarikan diri, ketika itu Hawazin adalah para pemanah ulung, ketika kami menyerbu mereka, mereka kocar-kacir sehingga kami tergiur mendapatkan ghanimah, dan gantian kami yang dihujani dengan anak panah.\" Kulihat Rasulullah shallallahu 'alaihi wasallam diatas bighalnya yang putih, dan Abu Sufyan bin Al Harits memegang kendalinya sedang Nabi sambil berseru; \"Aku Nabi yang tiada dusta # Aku anak Abd Muthalib. Sedang [Israil] dan [Zuhair] mengatakan dengan redaksi; \"Nabi shallallahu 'alaihi wasallam turun dari bighalnya.\""},"3701":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ عُفَيْرٍ قَالَ حَدَّثَنِي اللَّيْثُ حَدَّثَنِي عُقَيْلٌ عَنْ ابْنِ شِهَابٍ ح و حَدَّثَنِي إِسْحَاقُ حَدَّثَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا ابْنُ أَخِي ابْنِ شِهَابٍ قَالَ مُحَمَّدُ بْنُ شِهَابٍ وَزَعَمَ عُرْوَةُ بْنُ الزُّبَيْرِ أَنَّ مَرْوَانَ وَالْمِسْوَرَ بْنَ مَخْرَمَةَ أَخْبَرَاهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَامَ حِينَ جَاءَهُ وَفْدُ هَوَازِنَ مُسْلِمِينَ فَسَأَلُوهُ أَنْ يَرُدَّ إِلَيْهِمْ أَمْوَالَهُمْ وَسَبْيَهُمْ فَقَالَ لَهُمْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَعِي مَنْ تَرَوْنَ وَأَحَبُّ الْحَدِيثِ إِلَيَّ أَصْدَقُهُ فَاخْتَارُوا إِحْدَى الطَّائِفَتَيْنِ إِمَّا السَّبْيَ وَإِمَّا الْمَالَ وَ��َدْ كُنْتُ اسْتَأْنَيْتُ بِكُمْ وَكَانَ أَنْظَرَهُمْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِضْعَ عَشْرَةَ لَيْلَةً حِينَ قَفَلَ مِنْ الطَّائِفِ فَلَمَّا تَبَيَّنَ لَهُمْ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ غَيْرُ رَادٍّ إِلَيْهِمْ إِلَّا إِحْدَى الطَّائِفَتَيْنِ قَالُوا فَإِنَّا نَخْتَارُ سَبْيَنَا فَقَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الْمُسْلِمِينَ فَأَثْنَى عَلَى اللَّهِ بِمَا هُوَ أَهْلُهُ ثُمَّ قَالَ أَمَّا بَعْدُ فَإِنَّ إِخْوَانَكُمْ قَدْ جَاءُونَا تَائِبِينَ وَإِنِّي قَدْ رَأَيْتُ أَنْ أَرُدَّ إِلَيْهِمْ سَبْيَهُمْ فَمَنْ أَحَبَّ مِنْكُمْ أَنْ يُطَيِّبَ ذَلِكَ فَلْيَفْعَلْ وَمَنْ أَحَبَّ مِنْكُمْ أَنْ يَكُونَ عَلَى حَظِّهِ حَتَّى نُعْطِيَهُ إِيَّاهُ مِنْ أَوَّلِ مَا يُفِيءُ اللَّهُ عَلَيْنَا فَلْيَفْعَلْ فَقَالَ النَّاسُ قَدْ طَيَّبْنَا ذَلِكَ يَا رَسُولَ اللَّهِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّا لَا نَدْرِي مَنْ أَذِنَ مِنْكُمْ فِي ذَلِكَ مِمَّنْ لَمْ يَأْذَنْ فَارْجِعُوا حَتَّى يَرْفَعَ إِلَيْنَا عُرَفَاؤُكُمْ أَمْرَكُمْ فَرَجَعَ النَّاسُ فَكَلَّمَهُمْ عُرَفَاؤُهُمْ ثُمَّ رَجَعُوا إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَخْبَرُوهُ أَنَّهُمْ قَدْ طَيَّبُوا وَأَذِنُوا هَذَا الَّذِي بَلَغَنِي عَنْ سَبْيِ هَوَازِنَ","id":"Telah menceritakan kepada kami [Said bin Ufair], katanya, telah menceritakan kepadaku [Al Laits] telah menceritakan kepadaku [Uqail] dari [Ibnu Syihab] -lewat jalur periwayatan lain-telah menceritakan kepadaku [Ishaq] Telah menceritakan kepada kami [Ya'kub bin Ibrahim] Telah menceritakan kepada kami [Anak saudaraku, Ibnu Syihab], [Muhammad bin Syihab] berkata; -sedang [Urwah bin Zubair] beranggapan-bahwa [Marwan] dan [Miswar bin Makhramah] mengabarinya, bahwasanya Rasulullah shallallahu 'alaihi wasallam berdiri ketika beliau didatangi oleh utusan bani Hawazin yang telah masuk Islam. Mereka minta beliau agar mengembalikan harta dan tawanan kepada mereka. Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Aku membawa beberapa tawanan yang kalian lihat sendiri, dan ucapan yang paling aku sukai adalah yang paling jujur, maka pilihlah salah satu diantara dua pilihan, kalian minta tawanan atau harta, dan aku meminta kalian untuk memberi tangguh, dan waktu paling lama yang diminta Rasulullah adalah sekitar tujuh belasan hari ketika beliau pulang dari Thaif. Setelah jelas bagi suku Hawazin bahwa Rasulullah tak bakalan mengembalikan kepada mereka kecuali satu diantara dua pilihan, suku Hawazin berujar; \"Bolehlah, kami memilih tawanan kami.\" Maka Rasulullah shallallahu 'alaihi wasallam berdiri di tengah-tengah muslimin, memuji Allah dengan pujian yang semestinya kemudian berpidato: \"Hadirin yang dimuliakan, saudara-saudara kalian telah menemui kita dalam keadaan bertaubat, dan saya sependapat untuk mengembalikan tawanan mereka, maka siapa diantara kalian yang merelakan diri untuk ini, silahkan lakukan, namun siapa diantara kalian berkeinginan memperoleh bagiannya, kami pun akan memberinya dari harta yang Allah berikan. Para sahabat menjawab; \"Kami semua tulus wahai Rasulullah.\" Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kami tak tahu siapa diantara kalian yang memberi ijin dan siapa yang tidak, maka kembalilah kalian sehingga para orang-orang bijak kalian melaporkan perkara kalian kepada kami.\" Para sahabat pun pulang dan orang-orang bijak mereka mendiskusikan masalah kepada semua sahabat, kemudian mereka kembali menemui Rasulullah shallallahu 'alaihi wasallam dan memberitahu beliau bahwa mereka semua tulus dan mengijinkan. Inilah berita yang sampai kepadaku mengenai tawanan Hawazin."},"3702":{"ar":"حَدَّثَنَا أَبُو النُّعْمَانِ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ أَيُّوبَ عَنْ نَافِعٍ أَنَّ عُمَرَ قَالَ يَا رَسُولَ اللَّهِ ح حَدَّثَنِي مُحَمَّدُ بْنُ مُقَاتِلٍ أَخْبَرَنَا عَبْدُ اللَّهِ أَخْبَرَنَا مَعْمَرٌ عَنْ أَيُّوبَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا قَالَلَمَّا قَفَلْنَا مِنْ حُنَيْنٍ سَأَلَ عُمَرُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ نَذْرٍ كَانَ نَذَرَهُ فِي الْجَاهِلِيَّةِ اعْتِكَافٍ فَأَمَرَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِوَفَائِهِوَقَالَ بَعْضُهُمْ حَمَّادٌ عَنْ أَيُّوبَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ وَرَوَاهُ جَرِيرُ بْنُ حَازِمٍ وَحَمَّادُ بْنُ سَلَمَةَ عَنْ أَيُّوبَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Abu Nu'man] Telah menceritakan kepada kami [Hammad bin Zaid] dari [Ayyub] dari [Nafi'] bahwa Umar berujar; \"Wahai Rasulullah! -lewat jalur periwayatan lain-telah menceritakan kepadaku [Muhammad bin Muqatil] Telah mengabarkan kepada kami [Abdullah] Telah mengabarkan kepada kami [Ma'mar] dari [Ayyub] dari [Nafi'] dari [Ibnu Umar] radliallahu 'anhuma, katanya; Sekembali kami dari Hunain, Umar bertanya kepada Nabi shallallahu 'alaihi wasallam tentang nadzarnya yang ia lakukan semasa jahiliyah, yaitu untuk beri'tikaf. Maka Nabi shallallahu 'alaihi wasallam memerintahkan untuk menunaikannya. Sedang [sebagian mereka] mengatakan dari [Hammad] dari [Ayyub] dari [Nafi'] dari [Ibnu Umar] dan hadits ini diriwayatkan oleh [Jarir bin Hazim] dan [Hamad bin Salamah] dari [Ayyub] dari [Nafi'] dari [Ibnu Umar] dari Nabi shallallahu 'alaihi wasallam."},"3703":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ عُمَرَ بْنِ كَثِيرِ بْنِ أَفْلَحَ عَنْ أَبِي مُحَمَّدٍ مَوْلَى أَبِي قَتَادَةَ عَنْ أَبِي قَتَادَةَ قَالَخَرَجْنَا مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَامَ حُنَيْنٍ فَلَمَّا الْتَقَيْنَا كَانَتْ لِلْمُسْلِمِينَ جَوْلَةٌ فَرَأَيْتُ رَجُلًا مِنْ الْمُشْرِكِينَ قَدْ عَلَا رَجُلًا مِنْ الْمُسْلِمِينَ فَضَرَبْتُهُ مِنْ وَرَائِهِ عَلَى حَبْلِ عَاتِقِهِ بِالسَّيْفِ فَقَطَعْتُ الدِّرْعَ وَأَقْبَلَ عَلَيَّ فَضَمَّنِي ضَمَّةً وَجَدْتُ مِنْهَا رِيحَ الْمَوْتِ ثُمَّ أَدْرَكَهُ الْمَوْتُ فَأَرْسَلَنِي فَلَحِقْتُ عُمَرَ بْنَ الْخَطَّابِ فَقُلْتُ مَا بَالُ النَّاسِ قَالَ أَمْرُ اللَّهِ عَزَّ وَجَلَّ ثُمَّ رَجَعُوا وَجَلَسَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ مَنْ قَتَلَ قَتِيلًا لَهُ عَلَيْهِ بَيِّنَةٌ فَلَهُ سَلَبُهُ فَقُلْتُ مَنْ يَشْهَدُ لِي ثُمَّ جَلَسْتُ قَالَ ثُمَّ قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِثْلَهُ فَقُمْتُ فَقُلْتُ مَنْ يَشْهَدُ لِي ثُمَّ جَلَسْتُ قَالَ ثُمَّ قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِثْلَهُ فَقُمْتُ فَقَالَ مَا لَكَ يَا أَبَا قَتَادَةَ فَأَخْبَرْتُهُ فَقَالَ رَجُلٌ صَدَقَ وَسَلَبُهُ عِنْدِي فَأَرْضِهِ مِنِّي فَقَالَ أَبُو بَكْرٍ لَاهَا اللَّهِ إِذًا لَا يَعْمِدُ إِلَى أَسَدٍ مِنْ أُسْدِ اللَّهِ يُقَاتِلُ عَنْ اللَّهِ وَرَسُولِهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَيُعْطِيَكَ سَلَبَهُ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَدَقَ فَأَعْطِهِ فَأَعْطَانِيهِ فَابْتَعْتُ بِهِ مَخْرَفًا فِي بَنِي سَلِمَةَ فَإِنَّهُ لَأَوَّلُ مَالٍ تَأَثَّلْتُهُ فِي الْإِسْلَامِوَقَالَ اللَّيْثُ حَدَّثَنِي يَحْيَى بْنُ سَعِيدٍ عَنْ عُمَرَ بْنِ كَثِيرِ بْنِ أَفْلَحَ عَنْ أَبِي مُحَمَّدٍ مَوْلَى أَبِي قَتَادَةَ أَنَّ أَبَا قَتَادَةَ قَالَ لَمَّا كَانَ يَوْمَ حُنَيْنٍ نَظَرْتُ إِلَى رَجُلٍ مِنْ الْمُسْلِمِينَ يُقَاتِلُ رَجُلًا مِنْ الْمُشْرِكِينَ وَآخَرُ مِنْ الْمُشْرِكِينَ يَخْتِلُهُ مِنْ وَرَائِهِ لِيَقْتُلَهُ فَأَسْرَعْتُ إِلَى الَّذِي يَخْتِلُهُ فَرَفَعَ يَدَهُ لِيَضْرِبَنِي وَأَضْرِبُ يَدَهُ فَقَطَعْتُهَا ثُمَّ أَخَذَنِي فَضَمَّنِي ضَمًّا شَدِيدًا حَتَّى تَخَوَّفْتُ ثُمَّ تَرَكَ فَتَحَلَّلَ وَدَفَعْتُهُ ثُمَّ قَتَلْتُهُ وَانْهَزَمَ الْمُسْلِمُونَ وَانْهَزَمْتُ مَعَهُمْ فَإِذَا بِعُمَرَ بْنِ الْخَطَّابِ فِي النَّاسِ فَقُلْتُ لَهُ مَا شَأْنُ النَّاسِ قَالَ أَمْرُ اللَّهِ ثُمَّ تَرَاجَعَ النَّاسُ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ أَقَامَ بَيِّنَةً عَلَى قَتِيلٍ قَتَلَهُ فَلَهُ سَلَبُهُ فَقُمْتُ لِأَلْتَمِسَ بَيِّنَةً عَلَى قَتِيلِي فَلَمْ أَرَ أَحَدًا يَشْهَدُ لِي فَجَلَسْتُ ثُمَّ بَدَا لِي فَذَكَرْتُ أَمْرَهُ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ رَجُلٌ مِنْ جُلَسَائِهِ سِلَاحُ هَذَا الْقَتِيلِ الَّذِي يَذْكُرُ عِنْدِي فَأَرْضِهِ مِنْهُ فَقَالَ أَبُو بَكْرٍ كَلَّا لَا يُعْطِهِ أُصَيْبِغَ مِنْ قُرَيْشٍ وَيَدَعَ أَسَدًا مِنْ أُسْدِ اللَّهِ يُقَاتِلُ عَنْ اللَّهِ وَرَسُولِهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فَقَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَدَّاهُ إِلَيَّ فَاشْتَرَيْتُ مِنْهُ خِرَافًا فَكَانَ أَوَّلَ مَالٍ تَأَثَّلْتُهُ فِي الْإِسْلَامِ","id":"Telah menceritakan kepada kami [Abdullah bin Yusuf] Telah mengabarkan kepada kami [Malik] dari [Yahya bin Said] dari [Umar bin Katsir bin Aflah] dari [Abu Muhammad, -mantan budak- Abu Qatadah] dari [Abu Qatadah] katanya, kami berangkat bersama Nabi shallallahu 'alaihi wasallam pada perang Hunain. Tatkala kami berperang, terjadi perselisihan dikalangan kaum muslimin, namun selanjutnya kulihat seorang musyrikin memburu seorang kaum muslimin. Dengan sigap aku tebas si laki-laki musyrik itu dari belakangnya, tepatnya di urat pundaknya dengan pedang, aku berhasil membelah baju besinya. Tiba-tiba si laki-laki itu menghadapku, mendekapku, namun telah kucium bau kematiannya, dan kematian ia pun mati, sehingga aku terbebas darinya. Kemudian kutemui Umar bin Khattab dan kutanyakan \"Bagaimana nasib orang-orang? Jawabnya; 'Itu sudah menjadi Allah azza wa Jalla.\" Kemudian para sahabat pulang sedang Nabi shallallahu 'alaihi wasallam duduk dan mengumumkan: \"Barangsiapa yang bisa membunuh musuh, dan ia mempunyai bukti, maka baginyalah rampasannya\". Maka aku (Abu Qatadah) berkata; \"Siapa yang mau memberi kesaksian padaku? Aku lantas duduk. Nabi kemudian mengucapkan seperti semula.\" Maka aku pun berdiri untuk kedua kalinya dan mengatakan; siapa yang mau memberi kesaksian kepadaku? Lantas aku duduk. Lalu nabi shallallahu 'alaihi wasallam bersabda dengan kalimat yang serupa. Aku pun berdiri lagi, namun Nabi shallallahu 'alaihi wasallam bertanya; \"Apa perlumu wahai Abu Qatadah? Maka kuberitakan segala yang kulakukan. Tiba-tiba ada seorang sahabat berdiri dan berujar \"Abu Qatadah benar, dan rampasannya ada padaku, tolong bujuklah dia agar meridhai untukku!\" Seketika itu pula Abu Bakar tampil dan berujar; \"Saya bersumpah, Demi Allah, tidak bisa seperti ini. Tidak bisa orang itu menemui salah satu singa Allah (maksudnya Abu Qatadah) yang ia berperang demi Allah dan rasul-Nya lantas ia berikan salab (rampasannya)!\" Nabi shallallahu 'alaihi wasallam berujar; \"Abu Bakar benar, berikan rampasannya kepada Abu Qatadah! Maka si laki-laki pun memberikannya kepadaku. Lalu (Abu Qatadah) dengan rampasan itu aku belikan kebun di bani Salimah, dan itulah harta pertama-tama yang kumiliki semasa Islam. Sedang [Laits] mengatakan, Telah menceritakan kepadaku [Yahya bin Said] dari [Umar bin Katsir bin Aflah] dari [Abu Muhammad], -maula- Abu Qatadah, [Abu Qatadah] bercerita, ketika perang Hunain, aku mencermati seorang kaum muslimin yang memerangi seorang musyrikin, dan ada musuh musyrikin lain yang mengintainya di belakangnya untuk membunuhnya. Maka aku bergegas memburu si pengintai itu, ia angkat pedangnya untuk menyabetku, namun aku lebih dahulu menyabet tangannya hingga putus. Si laki-laki itu terus memegangku dan mendekapku sangat kuat hingga aku ketakutan juga, namun rupanya kekuatannya berangsur-angsur melemah, dan akhirnya aku sungkurkan dan kubunuh, kaum muslimin kemudian kocar-kacir dan aku kocar kacir bersama mereka, tapi ternyata Umar bin khattab masih ditengah-tengah kaum muslimin dan kutanyakan; \"Bagaimana nasib kita? Jawab Umar; \"Allah yang akan menentukannya!\" kemudian para sahabat menemui Rasulullah Shallallahu'alaihiwasallam, dan beliau sampaikan pengumuman; \"Barangsiapa yang bisa mengajukan bukti atas korban yang ia bunuh, maka ia peroleh rampasannya.\" Maka aku segera berdiri untuk mencari bukti atas korban yang kubunuh di perang itu, dan tak kulihat seorang pun yang mau memberi kesaksian atas pembunuhanku. Maka aku duduk, kemudian aku punya inisiatif agar kuutarakan uneg-unegku kepada Rasulullah Shallallahu'alaihiwasallam. Tiba-tiba salah seseorang berujar; \"Senjata orang yang dibunuhnya, yang selalu Abu Qatadah sebut-sebut ada padaku, tolong mintalah keridlaannya!\" Maka Abu Bakar kontan berujar; \"Sekali-kali tidak, nggak bisa, tidak bakalan Rasulullah memberi senjata itu hanya kepada burung pipit quraisy -ucapan penghinaan Abu bakar kepada si laki-laki- sedang beliau tinggalkan singa Allah (julukan Abu Qatadah) yang telah berperang membela Allah dan Rasul-Nya Shallallahu'alaihiwasallam. Maka Rasulullah shallallahu 'alaihi wasallam berdiri. Lalu si laki-laki menyerahkan senjatanya kepadaku yang dengannya kubelikan sebidang kebun. Itulah kekayaaan pertama-tama yang kumiliki dalam keIslamanku."},"3704":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْعَلَاءِ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ بُرَيْدِ بْنِ عَبْدِ اللَّهِ عَنْ أَبِي بُرْدَةَ عَنْ أَبِي مُوسَى رَضِيَ اللَّهُ عَنْهُ قَالَلَمَّا فَرَغَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ حُنَيْنٍ بَعَثَ أَبَا عَامِرٍ عَلَى جَيْشٍ إِلَى أَوْطَاسٍ فَلَقِيَ دُرَيْدَ بْنَ الصِّمَّةِ فَقُتِلَ دُرَيْدٌ وَهَزَمَ اللَّهُ أَصْحَابَهُ قَالَ أَبُو مُوسَى وَبَعَثَنِي مَعَ أَبِي عَامِرٍ فَرُمِيَ أَبُو عَامِرٍ فِي رُكْبَتِهِ رَمَاهُ جُشَمِيٌّ بِسَهْمٍ فَأَثْبَتَهُ فِي رُكْبَتِهِ فَانْتَهَيْتُ إِلَيْهِ فَقُلْتُ يَا عَمِّ مَنْ رَمَاكَ فَأَشَارَ إِلَى أَبِي مُوسَى فَقَالَ ذَاكَ قَاتِلِي الَّذِي رَمَانِي فَقَصَدْتُ لَهُ فَلَحِقْتُهُ فَلَمَّا رَآنِي وَلَّى فَاتَّبَعْتُهُ وَجَعَلْتُ أَقُولُ لَهُ أَلَا تَسْتَحْيِي أَلَا تَثْبُتُ فَكَفَّ فَاخْتَلَفْنَا ضَرْبَتَيْنِ بِالسَّيْفِ فَقَتَلْتُهُ ثُمَّ قُلْتُ لِأَبِي عَامِرٍ قَتَلَ اللَّهُ صَاحِبَكَ قَالَ فَانْزِعْ هَذَا السَّهْمَ فَنَزَعْتُهُ فَنَزَا مِنْهُ الْمَاءُ قَالَ يَا ابْنَ أَخِي أَقْرِئْ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ السَّلَامَ وَقُلْ لَهُ اسْتَغْفِرْ لِي وَاسْتَخْلَفَنِي أَبُو عَامِرٍ عَلَى النَّاسِ فَمَكُثَ يَسِيرًا ثُمَّ مَاتَ فَرَجَعْتُ فَدَخَلْتُ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي بَيْتِهِ عَلَى سَرِيرٍ مُرْمَلٍ وَعَلَيْهِ فِرَاشٌ قَدْ أَثَّرَ رِمَالُ السَّرِيرِ بِظَهْرِهِ وَجَنْبَيْهِ فَأَخْبَرْتُهُ بِخَبَرِنَا وَخَبَرِ أَبِي عَامِرٍ وَقَالَ قُلْ لَهُ اسْتَغْفِرْ لِي فَدَعَا بِمَاءٍ فَتَوَضَّأَ ثُمَّ رَفَعَ يَدَيْهِ فَقَالَ اللَّهُمَّ اغْفِرْ لِعُبَيْدٍ أَبِي عَامِرٍ وَرَأَيْتُ بَيَاضَ إِبْطَيْهِ ثُمَّ قَالَ اللَّهُمَّ اجْعَلْهُ يَوْمَ الْقِيَامَةِ فَوْقَ كَثِيرٍ مِنْ خَلْقِكَ مِنْ النَّاسِ فَقُلْتُ وَلِي فَاسْتَغْفِرْ فَقَالَ اللَّهُمَّ اغْفِرْ لِعَبْدِ اللَّهِ بْنِ قَيْسٍ ذَنْبَهُ وَأَدْخِلْهُ يَوْمَ الْقِيَامَةِ مُدْخَلًا كَرِيمًاقَالَ أَبُو بُرْدَةَ إِحْدَاهُمَا لِأَبِي عَامِرٍ وَالْأُخْرَى لِأَبِي مُوسَى","id":"Telah menceritakan kepada kami [Muhammad bin Al'Ala'] Telah menceritakan kepada kami [Abu Usamah] dari [Buraid bin Abdullah] dari [Abu Burdah] dari [Abu Musa] radliallahu 'anhu katanya, selepas Nabi shallallahu 'alaihi wasallam dari perang Hunain, beliau utus Abu Amir memimpin pasukan ke Authas. Selanjutnya Abu Amir temui Duraid bin Shimah dan Duraid pun terbunuh. Kemudian Allah menghancurkan para pengikutnya. Kata Abu Musa; Rasul mengutusku bersama Abu Amir, Abu umair kemudian terkena lemparan pada lututnya, ia terkena panah yang dibidikkan oleh Jusyami hingga panah itu terus menancap di lututnya. Aku pun menemuinya dan bertanya; \"Wahai paman, siapa yang melemparmu? Ia memberi isyarat kepada Abu Musa dan berujar; \"Itulah pembunuhku yang telah membidikkan panah kepadaku.\" Maka aku memburunya dan berusaha kutemui, ketika ia melihatku, ia melarikan diri, maka aku terus menguntitnya dan kuejek; \"Apa kamu tidak malu, tidak bisakah engkau bertahan?\" Ia pun bertahan, kami bergantian menebas dengan pedang dua kali sabetan yang selanjutnya aku berhasil membunuhnya. Kemudian kukatakan kepada Abu Amir; \"Allah telah membunuh kawanmu. Abu Amir kemudian berujar; \"Tolong cabutlah panah ini dariku\" Maka aku mencabutnya sehingga lukanya mengalirkan air. Kata Abu amir \"Wahai anak saudaraku, sampaikanlah salam kepada Nabi shallallahu 'alaihi wasallam dan sampaikan, \"Mintakanlah ampunan untukku! Dan Abu Amir menjadikanku sebagai komandan para sahabat. Ia masih bertahan beberapa saat kemudian wafat. Aku pun pulang dan kutemui Nabi shallallahu 'alaihi wasallam di rumahnya diatas tempat tidur yang terbuat dari pelepah kurma beralaskan kasur dan pelepah kasurnya membekas di punggung dan pinggangnya. Kusampaikan kepada beliau segala berita kami dan juga berita Abu Amir yang menyampaikan pesan, \"Sampaikan kepada Rasulullah, mintakanlah ampunan untukku.\" Nabi meminta air, dan beliau berwudhu, kemudian beliau tengadahkan kedua tangannya dan berdoa ALLOOHUMMAGHFIR LI'UBAID ABI AMIR\" (Ya Allah, berilah ampunan untuk hamba-Mu yang lemah, Abu Amir), dan kulihat ketiaknya yang putih kemudian beliau memanjatkan doa ALLOOHUMMAJ'ALHU YAUMAL QIYAAMATI FAUQO KATSIIRIN MIN KHOLQIKA MINAN NASI' (Ya Allah, jadikanlah ia diatas kebanyakan manusia ciptaan-Mu). Maka aku meminta; \"Dan aku juga mintakanlah ampunan.\" Maka Nabi panjatkan ALLOOHUMMAGH FIR LIABDILLAH BIN QAIS DZANBAHU WA ADKHILHU YAUMAL QIYAMATI MUDKHALAN KARIIMA (Ya Allah, ampunilah Abdullah bin Qais (Abu Musa) atas dosanya, dan masukkanlah pada hari kiamat ke tempat yang terpuji). Kata Abu Burdah, satu doanya untuk Abu Amir dan satunya untuk Abu Musa."},"3705":{"ar":"حَدَّثَنَا الْحُمَيْدِيُّ سَمِعَ سُفْيَانَ حَدَّثَنَا هِشَامٌ عَنْ أَبِيهِ عَنْ زَيْنَبَ بِنْتِ أَبِي سَلَمَةَ عَنْ أُمِّهَا أُمِّ سَلَمَةَ رَضِيَ اللَّهُ عَنْهَادَخَلَ عَلَيَّ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَعِنْدِي مُخَنَّثٌ فَسَمِعْتُهُ يَقُولُ لِعَبْدِ اللَّهِ بْنِ أَبِي أُمَيَّةَ يَا عَبْدَ اللَّهِ أَرَأَيْتَ إِنْ فَتَحَ اللَّهُ عَلَيْكُمْ الطَّائِفَ غَدًا فَعَلَيْكَ بِابْنَةِ غَيْلَانَ فَإِنَّهَا تُقْبِلُ بِأَرْبَعٍ وَتُدْبِرُ بِثَمَانٍ وَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَدْخُلَنَّ هَؤُلَاءِ عَلَيْكُنَّقَالَ ابْنُ عُيَيْنَةَ وَقَالَ ابْنُ جُرَيْجٍ الْمُخَنَّثُ هِيتٌ حَدَّثَنَا مَحْمُودٌ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ هِشَامٍ بِهَذَا وَزَادَ وَهُوَ مُحَاصِرُ الطَّائِفِ يَوْمَئِذٍ","id":"Telah menceritakan kepada kami [Al Humaidi] ia mendengar [Sufyan] Telah menceritakan kepada kami [Hisyam] dari [ayahnya] dari [Zaenab binti Abu Salamah] dari [Ibunya, Ummu Salamah] radliallahu 'anha, Nabi shallallahu 'alaihi wasallam menemuiku yang ketika itu disisiku ada seorang waria dan kudengar ia mengatakan kepada Abdullah bin Abu Umayyah; Wahai Abdullah, bagaimana pendapatmu jika Allah menalukkan Thaif untukmu, hendaklah engkau menikahi anak perempuan Ghailan, sebab ia (perempuan) yang menghadap dengan empat cabang dan berbalik dengan delapan cabang. Maka Nabi shallallahu 'alaihi wasallam langsung berkomentar: \"Jangan biarkan laki-laki waria (banci) itu menemui kalian. Kata Ibnu Uyainah, Ibnu Juraij mengatakan makna 'mukhannats' adalah banci, Telah menceritakan kepada kami [Mahmud] Telah menceritakan kepada kami [Abu Usamah] dari [Hisyam] dengan hadist ini dan beliau tambahkan redaksi; \"Ketika itu beliau sedang mengepung kota Thaif\"."},"3706":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا سُفْيَانُ عَنْ عَمْرٍو عَنْ أَبِي الْعَبَّاسِ الشَّاعِرِ الْأَعْمَى عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ قَالَلَمَّا حَاصَرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الطَّائِفَ فَلَمْ يَنَلْ مِنْهُمْ شَيْئًا قَالَ إِنَّا قَافِلُونَ إِنْ شَاءَ اللَّهُ فَثَقُلَ عَلَيْهِمْ وَقَالُوا نَذْهَبُ وَلَا نَفْتَحُهُ وَقَالَ مَرَّةً نَقْفُلُ فَقَالَ اغْدُوا عَلَى الْقِتَالِ فَغَدَوْا فَأَصَابَهُمْ جِرَاحٌ فَقَالَ إِنَّا قَافِلُونَ غَدًا إِنْ شَاءَ اللَّهُ فَأَعْجَبَهُمْ فَضَحِكَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَالَ سُفْيَانُ مَرَّةً فَتَبَسَّمَقَالَ قَالَ الْحُمَيْدِيُّ حَدَّثَنَا سُفْيَانُ الْخَبَرَ كُلَّهُ","id":"Telah menceritakan kepada kami [Ali bin Abdullah] Telah menceritakan kepada kami [Sufyan] dari [Amru] dari [Abul Abbas, tukang syair yang buta] dari [Abdullah bin Umar] katanya, ketika Rasulullah mengepung Thaif, dan beliau sama sekali belum memperoleh hasilnya, beliau berujar: \"Besok kita insya Allah pulang.\" Ucapan Nabi ini memberatkan mereka sehingga para sahabat berujar; \"Apakah kita akan pulang dan tidak menaklukkannya?\" Abdullah bin Umar adakalanya berujar dengan lafadz; \"Kita akan pulang.\" maka Rasulullah berujar: \"Teruslah kalian menyongsong peperangan.\" Para sahabat pun terus berangkat dan mereka peroleh luka-luka. Kata Nabi: \"Besok kita insya Allah kita pulang.\" Ucapan Nabi ini menjadikan para sahabat kagum (sebagai pelipur lara), maka Nabi shallallahu 'alaihi wasallam tertawa. Suatu kali Sufyan mengatakan dengan redaksi; \"Nabi tersenyum\". Kata Abul Abbas, kata [Humaidi], Telah menceritakan kepada kami [Sufyan] semua beritanya."},"3707":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا غُنْدَرٌ حَدَّثَنَا شُعْبَةُ عَنْ عَاصِمٍ قَالَ سَمِعْتُ أَبَا عُثْمَانَ قَالَ سَمِعْتُ سَعْدًاوَهُوَ أَوَّلُ مَنْ رَمَى بِسَهْمٍ فِي سَبِيلِ اللَّهِ وَأَبَا بَكْرَةَ وَكَانَ تَسَوَّرَ حِصْنَ الطَّائِفِ فِي أُنَاسٍ فَجَاءَ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَا سَمِعْنَا النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ ادَّعَى إِلَى غَيْرِ أَبِيهِ وَهُوَ يَعْلَمُ فَالْجَنَّةُ عَلَيْهِ حَرَامٌوَقَالَ هِشَامٌ وَأَخْبَرَنَا مَعْمَرٌ عَنْ عَاصِمٍ عَنْ أَبِي الْعَالِيَة�� أَوْ أَبِي عُثْمَانَ النَّهْدِيِّ قَالَ سَمِعْتُ سَعْدًا وَأَبَا بَكْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ عَاصِمٌ قُلْتُ لَقَدْ شَهِدَ عِنْدَكَ رَجُلَانِ حَسْبُكَ بِهِمَا قَالَ أَجَلْ أَمَّا أَحَدُهُمَا فَأَوَّلُ مَنْ رَمَى بِسَهْمٍ فِي سَبِيلِ اللَّهِ وَأَمَّا الْآخَرُ فَنَزَلَ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثَالِثَ ثَلَاثَةٍ وَعِشْرِينَ مِنْ الطَّائِفِ","id":"Telah menceritakan kepada kami [Muhammad bin Basyar] Telah menceritakan kepada kami [Ghundar] dari [Syu'bah] dari ['Ashim] katanya; Aku mendengar [Abu Usman] berkata; aku mendengar [Sa'ad] -yang ia adalah sahabat pertama-tama yang melesakkan panah fii sabilillah- dan [Abu Bakrah] yang ketika itu ia mengepung benteng Thaif bersama pasukan sahabat. Lantas menemui nabi shallallahu 'alaihi wasallam dan keduanya berujar; \"Aku dengar Nabi shallallahu 'alaihi wasallam bersabda: \"Siapa yang mengaku kepada selain ayahnya padahal ia tahu, maka surga haram baginya. Kata [Hisyam], Telah mengabarkan kepada kami [Ma'mar] dari ['Ashim] dari [Abu Aliyah] atau [Abu Utsman An Nahdi] katanya, aku mendengar [Sa'd] dan [Abu Bakrah] dari Nabi shallallahu 'alaihi wasallam. Kata [Ashim] saya bekomentar; Sudah ada dua orang memberi kesaksian bagimu (Abu Aliyah atau Abu Utsman), cukuplah keduanya sebagai saksi. Kata (Abu Aliyah atau Abu Utsman) \"Betul\", satunya adalah sahabat pertama-tama yang membidikan panah fi sabilillah dan kedua adalah sahabat yang termasuk dari orang ketiga diantara dua puluh tiga sahabat yang pulang dari Thaif."},"3708":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْعَلَاءِ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ بُرَيْدِ بْنِ عَبْدِ اللَّهِ عَنْ أَبِي بُرْدَةَ عَنْ أَبِي مُوسَى رَضِيَ اللَّهُ عَنْهُ قَالَكُنْتُ عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ نَازِلٌ بِالْجِعْرَانَةِ بَيْنَ مَكَّةَ وَالْمَدِينَةِ وَمَعَهُ بِلَالٌ فَأَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَعْرَابِيٌّ فَقَالَ أَلَا تُنْجِزُ لِي مَا وَعَدْتَنِي فَقَالَ لَهُ أَبْشِرْ فَقَالَ قَدْ أَكْثَرْتَ عَلَيَّ مِنْ أَبْشِرْ فَأَقْبَلَ عَلَى أَبِي مُوسَى وَبِلَالٍ كَهَيْئَةِ الْغَضْبَانِ فَقَالَ رَدَّ الْبُشْرَى فَاقْبَلَا أَنْتُمَا قَالَا قَبِلْنَا ثُمَّ دَعَا بِقَدَحٍ فِيهِ مَاءٌ فَغَسَلَ يَدَيْهِ وَوَجْهَهُ فِيهِ وَمَجَّ فِيهِ ثُمَّ قَالَ اشْرَبَا مِنْهُ وَأَفْرِغَا عَلَى وُجُوهِكُمَا وَنُحُورِكُمَا وَأَبْشِرَا فَأَخَذَا الْقَدَحَ فَفَعَلَا فَنَادَتْ أُمُّ سَلَمَةَ مِنْ وَرَاءِ السِّتْرِ أَنْ أَفْضِلَا لِأُمِّكُمَا فَأَفْضَلَا لَهَا مِنْهُ طَائِفَةً","id":"Telah menceritakan kepada kami [Muhammad bin Al'Ala'] Telah menceritakan kepada kami [Abu Usamah] dari [Buraid bin Abdullah] dari [Abu Burdah] dari [Abu Musa] radliallahu 'anhu, katanya Aku disisi Nabi shallallahu 'alaihi wasallam yang ketika itu beliau singgah di Ji'ranah antara Makkah dan Madinah, beliau bersama Bilal. Rupanya ada seorang arab badui (pelosok) menemui beliau dan berujar; \"Tidakkah engkau lunasi janjimu kepadaku? Jawab Nabi: \"Bergembiralah! Si arab badui menjawab; \"kamu berulang kali mengatakan; \"bergembiralah! Kemudian beliau temui Abu musa dan Bilal seolah-olah beliau emosi. Kata beliau: \"Orang arab itu telah menolak kabar gembira! Maka temuilah olehmu berdua! maka kami menemuinya. Selanjutnya Nabi meminta baskom berisi air, beliau cuci kedua tangannya, wajahnya dan beliau semprotkan air dari mulut beliau ke baskom, kemudian beliau bersabda: \"Silahkan kalian berdua minum, dan guyurkan pada wajah kalian, dan tengkuk kalian dan bergembiralah! Keduanya lantas mengambil baskom dan keduanya melaksanakan perintah Nabi shallallahu 'alaihi wasallam. Ummu Salamah lantas berseru dibalik tabir \"Tolong sisakan air itu untuk ibu kalian! Maka keduanya menyisakan air itu."},"3709":{"ar":"حَدَّثَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا إِسْمَاعِيلُ حَدَّثَنَا ابْنُ جُرَيْجٍ قَالَ أَخْبَرَنِي عَطَاءٌ أَنَّ صَفْوَانَ بْنَ يَعْلَى بْنِ أُمَيَّةَ أَخْبَرَهُ أَنَّ يَعْلَى كَانَ يَقُولُلَيْتَنِي أَرَى رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِينَ يُنْزَلُ عَلَيْهِ قَالَ فَبَيْنَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالْجِعْرَانَةِ وَعَلَيْهِ ثَوْبٌ قَدْ أُظِلَّ بِهِ مَعَهُ فِيهِ نَاسٌ مِنْ أَصْحَابِهِ إِذْ جَاءَهُ أَعْرَابِيٌّ عَلَيْهِ جُبَّةٌ مُتَضَمِّخٌ بِطِيبٍ فَقَالَ يَا رَسُولَ اللَّهِ كَيْفَ تَرَى فِي رَجُلٍ أَحْرَمَ بِعُمْرَةٍ فِي جُبَّةٍ بَعْدَمَا تَضَمَّخَ بِالطِّيبِ فَأَشَارَ عُمَرُ إِلَى يَعْلَى بِيَدِهِ أَنْ تَعَالَ فَجَاءَ يَعْلَى فَأَدْخَلَ رَأْسَهُ فَإِذَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُحْمَرُّ الْوَجْهِ يَغِطُّ كَذَلِكَ سَاعَةً ثُمَّ سُرِّيَ عَنْهُ فَقَالَ أَيْنَ الَّذِي يَسْأَلُنِي عَنْ الْعُمْرَةِ آنِفًا فَالْتُمِسَ الرَّجُلُ فَأُتِيَ بِهِ فَقَالَ أَمَّا الطِّيبُ الَّذِي بِكَ فَاغْسِلْهُ ثَلَاثَ مَرَّاتٍ وَأَمَّا الْجُبَّةُ فَانْزِعْهَا ثُمَّ اصْنَعْ فِي عُمْرَتِكَ كَمَا تَصْنَعُ فِي حَجِّكَ","id":"Telah menceritakan kepada kami [Ya'qub bin Ibrahim] Telah menceritakan kepada kami [Ismail] Telah menceritakan kepada kami [Ibnu Juraij] katanya, Telah menceritakan kepadaku ['Atha\"], bahwasanya [Shafwan bin Ya'la bin Umayyah] mengabarinya, [Ya'la] berujar; \"Sekiranya aku melihat Rasulullah shallallahu 'alaihi wasallam ketika wahyu diturunkan kepadanya! Katanya, maka ketika Nabi shallallahu 'alaihi wasallam berada di Ji'ranah yang ketika itu beliau dinaungi dengan sebuah kain bersama beberapa orang sahabatnya, tiba-tiba seorang arab pedusunan (badui,) yang memakai jubah beraroma minyak wangi menemuinya dan bertanya; \"Wahai Rasulullah, bagaimana pendapatmu tentang seseorang yang berihram untuk umrah dengan jubah setelah diberi wewangian? Umar lantas memberi isyarat kepada Ya'la dengan tangannya yang pesannya; \"Kemari\". Ya'la kemudian datang dan memasukkan kepalanya. Serta merta wajah Rasulullah memerah dan naik darah beberapa saat, kemudian reda. Kata beliau: \"Mana si arab badui yang bertanya tentang Umrah? Ia pun kemudian dicari dan didatangkan. Lalu Nabi bersabda: \"Wewangian yang ada padamu, tolong cucilah tiga kali, adapun jubah, maka tanggalkanlah, kemudian lakukan dalam umrahmu sebagaimana kamu lakukan dalam hajimu.\""},"3710":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ حَدَّثَنَا وُهَيْبٌ حَدَّثَنَا عَمْرُو بْنُ يَحْيَى عَنْ عَبَّادِ بْنِ تَمِيمٍ عَنْ عَبْدِ اللَّهِ بْنِ زَيْدِ بْنِ عَاصِمٍ قَالَلَمَّا أَفَاءَ اللَّهُ عَلَى رَسُولِهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ حُنَيْنٍ قَسَمَ فِي النَّاسِ فِي الْمُؤَلَّفَةِ قُلُوبُهُمْ وَلَمْ يُعْطِ الْأَنْصَارَ شَيْئًا فَكَأَنَّهُمْ وَجَدُوا إِذْ لَمْ يُصِبْهُمْ مَا أَصَابَ النَّاسَ فَخَطَبَهُمْ فَقَالَ يَا مَعْشَرَ الْأَنْصَارِ أَلَمْ أَجِدْكُمْ ضُلَّالًا فَهَدَاكُمْ اللَّهُ بِي وَكُنْتُمْ مُتَفَرِّقِينَ فَأَلَّفَكُمْ اللَّهُ بِي وَعَالَةً فَأَغْنَاكُمْ اللَّهُ بِي كُلَّمَا قَالَ شَيْئًا قَالُوا اللَّهُ وَرَسُولُهُ أَمَنُّ قَالَ مَا يَمْنَعُكُمْ أَنْ تُجِيبُوا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ كُلَّمَا قَالَ شَيْئًا قَالُوا اللَّهُ وَرَسُولُهُ أَمَنُّ قَالَ لَوْ شِئْتُمْ قُلْتُمْ جِئْتَنَا كَذَا وَكَذَا أَتَرْضَوْنَ أَنْ يَذْهَبَ النَّاسُ بِالشَّاةِ وَالْبَعِيرِ وَتَذْهَبُونَ بِالنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى رِحَالِكُمْ لَوْلَا الْهِجْرَةُ لَكُنْتُ امْرَأً مِنْ الْأَنْصَارِ وَلَوْ سَلَكَ النَّاسُ وَادِيًا وَشِعْبًا لَسَلَكْتُ وَادِيَ الْأَنْصَارِ وَشِعْبَهَا الْأَنْصَارُ شِعَارٌ وَالنَّاسُ دِثَارٌ إِنَّكُمْ سَتَلْقَوْنَ بَعْدِي أُثْرَةً فَاصْبِرُوا حَتَّى تَلْقَوْنِي عَلَى الْحَوْضِ","id":"Telah menceritakan kepada kami [Musa bin Ismail] Telah menceritakan kepada kami [Wuhaib] Telah menceritakan kepada kami [Amru bin Yahya] dari [Abbad bin Tamim] dari [Abdullah bin Zaid bin Ashim] katanya, ketika Allah memberi Rasul-Nya shallallahu 'alaihi wasallam rampasan (fai) pada perang Hunain, beliau membagi rampasan itu untuk orang-orang yang hatinya masih perlu ditarbiyah (muallaf), dan beliau sama sekali tidak memberi bagian sahabat anshar. Rupanya sahabat anshar ini emosi karena tidak memperoleh bagian sebagaimana yang lain memperolehnya. Maka kemudian Rasulullah menyampaikan pidato: \"Hadirin kaum Anshar, bukankah aku dahulu menjumpai kalian dalam keadaan sesat lantas Allah memberi kalian petunjuk dengan perantaraanku? Dahulu kalian dalam keadaan terpecah-belah lantas Allah mendamaikan kalian dengan perantaraanku? Dan kalian dalam keadaan miskin lantas Allah mengayakan kalian dengan perantaraanku? Setiap kali Nabi menyampaikan sesuatu, mereka jawab; \"Allah dan rasul-Nya lebih terpercaya.\" Beliau meneruskan: \"Lantas alasan apa yang menghalangi kalian menerima Rasulullah shallallahu 'alaihi wasallam?\" Kata Zaid, setiap kali Rasulullah mengatakan sesuatu mereka jawab; \"Allah dan rasul-Nya lebih terpercaya!\" Kata Nabi: \"Silahkan kalian mengatakan; Anda datang kepada kami dengan demikian dan demikian.\" Tidakkah kalian puas manusia membawa kambing dan unta, sedang kalian membawa Nabi shallallahu 'alaihi wasallam kalian shallallahu 'alaihi wasallam ke persinggahan kalian? kalaulah bukan karena hijrah, aku pasti menjadi orang Anshar, kalaulah manusia mengarungi sebuah lembah dan lereng, niscaya aku mengarungi lembah dan lereng Anshar. Anshar adalah pakaian luar -maksudnya primer dan utama- sedang manusia lain hanyalah pakaian dalam -maksudnya sekunder, kurang utama- sepeninggalku, akan kalian temui sikap-sikap egoistis dan individualistis, maka bersabarlah kalian hingga kalian menemuiku di telaga.\""},"3711":{"ar":"حَدَّثَنِي عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ حَدَّثَنَا هِشَامٌ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي أَنَسُ بْنُ مَالِكٍ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ نَاسٌ مِنْ الْأَنْصَارِ حِينَ أَفَاءَ اللَّهُ عَلَى رَسُولِهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا أَفَاءَ مِنْ أَمْوَالِ هَوَازِنَ فَطَفِقَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُعْطِي رِجَالًا الْمِائَةَ مِنْ الْإِبِلِ فَقَالُوا يَغْفِرُ اللَّهُ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُعْطِي قُرَيْشًا وَيَتْرُكُنَا وَسُيُوفُنَا تَقْطُرُ مِنْ دِمَائِهِمْ قَالَ أَنَسٌ فَحُدِّثَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمَقَالَتِهِمْ فَأَرْسَلَ إِلَى الْأَنْصَارِ فَجَمَعَهُمْ فِي قُبَّةٍ مِنْ أَدَمٍ وَلَمْ يَدْعُ مَعَهُمْ غَيْرَهُمْ فَلَمَّا اجْتَمَعُوا قَامَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ مَا حَدِيثٌ بَلَغَنِي عَنْكُمْ فَقَالَ فُقَهَاءُ الْأَنْصَارِ أَمَّا رُؤَسَاؤُنَا يَا رَسُولَ اللَّهِ فَلَمْ يَقُولُوا شَيْئًا وَأَمَّا نَاسٌ مِنَّا حَدِيثَةٌ أَسْنَانُهُمْ فَقَالُوا يَغْفِرُ اللَّهُ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُعْطِي قُرَيْشًا وَيَتْرُكُنَا وَسُيُوفُنَا تَقْطُرُ مِنْ دِمَائِهِمْ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَإِنِّي أُعْطِي رِجَالًا حَدِيثِي عَهْدٍ بِكُفْرٍ أَتَأَلَّفُهُمْ أَمَا تَرْضَوْنَ أَنْ يَذْهَبَ النَّاسُ بِالْأَمْوَالِ وَتَذْهَبُونَ بِالنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى رِحَالِكُمْ فَوَاللَّهِ لَمَا تَنْقَلِبُونَ بِهِ خَيْرٌ مِمَّا يَنْقَلِبُونَ بِهِ قَالُوا يَا رَسُولَ اللَّهِ قَدْ رَضِينَا فَقَالَ لَهُمْ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَتَجِدُونَ أُثْرَةً شَدِيدَةً فَاصْبِرُوا حَتَّى تَلْقَوْا اللَّهَ وَرَسُولَهُ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَإِنِّي عَلَى الْحَوْضِ قَالَ أَنَسٌ فَلَمْ يَصْبِرُوا","id":"Telah menceritakan kepadaku [Abdullah bin Muhammad] Telah menceritakan kepada kami [Hisyam] Telah mengabarkan kepada kami [Ma'mar] dari [Az Zuhri] katanya, telah mengabarkan kepadaku [Anas bin Malik] radliallahu 'anhu, katanya, sejumlah anshar mengatakan; ketika Allah memberi rampasan fai kepada Nabi shallallahu 'alaihi wasallam Shallallahu'alaihiwasallam, beliau memberi bagian kepada Quraisy dan membiarkan kami-kami, Anshar. Padahal pedang kami masih meneteskan darah mereka. Kata Anas, maka hal itu disampaikan kepada Rasulullah shallallahu 'alaihi wasallam. Seketika itu pula Rasulullah langsung mengutus utusan ke Anshar dan mengumpulkan mereka dalam sebuah kubah yang terbuat dari tanah liat dan tidak beliau undang selain mereka, Anshar. Setelah semua Anshar berkumpul, Rasulullah shallallahu 'alaihi wasallam berdiri dan bersabda: \"Apa maksud protes yang telah kudengar dari kalian? Para pemuka Anshar menjawab; \"Adapun para pemimpin-pemimpin kami wahai rasulullah, mereka sama sekali tak menyampaikan protes sepatah katapun, adapun generasi muda kami, memang mereka katakana; \"Kiranya Allah mengampuni Rasulullah Shallallahu'alaihiwasallam, sebab ia beri Quraisy namun membiarkan kami-kami ini, padahal pedang kami masih meneteskan darah mereka (musuh Quraisy musyrik). Maka Nabi shallallahu 'alaihi wasallam memberi jawaban \"Sungguh aku memberi beberapa orang yang baru saja terentaskan dari kekufuran (baru masuk Islam) dengan maksud aku menjinakkan hati mereka, apakah kalian tidak puas sekiranya manusia membawa harta sedang kalian membawa Nabi shallallahu 'alaihi wasallam ke perumahan kalian? Demi Allah, apa yang kalian bawa pulang, \"Jauh lebih istimewa\" daripada yang mereka bawa pulang. Mereka lantas berujar; \"Wahai Rasulullah, kami semua sekarang telah ridha.\" \"Kalian, kata Nabi selanjutnya, akan menemui sifat-sifat super egoisme, maka bersabarlah kalian hingga kalian temui Allah dan Rasul-Nya Shallallahu'alaihiwasallam, karena aku berada di telaga. Kata Anas, namun mereka tidak bersabar.\""},"3712":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي التَّيَّاحِ عَنْ أَنَسٍ قَالَلَمَّا كَانَ يَوْمُ فَتْحِ مَكَّةَ قَسَمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ غَنَائِمَ بَيْنَ قُرَيْشٍ فَغَضِبَتْ الْأَنْصَارُ قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَا تَرْضَوْنَ أَنْ يَذْهَبَ النَّاسُ بِالدُّنْيَا وَتَذْهَبُونَ بِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالُوا بَلَى قَالَ لَوْ سَلَكَ النَّاسُ وَادِيًا أَوْ شِعْبًا لَسَلَكْتُ وَادِيَ الْأَنْصَارِ أَوْ شِعْبَهُمْ","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] Telah menceritakan kepada kami [Syu'bah] dari [Abu At Tayyah] dari [Anas] katanya, ketika terjadi penaklukan Makkah, Rasulullah shallallahu 'alaihi wasallam membagi-bagi hanya untuk Quraisy. Maka kabilah merasa marah. Nabi shallallahu 'alaihi wasallam segera mengkritisi: \"Tidakkah kalian ridha jika orang-orang pergi membawa dunia sementara kalian pergi membawa Rasulullah shallallahu 'alaihi wasallam? 'Baik, ' Jawab Anshar. Nabi meneruskan: \"Kalaulah orang-orang mengarungi sebuah lembah atau lereng gunung, niscaya aku mengarungi lembah Anshar atau lereng gunung mereka.\""},"3713":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا أَزْهَرُ عَنْ ابْنِ عَوْنٍ أَنْبَأَنَا هِشَامُ بْنُ زَيْدِ بْنِ أَنَسٍ عَنْ أَنَسٍ رَضِيَ اللَّهُ عَنْهُ قَالَلَمَّا كَانَ يَوْمُ حُنَيْنٍ الْتَقَى هَوَازِنُ وَمَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَشَرَةُ آلَافٍ وَالطُّلَقَاءُ فَأَدْبَرُوا قَالَ يَا مَعْشَرَ الْأَنْصَارِ قَالُوا لَبَّيْكَ يَا رَسُولَ اللَّهِ وَسَعْدَيْكَ لَبَّيْكَ نَحْنُ بَيْنَ يَدَيْكَ فَنَزَلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَنَا عَبْدُ اللَّهِ وَرَسُولُهُ فَانْهَزَمَ الْمُشْرِكُونَ فَأَعْطَى الطُّلَقَاءَ وَالْمُهَاجِرِينَ وَلَمْ يُعْطِ الْأَنْصَارَ شَيْئًا فَقَالُوا فَدَعَاهُمْ فَأَدْخَلَهُمْ فِي قُبَّةٍ فَقَالَ أَمَا تَرْضَوْنَ أَنْ يَذْهَبَ النَّاسُ بِالشَّاةِ وَالْبَعِيرِ وَتَذْهَبُونَ بِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَوْ سَلَكَ النَّاسُ وَادِيًا وَسَلَكَتْ الْأَنْصَارُ شِعْبًا لَاخْتَرْتُ شِعْبَ الْأَنْصَارِ","id":"Telah menceritakan kepada kami [Ali bin Abdullah] Telah menceritakan kepada kami [Azhar] dari [Ibnu Aun] Telah memberitakan kepada kami [Hisyam bin Zaid bin Anas] dari [Anas] radliallahu 'anhu katanya; ketika perang Hunain, bani Hawazin ketika itu bertemu Nabi shallallahu 'alaihi wasallam beserta sahabatnya yang jumlahnya sekitar sepuluh ribu orang beserta para tawanan yang dibebaskan. Lantas Hawazin kocar-kacir melarikan diri. Kata Nabi: \"Wahai segenap anshar! Mereka menjawab; \"Baik ya Rasulullah, dan kami memenuhi ajakanmu dengan senang hati, dan selalu siap!\" Lantas Nabi shallallahu 'alaihi wasallam singgah sambil mengucapkan: \"Aku adalah hamba Allah dan Rasul-Nya!\" Orang-orang musyrik pun kocar-kacir. Selanjutnya Rasulullah memberi bagian orang-orang yang dimerdekakan dan kaum muhajirin, namun beliau sama sekali tidak memberi orang Anshar.\" Maka orang-orang Anshar pun melakukan protes dan kritik atas kebijakan Nabi. Atas kelakuan mereka ini, Nabi memanggil mereka dan mengajak mereka ke dalam sebuah kubah (ruangan), lantas Nabi sampaikan: \"Tidakkah kalian ridha jika orang-orang pulang membawa kambing dan unta, sedang kalian pulang membawa Rasulullah Shallallahu'alaihiwasallam? Beliau juga bersabda: \"Kalaulah orang-orang mengarungi sebuah lembah dan anshar mengarungi lembah lain, niscaya kupilih lembah yang dikarungi kaum Anshar.\""},"3714":{"ar":"حَدَّثَنِي مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا غُنْدَرٌ حَدَّثَنَا شُعْبَةُ قَالَ سَمِعْتُ قَتَادَةَ عَنْ أَنَسِ بْنِ مَالِكٍ رَضِيَ اللَّهُ عَنْهُ قَالَجَمَعَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَاسًا مِنْ الْأَنْصَارِ فَقَالَ إِنَّ قُرَيْشًا حَدِيثُ عَهْدٍ بِجَاهِلِيَّةٍ وَمُصِيبَةٍ وَإِنِّي أَرَدْتُ أَنْ أَجْبُرَهُمْ وَأَتَأَلَّفَهُمْ أَمَا تَرْضَوْنَ أَنْ يَرْجِعَ النَّاسُ بِالدُّنْيَا وَتَرْجِعُونَ بِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى بُيُوتِكُمْ قَالُوا بَلَى قَالَ لَوْ سَلَكَ النَّاسُ وَادِيًا وَسَلَكَتْ الْأَنْصَارُ شِعْبًا لَسَلَكْتُ وَادِيَ الْأَنْصَارِ أَوْ شِعْبَ الْأَنْصَارِ","id":"Telah menceritakan kepadaku [Muhammad bin Basyar] Telah menceritakan kepada kami [Ghundar] Telah menceritakan kepada kami [Syu'bah] katanya, aku mendengar [Qatadah] dari [Anas bin Malik] radliallahu 'anhu, katanya, suatu kali Nabi shallallahu 'alaihi wasallam mengumpulkan beberapa orang Anshar dan bersabda: \"Quraisy adalah kabilah yang baru saja meninggalkan masa-masa kejahiliyahan dan \"kerusakan agama\", maka aku ingin menjinakkan dan mengayomi mereka, tidakkah kalian puas jika orang-orang pulang dengan membawa harta duniawi sementara kalian pulang dengan membawa Rasulullah shallallahu 'alaihi wasallam ke rumah-rumah kalian? Jawab mereka: \"Tentu.\" Kata Nabi: \"kalaulah manusia mengarungi sebuah lembah dan anshar mengarungi sebuah lereng gunung, niscaya kukarungi lembah anshar atau lereng Anshar.\""},"3715":{"ar":"حَدَّثَنَا أَبُو النُّعْمَانِ حَدَّثَنَا حَمَّادٌ حَدَّثَنَا أَيُّوبُ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا قَالَبَعَثَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَرِيَّةً قِبَلَ نَجْدٍ فَكُنْتُ فِيهَا فَبَلَغَتْ سِهَامُنَا اثْنَيْ عَشَرَ بَعِيرًا وَنُفِّلْنَا بَعِيرًا بَعِيرًا فَرَجَعْنَا بِثَلَاثَةَ عَشَرَ بَعِيرًا","id":"Telah menceritakan kepada kami [Abu Nu'man] Telah menceritakan kepada kami [Hammad] Telah menceritakan kepada kami [Ayyub] dari [Nafi] dari [Ibnu Umar] radliallahu 'anhu, katanya, Nabi shallallahu 'alaihi wasallam mengirim sebuah ekpedisi militer ke arah Najed dan aku termasuk dalam pasukan itu, bagian ghanimah kami sebanyak dua belas ekor unta dan kami diberi nafl (pemberian cuma-cuma) masing-masing seekor unta, sehingga kami pulang masing-masing membawa tiga belas ekor unta."},"3716":{"ar":"حَدَّثَنِي مَحْمُودٌ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ ح و حَدَّثَنِي نُعَيْمٌ أَخْبَرَنَا عَبْدُ اللَّهِ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ سَالِمٍ عَنْ أَبِيهِ قَالَبَعَثَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَالِدَ بْنَ الْوَلِيدِ إِلَى بَنِي جَذِيمَةَ فَدَعَاهُمْ إِلَى الْإِسْلَامِ فَلَمْ يُحْسِنُوا أَنْ يَقُولُوا أَسْلَمْنَا فَجَعَلُوا يَقُولُونَ صَبَأْنَا صَبَأْنَا فَجَعَلَ خَالِدٌ يَقْتُلُ مِنْهُمْ وَيَأْسِرُ وَدَفَعَ إِلَى كُلِّ رَجُلٍ مِنَّا أَسِيرَهُ حَتَّى إِذَا كَانَ يَوْمٌ أَمَرَ خَالِدٌ أَنْ يَقْتُلَ كُلُّ رَجُلٍ مِنَّا أَسِيرَهُ فَقُلْتُ وَاللَّهِ لَا أَقْتُلُ أَسِيرِي وَلَا يَقْتُلُ رَجُلٌ مِنْ أَصْحَابِي أَسِيرَهُ حَتَّى قَدِمْنَا عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرْنَاهُ فَرَفَعَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَدَهُ فَقَالَ اللَّهُمَّ إِنِّي أَبْرَأُ إِلَيْكَ مِمَّا صَنَعَ خَالِدٌ مَرَّتَيْنِ","id":"Telah menceritakan kepadaku [Mahmud] Telah menceritakan kepada kami [Abdurrazaq] Telah mengabarkan kepada kami [Ma'mar] -lewat jalur periwayatan lain-Telah menceritakan kepadaku [Nu'aim] Telah mengabarkan kepada kami [Abdullah] Telah mengabarkan kepada kami [Ma'mar] dari [Azzuhri] dari [Salim] dari [Ayahnya] katanya, Nabi shallallahu 'alaihi wasallam suatu kali mengirim Khalid bin Al Walid ke bani Jidzamah dengan misi mengajak mereka masuk Islam, namun rupanya mereka belum fasih mengucapkan; \"Aslamnaa\" (kami masuk Islam) sehingga mereka keceplosan mengucapkan Shabba'naa (yang makna secara harfiah kami sembah matahari), mereka terus saja mengucapkan Shabba'na, Shabba'na -sekalipun maksudnya aslamnaa-Maka Khalid membantai diantara mereka dan sebagian lain ia tawan, dan ia serahi masing-masing kami seorang tawanan yang ia perintahkan untuk dibunuh di hari selanjutnya. Saya protes \"Demi Allah, saya tak akan membunuh tawananku, dan setiap kawanku juga tak akan membunuh tawanannya.\" Hingga akhirnya kami menemui Nabi shallallahu 'alaihi wasallam dan kami utarakan kasusnya kepada beliau Shallallahu'alaihiwasallam. Serta merta Nabi shallallahu 'alaihi wasallam mengangkat tangannya sembari bersabda: ALLAAHUMMA INNII ABRA'U ILAIKA MIMMAA SHANA'A KHALID (Ya Allah, saya berlepas diri kepada-MU dari perbuatan-perbuatan Khalid bin Al Walid. Beliau ulang dua kali."},"3717":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا عَبْدُ الْوَاحِدِ حَدَّثَنَا الْأَعْمَشُ قَالَ حَدَّثَنِي سَعْدُ بْنُ عُبَيْدَةَ عَنْ أَبِي عَبْدِ الرَّحْمَنِ عَنْ عَلِيٍّ رَضِيَ اللَّهُ عَنْهُ قَالَبَعَثَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَرِيَّةً فَاسْتَعْمَلَ رَجُلًا مِنْ الْأَنْصَارِ وَأَمَرَهُمْ أَنْ يُطِيعُوهُ فَغَضِبَ فَقَالَ أَلَيْسَ أَمَرَكُمْ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ تُطِيعُونِي قَالُوا بَلَى قَالَ فَاجْمَعُوا لِي حَطَبًا فَجَمَعُوا فَقَالَ أَوْقِدُوا نَارًا فَأَوْقَدُوهَا فَقَالَ ادْخُلُوهَا فَهَمُّوا وَجَعَلَ بَعْضُهُمْ يُمْسِكُ بَعْضًا وَيَقُولُونَ فَرَرْنَا إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ النَّارِ فَمَا زَالُوا حَتَّى خَمَدَتْ النَّارُ فَسَكَنَ غَضَبُهُ فَبَلَغَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لَوْ دَخَلُوهَا مَا خَرَجُوا مِنْهَا إِلَى يَوْمِ الْقِيَامَةِ الطَّاعَةُ فِي الْمَعْرُوفِ","id":"Telah menceritakan kepada kami [Musaddad] Telah menceritakan kepada kami [Abdul Wahid] Telah menceritakan kepada kami [Al A'masy] katanya, Telah menceritakan kepadaku [Sa'd bin Ubaidah] dari [Abu Abdurrahman] dari [Ali] radliallahu 'anhu, katanya, Nabi shallallahu 'alaihi wasallam suatu kali mengirim sebuah ekspedisi militer dan beliau angkat seorang laki-laki anshar untuk mengomandoi mereka sekaligus beliau perintahkan agar menaatinya. Selanjutnya si laki-laki anshar ini emosi dan berujar; \"Bukankah Nabi telah perintahkan kalian untuk menaatiku?\"Itu benar\" Jawab anggotanya. Kata sang komandan; \"Kalau begitu, kumpulkanlah kayu bakar untukku.\" Mereka pun melaksanakannya. Ia meneruskan intruksinya; \"Sekarang, nyalakanlah api!\" Mereka pun menyalakan. Ia meneruskan lagi; \"Sekarang masuklah kalian ke api itu! Dan sebagian mereka mencegah sebagian lainya seraya berujar \"Awas, kita dahulu menemui Nabi shallallahu 'alaihi wasallam dalam rangka menghindari api!\" Terus mereka dengungkan peringatan ini hingga api padam, kemudian emosi sang komandan mereda. Berita ini sampai kepada Nabi shallallahu 'alaihi wasallam sehingga beliau bersabda: \"Kalaulah mereka memasukinya, niscaya mereka tak bakalan bisa keluar hingga kiamat tiba. Sesungguhnya ketaatan hanya berlaku dalam kebaikan.\""},"3718":{"ar":"حَدَّثَنَا مُوسَى حَدَّثَنَا أَبُو عَوَانَةَ حَدَّثَنَا عَبْدُ الْمَلِكِ عَنْ أَبِي بُرْدَةَ قَالَبَعَثَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَبَا مُوسَى وَمُعَاذَ بْنَ جَبَلٍ إِلَى الْيَمَنِ قَالَ وَبَعَثَ كُلَّ وَاحِدٍ مِنْهُمَا عَلَى مِخْلَافٍ قَالَ وَالْيَمَنُ مِخْلَافَانِ ثُمَّ قَالَ يَسِّرَا وَلَا تُعَسِّرَا وَبَشِّرَا وَلَا تُنَفِّرَا فَانْطَلَقَ كُلُّ وَاحِدٍ مِنْهُمَا إِلَى عَمَلِهِ وَكَانَ كُلُّ وَاحِدٍ مِنْهُمَا إِذَا سَارَ فِي أَرْضِهِ كَانَ قَرِيبًا مِنْ صَاحِبِهِ أَحْدَثَ بِهِ عَهْدًا فَسَلَّمَ عَلَيْهِ فَسَارَ مُعَاذٌ فِي أَرْضِهِ قَرِيبًا مِنْ صَاحِبِهِ أَبِي مُوسَى فَجَاءَ يَسِيرُ عَلَى بَغْلَتِهِ حَتَّى انْتَهَى إِلَيْهِ وَإِذَا هُوَ جَالِسٌ وَقَدْ اجْتَمَعَ إِلَيْهِ النَّاسُ وَإِذَا رَجُلٌ عِنْدَهُ قَدْ جُمِعَتْ يَدَاهُ إِلَى عُنُقِهِ فَقَالَ لَهُ مُعَاذٌ يَا عَبْدَ اللَّهِ بْنَ قَيْسٍ أَيُّمَ هَذَا قَالَ هَذَا رَجُلٌ كَفَرَ بَعْدَ إِسْلَامِهِ قَالَ لَا أَنْزِلُ حَتَّى يُقْتَلَ قَالَ إِنَّمَا جِيءَ بِهِ لِذَلِكَ فَانْزِلْ قَالَ مَا أَنْزِلُ حَتَّى يُقْتَلَ فَأَمَرَ بِهِ فَقُتِلَ ثُمَّ نَزَلَ فَقَالَ يَا عَبْدَ اللَّهِ كَيْفَ تَقْرَأُ الْقُرْآنَ قَالَ أَتَفَوَّقُهُ تَفَوُّقًا قَالَ فَكَيْفَ تَقْرَأُ أَنْتَ يَا مُعَاذُ قَالَ أَنَامُ أَوَّلَ اللَّيْلِ فَأَقُومُ وَقَدْ قَضَيْتُ جُزْئِي مِنْ النَّوْمِ فَأَقْرَأُ مَا كَتَبَ اللَّهُ لِي فَأَحْتَسِبُ نَوْمَتِي كَمَا أَحْتَسِبُ قَوْمَتِي","id":"Telah menceritakan kepada kami [Musa] Telah menceritakan kepada kami [Abu Awanah] Telah menceritakan kepada kami [Abdul Malik] dari [Abu Burdah] katanya, Rasulullah shallallahu 'alaihi wasallam mengutus Abu Musa dan Mu'adz bin Jabal ke negeri Yaman. Dan beliau utus keduanya pada lokasi yang berbeda -sekalipun satu negara, Yaman- sebab Yaman ketika itu dibagi dua negara bagian, kemudian Nabi berpesan: \"Tolong kalian permudah, jangan kalian persulit, berilah kabar gembira, jangan kalian jadikan masyarakat alergi (terhadap agama).\" Masing-masing pun berangkat mengerjakan tugasnya. Selanjutnya masing-masing diantara keduanya jika berjalan di wilayah temannya, ia berusaha dekat dengan kawannya dan membuat perjanjian (kesepakatan bertemu) lantas mengucapkan salam. Di kemudian hari Mu'adz berjalan di kawasan kawannya, Abu musa, ia datang dengan berkendara diatas bighalnya hingga menemuinya yang ketika itu Mu'adz sedang duduk dikerumuni manusia. Tak tahunya disana ada seseorang yang kedua tangannya diikat diatas tengkuknya. Mu'adz menyapa; \"Wahai Abdullah bin Qais (nama lain Abu Musa), orang ini memangnya mengapa?\" Kata Abu Musa; \"Orang ini telah kufur setelah keIslamannya.\" Mu'adz menjawab; \"Saya tak akan turun hingga ia dibunuh.\" Abu Musa meneruskan; \"Orang ini didatangkan semata-mata karena kemurtadannya, maka turunlah.\" Muadz menjawab; \"Saya tak sudi turun dari hewan tungganganku hingga dibunuh.\" Maka Abu Musa perintahkan hingga si laki-laki dibunuh. Kemudian Muadz turun. Muadz bertanya; \"Wahai Abdullah, bagaimana engkau membaca alquran? Jawab Muadz; \"Saya berusaha membaca sebanyak-banyaknya, lalu engkau sendiri bagaimana wahai muadz?\" Kalau aku, jawab Muadz, saya tidur diawal malam kemudian bangun, kulaksanakan hak tidurku, dan aku baca apa yang Allah tetapkan bagiku, Aku berharap pahala dari tidurku sebagaimana berharap pahala dari shalat malamku."},"3719":{"ar":"حَدَّثَنِي إِسْحَاقُ حَدَّثَنَا خَالِدٌ عَنْ الشَّيْبَانِيِّ عَنْ سَعِيدِ بْنِ أَبِي بُرْدَةَ عَنْ أَبِيهِ عَنْ أَبِي مُوسَى الْأَشْعَرِيِّ رَضِيَ اللَّهُ عَنْهُأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعَثَهُ إِلَى الْيَمَنِ فَسَأَلَهُ عَنْ أَشْرِبَةٍ تُصْنَعُ بِهَا فَقَالَ وَمَا هِيَ قَالَ الْبِتْعُ وَالْمِزْرُ فَقُلْتُ لِأَبِي بُرْدَةَ مَا الْبِتْعُ قَالَ نَبِيذُ الْعَسَلِ وَالْمِزْرُ نَبِيذُ الشَّعِيرِ فَقَالَ كُلُّ مُسْكِرٍ حَرَامٌرَوَاهُ جَرِيرٌ وَعَبْدُ الْوَاحِدِ عَنْ الشَّيْبَانِيِّ عَنْ أَبِي بُرْدَةَ","id":"Telah menceritakan kepadaku [Ishaq] Telah menceritakan kepada kami [Khalid] dari [Asysyaibani] dari [Said bin Abu Burdah] dari [ayahnya] dari [Abu Musa Al'Asy'ari] radliallahu 'anhu, adalah Nabi shallallahu 'alaihi wasallam pernah mengutusnya ke negeri Yaman, selanjutnya beliau bertanya minuman yang biasa diminum disana. Tanya Nabi; \"Minuman apa yang biasa disana? ia menjawab; kebiasaan minuman disana adalah \"Albit'u\" dan \"Al Mizru\", aku mencoba bertanya kepada Abu Burdah? apa maksud minuman Albit'u? Jawabnya, ia adalah rendaman kurma, sedang almizru ialah sebutan untuk minuman dari rendaman tepung. Lantas Rasulullah berujar: \"Setiap yang memabukkan adalah haram.\" [Jarir] dan [Abdul Wahid] meriwayatkan hadits ini dari [Abu Burdah]."},"3720":{"ar":"حَدَّثَنَا مُسْلِمٌ حَدَّثَنَا شُعْبَةُ حَدَّثَنَا سَعِيدُ بْنُ أَبِي بُرْدَةَ عَنْ أَبِيهِ قَالَبَعَثَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جَدَّهُ أَبَا مُوسَى وَمُعَاذًا إِلَى الْيَمَنِ فَقَالَ يَسِّرَا وَلَا تُعَسِّرَا وَبَشِّرَا وَلَا تُنَفِّرَا وَتَطَاوَعَا فَقَالَ أَبُو مُوسَى يَا نَبِيَّ اللَّهِ إِنَّ أَرْضَنَا بِهَا شَرَابٌ مِنْ الشَّعِيرِ الْمِزْرُ وَشَرَابٌ مِنْ الْعَسَلِ الْبِتْعُ فَقَالَ كُلُّ مُسْكِرٍ حَرَامٌ فَانْطَلَقَا فَقَالَ مُعَاذٌ لِأَبِي مُوسَى كَيْفَ تَقْرَأُ الْقُرْآنَ قَالَ قَائِمًا وَقَاعِدًا وَعَلَى رَاحِلَتِي وَأَتَفَوَّقُهُ تَفَوُّقًا قَالَ أَمَّا أَنَا فَأَنَامُ وَأَقُومُ فَأَحْتَسِبُ نَوْمَتِي كَمَا أَحْتَسِبُ قَوْمَتِي وَضَرَبَ فُسْطَاطًا فَجَعَلَا يَتَزَاوَرَانِ فَزَارَ مُعَاذٌ أَبَا مُوسَى فَإِذَا رَجُلٌ مُوثَقٌ فَقَالَ مَا هَذَا فَقَالَ أَبُو مُوسَى يَهُودِيٌّ أَسْلَمَ ثُمَّ ارْتَدَّ فَقَالَ مُعَاذٌ لَأَضْرِبَنَّ عُنُقَهُتَابَعَهُ الْعَقَدِيُّ وَوَهْبٌ عَنْ شُعْبَةَ وَقَالَ وَكِيعٌ وَالْنَّضْرُ وَأَبُو دَاوُدَ عَنْ شُعْبَةَ عَنْ سَعِيدٍ عَنْ أَبِيهِ عَنْ جَدِّهِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَوَاهُ جَرِيرُ بْنُ عَبْدِ الْحَمِيدِ عَنْ الشَّيْبَانِيِّ عَنْ أَبِي بُرْدَةَ","id":"Telah menceritakan kepada kami [Muslim] Telah menceritakan kepada kami [Syubah] Telah menceritakan kepada kami [Said bin Abu Burdah] dari [ayahnya] katanya, Nabi shallallahu 'alaihi wasallam mengutus kakeknya, alias Abu Musa dan Mu'adz ke Yaman dan beliau pesan: \"Hendaklah kalian mempermudah, jangan mempersulit, berilah kabar gembira jangan kalian jadikan manusia lari (alergi terhadap agama), dan bersatu padulah.\" Lantas Abu Musa bertanya; \"Wahai Nabiyullah, wilayah kami disana ada minuman dari tepung yang sering diistilahkan almizru dan ada minuman dari kurma yang sering diistilahkan albit\"u? Lantas beliau bersabda: \"Setiap yang memabukkan adalah haram.\" Keduanya pun berangkat. lalu Mu'adz berkata kepada Abu Musa; \"Bagaimana engkau membaca Al Quran? Jawab Abu Musa; \"Baik dalam keadaan berdiri, duduk, atau saat aku diatas hewan tungganganku, namun terkadang aku masih menambah.\" Sedang Muadz mengatakan; \"Jika aku, kadang aku tidur dan shalat malam, aku perkirakan waktu tidurku seperti waktu aku shalat malam, masing-masing terus membuat kemah dan keduanya silih berganti melakukan kunjungan. Suatu kali Mu'adz mengunjungi Abu Musa, tak tahunya ada seorang laki-laki yang diikat. Mu'adz bertanya; \"Siapa laki-laki ini sebenarnya? Abu Musa menjawab \"Dia seorang yahudi yang masuk Islam, kemudian murtad. Maka Mu'adz menjawab; \"Kalau aku, sungguh akan kupenggal tengkuknya.\" Hadits ini dikuatkan jalur perawinya oleh [Al'Aqdi] dan [Wahab] dari [Syu'bah] dan [Waki'], [Nadhr] dan [Abu Dawud] mengatakan dari [Syu'bah] dari [Said] dari [ayahnya] dari [kakeknya] dari Nabi shallallahu 'alaihi wasallam. Dan [Jarir bin Abdul Hamid] meriwayatkannya dari [Asy Syaibani] dari [Abu Burdah]."},"3721":{"ar":"حَدَّثَنِي عَبَّاسُ بْنُ الْوَلِيدِ هُوَ النَّرْسِيُّ حَدَّثَنَا عَبْدُ الْوَاحِدِ عَنْ أَيُّوبَ بْنِ عَائِذٍ حَدَّثَنَا قَيْسُ بْنُ مُسْلِمٍ قَالَ سَمِعْتُ طَارِقَ بْنَ شِهَابٍ يَقُولُ حَدَّثَنِي أَبُو مُوسَى الْأَشْعَرِيُّ رَضِيَ اللَّهُ عَنْهُ قَالَبَعَثَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى أَرْضِ قَوْمِي فَجِئْتُ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُنِيخٌ بِالْأَبْطَحِ فَقَالَ أَحَجَجْتَ يَا عَبْدَ اللَّهِ بْنَ قَيْسٍ قُلْتُ نَعَمْ يَا رَسُولَ اللَّهِ قَالَ كَيْفَ قُلْتَ قَالَ قُلْتُ لَبَّيْكَ إِهْلَالًا كَإِهْلَالِكَ قَالَ فَهَلْ سُقْتَ مَعَكَ هَدْيًا قُلْتُ لَمْ أَسُقْ قَالَ فَطُفْ بِالْبَيْتِ وَاسْعَ بَيْنَ الصَّفَا وَالْمَرْوَةِ ثُمَّ حِلَّ فَفَعَلْتُ حَتَّى مَشَطَتْ لِي امْرَأَةٌ مِنْ نِسَاءِ بَنِي قَيْسٍ وَمَكُثْنَا بِذَلِكَ حَتَّى اسْتُخْلِفَ عُمَرُ","id":"Telah menceritakan kepadaku [Abbas bin Al Walid, alias An Narsi] Telah menceritakan kepada kami [Abdul Wahid] dari [Ayyub bin 'Aidz] Telah menceritakan kepada kami [Qais bin Muslim] katanya, aku mendengar [Thariq bin Syihab] mengatakan, Telah menceritakan kepadaku [Abu Musa Al Asy'ary] radliallahu 'anhu, katanya, Rasulullah shallallahu 'alaihi wasallam mengutusku ke perkampungan kaumku, selanjutnya aku singgah di Abtah. Rasulullah bertanya: \"Apa telah engkau lakukan haji wahai Abdullah bin Qais (sebutan Abu Musa)?\"Ya Rasulullah\" jawabku. Tanya Nabi: \"Dan bagaimana engkau ucapkan niyat ihram-mu? Kata Abu Musa; aku ucapkan; \"LABBAIKA IHLAALAN KA IHLAALIKA.\" (Aku penuhi panggilan-Mu, aku berniyat ihram sebagaimana ihrammu (Rasul, maksudnya). Nabi bertanya: \"Apa engkau juga membawa binatang kurban?\"Saya belum membawa, \" jawabku. Kata Nabi: \"Kalau begitu, lakukanlah thawaf di Baitullah dan lakukanlah sa'i antara Shafa dan Marwa, kemudian lakukanlah tahallul!\" dan aku pun mengerjakannya hingga seorang wanita bani Qais menyisiriku dan kami terus melakukan yang demikian hingga Umar diangkat menjadi khalifah."},"3722":{"ar":"حَدَّثَنِي حِبَّانُ أَخْبَرَنَا عَبْدُ اللَّهِ عَنْ زَكَرِيَّاءَ بْنِ إِسْحَاقَ عَنْ يَحْيَى بْنِ عَبْدِ اللَّهِ بْنِ صَيْفِيٍّ عَنْ أَبِي مَعْبَدٍ مَوْلَى ابْنِ عَبَّاسٍ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِمُعَاذِ بْنِ جَبَلٍ حِينَ بَعَثَهُ إِلَى الْيَمَنِ إِنَّكَ سَتَأْتِي قَوْمًا مِنْ أَهْلِ الْكِتَابِ فَإِذَا جِئْتَهُمْ فَادْعُهُمْ إِلَى أَنْ يَشْهَدُوا أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَأَنَّ مُحَمَّدًا رَسُولُ اللَّهِ فَإِنْ هُمْ طَاعُوا لَكَ بِذَلِكَ فَأَخْبِرْهُمْ أَنَّ اللَّهَ قَدْ فَرَضَ عَلَيْهِمْ خَمْسَ صَلَوَاتٍ فِي كُلِّ يَوْمٍ وَلَيْلَةٍ فَإِنْ هُمْ طَاعُوا لَكَ بِذَلِكَ فَأَخْبِرْهُمْ أَنَّ اللَّهَ قَدْ فَرَضَ عَلَيْهِمْ صَدَقَةً تُؤْخَذُ مِنْ أَغْنِيَائِهِمْ فَتُرَدُّ عَلَى فُقَرَائِهِمْ فَإِنْ هُمْ طَاعُوا لَكَ بِذَلِكَ فَإِيَّاكَ وَكَرَائِمَ أَمْوَالِهِمْ وَاتَّقِ دَعْوَةَ الْمَظْلُومِ فَإِنَّهُ لَيْسَ بَيْنَهُ وَبَيْنَ اللَّهِ حِجَابٌقَالَ أَبُو عَبْد اللَّهِ طَوَّعَتْ طَاعَتْ وَأَطَاعَتْ لُغَةٌ طِعْتُ وَطُعْتُ وَأَطَعْتُ","id":"Telah menceritakan kepadaku [Hibban] Telah mengabarkan kepada kami [Abdullah] dari [Zakaria bin Ishaq] dari [Yahya bin Abdullah bin Shaifi] dari [Abu Ma'bad] -mantan budak [Ibnu Abbas] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda kepada Mu'ad ketika mengutusnya ke Yaman, \"Engkau akan mendatangi kaum ahli kitab, Apabilah telah sampai kepada mereka maka serulah mereka untuk bersaksi bahwa tidak Tuhan yang berhak untuk disembah selain Allah dan Muhammad adalah utusan-Nya. Jika mereka ta'at untuk itu, maka beritahukanlah bahwa Allah telah mewajibkan kepada mereka shalat lima waktu sehari semalam. Jika mereka ta'at untuk itu, maka beritahukanlah bahwa Allah telah mewajibkan kepada mereka untuk mengeluarkan zakat harta mereka, di ambil dari orang-orang kaya mereka dan diberikan kepada orang-orang yang miskin dari mereka. Jika mereka taat untuk itu, maka hati-hatilah engkau dari mengambil harta milik mereka yang paling baik, takutlah engkau dengan do`anya orang dizhalimi, sebab antara ia dengan Allah tidak ada yang menghalanginya.\" Abu Abdullah berkata; 'Thawwa'at, thaa'at, 'Athaa'at secara bahasa adalah 'Ti'tu, dan Tu'tu, serta 'Atha'tu. (Aku ta'at)."},"3723":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا شُعْبَةُ عَنْ حَبِيبِ بْنِ أَبِي ثَابِتٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ عَمْرِو بْنِ مَيْمُونٍ أَنَّ مُعَاذًا رَضِيَ اللَّهُ عَنْهُلَمَّا قَدِمَ الْيَمَنَ صَلَّى بِهِمْ الصُّبْحَ فَقَرَأَ{ وَاتَّخَذَ اللَّهُ إِبْرَاهِيمَ خَلِيلًا }فَقَالَ رَجُلٌ مِنْ الْقَوْمِ لَقَدْ قَرَّتْ عَيْنُ أُمِّ إِبْرَاهِيمَزَادَ مُعَاذٌ عَنْ شُعْبَةَ عَنْ حَبِيبٍ عَنْ سَعِيدٍ عَنْ عَمْرٍو أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعَثَ مُعَاذًا إِلَى الْيَمَنِ فَقَرَأَ مُعَاذٌ فِي صَلَاةِ الصُّبْحِ سُورَةَ النِّسَاءِ فَلَمَّا قَالَ{ وَاتَّخَذَ اللَّهُ إِبْرَاهِيمَ خَلِيلًا }قَالَ رَجُلٌ خَلْفَهُ قَرَّتْ عَيْنُ أُمِّ إِبْرَاهِيمَ","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] Telah menceritakan kepada kami [Syu'bah] dari [Habib bin Abu Tsabit] dari [Sa'id bin Jubair] dari ['Amru bin Maimun] bahwa ketika [Mu'adz] sampai di Yaman, dia shalat shubuh bersama kaumnya dengan membaca ayat: \"Allah telah menjadikan Ibrahim sebagai kekasihnya.\" Maka berkatalah salah seorang dari kaumnya; 'Mata ibu Ibrahim telah berbinar karena bahagia.' Sedangkan di dalam riwayat lain, [Mu'adz] menambahkan dari [Syu'bah] dari [Habib] dari [Sa'id] dari [Amru] bahwa Nabi shallallahu 'alaihi wasallam mengutus [Mu'adz bin Jabal] ke Yaman. Lalu pada waktu shalat shubuh Mu'adz bin Jabal membaca surat An Nisa, tatkala sampai ayat; Allah telah menjadikan Ibrahim sebagai kekasih-Nya.\" Seseorang di belakangnya berkata; 'Mata Ibu Ibrahim telah berbinar karena bahagia.'"},"3724":{"ar":"حَدَّثَنِي أَحْمَدُ بْنُ عُثْمَانَ حَدَّثَنَا شُرَيْحُ بْنُ مَسْلَمَةَ حَدَّثَنَا إِبْرَاهِيمُ بْنُ يُوسُفَ بْنِ إِسْحَاقَ بْنِ أَبِي إِسْحَاقَ حَدَّثَنِي أَبِي عَنْ أَبِي إِسْحَاقَ سَمِعْتُ الْبَرَاءَ رَضِيَ اللَّهُ عَنْهُبَعَثَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَعَ خَالِدِ بْنِ الْوَلِيدِ إِلَى الْيَمَنِ قَالَ ثُمَّ بَعَثَ عَلِيًّا بَعْدَ ذَلِكَ مَكَانَهُ فَقَالَ مُرْ أَصْحَابَ خَالِدٍ مَنْ شَاءَ مِنْهُمْ أَنْ يُعَقِّبَ مَعَكَ فَلْيُعَقِّبْ وَمَنْ شَاءَ فَلْيُقْبِلْ فَكُنْتُ فِيمَنْ عَقَّبَ مَعَهُ قَالَ فَغَنِمْتُ أَوَاقٍ ذَوَاتِ عَدَدٍ","id":"Telah menceritakan kepadaku [Ahmad bin 'Utsman] Telah menceritakan kepada kami [Syuraih bin Maslamah] Telah menceritakan kepada kami [Ibrahim bin Yusuf bin Ishaq bin Abu Ishaq] Telah menceritakan kepadaku [Bapakku] dari [Abu Ishaq] Aku mendengar [Al Bara'] berkata; Rasulullah shallallahu 'alaihi wasallam mengutus kami bersama Khalid bin Walid ke Yaman, Al Bara berkata; kemudian Nabi shallallahu 'alaihi wasallam mengutus Ali untuk mengganti kepemimpinanya. Beliau berkata kepada Ali; 'Suruhlah tentara Khalid untuk ikut bersama kamu ke Yaman, bagi siapa saja yang mau, dan siapa yang ingin pulang, silahkan!.' Dan aku termasuk orang yang ikut bersama Ali. Al Bara berkata; 'lalu aku mendapatkan ghanimah yang begitu banyak.'"},"3725":{"ar":"حَدَّثَنِي مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا رَوْحُ بْنُ عُبَادَةَ حَدَّثَنَا عَلِيُّ بْنُ سُوَيْدِ بْنِ مَنْجُوفٍ عَنْ عَبْدِ اللَّهِ بْنِ بُرَيْدَةَ عَنْ أَبِيهِ رَضِيَ اللَّهُ عَنْهُ قَالَبَعَثَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلِيًّا إِلَى خَالِدٍ لِيَقْبِضَ الْخُمُسَ وَكُنْتُ أُبْغِضُ عَلِيًّا وَقَدْ اغْتَسَلَ فَقُلْتُ لِخَالِدٍ أَلَا تَرَى إِلَى هَذَا فَلَمَّا قَدِمْنَا عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذَكَرْتُ ذَلِكَ لَهُ فَقَالَ يَا بُرَيْدَةُ أَتُبْغِضُ عَلِيًّا فَقُلْتُ نَعَمْ قَالَ لَا تُبْغِضْهُ فَإِنَّ لَهُ فِي الْخُمُسِ أَكْثَرَ مِنْ ذَلِكَ","id":"Telah menceritakan kepadaku [Muhammad bin Basysyar] Telah menceritakan kepada kami [Rauh bin 'Ubadah] Telah menceritakan kepada kami ['Ali bin Suaid bin Manjuf] dari ['Abdullah bin Buraidah] dari [Bapaknya] dia berkata; Rasulullah Shallallahu'alaihiwasallam mengutus 'Ali untuk menemui Khalid bin Al Walid agar mengambil seperlima harta rampasan perang. Aku adalah orang yang membenci Ali yang pada waktu itu dia sudah mandi. Lalu aku berkata kepada Khalid; 'Apa kau tidak melihat apa yang dilakukannya? Tatkala aku menemui Rasulullah Shallallahu'alaihiwasallam aku sampaikan kepada beliau perihal Ali maka beliau bersabda: \"Wahai Buraidah! Apakah kau membenci 'Ali?\" aku Buraidah menjawab: 'Ya.' Rasulullah Shallallahu'alaihiwasallam bersabda: \"Jangan membencinya karena ia berhak mendapatkan yang lebih dari itu dari harta rampasan perang.\""},"3726":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا عَبْدُ الْوَاحِدِ عَنْ عُمَارَةَ بْنِ الْقَعْقَاعِ بْنِ شُبْرُمَةَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ أَبِي نُعْمٍ قَالَ سَمِعْتُ أَبَا سَعِيدٍ الْخُدْرِيَّ يَقُولُبَعَثَ عَلِيُّ بْنُ أَبِي طَالِبٍ رَضِيَ اللَّهُ عَنْهُ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ الْيَمَنِ بِذُهَيْبَةٍ فِي أَدِيمٍ مَقْرُوظٍ لَمْ تُحَصَّلْ مِنْ تُرَابِهَا قَالَ فَقَسَمَهَا بَيْنَ أَرْبَعَةِ نَفَرٍ بَيْنَ عُيَيْنَةَ بْنِ بَدْرٍ وَأَقْرَعَ بْنِ حابِسٍ وَزَيْدِ الْخَيْلِ وَالرَّابِعُ إِمَّا عَلْقَمَةُ وَإِمَّا عَامِرُ بْنُ الطُّفَيْلِ فَقَالَ رَجُلٌ مِنْ أَصْحَابِهِ كُنَّا نَحْنُ أَحَقَّ بِهَذَا مِنْ هَؤُلَاءِ قَالَ فَبَلَغَ ذَلِكَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَلَا تَأْمَنُونِي وَأَنَا أَمِينُ مَنْ فِي السَّمَاءِ يَأْتِينِي خَبَرُ السَّمَاءِ صَبَاحًا وَمَسَاءً قَالَ فَقَامَ رَجُلٌ غَائِرُ الْعَيْنَيْنِ مُشْرِفُ الْوَجْنَتَيْنِ نَاشِزُ الْجَبْهَةِ كَثُّ اللِّحْيَةِ مَحْلُوقُ الرَّأْسِ مُشَمَّرُ الْإِزَارِ فَقَالَ يَا رَسُولَ اللَّهِ اتَّقِ اللَّهَ قَالَ وَيْلَكَ أَوَلَسْتُ أَحَقَّ أَهْلِ الْأَرْضِ أَنْ يَتَّقِيَ اللَّهَ قَالَ ثُمَّ وَلَّى الرَّجُلُ قَالَ خَالِدُ بْنُ الْوَلِيدِ يَا رَسُولَ اللَّهِ أَلَا أَضْرِبُ عُنُقَهُ قَالَ لَا لَعَلَّهُ أَنْ يَكُونَ يُصَلِّي فَقَالَ خَالِدٌ وَكَمْ مِنْ مُصَلٍّ يَقُولُ بِلِسَانِهِ مَا لَيْسَ فِي قَلْبِهِ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنِّي لَمْ أُومَرْ أَنْ أَنْقُبَ عَنْ قُلُوبِ النَّاسِ وَلَا أَشُقَّ بُطُونَهُمْ قَالَ ثُمَّ نَظَرَ إِلَيْهِ وَهُوَ مُقَفٍّ فَقَالَ إِنَّهُ يَخْرُجُ مِنْ ضِئْضِئِ هَذَا قَوْمٌ يَتْلُونَ كِتَابَ اللَّهِ رَطْبًا لَا يُجَاوِزُ حَنَاجِرَهُمْ يَمْرُقُونَ مِنْ الدِّينِ كَمَا يَمْرُقُ السَّهْمُ مِنْ الرَّمِيَّةِ وَأَظُنُّهُ قَالَ لَئِنْ أَدْرَكْتُهُمْ لَأَقْتُلَنَّهُمْ قَتْلَ ثَمُودَ","id":"Telah menceritakan kepada kami [Qutaibah] Telah menceritakan kepada kami ['Abdul Wahid] dari ['Umarah bin Al Qa'qa' bin Syubrumah]; Telah menceritakan kepada kami ['Abdur Rahman bin Abu Nu'am] dia berkata; Aku mendengar [Abu Sa'id Al Khudri] berkata; Ali bin Abu Thalib mengirimkan sebatang emas yang belum diangkat dari cetakannya kepada Rasulullah shallallahu 'alaihi wasallam. Rasulullah shallallahu 'alaihi wasallam membagikannya kepada empat orang: 'Uyainah bin Badr, Aqra bin Habis, Zaid Al Khail, dan yang keempat adalah Alqamah atau 'Amir bin Thufail. Melihat hal itu, salah seorang sahabatnya berkata; \"Kami lebih berhak atas emas tersebut daripada orang-orang ini.\" Ketika kabar itu didengar Rasulullah shallallahu 'alaihi wasallam, Rasulullah shallallahu 'alaihi wasallam bersabda: 'Tidakkah kalian mempercayaiku padahal aku adalah orang yang terpercaya dari langit (surga)? Aku menerima kabar dari langit, pagi hari maupun sore hari.' Tiba-tiba seorang laki-laki dengan mata cekung, tulang pipi cembung, dahi menonjol, berjanggut tipis, berkepala gundul dan menggunakan ikat pinggang berdiri dan berkata; 'Ya Rasulullah! Takutlah kepada Allah.' Nabi shallallahu 'alaihi wasallam bersabda: 'Celaka kamu.' Bukankah di muka bumi ini akulah yang paling takut kepada Allah? ' Orang itu beranjak dari tempat duduknya. Khalid bin Walid berkata; 'Ya Rasulullah! Izinkan aku menebasnya. Nabi shallallahu 'alaihi wasallam bersabda: Jangan, bisa jadi ia mengerjakan shalat. Khalid berkata; Berapa banyak orang yang shalat berkata dengan lisannya yang tidak sesuai dengan hatinya. Rasulullah shallallahu 'alaihi wasallam bersabda: Aku tidak diperintah untuk menyelidiki hati seseorang atau mengetahui isi perutnya. Kemudian Nabi shallallahu 'alaihi wasallam melihat kepada orang itu ketika hendak pergi: sesungguhnya dari keturunannya akan muncul suatu kaum yang membaca Kitabullah tetapi hanya sampai tenggorokannya saja. Mereka lepas dari agama sebagaimana lepasnya anak panah dari busurnya. Aku kira Nabi shallallahu 'alaihi wasallam juga berkata; \"Seandainya aku hadir pada masa itu aku akan membunuh mereka sebagaimana bangsa Tsamud dibinasakan.\""},"3727":{"ar":"حَدَّثَنَا الْمَكِّيُّ بْنُ إِبْرَاهِيمَ عَنْ ابْنِ جُرَيْجٍ قَالَ عَطَاءٌ قَالَ جَابِرٌ أَمَرَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلِيًّا أَنْ يُقِيمَ عَلَى إِحْرَامِهِ زَادَ مُحَمَّدُ بْنُ بَكْرٍ عَنْ ابْنِ جُرَيْجٍ قَالَ عَطَاءٌ قَالَ جَابِرٌفَقَدِمَ عَلِيُّ بْنُ أَبِي طَالِبٍ رَضِيَ اللَّهُ عَنْهُ بِسِعَايَتِهِ قَالَ لَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمَ أَهْلَلْتَ يَا عَلِيُّ قَالَ بِمَا أَهَلَّ بِهِ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فَأَهْدِ وَامْكُثْ حَرَامًا كَمَا أَنْتَ قَالَ وَأَهْدَى لَهُ عَلِيٌّ هَدْيًا","id":"Telah menceritakan kepada kami [Al Makki bin Ibrahim] dari [Ibnu Juraij], ['Atha] berkata; [Jabir] berkata; Nabi shallallahu 'alaihi wasallam menyuruh 'Ali untuk melakukan ihram. [Muhammad bin Bakr] menambahkan dari [Ibnu Juraij], [Atha] berkata; [Jabir] berkata; kemudian Ali datang dari Yaman, maka Nabi shallallahu 'alaihi wasallam bertanya kepadanya; 'Wahai Ali dengan apa kamu bertalbiyah? Dia menjawab; saya bertalbiyah dengan talbiyah Rasulullah shallallahu 'alaihi wasallam. Beliau bersabda: 'Menyembelihlah dan tetaplah tinggal di Haram. Jabir berkata; lalu Ali menyembelih hewan kurban.'"},"3728":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا بِشْرُ بْنُ الْمُفَضَّلِ عَنْ حُمَيْدٍ الطَّوِيلِ حَدَّثَنَا بَكْرٌ أَنَّهُ ذَكَرَ لِابْنِ عُمَرَ أَنَّ أَنَسًا حَدَّثَهُمْأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَهَلَّ بِعُمْرَةٍ وَحَجَّةٍ فَقَالَ أَهَلَّ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالْحَجِّ وَأَهْلَلْنَا بِهِ مَعَهُ فَلَمَّا قَدِمْنَا مَكَّةَ قَالَ مَنْ لَمْ يَكُنْ مَعَهُ هَدْيٌ فَلْيَجْعَلْهَا عُمْرَةً وَكَانَ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَدْيٌ فَقَدِمَ عَلَيْنَا عَلِيُّ بْنُ أَبِي طَالِبٍ مِنْ الْيَمَنِ حَاجًّا فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمَ أَهْلَلْتَ فَإِنَّ مَعَنَا أَهْلَكَ قَالَ أَهْلَلْتُ بِمَا أَهَلَّ بِهِ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فَأَمْسِكْ فَإِنَّ مَعَنَا هَدْيًا","id":"Telah menceritakan kepada kami [Musaddad] Telah menceritakan kepada kami [Bisyr bin Al Mufadldlal] dari [Humaid Ath Thawil] Telah menceritakan kepada kami [Bakr] bahwasanya dia berkata kepada [Ibnu 'Umar] bahwa Anas pernah menceritakan kepada mereka mengenai talbiyah Rasulullah shallallahu 'alaihi wasallam dengan umrah dan haji. Anas berkata; Nabi shallallahu 'alaihi wasallam bertalbiyah dengan haji, dan kami pun bertalbiyah bersama beliau. Tatkala kami sampai di Makkah, beliau bersabda; 'Barangsiapa diantara kalian yang tidak memiliki hewan kurban maka niatkanlah untuk umrah.' Sedangkan pada waktu itu Rasulullah memiliki hewan kurban. Tiba-tiba Ali bin Abi Thalib kembali dari Yaman, lalu Nabi Shallallahu'alaihi wasallam bertanya kepadanya: \"Dengan apa kamu bertalbiyah sesungguhnya keluargamu bersama kami?, \" Ali menjawab; saya bertalbiyah dengan talbiyah Rasulullah Shallallahu'alaihi wasallam, maka Rasulullah Shallallahu'alaihi wasallam bersabda: 'Tenanglah, kami membawa hewan kurban.'"},"3729":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا خَالِدٌ حَدَّثَنَا بَيَانٌ عَنْ قَيْسٍ عَنْ جَرِيرٍ قَالَكَانَ بَيْتٌ فِي الْجَاهِلِيَّةِ يُقَالُ لَهُ ذُو الْخَلَصَةِ وَالْكَعْبَةُ الْيَمانِيَةُ وَالْكَعْبَةُ الشَّأْمِيَّةُ فَقَالَ لِي النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَلَا تُرِيحُنِي مِنْ ذِي الْخَلَصَةِ فَنَفَرْتُ فِي مِائَةٍ وَخَمْسِينَ رَاكِبًا فَكَسَرْنَاهُ وَقَتَلْنَا مَنْ وَجَدْنَا عِنْدَهُ فَأَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَخْبَرْتُهُ فَدَعَا لَنَا وَلِأَحْمَسَ","id":"Telah menceritakan kepada kami [Musaddad] Telah menceritakan kepada kami [Khalid] Telah menceritakan kepada kami [Bayan] dari [Qais] dari [Jarir] dia berkata; Pada masa Jahiliyah ada sebuah rumah yang diberi nama Dzul Khalshah, rumah itu biasa disebut dengan Al Ka'bah Al Yamaniyah dan Al Ka'bah As Sya'miyah. Lalu Rasulullah shallallahu 'alaihi wasallam bersabda kepadaku: \"Bisakah kamu menyenangkanku dengan menghancurkan Dzil Khalashah? Kata Jabir; lalu aku berangkat dengan seratus lima puluh pasukan berkuda yang tangguh. Kami hancurkan dan kami bunuh orang-orang yang berada di sekitarnya. Kemudian aku kembali mengabarkan keberhasilannya kepada Rasulullah shallallahu 'alaihi wasallam, dan Rasulullah pun mendo'akan kepada kami dan para penunggang kuda yang tangguh."},"3730":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا يَحْيَى حَدَّثَنَا إِسْمَاعِيلُ حَدَّثَنَا قَيْسٌ قَالَ قَالَ لِي جَرِيرٌ رَضِيَ اللَّهُ عَنْهُقَالَ لِي النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَلَا تُرِيحُنِي مِنْ ذِي الْخَلَصَةِ وَكَانَ بَيْتًا فِي خَثْعَمَ يُسَمَّى الْكَعْبَةَ الْيَمانِيَةَ فَانْطَلَقْتُ فِي خَمْسِينَ وَمِائَةِ فَارِسٍ مِنْ أَحْمَسَ وَكَانُوا أَصْحَابَ خَيْلٍ وَكُنْتُ لَا أَثْبُتُ عَلَى الْخَيْلِ فَضَرَبَ فِي صَدْرِي حَتَّى رَأَيْتُ أَثَرَ أَصَابِعِهِ فِي صَدْرِي وَقَالَ اللَّهُمَّ ثَبِّتْهُ وَاجْعَلْهُ هَادِيًا مَهْدِيًّا فَانْطَلَقَ إِلَيْهَا فَكَسَرَهَا وَحَرَّقَهَا ثُمَّ بَعَثَ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ رَسُولُ جَرِيرٍ وَالَّذِي بَعَثَكَ بِالْحَقِّ مَا جِئْتُكَ حَتَّى تَرَكْتُهَا كَأَنَّهَا جَمَلٌ أَجْرَبُ قَالَ فَبَارَكَ فِي خَيْلِ أَحْمَسَ وَرِجَالِهَا خَمْسَ مَرَّاتٍ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] Telah menceritakan kepada kami [Yahya] Telah menceritakan kepada kami [Isma'il] Telah menceritakan kepada kami [Qais] dia berkata; [Jarir] berkata kepadaku; \"Rasulullah shallallahu 'alaihi wasallam berkata kepada saya: \"Wahai Jarir, pimpinlah pasukan kaum muslimin ke Dzil Khalashah suatu tempat ibadah orang-orang Khats'am yang disebut Ka'bah Yamaniah.\" Maka aku segera berangkat bersama seratus lima puluh pasukan penunggang kuda yang tangguh. Namun pada waktu itu aku tidak bisa diam di atas kudaku. Maka beliau memukul dadaku dengan tangannya hingga aku dapat melihat bekas jari-jari beliau di dadaku. Beliau berdo'a: \"Ya Allah, kokohkanlah ia dan jadikanlah dia orang yang dapat memberi petunjuk dan ditunjuki.\" Lalu dia berangkat kemudian menghancurkan dan membakarnya dengan api. Setelah itu Jarir mengutus seseorang untuk mengabarkan kemenangan kepada Rasulullah shallallahu 'alaihi wasallam. Setelah sampai, utusan itu berkata kepada Rasulullah; 'Tidaklah aku menemuimu kecuali aku telah meninggalkan rumah itu dalam keadaan terbakar hingga seakan-akan seekor unta berkudisan (berwarna hitam).' Maka kemudian Rasulullah memberkahi kuda-kuda yang tangguh dan para penunggangnya sebanyak lima kali."},"3731":{"ar":"حَدَّثَنَا يُوسُفُ بْنُ مُوسَى أَخْبَرَنَا أَبُو أُسَامَةَ عَنْ إِسْمَاعِيلَ بْنِ أَبِي خَالِدٍ عَنْ قَيْسٍ عَنْ جَرِيرٍ قَالَقَالَ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَلَا تُرِيحُنِي مِنْ ذِي الْخَلَصَةِ فَقُلْتُ بَلَى فَانْطَلَقْتُ فِي خَمْسِينَ وَمِائَةِ فَارِسٍ مِنْ أَحْمَسَ وَكَانُوا أَصْحَابَ خَيْلٍ وَكُنْتُ لَا أَثْبُتُ عَلَى الْخَيْلِ فَذَكَرْتُ ذَلِكَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَضَرَبَ يَدَهُ عَلَى صَدْرِي حَتَّى رَأَيْتُ أَثَرَ يَدِهِ فِي صَدْرِي وَقَالَ اللَّهُمَّ ثَبِّتْهُ وَاجْعَلْهُ هَادِيًا مَهْدِيًّا قَالَ فَمَا وَقَعْتُ عَنْ فَرَسٍ بَعْدُ قَالَ وَكَانَ ذُو الْخَلَصَةِ بَيْتًا بِالْيَمَنِ لِخَثْعَمَ وَبَجِيلَةَ فِيهِ نُصُبٌ تُعْبَدُ يُقَ��لُ لَهُ الْكَعْبَةُ قَالَ فَأَتَاهَا فَحَرَّقَهَا بِالنَّارِ وَكَسَرَهَا قَالَ وَلَمَّا قَدِمَ جَرِيرٌ الْيَمَنَ كَانَ بِهَا رَجُلٌ يَسْتَقْسِمُ بِالْأَزْلَامِ فَقِيلَ لَهُ إِنَّ رَسُولَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَا هُنَا فَإِنْ قَدَرَ عَلَيْكَ ضَرَبَ عُنُقَكَ قَالَ فَبَيْنَمَا هُوَ يَضْرِبُ بِهَا إِذْ وَقَفَ عَلَيْهِ جَرِيرٌ فَقَالَ لَتَكْسِرَنَّهَا وَلَتَشْهَدَنَّ أَنْ لَا إِلَهَ إِلَّا اللَّهُ أَوْ لَأَضْرِبَنَّ عُنُقَكَ قَالَ فَكَسَرَهَا وَشَهِدَ ثُمَّ بَعَثَ جَرِيرٌ رَجُلًا مِنْ أَحْمَسَ يُكْنَى أَبَا أَرْطَاةَ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُبَشِّرُهُ بِذَلِكَ فَلَمَّا أَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يَا رَسُولَ اللَّهِ وَالَّذِي بَعَثَكَ بِالْحَقِّ مَا جِئْتُ حَتَّى تَرَكْتُهَا كَأَنَّهَا جَمَلٌ أَجْرَبُ قَالَ فَبَرَّكَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى خَيْلِ أَحْمَسَ وَرِجَالِهَا خَمْسَ مَرَّاتٍ","id":"Telah menceritakan kepada kami [Yusuf bin Musa] Telah mengabarkan kepada kami [Abu Usamah] dari [Isma'il bin Khalid] dari [Qais] dari [Jarir] dia berkata; Rasulullah berkata kepadaku: \"\"Wahai Jarir, bisakah kamu menyenangkanku dengan menghancurkan Dzil Khalashah? Aku menjawab: 'Tentu.' Maka aku segera berangkat bersama seratus lima puluh pasukan penunggang kuda yang tangguh. Namun pada waktu itu aku tidak bisa diam di atas kudaku. Maka hal itu aku kabarkan kepada Rasulullah, lalu beliau memukul dadaku dengan tangannya hingga aku dapat melihat bekas tangan beliau di dadaku. Beliau berdo'a: \"Ya Allah, kokohkanlah ia dan jadikanlah dia orang yang dapat memberi petunjuk dan ditunjuki.\" Jabir berkata; setelah itu aku tidak pernah jatuh lagi dari kudaku. Dzil Khalashah adalah suatu tempat ibadah di Yaman milik orang-orang Khats'am dan Bajilah. Di dalamnya banyak patung-patung yang mereka sembah, mereka menyebutnya Ka'bah.\" Lalu Jarir mendatanginya dan membakarnya dengan api serta menghancurkannya. Setelah Jarir sampai di Yaman di sana dia melihat seseorang yang sedang bersumpah atas nama berhala-berhala. Maka dikatakan kepadanya; Sesungguhnya Rasulullah shallallahu 'alaihi wasallam berada di sini, apabila beliau berkehendak beliau bisa saja memenggal lehermu. Tatkala orang tersebut menghancurkan berhalanya, tiba-tiba Jarir berdiri di hadapannya seraya berkata; 'Apakah kamu mau menghancurkannya dan bersaksi bahwa tidak ada Ilah selain Allah atau aku penggal lehermu.' Jarir berkata; 'maka orang itu menghancurkannya dan bersyahadat. Kemudian Jarir mengutus seorang laki-laki dari Ahmas bernama Abu Arthah untuk mengabarkan kemenangan kepada Rasulullah shallallahu 'alaihi wasallam. Setelah sampai, utusan itu berkata kepada Rasulullah; 'Demi Dzat yang telah mengutus engkau dengan kebenaran, tidaklah aku menemuimu kecuali aku telah meninggalkan rumah itu dalam keadaan terbakar hingga seakan-akan seekor unta berkudisan (berwarna hitam).' Maka kemudian Rasulullah memberkahi kuda-kuda Ahmas dan para penunggangnya sebanyak lima kali."},"3732":{"ar":"حَدَّثَنَا إِسْحَاقُ أَخْبَرَنَا خَالِدُ بْنُ عَبْدِ اللَّهِ عَنْ خَالِدٍ الْحَذَّاءِ عَنْ أَبِي عُثْمَانَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعَثَ عَمْرَو بْنَ الْعَاصِ عَلَى جَيْشِ ذَاتِ السُّلَاسِلِ قَالَ فَأَتَيْتُهُ فَقُلْتُ أَيُّ النَّاسِ أَحَبُّ إِلَيْكَ قَالَ عَائِشَةُ قُلْتُ مِنْ الرِّجَالِ قَالَ أَبُوهَا قُلْتُ ثُمَّ مَنْ قَالَ عُمَرُ فَعَدَّ رِجَالًا فَسَكَتُّ مَخَافَةَ أَنْ يَجْعَلَنِي فِي آخِرِهِمْ","id":"Telah menceritakan kepada kami [Ishaq] Telah mengabarkan kepada kami [Khalid bin 'Abdullah] dari [Khalid Al Hadzdza'] dari [Abu 'Utsman] bahwa Rasulullah shallallahu 'alaihi wasallam pernah mengutusnya [Amru bin Ash] untuk memimpin pasukan kaum muslimin dalam perang Dzatus Salasil. Amru bin Al Ash berkata; Aku menemui Rasulullah seraya bertanya; Ya Rasulullah, siapakah orang yang engkau cintai? Rasulullah menjawab; 'Aisyah.' Lalu saya tanyakan lagi; Kalau dari kaum laki-laki, siapakah orang yang paling engkau cintai? Rasulullah shallallahu 'alaihi wasallam menjawab: 'Ayah Aisyah (Abu Bakr).' saya bertanya lagi; lalu siapa? Rasulullah menjawab: 'Umar bin Khaththab.' Kemudian beliau menyebutkan beberapa orang sahabat lainnya. Setelah itu aku pun diam karena aku takut termasuk orang yang paling terakhir.'"},"3733":{"ar":"حَدَّثَنِي عَبْدُ اللَّهِ بْنُ أَبِي شَيْبَةَ الْعَبْسِيُّ حَدَّثَنَا ابْنُ إِدْرِيسَ عَنْ إِسْمَاعِيلَ بْنِ أَبِي خَالِدٍ عَنْ قَيْسٍ عَنْ جَرِيرٍ قَالَكُنْتُ بِالْيَمَنِ فَلَقِيتُ رَجُلَيْنِ مِنْ أَهْلِ الْيَمَنِ ذَا كَلَاعٍ وَذَا عَمْرٍو فَجَعَلْتُ أُحَدِّثُهُمْ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لَهُ ذُو عَمْرٍو لَئِنْ كَانَ الَّذِي تَذْكُرُ مِنْ أَمْرِ صَاحِبِكَ لَقَدْ مَرَّ عَلَى أَجَلِهِ مُنْذُ ثَلَاثٍ وَأَقْبَلَا مَعِي حَتَّى إِذَا كُنَّا فِي بَعْضِ الطَّرِيقِ رُفِعَ لَنَا رَكْبٌ مِنْ قِبَلِ الْمَدِينَةِ فَسَأَلْنَاهُمْ فَقَالُوا قُبِضَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَاسْتُخْلِفَ أَبُو بَكْرٍ وَالنَّاسُ صَالِحُونَ فَقَالَا أَخْبِرْ صَاحِبَكَ أَنَّا قَدْ جِئْنَا وَلَعَلَّنَا سَنَعُودُ إِنْ شَاءَ اللَّهُ وَرَجَعَا إِلَى الْيَمَنِ فَأَخْبَرْتُ أَبَا بَكْرٍ بِحَدِيثِهِمْ قَالَ أَفَلَا جِئْتَ بِهِمْ فَلَمَّا كَانَ بَعْدُ قَالَ لِي ذُو عَمْرٍو يَا جَرِيرُ إِنَّ بِكَ عَلَيَّ كَرَامَةً وَإِنِّي مُخْبِرُكَ خَبَرًا إِنَّكُمْ مَعْشَرَ الْعَرَبِ لَنْ تَزَالُوا بِخَيْرٍ مَا كُنْتُمْ إِذَا هَلَكَ أَمِيرٌ تَأَمَّرْتُمْ فِي آخَرَ فَإِذَا كَانَتْ بِالسَّيْفِ كَانُوا مُلُوكًا يَغْضَبُونَ غَضَبَ الْمُلُوكِ وَيَرْضَوْنَ رِضَا الْمُلُوكِ","id":"Telah menceritakan kepadaku ['Abdullah bin Abu Syaibah Al 'Absi] Telah menceritakan kepada kami [Ibnu Idris] dari [Isma'il bin Abu Khalid] dari [Qais] dari [Jarir] dia berkata; Ketika aku berada di Yaman, aku bertemu dengan dua orang Yaman yang bernama dzu-Kala dan Dzy-Amr. Kepada mereka berdua kuceritakan perihal Rasulllah Shallallahu'alaihiwasallam. Dzu-Amr berkata kepadaku, \"Jika cerita tentang sahabatmu itu (Rasulullah Shallallahu'alaihiwasallam) benar, maka ia telah wafat tiga hari yang lalu.\"Maka mereka berdua pergi bersamaku ke Madinah dan ketika jarak kami telah dekat dengan Madinah kami melihat sejumlah orang menunggang binatang-binatang mereka datang dari arah Madinah. Kami bertanya kepada mereka dan mereka berkata,: \"Rasulullah Shallallahu 'Alaih wa Sallam telah wafat dan Abu Bakar telah ditunjuk sebagai khalifah, sementara orang-orang (Muslim) dalam keadaan baik.\"Kemudian mereka (berdua) berkata, \"Katakan kepada sahabatmu (Abu Bakar) bahwa kami (berniat mengunjunginya) dan insya allah, kami akan kembali ke mari.\" Maka mereka (berdua) pulang kembali ke Yaman. Maka hal itu aku kabarkan kepada Abu Bakr. Lalu dia berkata; Kenapa kamu tidak datang bersama mereka. Pada keesokan harinya Dzu Amru berkata kepadaku; Ya Jarir, kamu memiliki kemuliaan padaku, Sungguh aku akan mengabarkan kepadamu satu kabar: Sesungguhnya kalian wahai bangsa Arab, akan senantiasa dalam keadaan baik sebagaimana keadaan saat ini. Karena ketika pemimpin kalian meninggal, kalian memilih pemimpin yang lain. Tetapi jika kalian memilihnya dengan memakai pedang (peperangan), maka hal itu tidak beda dengan para raja yang apa bila mereka murka maka kemurkaannya karena kekuasaan dan apabila rela maka kerelaannya pun karena kekuasaan."},"3734":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ قَالَ حَدَّثَنِي مَالِكٌ عَنْ وَهْبِ بْنِ كَيْسَانَ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُمَا أَنَّهُ قَالَبَعَثَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعْثًا قِبَلَ السَّاحِلِ وَأَمَّرَ عَلَيْهِمْ أَبَا عُبَيْدَةَ بْنَ الْجَرَّاحِ وَهُمْ ثَلَاثُ مِائَةٍ فَخَرَجْنَا وَكُنَّا بِبَعْضِ الطَّرِيقِ فَنِيَ الزَّادُ فَأَمَرَ أَبُو عُبَيْدَةَ بِأَزْوَادِ الْجَيْشِ فَجُمِعَ فَكَانَ مِزْوَدَيْ تَمْرٍ فَكَانَ يَقُوتُنَا كُلَّ يَوْمٍ قَلِيلٌ قَلِيلٌ حَتَّى فَنِيَ فَلَمْ يَكُنْ يُصِيبُنَا إِلَّا تَمْرَةٌ تَمْرَةٌ فَقُلْتُ مَا تُغْنِي عَنْكُمْ تَمْرَةٌ فَقَالَ لَقَدْ وَجَدْنَا فَقْدَهَا حِينَ فَنِيَتْ ثُمَّ انْتَهَيْنَا إِلَى الْبَحْرِ فَإِذَا حُوتٌ مِثْلُ الظَّرِبِ فَأَكَلَ مِنْهَا الْقَوْمُ ثَمَانِيَ عَشْرَةَ لَيْلَةً ثُمَّ أَمَرَ أَبُو عُبَيْدَةَ بِضِلَعَيْنِ مِنْ أَضْلَاعِهِ فَنُصِبَا ثُمَّ أَمَرَ بِرَاحِلَةٍ فَرُحِلَتْ ثُمَّ مَرَّتْ تَحْتَهُمَا فَلَمْ تُصِبْهُمَا","id":"Telah menceritakan kepada kami [Isma'il] dia berkata; Telah menceritakan kepadaku [Malik] dari [Wahb bin Kaisan] dari [Jabir bin 'Abdullah] dia berkata; \"Rasulullah Shalla Allahu 'alaihi wa sallam mengutus delegasi menuju ke pantai. Beliau mengangkat Abu Ubaidah bin Jarrah sebagai pemimpin pasukan. Mereka berjumlah tiga ratus orang.\" Kami berangkat, namun ketika sampai di suatu jalan perbekalan kami habis. Maka Abu Ubaidah memerintahkan untuk mengumpulkan perbekalan pasukan, dan perbekalan pun dikumpulkan. Bekal yang terkumpul berjumlah dua kantung kurma.\" Bekal itulah yang menjadi makanan pokok kami setiap hari, sedikit demi sedikit hingga habis. Sampai kami tidak mendapatkan jatah lagi kecuali hanyalah sebuah kurma tiap orang. Aku bertanya; 'Apalah artinya sebiji kurma.' Abu 'Ubaidah menjawab; 'Kami memang sudah mendapati tidak ada kurma lagi'.\" Jabir berkata; \"Kemudian kami tiba di sebuah pantai. Ternyata ada ikan paus sebesar anak bukit. Maka pasukan pun memakannya selama delapan belas malam. Abu Ubaidah memerintahkan untuk mengambil dua tulang rusuknya, lalu dipancangkan. Kemudian dia memerintahkan untuk mendatangkan seekor unta tunggangan. Ternyata unta tersebut dapat melewati bawah tulang rusuk ikan itu dan ia tidak mengenainya.\""},"3735":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا سُفْيَانُ قَالَ الَّذِي حَفِظْنَاهُ مِنْ عَمْرِو بْنِ دِينَارٍ قَالَ سَمِعْتُ جَابِرَ بْنَ عَبْدِ اللَّهِ يَقُولُبَعَثَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثَلَاثَ مِائَةِ رَاكِبٍ أَمِيرُنَا أَبُو عُبَيْدَةَ بْنُ الْجَرَّاحِ نَرْصُدُ عِيرَ قُرَيْشٍ فَأَقَمْنَا بِالسَّاحِلِ نِصْفَ شَهْرٍ فَأَصَابَنَا جُوعٌ شَدِيدٌ حَتَّى أَكَلْنَا الْخَبَطَ فَسُمِّيَ ذَلِكَ الْجَيْشُ جَيْشَ الْخَبَطِ فَأَلْقَى لَنَا الْبَحْرُ دَابَّةً يُقَالُ لَهَا الْعَنْبَرُ فَأَكَلْنَا مِنْهُ نِصْفَ شَهْرٍ وَادَّهَنَّا مِنْ وَدَكِهِ حَتَّى ثَابَتْ إِلَيْنَا أَجْسَامُنَا فَأَخَذَ أَبُو عُبَيْدَةَ ضِلَعًا مِنْ أَضْلَاعِهِ فَنَصَبَهُ فَعَمَدَ إِلَى أَطْوَلِ رَجُلٍ مَعَهُ قَالَ سُفْيَانُ مَرَّةً ضِلَعًا مِنْ أَضْلَاعِهِ فَنَصَبَهُ وَأَخَذَ رَجُلًا وَبَعِيرًا فَمَرَّ تَحْتَهُ قَالَ جَابِرٌ وَكَانَ رَجُلٌ مِنْ الْقَوْمِ نَحَرَ ثَلَاثَ جَزَائِرَ ثُمَّ نَحَرَ ثَلَاثَ جَزَائِرَ ثُمَّ نَحَرَ ثَلَاثَ جَزَائِرَ ثُمَّ إِنَّ أَبَا عُبَيْدَةَ نَهَاهُ وَكَانَ عَمْرٌو يَقُولُ أَخْبَرَنَا أَبُو صَالِحٍ أَنَّ قَيْسَ بْنَ سَعْدٍ قَالَ لِأَبِيهِ كُنْتُ فِي الْجَيْشِ فَجَاعُوا قَالَ انْحَرْ قَالَ نَحَرْتُ قَالَ ثُمَّ جَاعُوا قَالَ انْحَرْ قَالَ نَحَرْتُ قَالَ ثُمَّ جَاعُوا قَالَ انْحَرْ قَالَ نَحَرْتُ ثُمَّ جَاعُوا قَالَ انْحَرْ قَالَ نُهِيتُ","id":"Telah menceritakan kepada kami ['Ali bin 'Abdullah] Telah menceritakan kepada kami [Sufyan] dia berkata; yang kami hafal dari ['Amru bin Dinar] dia berkata; Aku mendengar [Jabir bin 'Abdullah] berkata; Rasulullah shallallahu 'alaihi wasallam mengutus kami sebanyak tiga ratus penunggang kuda dan pemimpin kami ketika itu adalah Abu Ubaidah bin Jarrah untuk mengintai unta milik orang Qurais. Kemudian kami bermukim di pantai selama setengah bulan. Hingga kami merasa sangat lapar. akhirnya kami memakan daun-daunan yang gugur. Karena itu pasukan kami tersebut dinamai pasukan Khabat (Khabat artinya daun yang gugur). Tiba-tiba laut melemparkan ikan yang disebut Al Anbar. Kami pun makan dari ikan tersebut selama setengah bulan. Dari tubuhnya yang penuh lemak, kami oleskan ke sejujur tubuh kami hingga tubuh kami pulih kembali. Kemudian Abu Ubaidah mengambil tulang rusuk ikan itu, lalu ia pancangkan seukuran orang yang paling tinggi. Sufyan berkata; ia memancangkan tulang rusak itu, lalu memerintahkan seseorang dan untanya melewati dibawahnya. Jabir berkata; di antara pasukan ada yang menyembelih tiga hewan tunggangan, kemudian menyembelih tiga lagi, kemudian menyembelih lagi tiga, lalu hal itu dilarang oleh Abu Ubaidah. Sedangkan 'Amru berkata; Telah mengabarkan kepada kami Abu Shalih bahwa Qais bin Sa'ad berkata kepada Bapaknya; Aku bersama pasukan, lalu mereka kelaparan, kemudian kami disuruh menyembelih binatang, kami pun menyembelih lagi. Namun setelah itu kami kelaparan lagi, hingga kami disuruh menyembelih sampai empat kali. Setelah itu kami dilarang menyembelih lagi."},"3736":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ ابْنِ جُرَيْجٍ قَالَ أَخْبَرَنِي عَمْرٌو أَنَّهُ سَمِعَ جَابِرًا رَضِيَ اللَّهُ عَنْهُ يَقُولُغَزَوْنَا جَيْشَ الْخَبَطِ وَأُمِّرَ أَبُو عُبَيْدَةَ فَجُعْنَا جُوعًا شَدِيدًا فَأَلْقَى الْبَحْرُ حُوتًا مَيِّتًا لَمْ نَرَ مِثْلَهُ يُقَالُ لَهُ الْعَنْبَرُ فَأَكَلْنَا مِنْهُ نِصْفَ شَهْرٍ فَأَخَذَ أَبُو عُبَيْدَةَ عَظْمًا مِنْ عِظَامِهِ فَمَرَّ الرَّاكِبُ تَحْتَهُ فَأَخْبَرَنِي أَبُو الزُّبَيْرِ أَنَّهُ سَمِعَ جَابِرًا يَقُولُ قَالَ أَبُو عُبَيْدَةَ كُلُوا فَلَمَّا قَدِمْنَا الْمَدِينَةَ ذَكَرْنَا ذَلِكَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ كُلُوا رِزْقًا أَخْرَجَهُ اللَّهُ أَطْعِمُونَا إِنْ كَانَ مَعَكُمْ فَأَتَاهُ بَعْضُهُمْ فَأَكَلَهُ","id":"Telah menceritakan kepada kami [Musaddad] Telah menceritakan kepada kami [Yahya] dari [Ibnu Juraij] dia berkata; Telah mengabarkan kepadaku ['Amru] bahwasanya mendengar [Jabir] berkata; 'Kami pernah berperang bersama pasukan Khabath (pemakan daun-daunan) yang pada waktu itu Abu Ubaidah di angkat sebagai pemimpin pasukan. Lalu kami merasa lapar sekali. Tiba-tiba laut melemparkan ikan paus yang tidak pernah aku lihat sebelumnya. Ikan itu disebut al Anbar. Kami makan dari ikan itu selama setengah bulan. Kemudian Abu Ubaidah mengambil salah satu bagian dari tulangnya dan dia pancangkan. Hingga seorang pengendara bisa lewat dibawah tulang itu. Telah mengabarkan kepadaku Abu Az Zubair bahwasanya dia mendengar Jabir berkata; Abu 'Ubaidah berkata; 'Makanlah oleh kalian semua! Tatkala kami sampai di Madinah, kami hal itu kami beritahukan kepada Nabi shallallahu 'alaihi wasallam. Maka beliau bersabda: 'Makanlah, itu adalah rizki yang telah Allah berikan. Jika masih tersisa, berilah kami! Maka sebagiannya di bawakan kepada beliau dan beliau pun memakannya.'"},"3737":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ دَاوُدَ أَبُو الرَّبِيعِ حَدَّثَنَا فُلَيْحٌ عَنْ الزُّهْرِيِّ عَنْ حُمَيْدِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِي هُرَيْرَةَأَنَّ أَبَا بَكْرٍ الصِّدِّيقَ رَضِيَ اللَّهُ عَنْهُ بَعَثَهُ فِي الْحَجَّةِ الَّتِي أَمَّرَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَيْهَا قَبْلَ حَجَّةِ الْوَدَاعِ يَوْمَ النَّحْرِ فِي رَهْطٍ يُؤَذِّنُ فِي النَّاسِ لَا يَحُجُّ بَعْدَ الْعَامِ مُشْرِكٌ وَلَا يَطُوفُ بِالْبَيْتِ عُرْيَانٌ","id":"Telah menceritakan kepada kami [Sulaiman bin Dawud Abu Ar Rabi'] Telah menceritakan kepada kami [Fulaih] dari [Az Zuhri] dari [Humaid bin 'Abdur Rahman] dari [Abu Hurairah] bahwa Abu Bakr Ash Shiddiq ditugaskan oleh Nabi shallallahu 'alaihi wasallam memimpin satu kaum pada hari Nahar sebelum haji Wada untuk memberitahukan kepada orang banyak bahwasannya; 'Sesudah tahun ini orang-orang musyrik tidak boleh lagi haji dan tidak boleh thawaf di ka'bah dalam keadaan telanjang.'"},"3738":{"ar":"حَدَّثَنِي عَبْدُ اللَّهِ بْنُ رَجَاءٍ حَدَّثَنَا إِسْرَائِيلُ عَنْ أَبِي إِسْحَاقَ عَنْ الْبَرَاءِ رَضِيَ اللَّهُ عَنْهُ قَالَآخِرُ سُورَةٍ نَزَلَتْ كَامِلَةً بَرَاءَةٌ وَآخِرُ سُورَةٍ نَزَلَتْ خَاتِمَةُ سُورَةِ النِّسَاءِ{ يَسْتَفْتُونَكَ قُلْ اللَّهُ يُفْتِيكُمْ فِي الْكَلَالَةِ }","id":"Telah menceritakan kepadaku ['Abdullah bin Raja'] Telah menceritakan kepada kami [Israil] dari [Abu Ishaq] dari [Al Bara' radliallahu 'anhu] berkata; Surat yang paling terakhir kali turun secara sempurna adalah surat Al Bara'ah. Dan surat penutup yang paling terakhir kali turun adalah surat An Nisa yang berbunyi; \"Mereka meminta fatwa kepadamu (tentang kalalah). Katakanlah Allah memberi fatwa kepadamu tentang kalalah. (QS. Annisa'; 176)."},"3739":{"ar":"حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا سُفْيَانُ عَنْ أَبِي صَخْرَةَ عَنْ صَفْوَانَ بْنِ مُحْرِزٍ الْمَازِنِيِّ عَنْ عِمْرَانَ بْنِ حُصَيْنٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَأَتَى نَفَرٌ مِنْ بَنِي تَمِيمٍ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ اقْبَلُوا الْبُشْرَى يَا بَنِي تَمِيمٍ قَالُوا يَا رَسُولَ اللَّهِ قَدْ بَشَّرْتَنَا فَأَعْطِنَا فَرُئِيَ ذَلِكَ فِي وَجْهِهِ فَجَاءَ نَفَرٌ مِنْ الْيَمَنِ فَقَالَ اقْبَلُوا الْبُشْرَى إِذْ لَمْ يَقْبَلْهَا بَنُو تَمِيمٍ قَالُوا قَدْ قَبِلْنَا يَا رَسُولَ اللَّهِ","id":"Telah menceritakan kepada kami [Abu Nu'aim] Telah menceritakan kepada kami [Sufyan] dari [Abu Shakhrah] dari [Shafwan bin Muhriz Al Mazini] dari ['Imran bin Hushain radliallahu 'anhuma] dia berkata; \"Sekelompok orang dari Bani Tamim datang menemui Rasulullah shallallahu 'alaihi wasallam, maka beliau bersabda: 'Terimahlah kabar gembira wahai Bani Tamim.' Mereka menjawab; 'Anda telah memberikan kabar gembira kepada kami, oleh karena itu berikanlah sesuatu kepada kami.' Maka muka Rasulullah shallallahu 'alaihi wasallam berubah, tidak lama kemudian serombongan dari penduduk Yaman datang kepada beliau, maka beliau bersabda: \"Terimalah kabar gembira, karena Bani Tamim tidak mau menerimanya!\" Mereka berkata; \"Ya Rasulallah, kami telah menerimanya.\""},"3740":{"ar":"حَدَّثَنِي زُهَيْرُ بْنُ حَرْبٍ حَدَّثَنَا جَرِيرٌ عَنْ عُمَارَةَ بْنِ الْقَعْقَاعِ عَنْ أَبِي زُرْعَةَ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَلَا أَزَالُ أُحِبُّ بَنِي تَمِيمٍ بَعْدَ ثَلَاثٍ سَمِعْتُهُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُهَا فِيهِمْ هُمْ أَشَدُّ أُمَّتِي عَلَى الدَّجَّالِ وَكَانَتْ فِيهِمْ سَبِيَّةٌ عِنْدَ عَائِشَةَ فَقَالَ أَعْتِقِيهَا فَإِنَّهَا مِنْ وَلَدِ إِسْمَاعِيلَ وَجَاءَتْ صَدَقَاتُهُمْ فَقَالَ هَذِهِ صَدَقَاتُ قَوْمٍ أَوْ قَوْمِي","id":"Telah menceritakan kepadaku [Zuhair bin Harb] Telah menceritakan kepada kami [Jarir] dari ['Umarah bin Al Qa'qa'] dari [Abu Zur'ah] dari [Abu Hurairah radliallahu 'anhu] dia berkata; Saya akan senantiasa mencintai Bani Tamim, karena tiga hal yang pernah saya mendengar dari Rasulullah tentang mereka: Pertama, saya pernah mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: 'Mereka (Bani Tamim) adalah umatku yang paling gigih melawan Dajjal.' Kedua, ada seorang tawanan perempuan dari Bani Tamim di rumah Aisyah. Kemudian Rasulullah bersabda: 'Hai Aisyah, bebaskanlah ia! Karena ia adalah keturunan Ismail.' Ketiga, Rasulullah shallallahu 'alaihi wasallam pernah bersabda ketika ada zakat dari Bani Tamim: 'Ini adalah zakat kaum kami.'"},"3741":{"ar":"حَدَّثَنِي إِبْرَاهِيمُ بْنُ مُوسَى حَدَّثَنَا هِشَامُ بْنُ يُوسُفَ أَنَّ ابْنَ جُرَيْجٍ أَخْبَرَهُمْ عَنْ ابْنِ أَبِي مُلَيْكَةَ أَنَّ عَبْدَ اللَّهِ بْنَ الزُّبَيْرِ أَخْبَرَهُمْأَنَّهُ قَدِمَ رَكْبٌ مِنْ بَنِي تَمِيمٍ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَبُو بَكْرٍ أَمِّرْ الْقَعْقَاعَ بْنَ مَعْبَدِ بْنِ زُرَارَةَ قَالَ عُمَرُ بَلْ أَمِّرْ الْأَقْرَعَ بْنَ حَابِسٍ قَالَ أَبُو بَكْرٍ مَا أَرَدْتَ إِلَّا خِلَافِي قَالَ عُمَرُ مَا أَرَدْتُ خِلَافَكَ فَتَمَارَيَا حَتَّى ارْتَفَعَتْ أَصْوَاتُهُمَا فَنَزَلَ فِي ذَلِكَ{ يَا أَيُّهَا الَّذِينَ آمَنُوا لَا تُقَدِّمُوا }حَتَّى انْقَضَتْ","id":"Telah menceritakan kepadaku [Ibrahim bin Musa] Telah menceritakan kepada kami [Hisyam bin Yusuf] bahwa [Ibnu Juraij] Telah mengabarkan kepada mereka dari [Ibnu Abu Mulaikah] bahwa ['Abdullah bin Az Zubair] telah mengabarkan kepada mereka; Serombongan dari bani Tamim datang kepada Nabi shallallahu 'alaihi wasallam, Abu Bakar berkata, \"Angkatlah Al Qa'qa' bin Ma'bad bin Zurarah.\" Sedangkan Umar radliallahu 'anhu berkata, \"Angkatlah Al Aqra' bin Habis.\" Abu Bakr berkata; 'Apakah kamu ingin menyelisihiku? ' Umar menjawab; 'Ya, aku ingin menyelisihimu.' Maka terjadilah perdebatan antara keduanya hingga suara mereka meninggi. Maka berkenaan dengan hal itu turunlah ayat: 'Hai orang-orang yang beriman, janganlah kamu mendahului Allah dan Rasulnya dan bertakwalah kepada Allah' hingga akhir ayat. (QS. Alhujurat ayat 1)."},"3742":{"ar":"حَدَّثَنِي إِسْحَاقُ أَخْبَرَنَا أَبُو عَامِرٍ الْعَقَدِيُّ حَدَّثَنَا قُرَّةُ عَنْ أَبِي جَمْرَةَ قُلْتُ لِابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَاإِنَّ لِي جَرَّةً يُنْتَبَذُ لِي نَبِيذٌ فَأَشْرَبُهُ حُلْوًا فِي جَرٍّ إِنْ أَكْثَرْتُ مِنْهُ فَجَالَسْتُ الْقَوْمَ فَأَطَلْتُ الْجُلُوسَ خَشِيتُ أَنْ أَفْتَضِحَ فَقَالَ قَدِمَ وَفْدُ عَبْدِ الْقَيْسِ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ مَرْحَبًا بِالْقَوْمِ غَيْرَ خَزَايَا وَلَا النَّدَامَى فَقَالُوا يَا رَسُولَ اللَّهِ إِنَّ بَيْنَنَا وَبَيْنَكَ الْمُشْرِكِينَ مِنْ مُضَرَ وَإِنَّا لَا نَصِلُ إِلَيْكَ إِلَّا فِي أَشْهُرِ الْحُرُمِ حَدِّثْنَا بِجُمَلٍ مِنْ الْأَمْرِ إِنْ عَمِلْنَا بِهِ دَخَلْنَا الْجَنَّةَ وَنَدْعُو بِهِ مَنْ وَرَاءَنَا قَالَ آمُرُكُمْ بِأَرْبَعٍ وَأَنْهَاكُمْ عَنْ أَرْبَعٍ الْإِيمَانِ بِاللَّهِ هَلْ تَدْرُونَ مَا الْإِيمَانُ بِاللَّهِ شَهَادَةُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَإِقَامُ الصَّلَاةِ وَإِيتَاءُ الزَّكَاةِ وَصَوْمُ رَمَضَانَ وَأَنْ تُعْطُوا مِنْ الْمَغَانِمِ الْخُمُسَ وَأَنْهَاكُمْ عَنْ أَرْبَعٍ مَا انْتُبِذَ فِي الدُّبَّاءِ وَالنَّقِيرِ وَالْحَنْتَمِ وَالْمُزَفَّتِ","id":"Telah menceritakan kepadaku [Ishaq] Telah mengabarkan kepada kami [Abu 'Amir Al 'Aqadi] Telah menceritakan kepada kami [Qurrah] dari [Abu Jamrah], Aku pernah berkata kepada Ibnu Abbas, \"Sesungguhnya aku memiliki bejana yang biasa di pakai untuk membuat perasan nabidz, lalu aku meminumnya dalam keadaan manis. Jika aku terlalu banyak minum, maka aku ikut berkumpul (duduk-duduk) bersama orang-orang agar tidak terlihat mabuk. [Ibnu Abbas] lalu berkata, \"Telah datang utusan Abu Qais kepada Rasulullah shallallahu 'alaihi wasallam, beliau lalu menyapa mereka dengan mengucapkan: 'Selamat datang kepada para utusan, yang tidak termasuk orang-orang yang hina dan menyesal.' Mereka berkata, \"Wahai Rasulullah, antara kami dengan engkau ada orang-orang musyrik dari kabilah Mudlar, dan kami tidak bisa berjumpa denganmu kecuali pada bulan-bulan haram. Maka berikanlah kepada kami sebuah perintah, jika kami amalkan maka kami bisa masuk surga, dan bisa kami sampaikan kepada orang-orang setelah kami.\" Beliau bersabda: \"Aku perintahkan kepada kalian empat perkara dan aku larang dari empat perkara. Aku perintahkan kalian agar beriman kepada Allah. Apakah kalian tahu apa itu iman kepada Allah?\" Yaitu: \"Bersaksi bahwa tidak ada Tuhan yang berhak disembah selain Allah, mendirikan shalat, menunaikan zakat, berpuasa di bulan Ramadlan dan mengeluarkan seperlima dari hasil ghanimah. Dan aku larang kalian dari empat perkara; membuat perasan nabidz dalam Ad Duba, An Naqir, Al Hantam dan Al Muzaffat.\""},"3743":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ أَبِي جَمْرَةَ قَالَ سَمِعْتُ ابْنَ عَبَّاسٍ يَقُولُقَدِمَ وَفْدُ عَبْدِ الْقَيْسِ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالُوا يَا رَسُولَ اللَّهِ إِنَّا هَذَا الْحَيَّ مِنْ رَبِيعَةَ وَقَدْ حَالَتْ بَيْنَنَا وَبَيْنَكَ كُفَّارُ مُضَرَ فَلَسْنَا نَخْلُصُ إِلَيْكَ إِلَّا فِي شَهْرٍ حَرَامٍ فَمُرْنَا بِأَشْيَاءَ نَأْخُذُ بِهَا وَنَدْعُو إِلَيْهَا مَنْ وَرَاءَنَا قَالَ آمُرُكُمْ بِأَرْبَعٍ وَأَنْهَاكُمْ عَنْ أَرْبَعٍ الْإِيمَانِ بِاللَّهِ شَهَادَةِ أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَعَقَدَ وَاحِدَةً وَإِقَامِ الصَّلَاةِ وَإِيتَاءِ الزَّكَاةِ وَأَنْ تُؤَدُّوا لِلَّهِ خُمْسَ مَا غَنِمْتُمْ وَأَنْهَاكُمْ عَنْ الدُّبَّاءِ وَالنَّقِيرِ وَالْحَنْتَمِ وَالْمُزَفَّتِ","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] Telah menceritakan kepada kami [Hammad bin Zaid] dari [Abu Jamrah] dia berkata; Aku Mendengar [Ibnu 'Abbas] berkata; Beberapa utusan 'Abdul Qais datang kepada Nabi shallallahu 'alaihi wasallam. Mereka berkata; Ya Rasulullah, sesungguhnya kami dari kampung Rabi'ah. Namun antara kami dan anda terhalangi oleh orang-orang kafir Mudlar, hingga kami tidak bisa bertemu dengan anda kecuali pada bulan-bulan haram. Maka perintahkanlah kepada kami beberapa hal yang dapat kami kerjakan dan bisa kami sampaikan kepada orang-orang di belakang kami.\" Beliau bersabda: \"Aku perintahkan kepada kalian empat perkara dan aku larang dari empat perkara. Aku perintahkan kalian agar beriman kepada Allah, yaitu: \"Bersaksi bahwa tidak ada Tuhan yang berhak disembah selain Allah, mendirikan shalat, menunaikan zakat, dan mengeluarkan seperlima dari hasil ghanimah. Dan aku larang kalian dari empat perkara; membuat perasan nabidz dalam Ad Duba, An Naqir, Al Hantam dan Al Muzaffat.\""},"3744":{"ar":"حَدَّثَنَا يَحْيَى بْنُ سُلَيْمَانَ حَدَّثَنِي ابْنُ وَهْبٍ أَخْبَرَنِي عَمْرٌو وَقَالَ بَكْرُ بْنُ مُضَرَ عَنْ عَمْرِو بْنِ الْحَارِثِ عَنْ بُكَيْرٍ أَنَّ كُرَيْبًا مَوْلَى ابْنِ عَبَّاسٍ حَدَّثَهُأَنَّ ابْنَ عَبَّاسٍ وَعَبْدَ الرَّحْمَنِ بْنَ أَزْهَرَ وَالْمِسْوَرَ بْنَ مَخْرَمَةَ أَرْسَلُوا إِلَى عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا فَقَالُوا اقْرَأْ عَلَيْهَا السَّلَامَ مِنَّا جَمِيعًا وَسَلْهَا عَنْ الرَّكْعَتَيْنِ بَعْدَ الْعَصْرِ وَإِنَّا أُخْبِرْنَا أَنَّكِ تُصَلِّيهَا وَقَدْ بَلَغَنَا أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْهَا قَالَ ابْنُ عَبَّاسٍ وَكُنْتُ أَضْرِبُ مَعَ عُمَرَ النَّاسَ عَنْهُمَا قَالَ كُرَيْبٌ فَدَخَلْتُ عَلَيْهَا وَبَلَّغْتُهَا مَا أَرْسَلُونِي فَقَالَتْ سَلْ أُمَّ سَلَمَةَ فَأَخْبَرْتُهُمْ فَرَدُّونِي إِلَى أُمِّ سَلَمَةَ بِمِثْلِ مَا أَرْسَلُونِي إِلَى عَائِشَةَ فَقَالَتْ أُمُّ سَلَمَةَ سَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَنْهَى عَنْهُمَا وَإِنَّهُ صَلَّى الْعَصْرَ ثُمَّ دَخَلَ عَلَيَّ وَعِنْدِي نِسْوَةٌ مِنْ بَنِي حَرَامٍ مِنْ الْأَنْصَارِ فَصَلَّاهُمَا فَأَرْسَلْتُ إِلَيْهِ الْخَادِمَ فَقُلْتُ قُومِي إِلَى جَنْبِهِ فَقُولِي تَقُولُ أُمُّ سَلَمَةَ يَا رَسُولَ اللَّهِ أَلَمْ أَسْمَعْكَ تَنْهَى عَنْ هَاتَيْنِ الرَّكْعَتَيْنِ فَأَرَاكَ تُصَلِّيهِمَا فَإِنْ أَشَارَ بِيَدِهِ فَاسْتَأْخِرِي فَفَعَلَتْ الْجَارِيَةُ فَأَشَارَ بِيَدِهِ فَاسْتَأْخَرَتْ عَنْهُ فَلَمَّا انْصَرَفَ قَالَ يَا بِنْتَ أَبِي أُمَيَّةَ سَأَلْتِ عَنْ الرَّكْعَتَيْنِ بَعْدَ الْعَصْرِ إِنَّهُ أَتَانِي أُنَاسٌ مِنْ عَبْدِ الْقَيْسِ بِالْإِسْلَامِ مِنْ قَوْمِهِمْ فَشَغَلُونِي عَنْ الرَّكْعَتَيْنِ اللَّتَيْنِ بَعْدَ الظُّهْرِ فَهُمَا هَاتَانِ","id":"Telah menceritakan kepada kami [Yahya bin Sulaiman] Telah menceritakan kepadaku [Ibnu Wahb] Telah mengabarkan kepadaku ['Amru] dan berkata [Bakr bin Mudlar] dari ['Amru bin Al Harits] dari [Bukair] bahwa [Kuraib] -budak- Ibnu 'Abbas telah menceritakan kepadanya bahwasanya Abdullah bin Abbas dan Abdurrahman bin Azhar serta Al Miswar bin Makhramah mengirimnya kepada Aisyah isteri Nabi shallallahu 'alaihi wasallam, mereka berkata; sampaikan salam kami kepadanya dan tanyakan kepadanya mengenai dua raka'at setelah Shalat 'Ashar dan katakan bahwa kami telah mendapatkan berita bahwa engkau melakukan kedua raka'at tersebut, sementara telah sampai kepada kami bahwa Nabi shallallahu 'alaihi wasallam melarang dari keduanya. Ibnu Abbas berkata; dan dahulu aku bersama Umar bin Al Khathab memukul orang-orang karena melakukan keduanya. Kuraib berkata; kemudian aku menemuinya dan menyampaikan kepadanya apa yang dengannya mereka mengutusku. Kemudian ia berkata; tanyakan kepada Ummu Salamah! Kemudian aku keluar menemui mereka dan mengabarkan kepada mereka mengenai perkataan Aisyah. Kemudian mereka mengembalikanku kepada Ummu Salamah seperti sesuatu yang dengannya mereka mengirimku kepada Aisyah. Kemudian [Ummu Salamah] berkata; aku mendengar Rasulullah shallallahu wa'alaihi wa sallam melarang dari keduanya kemudian aku melihat beliau melakukan keduanya, adapun ketika beliau melakukan keduanya maka sesungguhnya beliau telah melakukan Shalat 'Ashar kemudian beliau masuk dan di sisiku terdapat beberapa orang wanita dari Bani Haram dari kalangan anshar, kemudian beliau melakukan shalat dua raka'at tersebut, lalu aku mengirim seorang budak wanita kepada beliau dan aku katakan; berdirilah di samping beliau dan katakan; Ummu Salamah berkata; wahai Rasulullah, bukankah saya telah mendengar anda melarang dari melakukan dua raka'at ini? Dan saya melihat anda melakukan keduanya? Kemudian apabila beliau memberikan isyarat dengan tangannya maka mundurlah darinya. Ummu Salamah berkata; kemudian budak wanita tersebut melakukannya, kemudian beliau memberikan isyarat dengan tangannya, lalu ia mundur dari beliau. Kemudian tatkala telah berpaling beliau mengatakan: \"Wahai anak Abu Umayyah, engkau bertanya mengenai dua raka'at setelah 'Ashar, sesungguhnya beberapa orang dari Bani Abdul Qais telah datang kepadaku dengan membawa keIslaman sebagian dari kaumnya. Kemudian mereka menyibukkanku dari dua raka'at setelah Zhuhur, kedua shalat itu adalah kedua shalat tersebut.\" Abu Muhammad ditanya mengenai hadits ini, kemudian ia berkata; aku berpendapat dengan hadits Umar dari Nabi shallallahu 'alaihi wasallam: \"Tidak ada shalat setelah Shalat 'Ashar hingga matahari tenggelam, dan tidak pula setelah Shalat Subuh hingga matahari terbit.\""},"3745":{"ar":"حَدَّثَنِي عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ الْجُعْفِيُّ حَدَّثَنَا أَبُو عَامِرٍ عَبْدُ الْمَلِكِ حَدَّثَنَا إِبْرَاهِيمُ هُوَ ابْنُ طَهْمَانَ عَنْ أَبِي جَمْرَةَ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَأَوَّلُ جُمُعَةٍ جُمِّعَتْ بَعْدَ جُمُعَةٍ جُمِّعَتْ فِي مَسْجِدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي مَسْجِدِ عَبْدِ الْقَيْسِ بِجُوَاثَى يَعْنِي قَرْيَةً مِنْ الْبَحْرَيْنِ","id":"Telah menceritakan kepadaku ['Abdullah bin Muhammad Al Ju'fi] Telah menceritakan kepada kami [Abu 'Amir 'Abdul Malik] Telah menceritakan kepada kami [Ibrahim] yaitu Ibnu Thahman dari [Abu Jamrah] dari [Ibnu 'Abbas radliallahu 'anhuma] dia berkata; \"Shalat Jum'at pertama kali di laksanakan di masjid Rasulullah shallallahu 'alaihi wasallam, setelah itu di laksanakan di masjid Abdul Qais yaitu di Juatsa sebuah desa di Bahrain."},"3746":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ حَدَّثَنَا اللَّيْثُ قَالَ حَدَّثَنِي سَعِيدُ بْنُ أَبِي سَعِيدٍ أَنَّهُ سَمِعَ أَبَا هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَبَعَثَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَيْلًا قِبَلَ نَجْدٍ فَجَاءَتْ بِرَجُلٍ مِنْ بَنِي حَنِيفَةَ يُقَالُ لَهُ ثُمَامَةُ بْنُ أُثَالٍ فَرَبَطُوهُ بِسَارِيَةٍ مِنْ سَوَارِي الْمَسْجِدِ فَخَرَجَ إِلَيْهِ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ مَا عِنْدَكَ يَا ثُمَامَةُ فَقَالَ عِنْدِي خَيْرٌ يَا مُحَمَّدُ إِنْ تَقْتُلْنِي تَقْتُلْ ذَا دَمٍ وَإِنْ تُنْعِمْ تُنْعِمْ عَلَى شَاكِرٍ وَإِنْ كُنْتَ تُرِيدُ الْمَالَ فَسَلْ مِنْهُ مَا شِئْتَ فَتُرِكَ حَتَّى كَانَ الْغَدُ ثُمَّ قَالَ لَهُ مَا عِنْدَكَ يَا ثُمَامَةُ قَالَ مَا قُلْتُ لَكَ إِنْ تُنْعِمْ تُنْعِمْ عَلَى شَاكِرٍ فَتَرَكَهُ حَتَّى كَانَ بَعْدَ الْغَدِ فَقَالَ مَا عِنْدَكَ يَا ثُمَامَةُ فَقَالَ عِنْدِي مَا قُلْتُ لَكَ فَقَالَ أَطْلِقُوا ثُمَامَةَ فَانْطَلَقَ إِلَى نَجْلٍ قَرِيبٍ مِنْ الْمَسْجِدِ فَاغْتَسَلَ ثُمَّ دَخَلَ الْمَسْجِدَ فَقَالَ أَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَأَشْهَدُ أَنَّ مُحَمَّدًا رَسُولُ اللَّهِ يَا مُحَمَّدُ وَاللَّهِ مَا كَانَ عَلَى الْأَرْضِ وَجْهٌ أَبْغَضَ إِلَيَّ مِنْ وَجْهِكَ فَقَدْ أَصْبَحَ وَجْهُكَ أَحَبَّ الْوُجُوهِ إِلَيَّ وَاللَّهِ مَا كَانَ مِنْ دِينٍ أَبْغَضَ إِلَيَّ مِنْ دِينِكَ فَأَصْبَحَ دِينُكَ أَحَبَّ الدِّينِ إِلَيَّ وَاللَّهِ مَا كَانَ مِنْ بَلَدٍ أَبْغَضُ إِلَيَّ مِنْ بَلَدِكَ فَأَصْبَحَ بَلَدُكَ أَحَبَّ الْبِلَادِ إِلَيَّ وَإِنَّ خَيْلَكَ أَخَذَتْنِي وَأَنَا أُرِيدُ الْعُمْرَةَ فَمَاذَا تَرَى فَبَشَّرَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَمَرَهُ أَنْ يَعْتَمِرَ فَلَمَّا قَدِمَ مَكَّةَ قَالَ لَهُ قَائِلٌ صَبَوْتَ قَالَ لَا وَلَكِنْ أَسْلَمْتُ مَعَ مُحَمَّدٍ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلَا وَاللَّهِ لَا يَأْتِيكُمْ مِنْ الْيَمَامَةِ حَبَّةُ حِنْطَةٍ حَتَّى يَأْذَنَ فِيهَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Abdullah bin Yusuf] Telah menceritakan kepada kami [Al Laits] dia berkata; Telah menceritakan kepadaku [Sa'id bin Abu Sa'id] bahwasanya ia mendengar [Abu Hurairah] berkata; \"Rasulullah shallallahu 'alaihi wasallam mengirim pasukan menuju Nejed, lalu mereka menangkap seseorang dari Bani Hanifah, Tsumamah bin Utsal pemimpin penduduk Yamamah, kemudian mereka mengikatnya pada salah satu tiang masjid, lalu Rasulullah shallallahu 'alaihi wasallam menemuinya dan bersabda kepadanya: \"Apa yang kamu miliki hai Tsumamah?\" ia menjawab, \"Wahai Muhammad, aku memiliki apa yang lebih baik, jika engkau membunuhnya maka engkau telah membunuh yang memiliki darah, dan jika engkau memberi maka engkau memberi orang yang bersyukur, namun jika engkau menginginkan harta maka mintalah niscaya engkau akan diberi apa saja yang engkau inginkan.\" Kemudian Rasulullah shallallahu 'alaihi wasallam meninggalkannya, hingga keesokan harinya beliau bertanya, \"Apa yang engkau miliki wahai Tsumamah?\" ia menjawab, \"Seperti yang aku katakan, jika engkau memberi maka engkau memberi orang yang bersyukur, jika engkau membunuh maka engkau membunuh yang memiliki darah, jika engkau menginginkan harta maka mintalah niscaya engkau akan diberi apa yang engkau mau.\" Lalu Rasulullah shallallahu 'alaihi wasallam meninggalkannya, hingga keesokan harinya beliau bertanya lagi: \"Apa yang engkau miliki wahai Tsumamah?\" ia menjawab, \"Seperti yang aku katakan, jika engkau memberi maka engkau memberi orang yang bersyukur, jika engkau membunuh maka engkau membunuh yang memiliki darah, jika engkau menginginkan harta maka mintalah niscaya engkau akan diberi apa yang engkau mau, \" Rasulullah shallallahu 'alaihi wasallam kemudian bersabda kepada sahabatnya; \"Bawalah Tsumamah\" lalu mereka pun membawanya ke sebatang pohon kurma di samping masjid, ia pun mandi dan masuk masjid kembali, kemudian berkata; \"Aku bersaksi bahwa tiada Tuhan yang patut disembah melainkan hanya Allah dan bahwasanya Muhammad itu utusan Allah, demi Allah, dahulu tidak ada wajah di atas bumi ini yang lebih aku benci selain wajahmu, namun sekarang wajahmu menjadi wajah yang paling aku cintai dari pada yang lain, dan demi Allah, dahulu tidak ada agama yang lebih aku benci selain dari agamamu, namun saat ini agamamu menjadi agama yang paling aku cintai di antara yang lain, demi Allah dahulu tidak ada wilayah yang paling aku benci selain tempatmu, namun sekarang ia menjadi wilayah yang paling aku cintai di antara yang lain, sesungguhnya utusanmu telah menangkapku dan aku hendak melaksanakan umrah, bagaimana pendapatmu?\" Maka Rasulullah shallallahu 'alaihi wasallam memberinya kabar gembira dan memerintahkannya untuk melakukan umrah, ketika ia sampai di Makkah seseorang berkata kepadanya; \"Apakah engkau telah murtad?\" Ia menjawab; \"Tidak, tetapi aku telah masuk Islam bersama Muhammad shallallahu 'alaihi wasallam, dan demi Allah tidaklah kalian akan mendapatkan gandum dari Yamamah kecuali mendapatkan izin dari Rasulullah shallallahu 'alaihi wasallam.\""},"3747":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي حُسَيْنٍ حَدَّثَنَا نَافِعُ بْنُ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَقَدِمَ مُسَيْلِمَةُ الْكَذَّابُ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَجَعَلَ يَقُولُ إِنْ جَعَلَ لِي مُحَمَّدٌ الْأَمْرَ مِنْ بَعْدِهِ تَبِعْتُهُ وَقَدِمَهَا فِي بَشَرٍ كَثِيرٍ مِنْ قَوْمِهِ فَأَقْبَلَ إِلَيْهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَمَعَهُ ثَابِتُ بْنُ قَيْسِ بْنِ شَمَّاسٍ وَفِي يَدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قِطْعَةُ جَرِيدٍ حَتَّى وَقَفَ عَلَى مُسَيْلِمَةَ فِي أَصْحَابِهِ فَقَالَ لَوْ سَأَلْتَنِي هَذِهِ الْقِطْعَةَ مَا أَعْطَيْتُكَهَا وَلَنْ تَعْدُوَ أَمْرَ اللَّهِ فِيكَ وَلَئِنْ أَدْبَرْتَ لَيَعْقِرَنَّكَ اللَّهُ وَإِنِّي لَأَرَاكَ الَّذِي أُرِيتُ فِيهِ مَا رَأَيْتُ وَهَذَا ثَابِتٌ يُجِيبُكَ عَنِّي ثُمَّ انْصَرَفَ عَنْهُقَالَ ابْنُ عَبَّاسٍفَسَأَلْتُ عَنْ قَوْلِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّكَ أُرَى الَّذِي أُرِيتُ فِيهِ مَا أَرَيْتُ فَأَخْبَرَنِي أَبُو هُرَيْرَةَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ بَيْنَا أَنَا نَائِمٌ رَأَيْتُ فِي يَدَيَّ سِوَارَيْنِ مِنْ ذَهَبٍ فَأَهَمَّنِي شَأْنُهُمَا فَأُوحِيَ إِلَيَّ فِي الْمَنَامِ أَنْ انْفُخْهُمَا فَنَفَخْتُهُمَا فَطَارَا فَأَوَّلْتُهُمَا كَذَّابَيْنِ يَخْرُجَانِ بَعْدِي أَحَدُهُمَا الْعَنْسِيُّ وَالْآخَرُ مُسَيْلِمَةُ","id":"Telah menceritakan kepada kami [Abul Yaman] Telah mengabarkan kepada kami [Syu'aib] dari [Abdullah bin Abu Husain] Telah menceritakan kepada kami [Nafi' bin Jubair] dari [Ibnu Abbas radliallahu 'anhuma] dia berkata; Pada masa Nabi shallallahu 'alaihi wasallam, Musailamah Al Kadzab pernah datang ke Madinah. Sesampainya di sana, dia berkata; 'Kalau Muhammad mau mewariskan urusan kenabiannya kepadaku, niscaya aku akan mengikuti ajarannya.' Musailamah datang ke Madinah bersama dengan beberapa orang dari kaumnya. Kemudian Rasulullah shallallahu 'alaihi wasallam dan Tsabit bin Qais bin Syammas menyambut kedatangannya, dan pada saat itu beliau sedang memegang sebilah pelepah kurma. Setelah berhadapan dengan Musailamah dan para pengikutnya, Rasulullah shallallahu 'alaihi wasallam berkata; \"Hai Musailamah, seandainya kamu meminta agar aku memberikan sepotong pelepah kurma ini kepadamu, tentu aku tidak akan pernah memberikannya. Dan jika kamu meminta urusan Allah ini kepadaku, tentu aku lebih tidak akan pernah memberikannya kepadamu. Jika kamu tidak akan mematuhi perintah dan ajaran Allah, niscaya Dia pasti akan membinasakanmu. Hai Musailamah, sungguh aku telah melihat tentang kebinasaanmu, sebagaimana yang aku saksikan dalam mimpiku itu. inilah Tsabit yang akan menggantikanku untuk menjawab tantanganmu. Kemudian Rasulullah shallallahu 'alaihi wasallam meninggalkan Musailamah Al Kadzdzab. Ibnu Abbas berkata; 'Saya pernah bertanya tentang ucapan Nabi shallallahu 'alaihi wasallam tersebut, yaitu tentang mimpi beliau yang berhubungan dengan Musailamah Al Kadzdzab, maka [Abu Hurairah] berkata; Rasulullah shallallahu 'alaihi wasallam telah bersabda: 'Ketika aku sedang tidur, aku bermimpi bahwa di kedua tanganku ada dua buah gelang emas, hingga aku merasa cemas dengan keberadaan dua buah gelang itu. Kemudian aku diberi wahyu dalam tidurku itu agar aku meniup kedua gelang tersebut, lalu aku pun meniupnya hingga kedua gelang itu hilang. Maka dari mimpi itu aku menafsirkan bahwa dua buah gelang tersebut adalah dua orang pembohong (nabi palsu) yang akan muncul sepeninggalku kelak, yang satu adalah Al Ansi, seorang pemimpin dari Shan'a dan yang satunya adalah Musailamah, seorang pemimpin dari Yamamah."},"3748":{"ar":"حَدَّثَنَا إِسْحَاقُ بْنُ نَصْرٍ حَدَّثَنَا عَبْدُ الرَّزَّاقِ عَنْ مَعْمَرٍ عَنْ هَمَّامٍ أَنَّهُ سَمِعَ أَبَا هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَيْنَا أَنَا نَائِمٌ أُتِيتُ بِخَزَائِنِ الْأَرْضِ فَوُضِعَ فِي كَفِّي سِوَارَانِ مِنْ ذَهَبٍ فَكَبُرَا عَلَيَّ فَأَوْحَى اللَّهُ إِلَيَّ أَنْ انْفُخْهُمَا فَنَفَخْتُهُمَا فَذَهَبَا فَأَوَّلْتُهُمَا الْكَذَّابَيْنِ اللَّذَيْنِ أَنَا بَيْنَهُمَا صَاحِبَ صَنْعَاءَ وَصَاحِبَ الْيَمَامَةِ","id":"Telah menceritakan kepada kami [Ishaq bin Nashr] Telah menceritakan kepada kami [Abdurrazaq] dari [Ma'mar] dari [Hammam] bahwa dia mendengar [Abu Hurairah radliallahu 'anhu] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Aku bermimpi diberi kekuasaan dan kekayaan bumi, kemudian diletakkan pada kedua tanganku dua buah gelang emas, namun keduanya seakan-akan terlalu berat bagiku dan membuat aku gelisah, kemudian diwahyukan kepadaku agar aku meniup keduanya, lalu aku pun meniupnya hingga keduanya hilang. Aku menafsirkan mimpi tersebut dengan dua orang pendusta yang aku hidup di antara mereka berdua. Yaitu pemimpin Shan'a dan dan pemimpin Yamamah.\""},"3749":{"ar":"حَدَّثَنَا الصَّلْتُ بْنُ مُحَمَّدٍ قَالَ سَمِعْتُ مَهْدِيَّ بْنَ مَيْمُونٍ قَالَ سَمِعْتُ أَبَا رَجَاءٍ الْعُطَارِدِيَّ يَقُولُكُنَّا نَعْبُدُ الْحَجَرَ فَإِذَا وَجَدْنَا حَجَرًا هُوَ أَخْيَرُ مِنْهُ أَلْقَيْنَاهُ وَأَخَذْنَا الْآخَرَ فَإِذَا لَمْ نَجِدْ حَجَرًا جَمَعْنَا جُثْوَةً مِنْ تُرَابٍ ثُمَّ جِئْنَا بِالشَّاةِ فَحَلَبْنَاهُ عَلَيْهِ ثُمَّ طُفْنَا بِهِ فَإِذَا دَخَلَ شَهْرُ رَجَبٍ قُلْنَا مُنَصِّلُ الْأَسِنَّةِ فَلَا نَدَعُ رُمْحًا فِيهِ حَدِيدَةٌ وَلَا سَهْمًا فِيهِ حَدِيدَةٌ إِلَّا نَزَعْنَاهُ وَأَلْقَيْنَاهُ شَهْرَ رَجَبٍ وَسَمِعْتُ أَبَا رَجَاءٍ يَقُولُ كُنْتُ يَوْمَ بُعِثَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ غُلَامًا أَرْعَى الْإِبِلَ عَلَى أَهْلِي فَلَمَّا سَمِعْنَا بِخُرُوجِهِ فَرَرْنَا إِلَى النَّارِ إِلَى مُسَيْلِمَةَ الْكَذَّابِ","id":"Telah menceritakan kepada kami [Ash Shalt bin Muhammad] dia berkata; Aku mendengar [Mahdi bin Maimun] berkata; aku mendengar [Abu Raja' Al Atharidi] berkata; dulu kami menyembah batu. Apabila kami mendapatkan batu yang lebih baik, maka kami melemparkannya dan mengambil yang lain. Dan apabila kami tidak menemukan batu, kami mengumpulkan segenggam tanah, lalu kami bawakan seekor kambing kemudian kami peraskan susu untuknya. Lalu kami thawaf dengannya. Apabila datang bulan Rajab, kami mengatakan; tidak ada peperangan. Maka kami tidak membiarkan tombak maupun panah yang tajam kecuali kami cabut dan kami lemparkan sebagai pengagungan terhadap bulan Rajab. Dan aku mendengar Abu Raja berkata; pada hari Nabi shallallahu 'alaihi wasallam diutus, aku pada waktu itu sebagai seorang anak penggembala unta milik keluargaku. Tatkala kami mendengar Nabi shallallahu 'alaihi wasallam berdakwah, kami lari ke neraka, yaitu ke Musailamah Al Kadzab."},"3750":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ مُحَمَّدٍ الْجَرْمِيُّ حَدَّثَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا أَبِي عَنْ صَالِحٍ عَنْ ابْنِ عُبَيْدَةَ بْنِ نَشِيطٍ وَكَانَ فِي مَوْضِعٍ آخَرَ اسْمُهُ عَبْدُ اللَّهِ أَنَّ عُبَيْدَ اللَّهِ بْنَ عَبْدِ اللَّهِ بْنِ عُتْبَةَ قَالَبَلَغَنَا أَنَّ مُسَيْلِمَةَ الْكَذَّابَ قَدِمَ الْمَدِينَةَ فَنَزَلَ فِي دَارِ بِنْتِ الْحَارِثِ وَكَانَ تَحْتَهُ بِنْتُ الْحَارِثِ بْنِ كُرَيْزٍ وَهِيَ أُمُّ عَبْدِ اللَّهِ بْنِ عَامِرٍ فَأَتَاهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَمَعَهُ ثَابِتُ بْنُ قَيْسِ بْنِ شَمَّاسٍ وَهُوَ الَّذِي يُقَالُ لَهُ خَطِيبُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَفِي يَدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَضِيبٌ فَوَقَفَ عَلَيْهِ فَكَلَّمَهُ فَقَالَ لَهُ مُسَيْلِمَةُ إِنْ شِئْتَ خَلَّيْتَ بَيْنَنَا وَبَيْنَ الْأَمْرِ ثُمَّ جَعَلْتَهُ لَنَا بَعْدَكَ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَوْ سَأَلْتَنِي هَذَا الْقَضِيبَ مَا أَعْطَيْتُكَهُ وَإِنِّي لَأَرَاكَ الَّذِي أُرِيتُ فِيهِ مَا أُرِيتُ وَهَذَا ثَابِتُ بْنُ قَيْسٍ وَسَيُجِيبُكَ عَنِّي فَانْصَرَفَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَقَالَ عُبَيْدُ اللَّهِ بْنُ عَبْدِ اللَّهِ سَأَلْتُ عَبْدَ اللَّهِ بْنَ عَبَّاسٍ عَنْ رُؤْيَا رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الَّتِي ذَكَرَ فَقَالَ ابْنُ عَبَّاسٍ ذُكِرَ لِي أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ بَيْنَا أَنَا نَائِمٌ أُرِيتُ أَنَّهُ وُضِعَ فِي يَدَيَّ سِوَارَانِ مِنْ ذَهَبٍ فَفُظِعْتُهُمَا وَكَرِهْتُهُمَا فَأُذِنَ لِي فَنَفَخْتُهُمَا فَطَارَا فَأَوَّلْتُهُمَا كَذَّابَيْنِ يَخْرُجَانِ فَقَالَ عُبَيْدُ اللَّهِ أَحَدُهُمَا الْعَنْسِيُّ الَّذِي قَتَلَهُ فَيْرُوزُ بِالْيَمَنِ وَالْآخَرُ مُسَيْلِمَةُ الْكَذَّابُ","id":"Telah menceritakan kepada kami [Sa'id bin Muhammad Al Jarmi] Telah menceritakan kepada kami [Ya'qub bin Ibrahim] Telah menceritakan kepada kami [Bapakku] dari [Shalih] dari [Ibnu 'Ubaidah bin Nasyith] di dalam riwayat lain ia bernama 'Abdullah. ['Ubaidullah bin 'Abdullah bin 'Utbah] berkata; kami mendengar bahwa Musailamah Al Kadzdzab sudah sampai di Madinah, lalu ia singgah di rumah Binti Al Harits bin Kuraiz yaitu Ibnu Abdullah bin 'Amir. Lalu Rasulullah shallallahu 'alaihi wasallam bersama Tsabit bin Qais bin Syammas -juru bicara Rasulullah shallallahu 'alaihi wasallam- menemuinya. Pada waktu itu beliau membawa sebatang tongkat. Lalu beliau berdiri dihadapannya dan berdialog dengannya. Musailamah berkata kepada beliau; Jika anda mau, kita selesaikan urusan kita. Lalu Nabi shallallahu 'alaihi wasallam berkata; 'seandainya kamu meminta tongkat ini, maka aku tidak akan memberikannya kepadamu. Dan sungguh aku melihatmu seperti apa yang telah aku lihat dalam mimpiku. Inilah Tsabit bin Qais akan menjawab tantanganmu.' Lalu beliau shallallahu 'alaihi wasallam pergi. Ubaidullah bin Abdullah berkata; Aku bertanya kepada [Ibnu Abbas] tentang mimpi Rasulullah shallallahu 'alaihi wasallam yang telah beliau sebutkan. Ibnu Abbas menjawab; Rasulullah shallallahu 'alaihi wasallam menyebutkan kepadaku, beliau bersabda: 'Ketika aku sedang tidur, aku bermimpi bahwa di kedua tanganku ada dua buah gelang emas, hingga aku merasa cemas dengan keberadaan dua buah gelang itu. Kemudian aku diberi wahyu dalam tidurku itu agar aku meniup kedua gelang tersebut, lalu akupun meniupnya hingga kedua gelang itu hilang. Maka dari mimpi itu aku menafsirkan bahwa dua buah gelang tersebut adalah dua orang pembohong (nabi palsu) yang akan muncul sepeninggalku kelak. Ubaidullah berkata; yang satu adalah Al Ansi, yang dibunuh oleh Fairuz di Yaman, dan yang satunya adalah Musailamah Al Kadzab."},"3751":{"ar":"حَدَّثَنِي عَبَّاسُ بْنُ الْحُسَيْنِ حَدَّثَنَا يَحْيَى بْنُ آدَمَ عَنْ إِسْرَائِيلَ عَنْ أَبِي إِسْحَاقَ عَنْ صِلَةَ بْنِ زُفَرَ عَنْ حُذَيْفَةَ قَالَجَاءَ الْعَاقِبُ وَالسَّيِّدُ صَاحِبَا نَجْرَانَ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُرِيدَانِ أَنْ يُلَاعِنَاهُ قَالَ فَقَالَ أَحَدُهُمَا لِصَاحِبِهِ لَا تَفْعَلْ فَوَاللَّهِ لَئِنْ كَانَ نَبِيًّا فَلَاعَنَّا لَا نُفْلِحُ نَحْنُ وَلَا عَقِبُنَا مِنْ بَعْدِنَا قَالَا إِنَّا نُعْطِيكَ مَا سَأَلْتَنَا وَابْعَثْ مَعَنَا رَجُلًا أَمِينًا وَلَا تَبْعَثْ مَعَنَا إِلَّا أَمِينًا فَقَالَ لَأَبْعَثَنَّ مَعَكُمْ رَجُلًا أَمِينًا حَقَّ أَمِينٍ فَاسْتَشْرَفَ لَهُ أَصْحَابُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ قُمْ يَا أَبَا عُبَيْدَةَ بْنَ الْجَرَّاحِ فَلَ��َّا قَامَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَذَا أَمِينُ هَذِهِ الْأُمَّةِ","id":"Telah menceritakan kepadaku [Abbas bin Husain] Telah menceritakan kepada kami [Yahya bin Adam] dari [Israil] dari [Abu Ishaq] dari [Shilah bin Zufar] dari [Hudzaifah] dia berkata; Seorang baginda dan budak dari Najran mendatangi Nabi shallallahu 'alaihi wasallam untuk melaknat beliau, Hudzaifah berkata; salah satu dari mereka berkata kepada temannya; 'Jangan kamu lakukan, Demi Allah, Seandainya dia benar seorang nabi maka dia yang akan melaknat kita, hingga kita tidak akan pernah beruntung dan tidak punya keturunan lagi setelah kita. Kemudian keduanya berkata: wahai Rasulullah! Kami akan memberikan apa yang engkau minta kepada kami. Oleh karena itu utuslah orang kepercayaan engkau kepada kami. Dan jangan sekali-kali engkau mengutusnya kecuali memang orang itu sangat terpercaya. Maka nabi shallallahu 'alaihi wasallam bersabda: \"Aku akan mengutus orang kepercayaan yang sebenar-benarnya.\" Maka para sahabat merasa penasaran dan akhirnya menunggu-nunggu orang yang dimaksud oleh Rasulullah itu. Lalu Rasulullah shallallahu 'alaihi wasallam bersabda: 'Berdirilah wahai Abu Ubaidah bin Jarrah! ' setelah Abu Ubaidah bin Jarrah berdiri, Rasulullah shallallahu 'alaihi wasallam bersabda: 'Dialah orang kepercayaan umat ini."},"3752":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ قَالَ سَمِعْتُ أَبَا إِسْحَاقَ عَنْ صِلَةَ بْنِ زُفَرَ عَنْ حُذَيْفَةَ رَضِيَ اللَّهُ عَنْهُ قَالَجَاءَ أَهْلُ نَجْرَانَ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالُوا ابْعَثْ لَنَا رَجُلًا أَمِينًا فَقَالَ لَأَبْعَثَنَّ إِلَيْكُمْ رَجُلًا أَمِينًا حَقَّ أَمِينٍ فَاسْتَشْرَفَ لَهُ النَّاسُ فَبَعَثَ أَبَا عُبَيْدَةَ بْنَ الْجَرَّاحِ","id":"Telah menceritakan kepada kami [Muhammad bin Basyar] Telah menceritakan kepada kami [Muhammad bin Ja'far] Telah menceritakan kepada kami [Syu'bah] dia berkata; AKu mendengar [Abu Ishaq] dari [Shilah bin Zufar] dari [Hudzaifah radliallahu 'anhu] dia berkata; \"Orang-orang Najran pernah datang kepada Rasulullah shallallahu 'alaihi wasallam seraya berkata; 'Ya Rasulullah, utuslah kepada kami seseorang yang jujur dan dipercaya.' Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sungguh aku akan mengutus kepada kalian seseorang yang sangat jujur dan dapat dipercaya. Para sahabat merasa penasaran dan akhirnya menunggu-nunggu orang yang dimaksud oleh Rasulullah itu. Ternyata Rasulullah mengutus Abu Ubaidah bin Jarrah.\""},"3753":{"ar":"حَدَّثَنَا أَبُو الْوَلِيدِ حَدَّثَنَا شُعْبَةُ عَنْ خَالِدٍ عَنْ أَبِي قِلَابَةَ عَنْ أَنَسٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لِكُلِّ أُمَّةٍ أَمِينٌ وَأَمِينُ هَذِهِ الْأُمَّةِ أَبُو عُبَيْدَةَ بْنُ الْجَرَّاحِ","id":"Telah menceritakan kepada kami [Abul Walid] Telah menceritakan kepada kami [Syu'bah] dari [Khalid] dari [Abu Qilabah] dari [Anas] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Sesungguhnya setiap umat memiliki 'Amin' (penjaga/orang terpercaya) dan Amin umat ini adalah Abu Ubaidah bin Jarrah.\""},"3754":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا سُفْيَانُ سَمِعَ ابْنُ الْمُنْكَدِرِ جَابِرَ بْنَ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُمَا يَقُولُقَالَ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَوْ قَدْ جَاءَ مَالُ الْبَحْرَيْنِ لَقَدْ أَعْطَيْتُكَ هَكَذَا وَهَكَذَا ثَلَاثًا فَلَمْ يَقْدَمْ مَالُ الْبَحْرَيْنِ حَتَّى قُبِضَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمَّا قَدِمَ عَلَى أَبِي بَكْرٍ أَمَرَ مُنَادِيًا فَنَادَى مَنْ كَانَ لَهُ عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَيْنٌ أَوْ عِدَةٌ فَلْيَأْتِنِي قَالَ جَابِرٌ فَجِئْتُ أَبَا بَكْرٍ فَأَخْبَرْتُهُ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَوْ جَاءَ مَالُ الْبَحْرَيْنِ أَعْطَيْتُكَ هَكَذَا وَهَكَذَا ثَلَاثًا قَالَ فَأَعْطَانِي قَالَ جَابِرٌ فَلَقِيتُ أَبَا بَكْرٍ بَعْدَ ذَلِكَ فَسَأَلْتُهُ فَلَمْ يُعْطِنِي ثُمَّ أَتَيْتُهُ فَلَمْ يُعْطِنِي ثُمَّ أَتَيْتُهُ الثَّالِثَةَ فَلَمْ يُعْطِنِي فَقُلْتُ لَهُ قَدْ أَتَيْتُكَ فَلَمْ تُعْطِنِي ثُمَّ أَتَيْتُكَ فَلَمْ تُعْطِنِي ثُمَّ أَتَيْتُكَ فَلَمْ تُعْطِنِي فَإِمَّا أَنْ تُعْطِيَنِي وَإِمَّا أَنْ تَبْخَلَ عَنِّي فَقَالَ أَقُلْتَ تَبْخَلُ عَنِّي وَأَيُّ دَاءٍ أَدْوَأُ مِنْ الْبُخْلِ قَالَهَا ثَلَاثًا مَا مَنَعْتُكَ مِنْ مَرَّةٍ إِلَّا وَأَنَا أُرِيدُ أَنْ أُعْطِيَكَوَعَنْ عَمْرٍو عَنْ مُحَمَّدِ بْنِ عَلِيٍّ سَمِعْتُ جَابِرَ بْنَ عَبْدِ اللَّهِ يَقُولُ جِئْتُهُ فَقَالَ لِي أَبُو بَكْرٍ عُدَّهَا فَعَدَدْتُهَا فَوَجَدْتُهَا خَمْسَ مِائَةٍ فَقَالَ خُذْ مِثْلَهَا مَرَّتَيْنِ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] Telah menceritakan kepada kami [Sufyan], [Ibnu Al Munkadir] mendengar [Jabir bin Abdullah radliallahu 'anhuma] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda kepadaku: \"Kalau harta benda dari Bahrain telah sampai kepada kita, maka aku akan memberimu sekian dan sekian (sebanyak tiga kali).' Jabir berkata; dan memang hal itu beliau berikan kepadaku. Jabir berkata; Setelah beliau wafat, aku bertemu dengan Abu Bakr, lalu aku meminta harta itu, namun dia tidak memberikannya, kemudian aku minta lagi, ia pun tetap tidak memberikannya hingga tiga kali aku menemuinya. Maka aku tanyakan kepadanya; 'Aku berkali-kali menemuimu namun kamu tidak memberikannya kepadaku. Apakah kamu akan memberikannya kepadaku ataukah kamu memang merasa kikir untuk memberikannya kepadaku?. Abu Bakr menjawab; 'Apakah kamu mengatakanku sebagai orang yang kikir, padahal penyakit apakah yang lebih parah dari kikir? (Abu Bakr mengatakannya sebanyak tiga kali). Tidaklah aku menahannya kecuali aku pasti akan memberikannya kepadamu! Sedangkan dari jalur lain, dari [Amru] dari [Muhammad bin Ali] aku mendengar [Jabir bin Abdullah] berkata; kemudian aku menemui Abu Bakr, dia berkata kepadaku; 'Hitunglah! Lalu sayapun menghitungnya. Ternyata hanya ada lima ratus. Maka Abu Bakr berkata; 'Ambillah dua kali lipat dari itu (agar sesuai dengan janji Rasulullah)."},"3755":{"ar":"حَدَّثَنِي عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ وَإِسْحَاقُ بْنُ نَصْرٍ قَالَا حَدَّثَنَا يَحْيَى بْنُ آدَمَ حَدَّثَنَا ابْنُ أَبِي زَائِدَةَ عَنْ أَبِيهِ عَنْ أَبِي إِسْحَاقَ عَنْ الْأَسْوَدِ بْنِ يَزِيدَ عَنْ أَبِي مُوسَى رَضِيَ اللَّهُ عَنْهُ قَالَقَدِمْتُ أَنَا وَأَخِي مِنْ الْيَمَنِ فَمَكَثْنَا حِينًا مَا نُرَى ابْنَ مَسْعُودٍ وَأُمَّهُ إِلَّا مِنْ أَهْلِ الْبَيْتِ مِنْ كَثْرَةِ دُخُولِهِمْ وَلُزُومِهِمْ لَهُ","id":"Telah menceritakan kepadaku [Abdullah bin Muhammad] dan [Ishaq bin Nashr] keduanya berkata; Telah menceritakan kepada kami [Yahya bin Adam] Telah menceritakan kepada kami [Ibnu Abu Zaidah] dari [Bapaknya] dari [Abu Ishaq] dari [Al Aswad bin Yazid] dari [Abu Musa] dia berkata; \"Pada suatu hari, saya dan saudara laki-laki saya baru datang dari Yaman. Ketika datang, kami tidak melihat lbnu Mas'ud dan ibunya melainkan dalam keluarga Rasulullah shallallahu 'alaihi wasallam, karena seringnya mereka mondar-mandir dan berada di rumah beliau.\""},"3756":{"ar":"حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا عَبْدُ السَّلَامِ عَنْ أَيُّوبَ عَنْ أَبِي قِلَابَةَ عَنْ زَهْدَمٍ قَالَلَمَّا قَدِمَ أَبُو مُوسَى أَكْرَمَ هَذَا الْحَيَّ مِنْ جَرْمٍ وَإِنَّا لَجُلُوسٌ عِنْدَهُ وَهُوَ يَتَغَدَّى دَجَاجًا وَفِي الْقَوْمِ رَجُلٌ جَالِسٌ فَدَعَاهُ إِلَى الْغَدَاءِ فَقَالَ إِنِّي رَأَيْتُهُ يَأْكُلُ شَيْئًا فَقَذِرْتُهُ فَقَالَ هَلُمَّ فَإِنِّي رَأَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَأْكُلُهُ فَقَالَ إِنِّي حَلَفْتُ لَا آكُلُهُ فَقَالَ هَلُمَّ أُخْبِرْكَ عَنْ يَمِينِكَ إِنَّا أَتَيْنَا النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَفَرٌ مِنْ الْأَشْعَرِيِّينَ فَاسْتَحْمَلْنَاهُ فَأَبَى أَنْ يَحْمِلَنَا فَاسْتَحْمَلْنَاهُ فَحَلَفَ أَنْ لَا يَحْمِلَنَا ثُمَّ لَمْ يَلْبَثْ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ أُتِيَ بِنَهْبِ إِبِلٍ فَأَمَرَ لَنَا بِخَمْسِ ذَوْدٍ فَلَمَّا قَبَضْنَاهَا قُلْنَا تَغَفَّلْنَا النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَمِينَهُ لَا نُفْلِحُ بَعْدَهَا أَبَدًا فَأَتَيْتُهُ فَقُلْتُ يَا رَسُولَ اللَّهِ إِنَّكَ حَلَفْتَ أَنْ لَا تَحْمِلَنَا وَقَدْ حَمَلْتَنَا قَالَ أَجَلْ وَلَكِنْ لَا أَحْلِفُ عَلَى يَمِينٍ فَأَرَى غَيْرَهَا خَيْرًا مِنْهَا إِلَّا أَتَيْتُ الَّذِي هُوَ خَيْرٌ مِنْهَا","id":"Telah menceritakan kepada kami [Abu Nu'aim] Telah menceritakan kepada kami ['Abdus Salam] dari [Ayyub] dari [Abu Qilabah] dari [Zahdam] dia berkata; Tatkala [Abu Musa] datang ke Kufah, dia memuliakan penduduk Jaram. Kami duduk disampingnya ketika ia sedang makan siang dengan daging ayam. Di antara penduduk ada seseorang yang sedang duduk, lalu Abu Musa mengajaknya untuk makan. Tapi orang itu berkata; aku melihatnya makan sesuatu yang tidak aku sukai. Abu Musa berkata; kemarilah, karena aku melihat Nabi shallallahu 'alaihi wasallam memakannya. Namun orang itu berkata; Sesungguhnya aku telah bersumpah untuk tidak memakannya. Abu Musa berkata; kemarilah, akan aku kabarkan kepadamu tentang sumpahmu. Kami pernah menemui Nabi shallallahu 'alaihi wasallam bersama beberapa orang Asy'ariyyin. Lalu kami meminta hewan tunggangan, namun beliau menolak memberikan hewan tunggangan. Kemudian kami meminta lagi, tapi beliau bersumpah untuk tidak memberikan hewan tunggangan kepada kami. Tidak lama kemudian, beliau shallallahu 'alaihi wasallam memberikan kepada kami unta ghanimah. Lalu menyuruh kami untuk mengambil beberapa ekor dari unta itu. Tatkala unta itu telah kami bawa, kami berkata; Rasulullah shallallahu 'alaihi wasallam telah lupa dengan sumpahnya. Sungguh, setelah ini kita tidak akan beruntung! Lalu kami menemui Nabi shallallahu 'alaihi wasallam seraya berkata; Ya Rasulullah, bukankah engkau telah bersumpah tidak akan memberikan kepada kami hewan tunggangan, tapi kenapa engkau memberikannya kepada kami? Beliau menjawab: \"Ya, sebab jika aku bersumpah atas sesuatu dan ternyata di sana ada yang lebih baik dari itu tentu aku akan melakukan yang terbaik.\""},"3757":{"ar":"حَدَّثَنِي عَمْرُو بْنُ عَلِيٍّ حَدَّثَنَا أَبُو عَاصِمٍ حَدَّثَنَا سُفْيَانُ حَدَّثَنَا أَبُو صَخْرَةَ جَامِعُ بْنُ شَدَّادٍ حَدَّثَنَا صَفْوَانُ بْنُ مُحْرِزٍ الْمَازِنِيُّ حَدَّثَنَا عِمْرَانُ بْنُ حُصَيْنٍ قَالَجَاءَتْ بَنُو تَمِيمٍ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَبْشِرُوا يَا بَنِي تَمِيمٍ قَالُوا أَمَّا إِذْ بَشَّرْتَنَا فَأَعْطِنَا فَتَغَيَّرَ وَجْهُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَجَاءَ نَاسٌ مِنْ أَهْلِ الْيَمَنِ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اقْبَلُوا الْبُشْرَى إِذْ لَمْ يَقْبَلْهَا بَنُو تَمِيمٍ قَالُوا قَدْ قَبِلْنَا يَا رَسُولَ اللَّهِ","id":"Telah menceritakan kepadaku [Amru bin Ali] Telah menceritakan kepada kami [Abu Ashim] Telah menceritakan kepada kami [Sufyan] Telah menceritakan kepada kami [Abu Shakhrah Jami' bin Syudad] Telah menceritakan kepada kami [Shafwan bin Muhriz Al Mazini] Telah menceritakan kepada kami ['Imran bin Hushain] dia berkata; \"Sekelompok orang dari Bani Tamim datang menemui Rasulullah shallallahu 'alaihi wasallam, maka beliau bersabda: 'Terimalah kabar gembira wahai Bani Tamim.' Mereka menjawab; 'Anda telah memberikan kabar gembira kepada kami, oleh karena itu berikanlah sesuatu kepada kami.' Maka muka Rasulullah shallallahu 'alaihi wasallam berubah, tidak lama kemudian serombongan dari penduduk Yaman datang kepada beliau, maka beliau bersabda: \"Terimalah kabar gembira, karena Bani Tamim tidak mau menerimanya!\" Mereka berkata; \"Ya Rasulullah, kami telah menerimanya.\""},"3758":{"ar":"حَدَّثَنِي عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ الْجُعْفِيُّ حَدَّثَنَا وَهْبُ بْنُ جَرِيرٍ حَدَّثَنَا شُعْبَةُ عَنْ إِسْمَاعِيلَ بْنِ أَبِي خَالِدٍ عَنْ قَيْسِ بْنِ أَبِي حَازِمٍ عَنْ أَبِي مَسْعُودٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْإِيمَانُ هَا هُنَا وَأَشَارَ بِيَدِهِ إِلَى الْيَمَنِ وَالْجَفَاءُ وَغِلَظُ الْقُلُوبِ فِي الْفَدَّادِينَ عِنْدَ أُصُولِ أَذْنَابِ الْإِبِلِ مِنْ حَيْثُ يَطْلُعُ قَرْنَا الشَّيْطَانِ رَبِيعَةَ وَمُضَرَ","id":"Telah menceritakan kepada kami [Abdullah bin Muhammad Al Ju'fi] Telah menceritakan kepada kami [Wahab bin Jarir] Telah menceritakan kepada kami [Syu'bah] dari [Ismail bin Abu Khalid] dari [Qais bin Abu Hazim] dari [Abu Mas'ud] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Iman itu berada di sini, (beliau sambil menunjuk ke arah Yaman dengan tangan beliau) 'Dan sesungguhnya keras dan kasarnya hati ada pada para pemilik unta didekat ekor unta, di tempat dua tanduk setan muncul, yaitu di Rabi'ah dan Mudlar.\""},"3759":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا ابْنُ أَبِي عَدِيٍّ عَنْ شُعْبَةَ عَنْ سُلَيْمَانَ عَنْ ذَكْوَانَ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَتَاكُمْ أَهْلُ الْيَمَنِ هُمْ أَرَقُّ أَفْئِدَةً وَأَلْيَنُ قُلُوبًا الْإِيمَانُ يَمَانٍ وَالْحِكْمَةُ يَمَانِيَةٌ وَالْفَخْرُ وَالْخُيَلَاءُ فِي أَصْحَابِ الْإِبِلِ وَالسَّكِينَةُ وَالْوَقَارُ فِي أَهْلِ الْغَنَمِوَقَالَ غُنْدَرٌ عَنْ شُعْبَةَ عَنْ سُلَيْمَانَ سَمِعْتُ ذَكْوَانَ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Muhammad bin Basyar] Telah menceritakan kepada kami [Ibnu Abu Adi] dari [Syu'bah] dari [Sulaiman] dari [Dakwan] dari [Abu Hurairah radliallahu 'anhu] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Telah datang penduduk Yaman, mereka adalah orang-orang yang perasaan (sensitive) dan hatinya paling lembut, keimanan dari Yaman, hikmah ada pada orang Yaman, angkuh dan sombong ada pada para penggembala unta, sedangkan ketenangan dan kewibawaan ada pada para penggembala kambing.\" [Gundar] berkata; dari [Syu'bah] dari [Sulaiman] Aku mendengar [Dakwan] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam."},"3760":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ قَالَ حَدَّثَنِي أَخِي عَنْ سُلَيْمَانَ عَنْ ثَوْرِ بْنِ زَيْدٍ عَنْ أَبِي الْغَيْثِ عَنْ أَبِي هُرَيْرَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْإِيمَانُ يَمَانٍ وَالْفِتْنَةُ هَا هُنَا هَا هُنَا يَطْلُعُ قَرْنُ الشَّيْطَانِ","id":"Telah menceritakan kepada kami [Ismail] dia berkata; Telah menceritakan kepadaku [Saudaraku] dari [Sulaiman] dari [Tsaur bin Zaid] dari [Abul Ghaits] dari [Abu Hurairah] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Keimanan ada di Yaman, sedangkan fitnah di sini dan di sini, tempat munculnya tanduk syetan.\""},"3761":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ حَدَّثَنَا أَبُو الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَتَاكُمْ أَهْلُ الْيَمَنِ أَضْعَفُ قُلُوبًا وَأَرَقُّ أَفْئِدَةً الْفِقْهُ يَمَانٍ وَالْحِكْمَةُ يَمَانِيَةٌ","id":"Telah menceritakan kepada kami [Abul Yaman] Telah mengabarkan kepada kami [Syu'aib] Telah menceritakan kepada kami [Abu Zinad] dari [Al A'raj] dari [Abu Hurairah radliallahu 'anhu] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Telah datang penduduk Yaman, mereka adalah orang-orang yang perasaan (sensitive) dan hatinya paling lembut, kefaqihan dari Yaman, hikmah ada pada orang Yaman.\""},"3762":{"ar":"حَدَّثَنَا عَبْدَانُ عَنْ أَبِي حَمْزَةَ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ قَالَكُنَّا جُلُوسًا مَعَ ابْنِ مَسْعُودٍ فَجَاءَ خَبَّابٌ فَقَالَ يَا أَبَا عَبْدِ الرَّحْمَنِ أَيَسْتَطِيعُ هَؤُلَاءِ الشَّبَابُ أَنْ يَقْرَءُوا كَمَا تَقْرَأُ قَالَ أَمَا إِنَّكَ لَوْ شِئْتَ أَمَرْتُ بَعْضَهُمْ يَقْرَأُ عَلَيْكَ قَالَ أَجَلْ قَالَ اقْرَأْ يَا عَلْقَمَةُ فَقَالَ زَيْدُ بْنُ حُدَيْرٍ أَخُو زِيَادِ بْنِ حُدَيْرٍ أَتَأْمُرُ عَلْقَمَةَ أَنْ يَقْرَأَ وَلَيْسَ بِأَقْرَئِنَا قَالَ أَمَا إِنَّكَ إِنْ شِئْتَ أَخْبَرْتُكَ بِمَا قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي قَوْمِكَ وَقَوْمِهِ فَقَرَأْتُ خَمْسِينَ آيَةً مِنْ سُورَةِ مَرْيَمَ فَقَالَ عَبْدُ اللَّهِ كَيْفَ تَرَى قَالَ قَدْ أَحْسَنَ قَالَ عَبْدُ اللَّهِ مَا أَقْرَأُ شَيْئًا إِلَّا وَهُوَ يَقْرَؤُهُ ثُمَّ الْتَفَتَ إِلَى خَبَّابٍ وَعَلَيْهِ خَاتَمٌ مِنْ ذَهَبٍ فَقَالَ أَلَمْ يَأْنِ لِهَذَا الْخَاتَمِ أَنْ يُلْقَى قَالَ أَمَا إِنَّكَ لَنْ تَرَاهُ عَلَيَّ بَعْدَ الْيَوْمِ فَأَلْقَاهُرَوَاهُ غُنْدَرٌ عَنْ شُعْبَةَ","id":"Telah menceritakan kepada kami ['Abdan] dari [Abu Hamzah] dari [Al A'masy] dari [Ibrahim] dari ['Alqamah] dia berkata; Kami pernah duduk-duduk bersama [Ibnu Mas'ud]. Tiba-tiba Khabab datang seraya berkata; 'Wahai Abu Abdurrahman, Apakah para pemuda itu bisa membaca sebagaimana anda membaca? Dia menjawab; Kalau kamu ingin, aku suruh sebagian dari mereka untuk membacakan kepadamu? Khabab menjawab; 'Ya.' Ibnu Mas'ud berkata; 'Wahai Alqamah, bacalah! ' maka Zaid bin Hudair -saudara Ziyad bin Hudair- berkata; 'Apakah engkau menyuruh Alqamah untuk membaca padahal dia bukanlah yang terbaik dari kami? Ibnu Mas'ud berkata; Jika kamu mau, akan saya beritahukan kepadamu sabda Nabi shallallahu 'alaihi wasallam mengenai kaummu dan kaumnya. Maka aku membacakan lima puluh ayat dari surat Maryam. Lalu Abdullah berkata; Apa pendapatmu? Zaid berkata; Sungguh bagus. Abdullah berkata; Aku tidak membaca sesuatu kecuali ia pun telah membacanya. Kemudian ia menoleh kepada Khabab ditangannya ada cincin dari emas. Lalu Abdullah berkata; kenapa cincin ini tidak dibuang saja? Khabab berkata; sesungguhnya kamu tidak akan melihatnya lagi ada padaku setelah hari ini. Lalu ia membuangnya. Diriwayatkan oleh [Ghundar] dari [Syu'bah]."},"3763":{"ar":"حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا سُفْيَانُ عَنْ ابْنِ ذَكْوَانَ عَنْ عَبْدِ الرَّحْمَنِ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَجَاءَ الطُّفَيْلُ بْنُ عَمْرٍو إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنَّ دَوْسًا قَدْ هَلَكَتْ عَصَتْ وَأَبَتْ فَادْعُ اللَّهَ عَلَيْهِمْ فَقَالَ اللَّهُمَّ اهْدِ دَوْسًا وَأْتِ بِهِمْ","id":"Telah menceritakan kepada kami [Abu Nu'aim] Telah menceritakan kepada kami [Sufyan] dari [Ibnu Dzakwan] dari [Abdurrahman Al A'raj] dari [Abu Hurairah radliallahu 'anhu] dia berkata; Thufail bin Amru datang kepada Nabi shallallahu 'alaihi wasallam seraya berkata; Ya Rasulullah, sesungguhnya kabilah Daus telah kafir dan membangkang. Oleh karena itu, berdoalah kepada Allah agar mereka mendapatkan kecelakaan.' Tetapi Rasulullah shallallahu 'alaihi wasallam berdoa: \"Ya Allah, berikanlah petunjuk kepada kabilah Daus dan datangkanlah mereka!\""},"3764":{"ar":"حَدَّثَنِي مُحَمَّدُ بْنُ الْعَلَاءِ حَدَّثَنَا أَبُو أُسَامَةَ حَدَّثَنَا إِسْمَاعِيلُ عَنْ قَيْسٍ عَنْ أَبِي هُرَيْرَةَ قَالَلَمَّا قَدِمْتُ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قُلْتُ فِي الطَّرِيقِ يَا لَيْلَةً مِنْ طُولِهَا وَعَنَائِهَاعَلَى أَنَّهَا مِنْ دَارَةِ الْكُفْرِ نَجَّتِوَأَبَقَ غُلَامٌ لِي فِي الطَّرِيقِ فَلَمَّا قَدِمْتُ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَبَايَعْتُهُ فَبَيْنَا أَنَا عِنْدَهُ إِذْ طَلَعَ الْغُلَامُ فَقَالَ لِي النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا أَبَا هُرَيْرَةَ هَذَا غُلَامُكَ فَقُلْتُ هُوَ لِوَجْهِ اللَّهِ فَأَعْتَقْتُهُ","id":"Telah menceritakan kepadaku [Muhammad bin Al Alaa] Telah menceritakan kepada kami [Abu Usamah] Telah menceritakan kepada kami [Ismail] dari [Qais] dari [Abu Hurairah] dia berkata; ketika aku datang kepada Nabi shallallahu 'alaihi wasallam, di jalan aku melantunkan sebuah syair, \"Duhai malam yang panjang dan melelahkan meski ia bergegas cepat dari bumi kekafiran.\" Abu Hurairah berkata; lalu budak laki-lakiku pergi menghilang di jalan, ia berkata; maka tatkala aku datang kepada Rasulullah shallallahu 'alaihi wasallam aku berbai'at kepada beliau, dan pada saat aku berada di sisi beliau, budak laki-lakiku muncul. Maka Rasulullah shallallahu 'alaihi wasallam bersabda kepadaku: \"Wahai Abu Hurairah apakah ini budakmu?\" Aku berkata; \"Dia untuk Allah Azza Wa Jalla\", Akhirnya aku pun memerdekakannya.\""},"3765":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ حَدَّثَنَا أَبُو عَوَانَةَ حَدَّثَنَا عَبْدُ الْمَلِكِ عَنْ عَمْرِو بْنِ حُرَيْثٍ عَنْ عَدِيِّ بْنِ حَاتِمٍ قَالَأَتَيْنَا عُمَرَ فِي وَفْدٍ فَجَعَلَ يَدْعُو رَجُلًا رَجُلًا وَيُسَمِّيهِمْ فَقُلْتُ أَمَا تَعْرِفُنِي يَا أَمِيرَ الْمُؤْمِنِينَ قَالَ بَلَى أَسْلَمْتَ إِذْ كَفَرُوا وَأَقْبَلْتَ إِذْ أَدْبَرُوا وَوَفَيْتَ إِذْ غَدَرُوا وَعَرَفْتَ إِذْ أَنْكَرُوا فَقَالَ عَدِيٌّ فَلَا أُبَالِي إِذًا","id":"Telah menceritakan kepada kami [Musa bin Ismail] Telah menceritakan kepada kami [Abu 'Awanah] Telah menceritakan kepada kami [Abdul Malik] dari [Amru bin Huraits] dari [Adi bin Hatim] dia berkata; Kami menemui Umar bersama beberapa utusan. Lalu dia memanggil satu persatu dengan menyebutkan namanya. Aku berkata kepadanya; 'Apakah kamu mengenaliku wahai Amirul mukminin? Dia menjawab; \"Tentu, kamu adalah orang yang masuk Islam pada saat orang-orang menjadi kafir, kamu adalah orang yang maju ke garis depan pada saat orang-orang mundur kebelakang, kamu adalah orang yang menepati janji ketika semua orang berkhianat, dan kamu adalah orang yang mengakui kebenaran saat orang-orang mengingkarinya.\" Kemudian Adi berkata; 'Kalau begitu, aku tidak peduli siapa saja yang kamu panggil lebih dahulu.'"},"3766":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا مَالِكٌ عَنْ ابْنِ شِهَابٍ عَنْ عُرْوَةَ بْنِ الزُّبَيْرِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْخَرَجْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي حَجَّةِ الْوَدَاعِ فَأَهْلَلْنَا بِعُمْرَةٍ ثُمَّ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ كَانَ مَعَهُ هَدْيٌ فَلْيُهْلِلْ بِالْحَجِّ مَعَ الْعُمْرَةِ ثُمَّ لَا يَحِلَّ حَتَّى يَحِلَّ مِنْهُمَا جَمِيعًا فَقَدِمْتُ مَعَهُ مَكَّةَ وَأَنَا حَائِضٌ وَلَمْ أَطُفْ بِالْبَيْتِ وَلَا بَيْنَ الصَّفَا وَالْمَرْوَةِ فَشَكَوْتُ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ انْقُضِي رَأْسَكِ وَامْتَشِطِي وَأَهِلِّي بِالْحَجِّ وَدَعِي الْعُمْرَةَ فَفَعَلْتُ فَلَمَّا قَضَيْنَا الْحَجَّ أَرْسَلَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَعَ عَبْدِ الرَّحْمَنِ بْنِ أَبِي بَكْرٍ الصِّدِّيقِ إِلَى التَّنْعِيمِ فَاعْتَمَرْتُ فَقَالَ هَذِهِ مَكَانَ عُمْرَتِكِ قَالَتْ فَطَافَ الَّذِينَ أَهَلُّوا بِالْعُمْرَةِ بِالْبَيْتِ وَبَيْنَ الصَّفَا وَالْمَرْوَةِ ثُمَّ حَلُّوا ثُمَّ طَافُوا طَوَافًا آخَرَ بَعْدَ أَنْ رَجَعُوا مِنْ مِنًى وَأَمَّا الَّذِينَ جَمَعُوا الْحَجَّ وَالْعُمْرَةَ فَإِنَّمَا طَافُوا طَوَافًا وَاحِدًا","id":"Telah menceritakan kepada kami [Ismail bin Abdullah] Telah menceritakan kepada kami [Malik] dari [Ibnu Syihab] dari [Urwah bin Jubair] dari [Aisyah radliallahu 'anha] dia berkata; \"Kami keluar bersama Rasulullah shallaallahu'alaihi wa sallam pada haji wada`, kami bertalbiyah dengan umrah, kemudian Rasulullah shallaallahu'alaihi wa sallam bersabda: \"Barang siapa yang memiliki hewan kurban, hendaknya dia berihram untuk haji dan umroh, dan tidak bertahallul hingga dia telah bertahallul dari keduanya.\" Lalu saya masuk Makkah dalam keadaan haid, saya tidak thowaf di ka`bah dan tidak juga melakukan sai' antara shofa dan marwah. Lalu saya melaporkan hal tersebut kepada Rasulullah shallaallahu'alaihi wa sallam, beliau bersabda: \"lepaskan ikatan rambut kepalamu, bersisirlah, dan niatkanllah untuk berhaji, serta tinggalkan umrah.\" Aisyah berkata; \"Saya melakukannya hingga ketika kami selesai berhaji. Lalu Rasulullah shallaallahu'alaihi wa sallam mengirimku bersama Abdurrahman bin Abu Bakr menuju Tan'im, dan saya berniat umrah.\" Dia berkata; \"Ini adalah tempat berihram untuk umrahmu.\" Aisyah berkata; \"Maka orang-orang yang berihram untuk umrah berthawaf di ka'bah, dan melakukan sai' antara shofa dan marwah. Setelah itu, mereka bertahallul, kemudian thawaf dengan thawaf yang lain setelah mereka kembali dari Mina dalam haji. Adapun orang-orang yang menggabungkan antara haji dan umrah, mereka hanya melakukan thawaf sekali saja.\""},"3767":{"ar":"حَدَّثَنِي عَمْرُو بْنُ عَلِيٍّ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ حَدَّثَنَا ابْنُ جُرَيْجٍ قَالَ حَدَّثَنِي عَطَاءٌ عَنْ ابْنِ عَبَّاسٍإِذَا طَافَ بِالْبَيْتِ فَقَدْ حَلَّ فَقُلْتُ مِنْ أَيْنَ قَالَ هَذَا ابْنُ عَبَّاسٍ قَالَ مِنْ قَوْلِ اللَّهِ تَعَالَى{ ثُمَّ مَحِلُّهَا إِلَى الْبَيْتِ الْعَتِيقِ }وَمِنْ أَمْرِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَصْحَابَهُ أَنْ يَحِلُّوا فِي حَجَّةِ الْوَدَاعِ قُلْتُ إِنَّمَا كَانَ ذَلِكَ بَعْدَ الْمُعَرَّفِ قَالَ كَانَ ابْنُ عَبَّاسٍ يَرَاهُ قَبْلُ وَبَعْدُ","id":"Telah menceritakan kepadaku [Amru bin Ali] Telah menceritakan kepada kami [Yahya bin Sa'id] Telah menceritakan kepada kami [Ibnu Juraij] dia berkata; Telah menceritakan kepadaku ['Atha] dari [Ibnu Abbas]; 'Apabila sudah thawaf di Ka'bah maka dia telah bertahallul. Aku bertanya; 'Dari mana perkataan Ibnu Abbas ini? Atha menjawab; Dari firman Allah yang berbunyi: Kemudian tempat penyembelihannya adalah di sekitar Bai'tul 'Atiq. Dan dari perintah Nabi shallallahu 'alaihi wasallam kepada para sahabatnya agar bertahallul di waktu haji Wada.' Aku berkata; Hal itu di lakukan setelah wukuf di Arafah. Atha berkata; 'Ibnu Abbas melihat beliau melakukannya sebelum wukuf maupun setelah wukuf.'"},"3768":{"ar":"حَدَّثَنِي بَيَانٌ حَدَّثَنَا النَّضْرُ أَخْبَرَنَا شُعْبَةُ عَنْ قَيْسٍ قَالَ سَمِعْتُ طَارِقًا عَنْ أَبِي مُوسَى الْأَشْعَرِيِّ رَضِيَ اللَّهُ عَنْهُ قَالَقَدِمْتُ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالْبَطْحَاءِ فَقَالَ أَحَجَجْتَ قُلْتُ نَعَمْ قَالَ كَيْفَ أَهْلَلْتَ قُلْتُ لَبَّيْكَ بِإِهْلَالٍ كَإِهْلَالِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ طُفْ بِالْبَيْتِ وَبِالصَّفَا وَالْمَرْوَةِ ثُمَّ حِلَّ فَطُفْتُ بِالْبَيْتِ وَبِالصَّفَا وَالْمَرْوَةِ وَأَتَيْتُ امْرَأَةً مِنْ قَيْسٍ فَفَلَتْ رَأْسِي","id":"Telah menceritakan kepadaku [Bayan] Telah menceritakan kepada kami [An Nadlr] Telah mengabarkan kepada kami [Syu'bah] dari [Qais] dia berkata; Aku mendengar [Thariq] dari [Abu Musa radliallahu 'anhu] dia berkata; Aku menemui Nabi shallallahu 'alaihi wasallam di Bathha. Beliau berkata; \"Apakah kamu sudah melakukan haji? Aku menjawab; 'Ya.' Beliau bertanya; 'Bagaimana cara kamu bertalbiyah? ' Saya menjawab; saya bertalbiyah seperti talbiyah Rasulullah shallallahu 'alaihi wasallam. Beliau berkata; \"Thawafdi Ka'bah dan di Shofa dan Marwa kemudian lakukanlah tahallul.\" Maka aku berthawaf di Ka'bah dan di shofa dan Marwa kemudian aku mendatangi seorang perempuan dari bani Qais maka dia melepaskan kepala saya."},"3769":{"ar":"حَدَّثَنِي إِبْرَاهِيمُ بْنُ الْمُنْذِرِ أَخْبَرَنَا أَنَسُ بْنُ عِيَاضٍ حَدَّثَنَا مُوسَى بْنُ عُقْبَةَ عَنْ نَافِعٍ أَنَّ ابْنَ عُمَرَ أَخْبَرَهُ أَنَّ حَفْصَةَ رَضِيَ اللَّهُ عَنْهَا زَوْجَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَخْبَرَتْهُأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَرَ أَزْوَاجَهُ أَنْ يَحْلِلْنَ عَامَ حَجَّةِ الْوَدَاعِ فَقَالَتْ حَفْصَةُ فَمَا يَمْنَعُكَ فَقَالَ لَبَّدْتُ رَأْسِي وَقَلَّدْتُ هَدْيِي فَلَسْتُ أَحِلُّ حَتَّى أَنْحَرَ هَدْيِي","id":"Telah menceritakan kepadaku [Ibrahim bin Al Mundzir] Telah mengabarkan kepada kami [Anas bin 'Iyadl] Telah menceritakan kepada kami [Musa bin Uqbah] dari [Nafi'] bahwa [Ibnu Umar] telah mengabarkan kepadanya; dari [Hafsah radliallahu 'anha] -istri Nabi shallallahu 'alaihi wasallam- bahwa Nabi shallallahu 'alaihi wasallam menyuruh istri-istri beliau untuk bertahallul pada tahun haji Wada'. Hafshah berkata; 'Tapi kenapa anda belum bertahallul? ' Beliau menjawab: \"Saya telah mengikat kepalaku dan mengalungi hewan kurbanku, dan tidak akan bertahallul hingga menyembelih kurban.\""},"3770":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ قَالَ حَدَّثَنِي شُعَيْبٌ عَنْ الزُّهْرِيِّ وَقَالَ مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا الْأَوْزَاعِيُّ قَالَ أَخْبَرَنِي ابْنُ شِهَابٍ عَنْ سُلَيْمَانَ بْنِ يَسَارٍ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ امْرَأَةً مِنْ خَثْعَمَ اسْتَفْتَتْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي حَجَّةِ الْوَدَاعِ وَالْفَضْلُ بْنُ عَبَّاسٍ رَدِيفُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ يَا رَسُولَ اللَّهِ إِنَّ فَرِيضَةَ اللَّهِ عَلَى عِبَادِهِ أَدْرَكَتْ أَبِي شَيْخًا كَبِيرًا لَا يَسْتَطِيعُ أَنْ يَسْتَوِيَ عَلَى الرَّاحِلَةِ فَهَلْ يَقْضِي أَنْ أَحُجَّ عَنْهُ قَالَ نَعَمْ","id":"Telah menceritakan kepada kami [Abul Yaman] dia berkata; Telah menceritakan kepadaku [Syu'aib] dari [Az Zuhri] dan [Muhammad bin Yusuf] berkata; Telah menceritakan kepada kami [Al Auza'i] dia berkata; Telah mengabarkan kepadaku [Ibnu Syihab] dari [Sulaiman bin Yasar] dari [Ibnu Abbas] bahwa ada seorang wanita dari Suku Khats'am bertanya kepada Nabi shallallahu 'alaihi wasallam pada waktu haji Wada', -pada waktu itu Al Fadl bin Abbas bersama Rasulullah.- wanita itu berkata; \"Wahai Rasulullah, kewajiban berhaji yang Allah bebankan kepada para hamba-Nya telah menjumpai ayahku dalam keadaan tua renta, dia tidak mampu untuk mengendarai kendaraan, maka apakah saya boleh untuk melakukan haji untuknya?\" Beliau menjawab: 'Ya, silahkan.'"},"3771":{"ar":"حَدَّثَنِي مُحَمَّدٌ حَدَّثَنَا سُرَيْجُ بْنُ النُّعْمَانِ حَدَّثَنَا فُلَيْحٌ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا قَالَأَقْبَلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَامَ الْفَتْحِ وَهُوَ مُرْدِفٌ أُسَامَةَ عَلَى الْقَصْوَاءِ وَمَعَهُ بِلَالٌ وَعُثْمَانُ بْنُ طَلْحَةَ حَتَّى أَنَاخَ عِنْدَ الْبَيْتِ ثُمَّ قَالَ لِعُثْمَانَ ائْتِنَا بِالْمِفْتَاحِ فَجَاءَهُ بِالْمِفْتَاحِ فَفَتَحَ لَهُ الْبَابَ فَدَخَلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأُسَامَةُ وَبِلَالٌ وَعُثْمَانُ ثُمَّ أَغْلَقُوا عَلَيْهِمْ الْبَابَ فَمَكَثَ نَهَارًا طَوِيلًا ثُمَّ خَرَجَ وَابْتَدَرَ النَّاسُ الدُّخُولَ فَسَبَقْتُهُمْ فَوَجَدْتُ بِلَالًا قَائِمًا مِنْ وَرَاءِ الْبَابِ فَقُلْتُ لَهُ أَيْنَ صَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ صَلَّى بَيْنَ ذَيْنِكَ الْعَمُودَيْنِ الْمُقَدَّمَيْنِ وَكَانَ الْبَيْتُ عَلَى سِتَّةِ أَعْمِدَةٍ سَطْرَيْنِ صَلَّى بَيْنَ الْعَمُودَيْنِ مِنْ السَّطْرِ الْمُقَدَّمِ وَجَعَلَ بَابَ الْبَيْتِ خَلْفَ ظَهْرِهِ وَاسْتَقْبَلَ بِوَجْهِهِ الَّذِي يَسْتَقْبِلُكَ حِينَ تَلِجُ الْبَيْتَ بَيْنَهُ وَبَيْنَ الْجِدَارِ قَالَ وَنَسِيتُ أَنْ أَسْأَلَهُ كَمْ صَلَّى وَعِنْدَ الْمَكَانِ الَّذِي صَلَّى فِيهِ مَرْمَرَةٌ حَمْرَاءُ","id":"Telah menceritakan kepadaku [Muhammad] Telah menceritakan kepada kami [Suraij bin An Nu'man] Telah menceritakan kepada kami [Fulaih] dari [Nafi'] dari [Ibnu 'Umar] radliallahu 'anhu ia berkata: Pada sa'at fathu Makkah Rasulullah shallallahu 'alaihi wasallam memasuki Baitullah dengan mengendarai onta Qushwa bersama Usamah bin Zaid. Turut pula bersama beliau Bilal dan Utsman bin Thalhah hingga onta tersebut berhenti di halaman Ka'bah. Kemudian beliau shallallahu 'alaihi wasallam meminta kunci Ka'bah kepada Utsman bin Thalhah, lalu dia pun memberikannya dan membukakannya. Rasul pun segera masuk diikuti Usamah, Bilal, dan Utsman bin Thalhah. Pintu itu segera ditutup, beliau tinggal lama di dalam hingga siang. Lalu mereka keluar lagi. Orang-orang pun segera berdatangan ingin ikut masuk. Abdullah berkata: Aku segera menemui orang-orang itu, dan aku mendapati [Bilal] sedang berdiri di depan pintu. Aku bertanya kepadanya: Dimana Rasulullah shallallahu 'alaihi wasallam melaksanakan shalat? Dia menjawab; \"Di antara dua tiang yang berada di depan. Karena Ka'bah terdiri dari enam tiang dan dua garis. Beliau shalat di antara dua tiang pada garis terdepan dengan menjadikan pintu ka'bah berada di belakang beliau. Beliau menghadapkan wajahnya ke arah ketika beliau menyambut anda saat anda masuk ke Ka'bah. Yaitu di antara kedua temboknya. Abdullah berkata: Tapi aku lupa tidak menanyakan kepadanya berapa raka'at beliau shalat?.' Sedangkan tempat yang beliau gunakan shalat adalah dekat dengan 'Marmarah Hamra' (batu marmer merah)."},"3772":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ حَدَّثَنِي عُرْوَةُ بْنُ الزُّبَيْرِ وَأَبُو سَلَمَةَ بْنُ عَبْدِ الرَّحْمَنِ أَنَّ عَائِشَةَ زَوْجَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَخْبَرَتْهُمَاأَنَّ صَفِيَّةَ بِنْتَ حُيَيٍّ زَوْجَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَاضَتْ فِي حَجَّةِ الْوَدَاعِ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَحَابِسَتُنَا هِيَ فَقُلْتُ إِنَّهَا قَدْ أَفَاضَتْ يَا رَسُولَ اللَّهِ وَطَافَتْ بِالْبَيْتِ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلْتَنْفِرْ","id":"Telah menceritakan kepada kami [Abu Al Yaman] Telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhri] Telah menceritakan kepadaku ['Urwah bin Az Zubair] dan [Abu Salamah bin 'Abdur Rahman] bahwa ['Aisyah] isteri Nabi shallallahu 'alaihi wasallam Telah mengabarkan kepada mereka; \"Shafiyah binti Huyai -istri Nabi shallallahu 'alaihi wasallam- kedatangan haid saat haji wada'.\" Maka Rasulullah bersabda: \"Apakah hal itu menghalangi dari kita?\" Saya berkata; \"Wahai Rasulullah! Dia telah melakukan thawaf ifadlah dan thawaf di ka'bah. Rasulullah shalallahu'alaihi wa sallam pun bersabda: 'Kalau begitu Kembalilah (kembali dari Mina ke Madinah).'"},"3773":{"ar":"حَدَّثَنَا يَحْيَى بْنُ سُلَيْمَانَ قَالَ أَخْبَرَنِي ابْنُ وَهْبٍ قَالَ حَدَّثَنِي عُمَرُ بْنُ مُحَمَّدٍ أَنَّ أَبَاهُ حَدَّثَهُ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا قَالَكُنَّا نَتَحَدَّثُ بِحَجَّةِ الْوَدَاعِ وَالنَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَيْنَ أَظْهُرِنَا وَلَا نَدْرِي مَا حَجَّةُ الْوَدَاعِ فَحَمِدَ اللَّهَ وَأَثْنَى عَلَيْهِ ثُمَّ ذَكَرَ الْمَسِيحَ الدَّجَّالَ فَأَطْنَبَ فِي ذِكْرِهِ وَقَالَ مَا بَعَثَ اللَّهُ مِنْ نَبِيٍّ إِلَّا أَنْذَرَ أُمَّتَهُ أَنْذَرَهُ نُوحٌ وَالنَّبِيُّونَ مِنْ بَعْدِهِ وَإِنَّهُ يَخْرُجُ فِيكُمْ فَمَا خَفِيَ عَلَيْكُمْ مِنْ شَأْنِهِ فَلَيْسَ يَخْفَى عَلَيْكُمْ أَنَّ رَبَّكُمْ لَيْسَ عَلَى مَا يَخْفَى عَلَيْكُمْ ثَلَاثًا إِنَّ رَبَّكُمْ لَيْسَ بِأَعْوَرَ وَإِنَّهُ أَعْوَرُ عَيْنِ الْيُمْنَى كَأَنَّ عَيْنَهُ عِنَبَةٌ طَافِيَةٌ أَلَا إِنَّ اللَّهَ حَرَّمَ عَلَيْكُمْ دِمَاءَكُمْ وَأَمْوَالَكُمْ كَحُرْمَةِ يَوْمِكُمْ هَذَا فِي بَلَدِكُمْ هَذَا فِي شَهْرِكُمْ هَذَا أَلَا هَلْ بَلَّغْتُ قَالُوا نَعَمْ قَالَ اللَّهُمَّ اشْهَدْ ثَلَاثًا وَيْلَكُمْ أَوْ وَيْحَكُمْ انْظُرُوا لَا تَرْجِعُوا بَعْدِي كُفَّارًا يَضْرِبُ بَعْضُكُمْ رِقَابَ بَعْضٍ","id":"Telah menceritakan kepada kami [Yahya bin Sulaiman] dia berkata; Telah mengabarkan kepadaku [Ibnu Wahb] dia berkata; Telah menceritakan kepadaku ['Umar bin Muhammad] bahwa [Bapaknya] telah menceritakan kepadanya dari [Ibnu 'Umar radliallahu 'anhu] dia berkata; \"Kami bincang-bincang tentang Haji Wada', pada waktu Nabi shallallahu 'alaihi wasallam berada bersama kami. Namun kami tidak mengetahui apa yang dimaksud dengan haji Wada'. Kemudian Rasulullah Shallallahu'alaihi wasallam berkhutbah dengan memuji Allah terlebih dahulu, lalu beliau menyebut-nyebut tentang Masih Ad Dajjal kemudian beliau terus menyebutnya berulang kali hingga beliau bersabda: \"Tidaklah Allah mengutus seorang Nabi kecuali dia mengingatkan umatnya (dari bahaya Dajjal), Nuh telah mengingatkan umatnya dan juga para Nabi yang datang setelahnya. Ketahuilah bahwa Dajjal akan keluar kepada kalian, dan sekali-kali tidak tersembunyi dari kalian. Dan Rabb kalian pun tidak akan menyembunyikannya dari kalian. (beliau menyebutkan sebanyak tiga kali). Sesungguhnya Rabb kalian tidaklah buta sebelah. Sedangkan Dajjal buta mata sebelah kanannya. Matanya seperti buah anggur yang menjorok. Ketahuilah sesungguhnya Allah telah mengharamkan kepada kalian darah, dan harta kalian. Sebagaimana haramnya pada hari ini, di negeri ini dan bulan ini. Ketahuilah apakah aku sudah selesai menyampaikan? Mereka menjawab; 'Ya.' Beliau bersabda: 'Ya Allah, saksikanlah! (sebanyak tiga kali). Celakah kalian, janganlah kalian kembali menjadi kafir sepeninggalku, sehingga sebagian kalian memenggal leher sebagian yang lainnya.'"},"3774":{"ar":"حَدَّثَنَا عَمْرُو بْنُ خَالِدٍ حَدَّثَنَا زُهَيْرٌ حَدَّثَنَا أَبُو إِسْحَاقَ قَالَ حَدَّثَنِي زَيْدُ بْنُ أَرْقَمَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ غَزَا تِسْعَ عَشْرَةَ غَزْوَةً وَأَنَّهُ حَجَّ بَعْدَ مَا هَاجَرَ حَجَّةً وَاحِدَةً لَمْ يَحُجَّ بَعْدَهَا حَجَّةَ الْوَدَاعِقَالَ أَبُو إِسْحَاقَ وَبِمَكَّةَ أُخْرَى","id":"Telah menceritakan kepada kami ['Amru bin Khalid] Telah menceritakan kepada kami [Zuhair] Telah menceritakan kepada kami [Abu Ishaq] dia berkata; Telah menceritakan kepadaku [Zaid bin Arqam] bahwa Nabi shallallahu 'alaihi wasallam telah berperang sebanyak sembilan belas peperangan. Dan beliau melaksanakan haji setelah hijrah sebanyak satu kali, beliau tidak melaksanakan haji wada' setelah itu. Abu Ishaq berkata; dan beliau juga pernah melaksanakan haji ketika beliau berada di makkah."},"3775":{"ar":"حَدَّثَنَا حَفْصُ بْنُ عُمَرَ حَدَّثَنَا شُعْبَةُ عَنْ عَلِيِّ بْنِ مُدْرِكٍ عَنْ أَبِي زُرْعَةَ بْنِ عَمْرِو بْنِ جَرِيرٍ عَنْ جَرِيرٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فِي حَجَّةِ الْوَدَاعِ لِجَرِيرٍ اسْتَنْصِتْ النَّاسَ فَقَالَ لَا تَرْجِعُوا بَعْدِي كُفَّارًا يَضْرِبُ بَعْضُكُمْ رِقَابَ بَعْضٍ","id":"Telah menceritakan kepada kami [Hafsh bin 'Umar] Telah menceritakan kepada kami [Syu'bah] dari ['Ali bin Mudrik] dari [Abu Zur'ah bin 'Amru bin Jarir] dari [Jarir] bahwa Nabi shallallahu 'alaihi wasallam pada waktu haji Wada' berkata kepada Jarir agar menyuruh orang-orang diam. Lalu beliau bersabda: \"Janganlah kalian kembali menjadi kafir sepeninggalku, sehingga sebagian kalian memenggal leher sebagian yang lainnya.\""},"3776":{"ar":"حَدَّثَنِي مُحَمَّدُ بْنُ الْعَلَاءِ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ بُرَيْدِ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي بُرْدَةَ عَنْ أَبِي بُرْدَةَ عَنْ أَبِي مُوسَى رَضِيَ اللَّهُ عَنْهُ قَالَأَرْسَلَنِي أَصْحَابِي إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَسْأَلُهُ الْحُمْلَانَ لَهُمْ إِذْ هُمْ مَعَهُ فِي جَيْشِ الْعُسْرَةِ وَهِيَ غَزْوَةُ تَبُوكَ فَقُلْتُ يَا نَبِيَّ اللَّهِ إِنَّ أَصْحَابِي أَرْسَلُونِي إِلَيْكَ لِتَحْمِلَهُمْ فَقَالَ وَاللَّهِ لَا أَحْمِلُكُمْ عَلَى شَيْءٍ وَوَافَقْتُهُ وَهُوَ غَضْبَانُ وَلَا أَشْعُرُ وَرَجَعْتُ حَزِينًا مِنْ مَنْعِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَمِنْ مَخَافَةِ أَنْ يَكُونَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَجَدَ فِي نَفْسِهِ عَلَيَّ فَرَجَعْتُ إِلَى أَصْحَابِي فَأَخْبَرْتُهُمْ الَّذِي قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمْ أَلْبَثْ إِلَّا سُوَيْعَةً إِذْ سَمِعْتُ بِلَالًا يُنَادِي أَيْ عَبْدَ اللَّهِ بْنَ قَيْسٍ فَأَجَبْتُهُ فَقَالَ أَجِبْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَدْعُوكَ فَلَمَّا أَتَيْتُهُ قَالَ خُذْ هَذَيْنِ الْقَرِينَيْنِ وَهَذَيْنِ الْقَرِينَيْنِ لِسِتَّةِ أَبْعِرَةٍ ابْتَاعَهُنَّ حِينَئِذٍ مِنْ سَعْدٍ فَانْطَلِقْ بِهِنَّ إِلَى أَصْحَابِكَ فَقُلْ إِنَّ اللَّهَ أَوْ قَالَ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَحْمِلُكُمْ عَلَى هَؤُلَاءِ فَارْكَبُوهُنَّ فَانْطَلَقْتُ إِلَيْهِمْ بِهِنَّ فَقُلْتُ إِنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَحْمِلُكُمْ عَلَى هَؤُلَاءِ وَلَكِنِّي وَاللَّهِ لَا أَدَعُكُمْ حَتَّى يَنْطَلِقَ مَعِي بَعْضُكُمْ إِلَى مَنْ سَمِعَ مَقَالَةَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَظُنُّوا أَنِّي حَدَّثْتُكُمْ شَيْئًا لَمْ يَقُلْهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالُوا لِي وَاللَّهِ إِنَّكَ عِنْدَنَا لَمُصَدَّقٌ وَلَنَفْعَلَنَّ مَا أَحْبَبْتَ فَانْطَلَقَ أَبُو مُوسَى بِنَفَرٍ مِنْهُمْ حَتَّى أَتَوْا الَّذِينَ سَمِعُوا قَوْلَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْعَهُ إِيَّاهُمْ ثُمَّ إِعْطَاءَهُمْ بَعْدُ فَحَدَّثُوهُمْ بِمِثْلِ مَا حَدَّثَهُمْ بِهِ أَبُو مُوسَى","id":"Telah menceritakan kepadaku [Muhammad bin Al A'laa] Telah menceritakan kepada kami [Abu Usamah] dari [Buraid bin 'Abdullah bin Abu Burdah] dari [Abu Burdah] dari [Abu Musa] radliallahu 'anhu dia berkata; para sahabatku mengutusku menemui Rasulullah shallallahu 'alaihi wasallam untuk meminta darinya sejumlah hewan tunggangan karena mereka ikut ambil bagian bersama Rasulullah shallallahu 'alaihi wasallam dalam pasukan Al 'Usrah, yaitu perang Tabuk. Aku berkata; Ya Rasulullah! Para sahabatku memintamu memberi mereka hewan tunggangan. Nabi shallallahu 'alaihi wasallam bersabda: Demi Allah, kalian tidak perlu mengendarai apapun. Itu terjadi ketika aku menemui Nabi shallallahu 'alaihi wasallam dalam keadaan marah dan aku tidak mengetahuinya. Maka dengan perasaan sedih karena penolakan itu, aku kembali dan dengan perasaan takut kalau Rasulullah shallallahu 'alaihi wasallam akan marah padaku. Maka aku kembali menemui para sahabatku, dan memberi tahukan apa yang terjadi. Tak berapa lama kemudian, aku mendengar Bilal memanggilku; wahai Abdullah bin Qais! Aku menjawab panggilannya. Bilal berkata; Rasulullah shallallahu 'alaihi wasallam memanggilmu. Ketika aku berjumpa dengannya, Nabi shallallahu 'alaihi wasallam berkata; Ambillah dua unta ini, dan dua unta ini. Seraya menunjuk enam ekor unta yang dibawa Nabi shallallahu 'alaihi wasallam dari Sa'ad. Kemudian Nabi shallallahu 'alaihi wasallam bersabda: Bawalah unta-unta itu kepada para sahabatmu dan katakan Allah atau Rasulullah shallallahu 'alaihi wasallam mengizinkanmu mengendarainya, jadi kendarailah. Maka akupun membawa unta-unta itu kepada mereka dan berkata; Nabi shallallahu 'alaihi wasallam mengizinkan kalian mengendarai unta-unta ini, aku tidak akan meninggalkan kalian hingga sebagian dari kalian ikut bersamaku menemui seseorang yang mendengar perkataan Nabi shallallahu 'alaihi wasallam. Jangan berfikir bahwa aku mengatakan apa yang tidak dikatakan Nabi shallallahu 'alaihi wasallam. mereka berkata kepadaku; menurut kami, kamu benar. Dan kami akan melakukan apa yang kamu inginkan. Maka Abu Musa berangkat bersama sebagian dari mereka menemui orang-orang yang mendengar langsung perkataan Rasulullah shallallahu 'alaihi wasallam. Dan ternyata mereka menginformasikan hal yang sama sebagaimana yang diinformasikan Abu Musa."},"3777":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ شُعْبَةَ عَنْ الْحَكَمِ عَنْ مُصْعَبِ بْنِ سَعْدٍ عَنْ أَبِيهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَرَجَ إِلَى تَبُوكَ وَاسْتَخْلَفَ عَلِيًّا فَقَالَ أَتُخَلِّفُنِي فِي الصِّبْيَانِ وَالنِّسَاءِ قَالَ أَلَا تَرْضَى أَنْ تَكُونَ مِنِّي بِمَنْزِلَةِ هَارُونَ مِنْ مُوسَى إِلَّا أَنَّهُ لَيْسَ نَبِيٌّ بَعْدِيوَقَالَ أَبُو دَاوُدَ حَدَّثَنَا شُعْبَةُ عَنْ الْحَكَمِ سَمِعْتُ مُصْعَبًا","id":"Telah menceritakan kepada kami [Musaddad] Telah menceritakan kepada kami [Yahya] dari [Syu'bah] dari [Al Hakam] dari [Mush'ab bin Sa'ad] dari [Bapaknya] bahwa Rasulullah shallallahu 'alaihi wasallam pernah menugasi Ali bin Abu Thalib untuk menjaga kaum muslimin ketika terjadi perang Tabuk.\" Ali berkata; \"Ya Rasulullah, mengapa engkau hanya menugasi saya untuk menjaga kaum wanita dan anak-anak?\" Rasulullah shallallahu 'alaihi wasallam menjawab: \"Tidak inginkah kamu hai Ali memperoleh posisi di sisiku seperti posisi Harun di sisi Musa, padahal sesudahku tidak akan ada nabi lagi?\" [Abu Daud] berkata; Telah menceritakan kepada kami [Syu'bah] dari [Al Hakam] Aku mendengar [Mus'ab]."},"3778":{"ar":"حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ سَعِيدٍ حَدَّثَنَا مُحَمَّدُ بْنُ بَكْرٍ أَخْبَرَنَا ابْنُ جُرَيْجٍ قَالَ سَمِعْتُ عَطَاءً يُخْبِرُ قَالَ أَخْبَرَنِي صَفْوَانُ بْنُ يَعْلَى بْنِ أُمَيَّةَ عَنْ أَبِيهِ قَالَغَزَوْتُ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْعُسْرَةَ قَالَ كَانَ يَعْلَى يَقُولُ تِلْكَ الْغَزْوَةُ أَوْثَقُ أَعْمَالِي عِنْدِي قَالَ عَطَاءٌ فَقَالَ صَفْوَانُ قَالَ يَعْلَى فَكَانَ لِي أَجِيرٌ فَقَاتَلَ إِنْسَانًا فَعَضَّ أَحَدُهُمَا يَدَ الْآخَرِ قَالَ عَطَاءٌ فَلَقَدْ أَخْبَرَنِي صَفْوَانُ أَيُّهُمَا عَضَّ الْآخَرَ فَنَسِيتُهُ قَالَ فَانْتَزَعَ الْمَعْضُوضُ يَدَهُ مِنْ فِي الْعَاضِّ فَانْتَزَعَ إِحْدَى ثَنِيَّتَيْهِ فَأَتَيَا النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَهْدَرَ ثَنِيَّتَهُ قَالَ عَطَاءٌ وَحَسِبْتُ أَنَّهُ قَالَ قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَفَيَدَعُ يَدَهُ فِي فِيكَ تَقْضَمُهَا كَأَنَّهَا فِي فِي فَحْلٍ يَقْضَمُهَا","id":"Telah menceritakan kepada kami ['Ubaidullah bin Sa'id] Telah menceritakan kepada kami [Muhammad bin Bakr] Telah mengabarkan kepada kami [Ibnu Juraij] dia berkata; Aku mendengar ['Atha'] mengabarkan seraya berkata; Telah mengabarkan kepadaku [Shafwan bin Ya'la bin Umayyah] dari [Bapaknya] dia berkata; saya pernah ikut perang bersama Rasulullah shallallahu 'alaihi wasallam pada perang 'Usrah. Ya'al berkata; Perang itu merupakan amalanku yang paling kuat dalam diriku. Atha berkata; Shafwan berkata; selanjutnya Ya'ala berkata; dan saya memiliki orang upahan, kemudian ia berkelahi dengan seseorang, salah seorang dari mereka menggigit tangan lawannya, Atha berkata; Shafwan telah mengabarkan kepadaku siapakah yang menggigit tangan lawannya, namun aku lupa. kemudian yang digigit menarik tangannya dari mulut yang menggigit hingga melepaskan gigi serinya. Lalu keduanya menemui Nabi shallallahu 'alaihi wasallam. Maka beliau membentak orang yang lepas gigi serinya. Atha berkata; Aku mengira Shafwan berkata; Nabi shallallahu 'alaihi wasallam bersabda: \"Apakah ia akan membiarkan tangannya ada dalam mulutmu dan engkau menggigitnya seperti pejantan yang sedang menggigit?\""},"3779":{"ar":"حَدَّثَنَا يَحْيَى بْنُ بُكَيْرٍ حَدَّثَنَا اللَّيْثُ عَنْ عُقَيْلٍ عَنْ ابْنِ شِهَابٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ عَبْدِ اللَّهِ بْنِ كَعْبِ بْنِ مَالِكٍ أَنَّ عَبْدَ اللَّهِ بْنَ كَعْبِ بْنِ مَالِكٍ وَكَانَ قَائِدَ كَعْبٍ مِنْ بَنِيهِ حِينَ عَمِيَ قَالَ سَمِعْتُ كَعْبَ بْنَ مَالِكٍ يُحَدِّثُحِينَ تَخَلَّفَ عَنْ قِصَّةِ تَبُوكَ قَالَ كَعْبٌ لَمْ أَتَخَلَّفْ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي غَزْوَةٍ غَزَاهَا إِلَّا فِي غَزْوَةِ تَبُوكَ غَيْرَ أَنِّي كُنْتُ تَخَلَّفْتُ فِي غَزْوَةِ بَدْرٍ وَلَمْ يُعَاتِبْ أَحَدًا تَخَلَّفَ عَنْهَا إِنَّمَا خَرَجَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُرِيدُ عِيرَ قُرَيْشٍ حَتَّى جَمَعَ اللَّهُ بَيْنَهُمْ وَبَيْنَ عَدُوِّهِمْ عَلَى غَيْرِ مِيعَادٍ وَلَقَدْ شَهِدْتُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيْلَةَ الْعَقَبَةِ حِينَ تَوَاثَقْنَا عَلَى الْإِسْلَامِ وَمَا أُحِبُّ أَنَّ لِي بِهَا مَشْهَدَ بَدْرٍ وَإِنْ كَانَتْ بَدْرٌ أَذْكَرَ فِي النَّاسِ مِنْهَا كَانَ مِنْ خَبَرِي أَنِّي لَمْ أَكُنْ قَطُّ أَقْوَى وَلَا أَيْسَرَ حِينَ تَخَلَّفْتُ عَنْهُ فِي تِلْكَ الْغَزَاةِ وَاللَّهِ مَا اجْتَمَعَتْ عِنْدِي قَبْلَهُ رَاحِلَتَانِ قَطُّ حَتَّى جَمَعْتُهُمَا فِي تِلْكَ الْغَزْوَةِ وَلَمْ يَكُنْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُرِيدُ غَزْوَةً إِلَّا وَرَّى بِغَيْرِهَا حَتَّى كَانَتْ تِلْكَ الْغَزْوَةُ غَزَاهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي حَرٍّ شَدِيدٍ وَاسْتَقْبَلَ سَفَرًا بَعِيدًا وَمَفَازًا وَعَدُوًّا كَثِيرًا فَجَلَّى لِلْمُسْلِمِينَ أَمْرَهُمْ لِيَتَأَهَّبُوا أُهْبَةَ غَزْوِهِمْ فَأَخْبَرَهُمْ بِوَجْهِهِ الَّذِي يُرِيدُ وَالْمُسْلِمُونَ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَثِيرٌ وَلَا يَجْمَعُهُمْ كِتَابٌ حَافِظٌ يُرِيدُ الدِّيوَانَ قَالَ كَعْبٌ فَمَا رَجُلٌ يُرِيدُ أَنْ يَتَغَيَّبَ إِلَّا ظَنَّ أَنْ سَيَخْفَى لَهُ مَا لَمْ يَنْزِلْ فِيهِ وَحْيُ اللَّهِ وَغَزَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تِلْكَ الْغَزْوَةَ حِينَ طَابَتْ الثِّمَارُ وَالظِّلَالُ وَتَجَهَّزَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالْمُسْلِمُونَ مَعَهُ فَطَفِقْتُ أَغْدُو لِكَيْ أَتَجَهَّزَ مَعَهُمْ فَأَرْجِعُ وَلَمْ أَقْضِ شَيْئًا فَأَقُولُ فِي نَفْسِي أَنَا قَادِرٌ عَلَيْهِ فَلَمْ يَزَلْ يَتَمَادَى بِي حَتَّى اشْتَدَّ بِالنَّاسِ الْجِدُّ فَأَصْبَحَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالْمُسْلِمُونَ مَعَهُ وَلَمْ أَقْضِ مِنْ جَهَازِي شَيْئًا فَقُلْتُ أَتَجَهَّزُ بَعْدَهُ بِيَوْمٍ أَوْ يَوْمَيْنِ ثُمَّ أَلْحَقُهُمْ فَغَدَوْتُ بَعْدَ أَنْ فَصَلُوا لِأَتَجَهَّزَ فَرَجَعْتُ وَلَمْ أَقْضِ شَيْئًا ثُمَّ غَدَوْتُ ثُمَّ رَجَعْتُ وَلَمْ أَقْضِ شَيْئًا فَلَمْ يَزَلْ بِي حَتَّى أَسْرَعُوا وَتَفَارَطَ الْغَزْوُ وَهَمَمْتُ أَنْ أَرْتَحِلَ فَأُدْرِكَهُمْ وَلَيْتَنِي فَعَلْتُ فَلَمْ يُقَدَّرْ لِي ذَلِكَ فَكُنْتُ إِذَا خَرَجْتُ فِي النَّاسِ بَعْدَ خُرُوجِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَطُفْتُ فِيهِمْ أَحْزَنَنِي أَنِّي لَا أَرَى إِلَّا رَجُلًا مَغْمُوصًا عَلَيْهِ النِّفَاقُ أَوْ رَجُلًا مِمَّنْ عَذَرَ اللَّهُ مِنْ الضُّعَفَاءِ وَلَمْ يَذْكُرْنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى بَلَغَ تَبُوكَ فَقَالَ وَهُوَ جَالِسٌ فِي الْقَوْمِ بِتَبُوكَ مَا فَعَلَ كَعْبٌ فَقَالَ رَجُلٌ مِنْ بَنِي سَلِمَةَ يَا رَسُولَ اللَّهِ حَبَسَهُ بُرْدَاهُ وَنَظَرُهُ فِي عِطْفِهِ فَقَالَ مُعَاذُ بْنُ جَبَلٍ بِئْسَ مَا قُلْتَ وَاللَّهِ يَا رَسُولَ اللَّهِ مَا عَلِمْنَا عَلَيْهِ إِلَّا خَيْرًا فَسَكَتَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ كَعْبُ بْنُ مَالِكٍ فَلَمَّا بَلَغَنِي أَنَّهُ تَوَجَّهَ قَافِلًا حَضَرَنِي هَمِّي وَطَفِقْتُ أَتَذَكَّرُ الْكَذِبَ وَأَقُولُ بِمَاذَا أَخْرُجُ مِنْ سَخَطِهِ غَدًا وَاسْتَعَنْتُ عَلَى ذَلِكَ بِكُلِّ ذِي رَأْيٍ مِنْ أَهْلِي فَلَمَّا قِيلَ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ أَظَلَّ قَادِمًا زَاحَ عَنِّي الْبَاطِلُ وَعَرَفْتُ أَنِّي لَنْ أَخْرُجَ مِنْهُ أَبَدًا بِشَيْءٍ فِيهِ كَذِبٌ فَأَجْمَعْتُ صِدْقَهُ وَأَصْبَحَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَادِمًا وَكَانَ إِذَا قَدِمَ مِنْ سَفَرٍ بَدَأَ بِالْمَسْجِدِ فَيَرْكَعُ فِيهِ رَكْعَتَيْنِ ثُمَّ جَلَسَ لِلنَّاسِ فَلَمَّا فَعَلَ ذَلِكَ جَاءَهُ الْمُخَلَّفُونَ فَطَفِقُوا يَعْتَذِرُونَ إِلَيْهِ وَيَحْلِفُونَ لَهُ وَكَانُوا بِضْعَةً وَثَمَانِينَ رَجُلًا فَقَبِلَ مِنْهُمْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَانِيَتَهُمْ وَبَايَعَهُمْ وَاسْتَغْفَرَ لَهُمْ وَوَكَلَ سَرَائِرَهُمْ إِلَى اللَّهِ فَجِئْتُهُ فَلَمَّا سَلَّمْتُ عَلَيْهِ تَبَسَّمَ تَبَسُّمَ الْمُغْضَبِ ثُمَّ قَالَ تَعَالَ فَجِئْتُ أَمْشِي حَتَّى جَلَسْتُ بَيْنَ يَدَيْهِ فَقَالَ لِي مَا خَلَّفَكَ أَلَمْ تَكُنْ قَدْ ابْتَعْتَ ظَهْرَكَ فَقُلْتُ بَلَى إِنِّي وَاللَّهِ لَوْ جَلَسْتُ عِنْدَ غَيْرِكَ مِنْ أَهْلِ الدُّنْيَا لَرَأَيْتُ أَنْ سَأَخْرُجُ مِنْ سَخَطِهِ بِعُذْرٍ وَلَقَدْ أُعْطِيتُ جَدَلًا وَلَكِنِّي وَاللَّهِ لَقَدْ عَلِمْتُ لَئِنْ حَدَّثْتُكَ الْيَوْمَ حَدِيثَ كَذِبٍ تَرْضَى بِهِ عَنِّي لَيُوشِكَنَّ اللَّهُ أَنْ يُسْخِطَكَ عَلَيَّ وَلَئِنْ حَدَّثْتُكَ حَدِيثَ صِدْقٍ تَجِدُ عَلَيَّ فِيهِ إِنِّي لَأَرْجُو فِيهِ عَفْوَ اللَّهِ لَا وَاللَّهِ مَا كَانَ لِي مِنْ عُذْرٍ وَاللَّهِ مَا كُنْتُ قَطُّ أَقْوَى وَلَا أَيْسَرَ مِنِّي حِينَ تَخَلَّفْتُ عَنْكَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَّا هَذَا فَقَدْ صَدَقَ فَقُمْ حَتَّى يَقْضِيَ اللَّهُ فِيكَ فَقُمْتُ وَثَارَ رِجَالٌ مِنْ بَنِي سَلِمَةَ فَاتَّبَعُونِي فَقَالُوا لِي وَاللَّهِ مَا عَلِمْنَاكَ كُنْتَ أَذْنَبْتَ ذَنْبًا قَبْلَ هَذَا وَلَقَدْ عَجَزْتَ أَنْ لَا تَكُونَ اعْتَذَرْتَ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمَا اعْتَذَرَ إِلَيْهِ الْمُتَخَلِّفُونَ قَدْ كَانَ كَافِيَكَ ذَنْبَكَ اسْتِغْفَارُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَكَ فَوَاللَّهِ مَا زَالُوا يُؤَنِّبُونِي حَتَّى أَرَدْتُ أَنْ أَرْجِعَ فَأُكَذِّبَ نَفْسِي ثُمَّ قُلْتُ لَهُمْ هَلْ لَقِيَ هَذَا مَعِي أَحَدٌ قَالُوا نَعَمْ رَجُلَانِ قَالَا مِثْلَ مَا قُلْتَ فَقِيلَ لَهُمَا مِثْلُ مَا قِيلَ لَكَ فَقُلْتُ مَنْ هُمَا قَالُوا مُرَارَةُ بْنُ الرَّبِيعِ الْعَمْرِيُّ وَهِلَالُ بْنُ أُمَيَّةَ الْوَاقِفِيُّ فَذَكَرُوا لِي رَجُلَيْنِ صَالِحَيْنِ قَدْ شَهِدَا بَدْرًا فِيهِمَا أُسْوَةٌ فَمَضَيْتُ حِينَ ذَكَرُوهُمَا لِي وَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمُسْلِمِينَ عَنْ كَلَامِنَا أَيُّهَا الثَّلَاثَةُ مِنْ بَيْنِ مَنْ تَخَلَّفَ عَنْهُ فَاجْتَنَبَنَا النَّاسُ وَتَغَيَّرُوا لَنَا حَتَّى تَنَكَّرَتْ فِي نَفْسِي الْأَرْضُ فَمَا هِيَ الَّتِي أَعْرِفُ فَلَبِثْنَا عَلَى ذَلِكَ خَمْسِينَ لَيْلَةً فَأَمَّا صَاحِبَايَ فَاسْتَكَانَا وَقَعَدَا فِي بُيُوتِهِمَا يَبْكِيَانِ وَأَمَّا أَنَا فَكُنْتُ أَشَبَّ الْقَوْمِ وَأَجْلَدَهُمْ فَكُنْتُ أَخْرُجُ فَأَشْهَدُ الصَّلَاةَ مَعَ الْمُسْلِمِينَ وَأَطُوفُ فِي الْأَسْوَاقِ وَلَا يُكَلِّمُنِي أَحَدٌ وَآتِي رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأُسَلِّمُ عَلَيْهِ وَهُوَ فِي مَجْلِسِهِ بَعْدَ الصَّلَاةِ فَأَقُولُ فِي نَفْسِي هَلْ حَرَّكَ شَفَتَيْهِ بِرَدِّ السَّلَامِ عَلَيَّ أَمْ لَا ثُمَّ أُصَلِّي قَرِيبًا مِنْهُ فَأُسَارِقُهُ النَّظَرَ فَإِذَا أَقْبَلْتُ عَلَى صَلَاتِي أَقْبَلَ إِلَيَّ وَإِذَا الْتَفَتُّ نَحْوَهُ أَعْرَضَ عَنِّي حَتَّى إِذَا طَالَ عَلَيَّ ذَلِكَ مِنْ جَفْوَةِ النَّاسِ مَشَيْتُ حَتَّى تَسَوَّرْتُ جِدَارَ حَائِطِ أَبِي قَتَادَةَ وَهُوَ ابْنُ عَمِّي وَأَحَبُّ النَّاسِ إِلَيَّ فَسَلَّمْتُ عَلَيْهِ فَوَاللَّهِ مَا رَدَّ عَلَيَّ السَّلَامَ فَقُلْتُ يَا أَبَا قَتَادَةَ أَنْشُدُكَ بِاللَّهِ هَلْ تَعْلَمُنِي أُحِبُّ اللَّهَ وَرَسُولَهُ فَسَكَتَ فَعُدْتُ لَهُ فَنَشَدْتُهُ فَسَكَتَ فَعُدْتُ لَهُ فَنَشَدْتُهُ فَقَالَ اللَّهُ وَرَسُولُهُ أَعْلَمُ فَفَاضَتْ عَيْنَايَ وَتَوَلَّيْتُ حَتَّى تَسَوَّرْتُ الْجِدَارَ قَالَ فَبَيْنَا أَنَا أَمْشِي بِسُوقِ الْمَدِينَةِ إِذَا نَبَطِيٌّ مِنْ أَنْبَاطِ أَهْلِ الشَّأْمِ مِمَّنْ قَدِمَ بِالطَّعَامِ يَبِيعُهُ بِالْمَدِينَةِ يَقُولُ مَنْ يَدُلُّ عَلَى كَعْبِ بْنِ مَالِكٍ فَطَفِقَ النَّاسُ يُشِيرُونَ لَهُ حَتَّى إِذَا جَاءَنِي دَفَعَ إِلَيَّ كِتَابًا مِنْ مَلِكِ غَسَّانَ فَإِذَا فِيهِ أَمَّا بَعْدُ فَإِنَّهُ قَدْ بَلَغَنِي أَنَّ صَاحِبَكَ قَدْ جَفَاكَ وَلَمْ يَجْعَلْكَ اللَّهُ بِدَارِ هَوَانٍ وَلَا مَضْيَعَةٍ فَالْحَقْ بِنَا نُوَاسِكَ فَقُلْتُ لَمَّا قَرَأْتُهَا وَهَذَا أَيْضًا مِنْ الْبَلَاءِ فَتَيَمَّمْتُ بِهَا التَّنُّورَ فَسَجَرْتُهُ بِهَا حَتَّى إِذَا مَضَتْ أَرْبَعُونَ لَيْلَةً مِنْ الْخَمْسِينَ إِذَا رَسُولُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَأْتِينِي فَقَالَ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَأْمُرُكَ أَنْ تَعْتَزِلَ امْرَأَتَكَ فَقُلْتُ أُطَلِّقُهَا أَمْ مَاذَا أَفْعَلُ قَالَ لَا بَلْ اعْتَزِلْهَا وَلَا تَقْرَبْهَا وَأَرْسَلَ إِلَى صَاحِبَيَّ مِثْلَ ذَلِكَ فَقُلْتُ لِامْرَأَتِي الْحَقِي بِأَهْلِكِ فَتَكُونِي عِنْدَهُمْ حَتَّى يَقْضِيَ اللَّهُ فِي هَذَا الْأَمْرِ قَالَ كَعْبٌ فَجَاءَتْ امْرَأَةُ هِلَالِ بْنِ أُمَيَّةَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ يَا رَسُولَ اللَّهِ إِنَّ هِلَالَ بْنَ أُمَيَّةَ شَيْخٌ ضَائِعٌ لَيْسَ لَهُ خَادِمٌ فَهَلْ تَكْرَهُ أَنْ أَخْدُمَهُ قَالَ لَا وَلَكِنْ لَا يَقْرَبْكِ قَالَتْ إِنَّهُ وَاللَّهِ مَا بِهِ حَرَكَةٌ إِلَى شَ","id":"Telah menceritakan kepada kami [Yahya bin Bukair] Telah menceritakan kepada kami [Al Laits] dari ['Uqail] dari [Ibnu Syihab] dari ['Abdur Rahman bin 'Abdullah bin Ka'ab bin Malik] bahwa ['Abdullah bin Ka'ab bin Malik] -Abdullah bin Ka'ab adalah salah seorang putra Ka'ab yang mendampingi Ka'ab ketika ia buta- berkata; 'Saya pernah mendengar [Ka'ab bin Malik] menceritakan peristiwa tentang dirinya ketika ia tertinggal dari Rasulullah shallallahu 'alaihi wasallam dalam perang Tabuk.' Ka'ab bin Malik berkata; 'Saya tidak pernah tertinggal menyertai Rasulullah shallallahu 'alaihi wasallam dalam peperangan yang beliau ikuti kecuali perang Tabuk, akan tetapi saya juga pernah tertinggal dalam perang Badar. Hanya Rasulullah shallallahu 'alaihi wasallam tidak pernah mencela seorang muslim yang tidak turut dalam perang Badar. Yang demikian karena pada awalmulanya Rasulullah shallallahu 'alaihi wasallam dan kaum muslimin hanya ingin mencegat kaum kafir Quraisy yang sedang berada dalam perjalanan dengan mengendarai unta hingga Allah mempertemukan kaum muslimin dengan musuh mereka tanpa waktu yang di sepakati sebelumnya. Saat itu saya ikut serta bersama Rasulullah pada malam Aqabah ketika kami berjanji untuk membela Islam. Menurut saya, turut serta dalam perang Badar tidak sebanding dengan turut serta dalam malam Aqabah, meskipun perang Badar lebih populer kebanyakan orang. Di antara cerita ketika saya tidak turut serta bersama Rasulullah dalam perang Tabuk adalah sebagai berikut; 'Belum pernah stamina saya betul-betul fit dan mempunyai keluasan harta daripada ketika saya tidak ikut serta dalam perang Tabuk tersebut. Demi Allah, sebelumnya saya tidak menyiapkan dua ekor hewan tunggangan sama sekali dalam pelbagai peperangan. Tetapi dalam perang Tabuk ini, saya bisa menyiapkan dua ekor hewan tunggangan. Adalah sudah menjadi tradisi beliau Shallallahu'alaihiwasallam, beliau tidak pernah melakukan sebuah peperangan selain beliau merahasiakan tujuan peperangannya, hingga saat terjadilah perang tabuk ini, yang beliau nyatakan tujuan perangnya secara vulgar (terang-terangan). Akhirnya Rasulullah shallallahu 'alaihi wasallam pergi berangkat ke perang Tabuk pada saat cuaca sangat panas. Dapat di katakan bahwasanya beliau menempuh perjalanan yang amat jauh dan penuh resiko serta menghadapi musuh yang berjumlah besar. Lalu Rasulullah shallallahu 'alaihi wasallam menjelaskan kepada kaum muslimin apa yang akan mereka hadapi bersamanya. Oleh karena itu, beliau memerintahkan kaum muslimin untuk mempersiapkan perbekalan perang yang cukup. Pada saat itu, kaum muslimin yang menyertai Rasulullah shallallahu 'alaihi wasallam banyak sekali tanpa ditunjuk melalui surat tugas untuk berperang. Ka'ab berkata; 'Ada seorang laki-laki yang tidak muncul karena ia ingin tidak turut serta berperang. Ia menduga bahwa ketidak turutannya itu tidak akan di ketahui oleh Rasulullah shallallahu 'alaihi wasallam -selama tidak ada wahyu yang turun mengenai dirinya dari Allah Azza Wa Jalla -. Rasulullah shallallahu 'alaihi wasallam pergi berperang ke perang tabuk ketika hasil panen buah sangat memuaskan, hingga saya harus memalingkan perhatian dari hasil panen tersebut. Rasulullah shallallahu 'alaihi wasallam dan kaum muslimin yang ikut serta sudah bersiap-siap dan saya pun segera pergi untuk mencari perbekalan bersama mereka. Lalu saya pulang tanpa memperoleh perbekalan sama sekali. Saya berkata dalam hati; 'Ahh, saya dapat mempersiapkan perbekalan sewaktu-waktu. Saya selalu dalam teka-teki antara iya (berangkat) dan tidak hingga orang-orang semakin siap.' Rasulullah shallallahu 'alaihi wasallam berangkat bersama kaum muslimin, sedangkan saya belum mempersiapkan perbekalan sama sekali. Akhirnya saya pergi, lalu saya pulang tanpa mempersiapkan sesuatu. Saya senantiasa berada dalam kebimbangan seperti itu antara turut serta berperang ataupun tidak, hingga pasukan kaum muslimin telah bergegas berangkat dan perang pun berkecamuk sudah. Kemudian saya ingin menyusul ke medan pertempuran -tetapi hal itu hanyalah angan-angan belaka- dan akhirnya saya ditakdirkan untuk tidak ikut serta ke medan perang. Setelah Rasulullah shallallahu 'alaihi wasallam pergi ke medan perang tabuk, maka mulailah rasa sedih menyelimuti diri saya. Ketika keluar ke tengah-tengah masyarakat sekitar. Saya menyadari bahwasanya tidak ada yang dapat saya temui kecuali orang-orang yang dalam kemunafikan atau orang-orang yang lemah yang diberikan uzur oleh Allah Azza Wa Jalla. Sementara itu, Rasulullah shallallahu 'alaihi wasallam tidak mengingat diri saya hingga beliau sampai di Tabuk. Kemudian, ketika beliau sedang duduk-duduk di tengah para sahabat, tiba-tiba beliau bertanya; 'Mengapa Ka'ab bin Malik tidak ikut serta bersama kita? ' Seorang sahabat dari Bani Salimah menjawab; 'Ya Rasulullah, sepertinya Ka'ab bin Malik lebih mementingkan dirinya sendiri daripada perjuangan ini? ' Mendengar ucapan sahabat tersebut, Muadz bin Jabal berkata; 'Hai sahabat, buruk sekali ucapanmu itu! Demi Allah ya Rasulullah, saya tahu bahwasanya Ka'ab bin Malik itu adalah orang yang baik.' Kemudian Rasulullah shallallahu 'alaihi wasallam diam. Ketika beliau terdiam seperti itu, tiba-tiba beliau melihat seorang laki-laki yang memakai helm besi yang sulit di kenali. Lalu Rasulullah shallallahu 'alaihi wasallam berkata: 'Kamu pasti Abu Khaitsamah? ' Ternyata orang tersebut adalah memang benar-benar Abu Khaitsamah Al Anshari, sahabat yang pernah menyedekahkan satu sha' kurma ketika ia dicaci maki oleh orang-orang munafik. Ka'ab bin Malik berkata; 'Ketika saya mendengar bahwasanya Rasulullah shallallahu 'alaihi wasallam telah bersiap-siap kembali dari perang Tabuk, maka saya pun diliputi kesedihan. Lalu saya mulai merancang alasan untuk berdusta. Saya berkata dalam hati; 'Alasan apa yang dapat menyelamatkan diri saya dari amarah Rasulullah? ' Untuk menghadapi hal tersebut, saya meminta pertolongan kepada keluarga yang dapat memberikan saran. Ketika ada seseorang yang berkata kepada saya bahwasanya Rasulullah shallallahu 'alaihi wasallam hampir tiba di kota Madinah, hilanglah alasan untuk berdusta dari benak saya. Akhirnya saya menyadari bahwasanya saya tidak dapat berbohong sedikit pun kepada Rasulullah shallallahu 'alaihi wasallam. Oleh karena itu, saya pun harus berkata jujur kepada beliau. Tak lama kemudian Rasulullah shallallahu 'alaihi wasallam tiba di kota Madinah. Seperti biasa, beliau langsung menuju Masjid - sebagaimana tradisi beliau manakala tiba dari bepergian ke suatu daerah - untuk melakukan shalat. Setelah melakukan shalat sunnah, Rasulullah shallallahu 'alaihi wasallam langsung bercengkrama bersama para sahabat. Setelah itu, datanglah beberapa orang sahabat yang tidak sempat ikut serta bertempur bersama kaum muslimin seraya menyampaikan berbagai alasan kepada beliau dengan bersumpah. Diperkirakan mereka yang tidak turut serta bertempur itu sekitar delapan puluh orang lebih. Ternyata Rasulullah menerima keterus terangan mereka yang tidak ikut serta berperang, membai'at mereka, memohon ampun untuk mereka, dan menyerahkan apa yang mereka sembunyikan dalam hati mereka kepada Allah. Selang beberapa saat kemudian, saya datang menemui Rasulullah shallallahu 'alaihi wasallam. Setelah saya memberi salam, beliau tersenyum seperti senyuman orang yang marah. Kemudian beliau pun berkata; 'Kemarilah! ' Lalu saya berjalan mendekati beliau hingga saya duduk tepat di hadapan beliau. Setelah itu Rasulullah shallallahu 'alaihi wasallam bertanya: 'Mengapa kamu tidak ikut serta bertempur bersama kami hai Ka'ab? Bukankah kamu telah berjanji untuk menyerahkan jiwa ragamu untuk Islam? ' Saya menjawab; 'Ya Rasulullah, demi Allah seandainya saya duduk di dekat orang selain diri engkau, niscaya saya yakin bahwasanya saya akan terbebaskan dari kemurkaannya karena alasan dan argumentasi yang saya sampaikan. Tetapi, demi Allah, saya tahu jika sekarang saya menyampaikan kepada engkau alasan yang penuh dusta hingga membuat engkau tidak marah, tentunya Allah lah yang membuat engkau marah kepada saya. Apabila saya mengemukakan kepada engkau ya Rasulullah alasan saya yang benar dan jujur, lalu engkau akan memarahi saya dengan alasan tersebut, maka saya pun akan menerimanya dengan senang hati. Biarkanlah Allah memberi hukuman kepada saya dengan ucapan saya yang jujur tersebut. Demi Allah, sesungguhya tidak ada uzur yang membuat saya tidak ikut serta berperang. Demi Allah, saya tidak berdaya sama sekali kala itu meskipun saya mempunyai peluang yang sangat longgar sekali untuk ikut berjuang bersama kaum muslimin.' Mendengar pengakuan yang tulus itu, Rasulullah pun berkata: 'Orang ini telah berkata jujur dan benar. Oleh karena itu, berdirilah hingga Allah memberimu keputusan.\" Akhirnya saya pun berdiri dan beranjak dari sisi beliau. Tak lama kemudian, ada beberapa orang dari Bani Salimah beramai-ramai mengikuti saya seraya berkata; 'Hai Ka'ab, demi Allah, sebelumnya kami tidak mengetahui bahwasanya kamu telah berbuat suatu kesalahan/dosa. Kamu benar-benar tidak mengemukakan alasan kepada Rasulullah sebagaimana alasan yang dikemukakan para sahabat lain yang tidak turut berperang. Sesungguhnya, hanya istighfar Rasulullah untukmulah yang menghapus dosamu.' Ka'ab bin Malik berkata setelah itu; 'Demi Allah, mereka selalu mencerca saya hingga saya ingin kembali lagi kepada Rasulullah shallallahu 'alaihi wasallam lalu saya dustakan diri saya.' Ka'ab bin Malik berkata; 'Apakah ada orang lain yang telah menghadap Rasulullah shallallahu 'alaihi wasallam seperti diri saya ini? ' Orang-orang Bani Salimah menjawab; 'Ya. Ada dua orang lagi seperti dirimu. Kedua orang tersebut mengatakan kepada Rasulullah seperti apa yang telah kamu utarakan dan Rasulullah pun menjawabnya seperti jawaban kepadamu.' Ka'ab bin Malik berkata; 'Lalu saya pun bertanya; 'Siapakah kedua orang tersebut hai para sahabat? ' Mereka, kaum Bani Salimah, menjawab; 'Kedua orang tersebut adalah Murarah bin Rabi'ah Al Amin dan Hilal bin Ummayah Al Waqifi.' Ka'ab bin Malik berkata; 'Kemudian mereka menyebutkan dua orang sahabat yang shalih yang ikut serta dalam perang Badar dan keduanya layak dijadikan suri tauladan yang baik. Setelah itu, saya pun berlalu ketika mereka menyebutkan dua orang tersebut kepada saya.' Ka'ab bin Malik berkata; 'Beberapa hari kemudian, Rasulullah shallallahu 'alaihi wasallam melarang kaum muslimin untuk berbicara dengan kami bertiga yang tidak ikut serta dalam perang Tabuk. Sejak saat itu, kaum muslimin mulai menjauhi dan berubah sikap terhadap kami bertiga hingga bumi ini terasa asing bagi kami. Sepertinya, bumi ini bukanlah bumi yang pernah saya huni sebelumnya dan hal itu berlangsung lima puluh malam lamanya.' Dua orang teman saya yang tidak ikut serta dalam perang Tabuk itu kini bersimpuh sedih di rumahnya sambil menangis, sedangkan saya adalah seorang anak muda yang tangguh dan tegar. Saya tetap bersikap wajar dan menjalankan aktivitas sehari-hari seperti biasanya. Saya tetap keluar dari rumah, pergi ke masjid untuk menghadiri shalat jama'ah bersama kaum muslimin lainnya, dan berjalan-jalan di pasar meskipun tidak ada seorang pun yang sudi berbicara dengan saya. Hingga pada suatu ketika saya menghampiri Rasulullah shallallahu 'alaihi wasallam sambil memberikan salam kepadanya ketika beliau berada di tempat duduknya usai shalat. Saya bertanya dalam hati; 'Apakah Rasulullah shallallahu 'alaihi wasallam akan menggerakkan bibirnya untuk menjawab salam ataukah tidak? Kemudian saya melaksanakan shalat di dekat Rasulullah sambil mencuri pandangan kepada beliau. Ketika saya telah bersiap untuk melaksanakan shalat, beliau memandang kepada saya. Dan ketika saya menoleh kepadanya, beliaupun mengalihkan pandangannya dari saya.' Setelah lama terisolisir dari pergaulan kaum muslimin, saya pun pergi berjalan-jalan hingga sampai di pagar kebun Abu Qatadah. Abu Qatadah adalah putera paman saya (sepupu saya) dan ia adalah orang yang saya sukai. Sesampainya di sana, saya pun mengucapkan salam kepadanya. Tetapi, demi Allah, sama sekali ia tidak menjawab salam saya. Akhirnya saya memberanikan diri untuk bertanya kepadanya; 'Hai Abu Qatadah, saya bersumpah kepadamu dengan nama Allah, apakah kamu tidak mengetahui bahwasanya saya sangat mencintai Allah dan Rasul-Nya? ' Ternyata Abu Qatadah hanya terdiam saja. Lalu saya ulangi lagi ucapan saya dengan bersumpah seperti yang pertama kali. Namun ia tetap saja terdiam. Kemudian saya ulangi ucapan saya dan ia pun menjawab; 'Sesungguhnya Allah dan Rasul-Nya lebih mengetahui tentang hal ini.' Mendengar ucapannya itu, berlinanglah air mata saya dan saya pun kembali ke rumah sambil menyusuri kebun tersebut. Ketika saya sedang berjalan-jalan di pasar Madinah, ada seorang laki-laki dari negeri Syam yang berjualan makanan di kota Madinah bertanya; 'Siapakah yang dapat menunjukkan kepada saya di mana Ka'ab bin Malik? ' Lalu orang-orang pun menunjukkan kepada saya hingga orang tersebut datang kepada saya sambil menyerahkan sepucuk surat kepada saya dari raja Ghassan. Karena saya dapat membaca dan menulis, maka saya pun memahami isi surat tersebut. Ternyata isi surat tersebut sebagai berikut; 'Kami mendengar bahwasanya temanmu (maksudnya adalah Rasulullah shallallahu 'alaihi wasallam) telah mengisolirmu dari pergaulan umum, sementara Tuhanmu sendiri tidaklah menyia-nyiakanmu seperti itu. Oleh karena itu, bergabunglah dengan kami, niscaya kami akan menolongmu.' Selesai membaca surat itu, saya pun berkata; 'Sebenarnya surat ini juga merupakan sebuah bencana bagi saya.' Lalu saya memasukkannya ke dalam pembakaran dan membakarnya hingga musnah. Setelah empat puluh hari lamanya dari pengucilan umum, ternyata wahyu Tuhan pun tidak juga turun. Hingga pada suatu ketika, seorang utusan Rasulullah shallallahu 'alaihi wasallam mendatangi saya sambil menyampaikan sebuah pesan; 'Hai Ka'ab, sesungguhnya Rasulullah shallallahu 'alaihi wasallam memerintahkanmu untuk menghindari istrimu.' Saya bertanya; 'Apakah saya harus menceraikan atau bagaimana? ' Utusan tersebut menjawab; 'Tidak usah kamu ceraikan. Tetapi, cukuplah kamu menghindarinya dan janganlah kamu mendekatinya.' Lalu saya katakan kepada istri saya; 'Wahai dinda, sebaiknya dinda pulang terlebih dahulu ke rumah orang tua dinda dan tinggallah bersama dengan mereka hingga Allah memberikan keputusan yang jelas dalam permasalahan ini.' Ka'ab bin Malik berkata; 'Tak lama kemudian istri Hilal bin Umayyah pergi mendatangi Rasulullah shallallahu 'alaihi wasallam sambil bertanya; 'Ya Rasulullah, Hilal bin Umayyah itu sudah lanjut usia dan lemah serta tidak mempunyai pembantu. Oleh karena itu, izinkanlah saya merawatnya.' Rasulullah shallallahu 'alaihi wasallam pun menjawab: 'Jangan. Sebaiknya kamu tidak usah menemaninya terlebih dahulu dan ia tidak boleh dekat denganmu untuk beberapa saat.' Isteri Hilal tetap bersikeras dan berkata; 'Demi Allah ya Rasullah, sekarang ia itu tidak mempunyai semangat hidup lagi. Ia senantiasa menangis, sejak mendapatkan permasalahan ini sampai sekarang.' Ka'ab bin Malik berkata; 'Beberapa orang dari keluarga saya berkata; 'Sebaiknya kamu meminta izin terlebih dahulu kepada Rasulullah dalam masalah istrimu ini. Karena Rasulullah shallallahu 'alaihi wasallam sendiri telah memberikan izin kepada Hilal bin Umayyah untuk merawat suaminya.' Ka'ab bin Malik berkata; 'Saya tidak akan meminta izin kepada Rasulullah shallallahu 'alaihi wasallam dalam persoalan istri saya ini. Karena, bagaimanapun, saya tidak akan tahu bagaimana jawaban Rasulullah nanti jika saya meminta izin kepada beliau sedangkan saya masih muda belia.' Ka'ab bin Malik berkata; 'Ternyata hal itu berlangsung selama sepuluh malam hingga dengan demikian lengkaplah sudah lima puluh malam bagi kami terhitung sejak kaum muslimin dilarang untuk berbicara kepada kami. Ka'ab bin Malik berkata; 'Lalu saya melakukan shalat fajar pada malam yang ke lima puluh di bagian belakang rumah. Ketika saya sedang duduk dalam shalat tersebut, diri saya diliputi penyesalan dan kesedihan. Sepertinya bumi yang luas ini terasa sempit bagi diri saya. Tiba-tiba saya mendengar seseorang berteriak dengan lantangnya menembus cakrawala; 'Hai Ka'ab bin Malik, bergembiralah! ' Maka saya pun tersungkur sujud dan mengetahui bahwasanya saya telah terbebas dari persoalan saya. Ka'ab bin Malik berkata; 'Kemudian Rasulullah shallallahu 'alaihi wasallam mengumumkan kepada kaum muslimin usai shalat Shubuh bahwasanya Allah Subhanah"},"3780":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ الْجُعْفِيُّ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ سَالِمٍ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا قَالَلَمَّا مَرَّ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالْحِجْرِ قَالَ لَا تَدْخُلُوا مَسَاكِنَ الَّذِينَ ظَلَمُوا أَنْفُسَهُمْ أَنْ يُصِيبَكُمْ مَا أَصَابَهُمْ إِلَّا أَنْ تَكُونُوا بَاكِينَ ثُمَّ قَنَّعَ رَأْسَهُ وَأَسْرَعَ السَّيْرَ حَتَّى أَجَازَ الْوَادِيَ","id":"Telah menceritakan kepada kami ['Abdullah bin Muhammad Al Ju'fi] Telah menceritakan kepada kami ['Abdur Razzaq] Telah mengabarkan kepada kami [Ma'mar] dari [Az Zuhri] dari [Salim] dari [Ibnu 'Umar radliallahu 'anhu] dia berkata; Tatkala Rasulullah shallallahu 'alaihi wasallam melewati Hijr, Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah kalian memasuki tempat-tempat tinggal orang yang menzhalimi diri mereka sendiri kecuali kalian dengan menangis karena khawatir kalian tertimpa seperti yang menimpa mereka.\" Beliau kemudian menutupi kepalanya dan cepat-cepat pergi hingga melintasi lembah."},"3781":{"ar":"حَدَّثَنَا يَحْيَى بْن بُكَيْرٍ حَدَّثَنَا مَالِكٌ عَنْ عَبْدِ اللَّهِ بْنِ دِينَارٍ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِأَصْحَابِ الْحِجْرِ لَا تَدْخُلُوا عَلَى هَؤُلَاءِ الْمُعَذَّبِينَ إِلَّا أَنْ تَكُونُوا بَاكِينَ أَنْ يُصِيبَكُمْ مِثْلُ مَا أَصَابَهُمْ","id":"Telah menceritakan kepada kami [Yahya bin Bukair] Telah menceritakan kepada kami [Malik] dari ['Abdullah bin Dinar] dari [Ibnu 'Umar radliallahu 'anhuma] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda kepada para sahabat beliau yang tengah melintasi Hijr (tempat kaum Tsamud, pent.): \"Jangan memasuki mereka kaum yang disiksa kecuali kalian menangis, karena jangan-jangan kalian tertimpa seperti yang menimpa mereka.\""},"3782":{"ar":"بَاب حَدَّثَنَا يَحْيَى بْنُ بُكَيْرٍ عَنْ اللَّيْثِ عَنْ عَبْدِ الْعَزِيزِ بْنِ أَبِي سَلَمَةَ عَنْ سَعْدِ بْنِ إِبْرَاهِيمَ عَنْ نَافِعِ بْنِ جُبَيْرٍ عَنْ عُرْوَةَ بْنِ الْمُغِيرَةِ عَنْأَبِيهِ الْمُغِيرَةِ بْنِ شُعْبَةَ قَالَ ذَهَبَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِبَعْضِ حَاجَتِهِ فَقُمْتُ أَسْكُبُ عَلَيْهِ الْمَاءَ لَا أَعْلَمُهُ إِلَّا قَالَ فِي غَزْوَةِ تَبُوكَ فَغَسَلَ وَجْهَهُ وَذَهَبَ يَغْسِلُ ذِرَاعَيْهِ فَضَاقَ عَلَيْهِ كُمُّ الْجُبَّةِ فَأَخْرَجَهُمَا مِنْ تَحْتِ جُبَّتِهِ فَغَسَلَهُمَا ثُمَّ مَسَحَ عَلَى خُفَّيْهِ","id":"Bab telah menceritakan kepada kami [Yahya bin Bukair] dari [Al Laits] dari ['Abdul 'Aziz bin Abu Salamah] dari [Sa'ad bin Ibrahim] dari [Nafi' bin Jubair] dari ['Urwah bin Al Mughirah] dari [Bapaknya, Al Mughirah bin Syu'bah] dia berkata; Nabi shallallahu 'alaihi wasallam pernah pergi untuk melaksanakan hajatnya. Maka aku pun menuangkan air untuknya. -Sepengetahuanku bapakku berkata pada saat perang Tabuk-. Lalu beliau membasuh wajahnya, mencuci kedua lengannya, namun lubang lengannya sangat sempit. Maka beliau mengeluarkan tangannya dari bahwa pakaiannya. Kemudian beliau mencuci lengannya dan membasuh kedua khufnya."},"3783":{"ar":"حَدَّثَنَا خَالِدُ بْنُ مَخْلَدٍ حَدَّثَنَا سُلَيْمَانُ قَالَ حَدَّثَنِي عَمْرُو بْنُ يَحْيَى عَنْ عَبَّاسِ بْنِ سَهْلِ بْنِ سَعْدٍ عَنْ أَبِي حُمَيْدٍ قَالَأَقْبَلْنَا مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ غَزْوَةِ تَبُوكَ حَتَّى إِذَا أَشْرَفْنَا عَلَى الْمَدِينَةِ قَالَ هَذِهِ طَابَةُ وَهَذَا أُحُدٌ جَبَلٌ يُحِبُّنَا وَنُحِبُّهُ","id":"Telah menceritakan kepada kami [Khalid bin Makhlad] Telah menceritakan kepada kami [Sulaiman] dia berkata; Telah menceritakan kepadaku [Amru bin Yahya] dari [Abbas bin Sahal bin Sa'ad] dari [Abu Humaid] dia berkata; \"Kami pulang dari perang Tabuk hingga ketika kami sudah sampai di Madinah beliau bersabda: 'Inilah kota yang baik. Dan ini adalah gunung Uhud yaitu gunung yang mencintai kita dan kita pun mencintainya.'"},"3784":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مُحَمَّدٍ أَخْبَرَنَا عَبْدُ اللَّهِ أَخْبَرَنَا حُمَيْدٌ الطَّوِيلُ عَنْ أَنَسِ بْنِ مَالِكٍ رَضِيَ اللَّهُ عَنْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَجَعَ مِنْ غَزْوَةِ تَبُوكَ فَدَنَا مِنْ الْمَدِينَةِ فَقَالَ إِنَّ بِالْمَدِينَةِ أَقْوَامًا مَا سِرْتُمْ مَسِيرًا وَلَا قَطَعْتُمْ وَادِيًا إِلَّا كَانُوا مَعَكُمْ قَالُوا يَا رَسُولَ اللَّهِ وَهُمْ بِالْمَدِينَةِ قَالَ وَهُمْ بِالْمَدِينَةِ حَبَسَهُمْ الْعُذْرُ","id":"Telah menceritakan kepada kami [Ahmad bin Muhammad] Telah mengabarkan kepada kami [Abdullah] Telah mengabarkan kepada kami [Humaid Ath Thawil] dari [Anas bin Malik radliallahu 'anhu] bahwa Rasulullah shallallahu 'alaihi wasallam tatkala kembali dari perang Tabuk dan sudah mendekati Madinah, beliau bersabda: \"Sesungguhnya di dalam Madinah itu ada sekelompok kaum, yang tidaklah kalian menempuh perjalanan dan tidaklah kalian menyebrangi lembah kecuali mereka diikutsertakan bersama kalian dalam ganjaran.\" Mereka bertanya; \"Wahai Rasulullah, apakah mereka berada di dalam Madinah? ' Beliau menjawab: \"Mereka di Madinah karena mereka terhalangi oleh udzur\"."},"3785":{"ar":"حَدَّثَنَا إِسْحَاقُ حَدَّثَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا أَبِي عَنْ صَالِحٍ عَنْ ابْنِ شِهَابٍ قَالَ أَخْبَرَنِي عُبَيْدُ اللَّهِ بْنُ عَبْدِ اللَّهِ أَنَّ ابْنَ عَبَّاسٍ أَخْبَرَهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعَثَ بِكِتَابِهِ إِلَى كِسْرَى مَعَ عَبْدِ اللَّهِ بْنِ حُذَافَةَ السَّهْمِيِّ فَأَمَرَهُ أَنْ يَدْفَعَهُ إِلَى عَظِيمِ الْبَحْرَيْنِ فَدَفَعَهُ عَظِيمُ الْبَحْرَيْنِ إِلَى كِسْرَى فَلَمَّا قَرَأَهُ مَزَّقَهُ فَحَسِبْتُ أَنَّ ابْنَ الْمُسَيَّبِ قَالَ فَدَعَا عَلَيْهِمْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يُمَزَّقُوا كُلَّ مُمَزَّقٍ","id":"Telah menceritakan kepada kami [Ishaq] telah menceritakan kepada kami [Ya'qub bin Ibrahim] Telah menceritakan kepada kami [Bapakku] dari [Shalih] dari [Ibnu Syihab] dia berkata [Ubaidullah bin Abdullah] telah mengabarkan kepadaku, bahwa [Ibnu Abbas] telah mengabarkan kepadanya, Sesungguhnya Nabi shallallahu 'alaihi wasallam pernah mengirimkan suratnya kepada Kisra yang diantar oleh Abdullah bin Hudzafah As Sahmi, beliau menyuruhnya agar menyerahkannya kepada pembesar Bahrain, lalu ia menyerahkannya kepada pembesar Bahrain setelah itu dia sampaikan ke Kisra. Setelah membacanya, ia merobeknya. Saya mengira Ibnu Syihab berkata; \"Maka Rasulullah shallallahu 'alaihi wasallam mendo'akan untuk mereka agar mereka dicabik-cabik dengan sehancur-hancurnya.\""},"3786":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ الْهَيْثَمِ حَدَّثَنَا عَوْفٌ عَنْ الْحَسَنِ عَنْ أَبِي بَكْرَةَ قَالَلَقَدْ نَفَعَنِي اللَّهُ بِكَلِمَةٍ سَمِعْتُهَا مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَيَّامَ الْجَمَلِ بَعْدَ مَا كِدْتُ أَنْ أَلْحَقَ بِأَصْحَابِ الْجَمَلِ فَأُقَاتِلَ مَعَهُمْ قَالَ لَمَّا بَلَغَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّ أَهْلَ فَارِسَ قَدْ مَلَّكُوا عَلَيْهِمْ بِنْتَ كِسْرَى قَالَ لَنْ يُفْلِحَ قَوْمٌ وَلَّوْا أَمْرَهُمْ امْرَأَةً","id":"Telah menceritakan kepada kami [Utsman bin Haitsam] Telah menceritakan kepada kami [Auf] dari [Al Hasan] dari [Abu Bakrah] dia berkata; Sungguh Allah telah memberikan manfaat kepadaku dengan suatu kalimat yang pernah aku dengar dari Rasulullah, -yaitu pada waktu perang Jamal tatkala aku hampir bergabung dengan para penunggang unta lalu aku ingin berperang bersama mereka.- Dia berkata; 'Tatkala sampai kepada Rasulullah shallallahu 'alaihi wasallam, bahwa penduduk Persia telah di pimpin oleh seorang anak perempuan putri raja Kisra, beliau bersabda: \"Suatu kaum tidak akan beruntung, jika dipimpin oleh seorang wanita.\""},"3787":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا سُفْيَانُ قَالَ سَمِعْتُ الزُّهْرِيَّ عَنْ السَّائِبِ بْنِ يَزِيدَ يَقُولُأَذْكُرُ أَنِّي خَرَجْتُ مَعَ الْغِلْمَانِ إِلَى ثَنِيَّةِ الْوَدَاعِ نَتَلَقَّى رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَوَقَالَ سُفْيَانُ مَرَّةً مَعَ الصِّبْيَانِ","id":"Telah menceritakan kepada kami [Ali bin Abdullah] Telah menceritakan kepada kami [Sufyan] dia berkata; Aku mendengar [Az Zuhri] dari [As Saaib bin Yazid] berkata; Aku ingat bahwa aku pernah keluar bersama anak-anak ke bukit Wada' untuk menemui Rasulullah shallallahu 'alaihi wasallam. Sufyan berkata di Hadits yang lain dengan lafazh; 'ma'a shibyan.' (bersama anak-anak)."},"3788":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ حَدَّثَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ عَنْ السَّائِبِأَذْكُرُ أَنِّي خَرَجْتُ مَعَ الصِّبْيَانِ نَتَلَقَّى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى ثَنِيَّةِ الْوَدَاعِ مَقْدَمَهُ مِنْ غَزْوَةِ تَبُوكَ","id":"Telah menceritakan kepada kami [Abdullah bin Muhammad] Telah menceritakan kepada kami [Sufyan] dari [Az Zuhri] dari [As Saaib] aku ingat bahwa aku pernah keluar bersama anak-anak menemui Nabi shallallahu 'alaihi wasallam ke bukit wada' setelah beliau pulang dari perang Tabuk."},"3789":{"ar":"حَدَّثَنَا يَحْيَى بْنُ بُكَيْرٍ حَدَّثَنَا اللَّيْثُ عَنْ عُقَيْلٍ عَنْ ابْنِ شِهَابٍ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ عَنْ عَبْدِ اللَّهِ بْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا عَنْ أُمِّ الْفَضْلِ بِنْتِ الْحَارِثِ قَالَتْسَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْرَأُ فِي الْمَغْرِبِ بِالْمُرْسَلَاتِ عُرْفًا ثُمَّ مَا صَلَّى لَنَا بَعْدَهَا حَتَّى قَبَضَهُ اللَّهُ","id":"Telah menceritakan kepada kami [Yahya bin Bukair] Telah menceritakan kepada kami [Al Laits] dari [Uqail] dari [Ibnu Syihab] dari [Ubaidullah bin Abdullah] dari [Abdullah bin Abbas radliallahu 'anhuma] dari [Ummu Fadl binti Al Harits] dia berkata; \"Aku mendengar Nabi shallallahu 'alaihi wasallam pada waktu shalat maghrib membaca surat Al Mursalat. Setelah itu beliau tidak shalat lagi bersama kami hingga beliau wafat.\""},"3790":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَرْعَرَةَ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي بِشْرٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ قَالَكَانَ عُمَرُ بْنُ الْخَطَّابِ رَضِيَ اللَّهُ عَنْهُ يُدْنِي ابْنَ عَبَّاسٍ فَقَالَ لَهُ عَبْدُ الرَّحْمَنِ بْنُ عَوْفٍ إِنَّ لَنَا أَبْنَاءً مِثْلَهُ فَقَالَ إِنَّهُ مِنْ حَيْثُ تَعْلَمُ فَسَأَلَ عُمَرُ ابْنَ عَبَّاسٍ عَنْ هَذِهِ الْآيَةِ{ إِذَا جَاءَ نَصْرُ اللَّهِ وَالْفَتْحُ }فَقَالَ أَجَلُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَعْلَمَهُ إِيَّاهُ فَقَالَ مَا أَعْلَمُ مِنْهَا إِلَّا مَا تَعْلَمُ","id":"Telah menceritakan kepada kami [Muhammad bin Ar'arah] Telah menceritakan kepada kami [Syu'bah] dari [Abu Bisyr] dari [Sa'id bin Jubair] dari [Ibnu Abbas] dia berkata; Umar bin Khaththab radliallahu 'anhu pernah mendekatiku. Maka Abdurrahman bin Auf berkata kepadanya; Sesungguhnya kita juga punya anak-anak sepertinya. Umar menjawab; kamu sendirikan tahu siapakah Ibnu Abbas. Lalu Umar bertanya kepada Ibnu Abbas tentang ayat; \"Apabila pertolongan dan kemenangan Allah telah datang.(QS. Alfath 1-5) \" Ibnu Abbas menjawab; \"Ajal Rasulullah shallallahu 'alaihi wasallam telah memberitahukan kepada beliau bahwa dia telah datang kepadanya.\" Umar berkata; 'Aku tidak tahu tentang ayat itu kecuali apa yang kamu ketahui.'"},"3791":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا سُفْيَانُ عَنْ سُلَيْمَانَ الْأَحْوَلِ عَنْ سَعِيدِ بْنِ جُبَيْرٍ قَالَ قَالَ ابْنُ عَبَّاسٍيَوْمُ الْخَمِيسِ وَمَا يَوْمُ الْخَمِيسِ اشْتَدَّ بِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَجَعُهُ فَقَالَ ائْتُونِي أَكْتُبْ لَكُمْ كِتَابًا لَنْ تَضِلُّوا بَعْدَهُ أَبَدًا فَتَنَازَعُوا وَلَا يَنْبَغِي عِنْدَ نَبِيٍّ تَنَازُعٌ فَقَالُوا مَا شَأْنُهُ أَهَجَرَ اسْتَفْهِمُوهُ فَذَهَبُوا يَرُدُّونَ عَلَيْهِ فَقَالَ دَعُونِي فَالَّذِي أَنَا فِيهِ خَيْرٌ مِمَّا تَدْعُونِي إِلَيْهِ وَأَوْصَاهُمْ بِثَلَاثٍ قَالَ أَخْرِجُوا الْمُشْرِكِينَ مِنْ جَزِيرَةِ الْعَرَبِ وَأَجِيزُوا الْوَفْدَ بِنَحْوِ مَا كُنْتُ أُجِيزُهُمْ وَسَكَتَ عَنْ الثَّالِثَةِ أَوْ قَالَ فَنَسِيتُهَا","id":"Telah menceritakan kepada kami [Qutaibah] Telah menceritakan kepada kami [Sufyan] dari [Sulaiman Al Ahwal] dari [Sa'id bin Jubair] dia berkata; [Ibnu Abbas] berkata; \"Ingatkan kalian hari kamis, dan ingatkan kalian hari kamis itu?\" \"Pada hari tersebut sakit Rasulullah shallallahu 'alaihi wasallam semakin parah, lalu beliau berkata: \"Kemarilah, aku tuliskan untuk kalian sebuah surat, sehingga kalian tidak akan tersesat setelahnya selamanya.\" Namun mereka berselisih, padahal tidak pantas ada yang berselisih di dekat seorang Nabi. Mereka berkata; \"Bagaimana keadaan beliau, apakah beliau mengigau? hendaknya kalian tanyakan kembali kepada beliau.\" lalu mereka pergi dan menyakannya kembali. Maka beliau bersabda: \"Tinggalkan aku, keadaanku sekarang lebih baik dari pada apa yang kalian kira.\" Beliau mewasiatkan tiga hal, beliau bersabda: \"Usirlah orang-orang musyrik dari Jazirah Arab, dan perlakukan utusan sebagaimana saya memperlakukan mereka.\" Tetapi Sa'id tidak menyebutkan wasiat yang ketiga, atau dia mengatakannya namun aku lupa.'"},"3792":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ عُتْبَةَ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَلَمَّا حُضِرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَفِي الْبَيْتِ رِجَالٌ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَلُمُّوا أَكْتُبْ لَكُمْ كِتَابًا لَا تَضِلُّوا بَعْدَهُ فَقَالَ بَعْضُهُمْ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ غَلَبَهُ الْوَجَعُ وَعِنْدَكُ��ْ الْقُرْآنُ حَسْبُنَا كِتَابُ اللَّهِ فَاخْتَلَفَ أَهْلُ الْبَيْتِ وَاخْتَصَمُوا فَمِنْهُمْ مَنْ يَقُولُ قَرِّبُوا يَكْتُبُ لَكُمْ كِتَابًا لَا تَضِلُّوا بَعْدَهُ وَمِنْهُمْ مَنْ يَقُولُ غَيْرَ ذَلِكَ فَلَمَّا أَكْثَرُوا اللَّغْوَ وَالِاخْتِلَافَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قُومُواقَالَ عُبَيْدُ اللَّهِ فَكَانَ يَقُولُ ابْنُ عَبَّاسٍ إِنَّ الرَّزِيَّةَ كُلَّ الرَّزِيَّةِ مَا حَالَ بَيْنَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَبَيْنَ أَنْ يَكْتُبَ لَهُمْ ذَلِكَ الْكِتَابَ لِاخْتِلَافِهِمْ وَلَغَطِهِمْ","id":"Telah menceritakan kepada kami [Ali bin Abdullah] Telah menceritakan kepada kami [Abdurrazaq] Telah mengabarkan kepada kami [Ma'mar] dari [Az Zuhri] dari [Ubaidullah bin Abdullah bin Utbah] dari [Ibnu Abbas radliallahu 'anhuma] dia berkata; Ada beberapa orang lelaki di rumah Rasulullah shallallahu 'alaihi wasallam ketika beliau menjelang ajalnya, beliau bersabda: \"Kemarilah, aku akan menulis sebuah tulisan (pesan) kepada kalian, sehingga kalian tidak akan tersesat setelahnya.\" Sebagian mereka berkata; 'Sesungguhnya rasa sakit telah mempengaruhi Rasulullah shallallahu 'alaihi wasallam dan kalian memiliki Al Qur`an, maka cukuplah Kitabullah bagi kita. Maka orang-orang yang di rumah itu berselisih, dan berdebatlah mereka, di antara mereka ada yang berkata; mendekatlah, Rasulullah shallallahu 'alaihi wasallam akan menuliskan sesuatu kepada kalian. Dan di antara mereka ada yang menolaknya. Maka ketika terjadi banyaknya keributan dan perselisihan, sementara Rasulullah shallallahu 'alaihi wasallam dikerumuni, beliau bersabda: \"Pergilah kalian dariku.\" Ubaidullah berkata; Maka Ibnu Abbas berkata; 'Sungguh ini musibah segala musibah, tidak ada kesempatan bagi Rasulullah shallallahu 'alaihi wasallam dengan menuliskan pesan untuk mereka karena perselisihan dan keributan mereka.'"},"3793":{"ar":"حَدَّثَنَا يَسَرَةُ بْنُ صَفْوَانَ بْنِ جَمِيلٍ اللَّخْمِيُّ حَدَّثَنَا إِبْرَاهِيمُ بْنُ سَعْدٍ عَنْ أَبِيهِ عَنْ عُرْوَةَ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْدَعَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَاطِمَةَ عَلَيْهَا السَّلَام فِي شَكْوَاهُ الَّذِي قُبِضَ فِيهِ فَسَارَّهَا بِشَيْءٍ فَبَكَتْ ثُمَّ دَعَاهَا فَسَارَّهَا بِشَيْءٍ فَضَحِكَتْ فَسَأَلْنَا عَنْ ذَلِكَ فَقَالَتْ سَارَّنِي النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ يُقْبَضُ فِي وَجَعِهِ الَّذِي تُوُفِّيَ فِيهِ فَبَكَيْتُ ثُمَّ سَارَّنِي فَأَخْبَرَنِي أَنِّي أَوَّلُ أَهْلِهِ يَتْبَعُهُ فَضَحِكْتُ","id":"Telah menceritakan kepada kami [Yasarah bin Shafwan bin Jamil Al Lakhmi] Telah menceritakan kepada kami [Ibrahim bin Sa'ad] dari [Bapaknya] dari [Urwah] dari [Aisyah radliallahu 'anha] dia berkata; \"Ketika Rasulullah sakit yang menyebabkan beliau meninggal, beliau memanggil Fathimah. Beliau membisikinya dan ia pun menangis, lalu beliau membisikinya dan ia pun tersenyum. Aisyah berkata; \"Saya bertanya kepada Fathimah; 'Apa yang dibisikkan oleh Rasulullah shalallahu'alaihi wa sallam kepadamu. ia menjawab; \"Beliau berbisik kepadaku dan memberitahuku perihal kematiannya, aku pun menangis. Kemudian beliau berbisik kepadaku dan memberitahuku bahwa saya adalah orang yang pertama kali mengikutinya dari keluarganya maka aku pun tersenyum.\""},"3794":{"ar":"حَدَّثَنِي مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا غُنْدَرٌ حَدَّثَنَا شُعْبَةُ عَنْ سَعْدٍ عَنْ عُرْوَةَ عَنْ عَائِشَةَ قَالَتْكُنْتُ أَسْمَعُ أَنَّهُ لَا يَمُوتُ نَبِيٌّ حَتَّى يُخَيَّرَ بَيْنَ الدُّنْيَا وَالْآخِرَةِ فَسَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ فِي مَرَضِهِ الَّذِي مَاتَ فِيهِ وَأَخَذَتْهُ بُحَّةٌ يَقُولُ{ مَعَ الَّذِينَ أَنْعَمَ اللَّهُ عَلَيْهِمْ }الْآيَةَ فَظَنَنْتُ أَنَّهُ خُيِّرَ","id":"Telah menceritakan kepadaku [Muhammad bin Basyar] Telah menceritakan kepada kami [Gundar] Telah menceritakan kepada kami [Syu'bah] dari [Sa'ad] dari [Urwah] dari [Aisyah] dia berkata; Aku pernah mendengar bahwa seorang nabi tidak akan meninggal hingga dia di suruh memilih antara dunia dan akhirat. Aisyah berkata; Kemudian ketika Nabi shallallahu 'alaihi wasallam sakit yang menyebabkan kematiannya, aku mendengar beliau menuturkan dengan terputus-putus, beliau bersabda: \"Bersama orang-orang yang telah Allah beri nikmat kepada mereka, baik dari para nabi, orang-orang yang jujur, orang-orang yang mati syahid, dan orang-orang yang shalih dan mereka itulah sebaik-baik teman.\" Aisyah berkata; \"Aku mengira pada waktu itulah beliau diberi pilihan.\""},"3795":{"ar":"حَدَّثَنَا مُسْلِمٌ حَدَّثَنَا شُعْبَةُ عَنْ سَعْدٍ عَنْ عُرْوَةَ عَنْ عَائِشَةَ قَالَتْلَمَّا مَرِضَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمَرَضَ الَّذِي مَاتَ فِيهِ جَعَلَ يَقُولُ فِي الرَّفِيقِ الْأَعْلَى","id":"Telah menceritakan kepada kami [Muslim] Telah menceritakan kepada kami [Syu'bah] dari [Sa'ad] dari [Urwah] dari [Aisyah] dia berkata; \"Tatkala beliau sakit yang menyebabkan kematiannya, beliau bersabda: \"Ar Rafiiqul A'laa.\" (Ya Allah, sekarang aku memilih kekasihku yang tertinggi).\""},"3796":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي عُرْوَةُ بْنُ الزُّبَيْرِ إِنَّ عَائِشَةَ قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ صَحِيحٌ يَقُولُ إِنَّهُ لَمْ يُقْبَضْ نَبِيٌّ قَطُّ حَتَّى يَرَى مَقْعَدَهُ مِنْ الْجَنَّةِ ثُمَّ يُحَيَّا أَوْ يُخَيَّرَ فَلَمَّا اشْتَكَى وَحَضَرَهُ الْقَبْضُ وَرَأْسُهُ عَلَى فَخِذِ عَائِشَةَ غُشِيَ عَلَيْهِ فَلَمَّا أَفَاقَ شَخَصَ بَصَرُهُ نَحْوَ سَقْفِ الْبَيْتِ ثُمَّ قَالَ اللَّهُمَّ فِي الرَّفِيقِ الْأَعْلَى فَقُلْتُ إِذًا لَا يُجَاوِرُنَا فَعَرَفْتُ أَنَّهُ حَدِيثُهُ الَّذِي كَانَ يُحَدِّثُنَا وَهُوَ صَحِيحٌ","id":"Telah menceritakan kepada kami [Abul Yaman] Telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhri] dia berkata; Telah mengabarkan kepadaku [Urwah bin Zubair] bahwa [Aisyah] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda ketika beliau masih sehat: \"Tidaklah seorang nabi diambil nyawanya, hingga di perlihatkan terlebih dahulu tempat duduknya di surga. Lalu di suruh memilihnya.\" Tatkala beliau sakit dan ajal menjemputnya, yang pada waktu itu kepala beliau berada di paha Aisyah, beliau pingsan. Setelah beliau sadar, beliau mengalihkan pandangannya ke atap rumah kemudian bersabda: \"Ya Allah, sekarang aku memilih kekasihku yang tertinggi.\" Aku berkata; 'kalau begitu beliau tidak akan bersama kita. Maka aku pun mengerti bahwa ucapanya itu adalah perkataan yang pernah beliau sampaikan kepada kami ketika beliau masih sehat.'"},"3797":{"ar":"حَدَّثَنَا مُحَمَّدٌ حَدَّثَنَا عَفَّانُ عَنْ صَخْرِ بْنِ جُوَيْرِيَةَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْقَاسِمِ عَنْ أَبِيهِ عَنْ عَائِشَةَدَخَلَ عَبْدُ الرَّحْمَنِ بْنُ أَبِي بَكْرٍ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنَا مُسْنِدَتُهُ إِلَى صَدْرِي وَمَعَ عَبْدِ الرَّحْمَنِ سِوَاكٌ رَطْبٌ يَسْتَنُّ بِهِ فَأَبَدَّهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَصَرَهُ فَأَخَذْتُ السِّوَاكَ فَقَصَمْتُهُ وَنَفَضْتُهُ وَطَيَّبْتُهُ ثُمَّ دَفَعْتُهُ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَاسْتَنَّ بِهِ فَمَا رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اسْتَنَّ اسْتِنَانًا قَطُّ أَحْسَنَ مِنْهُ فَمَا عَدَا أَنْ فَرَغَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَفَعَ يَدَهُ أَوْ إِصْبَعَهُ ثُمَّ قَالَ فِي الرَّفِيقِ الْأَعْلَى ثَلَاثًا ثُمَّ قَضَى وَكَانَتْ تَقُولُ مَاتَ بَيْنَ حَاقِنَتِي وَذَاقِنَتِي","id":"Telah menceritakan kepada kami [Muhammad] Telah menceritakan kepada kami [Affan] dari [Shakhr bin Juwairiyah] dari [Abdurrahman bin Al Qasim] dari [Bapaknya] dari [Aisyah] bahwa ketika Rasulullah shallallahu 'alaihi wasallam bersandar di dadaku, Abdurrahman bin Abu Bakr masuk ke rumah sambil membawa kayu siwak yang biasa dia pakai. Rasulullah shallallahu 'alaihi wasallam pun melihat kepadanya. Aku berkata kepadanya; 'Berikan siwak itu kepadaku wahai Abdurrahman! ' Lalu dia memberikannya kepadaku. Kemudian aku bersihkan, dan aku kunyah setelah itu aku berikan kepada Rasulullah shallallahu 'alaihi wasallam. Beliau pun bersiwak dengannya. Aku tidak pernah melihat sebelumnya beliau bersiwak sebaik itu. Setelah selesai, beliau mengangkat tangannya, atau jarinya seraya berkata; 'Arrafiiqul A'laa, Arrafiiqul A'laa (Ya Allah, sekarang aku memilih kekasihku yang tertinggi sekarang aku memilih kekasihku yang tertinggi) sebanyak tiga kali. Lalu beliau wafat. Aisyah berkata; 'Beliau wafat di antara dagu dan tenggorokanku.'"},"3798":{"ar":"حَدَّثَنِي حِبَّانُ أَخْبَرَنَا عَبْدُ اللَّهِ أَخْبَرَنَا يُونُسُ عَنْ ابْنِ شِهَابٍ قَالَ أَخْبَرَنِي عُرْوَةُ أَنَّ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا أَخْبَرَتْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا اشْتَكَى نَفَثَ عَلَى نَفْسِهِ بِالْمُعَوِّذَاتِ وَمَسَحَ عَنْهُ بِيَدِهِ فَلَمَّا اشْتَكَى وَجَعَهُ الَّذِي تُوُفِّيَ فِيهِ طَفِقْتُ أَنْفِثُ عَلَى نَفْسِهِ بِالْمُعَوِّذَاتِ الَّتِي كَانَ يَنْفِثُ وَأَمْسَحُ بِيَدِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْهُ","id":"Telah menceritakan kepadaku [Hibban] Telah mengabarkan kepada kami [Abdullah] Telah mengabarkan kepada kami [Yunus] dari [Ibnu Syihab] dia berkata; Telah mengabarkan kepadaku [Urwah] bahwa [Aisyah radliallahu 'anha] mengabarkan kepadanya; Apabila Rasulullah shallallahu 'alaihi wasallam sakit, beliau tiupkan pada dirinya surat-surat mu'awwidzaat dan beliau usapkan dengan tangannya. Maka tatkala beliau sakit yang menyebabkan beliau meninggal, kutiupkan pula kepadanya surat-surat Mu'awwidzat dan kusapukan tangannya ke tubuhnya."},"3799":{"ar":"حَدَّثَنَا بِشْرُ بْنُ مُحَمَّدٍ حَدَّثَنَا عَبْدُ اللَّهِ قَالَ يُونُسُ قَالَ الزُّهْرِيُّ أَخْبَرَنِي سَعِيدُ بْنُ الْمُسَيَّبِ فِي رِجَالٍ مِنْ أَهْلِ الْعِلْمِ أَنَّ عَائِشَةَ قَالَتْكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ وَهُوَ صَحِيحٌ إِنَّهُ لَمْ يُقْبَضْ نَبِيٌّ حَتَّى يَرَى مَقْعَدَهُ مِنْ الْجَنَّةِ ثُمَّ يُخَيَّرَ فَلَمَّا نَزَلَ بِهِ وَرَأْسُهُ عَلَى فَخِذِي غُشِيَ عَلَيْهِ ثُمَّ أَفَاقَ فَأَشْخَصَ بَصَرَهُ إِلَى سَقْفِ الْبَيْتِ ثُمَّ قَالَ اللَّهُمَّ الرَّفِيقَ الْأَعْلَى فَقُلْتُ إِذًا لَا يَخْتَارُنَا وَعَرَفْتُ أَنَّهُ الْحَدِيثُ الَّذِي كَانَ يُحَدِّثُنَا وَهُوَ صَحِيحٌ قَالَتْ فَكَانَتْ آخِرَ كَلِمَةٍ تَكَلَّمَ بِهَا اللَّهُمَّ الرَّفِيقَ الْأَعْلَى","id":"Telah menceritakan kepada kami [Bisyr bin Muhammad] Telah menceritakan kepada kami [Abdullah], [Yunus] berkata; [Az Zuhri] berkata; Telah mengabarkan kepadaku [Sa'id bin Al Musayyab] -di antara orang-orang yang berilmu-, bahwa [Aisyah] istri Nabi shallallahu 'alaihi wasallam berkata; Ketika Rasulullah shallallahu 'alaihi wasallam berada dalam keadaan sehat wal afiat, beliau pernah bersabda: 'Sesungguhnya seorang nabi tidaklah diwafatkan hingga diperlihatkan kepadanya tempatnya di surga lalu ia dipersilahkan untuk memilih.' Aisyah berkata; \"Ketika malaikat pencabut nyawa datang kepada Rasulullah, sementara kepala beliau berada di pangkuan saya, maka Rasulullah pingsan beberapa saat. Tak lama kemudian ia sadar kembali. Setelah itu, beliau menatap pandangannya ke atas sambil mengucapkan: Ya Allah, pertemukanlah aku dengan kekasihku, Allah Yang Maha Tinggi! ' Aisyah berkata; \"Dengan demikian, Rasulullah shallallahu 'alaihi wasallam tidak memilih untuk hidup Iebih lama lagi bersama kami.\" Aisyah pernah berkata; \"Saya teringat ucapan yang pernah beliau sampaikan kepada kami ketika beliau masih sehat; \"Itulah kata-kata terakhir yang pernah beliau ucapkan, yaitu: 'Ya Allah, pertemukanlah aku dengan kekasihku Yang Maha Tinggi.'"},"3800":{"ar":"حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا شَيْبَانُ عَنْ يَحْيَى عَنْ أَبِي سَلَمَةَ عَنْ عَائِشَةَ وَابْنِ عَبَّاسِ رَضِيَ اللَّهُ عَنْهُمْأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَبِثَ بِمَكَّةَ عَشْرَ سِنِينَ يُنْزَلُ عَلَيْهِ الْقُرْآنُ وَبِالْمَدِينَةِ عَشْرًا","id":"Telah menceritakan kepada kami [Abu Nu'aim] Telah menceritakan kepada kami [Syaiban] dari [Yahya] dari [Abu Salamah] dari ['Aisyah] dan [Ibnu 'Abbas radliallahu 'anhu] bahwa Nabi shallallahu 'alaihi wasallam \"Rasulullah menetap di Makkah selama sepuluh tahun, ketika itu Al Qur'an sudah turun kepadanya. Dan di Madinah selama sepuluh tahun juga."},"3801":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ حَدَّثَنَا اللَّيْ��ُ عَنْ عُقَيْلٍ عَنْ ابْنِ شِهَابٍ عَنْ عُرْوَةَ بْنِ الزُّبَيْرِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تُوُفِّيَ وَهُوَ ابْنُ ثَلَاثٍ وَسِتِّينَقَالَ ابْنُ شِهَابٍ وَأَخْبَرَنِي سَعِيدُ بْنُ الْمُسَيَّبِ مِثْلَهُ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] Telah menceritakan kepada kami [Al Laits] dari ['Uqail] dari [Ibnu Syihab] dari ['Urwah bin Az Zubair] dari ['Aisyah radliallahu 'anhu] bahwa Rasulullah shallallahu 'alaihi wasallam meninggal pada umur enam puluh tiga tahun.' Ibnu Syihab berkata; Dan telah mengabarkan kepadaku [Sa'id bin Al Musayyab] dengan Hadits yang serupa."},"3802":{"ar":"بَاب حَدَّثَنَا قَبِيصَةُ حَدَّثَنَا سُفْيَانُ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ عَنْ الْأَسْوَدِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْتُوُفِّيَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَدِرْعُهُ مَرْهُونَةٌ عِنْدَ يَهُودِيٍّ بِثَلَاثِينَ","id":"Bab telah menceritakan kepada kami [Qabishah] Telah menceritakan kepada kami [Sufyan] dari [Al A'masy] dari [Ibrahim] dari [Al Aswad] dari ['Aisyah radliallahu 'anha] dia berkata; \"Rasulullah shallallahu 'alaihi wasallam wafat, dan beliau meninggalkan baju besinya yang digadaikan kepada orang Yahudi seharga tiga puluh sha.'"},"3803":{"ar":"حَدَّثَنَا أَبُو عَاصِمٍ الضَّحَّاكُ بْنُ مَخْلَدٍ عَنْ الْفُضَيْلِ بْنِ سُلَيْمَانَ حَدَّثَنَا مُوسَى بْنُ عُقْبَةَ عَنْ سَالِمٍ عَنْ أَبِيهِاسْتَعْمَلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أُسَامَةَ فَقَالُوا فِيهِ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ بَلَغَنِي أَنَّكُمْ قُلْتُمْ فِي أُسَامَةَ وَإِنَّهُ أَحَبُّ النَّاسِ إِلَيَّ","id":"Telah menceritakan kepada kami [Abu 'Ashim Adl Dlahak bin Makhlad] dari [Al Fudlail bin Sulaiman] Telah menceritakan kepada kami [Musa bin 'Uqbah] dari [Salim] dari [Bapaknya]; Nabi shallallahu 'alaihi wasallam mengangkat Usamah sebagai komandan pasukan, maka para sahabat pun banyak yang tidak setuju. Lalu beliau bersabda: \"Aku mendengar kalian mengatakan sesuatu yang tidak baik tentang Usamah, sesungguhnya dia adalah orang yang sangat aku cintai.\""},"3804":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ حَدَّثَنَا مَالِكٌ عَنْ عَبْدِ اللَّهِ بْنِ دِينَارٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعَثَ بَعْثًا وَأَمَّرَ عَلَيْهِمْ أُسَامَةَ بْنَ زَيْدٍ فَطَعَنَ النَّاسُ فِي إِمَارَتِهِ فَقَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنْ تَطْعَنُوا فِي إِمَارَتِهِ فَقَدْ كُنْتُمْ تَطْعَنُونَ فِي إِمَارَةِ أَبِيهِ مِنْ قَبْلُ وَايْمُ اللَّهِ إِنْ كَانَ لَخَلِيقًا لِلْإِمَارَةِ وَإِنْ كَانَ لَمِنْ أَحَبِّ النَّاسِ إِلَيَّ وَإِنَّ هَذَا لَمِنْ أَحَبِّ النَّاسِ إِلَيَّ بَعْدَهُ","id":"Telah menceritakan kepada kami [Isma'il] Telah menceritakan kepada kami [Malik] dari ['Abdullah bin Dinar] dari ['Abdullah bin 'Umar radliallahu 'anhu] \"Rasulullah shallallahu 'alaihi wasallam pernah menyiapkan sebuah pasukan perang yang dipimpin oleh Usamah bin Zaid. Lalu para sahabat saling mengecam kepemimpinannya. Maka Rasulullah shallallahu 'alaihi wasallam bangkit seraya bersabda: \"Apabila kalian mengecam kepemimpinan Usamah bin Zaid, maka berarti kalian juga mengecam kepemimpinan ayahnya sebelum itu. Demi Allah, sungguh ia memang layak dengan jabatan itu. Jika bapaknya adalah termasuk orang yang paling aku cintai, maka Usamah juga termasuk dari orang yang paling aku cintai setelahnya.\""},"3805":{"ar":"بَاب حَدَّثَنَا أَصْبَغُ قَالَ أَخْبَرَنِي ابْنُ وَهْبٍ قَالَ أَخْبَرَنِي عَمْرُو بْنُ الْحَارِثِ عَنْ ابْنِ أَبِي حَبِيبٍ عَنْ أَبِي الْخَيْرِ عَنْ الصُّنَابِحِيِّ أَنَّهُ قَالَ لَهُمَتَى هَاجَرْتَ قَالَ خَرَجْنَا مِنْ الْيَمَنِ مُهَاجِرِينَ فَقَدِمْنَا الْجُحْفَةَ فَأَقْبَلَ رَاكِبٌ فَقُلْتُ لَهُ الْخَبَرَ فَقَالَ دَفَنَّا النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُنْذُ خَمْسٍ قُلْتُ هَلْ سَمِعْتَ فِي لَيْلَةِ الْقَدْرِ شَيْئًا قَالَ نَعَمْ أَخْبَرَنِي بِلَالٌ مُؤَذِّنُ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ فِي السَّبْعِ فِي الْعَشْرِ الْأَوَاخِرِ","id":"Bab telah menceritakan kepada kami [Ashbagh] berkata; Telah mengabarkan kepadaku [Ibnu Wahb] berkata; Telah mengabarkan kepadaku ['Amru bin Al Harits] dari [Ibnu Abu Habib] dari [Abu Al Khair] dari [Ash Shunabihi] bahwasanya dia bertanya kepada Ash Shunabihi; \"Kapan kamu berhijrah? Dia menjawab; Kami berhijrah dari Yaman hingga kami sampai di Juhfah. Kemudian kami bertemu dengan seorang pengendara dan aku tanyakan kepadanya tentang kabar Rasulullah shallallahu 'alaihi wasallam. Dia menjawab; \"Kami telah menguburkan jasad Rasulullah shallallahu 'alaihi wasallam sejak lima hari yang lalu. Aku bertanya lagi; 'Apakah kamu mendengar berita tentang lailatul qadar? Dia menjawab; 'Ya, [Bilal] -mu'adzin Rasulullah shallallahu 'alaihi wasallam- mengabarkan kepadaku bahwa itu terjadi pada hari ketujuh dari sepuluh hari terakhir.'"},"3806":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ رَجَاءٍ حَدَّثَنَا إِسْرَائِيلُ عَنْ أَبِي إِسْحَاقَ قَالَ سَأَلْتُ زَيْدَ بْنَ أَرْقَمَ رَضِيَ اللَّهُ عَنْهُكَمْ غَزَوْتَ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ سَبْعَ عَشْرَةَ قُلْتُ كَمْ غَزَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ تِسْعَ عَشْرَةَ","id":"Telah menceritakan kepada kami ['Abdullah bin Raja'] Telah menceritakan kepada kami [Israil] dari [Abu Ishaq] dia berkata; Aku bertanya kepada [Zaid bin Arqam radliallahu 'anhu] berapa kali kamu berperang bersama Rasulullah shallallahu 'alaihi wasallam? Dia menjawab; 'Tujuh belas kali.' Aku bertanya lagi; 'Berapa kali beliau berperang? Dia menjawab; 'Sembilan belas kali.'"},"3807":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ رَجَاءٍ حَدَّثَنَا إِسْرَائِيلُ عَنْ أَبِي إِسْحَاقَ حَدَّثَنَا الْبَرَاءُ رَضِيَ اللَّهُ عَنْهُ قَالَغَزَوْتُ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَمْسَ عَشْرَةَ","id":"Telah menceritakan kepada kami ['Abdullah bin Raja'] Telah menceritakan kepada kami [Israil] dari [Abu Ishaq] Telah menceritakan kepada kami [Al Bara' radliallahu 'anhu] dia berkata; Aku berperang bersama Rasulullah shallallahu 'alaihi wasallam sebanyak lima belas kali.'"},"3808":{"ar":"حَدَّثَنِي أَحْمَدُ بْنُ الحَسَنِ حَدَّثَنَا أَحْمَدُ بْنُ مُحَمَّدِ بْنِ حَنْبَلِ بْنِ هِلَالٍ حَدَّثَنَا مُعْتَمِرُ بْنُ سُلَيْمَانَ عَنْ كَهْمَسٍ عَنْ ابْنِ بُرَيْدَةَ عَنْ أَبِيهِ قَالَغَزَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سِتَّ عَشْرَةَ غَزْوَةً","id":"Telah menceritakan kepadaku [Ahmad bin Al Hasan] Telah menceritakan kepada kami [Ahmad bin Muhammad bin Hanbal bin Hilal] Telah menceritakan kepada kami [Mu'tamir bin Sulaiman] dari [Kahmas] dari [Ibnu Buraidah] dari [Bapaknya] dia berkata; bahwa dia berperang bersama Rasulullah shallallahu 'alaihi wasallam sebanyak enam belas kali peperangan.'"},"3809":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ شُعْبَةَ قَالَ حَدَّثَنِي خُبَيْبُ بْنُ عَبْدِ الرَّحْمَنِ عَنْ حَفْصِ بْنِ عَاصِمٍ عَنْ أَبِي سَعِيدِ بْنِ الْمُعَلَّى قَالَكُنْتُ أُصَلِّي فِي الْمَسْجِدِ فَدَعَانِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمْ أُجِبْهُ فَقُلْتُ يَا رَسُولَ اللَّهِ إِنِّي كُنْتُ أُصَلِّي فَقَالَ أَلَمْ يَقُلْ اللَّهُ{ اسْتَجِيبُوا لِلَّهِ وَلِلرَّسُولِ إِذَا دَعَاكُمْ لِمَا يُحْيِيكُمْ }ثُمَّ قَالَ لِي لَأُعَلِّمَنَّكَ سُورَةً هِيَ أَعْظَمُ السُّوَرِ فِي الْقُرْآنِ قَبْلَ أَنْ تَخْرُجَ مِنْ الْمَسْجِدِ ثُمَّ أَخَذَ بِيَدِي فَلَمَّا أَرَادَ أَنْ يَخْرُجَ قُلْتُ لَهُ أَلَمْ تَقُلْ لَأُعَلِّمَنَّكَ سُورَةً هِيَ أَعْظَمُ سُورَةٍ فِي الْقُرْآنِ قَالَ الْحَمْدُ لِلَّهِ رَبِّ الْعَالَمِينَ هِيَ السَّبْعُ الْمَثَانِي وَالْقُرْآنُ الْعَظِيمُ الَّذِي أُوتِيتُهُ","id":"Telah menceritakan kepada kami [Musaddad] Telah menceritakan kepada kami [Yahya] dari [Syu'bah] dia berkata; Telah menceritakan kepadaku [Khubaib bin 'Abdur Rahman] dari [Hafsh bin 'Ashim] dari [Abu Sa'id bin Al Mu'alla] dia berkata; Suatu saat saya sedang melaksanakan shalat di masjid, tiba-tiba Rasulullah shallallahu 'alaihi wasallam memanggilku namun saya tidak menjawab panggilannya hingga shalatku selesai. Setelah itu, saya menemui beliau dan berkata; \"Wahai Rasulullah shallallahu 'alaihi wasallam, sesungguhnya pada waktu itu saya sedang shalat.\" Beliau bersabda: \"Bukankah Allah 'azza wajalla telah berfirman; 'Hai orang-orang yang beriman, penuhilah seruan Allah dan seruan Rasul apabila Rasul menyeru kamu.'\" Beliau bersabda lagi: \"Sungguh, saya akan mengajarimu tentang surat yang paling agung yang terdapat di dalam Al Qur`an sebelum kamu keluar dari Masjid.\" Kemudian beliau memegang tanganku, dan saat beliau hendak keluar Masjid, saya pun berkata; \"Bukankah engkau berjanji; 'Saya akan mengajarimu surat yang paling agung yang terdapat di dalam Al Qur`an.' Beliau menjawab; (Yaitu surat) AL HAMDU LILLAHI RABBIL 'AALAMIIN (Segala puji bagi Allah, Rabb semesta Alam), ia adalah As Sab'u Al Matsani, dan Al Qur`an Al Azhim yang telah diwahyukan kepadaku."},"3810":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ سُمَيٍّ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا قَالَ الْإِمَامُ{ غَيْرِ الْمَغْضُوبِ عَلَيْهِمْ وَلَا الضَّالِّينَ }فَقُولُوا آمِينَ فَمَنْ وَافَقَ قَوْلُهُ قَوْلَ الْمَلَائِكَةِ غُفِرَ لَهُ مَا تَقَدَّمَ مِنْ ذَنْبِهِ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] Telah mengabarkan kepada kami [Malik] dari [Sumayya] dari [Abu Shalih] dari [Abu Hurairah radliallahu 'anhu] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Bila imam mengucapkan, 'Ghairil maghdluubi 'alaihim walaadl-dlalliin (Bukan orang-orang yang dimurkai dan bukan orang-orang yang sesat) ' maka ucapkanlah, 'Aamiin', Barangsiapa ucapan aamiin-nya bersamaan dengan aamiin para malaikat, maka akan diampuni dosanya yang telah lalu.\""},"3811":{"ar":"حَدَّثَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا هِشَامٌ حَدَّثَنَا قَتَادَةُ عَنْ أَنَسٍ رَضِيَ اللَّهُ عَنْهُ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ح و قَالَ لِي خَلِيفَةُ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ حَدَّثَنَا سَعِيدٌ عَنْ قَتَادَةَ عَنْ أَنَسٍ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يَجْتَمِعُ الْمُؤْمِنُونَ يَوْمَ الْقِيَامَةِ فَيَقُولُونَ لَوْ اسْتَشْفَعْنَا إِلَى رَبِّنَا فَيَأْتُونَ آدَمَ فَيَقُولُونَ أَنْتَ أَبُو النَّاسِ خَلَقَكَ اللَّهُ بِيَدِهِ وَأَسْجَدَ لَكَ مَلَائِكَتَهُ وَعَلَّمَكَ أَسْمَاءَ كُلِّ شَيْءٍ فَاشْفَعْ لَنَا عِنْدَ رَبِّكَ حَتَّى يُرِيحَنَا مِنْ مَكَانِنَا هَذَا فَيَقُولُ لَسْتُ هُنَاكُمْ وَيَذْكُرُ ذَنْبَهُ فَيَسْتَحِي ائْتُوا نُوحًا فَإِنَّهُ أَوَّلُ رَسُولٍ بَعَثَهُ اللَّهُ إِلَى أَهْلِ الْأَرْضِ فَيَأْتُونَهُ فَيَقُولُ لَسْتُ هُنَاكُمْ وَيَذْكُرُ سُؤَالَهُ رَبَّهُ مَا لَيْسَ لَهُ بِهِ عِلْمٌ فَيَسْتَحِي فَيَقُولُ ائْتُوا خَلِيلَ الرَّحْمَنِ فَيَأْتُونَهُ فَيَقُولُ لَسْتُ هُنَاكُمْ ائْتُوا مُوسَى عَبْدًا كَلَّمَهُ اللَّهُ وَأَعْطَاهُ التَّوْرَاةَ فَيَأْتُونَهُ فَيَقُولُ لَسْتُ هُنَاكُمْ وَيَذْكُرُ قَتْلَ النَّفْسِ بِغَيْرِ نَفْسٍ فَيَسْتَحِي مِنْ رَبِّهِ فَيَقُولُ ائْتُوا عِيسَى عَبْدَ اللَّهِ وَرَسُولَهُ وَكَلِمَةَ اللَّهِ وَرُوحَهُ فَيَقُولُ لَسْتُ هُنَاكُمْ ائْتُوا مُحَمَّدًا صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَبْدًا غَفَرَ اللَّهُ لَهُ مَا تَقَدَّمَ مِنْ ذَنْبِهِ وَمَا تَأَخَّرَ فَيَأْتُونِي فَأَنْطَلِقُ حَتَّى أَسْتَأْذِنَ عَلَى رَبِّي فَيُؤْذَنَ لِي فَإِذَا رَأَيْتُ رَبِّي وَقَعْتُ سَاجِدًا فَيَدَعُنِي مَا شَاءَ اللَّهُ ثُمَّ يُقَالُ ارْفَعْ رَأْسَكَ وَسَلْ تُعْطَهْ وَقُلْ يُسْمَعْ وَاشْفَعْ تُشَفَّعْ فَأَرْفَعُ رَأْسِي فَأَحْمَدُهُ بِتَحْمِيدٍ يُعَلِّمُنِيهِ ثُمَّ أَشْفَعُ فَيَحُدُّ لِي حَدًّا فَأُدْخِلُهُمْ الْجَنَّةَ ثُمَّ أَعُودُ إِلَيْهِ فَإِذَا رَأَيْتُ رَبِّي مِثْلَهُ ثُمَّ أَشْفَعُ فَيَحُدُّ لِي حَدًّا فَأُدْخِلُهُمْ الْجَنَّةَ ثُمَّ أَعُودُ الرَّابِعَةَ فَأَقُولُ مَا بَقِيَ فِي النَّارِ إِلَّا مَنْ حَبَسَهُ الْقُرْآنُ وَوَجَبَ عَلَيْهِ الْخُلُودُقَالَ أَبُو عَبْد اللَّهِ إِلَّا مَنْ حَبَسَهُ الْقُرْآنُ يَعْنِي قَوْلَ اللَّهِ تَعَالَى{ خَالِدِينَ فِيهَا }","id":"Telah menceritakan kepada kami [Muslim bin Ibrahim] Telah menceritakan kepada kami [Hisyam] Telah menceritakan kepada kami [Qatadah] dari [Anas radliallahu 'anhu] dari Nabi shallallahu 'alaihi wasallam Demikian juga diriwayatkan dari jalur lainnya, dan [Khalifah] berkata kepadaku Telah menceritakan kepada kami [Yazid bin Zura'i] Telah menceritakan kepada kami [Sa'id] dari [Qatadah] dari [Anas radliallahu 'anhu] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Pada hari kiamat orang-orang yang beriman berkumpul lalu mereka berkata; 'Sebaiknya kita meminta syafa'at kepada Rabb kita 'azza wajalla sehingga kita dapat pindah dari tempat kita sekarang juga.' Lalu mereka mendatangi Adam 'Alaihis Salam seraya mengatakan; 'Wahai Adam, engkau adalah bapaknya manusia, Allah menciptakanmu dengan tangan-Nya sendiri dan menjadikan malaikat-malaikat-Nya sujud kepadamu, serta diajarkan pula kepadamu nama-nama segala sesuatu, maka mintakanlah syafa'at kepada Rabb kami 'azza wajalla agar Dia memindahkan kami dari tempat kami ini! ' Maka Adam berkata; 'Bukan aku yang kalian maksud, ' kemudian Adam menyebutkan dosa yang pernah ia lakukan, hingga dosa tersebut membuatnya malu kepada Allah, lalu Adam berkata; 'Datanglah kalian kepada Nuh 'Alaihis Salam karena ia adalah rasul pertama kali yang Allah utus ke muka bumi, ' kemudian mereka pun mendatangi Nuh 'Alaihis Salam, lalu Nuh berkata; 'Bukan aku yang kalian maksud, ' lalu ia menyebutkan kesalahan dan permintaannya kepada Rabbnya dengan tanpa ilmu, hingga membuatnya malu kepada Rabbnya; 'akan tetapi datangilah Ibrahim 'Alaihis Salam kekasih Ar Rahman 'azza wajalla, ' maka mereka pun mendatanginya, lalu Ibrahim mengatakan; 'Bukan aku yang kalian maksud, tapi datanglah kalian kepada Musa 'Alaihis Salam, seorang hamba yang Allah ajak bicara secara langsung dan diberikan Taurat.' Maka mereka pun mendatangi Musa, dan Musa juga berkata; 'Bukan aku yang kalian maksud, ' seraya menyebutkan seseorang yang dia bunuh tanpa alasan yang benar, hingga hal itu membuatnya malu kepada Rabbnya; 'akan tetapi datanglah kalian kepada Isa 'Alaihis Salam, hamba Allah dan Rasul-Nya, kalimat serta ruh-Nya.' Maka mereka pun mendatangi Isa, kemudian Isa mengatakan; 'Bukan aku yang kalian maksud, akan tetapi datanglah kalian kepada Muhammad, seorang hamba yang dosanya telah diampuni Allah, baik yang lalu atau yang akan datang.' Maka mereka pun mendatangiku, maka aku pun pergi sehingga aku meminta izin kepada Rabbku 'azza wajalla, lalu aku pun diizinkan. Maka ketika aku melihat Rabbku, aku langsung jatuh sujud kepada Rabbku 'azza wajalla, kemudian Dia membiarkanku bersujud sekehendak-Nya. Setelah itu dikatakan; 'Bangunlah ya Muhammad! memintalah maka engkau akan diberikan! berkatalah maka engkau akan didengarkan! dan mintalah syafa'at maka engkau akan diberi (hak memberi syafa'at).\" Maka aku mengangkat kepalaku dan memuji-Nya dengan pujian yang Dia ajarkan kepadaku, kemudian aku memberikan syafa'at dan Dia memberikan aku batasan, lalu aku memasukkan orang-orang ke dalam surga. Kemudian aku kembali kepada Rabbku 'azza wajalla untuk yang kedua kalinya, dan ketika aku melihat Rabbku aku langsung jatuh sujud kepada Rabbku, kemudian Dia membiarkanku bersujud sekehendak-Nya. Kemudian dikatakan; 'Bangunlah ya Muhammad! berkatalah maka engkau akan didengarkan! memintalah maka engkau akan diberikan! dan mintalah syafa'at maka engkau akan diberi (hak memberi syafa'at).\" Maka aku mengangkat kepalaku dan memuji-Nya dengan pujian yang Dia ajarkan kepadaku, kemudian aku memberikan syafa'at dan Dia memberikan aku batasan, lalu aku memasukkan orang-orang ke dalam surga.\" Kemudian aku kembali kepada Rabbku 'azza wajalla untuk yang ketiga kalinya, dan ketika aku melihat Rabbku aku langsung tersungkur bersujud kepada Rabbku, kemudian Dia membiarkanku bersujud sekehendak-Nya. Kemudian dikatakan; 'Bangunlah ya Muhammad! berkatalah maka engkau akan didengarkan! memintalah maka engkau akan diberikan! dan mintalah syafa'at maka engkau akan diberi (hak memberi syafa'at).' Maka aku mengangkat kepalaku dan memuji-Nya dengan pujian yang Dia ajarkan kepadaku, kemudian aku memberikan syafa'at dan Dia memberikan aku batasan, lalu aku memasukkan orang-orang ke dalam surga.\" Kemudian aku kembali kepada Rabbku 'azza wajalla untuk yang keempat kalinya, lalu aku berkata: 'Wahai Rabb, tidak ada yang tersisa kecuali orang yang terhalang oleh Al Qur`an dan wajib kekal di neraka.'"},"3812":{"ar":"حَدَّثَنِي عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا جَرِيرٌ عَنْ مَنْصُورٍ عَنْ أَبِي وَائِلٍ عَنْ عَمْرِو بْنِ شُرَحْبِيلَ عَنْ عَبْدِ اللَّهِ قَالَسَأَلْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَيُّ الذَّنْبِ أَعْظَمُ عِنْدَ اللَّهِ قَالَ أَنْ تَجْعَلَ لِلَّهِ نِدًّا وَهُوَ خَلَقَكَ قُلْتُ إِنَّ ذَلِكَ لَعَظِيمٌ قُلْتُ ثُمَّ أَيُّ قَالَ وَأَنْ تَقْتُلَ وَلَدَكَ تَخَافُ أَنْ يَطْعَمَ مَعَكَ قُلْتُ ثُمَّ أَيُّ قَالَ أَنْ تُزَانِيَ حَلِيلَةَ جَارِكَ","id":"Telah menceritakan kepadaku ['Utsman bin Abu Syaibah] Telah menceritakan kepada kami [Jarir] dari [Manshur] dari [Abu Wail] dari ['Amru bin Syurahbil] dari ['Abdullah] dia berkata; Aku bertanya kepada Nabi shallallahu 'alaihi wasallam; 'Dosa apakah yang paling besar di sisi Allah? Beliau menjawab; 'Bila kamu menyekutukan Allah, padahal dialah yang menciptakanmu. Aku berkata; tentu itu sungguh besar.' Aku bertanya lagi; 'Kemudian apa? Beliau menjawab; 'Apabila kami membunuh anakmu karena takut membuat kelaparan.' Aku bertanya lagi; 'kemudian apa? ' beliau menjawab; 'Berzina dengan istri tetanggamu.'"},"3813":{"ar":"حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا سُفْيَانُ عَنْ عَبْدِ الْمَلِكِ عَنْ عَمْرِو بْنِ حُرَيْثٍ عَنْ سَعِيدِ بْنِ زَيْدٍ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْكَمْأَةُ مِنْ الْمَنِّ وَمَاؤُهَا شِفَاءٌ لِلْعَيْنِ","id":"Telah menceritakan kepada kami [Abu Nu'aim] Telah menceritakan kepada kami [Sufyan] dari ['Abdul Malik] dari ['Amru bin Huraits] dari [Sa'id bin Zaid radliallahu 'anhu] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Al Kam-at (cendawan) adalah sejenis manna (sejenis makanan yang diturunkan Allah Ta'ala kepada Bani Israil), airnya mengandung obat bagi penyakit mata.\""},"3814":{"ar":"حَدَّثَنِي مُحَمَّدٌ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ عَنْ ابْنِ الْمُبَارَكِ عَنْ مَعْمَرٍ عَنْ هَمَّامِ بْنِ مُنَبِّهٍ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ قِيلَ لِبَنِي إِسْرَائِيلَ{ ادْخُلُوا الْبَابَ سُجَّدًا وَقُولُوا حِطَّةٌ }فَدَخَلُوا يَزْحَفُونَ عَلَى أَسْتَاهِهِمْ فَبَدَّلُوا وَقَالُوا حِطَّةٌ حَبَّةٌ فِي شَعَرَةٍ","id":"Telah menceritakan kepadaku [Muhammad] Telah menceritakan kepada kami ['Abdur Rahman bin Mahdi] dari [Ibnu Al Mubarak] dari [Ma'mar] dari [Hammam bin Munabbih] dari [Abu Hurairah radliallahu 'anhu] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Dikatakan kepada Bani Israil: 'Masuklah kalian pintu itu dengan keadaan sujud dan Katakanlah: 'Hitthah' (ampunilah dosa-dosa) niscaya Dia mengampuni kesalahan-kesalahan kalian. Lalu mereka memasuki pintu itu dan mengganti apa yang telah diperintahkan kepada mereka seraya merangkak di atas pantat-pantat mereka dan mereka berkata: 'Hiththah adalah Habbah (biji) dalam tepung.\""},"3815":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُنِيرٍ سَمِعَ عَبْدَ اللَّهِ بْنَ بَكْرٍ حَدَّثَنَا حُمَيْدٌ عَنْ أَنَسٍ قَالَسَمِعَ عَبْدُ اللَّهِ بْنُ سَلَامٍ بِقُدُومِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهْوَ فِي أَرْضٍ يَخْتَرِفُ فَأَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنِّي سَائِلُكَ عَنْ ثَلَاثٍ لَا يَعْلَمُهُنَّ إِلَّا نَبِيٌّ فَمَا أَوَّلُ أَشْرَاطِ السَّاعَةِ وَمَا أَوَّلُ طَعَامِ أَهْلِ الْجَنَّةِ وَمَا يَنْزِعُ الْوَلَدُ إِلَى أَبِيهِ أَوْ إِلَى أُمِّهِ قَالَ أَخْبَرَنِي بِهِنَّ جِبْرِيلُ آنِفًا قَالَ جِبْرِيلُ قَالَ نَعَمْ قَالَ ذَاكَ عَدُوُّ الْيَهُودِ مِنْ الْمَلَائِكَةِ فَقَرَأَ هَذِهِ الْآيَةَ{ مَنْ كَانَ عَدُوًّا لِجِبْرِيلَ فَإِنَّهُ نَزَّلَهُ عَلَى قَلْبِكَ بِإِذْنِ اللَّهِ }أَمَّا أَوَّلُ أَشْرَاطِ السَّاعَةِ فَنَارٌ تَحْشُرُ النَّاسَ مِنْ الْمَشْرِقِ إِلَى الْمَغْرِبِ وَأَمَّا أَوَّلُ طَعَامٍ يَأْكُلُهُ أَهْلُ الْجَنَّةِ فَزِيَادَةُ كَبِدِ حُوتٍ وَإِذَا سَبَقَ مَاءُ الرَّجُلِ مَاءَ الْمَرْأَةِ نَزَعَ الْوَلَدَ وَإِذَا سَبَقَ مَاءُ الْمَرْأَةِ نَزَعَتْ قَالَ أَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَأَشْهَدُ أَنَّكَ رَسُولُ اللَّهِ يَا رَسُولَ اللَّهِ إِنَّ الْيَهُودَ قَوْمٌ بُهُتٌ وَإِنَّهُمْ إِنْ يَعْلَمُوا بِإِسْلَامِي قَبْلَ أَنْ تَسْأَلَهُمْ يَبْهَتُونِي فَجَاءَتْ الْيَهُودُ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَيُّ رَجُلٍ عَبْدُ اللَّهِ فِيكُمْ قَالُوا خَيْرُنَا وَابْنُ خَيْرِنَا وَسَيِّدُنَا وَابْنُ سَيِّدِنَا قَالَ أَرَأَيْتُمْ إِنْ أَسْلَمَ عَبْدُ اللَّهِ بْنُ سَلَامٍ فَقَالُوا أَعَاذَهُ اللَّهُ مِنْ ذَلِكَ فَخَرَجَ عَبْدُ اللَّهِ فَقَالَ أَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَأَنَّ مُحَمَّدًا رَسُولُ اللَّهِ فَقَالُوا شَرُّنَا وَابْنُ شَرِّنَا وَانْتَقَصُوهُ قَالَ فَهَذَا الَّذِي كُنْتُ أَخَافُ يَا رَسُولَ اللَّهِ","id":"Telah menceritakan kepada kami ['Abdullah bin Munir] dia mendengar ['Abdullah bin Bakr] Telah menceritakan kepada kami [Humaid] dari [Anas] dia berkata; 'Abdullah bin Salam mendengar kedatangan Rasulullah Shallallahu 'Alaihi. Maka ia langsung menemui Nabi shallallahu 'alaihi wasallam seraya berkata; \"Wahai Rasulullah, aku bertanya kepadamu tentang tiga perkara tidak akan ada yang dapat menjawab kecuali seorang Nabi, Apakah yang terjadi pertama kali dari tanda-tanda hari kiamat, apa yang pertama kali dimakan oleh penduduk surga, dan dari mana seseorang dapat menyerupai bapaknya atau ibunya?\" Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jibril 'Alaihis Salam baru saja memberiku kabar.\" Abdullah bertanya; siapakah Jibril? Beliau menjawab: \"Ia adalah malaikat yang sangat dimusuhi yahudi.\" Beliau bersabda: \"Tanda hari kiamat yang akan terjadi pertama kali adalah api yang keluar dari timur yang akan menggiring manusia ke barat, adapun sesuatu yang pertama kali dimakan penduduk surga adalah hati ikan hiu, adapun darimana seseorang dapat menyerupai bapak atau ibunya adalah apabila air mani laki-laki dapat mendahului sel telur wanita maka akan keluar laki-laki, dan apabila sel telur wanita dapat mendahului air mani laki-laki maka akan keluar wanita.\" Kemudian Abdullah bin Salam berkata; \"Aku bersaksi bahwa tidak ada Tuhan yang berhak untuk disembah kecuali Allah dan aku bersaksi bahwa engkau adalah Rasulullah.\" Kemudian dia berkata lagi; \"Wahai Rasulullah, sesungguhnya orang yahudi itu adalah kaum yang pendusta, kalau mereka mengetahui keIslamanku mereka pasti akan menghinaku dihadapanmu. Maka utuslah seseorang agar memanggil mereka dan tanyakan kepada mereka tentang aku.\" Beliau lalu mengutus seseorang untuk memanggil mereka, lalu beliau bertanya kepada mereka: \"Siapakah Abdullah bin Salam di menurut kalian?\" Mereka menjawab; \"Dia adalah orang terbaik kami dan anak dari orang terbaik dari kami, dia adalah tuan kami dan anak dari tuan kami.\" Beliau bertanya lagi: \"Bagaimana menurut kalian, kalau seandainya dia masuk Islam? Mereka menjawab; \"Mudah-mudahan Allah melindunginya dari hal itu (masuk Islam).\" Maka Abdullah bin Salam keluar seraya mengatakan; \"Aku bersaksi bahwa tidak ada tuhan yang berhak untuk disembah kecuali Allah, dan aku bersaksi bahwa Muhammad adalah utusan Allah.\" Lalu mereka berkata; \"Dia adalah orang yang paling jelek di antara kami dan anak dari orang yang paling jelek di antara kami. -Mereka menjelek-jelekkan Abdullah bin Salam.- Setelah itu Abdullah bin Salam berkata; \"Inilah yang paling aku khawatirkan.\""},"3816":{"ar":"حَدَّثَنَا عَمْرُو بْنُ عَلِيٍّ حَدَّثَنَا يَحْيَى حَدَّثَنَا سُفْيَانُ عَنْ حَبِيبٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ قَالَ قَالَ عُمَرُ رَضِيَ اللَّهُ عَنْهُأَقْرَؤُنَا أُبَيٌّ وَأَقْضَانَا عَلِيٌّ وَإِنَّا لَنَدَعُ مِنْ قَوْلِ أُبَيٍّ وَذَاكَ أَنَّ أُبَيًّا يَقُولُ لَا أَدَعُ شَيْئًا سَمِعْتُهُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَدْ قَالَ اللَّهُ تَعَالَى{ مَا نَنْسَخْ مِنْ آيَةٍ أَوْ نُنْسِهَا }","id":"Telah menceritakan kepada kami ['Amru bin 'Ali] Telah menceritakan kepada kami [Yahya] Telah menceritakan kepada kami [Sufyan] dari [Habib] dari [Sa'id bin Jubair] dari [Ibnu 'Abbas] dia berkata; ['Umar radliallahu 'anhu] berkata; \"Ubay adalah orang yang paling pandai dalam membaca Al Qur'an di antara kami, dan Ali adalah orang yang paling paham dengan hukum di antara kami. Sementara kami banyak meninggalkan qira`ah Ubay (dalam membaca Al Qur'an). Karena [Ubay] pernah berkata, \"Aku tidak akan meninggalkan sesuatu yang telah aku dengar dari Rasulullah. Sementara Allah Tabaraka Wa Ta'ala berfirman: '(Ayat mana saja yang kami nasakhkan, atau kami jadikan (manusia) lupa kepadanya, kami datangkan yang lebih baik daripadanya atau yang sebanding dengannya) ' (QS. Al Baqarah: 106)."},"3817":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي حُسَيْنٍ حَدَّثَنَا نَافِعُ بْنُ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَاعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ قَالَ اللَّهُ كَذَّبَنِي ابْنُ آدَمَ وَلَمْ يَكُنْ لَهُ ذَلِكَ وَشَتَمَنِي وَلَمْ يَكُنْ لَهُ ذَلِكَ فَأَمَّا تَكْذِيبُهُ إِيَّايَ فَزَعَمَ أَنِّي لَا أَقْدِرُ أَنْ أُعِيدَهُ كَمَا كَانَ وَأَمَّا شَتْمُهُ إِيَّايَ فَقَوْلُهُ لِي وَلَدٌ فَسُبْحَانِي أَنْ أَتَّخِذَ صَاحِبَةً أَوْ وَلَدًا","id":"Telah menceritakan kepada kami [Abu Al Yaman] Telah mengabarkan kepada kami [Syu'aib] dari ['Abdullah bin Abu Husain] Telah menceritakan kepada kami [Nafi' bin Jubair] dari [Ibnu 'Abbas radliallahu 'anhuma] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: Allah Ta'ala berfirman: Sebagian keturunan Adam telah mengatakan kebohongan tentang Aku padahal mereka sama sekali tidak berhak melakukan demikian. Dan mereka mencelaku, padahal mereka tidak punya hak untuk mencelaku. Kebohongan yang mereka perbuat tentang-Ku adalah mereka menganggap Aku tidak mampu menciptakan kembali sebagaimana dulu telah ciptakan. Adapun celaannya kepada-Ku, yaitu mereka mengatakan bahwa Aku mempunyai anak. Maha Suci Aku, sama sekali Aku tidak mengambil istri dan tidak mempunyai anak.'"},"3818":{"ar":"حَدَّثَنَا مُسَدَّدٌ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ حُمَيْدٍ عَنْ أَنَسٍ قَالَ قَالَ عُمَرُوَافَقْتُ اللَّهَ فِي ثَلَاثٍ أَوْ وَافَقَنِي رَبِّي فِي ثَلَاثٍ قُلْتُ يَا رَسُولَ اللَّهِ لَوْ اتَّخَذْتَ مَقَامَ إِبْرَاهِيمَ مُصَلًّى وَقُلْتُ يَا رَسُولَ اللَّهِ يَدْخُلُ عَلَيْكَ الْبَرُّ وَالْفَاجِرُ فَلَوْ أَمَرْتَ أُمَّهَاتِ الْمُؤْمِنِينَ بِالْحِجَابِ فَأَنْزَلَ اللَّهُ آيَةَ الْحِجَابِ قَالَ وَبَلَغَنِي مُعَاتَبَةُ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعْضَ نِسَائِهِ فَدَخَلْتُ عَلَيْهِنَّ قُلْتُ إِنْ انْتَهَيْتُنَّ أَوْ لَيُبَدِّلَنَّ اللَّهُ رَسُولَهُ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَيْرًا مِنْكُنَّ حَتَّى أَتَيْتُ إِحْدَى نِسَائِهِ قَالَتْ يَا عُمَرُ أَمَا فِي رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا يَعِظُ نِسَاءَهُ حَتَّى تَعِظَهُنَّ أَنْتَ فَأَنْزَلَ اللَّهُ{ عَسَى رَبُّهُ إِنْ طَلَّقَكُنَّ أَنْ يُبَدِّلَهُ أَزْوَاجًا خَيْرًا مِنْكُنَّ مُسْلِمَاتٍ }الْآيَةَوَقَالَ ابْنُ أَبِي مَرْيَمَ أَخْبَرَنَا يَحْيَى بْنُ أَيُّوبَ حَدَّثَنِي حُمَيْدٌ سَمِعْتُ أَنَسًا عَنْ عُمَرَ","id":"Telah menceritakan kepada kami [Musaddad] dari [Yahya bin Sa'id] dari [Humaid] dari [Anas] dia berkata; ['Umar] berkata; Aku telah menepati Rabbku dalam tiga hal, atau Rabbku telah menyetujuiku dalam tiga hal. Aku berkata; \"Wahai Rasulullah seandainya engkau menjadikan Maqam Ibrahim sebagai tempat shalat.\" Aku berkata; \"Wahai Rasulullah, sesungguhnya yang menemuimu adalah orang-orang yang baik dan yang jahat, seandainya engkau perintahkan kepada para Ummul Mukminin supaya memakai hijab.\" maka turunlah ayat hijab. Dan suatu ketika aku mendengar Rasulullah shallallahu 'alaihi wasallam mempersalahkan sebagian istri-istrinya, maka akupun mengunjungi mereka dan berkata; \"Berhentilah kalian dari berbuat masalah dengan Nabi atau boleh jadi Allah akan memberi ganti kepadanya dengan isteri yang lebih baik dari pada kalian.\" Ketika aku menemui salah seorang istrinya, ia berkata kepadaku; wahai Umar! Bukankah Rasulullah shallallahu 'alaihi wasallam lebih berhak menasihati istri-istrinya daripada kamu? Maka turunlah ayat; \"Boleh jadi jika ia ceraikan kamu, Tuhannya akan memberinya ganti istri-istri yang lebih baik dari pada kamu -perempuan yang berserah diri.- (QS At Tahrim: 5).\" Dan [Ibnu Abu Maryam] berkata; Telah mengabarkan kepada kami [Yahya bin Ayub] Telah menceritakan kepadaku [Humaid] Aku mendengar [Anas] dari [Umar]."},"3819":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ قَالَ حَدَّثَنِي مَالِكٌ عَنْ ابْنِ شِهَابٍ عَنْ سَالِمِ بْنِ عَبْدِ اللَّهِ أَنَّ عَبْدَ اللَّهِ بْنَ مُحَمَّدِ بْنِ أَبِي بَكْرٍ أَخْبَرَ عَبْدَ اللَّهِ بْنَ عُمَرَ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَلَمْ تَرَيْ أَنْ قَوْمَكِ بَنَوْا الْكَعْبَةَ وَاقْتَصَرُوا عَنْ قَوَاعِدِ إِبْرَاهِيمَ فَقُلْتُ يَا رَسُولَ اللَّهِ أَلَا تَرُدُّهَا عَلَى قَوَاعِدِ إِبْرَاهِيمَ قَالَ لَوْلَا حِدْثَانُ قَوْمِكِ بِالْكُفْرِفَقَالَ عَبْدُ اللَّهِ بْنُ عُمَرَ لَئِنْ كَانَتْ عَائِشَةُ سَمِعَتْ هَذَا مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا أُرَى رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَرَكَ اسْتِلَامَ الرُّكْنَيْنِ اللَّذَيْنِ يَلِيَانِ الْحِجْرَ إِلَّا أَنَّ الْبَيْتَ لَمْ يُتَمَّمْ عَلَى قَوَاعِدِ إِبْرَاهِيمَ","id":"Telah menceritakan kepada kami [Isma'il] berkata; Telah menceritakan kepadaku [Malik] dari [Ibnu Syihab] dari [Salim bin 'Abdullah] bahwa ['Abdullah bin Muhammad bin Abu Bakr]; Telah mengabarkan kepada kami ['Abdullah bin 'Umar] dari ['Aisyah radliallahu 'anhu] isteri Nabi shallallahu 'alaihi wasallam bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Bukankah engkau melihat bahwa kaummu ketika membangun Ka'bah mengurangi pondasi-pondasi Ibrahim 'Alaihissalam?\" Maka saya katakan; wahai Rasulullah shallallahu 'alaihi wasallam, tidakkah engkau kembalikan ke pondasi-pondasi Ibrahim 'alaihissalam? Beliau menjawab: \"Kalaulah tidak karena kaummu dekat dengan masa kekafiran.\" Abdullah bin Umar berkata; seandainya Aisyah telah mendengar hal ini dari Rasulullah shallallahu 'alaihi wasallam tentu saya tidak akan melihat Rasulullah shallallahu 'alaihi wasallam meninggalkan dari menyentuh dua rukun yang terletak setelah Hijr, hanya saja Ka'bah belum disempurnakan di atas pondasi-pondasi Ibrahim 'alaihissalam ketika itu."},"3820":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا عُثْمَانُ بْنُ عُمَرَ أَخْبَرَنَا عَلِيُّ بْنُ الْمُبَارَكِ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَكَانَ أَهْلُ الْكِتَابِ يَقْرَءُونَ التَّوْرَاةَ بِالْعِبْرَانِيَّةِ وَيُفَسِّرُونَهَا بِالْعَرَبِيَّةِ لِأَهْلِ الْإِسْلَامِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تُصَدِّقُوا أَهْلَ الْكِتَابِ وَلَا تُكَذِّبُوهُمْ وَقُولُوا{ آمَنَّا بِاللَّهِ وَمَا أُنْزِلَ إِلَيْنَا }الْآيَةَ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] Telah menceritakan kepada kami ['Utsman bin 'Umar] Telah mengabarkan kepada kami ['Ali Al Mubarak] dari [Yahya bin Abu Katsir] dari [Abu Salamah] dari [Abu Hurairah radliallahu 'anhu] berkata; \"Orang-orang ahlu kitab membaca Taurat dengan bahasa Ibrani dan menjelaskannya kepada orang-orang Islam dengan bahasa arab. Melihat hal itu Rasulullah shallallahu 'alaihi wasallam bersabda: Janganlah kalian mempercayai ahlu kitab dan jangan pula mendustakannya. Tetapi ucapkanlah; \"Kami beriman kepada Allah dan kepada apa yang telah diturunkan kepada kami. (Al Baqarah; 136).'"},"3821":{"ar":"حَدَّثَنَا أَبُو نُعَيْمٍ سَمِعَ زُهَيْرًا عَنْ أَبِي إِسْحَاقَ عَنْ الْبَرَاءِ رَضِيَ اللَّهُ عَنْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى إِلَى بَيْتِ الْمَقْدِسِ سِتَّةَ عَشَرَ شَهْرًا أَوْ سَبْعَةَ عَشَرَ شَهْرًا وَكَانَ يُعْجِبُهُ أَنْ تَكُونَ قِبْلَتُهُ قِبَلَ الْبَيْتِ وَأَنَّهُ صَلَّى أَوْ صَلَّاهَا صَلَاةَ الْعَصْرِ وَصَلَّى مَعَهُ قَوْمٌ فَخَرَجَ رَجُلٌ مِمَّنْ كَانَ صَلَّى مَعَهُ فَمَرَّ عَلَى أَهْلِ الْمَسْجِدِ وَهُمْ رَاكِعُونَ قَالَ أَشْهَدُ بِاللَّهِ لَقَدْ صَلَّيْتُ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قِبَلَ مَكَّةَ فَدَارُوا كَمَا هُمْ قِبَلَ الْبَيْتِ وَكَانَ الَّذِي مَاتَ عَلَى الْقِبْلَةِ قَبْلَ أَنْ تُحَوَّلَ قِبَلَ الْبَيْتِ رِجَالٌ قُتِلُوا لَمْ نَدْرِ مَا نَقُولُ فِيهِمْ فَأَنْزَلَ اللَّهُ{ وَمَا كَانَ اللَّهُ لِيُضِيعَ إِيمَانَكُمْ إِنَّ اللَّهَ بِالنَّاسِ لَرَءُوفٌ رَحِيمٌ }","id":"Telah menceritakan kepada kami [Abu Nu'aim] dia mendengar dari [Zuhair] dari [Abu Ishaq] dari [Al Bara' radliallahu 'anhu] bahwa Rasulullah shallallahu 'alaihi wasallam shalat dengan menghadap ke baitul Maqdis selama enam belas atau tujuh belas bulan. Dan beliau menyukai jika kiblatnya menghadap ke arah ka'bah. Kemudian beliau pun shalat Ashar bersama sekelompok para sahabat dengan menghadap ke arab kiblat. Setelah itu salah seorang dari sahabat tersebut keluar dan melewati kaum muslimin di sebuah masjid yang pada waktu itu mereka sedang ruku. Sahabat tadi berkata; AKu bersaksi kepada Allah, sungguh aku telah shalat bersama Nabi shallallahu 'alaihi wasallam dengan menghadap kiblat. Mereka pun segera berputar dalam keadaan shalat menghadap ke arah kiblat. Ada beberapa orang yang telah meninggal dengan menghadap ke arah kiblat pertama yang kami tidak tahu apa yang harus kami katakan mengenai hukumnya bagi mereka tersebut. Maka Allah pun menurunkan ayat; \"Dan Allah tidak akan menyia-nyiakan keimanan kalian, sesungguhnya Allah maha pengasih lagi maha penyayang kepada manusia.\" (Al Baqarah: 143)."},"3822":{"ar":"حَدَّثَنَا يُوسُفُ بْنُ رَاشِدٍ حَدَّثَنَا جَرِيرٌ وَأَبُو أُسَامَةَ وَاللَّفْظُ لِجَرِيرٍ عَنْ الْأَعْمَشِ عَنْ أَبِي صَالِحٍ وَقَالَ أَبُو أُسَامَةَ حَدَّثَنَا أَبُو صَالِحٍ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُدْعَى نُوحٌ يَوْمَ الْقِيَامَةِ فَيَقُولُ لَبَّيْكَ وَسَعْدَيْكَ يَا رَبِّ فَيَقُولُ هَلْ بَلَّغْتَ فَيَقُولُ نَعَمْ فَيُقَالُ لِأُمَّتِهِ هَلْ بَلَّغَكُمْ فَيَقُولُونَ مَا أَتَانَا مِنْ نَذِيرٍ فَيَقُولُ مَنْ يَشْهَدُ لَكَ فَيَقُولُ مُحَمَّدٌ وَأُمَّتُهُ فَتَشْهَدُونَ أَنَّهُ قَدْ بَلَّغَ{ وَيَكُونَ الرَّسُولُ عَلَيْكُمْ شَهِيدًا }فَذَلِكَ قَوْلُهُ جَلَّ ذِكْرُهُ{ وَكَذَلِكَ جَعَلْنَاكُمْ أُمَّةً وَسَطًا لِتَكُونُوا شُهَدَاءَ عَلَى النَّاسِ وَيَكُونَ الرَّسُولُ عَلَيْكُمْ شَهِيدًا }وَالْوَسَطُ الْعَدْلُ","id":"Telah menceritakan kepada kami [Yusuf bin Rasyid] Telah menceritakan kepada kami [Jarir] dan [Abu Usamah] dan lafazh ini milik Jarir dari [Al A'masy] dari [Abu Shalih], Abu Usamah berkata; Telah menceritakan kepada kami Abu Shalih dari [Abu Sa'id Al Khudri] berkata; Rasulullah shallallahu 'alaihi wasallam pernah bersabda: \"Pada hari kiamat, Nuh akan dipanggil (Allah) dan ia akan menjawab: 'Labbaik dan Sa'daik, wahai TuhanKu! ' lalu Allah bertanya: 'Apakah telah kau sampaikan pesan Kami? ' Nuh menjawab: 'Ya'. Kemudian Allah akan bertanya kepada bangsa (umat) Nuh: 'Apakah ia telah menyampaikan pesan kami kepadamu sekalian? ' Mereka akan berkata; 'Tidak ada yang memberikan peringatan kepada kami.' Maka Allah bertanya: 'Siapa yang menjadi saksimu? ' Nuh menjawab: 'Muhammad shallallahu 'alaihi wasallam dan para pengikutnya.' Maka mereka (umat muslim) akan bersaksi bahwa Nuh telah menyampaikan pesan (Allah). Kemudian Rasul (Muhammad shallallahu 'alaihi wasallam) akan menjadi saksi untukmu sekalian dan itulah maksud dari firman Allah: 'Demikianlah kami jadikan kalian sebagai umat yang adil supaya kamu menjadi saksi atas manusia. Dan Rasul menjadi saksi atas kalian.\" (QS. Al Baqarah (2): 143)."},"3823":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ سُفْيَانَ عَنْ عَبْدِ اللَّهِ بْنِ دِينَارٍ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَابَيْنَا النَّاسُ يُصَلُّونَ الصُّبْحَ فِي مَسْجِدِ قُبَاءٍ إِذْ جَاءَ جَاءٍ فَقَالَ أَنْزَلَ اللَّهُ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قُرْآنًا أَنْ يَسْتَقْبِلَ الْكَعْبَةَ فَاسْتَقْبِلُوهَا فَتَوَجَّهُوا إِلَى الْكَعْبَةِ","id":"Telah menceritakan kepada kami [Musaddad] Telah menceritakan kepada kami [Yahya] dari [Sufyan] dari [Abdullah bin Dinar] dari [Ibnu Umar] radliallahu 'anhuma; \"Tatkala orang-orang melaksanakan shalat shubuh di Quba`, tiba-tiba ada orang yang datang dan berkata; Allah telah menurunkan wahyu kepada Nabi shallallahu 'alaihi wasallam agar menghadap kiblat, maka menghadaplah ke sana! lalu mereka berbalik menghadap Ka'bah."},"3824":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا مُعْتَمِرٌ عَنْ أَبِيهِ عَنْ أَنَسٍ رَضِيَ اللَّهُ عَنْهُ قَالَلَمْ يَبْقَ مِمَّنْ صَلَّى الْقِبْلَتَيْنِ غَيْرِي","id":"Telah menceritakan kepada kami [Ali bin Abdullah] Telah menceritakan kepada kami [Mu'tamir] dari [Bapaknya] dari [Anas radliallahu 'anhu] dia berkata; 'semua orang yang pernah shalat menghadap dua kiblat sudah tiada kecuali aku.'"},"3825":{"ar":"حَدَّثَنَا خَالِدُ بْنُ مَخْلَدٍ حَدَّثَنَا سُلَيْمَانُ حَدَّثَنِي عَبْدُ اللَّهِ بْنُ دِينَارٍ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَابَيْنَمَا النَّاسُ فِي الصُّبْحِ بِقُبَاءٍ جَاءَهُمْ رَجُلٌ فَقَالَ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ أُنْزِلَ عَلَيْهِ اللَّيْلَةَ قُرْآنٌ وَأُمِرَ أَنْ يَسْتَقْبِلَ الْكَعْبَةَ أَلَا فَاسْتَقْبِلُوهَا وَكَانَ وَجْهُ النَّاسِ إِلَى الشَّأْمِ فَاسْتَدَارُوا بِوُجُوهِهِمْ إِلَى الْكَعْبَةِ","id":"Telah menceritakan kepada kami [Khalid bin Makhlad] Telah menceritakan kepada kami [Sulaiman] Dan telah menceritakan kepadaku [Abdullah bin Dinar] dari [Ibnu Umar radliallahu 'anhuma]; \"Tatkala orang-orang sedang shalat shubuh di Quba', datang seseorang lalu berkata, 'Rasulullah Shallallahu'alaihi wasallam pada malam ini mendapat wahyu, beliau diperintahkan menghadap ke Ka'bah'. Maka menghadaplah ke sana! Mereka pun segera beralih ke Ka'bah, padahal sebelumnya wajah-wajah mereka menghadap ke Syam (Baitul Maqdis) '.\""},"3826":{"ar":"حَدَّثَنَا يَحْيَى بْنُ قَزَعَةَ حَدَّثَنَا مَالِكٌ عَنْ عَبْدِ اللَّهِ بْنِ دِينَارٍ عَنْ ابْنِ عُمَرَ قَالَبَيْنَا النَّاسُ بِقُبَاءٍ فِي صَلَاةِ الصُّبْحِ إِذْ جَاءَهُمْ آتٍ فَقَالَ إِنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ أُنْزِلَ عَلَيْهِ اللَّيْلَةَ قُرْآنٌ وَقَدْ أُمِرَ أَنْ يَسْتَقْبِلَ الْكَعْبَةَ فَاسْتَقْبِلُوهَا وَكَانَتْ وُجُوهُهُمْ إِلَى الشَّأْمِ فَاسْتَدَارُوا إِلَى الْكَعْبَةِ","id":"Telah menceritakan kepada kami [Yahya bin Qaza'ah] Telah menceritakan kepada kami [Malik] dari [Abdullah bin Dinar] dari [Ibnu Umar] dia berkata; \"Tatkala orang-orang sedang shalat shubuh di Quba', datang seseorang lalu berkata, 'Rasulullah Shallallahu'alaihi wasallam pada malam ini mendapat wahyu, beliau diperintahkan menghadap ke Ka'bah'. Maka menghadaplah ke sana! Mereka pun segera beralih ke Ka'bah, padahal sebelumnya wajah-wajah mereka menghadap ke Syam (Baitul Maqdis).\""},"3827":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا يَحْيَى عَنْ سُفْيَانَ حَدَّثَنِي أَبُو إِسْحَاقَ قَالَ سَمِعْتُ الْبَرَاءَ رَضِيَ اللَّهُ عَنْهُ قَالَصَلَّيْنَا مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَ بَيْتِ الْمَقْدِسِ سِتَّةَ عَشَرَ أَوْ سَبْعَةَ عَشَرَ شَهْرًا ثُمَّ صَرَفَهُ نَحْوَ الْقِبْلَةِ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] Telah menceritakan kepada kami [Yahya] dari [Sufyan] Telah menceritakan kepadaku [Abu Ishaq] dia berkata; Aku mendengar [Al Barra radliallahu 'anhu] berkata; \"Kami shalat bersama Rasulullah shallallahu 'alaihi wasallam dengan menghadap ke Baitul Maqdis selama enam belas atau tujuh belas bulan. Lalu beliau merubahnya dengan menghadap kiblat.\""},"3828":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ مُسْلِمٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ دِينَارٍ قَالَ سَمِعْتُ ابْنَ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا يَقُولُبَيْنَا النَّاسُ فِي الصُّبْحِ بِقُبَاءٍ إِذْ جَاءَهُمْ رَجُلٌ فَقَالَ أُنْزِلَ اللَّيْلَةَ قُرْآنٌ فَأُمِرَ أَنْ يَسْتَقْبِلَ الْكَعْبَةَ فَاسْتَقْبِلُوهَا وَاسْتَدَارُوا كَهَيْئَتِهِمْ فَتَوَجَّهُوا إِلَى الْكَعْبَةِ وَكَانَ وَجْهُ النَّاس إِلَى الشَّأْمِ","id":"Telah menceritakan kepada kami [Musa bin Ismail] Telah menceritakan kepada kami [Abdul Aziz bin Muslim] Telah menceritakan kepada kami [Abdullah bin Dinar] dia berkata; Aku mendengar [Ibnu Umar radliallahu 'anhuma] berkata; \"Tatkala orang-orang sedang shalat shubuh di Quba', datang seseorang lalu berkata, 'Rasulullah Shallallahu'alaihi wasallam pada malam ini mendapat wahyu, beliau diperintahkan menghadap ke Ka'bah'. Maka menghadaplah ke sana! Mereka pun segera beralih ke Ka'bah dalam keadaan shalat, padahal sebelumnya wajah-wajah mereka menghadap ke Syam (Baitul Maqdis).\""},"3829":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ عَنْ مَالِكٍ عَنْ عَبْدِ اللَّهِ بْنِ دِينَارٍ عَنْ ابْنِ عُمَرَ قَالَبَيْنَمَا النَّاسُ فِي صَلَاةِ الصُّبْحِ بِقُبَاءٍ إِذْ جَاءَهُمْ آتٍ فَقَالَ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ أُنْزِلَ عَلَيْهِ اللَّيْلَةَ وَقَدْ أُمِرَ أَنْ يَسْتَقْبِلَ الْكَعْبَةَ فَاسْتَقْبِلُوهَا وَكَانَتْ وُجُوهُهُمْ إِلَى الشَّأْمِ فَاسْتَدَارُوا إِلَى الْقِبْلَةِ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] dari [Malik] dari [Abdullah bin Dinar] dari [Ibnu Umar] dia berkata; \"Tatkala orang-orang sedang shalat shubuh di Quba', datang seseorang lalu berkata, 'Rasulullah Shallallahu'alaihi wasallam pada malam ini mendapat wahyu, beliau diperintahkan menghadap ke Ka'bah'. Maka menghadaplah ke sana! Mereka pun segera beralih ke Ka'bah, padahal sebelumnya wajah-wajah mereka menghadap ke Syam (Baitul Maqdis).\""},"3830":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ أَنَّهُ قَالَ قُلْتُ لِعَائِشَةَ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَوَأَنَا يَوْمَئِذٍ حَدِيثُ السِّنِّ أَرَأَيْتِ قَوْلَ اللَّهِ تَبَارَكَ وَتَعَالَى{ إِنَّ الصَّفَا وَالْمَرْوَةَ مِنْ شَعَائِرِ اللَّهِ فَمَنْ حَجَّ الْبَيْتَ أَوْ اعْتَمَرَ فَلَا جُنَاحَ عَلَيْهِ أَنْ يَطَّوَّفَ بِهِمَا }فَمَا أُرَى عَلَى أَحَدٍ شَيْئًا أَنْ لَا يَطَّوَّفَ بِهِمَا فَقَالَتْ عَائِشَةُ كَلَّا لَوْ كَانَتْ كَمَا تَقُولُ كَانَتْ فَلَا جُنَاحَ عَلَيْهِ أَنْ لَا يَطَّوَّفَ بِهِمَا إِنَّمَا أُنْزِلَتْ هَذِهِ الْآيَةُ فِي الْأَنْصَارِ كَانُوا يُهِلُّونَ لِمَنَاةَ وَكَانَتْ مَنَاةُ حَذْوَ قُدَيْدٍ وَكَانُوا يَتَحَرَّجُونَ أَنْ يَطُوفُوا بَيْنَ الصَّفَا وَالْمَرْوَةِ فَلَمَّا جَاءَ الْإِسْلَامُ سَأَلُوا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ ذَلِكَ فَأَنْزَلَ اللَّهُ{ إِنَّ الصَّفَا وَالْمَرْوَةَ مِنْ شَعَائِرِ اللَّهِ فَمَنْ حَجَّ الْبَيْتَ أَوْ اعْتَمَرَ فَلَا جُنَاحَ عَلَيْهِ أَنْ يَطَّوَّفَ بِهِمَا }","id":"Telah menceritakan kepada kami [Abdullah bin Yusuf] Telah mengabarkan kepada kami [Malik] dari [Hisyam bin Urwah] dari [Bapaknya] dia berkata; Aku bertanya kepada [Aisyah] istri Rasulullah shallallahu 'alaihi wasallam, -Saat itu saya masih muda-: 'Apakah anda tahu tentang firman Allah Tabaraka Wa Ta'ala: 'Sesungguhnya Shafaa dan Marwa adalah sebahagian dari syi'ar Allah. Barangsiapa yang beribadah haji ke Baitullah atau ber'umrah, maka tidak ada dosa baginya mengerjakan sa'i antara keduanya.' Sebab sepengetahuanku nggak masalah bagi seseorang untuk meninggalkan Sa'i antara keduanya. Aisyah menjawab; \"Bukan begitu, kalau seperti yang kamu katakan, maka jadinya tidak ada dosa orang tidak melakukan sa'i. Ayat ini turun pada orang-orang Anshar, yang dahulu mereka melakukan talbiyah karena Manat, yang letaknya di depan Qadid. Yang mereka berkeharusan berthawaf antara Shofa dan Marwa. Tatkala Islam datang, mereka bertanya pada Rasulullah shallallahu 'alaihi wasallam tentang hal itu. Maka Allah Tabaraka Wa Ta'ala menurunkan ayat: 'Sesungguhnya Shafa dan Marwa adalah sebagian dari syi'ar Allah. Maka barangsiapa yang beribadah haji ke Baitullah atau ber-'umrah, Maka tidak ada dosa baginya mengerjakan sa'i antara keduanya'.\" (QS. Albaqarah 158)."},"3831":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا سُفْيَانُ عَنْ عَاصِمِ بْنِ سُلَيْمَانَ قَالَ سَأَلْتُ أَنَسَ بْنَ مَالِكٍ رَضِيَ اللَّهُ عَنْهُعَنْ الصَّفَا وَالْمَرْوَةِ فَقَالَ كُنَّا نَرَى أَنَّهُمَا مِنْ أَمْرِ الْجَاهِلِيَّةِ فَلَمَّا كَانَ الْإِسْلَامُ أَمْسَكْنَا عَنْهُمَا فَأَنْزَلَ اللَّهُ تَعَالَى{ إِنَّ الصَّفَا وَالْمَرْوَةَ مِنْ شَعَائِرِ اللَّهِ فَمَنْ حَجَّ الْبَيْتَ أَوْ اعْتَمَرَ فَلَا جُنَاحَ عَلَيْهِ أَنْ يَطَّوَّفَ بِهِمَا }","id":"Telah menceritakan kepada kami [Muhammad bin Yusuf] Telah menceritakan kepada kami [Sufyan] dari ['Ashim bin Sulaiman] dia berkata; Aku bertanya kepada [Anas bin Malik radliallahu 'anhu] tentang Shafa dan Marwa. Maka dia menjawab; Aku menganggap keduanya sebagai perkara jahiliyah, tatkala Islam datang, keduanya kami tinggalkan lalu turunlah firman Allah; \"Sesungguhnya Shafa dan Marwa adalah sebagian dari syi'ar Allah. Maka barangsiapa yang beribadah haji ke Baitullah atau ber-'umrah, Maka tidak ada dosa baginya mengerjakan sa'i antara keduanya.\" (QS. Albaqarah 158)."},"3832":{"ar":"حَدَّثَنَا عَبْدَانُ عَنْ أَبِي حَمْزَةَ عَنْ الْأَعْمَشِ عَنْ شَقِيقٍ عَنْ عَبْدِ اللَّهِقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَلِمَةً وَقُلْتُ أُخْرَى قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ مَاتَ وَهْوَ يَدْعُو مِنْ دُونِ اللَّهِ نِدًّا دَخَلَ النَّارَوَقُلْتُ أَنَا مَنْ مَاتَ وَهْوَ لَا يَدْعُو لِلَّهِ نِدًّا دَخَلَ الْجَنَّةَ","id":"Telah menceritakan kepada kami [Abdan] dari [Abu Hamzah] dari [Al A'masy] dari [Syaqiq] dari [Abdullah], Nabi shallallahu 'alaihi wasallam bersabda beberapa kalimat yang aku tambahkan. Nabi shallallahu 'alaihi wasallam bersabda: \"Barang siapa yang mati, sedangkan dia menyeru selain Allah sebagai tandingannya maka dia masuk neraka.\" Sedangkan aku berkata; 'Barang siapa yang mati dan dia tidak menyekutukan Allah dengan sesuatu maka dia masuk surga.'"},"3833":{"ar":"حَدَّثَنَا الْحُمَيْدِيُّ حَدَّثَنَا سُفْيَانُ حَدَّثَنَا عَمْرٌو قَالَ سَمِعْتُ مُجَاهِدًا قَالَ سَمِعْتُ ابْنَ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا يَقُولُكَانَ فِي بَنِي إِسْرَائِيلَ الْقِصَاصُ وَلَمْ تَكُنْ فِيهِمْ الدِّيَةُ فَقَالَ اللَّهُ تَعَالَى لِهَذِهِ الْأُمَّةِ{ كُتِبَ عَلَيْكُمْ الْقِصَاصُ فِي الْقَتْلَى الْحُرُّ بِالْحُرِّ وَالْعَبْدُ بِالْعَبْدِ وَالْأُنْثَى بِالْأُنْثَى فَمَنْ عُفِيَ لَهُ مِنْ أَخِيهِ شَيْءٌ }فَالْعَفْوُ أَنْ يَقْبَلَ الدِّيَةَ فِي الْعَمْدِ{ فَاتِّبَاعٌ بِالْمَعْرُوفِ وَأَدَاءٌ إِلَيْهِ بِإِحْسَانٍ }يَتَّبِعُ بِالْمَعْرُوفِ وَيُؤَدِّي بِإِحْسَانٍ{ ذَلِكَ تَخْفِيفٌ مِنْ رَبِّكُمْ وَرَحْمَةٌ }مِمَّا كُتِبَ عَلَى مَنْ كَانَ قَبْلَكُمْ{ فَمَنْ اعْتَدَى بَعْدَ ذَلِكَ فَلَهُ عَذَابٌ أَلِيمٌ }قَتَلَ بَعْدَ قَبُولِ الدِّيَةِ","id":"Telah menceritakan kepada kami [Al Humaidi] Telah menceritakan kepada kami [Sufyan] Telah menceritakan kepada kami [Amru] dia berkata; Aku mendengar [Mujahid] berkata; Aku mendengar [Ibnu Abbas radliallahu 'anhuma] berkata; \"Dahulu pada Bani Israil terdapat hukum qishas namun tidak ada diyah pada mereka, lalu Allah Azza wa jalla menurunkan ayat: \"Hai orang-orang yang beriman, diwajibkan atas kamu qishaash berkenaan dengan orang-orang yang dibunuh; orang merdeka dengan orang merdeka, hamba dengan hamba, dan wanita dengan wanita. Maka barangsiapa yang mendapat suatu pema'afan dari saudaranya, hendaklah (yang mema'afkan) mengikuti dengan cara yang baik, dan hendaklah (yang diberi ma'af) membayar (diat) kepada yang memberi ma'af dengan cara yang baik (pula). (QS. Albaqarah 178). Pemberian maaf itu maksudnya adalah menerima diyat pada pembunuhan dengan sengaja. mengikuti dengan cara yang baik yaitu ia mengikuti ini dengan cara yang ma'ruf, dan membayar dengan cara yang baik serta melaksanakan ini dengan kebaikan. Yang demikian itu adalah suatu keringanan dari Tuhan kamu dan suatu rahmat (QS. Albaqarah 178) dari apa yang telah diwajibkan atas kaum sebelum kalian, sesungguhnya hal tersebut adalah qishas bukan diyah. Barang siapa yang melampui batas setelah itu, maka baginya Adzab yang pedih.' Yaitu membunuh setelah menerima diyah."},"3834":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ الْأَنْصَارِيُّ حَدَّثَنَا حُمَيْدٌ أَنَّ أَنَسًا حَدَّثَهُمْعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ كِتَابُ اللَّهِ الْقِصَاصُ","id":"Telah menceritakan kepada kami [Muhammad bin Abdullah Al Anshari] Telah menceritakan kepada kami [Humaid] bahwa [Anas] menceritakan kepada mereka dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Kitabullah adalah al Qishas.\""},"3835":{"ar":"حَدَّثَنِي عَبْدُ اللَّهِ بْنُ مُنِيرٍ سَمِعَ عَبْدَ اللَّهِ بْنَ بَكْرٍ السَّهْمِيَّ حَدَّثَنَا حُمَيْدٌ عَنْ أَنَسٍأَنَّ الرُّبَيِّعَ عَمَّتَهُ كَسَرَتْ ثَنِيَّةَ جَارِيَةٍ فَطَلَبُوا إِلَيْهَا الْعَفْوَ فَأَبَوْا فَعَرَضُوا الْأَرْشَ فَأَبَوْا فَأَتَوْا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَبَوْا إِلَّا الْقِصَاصَ فَأَمَرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالْقِصَاصِ فَقَالَ أَنَسُ بْنُ النَّضْرِ يَا رَسُولَ اللَّهِ أَتُكْسَرُ ثَنِيَّةُ الرُّبَيِّعِ لَا وَالَّذِي بَعَثَكَ بِالْحَقِّ لَا تُكْسَرُ ثَنِيَّتُهَا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا أَنَسُ كِتَابُ اللَّهِ الْقِصَاصُ فَرَضِيَ الْقَوْمُ فَعَفَوْا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ مِنْ عِبَادِ اللَّهِ مَنْ لَوْ أَقْسَمَ عَلَى اللَّهِ لَأَبَرَّهُ","id":"Telah menceritakan kepadaku [Abdullah bin Munir] dia mendengar [Abdullah bin Bakr As Sahmi] Telah menceritakan kepada kami [Humaid] dari [Anas] bahwa Rabayyi' -pamannya- pernah mematahkan gigi seri seorang budak wanita, kemudian mereka meminta kepadanya untuk memaafkan, namun mereka (keluarganya) menolak. Kemudian ditawarkan kepada mereka denda, namun mereka tetap menolak, lalu mereka mendatangi Nabi shallallahu'alaihi wa sallam, maka beliau memerintahkan untuk diqishash. Anas bin An Nadhr berkata; wahai Rasulullah, apakah gigi seri Ar Rubayyi' akan dipatahkan? Tidak, demi Dzat yang mengutusmu dengan kebenaran, gigi serinya jangan dipatahkan. Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ya Anas, Kitabullah adalah Al Qishas. Maka orang-orang tersebut rela memberikan maaf. kemudian Nabi shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya diantara hamba-hamba Allah terdapat orang yang apabila ia bersumpah atas nama Allah maka Allah akan mengabulkannya.\""},"3836":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ عُبَيْدِ اللَّهِ قَالَ أَخْبَرَنِي نَافِعٌ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا قَالَكَانَ عَاشُورَاءُ يَصُومُهُ أَهْلُ الْجَاهِلِيَّةِ فَلَمَّا نَزَلَ رَمَضَانُ قَالَ مَنْ شَاءَ صَامَهُ وَمَنْ شَاءَ لَمْ يَصُمْهُ","id":"Telah menceritakan kepada kami [Musaddad] Telah menceritakan kepada kami [Yahya] dari [Ubaidullah] dia berkata; Telah mengabarkan kepadaku [Nafi'] dari [Ibnu Umar radliallahu 'anhuma] dia berkata; \"Dahulu hari Asyura' adalah hari yang orang-orang jahilliyah pergunakan untuk puasa, tatkala turun bulan ramadlan, beliau bersabda: \"Barang siapa yang ingin berpuasa Asyura' hendaklah ia berpuasa, dan bagi yang tidak ingin, silahkan ia tinggalkan.\""},"3837":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ حَدَّثَنَا ابْنُ عُيَيْنَةَ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاكَانَ عَاشُورَاءُ يُصَامُ قَبْلَ رَمَضَانَ فَلَمَّا نَزَلَ رَمَضَانُ قَالَ مَنْ شَاءَ صَامَ وَمَنْ شَاءَ أَفْطَرَ","id":"Telah menceritakan kepada kami [Abdullah bin Muhammad] Telah menceritakan kepada kami [Ibnu Uyainah] dari [Az Zuhri] dari [Urwah] dari [Aisyah radliallahu 'anha]; \"Dahulu hari Asyura' adalah hari-hari yang dipergunakan orang-orang jahilliyah untuk melakukan puasa, tatkala datang bulan ramadlan, beliau bersabda: \"Barang siapa yang ingin berpuasa Asyura' hendaklah ia berpuasa, dan bagi yang tidak ingin, maka berbukalah.\""},"3838":{"ar":"حَدَّثَنِي مَحْمُودٌ أَخْبَرَنَا عُبَيْدُ اللَّهِ عَنْ إِسْرَائِيلَ عَنْ مَنْصُورٍ عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ عَنْ عَبْدِ اللَّهِ قَالَدَخَلَ عَلَيْهِ الْأَشْعَثُ وَهْوَ يَطْعَمُ فَقَالَ الْيَوْمُ عَاشُورَاءُ فَقَالَ كَانَ يُصَامُ قَبْلَ أَنْ يَنْزِلَ رَمَضَانُ فَلَمَّا نَزَلَ رَمَضَانُ تُرِكَ فَادْنُ فَكُلْ","id":"Telah menceritakan kepadaku [Mahmud] Telah mengabarkan kepada kami [Ubaidullah] dari [Israil] dari [Manshur] dari [Ibrahim] dari [Alqamah] dari [Abdullah] dia berkata; bahwa suatu hari Al Asy'ats menemuinya yang pada waktu itu dia sedang makan. Maka dia berkata; Hari ini adalah hari Asyura. Abdullah berkata; Dahulu sebelum diwajibkan bulan Ramadlan, hari ini adalah hari berpuasa. Tatkala diwajibkan bulan Ramadlan, maka hari itu ditinggalkan, oleh karena itu ayo mendekat dan makanlah! "},"3839":{"ar":"حَدَّثَنِي مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا يَحْيَى حَدَّثَنَا هِشَامٌ قَالَ أَخْبَرَنِي أَبِي عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْكَانَ يَوْمُ عَاشُورَاءَ تَصُومُهُ قُرَيْشٌ فِي الْجَاهِلِيَّةِ وَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَصُومُهُ فَلَمَّا قَدِمَ الْمَدِينَةَ صَامَهُ وَأَمَرَ بِصِيَامِهِ فَلَمَّا نَزَلَ رَمَضَانُ كَانَ رَمَضَانُ الْفَرِيضَةَ وَتُرِكَ عَاشُورَاءُ فَكَانَ مَنْ شَاءَ صَامَهُ وَمَنْ شَاءَ لَمْ يَصُمْهُ","id":"Telah menceritakan kepadaku [Muhammad bin Al Mutsanna] Telah menceritakan kepada kami [Yahya] Telah menceritakan kepada kami [Hisyam] dia berkata; Telah mengabarkan kepadaku [Bapakku] dari [Aisyah radliallahu 'anha] dia berkata; Dahulu hari 'Asyura adalah hari yang orang-orang Quraisy pergunakan pada masa Jahiliyah untuk berpuasa. Rasulullah shallallahu 'alaihi wasallam pernah melakukan puasa itu. Tatkala sampai di Madinah beliau berpuasa pada hari itu dan pernah memerintahkan untuk berpuasa (pada hari itu), namun ketika perintah puasa ramadlan turun dan diwajibkan, maka puasa 'Asyura ditinggalkan. Akhirnya barang siapa yang ingin berpuasa 'Asyura hendaklah berpuasa, dan barangsiapa yang tidak ingin, maka tinggalkanlah.'"},"3840":{"ar":"حَدَّثَنِي إِسْحَاقُ أَخْبَرَنَا رَوْحٌ حَدَّثَنَا زَكَرِيَّاءُ بْنُ إِسْحَاقَ حَدَّثَنَا عَمْرُو بْنُ دِينَارٍ عَنْ عَطَاءٍ سَمِعَ ابْنَ عَبَّاسٍيَقْرَأُ وَعَلَى الَّذِينَ يُطَوَّقُونَهُ فَلَا يُطِيقُونَهُ{ فِدْيَةٌ طَعَامُ مِسْكِينٍ }قَالَ ابْنُ عَبَّاسٍ لَيْسَتْ بِمَنْسُوخَةٍ هُوَ الشَّيْخُ الْكَبِيرُ وَالْمَرْأَةُ الْكَبِيرَةُ لَا يَسْتَطِيعَانِ أَنْ يَصُومَا فَيُطْعِمَانِ مَكَانَ كُلِّ يَوْمٍ مِسْكِينًا","id":"Telah menceritakan kepadaku [Ishaq] Telah mengabarkan kepada kami [Rauh] Telah menceritakan kepada kami [Zakaria bin Ishaq] Telah menceritakan kepada kami [Amru bin Dinar] dari [Atha] dia mendengar [Ibnu Abbas] membaca ayat; \"Dan bagi orang-orang yang berat menjalankannya maka wajib membayar fidya yaitu memberi makan orang miskin, \"(QS. Albaqarah 184), Ibnu Abbas berkata; Ayat ini tidak dimanshukh, namun ayat ini hanya untuk orang yang sudah sangat tua dan nenek tua, yang tidak mampu menjalankannya, maka hendaklah mereka memberi makan setiap hari kepada orang miskin.'"},"3841":{"ar":"حَدَّثَنَا عَيَّاشُ بْنُ الْوَلِيدِ حَدَّثَنَا عَبْدُ الْأَعْلَى حَدَّثَنَا عُبَيْدُ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاأَنَّهُ قَرَأَ{ فِدْيَةٌ طَعَامُ مَسَاكِينَ }قَالَ هِيَ مَنْسُوخَةٌ","id":"Telah menceritakan kepada kami [Ayyas bin Al Walid] Telah menceritakan kepada kami [Abdul A'la] Telah menceritakan kepada kami [Ubaidullah] dari [Nafi] dari [Ibnu Umar radliallahu 'anhuma] bahwa dia membaca ayat: 'wajib membayar fidyah dengan memberi maka kepada orang miskin'. Ibnu Umar berkata; Ayat ini telah dimanshukh.'"},"3842":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا بَكْرُ بْنُ مُضَرَ عَنْ عَمْرِو بْنِ الْحَارِثِ عَنْ بُكَيْرِ بْنِ عَبْدِ اللَّهِ عَنْ يَزِيدَ مَوْلَى سَلَمَةَ بْنِ الْأَكْوَعِ عَنْ سَلَمَةَ قَالَلَمَّا نَزَلَتْ{ وَعَلَى الَّذِينَ يُطِيقُونَهُ فِدْيَةٌ طَعَامُ مِسْكِينٍ }كَانَ مَنْ أَرَادَ أَنْ يُفْطِرَ وَيَفْتَدِيَ حَتَّى نَزَلَتْ الْآيَةُ الَّتِي بَعْدَهَا فَنَسَخَتْهَاقَالَ أَبُو عَبْد اللَّهِ مَاتَ بُكَيْرٌ قَبْلَ يَزِيدَ","id":"Telah menceritakan kepada kami [Qutaibah] Telah menceritakan kepada kami [Bakr bin Mudlar] dari [Amru bin Al Harits] dari [Bukair bin Abdullah] dari [Yazid] budak yang dimerdekakan Salamah bin Al Akwa' dari [Salamah] dia berkata; \"Tatkala turun ayat; \"Dan bagi orang-orang yang berat menjalankannya maka wajib membayar fidya yaitu memberi makan orang miskin, \" adalah barang siapa yang ingin berbuka maka hendaklah membayar fidyah, hingga turunlah ayat setelahnya yang menasakh (menghapus) ayat tersebut. Abu Abdullah berkata; Bukair meninggal sebelum Yazid."},"3843":{"ar":"حَدَّثَنَا عُبَيْدُ اللَّهِ عَنْ إِسْرَائِيلَ عَنْ أَبِي إِسْحَاقَ عَنْ الْبَرَاءِ ح و حَدَّثَنَا أَحْمَدُ بْنُ عُثْمَانَ حَدَّثَنَا شُرَيْحُ بْنُ مَسْلَمَةَ قَالَ حَدَّثَنِي إِبْرَاهِيمُ بْنُ يُوسُفَ عَنْ أَبِيهِ عَنْ أَبِي إِسْحَاقَ قَالَ سَمِعْتُ الْبَرَاءَ رَضِيَ اللَّهُ عَنْهُلَمَّا نَزَلَ صَوْمُ رَمَضَانَ كَانُوا لَا يَقْرَبُونَ النِّسَاءَ رَمَضَانَ كُلَّهُ وَكَانَ رِجَالٌ يَخُونُونَ أَنْفُسَهُمْ فَأَنْزَلَ اللَّهُ{ عَلِمَ اللَّهُ أَنَّكُمْ كُنْتُمْ تَخْتَانُونَ أَنْفُسَكُمْ فَتَابَ عَلَيْكُمْ وَعَفَا عَنْكُمْ }","id":"Telah menceritakan kepada kami [Ubaidullah] dari [Israil] dari [Abu Ishaq] dari [Al Barra] Demikian juga diriwayatkan dari jalur lainnya, Dan telah menceritakan kepada kami [Ahmad bin Utsman] Telah menceritakan kepada kami [Syuraih bin Maslamah] dia berkata; Telah menceritakan kepadaku [Ibrahim bin Yusuf] dari [Bapaknya] dari [Abu Ishaq] dia berkata; Aku mendengar [Al Barra radliallahu 'anhu], -tatkala diperintahkan puasa Ramadlan, orang-orang tidak mau mendekati para wanita sepanjang bulan Ramadlah tersebut. Dan ada beberapa orang yang mengkhianati dirinya sendiri. Maka Allah menurunkan ayat; \"Allah mengetahui bahwa kalian tidak dapat menahan diri kalian sendiri. Maka Dia menerima taubat kalian dan memaafkan kalian.\""},"3844":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ حُصَيْنٍ عَنْ الشَّعْبِيِّ عَنْ عَدِيٍّ قَالَأَخَذَ عَدِيٌّ عِقَالًا أَبْيَضَ وَعِقَالًا أَسْوَدَ حَتَّى كَانَ بَعْضُ اللَّيْلِ نَظَرَ فَلَمْ يَسْتَبِينَا فَلَمَّا أَصْبَحَ قَالَ يَا رَسُولَ اللَّهِ جَعَلْتُ تَحْتَ وِسَادِي عِقَالَيْنِ قَالَ إِنَّ وِسَادَكَ إِذًا لَعَرِيضٌ أَنْ كَانَ الْخَيْطُ الْأَبْيَضُ وَالْأَسْوَدُ تَحْتَ وِسَادَتِكَ","id":"Telah menceritakan kepada kami [Musa bin Ismail] Telah menceritakan kepada kami [Abu 'Awanah] dari [Hushain] dari [As Sya'bi] dari [Adi] dia berkata; Adi mengambil benang putih dan benang hitam. Hingga apabil malam tiba dia melihat pada benang tersebut, namun keduanya tidak Nampak juga. Dipagi harinya dia berkata; \"Wahai Rasulullah shallallahu 'alaihi wasallam, aku telah meletakkan dibawah bantalku benang putih dan benang hitam, maka beliau bersabda: Bantalmu terlalu besar jika kau bentangkan benang hitam dan putih dibawah bantalmu."},"3845":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا جَرِيرٌ عَنْ مُطَرِّفٍ عَنْ الشَّعْبِيِّ عَنْ عَدِيِّ بْنِ حَاتِمٍ رَضِيَ اللَّهُ عَنْهُ قَالَقُلْتُ يَا رَسُولَ اللَّهِ مَا{ الْخَيْطُ الْأَبْيَضُ مِنْ الْخَيْطِ الْأَسْوَدِ }أَهُمَا الْخَيْطَانِ قَالَ إِنَّكَ لَعَرِيضُ الْقَفَا إِنْ أَبْصَرْتَ الْخَيْطَيْنِ ثُمَّ قَالَ لَا بَل�� هُوَ سَوَادُ اللَّيْلِ وَبَيَاضُ النَّهَارِ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] Telah menceritakan kepada kami [Jarir] dari [Mutharrif] dari [Asy Sya'bi] dari ['Adi bin Hatim radliallahu 'anhu] berkata; Aku bertanya ya Rasulullah apakah yang dimaksud benang putih dan benang hitam itu? Apakah benar-benar berbentuk benang tali? Beliau menjawab: 'Sesunguhnya lehermu terlalu panjang bila melihat kedua benang itu. tidak demikian, sesungguhnya yang dimaksud adalah hitamnya malam dan putihnya siang hari.'"},"3846":{"ar":"حَدَّثَنَا ابْنُ أَبِي مَرْيَمَ حَدَّثَنَا أَبُو غَسَّانَ مُحَمَّدُ بْنُ مُطَرِّفٍ حَدَّثَنِي أَبُو حَازِمٍ عَنْ سَهْلِ بْنِ سَعْدٍ قَالَوَأُنْزِلَتْ{ وَكُلُوا وَاشْرَبُوا حَتَّى يَتَبَيَّنَ لَكُمْ الْخَيْطُ الْأَبْيَضُ مِنْ الْخَيْطِ الْأَسْوَدِ }وَلَمْ يُنْزَلْ{ مِنْ الْفَجْرِ }وَكَانَ رِجَالٌ إِذَا أَرَادُوا الصَّوْمَ رَبَطَ أَحَدُهُمْ فِي رِجْلَيْهِ الْخَيْطَ الْأَبْيَضَ وَالْخَيْطَ الْأَسْوَدَ وَلَا يَزَالُ يَأْكُلُ حَتَّى يَتَبَيَّنَ لَهُ رُؤْيَتُهُمَا فَأَنْزَلَ اللَّهُ بَعْدَهُ{ مِنْ الْفَجْرِ }فَعَلِمُوا أَنَّمَا يَعْنِي اللَّيْلَ مِنْ النَّهَارِ","id":"Telah menceritakan kepada kami [Ibnu Abu Maryam] Telah menceritakan kepada kami [Abu Ghassan Muhammad bin Mutharrif] Telah menceritakan kepadaku [Abu Hazim] dari [Sahal bin Sa'ad] dia berkata; Ketika turun ayat; \"dan makan minumlah kamu sehingga terang bagimu benang putih dari benang hitam. (Q.S.Al Baqarah: 187). Sedangkan ayat 'minal fajrinya' (di waktu fajar) belum turun. Orang-orangpun apabila mau berpuasa, salah seorang dari mereka mengikat kakinya dengan benang putih dan benang hitam, dan mereka terus makan hingga nampak bagi mereka kedua benang tersebut. Lalu Allah menurunkan ayat; 'Minal fajri.' (diwaktu fajar). Akhirnya mereka mengerti bahwa yang dimaksud adalah dari waktu malam ke siang."},"3847":{"ar":"حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى عَنْ إِسْرَائِيلَ عَنْ أَبِي إِسْحَاقَ عَنْ الْبَرَاءِ قَالَكَانُوا إِذَا أَحْرَمُوا فِي الْجَاهِلِيَّةِ أَتَوْا الْبَيْتَ مِنْ ظَهْرِهِ فَأَنْزَلَ اللَّهُ{ وَلَيْسَ الْبِرُّ بِأَنْ تَأْتُوا الْبُيُوتَ مِنْ ظُهُورِهَا وَلَكِنَّ الْبِرَّ مَنْ اتَّقَى وَأْتُوا الْبُيُوتَ مِنْ أَبْوَابِهَا }","id":"Telah menceritakan kepada kami [Ubaidullah bin Musa] dari [Israil] dari [Abu Ishaq] dari [Al Barra] dia berkata; \"Pada masa Jahiliyah, orang-orang yang berihram pada waktu haji, mendatangi rumah dari belakang, maka Allah menurunkan ayat; \"Bukan suatu kebaikan mendatangi rumah-rumah dari belakang, kebaikan adalah (kebaikan) orang yang bertakwa. Datangilah rumah-rumah dari pintu-pintunya.\" (QS.Albaqarah 189)."},"3848":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا عَبْدُ الْوَهَّابِ حَدَّثَنَا عُبَيْدُ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاأَتَاهُ رَجُلَانِ فِي فِتْنَةِ ابْنِ الزُّبَيْرِ فَقَالَا إِنَّ النَّاسَ صَنَعُوا وَأَنْتَ ابْنُ عُمَرَ وَصَاحِبُ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَمَا يَمْنَعُكَ أَنْ تَخْرُجَ فَقَالَ يَمْنَعُنِي أَنَّ اللَّهَ حَرَّمَ دَمَ أَخِي فَقَالَا أَلَمْ يَقُلْ اللَّهُ{ وَقَاتِلُوهُمْ حَتَّى لَا تَكُونَ فِتْنَةٌ }فَقَالَ قَاتَلْنَا حَتَّى لَمْ تَكُنْ فِتْنَةٌ وَكَانَ الدِّينُ لِلَّهِ وَأَنْتُمْ تُرِيدُونَ أَنْ تُقَاتِلُوا حَتَّى تَكُونَ فِتْنَةٌ وَيَكُونَ الدِّينُ لِغَيْرِ اللَّهِوَزَادَ عُثْمَانُ بْنُ صَالِحٍ عَنْ ابْنِ وَهْبٍ قَالَ أَخْبَرَنِي فُلَانٌ وَحَيْوَةُ بْنُ شُرَيْحٍ عَنْ بَكْرِ بْنِ عَمْرٍو الْمَعَافِرِيِّ أَنَّ بُكَيْرَ بْنَ عَبْدِ اللَّهِ حَدَّثَهُ عَنْ نَافِعٍ أَنَّ رَجُلًا أَتَى ابْنَ عُمَرَ فَقَالَ يَا أَبَا عَبْدِ الرَّحْمَنِ مَا حَمَلَكَ عَلَى أَنْ تَحُجَّ عَامًا وَتَعْتَمِرَ عَامًا وَتَتْرُكَ الْجِهَادَ فِي سَبِيلِ اللَّهِ عَزَّ وَجَلَّ وَقَدْ عَلِمْتَ مَا رَغَّبَ اللَّهُ فِيهِ قَالَ يَا ابْنَ أَخِي بُنِيَ الْإِسْلَامُ عَلَى خَمْسٍ إِيمَانٍ بِاللَّهِ وَرَسُولِهِ وَالصَّلَاةِ الْخَمْسِ وَصِيَامِ رَمَضَانَ وَأَدَاءِ الزَّكَاةِ وَحَجِّ الْبَيْتِ قَالَ يَا أَبَا عَبْدِ الرَّحْمَنِ أَلَا تَسْمَعُ مَا ذَكَرَ اللَّهُ فِي كِتَابِهِ{ وَإِنْ طَائِفَتَانِ مِنْ الْمُؤْمِنِينَ اقْتَتَلُوا فَأَصْلِحُوا بَيْنَهُمَا فَإِنْ بَغَتْ إِحْدَاهُمَا عَلَى الْأُخْرَى فَقَاتِلُوا الَّتِي تَبْغِي حَتَّى تَفِيءَ إِلَى أَمْرِ اللَّهِ }{ قَاتِلُوهُمْ حَتَّى لَا تَكُونَ فِتْنَةٌ }قَالَ فَعَلْنَا عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَكَانَ الْإِسْلَامُ قَلِيلًا فَكَانَ الرَّجُلُ يُفْتَنُ فِي دِينِهِ إِمَّا قَتَلُوهُ وَإِمَّا يُعَذِّبُونَهُ حَتَّى كَثُرَ الْإِسْلَامُ فَلَمْ تَكُنْ فِتْنَةٌ قَالَ فَمَا قَوْلُكَ فِي عَلِيٍّ وَعُثْمَانَ قَالَ أَمَّا عُثْمَانُ فَكَأَنَّ اللَّهَ عَفَا عَنْهُ وَأَمَّا أَنْتُمْ فَكَرِهْتُمْ أَنْ تَعْفُوا عَنْهُ وَأَمَّا عَلِيٌّ فَابْنُ عَمِّ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَخَتَنُهُ وَأَشَارَ بِيَدِهِ فَقَالَ هَذَا بَيْتُهُ حَيْثُ تَرَوْنَ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] Telah menceritakan kepada kami ['Abdul Wahhab] Telah menceritakan kepada kami ['Ubaidullah] dari [Nafi'] dari [Ibnu Umar radliallahu 'anhuma] bahwa dua orang laki-laki mendatangi Ibnu Jubair mengadukan perihal fitnah yang menimpa Ibnu Jubair keduanya berkata; sesungguhnya orang-orang telah berbuat sesuatu kepadanya, sedangkan kamu wahai Ibnu Umar sebagai sahabat Rasulullah shallallahu 'alaihi wasallam, apa yang menghalangimu tidak ikut campur dalam urusan ini? Ibnu Umar menjawab; 'Yang menghalangiku adalah karena Allah telah mengharamkan darah saudara muslim. Lalu keduanya berkata; 'Bukankah Allah telah berfirman: \"Dan perangilah mereka sehingga tidak ada lagi fitnah?\" maka Ibnu Umar menjawab: \"Kami telah berperang hingga fitnah itu tidak ada lagi dan din ini sudah menjadi milik Allah. Sedangkan kalian menginginkan peperangan hingga terjadi fitnah dan din ini menjadi milik bukan selain Allah. ['Utsman bin Shalih] menambahkan dari [Ibnu Wahhab] dia berkata; Telah mengabarkan kepadaku Fulaan dan [Haiwah bin Syuraih] dari [Bakr bin 'Amru Al Ma'afiri] bahwa [Bukair bin 'Abdullah] Telah menceritakan kepadanya dari [Nafi'] bahwa seseorang menemui Ibnu 'Umar seraya berkata; 'Wahai Abu 'Abdur Rahman apa yang menghalangimu untuk berhaji dan berumrah pada tahun ini dan kamu meninggalkan jihad di jalan Allah padahal kamu tahu bahwa Allah sangat menganjurkan hal itu? [Ibnu Umar] menjawab; 'Wahai anak saudaraku, Islam ini dibangun atas lima dasar; Iman kepada Allah dan Rasul-Nya, shalat lima waktu, puasa dibulan Ramadlan, menunaikan zakat, dan haji ke baitullah. Laki-laki itu berkata; 'Wahai Abu Abdurrahman, apakah kamu tidak mendengar apa yang disebutkan Allah di dalam kitabnya: \"Dan kalau ada dua golongan dari mereka yang beriman itu berperang hendaklah kamu damaikan antara keduanya! Tapi kalau yang satu melanggar perjanjian terhadap yang lain, hendaklah yang melanggar perjanjian itu kamu perangi sampai kembali pada perintah Allah\". Juga firman Allah: \"Perangilah mereka hingga tidak ada fitnah.\" Ibnu Umar menjawab; 'kami telah melakukan hal itu pada masa Rasulullah shallallahu 'alaihi wasallam ketika Islam masih sedikit hingga seseorang dari kami difitnah karena agamanya, baik dengan dibunuh maupun disiksa sampai Islam semakin menyebar dan tidak ada lagi fitnah. Orang itu berkata lagi; 'Bagaimana pendapatmu tentang Utsman dan Ali? Ibnu Umar menjawab; 'Adapun Utsman maka Allah telah memaafkannya sedangkan kalian telah membenci untuk memaafkannya. Sedangkan Ali dia adalah sepupu Rasulullah shallallahu 'alaihi wasallam dan menantunya. Lalu dia mengisyaratkan dengan tangannya seraya berkata; 'Inilah rumahnya sebagaimana kamu lihat.'"},"3849":{"ar":"حَدَّثَنَا إِسْحَاقُ أَخْبَرَنَا النَّضْرُ حَدَّثَنَا شُعْبَةُ عَنْ سُلَيْمَانَ قَالَ سَمِعْتُ أَبَا وَائِلٍ عَنْ حُذَيْفَةَ{ وَأَنْفِقُوا فِي سَبِيلِ اللَّهِ وَلَا تُلْقُوا بِأَيْدِيكُمْ إِلَى التَّهْلُكَةِ }قَالَ نَزَلَتْ فِي النَّفَقَةِ","id":"Telah menceritakan kepada kami [Ishaq] Telah mengabarkan kepada kami [An Nadlr] Telah menceritakan kepada kami [Syu'bah] dari [Sulaiman] dia berkata; Aku mendengar [Abu Wa'il] dari [Hudzaifah] mengenai ayat; \"Dan infaqkanlah hartamu di jalan Allah, dan janganlah kamu jatuhkan dirimu sendiri kedalam kebinasaan dengan tanganmu sendiri.\" Ayat ini turun tentang memberi nafkah."},"3850":{"ar":"حَدَّثَنَا آدَمُ حَدَّثَنَا شُعْبَةُ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْأَصْبَهَانِيِّ قَالَ سَمِعْتُ عَبْدَ اللَّهِ بْنَ مَعْقِلٍ قَالَ قَعَدْتُ إِلَى كَعْبِ بْنِ عُجْرَةَ فِي هَذَا الْمَسْجِدِ يَعْنِي مَسْجِدَ الْكُوفَةِ فَسَأَلْتُهُ عَنْ فِدْيَةٌ مِنْ صِيَامٍفَقَالَ حُمِلْتُ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالْقَمْلُ يَتَنَاثَرُ عَلَى وَجْهِي فَقَالَ مَا كُنْتُ أُرَى أَنَّ الْجَهْدَ قَدْ بَلَغَ بِكَ هَذَا أَمَا تَجِدُ شَاةً قُلْتُ لَا قَالَ صُمْ ثَلَاثَةَ أَيَّامٍ أَوْ أَطْعِمْ سِتَّةَ مَسَاكِينَ لِكُلِّ مِسْكِينٍ نِصْفُ صَاعٍ مِنْ طَعَامٍ وَاحْلِقْ رَأْسَكَ فَنَزَلَتْ فِيَّ خَاصَّةً وَهْيَ لَكُمْ عَامَّةً","id":"Telah menceritakan kepada kami [Adam] Telah menceritakan kepada kami [Syu'bah] dari [Abdurrahman bin Al Ashbahani] dia berkata; Aku mendengar [Abdullah bin Ma'qil] dia berkata; Aku duduk mendekati [Ka'ab bin Ujrah] di masjid Kufah, lalu aku bertanya kepada Ka'ab tentang fidyah puasa. Saya pernah dibawa menghadap Rasulullah shallallahu 'alaihi wasallam sementara kutu-kutu telah bertebaran di wajahku. Maka beliau berkata: \"Saya lihat penyakitmu sudah demikian parah, apakah kamu mempunyai seekor kambing?\" saya menjawab; \"Tidak.\" Beliau bersabda: 'Berpuasalah tiga hari, atau memberi makan kepada enam orang miskin yakni sebanyak tetengah sha' untuk setiap orang dan cukurlah rambutmu.\" Ka'ab berkata; Maka ayat ini turun khusus berkenaan denganku, namun bagi kalian bersifat umum."},"3851":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ عِمْرَانَ أَبِي بَكْرٍ حَدَّثَنَا أَبُو رَجَاءٍ عَنْ عِمْرَانَ بْنِ حُصَيْنٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَأُنْزِلَتْ آيَةُ الْمُتْعَةِ فِي كِتَابِ اللَّهِ فَفَعَلْنَاهَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلَمْ يُنْزَلْ قُرْآنٌ يُحَرِّمُهُ وَلَمْ يَنْهَ عَنْهَا حَتَّى مَاتَ قَالَ رَجُلٌ بِرَأْيِهِ مَا شَاءَ","id":"Telah menceritakan kepada kami [Musaddad] Telah menceritakan kepada kami [Yahya] dari [Imran Abu Bakr] Telah menceritakan kepada kami [Abu Raja'] dari [Imran bin Hushain radliallahu 'anhuma] dia berkata; Ayat mut'ah (menggabungkan haji dan umrah) telah diturunkan di dalam kitabullah, maka kami pun melaksanakannya bersama Rasulullah shallallahu 'alaihi wasallam, dan Al qur'an tidak menurunkan ayat yang mengharamkannya, beliau pun tidak melarangnya hingga beliau wafat. sehingga seseorang dapat berbicara apa yang ia kehendaki menurut pendapatnya."},"3852":{"ar":"حَدَّثَنِي مُحَمَّدٌ قَالَ أَخْبَرَنِي ابْنُ عُيَيْنَةَ عَنْ عَمْرٍو عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَكَانَتْ عُكَاظُ وَمَجَنَّةُ وَذُو الْمَجَازِ أَسْوَاقًا فِي الْجَاهِلِيَّةِ فَتَأَثَّمُوا أَنْ يَتَّجِرُوا فِي الْمَوَاسِمِ فَنَزَلَتْ{ لَيْسَ عَلَيْكُمْ جُنَاحٌ أَنْ تَبْتَغُوا فَضْلًا مِنْ رَبِّكُمْ }فِي مَوَاسِمِ الْحَجِّ","id":"Telah menceritakan kepadaku [Muhammad] dia berkata; Telah mengabarkan kepadaku [Ibnu Uyainah] dari [Amru] dari [Ibnu Abbas radliallahu 'anhuma] dia berkata; Ukazh, Majanah, Dzul Majaz adalah pasar-pasar yang ada pada masa jahiliyah. Mereka merasa takut berdosa bila berjualan pada musim haji. Maka turunlah ayat; Bukanlah suatu dosa bagimu sekalian mencari karunia dari Rabb kalian. (QS. Albaqarah 198). Yaitu pada musim haji."},"3853":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا مُحَمَّدُ بْنُ خَازِمٍ حَدَّثَنَا هِشَامٌ عَنْ أَبِيهِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاكَانَتْ قُرَيْشٌ وَمَنْ دَانَ دِينَهَا يَقِفُونَ بِالْمُزْدَلِفَةِ وَكَانُوا يُسَمَّوْنَ الْحُمْسَ وَكَانَ سَائِرُ الْعَرَبِ يَقِفُونَ بِعَرَفَاتٍ فَلَمَّا جَاءَ الْإِسْلَامُ أَمَرَ اللَّهُ نَبِيَّهُ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يَأْتِيَ عَرَفَاتٍ ثُمَّ يَقِفَ بِهَا ثُمَّ يُفِيضَ مِنْهَا فَذَلِكَ قَوْلُهُ تَعَالَى{ ثُمَّ أَفِيضُوا مِنْ حَيْثُ أَفَاضَ النَّاسُ }","id":"Telah menceritakan kepada kami [Ali bin Abdullah] Telah menceritakan kepada kami [Muhammad bin Hazim] Telah menceritakan kepada kami [Hisyam] dari [Bapaknya] dari [Aisyah radliallahu 'anha], Suku Quraisy dan orang-orang yang memeluk agama mereka, biasa tinggal di Muzdalifah dan memanggil diri mereka sendiri dengan Al Hums, sementara orang-orang Arab lainnya biasa tinggal di Arafah. Ketika Islam datang, Allah memerintahkan Nabi shallallahu 'alaihi wasallam untuk tinggal di sana (dengan waktu yang telah ditentukan) dan kemudian berangkat dari sana. Itulah yang dimaksud firman Allah; \"Kemudian berangkatlah beramai-ramai dari tempat bertolaknya orang banyak\". (QS. Albaqarah 199)."},"3854":{"ar":"حَدَّثَنِي مُحَمَّدُ بْنُ أَبِي بَكْرٍ حَدَّثَنَا فُضَيْلُ بْنُ سُلَيْمَانَ حَدَّثَنَا مُوسَى بْنُ عُقْبَةَ أَخْبَرَنِي كُرَيْبٌ عَنْ ابْنِ عَبَّاسٍ قَالَيَطَّوَّفُ الرَّجُلُ بِالْبَيْتِ مَا كَانَ حَلَالًا حَتَّى يُهِلَّ بِالْحَجِّ فَإِذَا رَكِبَ إِلَى عَرَفَةَ فَمَنْ تَيَسَّرَ لَهُ هَدِيَّةٌ مِنْ الْإِبِلِ أَوْ الْبَقَرِ أَوْ الْغَنَمِ مَا تَيَسَّرَ لَهُ مِنْ ذَلِكَ أَيَّ ذَلِكَ شَاءَ غَيْرَ أَنَّهُ إِنْ لَمْ يَتَيَسَّرْ لَهُ فَعَلَيْهِ ثَلَاثَةُ أَيَّامٍ فِي الْحَجِّ وَذَلِكَ قَبْلَ يَوْمِ عَرَفَةَ فَإِنْ كَانَ آخِرُ يَوْمٍ مِنْ الْأَيَّامِ الثَّلَاثَةِ يَوْمَ عَرَفَةَ فَلَا جُنَاحَ عَلَيْهِ ثُمَّ لِيَنْطَلِقْ حَتَّى يَقِفَ بِعَرَفَاتٍ مِنْ صَلَاةِ الْعَصْرِ إِلَى أَنْ يَكُونَ الظَّلَامُ ثُمَّ لِيَدْفَعُوا مِنْ عَرَفَاتٍ إِذَا أَفَاضُوا مِنْهَا حَتَّى يَبْلُغُوا جَمْعًا الَّذِي يَبِيتُونَ بِهِ ثُمَّ لِيَذْكُرُوا اللَّهَ كَثِيرًا وَأَكْثِرُوا التَّكْبِيرَ وَالتَّهْلِيلَ قَبْلَ أَنْ تُصْبِحُوا ثُمَّ أَفِيضُوا فَإِنَّ النَّاسَ كَانُوا يُفِيضُونَ وَقَالَ اللَّهُ تَعَالَى{ ثُمَّ أَفِيضُوا مِنْ حَيْثُ أَفَاضَ النَّاسُ وَاسْتَغْفِرُوا اللَّهَ إِنَّ اللَّهَ غَفُورٌ رَحِيمٌ }حَتَّى تَرْمُوا الْجَمْرَةَ","id":"Telah menceritakan kepadaku [Muhammad bin Abu Bakr] Telah menceritakan kepada kami [Fudlail bin Sulaiman] Telah menceritakan kepada kami [Musa bin 'Uqbah] Telah mengabarkan kepadaku [Kuraib] dari [Ibnu 'Abbas] dia berkata; seseorang berthawaf di ka'bah setelah bertahalul hingga dia bertalbiyah untuk haji. Apabila dia hendak pergi ke Arafah, maka hendaklah dia menyembelih unta, atau sapi, atau kambing kapan saja dia kehendaki jika hal itu mudah baginya. Jika hal itu terasa sulit, maka hendaklah dia berpuasa selama tiga hari pada waktu haji, yaitu sebelum hari Arafah. Jika ternyata hari terakhirnya dari tiga hari tersebut adalah hari Arafah, maka hal itu tidak mengapa baginya. Kemudian hendaklah dia berangkat untuk wukuf di Arafah dari waktu Ashar hingga menjelang malam. Lalu berangkat dari Arafah ketika orang-orang keluar darinya hingga sampai di Muzdalifah tempat mereka bermalam. setelah itu hendaklah mereka berdzikir kepada Allah dengan memperbanyak takbir, dan tahlil sebelum subuh tiba. Kemudian bertolaklah kalian dari Arafah karena orang-orang telah bertolak. Allah Ta'ala berfirman: \"Kemudian bertolaklah dari tempat bertolaknya orang-orang banyak ('Arafah) dan mohonlah ampun kepada Allah sesungguhnya Allah Maha Pengampun lagi Maha Penyayang.\" (QS. Albaqarah 199). Hingga kalian melempar Jumrah."},"3855":{"ar":"حَدَّثَنَا أَبُو مَعْمَرٍ حَدَّثَنَا عَبْدُ الْوَارِثِ عَنْ عَبْدِ الْعَزِيزِ عَنْ أَنَسٍ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ اللَّهُمَّ{ رَبَّنَا آتِنَا فِي الدُّنْيَا حَسَنَةً وَفِي الْآخِرَةِ حَسَنَةً وَقِنَا عَذَابَ النَّارِ }","id":"Telah menceritakan kepada kami [Abu Ma'mar] Telah menceritakan kepada kami [Abdul Warits] dari [Abdul Aziz] dari [Anas] dia berkata; Nabi shallallahu 'alaihi wasallam shallallahu 'alaihi wasallam berdo'a; \"RABBANAA AATINA FID DUNYA HASANATAN WA FIL AKHIRATI HASANAH WAQIAN ADZABAN NAAR (Ya Allah berilah kami kebaikan di dunia dan di akhirat, dan lindungilah kami dari adzab neraka).\""},"3856":{"ar":"حَدَّثَنَا قَبِيصَةُ حَدَّثَنَا سُفْيَانُ عَنْ ابْنِ جُرَيْجٍ عَنْ ابْنِ أَبِي مُلَيْكَةَ عَنْ عَائِشَةَ تَرْفَعُهُ قَالَأَبْغَضُ الرِّجَالِ إِلَى اللَّهِ الْأَلَدُّ الْخَصِمُوَقَالَ عَبْدُ اللَّهِ حَدَّثَنَا سُفْيَانُ حَدَّثَنِي ابْنُ جُرَيْجٍ عَنْ ابْنِ أَبِي مُلَيْكَةَ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Qabisha] Telah menceritakan kepada kami [Sufyan] dari [Ibnu Juraij] dari [Ibnu Mulaikah] dari [Aisyah] secara marfu' dia berkata; \"Orang yang paling Allah benci adalah orang yang suka membantah dan sengit permusuhannya. [Abdullah] berkata; Telah menceritakan kepada kami [Sufyan] Telah menceritakan kepadaku [Ibnu Juraij] dari [Ibnu Mulaikah] dari [Aisyah radliallahu 'anha] dari Nabi shallallahu 'alaihi wasallam."},"3857":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ مُوسَى أَخْبَرَنَا هِشَامٌ عَنْ ابْنِ جُرَيْجٍ قَالَ سَمِعْتُ ابْنَ أَبِي مُلَيْكَةَ يَقُولُ قَالَ ابْنُ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا{ حَتَّى إِذَا اسْتَيْأَسَ الرُّسُلُ وَظَنُّوا أَنَّهُمْ قَدْ كُذِبُوا }خَفِيفَةً ذَهَبَ بِهَا هُنَاكَ وَتَلَا{ حَتَّى يَقُولَ الرَّسُولُ وَالَّذِينَ آمَنُوا مَعَهُ مَتَى نَصْرُ اللَّهِ أَلَا إِنَّ نَصْرَ اللَّهِ قَرِيبٌ }فَلَقِيتُ عُرْوَةَ بْنَ الزُّبَيْرِ فَذَكَرْتُ لَهُ ذَلِكَ فَقَالَ قَالَتْ عَائِشَةُ مَعَاذَ اللَّهِ وَاللَّهِ مَا وَعَدَ اللَّهُ رَسُولَهُ مِنْ شَيْءٍ قَطُّ إِلَّا عَلِمَ أَنَّهُ كَائِنٌ قَبْلَ أَنْ يَمُوتَ وَلَكِنْ لَمْ يَزَلْ الْبَلَاءُ بِالرُّسُلِ حَتَّى خَافُوا أَنْ يَكُونَ مَنْ مَعَهُمْ يُكَذِّبُونَهُمْ فَكَانَتْ تَقْرَؤُهَا{ وَظَنُّوا أَنَّهُمْ قَدْ كُذِّبُوا }مُثَقَّلَةً","id":"Telah menceritakan kepada kami [Ibrahim bin Musa] Telah mengabarkan kepada kami [Hisyam] dari [Ibnu Juraij] dia berkata; Aku mendengar [Ibnu Abu Mulaikah] berkata; [Ibnu Abbas radliallahu 'anhuma] berkata mengenai firman Allah: \" Sehingga apabila para rasul tidak mempunyai harapan lagi (tentang keimanan mereka) dan telah meyakini bahwa mereka telah didustakan...\" (Yusuf; 110). Perlahan-lahan Ibnu Abbas pergi sembil memikirkan ayat itu seraya membaca ayat; Sehingga berkatalah Rasul dan orang-orang yang beriman bersamanya: \"Bilakah datangnya pertolongan Allah?\" Ingatlah, sesungguhnya pertolongan Allah itu amat dekat\". (Al Baqarah: 214). Lalu aku bertemu dengan [Urwah], maka aku sebutkan tentang ayat tersebut kepadanya; dia pun menjawab; [Aisyah] berkata; demi Allah, tidaklah Allah berjanji kepada Rasul-Nya sedikitpun kecuali hal itu akan diketahui olehnya sebelum dia meninggal. Namun ujian demi ujian bagi para Rasul akan senantiasa ada hingga mereka merasa khawatir orang-orang yang bersama mereka akan ada yang mendustakannya. Aisyah seraya membaca; Mereka (para rasul) itu menyangka mereka akan didustakan."},"3858":{"ar":"حَدَّثَنَا إِسْحَاقُ أَخْبَرَنَا النَّضْرُ بْنُ شُمَيْلٍ أَخْبَرَنَا ابْنُ عَوْنٍ عَنْ نَافِعٍ قَالَ كَانَ ابْنُ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاإِذَا قَرَأَ الْقُرْآنَ لَمْ يَتَكَلَّمْ حَتَّى يَفْرُغَ مِنْهُ فَأَخَذْتُ عَلَيْهِ يَوْمًا فَقَرَأَ سُورَةَ الْبَقَرَةِ حَتَّى انْتَهَى إِلَى مَكَانٍ قَالَ تَدْرِي فِيمَ أُنْزِلَتْ قُلْتُ لَا قَالَ أُنْزِلَتْ فِي كَذَا وَكَذَا ثُمَّ مَضَىوَعَنْ عَبْدِ الصَّمَدِ حَدَّثَنِي أَبِي حَدَّثَنِي أَيُّوبُ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ{ فَأْتُوا حَرْثَكُمْ أَنَّى شِئْتُمْ }قَالَ يَأْتِيهَا فِي رَوَاهُ مُحَمَّدُ بْنُ يَحْيَى بْنِ سَعِيدٍ عَنْ أَبِيهِ عَنْ عُبَيْدِ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ","id":"Telah menceritakan kepada kami [Ishaq] Telah mengabarkan kepada kami [An Nadlr bin Syumail] Telah mengabarkan kepada kami [Ibnu Aun] dari [Nafi'] dia berkata; [Ibnu Umar radliallahu 'anhuma] apabila membaca Al Qur'an, beliau tidak berbicara hingga selesai membacanya. Pada suatu hari aku mengambil mushaf-nya, maka membaca surat Al Baqarah hingga selesai dengan hafalannya. Lalu dia berkata; tahukah kamu tentang apa surat ini turun? Aku menjawab; 'Tidak.' Dia berkata; surat ini turun tentang ini dan itu kemudian dia pergi.' Dan dari [Abdus Shamad] Telah menceritakan kepadaku [ayahku] telah menceritakan kepadaku [Ayyub] dari [Nafi] dari [Ibnu Umar] mengenai ayat; \"istri-istrimu adalah ladang bagimu maka datangilah ladang-ladangmu kapan saja sesuai yang kamu sukai\".(QS. Albaqarah 223), Ibnu Umar berkata; yaitu mendatanginya dari kemaluannya. Diriwayatkan oleh [Muhammad bin Yahyan bin Sa'id] dari [Bapaknya] dari [Ubaidullah] dari [Nafi] dari [Ibnu Umar]."},"3859":{"ar":"حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا سُفْيَانُ عَنْ ابْنِ الْمُنْكَدِرِ سَمِعْتُ جَابِرًا رَضِيَ اللَّهُ عَنْهُ قَالَكَانَتْ الْيَهُودُ تَقُولُ إِذَا جَامَعَهَا مِنْ وَرَائِهَا جَاءَ الْوَلَدُ أَحْوَلَ فَنَزَلَتْ{ نِسَاؤُكُمْ حَرْثٌ لَكُمْ فَأْتُوا حَرْثَكُمْ أَنَّى شِئْتُمْ }","id":"Telah menceritakan kepada kami [Abu Nu'aim] Telah menceritakan kepada kami [Sufyan] dari [Ibnu Al Munkadir] aku mendengar [Jabir radliallahu 'anhu] berkata; Orang-orang Yahudi berkata; Apabila menggauli wanita melalui belakang maka mata anaknya akan menjadi juling'. Lalu Allah Subhaanahu menurunkan ayat; Isteri-isteri kalian adalah ladang kalian, maka datangilah ladang kalian dari mana engkau kehendaki.\" (QS. Albaqarah 223)."},"3860":{"ar":"حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ سَعِيدٍ حَدَّثَنَا أَبُو عَامِرٍ الْعَقَدِيُّ حَدَّثَنَا عَبَّادُ بْنُ رَاشِدٍ حَدَّثَنَا الْحَسَنُ قَالَ حَدَّثَنِي مَعْقِلُ بْنُ يَسَارٍ قَالَ كَانَتْ لِي أُخْتٌ تُخْطَبُ إِلَيَّ وَقَالَ إِبْرَاهِيمُ عَنْ يُونُسَ عَنْ الْحَسَنِ حَدَّثَنِي مَعْقِلُ بْنُ يَسَارٍ ح حَدَّثَنَا أَبُو مَعْمَرٍ حَدَّثَنَا عَبْدُ الْوَارِثِ حَدَّثَنَا يُونُسُ عَنْ الْحَسَنِأَنَّ أُخْتَ مَعْقِلِ بْنِ يَسَارٍ طَلَّقَهَا زَوْجُهَا فَتَرَكَهَا حَتَّى انْقَضَتْ عِدَّتُهَا فَخَطَبَهَا فَأَبَى مَعْقِلٌ فَنَزَلَتْ{ فَلَا تَعْضُلُوهُنَّ أَنْ يَنْكِحْنَ أَزْوَاجَهُنَّ }","id":"Telah menceritakan kepada kami [Ubaidullah bin Sa'id] Telah menceritakan kepada kami [Abu Amir Al 'Aqidi] Telah menceritakan kepada kami [Abbad bin Rasyid] Telah menceritakan kepada kami [Al Hasan] dia berkata; Telah menceritakan kepadaku [Ma'qil bin Yasar] berkata; aku mempunyai saudara perempuan yang dilamar kepadaku. Dan [Ibrahim] berkata; dari [Yunus] dari [Al Hasan] telah menceritakan kepadaku [Ma'qil bin Yasar]. -diriwayatkan dari jalur lainnya- Telah menceritakan kepada kami [Abu Ma'mar] Telah menceritakan kepada kami [Abdul Warits] Telah menceritakan kepada kami [Yunus] dari [Al Hasan] bahwa saudara perempuan Ma'qil ditalak suaminya dan meninggalkannya hingga habis masa iddahnya. Kemudian dia meminangnya lagi, namun Ma'qil menolaknya. Maka turunlah ayat; Jangalah kamu halangi mereka untuk menikah lagi dengan suaminya. (QS. Albaqarah 232)."},"3861":{"ar":"حَدَّثَنِي أُمَيَّةُ بْنُ بِسْطَامٍ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ عَنْ حَبِيبٍ عَنْ ابْنِ أَبِي مُلَيْكَةَ قَالَ ابْنُ الزُّبَيْرِ قُلْتُ لِعُثْمَانَ بْنِ عَفَّانَ{ وَالَّذِينَ يُتَوَفَّوْنَ مِنْكُمْ وَيَذَرُونَ أَزْوَاجًا }قَالَ قَدْ نَسَخَتْهَا الْآيَةُ الْأُخْرَى فَلِمَ تَكْتُبُهَا أَوْ تَدَعُهَا قَالَ يَا ابْنَ أَخِي لَا أُغَيِّرُ شَيْئًا مِنْهُ مِنْ مَكَانِهِ","id":"Telah menceritakan kepadaku [Umayyah bin Bustham] Telah menceritakan kepada kami [Yazid bin Zurai'i] dari [Habib] dari [Ibnu Abu Mulaikah], [Ibnu Zubair] berkata; Aku bertanya kepada [Utsman bin Affan] mengenai ayat; Dan orang-orang yang mati di antara kamu serta meninggalkan istri-istri (Al Baqarah; 234). Dia menjawab; Ayat itu telah dinasakh dengan ayat yang lain. Lalu aku bertanya; kenapa kamu menulisnya atau membiarkannya. Dia menjawab; Wahai anak saudaraku, aku tidak akan merubahnya sedikitpun dari tempatnya."},"3862":{"ar":"حَدَّثَنَا إِسْحَاقُ حَدَّثَنَا رَوْحٌ حَدَّثَنَا شِبْلٌ عَنْ ابْنِ أَبِي نَجِيحٍ عَنْ مُجَاهِدٍ{ وَالَّذِينَ يُتَوَفَّوْنَ مِنْكُمْ وَيَذَرُونَ أَزْوَاجًا }قَالَ كَانَتْ هَذِهِ الْعِدَّةُ تَعْتَدُّ عِنْدَ أَهْلِ زَوْجِهَا وَاجِبٌ فَأَنْزَلَ اللَّهُ{ وَالَّذِينَ يُتَوَفَّوْنَ مِنْكُمْ وَيَذَرُونَ أَزْوَاجًا وَصِيَّةً لِأَزْوَاجِهِمْ مَتَاعًا إِلَى الْحَوْلِ غَيْرَ إِخْرَاجٍ فَإِنْ خَرَجْنَ فَلَا جُنَاحَ عَلَيْكُمْ فِيمَا فَعَلْنَ فِي أَنْفُسِهِنَّ مِنْ مَعْرُوفٍ }قَالَ جَعَلَ اللَّهُ لَهَا تَمَامَ السَّنَةِ سَبْعَةَ أَشْهُرٍ وَعِشْرِينَ لَيْلَةً وَصِيَّةً إِنْ شَاءَتْ سَكَنَتْ فِي وَصِيَّتِهَا وَإِنْ شَاءَتْ خَرَجَتْ وَهْوَ قَوْلُ اللَّهِ تَعَالَى{ غَيْرَ إِخْرَاجٍ فَإِنْ خَرَجْنَ فَلَا جُنَاحَ عَلَيْكُمْ }فَالْعِدَّةُ كَمَا هِيَ وَاجِبٌ عَلَيْهَا زَعَمَ ذَلِكَ عَنْ مُجَاهِدٍ وَقَالَ عَطَاءٌ قَالَ ابْنُ عَبَّاسٍنَسَخَتْ هَذِهِ الْآيَةُ عِدَّتَهَا عِنْدَ أَهْلِهَا فَتَعْتَدُّ حَيْثُ شَاءَتْ وَهْوَ قَوْلُ اللَّهِ تَعَالَى{ غَيْرَ إِخْرَاجٍ }قَالَ عَطَاءٌ إِنْ شَاءَتْ اعْتَدَّتْ عِنْدَ أَهْلِهِ وَسَكَنَتْ فِي وَصِيَّتِهَا وَإِنْ شَاءَتْ خَرَجَتْ لِقَوْلِ اللَّهِ تَعَالَى{ فَلَا جُنَاحَ عَلَيْكُمْ فِيمَا فَعَلْنَ }قَالَ عَطَاءٌ ثُمَّ جَاءَ الْمِيرَاثُ فَنَسَخَ السُّكْنَى فَتَعْتَدُّ حَيْثُ شَاءَتْ وَلَا سُكْنَى لَهَا وَعَنْ مُحَمَّدِ بْنِ يُوسُفَ حَدَّثَنَا وَرْقَاءُ عَنْ ابْنِ أَبِي نَجِيحٍ عَنْ مُجَاهِدٍ بِهَذَا وَعَنْ ابْنِ أَبِي نَجِيحٍ عَنْ عَطَاءٍ عَنْ ابْنِ عَبَّاسٍ قَالَ نَسَخَتْ هَذِهِ الْآيَةُ عِدَّتَهَا فِي أَهْلِهَا فَتَعْتَدُّ حَيْثُ شَاءَتْ لِقَوْلِ اللَّهِ{ غَيْرَ إِخْرَاجٍ }نَحْوَهُ","id":"Telah menceritakan kepada kami [Ishaq] Telah menceritakan kepada kami [Rauh] Telah menceritakan kepada kami [Syibl] dari [Ibnu Abu Najih] dari Mujahid mengenai firman Allah: Dan orang-orang yang mati di antara kamu serta meninggalkan istri-istri (Al Baqarah; 234). Ayat ini menerangkan wajibnya iddah di rumah keluarganya. Lalu Allah menurunkan ayat; Dan orang-orang yang akan mati di antara kami dan meninggalkan istri-istri, hendaklah membuat wasiat untuk istri-istrinya yaitu nafkah sampai setahun tanpa mengeluarkannya dari rumah. Tetapi jika mereka keluar sendiri, maka tidak ada dosa bagimu mengenai apa yang mereka lakukan terhadap diri mereka sendiri dalam hal-hal yang baik. Mujahid berkata; Allah telah menjadikannya sebagai penyempurna dalam hitungan setahun yaitu tujuh bulan dan dua puluh malam sebagai wasiat. Apabila dia ingin, maka dia menempati sesuai wasiat tersebut. Namun jika ia ingin keluar, maka itu sudah menjadi kehendaknya. Itulah yang dimaksud firman Allah Ta'ala: Tetapi jika mereka keluar sendiri, maka tidak ada dosa bagimu. Maka Iddah adalah perkara yang wajib. Perawi mengaku itu dari Mujahid. [Atha] berkata; [Ibnu Abbas] berkata; \"Ayat ini telah menghapus 'iddah di rumah keluarganya sehingga ia ber'iddah di tempat yang ia kehendaki, yaitu firman Allah Azza wa Jalla: 'Tanpa keluar rumah.' Atha berkata; 'Jika dia berkehendak, maka dia beriddah di rumah keluarganya dan tinggal sesuai wasiatnya.' Namun jika dia berkehendak, ia keluar darinya. Sebagaimana firman Allah Ta'ala: \"Maka tidak ada dosa bagimu mengenai apa yang mereka lakukan terhadap diri mereka senidiri.\" (QS. Albaqarah 240), Atha berkata; kemudian turun ayat mirats (mengenai warisan) yang menghapus mengenai tempat tinggal, maka dia boleh beriddah sesuai kehendaknya tanpa harus tinggal dirumahnya. Dan dari [Muhammad bin Yusuf] Telah menceritakan kepada kami [Warqa] dari [Ibnu Abu Najih] dari Mujahid dengan redaksi yang serupa. Dan dari Ibnu Abu Najih dari [Atha] dari [Ibnu Abbas] dia berkata; 'ayat ini telah menghapus 'iddahnya di rumah keluarganya sehingga ia ber'iddah di tempat yang ia kehendaki, yaitu firman Allah Azza wa Jalla: 'Tanpa keluar rumah.'"},"3863":{"ar":"حَدَّثَنَا حِبَّانُ حَدَّثَنَا عَبْدُ اللَّهِ أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ عَوْنٍ عَنْ مُحَمَّدِ بْنِ سِيرِينَ قَالَ جَلَسْتُ إِلَى مَجْلِسٍ فِيهِ عُظْمٌ مِنْ الْأَنْصَارِ وَفِيهِمْ عَبْدُ الرَّحْمَنِ بْنُ أَبِي لَيْلَى فَذَكَرْتُ حَدِيثَ عَبْدِ اللَّهِ بْنِ عُتْبَةَ فِي شَأْنِ سُبَيْعَةَ بِنْتِ الْحَارِثِ فَقَالَ عَبْدُ الرَّحْمَنِ وَلَكِنَّ عَمَّهُ كَانَ لَا يَقُولُ ذَلِكَ فَقُلْتُ إِنِّي لَجَرِيءٌ إِنْ كَذَبْتُ عَلَى رَجُلٍ فِي جَانِبِ الْكُوفَةِ وَرَفَعَ صَوْتَهُ قَالَ ثُمَّ خَرَجْتُ فَلَقِيتُ مَالِكَ بْنَ عَامِرٍ أَوْ مَالِكَ بْنَ عَوْفٍ قُلْتُ كَيْفَ كَانَ قَوْلُ ابْنِ مَسْعُودٍ فِي الْمُتَوَفَّى عَنْهَا زَوْجُهَا وَهْيَ حَامِلٌ فَقَالَ قَالَ ابْنُ مَسْعُودٍأَتَجْعَلُونَ عَلَيْهَا التَّغْلِيظَ وَلَا تَجْعَلُونَ لَهَا الرُّخْصَةَ لَنَزَلَتْ سُورَةُ النِّسَاءِ الْقُصْرَى بَعْدَ الطُّولَىوَقَالَ أَيُّوبُ عَنْ مُحَمَّدٍ لَقِيتُ أَبَا عَطِيَّةَ مَالِكَ بْنَ عَامِرٍ","id":"Telah menceritakan kepada kami [Hibban] Telah menceritakan kepada kami [Abdullah] Telah mengabarkan kepada kami [Abdullah bin Aun] dari [Muhammad bin Sirin] dia berkata; Aku duduk di sebuah majlis yang di dalamnya ada sekelompok orang-orang Anshar, di dalamnya ada Abdurrahman bin Abu Laila, lalu aku menyebutkan Hadits Abdullah bin Utbah yang menceritakan tentang Subaiah binti Al Harits. Maka Abdurrahman bin Abu Laila berkata; 'Akan tetapi pamannya tidak mengatakan hal itu. Lalu aku katakan, aku berani bertanggung jawab jika aku berdusta tentang orang yang berada di sisi Kufah -seraya mengeraskan suaranya-. Kemudian aku keluar dan bertemu dengan [Malik bin Amir], atau Malik bin Auf. Aku berkata; Bagaimana menurut Ibnu Mas'ud tentang orang yang telah ditinggal mati oleh suaminya padahal dia dalam keadaan hamil? Dia menjawab; [Ibnu Mas'ud] berkata; 'Apakah kamu akan memberatkannya dan tidak memberinya rukhsah, padahal sungguh telah turun surat Annisa' yang pendek setelah surat yang panjang (Al Baqarah)?. [Ayyub] berkata; dari [Muhammad] Aku bertemu dengan [Abu Atiyyah Malik bin Amir]."},"3864":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ حَدَّثَنَا يَزِيدُ أَخْبَرَنَا هِشَامٌ عَنْ مُحَمَّدٍ عَنْ عَبِيدَةَ عَنْ عَلِيٍّ رَضِيَ اللَّهُ عَنْهُ قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ح و حَدَّثَنِي عَبْدُ الرَّحْمَنِ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ قَالَ حَدَّثَنَا هِشَامٌ قَالَ حَدَّثَنَا مُحَمَّدٌ عَنْ عَبِيدَةَ عَنْ عَلِيٍّ رَضِيَ اللَّهُ عَنْهُأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يَوْمَ الْخَنْدَقِ حَبَسُونَا عَنْ صَلَاةِ الْوُسْطَى حَتَّى غَابَتْ الشَّمْسُ مَلَأَ اللَّهُ قُبُورَهُمْ وَبُيُوتَهُمْ أَوْ أَجْوَافَهُمْ شَكَّ يَحْيَى نَارًا","id":"Telah menceritakan kepada kami [Abdullah bin Muhammad] Telah menceritakan kepada kami [Yazid] Telah mengabarkan kepada kami [Hisyam] dari [Muhammad] dari [Abidah] dari [Ali radliallahu 'anhu] dia berkata; Nabi shallallahu 'alaihi wasallam shallallahu 'alaihi wasallam bersabda: Dan telah menceritakan kepadaku [Abdurrahman] Telah menceritakan kepada kami [Yahya bin Sa'id] dia berkata; Telah menceritakan kepada kami [Hisyam] dia berkata; Telah menceritakan kepada kami [Muhammad] dari [Abidah] dari [Ali radliallahu 'anhu] bahwa Nabi shallallahu 'alaihi wasallam bersabda pada hari perang khandak: \"Mereka telah menyibukkan kita dari shalat wustha yaitu shalat asar, hingga matahari terbenam, semoga Allah memenuhi kuburan dan rumah mereka atau perut -Yahya merasa ragu- mereka dengan api.\""},"3865":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ إِسْمَاعِيلَ بْنِ أَبِي خَالِدٍ عَنْ الْحَارِثِ بْنِ شُبَيْلٍ عَنْ أَبِي عَمْرٍو الشَّيْبَانِيِّ عَنْ زَيْدِ بْنِ أَرْقَمَ قَالَكُنَّا نَتَكَلَّمُ فِي الصَّلَاةِ يُكَلِّمُ أَحَدُنَا أَخَاهُ فِي حَاجَتِهِ حَتَّى نَزَلَتْ هَذِهِ الْآيَةُ{ حَافِظُوا عَلَى الصَّلَوَاتِ وَالصَّلَاةِ الْوُسْطَى وَقُومُوا لِلَّهِ قَانِتِينَ }فَأُمِرْنَا بِالسُّكُوتِ","id":"Telah menceritakan kepada kami [Musaddad] Telah menceritakan kepada kami [Yahya] dari [Ismail bin Abu Khalid] dari [Al Harits bin Syubail] dari [Abu Amru As Saibani] dari [Zaid bin Arqam] dia berkata; \"Kami berbincang-bincang pada waktu shalat. Seorang dari kami berbicara dengan temannya karena ada satu keperluan, hingga akhirnya turunlah ayat: \"Dan berdirilah untuk Allah dalam shalatmu dengan khusyu\". Lalu kami diperintahkan untuk diam.'"},"3866":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ حَدَّثَنَا مَالِكٌ عَنْ نَافِعٍ أَنَّ عَبْدَ اللَّهِ بْنَ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاكَانَ إِذَا سُئِلَ عَنْ صَلَاةِ الْخَوْفِ قَالَ يَتَقَدَّمُ الْإِمَامُ وَطَائِفَةٌ مِنْ النَّاسِ فَيُصَلِّي بِهِمْ الْإِمَامُ رَكْعَةً وَتَكُونُ طَائِفَةٌ مِنْهُمْ بَيْنَهُمْ وَبَيْنَ الْعَدُوِّ لَمْ يُصَلُّوا فَإِذَا صَلَّى الَّذِينَ مَعَهُ رَكْعَةً اسْتَأْخَرُوا مَكَانَ الَّذِينَ لَمْ يُصَلُّوا وَلَا يُسَلِّمُونَ وَيَتَقَدَّمُ الَّذِينَ لَمْ يُصَلُّوا فَيُصَلُّونَ مَعَهُ رَكْعَةً ثُمَّ يَنْصَرِفُ الْإِمَامُ وَقَدْ صَلَّى رَكْعَتَيْنِ فَيَقُومُ كُلُّ وَاحِدٍ مِنْ الطَّائِفَتَيْنِ فَيُصَلُّونَ لِأَنْفُسِهِمْ رَكْعَةً بَعْدَ أَنْ يَنْصَرِفَ الْإِمَامُ فَيَكُونُ كُلُّ وَاحِدٍ مِنْ الطَّائِفَتَيْنِ قَدْ صَلَّى رَكْعَتَيْنِ فَإِنْ كَانَ خَوْفٌ هُوَ أَشَدَّ مِنْ ذَلِكَ صَلَّوْا رِجَالًا قِيَامًا عَلَى أَقْدَامِهِمْ أَوْ رُكْبَانًا مُسْتَقْبِلِي الْقِبْلَةِ أَوْ غَيْرَ مُسْتَقْبِلِيهَا قَالَ مَالِكٌ قَالَ نَافِعٌ لَا أُرَى عَبْدَ اللَّهِ بْنَ عُمَرَ ذَكَرَ ذَلِكَ إِلَّا عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Abdullah bin Yusuf] Telah menceritakan kepada kami [Malik] dari [Nafi'] bahwa [Abdullah bin Umar radliallahu 'anhuma] apabila ditanya tentang shalat khauf dia menjawab; \"Seorang imam maju bersama sekelompok orang, lalu shalat satu rekaat bersama mereka. Sedangkan sekelompok yang lain yang berada antara imam dengan musuh belum mengerjakan shalat. Jika orang-orang yang shalat bersama imam telah selesai, mereka mundur ke tempat orang-orang yang belum shalat dan mereka belum salam. Kelompok yang belum shalat maju dan shalat bersama imam satu rekaat. Imam pergi dan dia telah shalat dua rekaat. Maka semua dari dua kelompok itu berdiri dan menyempurnakan shalat mereka satu rekaat, satu rekaat, setelah perginya imam. Setiap kelompok itu telah menyempurnakan dua rekaaat. Jika keadaan lebih menakutkan daripada itu, mereka shalat dengan berjalan kaki atau dengan menunggangi tunggangan, baik menghadap qiblat atau tidak.\" Malik berkata, Nafi' berkata; \"Saya tidak melihat Abdullah bin Umar menceritakannya melainkan dari Rasulullah shallallahu 'alaihi wasallam.\""},"3867":{"ar":"حَدَّثَنِي عَبْدُ اللَّهِ بْنُ أَبِي الْأَسْوَدِ حَدَّثَنَا حُمَيْدُ بْنُ الْأَسْوَدِ وَيَزِيدُ بْنُ زُرَيْعٍ قَالَا حَدَّثَنَا حَبِيبُ بْنُ الشَّهِيدِ عَنْ ابْنِ أَبِي مُلَيْكَةَ قَالَ قَالَ ابْنُ الزُّبَيْرِقُلْتُ لِعُثْمَانَ هَذِهِ الْآيَةُ الَّتِي فِي الْبَقَرَةِ{ وَالَّذِينَ يُتَوَفَّوْنَ مِنْكُمْ وَيَذَرُونَ أَزْوَاجًا إِلَى قَوْلِهِ غَيْرَ إِخْرَاجٍ }قَدْ نَسَخَتْهَا الْأُخْرَى فَلِمَ تَكْتُبُهَا قَالَ تَدَعُهَا يَا ابْنَ أَخِي لَا أُغَيِّرُ شَيْئًا مِنْهُ مِنْ مَكَانِهِقَالَ حُمَيْدٌ أَوْ نَحْوَ هَذَا","id":"Telah menceritakan kepadaku [Abdullah bin Abu Al Aswad] Telah menceritakan kepada kami [Humaid bin Al Aswad] dan [Yazid bin Zurai'i] keduanya berkata; Telah menceritakan kepada kami [Habib bin Syahid] dari [Ibnu Abu Mulaikah] dia berkata; [Ibnu Zubair] berkata; Aku bertanya kepada [Utsman] tentang ayat yang terdapat dalam surah Al Baqarah yaitu: Dan orang-orang yang mati di antara kamu serta meninggalkan istri-istri, -hingga ayat-; 'tanpa keluar rumah. (Al Baqarah; 234). Dia menjawab; Ayat itu telah dinasakh dengan ayat yang lain. Lalu aku bertanya; kenapa kamu menulisnya? Dia menjawab; Wahai anak saudaraku, apakah kamu akan meninggalkannya? aku tidak akan merubahnya sedikitpun dari tempatnya. Humaid berkata; atau perkataan yang serupa dengan ini."},"3868":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ صَالِحٍ حَدَّثَنَا ابْنُ وَهْبٍ أَخْبَرَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ عَنْ أَبِي سَلَمَةَ وَسَعِيدٍ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْنُ أَحَقُّ بِالشَّكِّ مِنْ إِبْرَاهِيمَ إِذْ قَالَ{ رَبِّ أَرِنِي كَيْفَ تُحْيِي الْمَوْتَى قَالَ أَوَلَمْ تُؤْمِنْ قَالَ بَلَى وَلَكِنْ لِيَطْمَئِنَّ قَلْبِي }","id":"Telah menceritakan kepada kami [Ahmad bin Shalih] Telah menceritakan kepada kami [Ibnu Wahab] Telah mengabarkan kepadaku [Yunus] dari [Ibnu Syihab] dari [Abu Salamah] dan [Sa'id] dari [Abu Hurairah radliallahu 'anhu] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda:: \"Aku lebih berhak untuk ragu dari pada Ibrahim 'Alaihis Salam ketika ia berkata; \"Wahai Tuhanku perlihatkanlah kepada saya bagaimana Engkau menghidupkan orang-orang yang telah mati, \" Allah berfirman: \"Apakah kamu tidak beriman?\" Ibrahim berkata; \"Tentu aku telah beriman, hanya agar hatiku lebih mantap.\""},"3869":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ أَخْبَرَنَا هِشَامٌ عَنْ ابْنِ جُرَيْجٍ سَمِعْتُ عَبْدَ اللَّهِ بْنَ أَبِي مُلَيْكَةَ يُحَدِّثُ عَنْ ابْنِ عَبَّاسٍ قَالَ وَسَمِعْتُ أَخَاهُ أَبَا بَكْرِ بْنَ أَبِي مُلَيْكَةَ يُحَدِّثُ عَنْ عُبَيْدِ بْنِ عُمَيْرٍ قَالَ قَالَ عُمَرُ رَضِيَ اللَّهُ عَنْهُ يَوْمًا لِأَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِيمَ تَرَوْنَ هَذِهِ الْآيَةَ نَزَلَتْ{ أَيَوَدُّ أَحَدُكُمْ أَنْ تَكُونَ لَهُ جَنَّةٌ }قَالُوا اللَّهُ أَعْلَمُ فَغَضِبَ عُمَرُ فَقَالَ قُولُوا نَعْلَمُ أَوْ لَا نَعْلَمُ فَقَالَ ابْنُ عَبَّاسٍ فِي نَفْسِي مِنْهَا شَيْءٌ يَا أَمِيرَ الْمُؤْمِنِينَ قَالَ عُمَرُ يَا ابْنَ أَخِي قُلْ وَلَا تَحْقِرْ نَفْسَكَ قَالَ ابْنُ عَبَّاسٍ ضُرِبَتْ مَثَلًا لِعَمَلٍ قَالَ عُمَرُ أَيُّ عَمَلٍ قَالَ ابْنُ عَبَّاسٍ لِعَمَلٍ قَالَ عُمَرُ لِرَجُلٍ غَنِيٍّ يَعْمَلُ بِطَاعَةِ اللَّهِ عَزَّ وَجَلَّ ثُمَّ بَعَثَ اللَّهُ لَهُ الشَّيْطَانَ فَعَمِلَ بِالْمَعَاصِي حَتَّى أَغْرَقَ أَعْمَالَهُ","id":"Telah menceritakan kepada kami [Ibrahim] Telah mengabarkan kepada kami [Hisyam] dari [Ibnu Juraij] Aku mendengar [Abdullah bin Abu Mulaikah] bercerita dari [Ibnu Abbas] dia berkata; dan aku juga mendengar saudaranya yaitu [Abu Bakr bin Abu Mulaikah] bercerita dari [Ubaid bin Umair] dia berkata; Pada suatu hari [Umar radliallahu 'anhu] berkata kepada para sahabat Nabi shallallahu 'alaihi wasallam; Menurut kalian berkenaan dengan apakah ayat ini; \"Adakah salah seorang dari kalian yang ingin memiliki kebun…. (al Baqarah; 266). Para sahabat menjawab; 'Allahu A'lam.' Maka Umar pun marah, seraya berkata; Katakan kami tahu atau kami tidak tahu. Kemudian Ibnu Abbas berkata; 'aku mengerti sedikit tentang ayat itu ya Amirul Mukminin. Umar berkata; Wahai anak saudaraku, katakanlah! Jangan kamu cela dirimu sendiri. Ibnu Abbas berkata; ayat itu membuat sebuah perumpamaan tentang suatu amalan. Umar berkata; Amalan apakah? Ibnu Abbas menjawab; tentang suatu amalan. Umar melanjutkan; yaitu tentang seorang laki-laki yang kaya, lalu dia beramal dengan menta'ati Allah Azza Wa Jalla. Kemudian Allah mengutus syetan kepadanya. Maka ia pun melakukan maksiat hingga ia tenggelamkan amalan kebaikan yang telah dilakukannya."},"3870":{"ar":"حَدَّثَنَا ابْنُ أَبِي مَرْيَمَ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ قَالَ حَدَّثَنِي شَرِيكُ بْنُ أَبِي نَمِرٍ أَنَّ عَطَاءَ بْنَ يَسَارٍ وَعَبْدَ الرَّحْمَنِ بْنَ أَبِي عَمْرَةَ الْأَنْصَارِيَّ قَالَا سَمِعْنَا أَبَا هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ يَقُولُقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيْسَ الْمِسْكِينُ الَّذِي تَرُدُّهُ التَّمْرَةُ وَالتَّمْرَتَانِ وَلَا اللُّقْمَةُ وَلَا اللُّقْمَتَانِ إِنَّمَا الْمِسْكِينُ الَّذِي يَتَعَفَّفُ وَاقْرَءُوا إِنْ شِئْتُمْ يَعْنِي قَوْلَهُ{ لَا يَسْأَلُونَ النَّاسَ إِلْحَافًا }","id":"Telah menceritakan kepada kami [Ibnu Abu Maryam] Telah menceritakan kepada kami [Muhammad bin Ja'far] dia berkata; Telah menceritakan kepadaku [Syarik bin Abu Namir] bahwa [Atha bin Yasar] dan [Abdurrahman bin Abu 'Amrah Al Anshari] keduanya berkata; Kami mendengar [Abu Hurairah radliallahu 'anhu] berkata; Nabi shallallahu 'alaihi wasallam bersabda: \"Orang yang miskin bukanlah orang yang merasa telah cukup dengan satu atau dua buah kurma, atau sesuap atau dua suap makanan. Tetapi orang miskin adalah orang yang tidak meminta-minta dan menunjukan kemiskinannya kepada orang lain. Jika kalian mau, bacalah firman Allah: \"Mereka tidak meminta-minta kepada orang lain.\" (Al Baqarah: 273)."},"3871":{"ar":"حَدَّثَنَا عُمَرُ بْنُ حَفْصِ بْنِ غِيَاثٍ حَدَّثَنَا أَبِي حَدَّثَنَا الْأَعْمَشُ حَدَّثَنَا مُسْلِمٌ عَنْ مَسْرُوقٍ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْلَمَّا نَزَلَتْ الْآيَاتُ مِنْ آخِرِ سُورَةِ الْبَقَرَةِ فِي الرِّبَا قَرَأَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى النَّاسِ ثُمَّ حَرَّمَ التِّجَارَةَ فِي الْخَمْرِ","id":"Telah menceritakan kepada kami [Umar bin Hafsh bin Giyats] Telah menceritakan kepada kami [Bapakku] Telah menceritakan kepada kami [Al A'masy] Telah menceritakan kepada kami [Muslim] dari [Masruq] dari [Aisyah radliallahu 'anha] dia berkata; 'Beberapa ayat terakhir dari surat al Baqarah turun mengenai riba. Rasulullah shallallahu 'alaihi wasallam membacakannya kepada orang-orang, kemudian beliau mengharamkan jual beli khamr (minuman keras)."},"3872":{"ar":"حَدَّثَنَا بِشْرُ بْنُ خَالِدٍ أَخْبَرَنَا مُحَمَّدُ بْنُ جَعْفَرٍ عَنْ شُعْبَةَ عَنْ سُلَيْمَانَ الْأَعْمَشِ سَمِعْتُ أَبَا الضُّحَى يُحَدِّثُ عَنْ مَسْرُوقٍ عَنْ عَائِشَةَ أَنَّهَا قَالَتْلَمَّا أُنْزِلَتْ الْآيَاتُ الْأَوَاخِرُ مِنْ سُورَةِ الْبَقَرَةِ خَرَجَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَتَلَاهُنَّ فِي الْمَسْجِدِ فَحَرَّمَ التِّجَارَةَ فِي الْخَمْرِ","id":"Telah menceritakan kepada kami [Bisyr bin Khalid] Telah mengabarkan kepada kami [Muhammad bin Ja'far] dari [Syu'bah] dari [Sulaiman Al A'masy] Aku mendengar [Abu ADluha] bercerita dari [Masruq] dari [Aisyah] dia berkata; Tatkala turun beberapa ayat terakhir dari surat Al Baqarah, Rasulullah shallallahu 'alaihi wasallam keluar lalu membacakannya di masjid. Kemudian beliau mengharamkan jual beli minuman keras.'"},"3873":{"ar":"حَدَّثَنِي مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا غُنْدَرٌ حَدَّثَنَا شُعْبَةُ عَنْ مَنْصُورٍ عَنْ أَبِي الضُّحَى عَنْ مَسْرُوقٍ عَنْ عَائِشَةَ قَالَتْلَمَّا أُنْزِلَتْ الْآيَاتُ مِنْ آخِرِ سُورَةِ الْبَقَرَةِ قَرَأَهُنَّ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَيْهِمْ فِي الْمَسْجِدِ وَحَرَّمَ التِّجَارَةَ فِي الْخَمْرِ","id":"Telah menceritakan kepadaku [Muhammad bin Basyar] Telah menceritakan kepada kami [Gundar] Telah menceritakan kepada kami [Syu'bah] dari [Manshur] dari [Abu Dluha] dari [Masruq] dari [Aisyah] dia berkata; Tatkala beberapa ayat terakhir dari surat Al Baqarah diturunkan, Rasulullah shallallahu 'alaihi wasallam membacakannya di masjid dan beliau mengharamkan jual beli minuman keras.'"},"3874":{"ar":"وَ قَالَ لَنَا مُحَمَّدُ بْنُ يُوسُفَ عَنْ سُفْيَانَ عَنْ مَنْصُورٍ وَالْأَعْمَشِ عَنْ أَبِي الضُّحَى عَنْ مَسْرُوقٍ عَنْ عَائِشَةَ قَالَتْلَمَّا أُنْزِلَتْ الْآيَاتُ مِنْ آخِرِ سُورَةِ الْبَقَرَةِ قَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَرَأَهُنَّ عَلَيْنَا ثُمَّ حَرَّمَ التِّجَارَةَ فِي الْخَمْرِ","id":"Dan [Muhammad bin Yusuf] berkata kepada kami; dari [Sufyan] dari [Manshur] dan [Al A'masy] dari [Abu Ad Dluha] dari [Masruq] dari [Aisyah] dia berkata; Tatkala beberapa ayat terakhir dari surat Al Baqarah diturunkan, Rasulullah shallallahu 'alaihi wasallam berdiri membacakannya kepada kami kemudian beliau mengharamkan jual beli minuman keras.'"},"3875":{"ar":"حَدَّثَنَا قَبِيصَةُ بْنُ عُقْبَةَ حَدَّثَنَا سُفْيَانُ عَنْ عَاصِمٍ عَنْ الشَّعْبِيِّ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَآخِرُ آيَةٍ نَزَلَتْ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ آيَةُ الرِّبَا","id":"Telah menceritakan kepada kami [Qabishah bin Uqbah] Telah menceritakan kepada kami [Sufyan] dari ['Ashim] dari [As Sya'bi] dari [Ibnu Abbas radliallahu 'anhuma] dia berkata; Ayat terakhir yang di turunkan kepada Nabi shallallahu 'alaihi wasallam adalah ayat tentang riba.'"},"3876":{"ar":"حَدَّثَنَا مُحَمَّدٌ حَدَّثَنَا النُّفَيْلِيُّ حَدَّثَنَا مِسْكِينٌ عَنْ شُعْبَةَ عَنْ خَالِدٍ الْحَذَّاءِ عَنْ مَرْوَانَ الْأَصْفَرِ عَنْ رَجُلٍ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهْوَ ابْنُ عُمَرَأَنَّهَا قَدْ نُسِخَتْ{ وَإِنْ تُبْدُوا مَا فِي أَنْفُسِكُمْ أَوْ تُخْفُوهُ }الْآيَةَ","id":"Telah menceritakan kepada kami [Muhammad] Telah menceritakan kepada kami [An Nafali] Telah menceritakan kepada kami [Miskin] dari [Syu'bah] dari [Khalid Al Hadza] dari [Marwan Al Ashfar] dari salah seorang sahabat Nabi shallallahu 'alaihi wasallam yaitu [Ibnu Umar]; bahwa ayat; \"Jika kalian menampakkan apa yang ada dalam diri kalian atau menyembunyikannya\" (al Baqarah: 284) telah di naskh.'"},"3877":{"ar":"حَدَّثَنِي إِسْحَاقُ بْنُ مَنْصُورٍ أَخْبَرَنَا رَوْحٌ أَخْبَرَنَا شُعْبَةُ عَنْ خَالِدٍ الْحَذَّاءِ عَنْ مَرْوَانَ الْأَصْفَرِ عَنْ رَجُلٍ مِنْ أَصْحَابِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَحْسِبُهُ ابْنَ عُمَرَ{ إِنْ تُبْدُوا مَا فِي أَنْفُسِكُمْ أَوْ تُخْفُوهُ }قَالَ نَسَخَتْهَا الْآيَةُ الَّتِي بَعْدَهَا","id":"Telah menceritakan kepadaku [Ishaq bin Manshur] Telah mengabarkan kepada kami [Rauh] Telah mengabarkan kepada kami [Syubah] dari [Khalid Al Hadza] dari [Marwan Al Ashfar] dari salah seorang sahabat Rasulullah shallallahu 'alaihi wasallam yang aku kira [Ibnu Umar] mengenai firman Allah; \"Jika kalian menampakkan apa yang ada dalam diri kalian atau menyembunyikannya\" (Al Baqarah: 284). Ibnu Umar berkata; Ayat ini telah dinaskh oleh ayat sesudahnya."},"3878":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ حَدَّثَنَا يَزِيدُ بْنُ إِبْرَاهِيمَ التُّسْتَرِيُّ عَنْ ابْنِ أَبِي مُلَيْكَةَ عَنْ الْقَاسِمِ بْنِ مُحَمَّدٍ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْتَلَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَذِهِ الْآيَةَ{ هُوَ الَّذِي أَنْزَلَ عَلَيْكَ الْكِتَابَ مِنْهُ آيَاتٌ مُحْكَمَاتٌ هُنَّ أُمُّ الْكِتَابِ وَأُخَرُ مُتَشَابِهَاتٌ فَأَمَّا الَّذِينَ فِي قُلُوبِهِمْ زَيْغٌ فَيَتَّبِعُونَ مَا تَشَابَهَ مِنْهُ ابْتِغَاءَ الْفِتْنَةِ وَابْتِغَاءَ تَأْوِيلِهِ وَمَا يَعْلَمُ تَأْوِيلَهُ إِلَّا اللَّهُ وَالرَّاسِخُونَ فِي الْعِلْمِ يَقُولُونَ آمَنَّا بِهِ كُلٌّ مِنْ عِنْدِ رَبِّنَا وَمَا يَذَّكَّرُ إِلَّا أُولُو الْأَلْبَابِ }قَالَتْ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَإِذَا رَأَيْتِ الَّذِينَ يَتَّبِعُونَ مَا تَشَابَهَ مِنْهُ فَأُولَئِكِ الَّذِينَ سَمَّى اللَّهُ فَاحْذَرُوهُمْ","id":"Telah menceritakan kepada kami [Abdullah bin Maslamah] Telah menceritakan kepada kami [Yazid bin Ibrahim At Tustari] dari [Ibnu Abu Mulaikah] dari [Al Qasim bin Muhammad] dari [Aisyah radliallahu 'anha] dia berkata; Rasulullah shallallahu 'alaihi wasallam membaca ayat ini; \"Dia-lah yang menurunkan Al Kitab (Al Quran) kepada kamu. di antara (isi) nya ada ayat-ayat yang muhkamaat, Itulah pokok-pokok isi Al Qur'an dan yang lain (ayat-ayat) mutasyaabihaat. adapun orang-orang yang dalam hatinya condong kepada kesesatan, maka mereka mengikuti sebahagian ayat-ayat yang mutasyaabihaat darinya untuk menimbulkan fitnah untuk mencari-cari ta'wilnya, padahal tidak ada yang mengetahui ta'wilnya melainkan Allah. Dan orang-orang yang mendalam ilmunya berkata; Kami beriman kepada Al Qur'an seluruhnya dari Rabb kami. Dan tidak ada yang dapat mengambil pelajaran kecuali orang-orang yang memiliki akal pikiran. (Ali Imran: 7). Aisyah berkata; kemudian Rasulullah shallaallahu 'alaihi wa sallam bersabda: \"Apabila kalian melihat orang-orang yang mengikuti sebahagian ayat-ayat yang mutasyaabihaat, maka mereka itulah adalah orang-orang yang disebutkan oleh Allah, Maka Waspadalah kalian terhadap mereka!\""},"3879":{"ar":"حَدَّثَنِي عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَا مِنْ مَوْلُودٍ يُولَدُ إِلَّا وَالشَّيْطَانُ يَمَسُّهُ حِينَ يُولَدُ فَيَسْتَهِلُّ صَارِخًا مِنْ مَسِّ الشَّيْطَانِ إِيَّاهُ إِلَّا مَرْيَمَ وَابْنَهَا ثُمَّ يَقُولُ أَبُو هُرَيْرَةَ وَاقْرَءُوا إِنْ شِئْتُمْ{ وَإِنِّي أُعِيذُهَا بِكَ وَذُرِّيَّتَهَا مِنْ الشَّيْطَانِ الرَّجِيمِ }","id":"Telah menceritakan kepadaku [Abdullah bin Muhammad] Telah menceritakan kepada kami [Abdurrazaq] Telah mengabarkan kepada kami [Ma'mar] dari [Az Zuhri] dari [Sa'id bin Al Musayyab] dari [Abu Hurairah radliallahu 'anhu] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Tidaklah bayi yang dilahirkan kecuali setan akan menyentuhnya ketika ia lahir, sehingga mereka menangis keras karena sentuhan setan tersebut, kecuali Maryam dan putranya.\" Lalu Abu Hurairah berkata; \"Jika kalian mau bacalah; \"dan aku mohon perlindungan untuknya serta anak-anak keturunannya kepada (pemeliharaan) Engkau daripada syaitan yang terkutuk.\" (Ali Imran: 36)."},"3880":{"ar":"حَدَّثَنَا حَجَّاجُ بْنُ مِنْهَالٍ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ الْأَعْمَشِ عَنْ أَبِي وَائِلٍ عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ حَلَفَ يَمِينَ صَبْرٍ لِيَقْتَطِعَ بِهَا مَالَ امْرِئٍ مُسْلِمٍ لَقِيَ اللَّهَ وَهْوَ عَلَيْهِ غَضْبَانُ فَأَنْزَلَ اللَّهُ تَصْدِيقَ ذَلِكَ{ إِنَّ الَّذِينَ يَشْتَرُونَ بِعَهْدِ اللَّهِ وَأَيْمَانِهِمْ ثَمَنًا قَلِيلًا أُولَئِكَ لَا خَلَاقَ لَهُمْ فِي الْآخِرَةِ }إِلَى آخِرِ الْآيَةِقَالَ فَدَخَلَ الْأَشْعَثُ بْنُ قَيْسٍ وَقَالَ مَا يُحَدِّثُكُمْ أَبُو عَبْدِ الرَّحْمَنِ قُلْنَا كَذَا وَكَذَا قَالَ فِيَّ أُنْزِلَتْ كَانَتْ لِي بِئْرٌ فِي أَرْضِ ابْنِ عَمٍّ لِي قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَيِّنَتُكَ أَوْ يَمِينُهُ فَقُلْتُ إِذًا يَحْلِفَ يَا رَسُولَ اللَّهِ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ حَلَفَ عَلَى يَمِينِ صَبْرٍ يَقْتَطِعُ بِهَا مَالَ امْرِئٍ مُسْلِمٍ وَهْوَ فِيهَا فَاجِرٌ لَقِيَ اللَّهَ وَهْوَ عَلَيْهِ غَضْبَانٌ","id":"Telah menceritakan kepada kami [Hajjaj bin Minhal] Telah menceritakan kepada kami [Abu 'Awanah] dari [Al A'masy] dari [Abu Wa'il] dari [Abdullah bin Mas'ud radliallahu 'anhu] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa bersumpah palsu atas sesuatu, yang dengannya ingin merampas harta seorang muslim, maka ia akan berjumpa dengan Allah sementara Ia murka kepadanya.\" Sebagai pembenaran hal itu Allah telah menurunkan ayat: \"Sesungguhnya orang-orang yang menukar janji (nya dengan) Allah dan sumpah-sumpah mereka dengan harga yang sedikit, mereka itu tidak mendapat bahagian (pahala) di akhirat, dan Allah tidak akan berkata-kata dengan mereka dan tidak akan melihat kepada mereka pada hari kiamat dan tidak (pula) akan mensucikan mereka. Bagi mereka azab yang pedih.\" (Ali Imran: 77). Maka [Asy'ats bin Qais] masuk seraya bertanya; Apa yang dikatakan Abdurrahman kepada kalian? Kami menjawab; begini dan begitu. Dia berkata; ayat itu berkenaan denganku; Aku mempunyai sebuah sumur disebidang tanah milik sepupuku. Nabi shallallahu 'alaihi wasallam shallallahu 'alaihi wasallam bersabda: yang menjadi keputusan sekarang adalah pengakuanmu atau sumpahnya. Aku berkata; 'Kalau begitu dia yang bersumpah ya Rasulullah! Nabi shallallahu 'alaihi wasallam bersabda: \"Barangsiapa bersumpah palsu atas sesuatu, yang dengannya ingin merampas harta seorang muslim, dan dia menjadi pelaku kejahatan karenanya, maka ia akan berjumpa dengan Allah sementara Ia murka kepadanya.\""},"3881":{"ar":"حَدَّثَنَا عَلِيٌّ هُوَ ابْنُ أَبِي هَاشِمٍ سَمِعَ هُشَيْمًا أَخْبَرَنَا الْعَوَّامُ بْنُ حَوْشَبٍ عَنْ إِبْرَاهِيمَ بْنِ عَبْدِ الرَّحْمَنِ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي أَوْفَى رَضِيَ اللَّهُ عَنْهُمَاأَنَّ رَجُلًا أَقَامَ سِلْعَةً فِي السُّوقِ فَحَلَفَ فِيهَا لَقَدْ أَعْطَى بِهَا مَا لَمْ يُعْطِهِ لِيُوقِعَ فِيهَا رَجُلًا مِنْ الْمُسْلِمِينَ فَنَزَلَتْ{ إِنَّ الَّذِينَ يَشْتَرُونَ بِعَهْدِ اللَّهِ وَأَيْمَانِهِمْ ثَمَنًا قَلِيلًا }إِلَى آخِرِ الْآيَةِ","id":"Telah menceritakan kepada kami [Ali yaitu Ibnu Abu Hasyim] dia mendengar [Husyaim], Telah mengabarkan kepada kami [Al 'Awwam bin Hausyab] dari [Ibrahim bin Abdurrahman] dari [Abdullah bin Abu Aufa radliallahu 'anhuma] bahwa seorang laki-laki menjual barang di pasar, lalu dia bersumpah bahwa di telah memberikan barangnya padahal belum dia berikan, hal itu dia lakukan untuk merayu seorang muslim agar membeli barangnya. Maka turunlah ayat; \"Sesungguhnya orang-orang yang menukar janji (nya dengan) Allah dan sumpah-sumpah mereka dengan harga yang sedikit, mereka itu tidak mendapat bahagian (pahala) di akhirat, dan Allah tidak akan berkata-kata dengan mereka dan tidak akan melihat kepada mereka pada hari kiamat dan tidak (pula) akan mensucikan mereka. Bagi mereka azab yang pedih.\" (Ali Imran: 77)."},"3882":{"ar":"حَدَّثَنَا نَصْرُ بْنُ عَلِيِّ بْنِ نَصْرٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ دَاوُدَ عَنْ ابْنِ جُرَيْجٍ عَنْ ابْنِ أَبِي مُلَيْكَةَأَنَّ امْرَأَتَيْنِ كَانَتَا تَخْرِزَانِ فِي بَيْتٍ أَوْ فِي الْحُجْرَةِ فَخَرَجَتْ إِحْدَاهُمَا وَقَدْ أُنْفِذَ بِإِشْفَى فِي كَفِّهَا فَادَّعَتْ عَلَى الْأُخْرَى فَرُفِعَ إِلَى ابْنِ عَبَّاسٍ فَقَالَ ابْنُ عَبَّاسٍ قَالَ رَسُولُ اللَّه�� صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَوْ يُعْطَى النَّاسُ بِدَعْوَاهُمْ لذَهَبَ دِمَاءُ قَوْمٍ وَأَمْوَالُهُمْ ذَكِّرُوهَا بِاللَّهِ وَاقْرَءُوا عَلَيْهَا{ إِنَّ الَّذِينَ يَشْتَرُونَ بِعَهْدِ اللَّهِ }فَذَكَّرُوهَا فَاعْتَرَفَتْ فَقَالَ ابْنُ عَبَّاسٍ قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْيَمِينُ عَلَى الْمُدَّعَى عَلَيْهِ","id":"Telah menceritakan kepada kami [Nashr bin 'Ali bin Nashr]; Telah menceritakan kepada kami ['Abdullah bin Daud] dari [Juraij] dari [Ibnu Abu Mulaikah] bahwa dua orang wanita pernah menjahit kulit di sebuah rumah atau di sebuah kamar. Lalu salah seorang dari mereka keluar seraya membawa alat jahitnya ditelapak tangannya. Lalu dia menuduh temannya yang mengambil. Akhirnya hal itu dilaporkan kepada Ibnu Abbas. [Ibnu Abbas] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kalau orang-orang di benarkan sesuai dengan pengakuannya maka akan hilanglah darah dan harta suatu kaum. Ingatkanlah ia dengan Allah dan bacakanlah kepadanya firman Allah: \"Sesungguhnya orang-orang yang menukar janji (nya dengan) Allah dan sumpah-sumpah mereka...\" (Al Imran: 77). Lalu perempuan itu mengakuinya. Kemudian Ibnu Abbas berkata; Nabi shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya sumpah itu berlaku bagi orang yang dituduh.\""},"3883":{"ar":"حَدَّثَنِي إِبْرَاهِيمُ بْنُ مُوسَى عَنْ هِشَامٍ عَنْ مَعْمَرٍ ح و حَدَّثَنِي عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي عُبَيْدُ اللَّهِ بْنُ عَبْدِ اللَّهِ بْنِ عُتْبَةَ قَالَ حَدَّثَنِي ابْنُ عَبَّاسٍ قَالَ حَدَّثَنِي أَبُو سُفْيَانَ مِنْ فِيهِ إِلَى فِيَّ قَالَانْطَلَقْتُ فِي الْمُدَّةِ الَّتِي كَانَتْ بَيْنِي وَبَيْنَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فَبَيْنَا أَنَا بِالشَّأْمِ إِذْ جِيءَ بِكِتَابٍ مِنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى هِرَقْلَ قَالَ وَكَانَ دَحْيَةُ الْكَلْبِيُّ جَاءَ بِهِ فَدَفَعَهُ إِلَى عَظِيمِ بُصْرَى فَدَفَعَهُ عَظِيمُ بُصْرَى إِلَى هِرَقْلَ قَالَ فَقَالَ هِرَقْلُ هَلْ هَا هُنَا أَحَدٌ مِنْ قَوْمِ هَذَا الرَّجُلِ الَّذِي يَزْعُمُ أَنَّهُ نَبِيٌّ فَقَالُوا نَعَمْ قَالَ فَدُعِيتُ فِي نَفَرٍ مِنْ قُرَيْشٍ فَدَخَلْنَا عَلَى هِرَقْلَ فَأُجْلِسْنَا بَيْنَ يَدَيْهِ فَقَالَ أَيُّكُمْ أَقْرَبُ نَسَبًا مِنْ هَذَا الرَّجُلِ الَّذِي يَزْعُمُ أَنَّهُ نَبِيٌّ فَقَالَ أَبُو سُفْيَانَ فَقُلْتُ أَنَا فَأَجْلَسُونِي بَيْنَ يَدَيْهِ وَأَجْلَسُوا أَصْحَابِي خَلْفِي ثُمَّ دَعَا بِتَرْجُمَانِهِ فَقَالَ قُلْ لَهُمْ إِنِّي سَائِلٌ هَذَا عَنْ هَذَا الرَّجُلِ الَّذِي يَزْعُمُ أَنَّهُ نَبِيٌّ فَإِنْ كَذَبَنِي فَكَذِّبُوهُ قَالَ أَبُو سُفْيَانَ وَايْمُ اللَّهِ لَوْلَا أَنْ يُؤْثِرُوا عَلَيَّ الْكَذِبَ لَكَذَبْتُ ثُمَّ قَالَ لِتَرْجُمَانِهِ سَلْهُ كَيْفَ حَسَبُهُ فِيكُمْ قَالَ قُلْتُ هُوَ فِينَا ذُو حَسَبٍ قَالَ فَهَلْ كَانَ مِنْ آبَائِهِ مَلِكٌ قَالَ قُلْتُ لَا قَالَ فَهَلْ كُنْتُمْ تَتَّهِمُونَهُ بِالْكَذِبِ قَبْلَ أَنْ يَقُولَ مَا قَالَ قُلْتُ لَا قَالَ أَيَتَّبِعُهُ أَشْرَافُ النَّاسِ أَمْ ضُعَفَاؤُهُمْ قَالَ قُلْتُ بَلْ ضُعَفَاؤُهُمْ قَالَ يَزِيدُونَ أَوْ يَنْقُصُونَ قَالَ قُلْتُ لَا بَلْ يَزِيدُونَ قَالَ هَلْ يَرْتَدُّ أَحَدٌ مِنْهُمْ عَنْ دِينِهِ بَعْدَ أَنْ يَدْخُلَ فِيهِ سَخْطَةً لَهُ قَالَ قُلْتُ لَا قَالَ فَهَلْ قَاتَلْتُمُوهُ قَالَ قُلْتُ نَعَمْ قَالَ فَكَيْفَ كَانَ قِتَالُكُمْ إِيَّاهُ قَالَ قُلْتُ تَكُونُ الْحَرْبُ بَيْنَنَا وَبَيْنَهُ سِجَالًا يُصِيبُ مِنَّا وَنُصِيبُ مِنْهُ قَالَ فَهَلْ يَغْدِرُ قَالَ قُلْتُ لَا وَنَحْنُ مِنْهُ فِي هَذِهِ الْمُدَّةِ لَا نَدْرِي مَا هُوَ صَانِعٌ فِيهَا قَالَ وَاللَّهِ مَا أَمْكَنَنِي مِنْ كَلِمَةٍ أُدْخِلُ فِيهَا شَيْئًا غَيْرَ هَذِهِ قَالَ فَهَلْ قَالَ هَذَا الْقَوْلَ أَحَدٌ قَبْلَهُ قُلْتُ لَا ثُمَّ قَالَ لِتُرْجُمَانِهِ قُلْ لَهُ إِنِّي سَأَلْتُكَ عَنْ حَسَبِهِ فِيكُمْ فَزَعَمْتَ أَنَّهُ فِيكُمْ ذُو حَسَبٍ وَكَذَلِكَ الرُّسُلُ تُبْعَثُ فِي أَحْسَابِ قَوْمِهَا وَسَأَلْتُكَ هَلْ كَانَ فِي آبَائِهِ مَلِكٌ فَزَعَمْتَ أَنْ لَا فَقُلْتُ لَوْ كَانَ مِنْ آبَائِهِ مَلِكٌ قُلْتُ رَجُلٌ يَطْلُبُ مُلْكَ آبَائِهِ وَسَأَلْتُكَ عَنْ أَتْبَاعِهِ أَضُعَفَاؤُهُمْ أَمْ أَشْرَافُهُمْ فَقُلْتَ بَلْ ضُعَفَاؤُهُمْ وَهُمْ أَتْبَاعُ الرُّسُلِ وَسَأَلْتُكَ هَلْ كُنْتُمْ تَتَّهِمُونَهُ بِالْكَذِبِ قَبْلَ أَنْ يَقُولَ مَا قَالَ فَزَعَمْتَ أَنْ لَا فَعَرَفْتُ أَنَّهُ لَمْ يَكُنْ لِيَدَعَ الْكَذِبَ عَلَى النَّاسِ ثُمَّ يَذْهَبَ فَيَكْذِبَ عَلَى اللَّهِ وَسَأَلْتُكَ هَلْ يَرْتَدُّ أَحَدٌ مِنْهُمْ عَنْ دِينِهِ بَعْدَ أَنْ يَدْخُلَ فِيهِ سَخْطَةً لَهُ فَزَعَمْتَ أَنْ لَا وَكَذَلِكَ الْإِيمَانُ إِذَا خَالَطَ بَشَاشَةَ الْقُلُوبِ وَسَأَلْتُكَ هَلْ يَزِيدُونَ أَمْ يَنْقُصُونَ فَزَعَمْتَ أَنَّهُمْ يُزِيدُونَ وَكَذَلِكَ الْإِيمَانُ حَتَّى يَتِمَّ وَسَأَلْتُكَ هَلْ قَاتَلْتُمُوهُ فَزَعَمْتَ أَنَّكُمْ قَاتَلْتُمُوهُ فَتَكُونُ الْحَرْبُ بَيْنَكُمْ وَبَيْنَهُ سِجَالًا يَنَالُ مِنْكُمْ وَتَنَالُونَ مِنْهُ وَكَذَلِكَ الرُّسُلُ تُبْتَلَى ثُمَّ تَكُونُ لَهُمْ الْعَاقِبَةُ وَسَأَلْتُكَ هَلْ يَغْدِرُ فَزَعَمْتَ أَنَّهُ لَا يَغْدِرُ وَكَذَلِكَ الرُّسُلُ لَا تَغْدِرُ وَسَأَلْتُكَ هَلْ قَالَ أَحَدٌ هَذَا الْقَوْلَ قَبْلَهُ فَزَعَمْتَ أَنْ لَا فَقُلْتُ لَوْ كَانَ قَالَ هَذَا الْقَوْلَ أَحَدٌ قَبْلَهُ قُلْتُ رَجُلٌ ائْتَمَّ بِقَوْلٍ قِيلَ قَبْلَهُ قَالَ ثُمَّ قَالَ بِمَ يَأْمُرُكُمْ قَالَ قُلْتُ يَأْمُرُنَا بِالصَّلَاةِ وَالزَّكَاةِ وَالصِّلَةِ وَالْعَفَافِ قَالَ إِنْ يَكُ مَا تَقُولُ فِيهِ حَقًّا فَإِنَّهُ نَبِيٌّ وَقَدْ كُنْتُ أَعْلَمُ أَنَّهُ خَارِجٌ وَلَمْ أَكُ أَظُنُّهُ مِنْكُمْ وَلَوْ أَنِّي أَعْلَمُ أَنِّي أَخْلُصُ إِلَيْهِ لَأَحْبَبْتُ لِقَاءَهُ وَلَوْ كُنْتُ عِنْدَهُ لَغَسَلْتُ عَنْ قَدَمَيْهِ وَلَيَبْلُغَنَّ مُلْكُهُ مَا تَحْتَ قَدَمَيَّ قَالَ ثُمَّ دَعَا بِكِتَابِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَرَأَهُ فَإِذَا فِيهِ بِسْمِ اللَّهِ الرَّحْمَنِ الرَّحِيمِ مِنْ مُحَمَّدٍ رَسُولِ اللَّهِ إِلَى هِرَقْلَ عَظِيمِ الرُّومِ سَلَامٌ عَلَى مَنْ اتَّبَعَ الْهُدَى أَمَّا بَعْدُ فَإِنِّي أَدْعُوكَ بِدِعَايَةِ الْإِسْلَامِ أَسْلِمْ تَسْلَمْ وَأَسْلِمْ يُؤْتِكَ اللَّهُ أَجْرَكَ مَرَّتَيْنِ فَإِنْ تَوَلَّيْتَ فَإِنَّ عَلَيْكَ إِثْمَ الْأَرِيسِيِّينَ وَ{ يَا أَهْلَ الْكِتَابِ تَعَالَوْا إِلَى كَلِمَةٍ سَوَاءٍ بَيْنَنَا وَبَيْنَكُمْ أَنْ لَا نَعْبُدَ إِلَّا اللَّهَ إِلَى قَوْلِهِ اشْهَدُوا بِأَنَّا مُسْلِمُونَ }فَلَمَّا فَرَغَ مِنْ قِرَاءَةِ الْكِتَابِ ارْتَفَعَتْ الْأَصْوَاتُ عِنْدَهُ وَكَثُرَ اللَّغَطُ وَأُمِرَ بِنَا فَأُخْرِجْنَا قَالَ فَقُلْتُ لِأَصْحَابِي حِينَ خَرَجْنَا لَقَدْ أَمِرَ أَمْرُ ابْنِ أَبِي كَبْشَةَ إِنَّهُ لَيَخَافُهُ مَلِكُ بَنِي الْأَصْفَرِ فَمَا زِلْتُ مُوقِنًا بِأَمْرِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ سَيَظْهَرُ حَتَّى أَدْخَلَ اللَّهُ عَلَيَّ الْإِسْلَامَ قَالَ الزُّهْرِيُّ فَدَعَا هِرَقْلُ عُظَمَاءَ الرُّومِ فَجَمَعَهُمْ فِي دَارٍ لَهُ فَقَالَ يَا مَعْشَرَ الرُّومِ هَلْ لَكُمْ فِي الْفَلَاحِ وَالرَّشَدِ آخِرَ الْأَبَدِ وَأَنْ يَثْبُتَ لَكُمْ مُلْكُكُمْ قَالَ فَحَاصُوا حَيْصَةَ حُمُرِ الْوَحْشِ إِلَى الْأَبْوَابِ فَوَجَدُوهَا قَدْ غُلِّقَتْ فَقَالَ عَلَيَّ بِهِمْ فَدَعَا بِهِمْ فَقَالَ إِنِّي إِنَّمَا اخْتَبَرْتُ شِدَّتَكُمْ عَلَى دِينِكُمْ فَقَدْ رَأَيْتُ مِنْكُمْ الَّذِي أَحْبَبْتُ فَسَجَدُوا لَهُ وَرَضُوا عَنْهُ","id":"Telah menceritakan kepadaku [Ibrahim bin Musa] dari [Hisyam] dari [Ma'mar]; Demikian juga diriwayatkan dari jalur lainnya, Dan telah menceritakan kepadaku ['Abdullah bin Muhammad]; Telah menceritakan kepada kami ['Abdur Razzaq]; Telah mengabarkan kepada kami [Ma'mar] dari [Az Zuhri] berkata; Telah mengabarkan kepadaku ['Ubaidullah bin 'Abdullah bin 'Utbah] berkata; Telah menceritakan kepadaku [Ibnu 'Abbas] berkata; Telah menceritakan kepadaku [Abu Sufyan] dari lisannya ke lisanku, ia berkata; Aku berangkat pada masa-masa Rasulullah shallallahu 'alaihi wasallam diutus. Dan ketika aku berada di Syam, ada sebuah surat dari Rasulullah shallallahu 'alaihi wasallam kepada Kaisar Ramawi, yang membawa surat itu adalah Dahyah Al Kalbi, lalu ia menyerahkan kepada pembesar Bashrah, kemudian pembesar Bashrah menyerahkannya kepada Kaisra Ramawi. Abu Sufyan berkata; Maka Kaisar berkata; Apakah di sini ada seseorang yang berasal dari kaum orang yang mengaku nabi ini? Mereka menjawab; 'Ya.' Lalu aku dipanggil bersama orang-orang Quraisy. Kami pun masuk menemui Kaisar, kemudian disuruh duduk dihadapannya. Kaisar berkata; Siapakah di antara kalian yang lebih dekat nasabnya dengan orang yang mengaku nabi ini? Abu Sufyan berkata; Aku menjawab; 'Aku.' Lalu mereka mendudukkanku lebih depan lagi. Sedangkan para sahabatku duduk dibelakangku. Kemudian dipanggilah penerjamah. Kaisar berkata; Katakan kepada orang ini, bahwa aku akan menanyakannya tentang orang yang mengaku nabi itu, apabila ia berdusta, maka dustakanlah. Abu Sufyan berkata; Demi Allah, kalaulah berdusta itu menguntungkanku tentu aku akan berdusta. Kaisar bertanya kepada penerjemahnya; Bagaimana kedudukannya diantara kalian? Aku menjawab; ia mempunyai kedudukan diantara kami. Kaisar berkata; Apakah dari nenek moyangnya ada seorang raja? Aku menjawab; 'Tidak ada.' Kaisar bertanya; Apakah kalian menganggapnya sebagai pendusta sebelum ia menyerukan dakwahnya? Aku menjawab; Tidak.' Kaisar bertanya; 'Apakah yang mengikutinya dari kalangan bangsawan atau dari kalangan orang-orang lemah? Aku menjawab; 'Bahkan dari kalangan orang-orang yang lemah.' Kaisar bertanya: 'Apakah jumlahnya semakin banyak atau semakin berkurang? ' AKu menjawab; 'Semakin bertambah. Kaisar berkata; 'Apakah diantara pengikutnya ada yang murtad setelah ia masuk Islam, karena menyesal dan benci kepadanya? Aku menjawab; 'Tidak ada.' Kaisar bertanya; Apakah kalian memeranginya? Aku menjawab; Ya. Kaisar bertanya; 'Bagaimana kalian memeranginya? Aku menjawab; kami memeranginya secara bergantian kadang kami menang, dan kadang kami yang kalah.' Kaisar bertanya; Apakah ia berkhianat? Dan kami tidak tahu apa yang dia lakukan sekarang. Abu Sufyan berkata; Demi Allah, Tidak ada yang dapat aku katakana kecuali itu. Kemudian Kaisar berkata; Apakah ada yang menyerukan sebelumnya seperti apa yang ia serukan. Aku menjawab; Tidak. Lalu Kaisar berkata kepada penerjemahnya; \"Katakan padanya, Sesungguhnya aku tanyakan padamu tentang nasab keturunannya, lalu kau sebutkan bahwa ia mempunyai nasab yang terhormat, memang begitulah para rasul, mereka diutus (dari keluarga) yang mempunyai nasab luhur di antara kaumnya. Aku tanyakan padamu apakah ada seseorang dari kalian yang menyerukan kepada hal ini sebelumnya, engkau jawab belum pernah, menurutku, Bila ada orang yang pernah menyeru kepada hal ini sebelumnya, niscaya aku akan berkata; 'Dia Cuma mengikuti perkataan yang pernah diucapkan sebelumnya.' Aku tanyakan apakah kalian pernah menuduhnya berdusta sebelum ia mengatakan ini (mengaku menjadi Nabi), kau jawab belum pernah. Aku tahu tidaklah mungkin ia meninggalkan perkataan dusta kepada manusia kemudian dia berani berbohong kepada Allah 'azza wajalla. Aku tanyakan apakah kakek-kakeknya ada yang pernah menjadi raja, kau jawab tidak ada. Menurutku, Bila ada di antara kakek-kakeknya menjadi raja, pasti aku katakan; 'Dia hanya ingin mengembalikan kekuasaan leluhurnya.' Aku tanyakan kepadamu, apakah pemuka-pemuka masyarakat yang menjadi pengikutnya ataukah orang-orang lemah di antara mereka, kau jawab, orang-orang lemahlah yang mengikutinya. (Aku tahu), memang orang-orang lemahlah pengikut para rasul. Aku tanyakan kepadamu, apakah mereka bertambah atau berkurang, kau jawab bahwa mereka selalu bertambah. Begitulah halnya perkara iman sampai ia sempurna. Aku tanyakan kepadamu, apakah ada seseorang yang murtad karena benci kepada agamanya setelah memeluknya, kau jawab, tidak ada. Begitulah halnya perkara iman ketika telah bercampur pesonanya dengan hati, tidak seorang pun membencinya. Aku tanyakan kepadamu, apakah ia pernah berkhianat, kau jawab, belum pernah. Begitulah para rasul, mereka tidak pernah berkhianat. Aku tanyakan kepadamu, apakah kalian memeranginya dan dia pun memerangi kalian, kau jawab, bahwa itu memang terjadi, dan peperangan kalian dengannya seimbang. Kadang kalian menang dan kadang kalah. Demikian juga para rasul, mereka mendapati berbagai ujian lalu memperoleh hasil yang baik. Lalu Kaisar bertanya; \"Dia menyuruh kalian untuk apa?\" Abu Sufyan berkata; Aku menjawab; \"Dia menyuruh kami agar menyembah Allah semata dan tidak mempersekutukanNya dengan sesuatu pun. Dia juga melarang kami dari menyembah sesembahan nenek moyang kami. Serta menyuruh kami untuk shalat, berkata jujur, menjaga kehormatan, menepati janji dan menunaikan amanah.\" Kaisar berkata; Ini adalah sifat nabi. Aku tahu bahwa dia akan diutus, tapi aku tidak menyangka bahwa dia dari (bangsa) kalian. Jika apa yang telah kau katakan adalah benar, maka ia akan dapat memiliki tempat kedua kakiku berdiri ini. Demi Allah, jika saja aku dapat memastikan bahwa aku akan bertemu dengannya niscaya aku memilih bertemu dengannya. Jika ada di sisinya, pasti aku cuci kedua kakinya (sebagai bentuk penghormatan).\" Abu Sufyan berkata; Kemudian ia meminta Surat Rasulullah shallallahu 'alaihi wasallam dan membacakan. Isi surat itu; BISMILLAHIRRAHMAANIRRAHIIM (dengan nama Allah yang maha Pengasih lagi maha Penyayang). Dari Muhammad hamba Allah dan Rasul-Nya kepada Heraclius penguasa Romawi, semoga keselamatan menyertai siapa saja yang mengikuti petunjuk (kebenaran). Amma Ba'du. Sesungguhnya aku menyerumu untuk memenuhi panggilan Islam, masuk Islamlah niscaya engkau selamat. Dan masuk Islamlah, niscaya Allah akan memberikan pahalaNya padamu dua kali lipat. Tapi jika engkau berpaling (menolak), maka engkau akan menanggung seluruh dosa orang-orang Romawi. Dan \"Katakanlah: 'Hai Ahli Kitab, marilah (berpegang) kepada suatu kalimat (ketetapan) yang tidak ada perselisihan antara kami dan kamu, bahwa tidak kita sembah kecuali Allah dan tidak kita persekutukan dia dengan sesuatupun dan tidak (pula) sebagian kita menjadikan sebagian yang lain sebagai Tuhan selain Allah'. jika mereka berpaling Maka Katakanlah kepada mereka: 'Saksikanlah, bahwa kami adalah orang-orang yang berserah diri (kepada Allah) '\". Setelah ia selesai dengan bacaannya, terjadilah kegaduhan di antara para pembesar Romawi yang ada di sekitarnya, dan menjadi semakin ribut, sehingga aku tidak tahu apa yang mereka katakan. Lalu keluarlah perintah, dan kami dibawa keluar. Abu Sufyan berkata; Ketika aku dan kawan-kawanku telah keluar dan menyelesaikan urusanku dengan mereka, aku berkata pada mereka; \"Urusan Ibnu Abu Kabsyah telah menjadikan ia ditakuti oleh raja-raja Bani Al Ashfar (kulit kuning).\" Abu Sufyan berkata; Demi Allah. Aku senantiasa meyakini bahwa Muhammad akan meraih kejayaan, hingga akhirnya Allah memasukkan Islam ke dalam hatiku. Az Zuhri berkata; lalu Kaisar Ramawi menyeru para pembesar Ramawi dan mengumpulkan mereka di rumahnya. Ia berseru; Wahai bangsa Ruum, Apakah kalian mau menang dan jaya selama-lamanya? Dan kerajaan kalian tetap langgeng? Lalu mereka berontak dengan marah dan melempari pintu, hingga pintunya ditutup. Lalu Kaisar berkata; Sesungguhnya aku hanya ingin menguji kalian apakah kalian masih mencintai agama kalian atau tidak, dan sungguh aku telah melihat kalian dalam keadaan yang aku sukai. Lalu merekapun bersujud dan ridla atas ungkapan kaisar."},"3884":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ قَالَ حَدَّثَنِي مَالِكٌ عَنْ إِسْحَاقَ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي طَلْحَةَ أَنَّهُ سَمِعَ أَنَسَ بْنَ مَالِكٍ رَضِيَ اللَّهُ عَنْهُ يَقُولُكَانَ أَبُو طَلْحَةَ أَكْثَرَ أَنْصَارِيٍّ بِالْمَدِينَةِ نَخْلًا وَكَانَ أَحَبَّ أَمْوَالِهِ إِلَيْهِ بَيْرُحَاءَ وَكَانَتْ مُسْتَقْبِلَةَ الْمَسْجِدِ وَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَدْخُلُهَا وَيَشْرَبُ مِنْ مَاءٍ فِيهَا طَيِّبٍ فَلَمَّا أُنْزِلَتْ{ لَنْ تَنَالُوا الْبِرَّ حَتَّى تُنْفِقُوا مِمَّا تُحِبُّونَ }قَامَ أَبُو طَلْحَةَ فَقَالَ يَا رَسُولَ اللَّهِ إِنَّ اللَّهَ يَقُولُ{ لَنْ تَنَالُوا الْبِرَّ حَتَّى تُنْفِقُوا مِمَّا تُحِبُّونَ }وَإِنَّ أَحَبَّ أَمْوَالِي إِلَيَّ بَيْرُحَاءَ وَإِنَّهَا صَدَقَةٌ لِلَّهِ أَرْجُو بِرَّهَا وَذُخْرَهَا عِنْدَ اللَّهِ فَضَعْهَا يَا رَسُولَ اللَّهِ حَيْثُ أَرَاكَ اللَّهُ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَخْ ذَلِكَ مَالٌ رَايِحٌ ذَلِكَ مَالٌ رَايِحٌ وَقَدْ سَمِعْتُ مَا قُلْتَ وَإِنِّي أَرَى أَنْ تَجْعَلَهَا فِي الْأَقْرَبِينَ قَالَ أَبُو طَلْحَةَ أَفْعَلُ يَا رَسُولَ اللَّهِ فَقَسَمَهَا أَبُو طَلْحَةَ فِي أَقَارِبِهِ وَفِي بَنِي عَمِّهِقَالَ عَبْدُ اللَّهِ بْنُ يُوسُفَ وَرَوْحُ بْنُ عُبَادَةَ ذَلِكَ مَالٌ رَابِحٌ حَدَّثَنِي يَحْيَى بْنُ يَحْيَى قَالَ قَرَأْتُ عَلَى مَالِكٍ مَالٌ رَايِحٌ حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ الْأَنْصَارِيُّ قَالَ حَدَّثَنِي أَبِي عَنْ ثُمَامَةَ عَنْ أَنَسٍ رَضِيَ اللَّهُ عَنْهُ قَالَ فَجَعَلَهَا لِحَسَّانَ وَأُبَيٍّ وَأَنَا أَقْرَبُ إِلَيْهِ وَلَمْ يَجْعَلْ لِي مِنْهَا شَيْئًا","id":"Telah menceritakan kepada kami [Isma'il] berkata; Telah menceritakan kepadaku [Malik] dari [Ishaq bin 'Abdullah bin Abu Thalhah] bahwasanya dia mendengar [Anas bin Malik radliallahu 'anhu] berkata; Abu Thalhah adalah orang Anshar yang paling banyak pohon kurmanya. Dan harta yang paling ia sukai dari harta miliknya adalah Bairuha` (kebun) yang berhadapan dengan masjid. Nabi shallallahu 'alaihi wasallam biasa masuk ke dalamnya untuk minum airnya yang jernih segar. ketika turun ayat: \"Kamu sekali-kali tidak akan mendapatkan kebajikan (yang sempurna) sebelum kamu menafkahkan sebahagian harta yang kamu cintai. Maka Abu Thalhah berkata; \"Wahai Rasulullah, sesungguhnya Allah telah berfirman: Kamu sekali-kali tidak sampai kepada kebajikan (yang sempurna), sebelum kamu menafkahkan sebahagian harta yang kamu cintai, dan harta yang paling aku sukai adalah Bairuha`, maka ia sekarang adalah sedekah bagi Allah 'azza wajalla. Dan aku mengharap kebaikan dan simpanannya di sisi Allah. Wahai Rasulullah, sekarang aturlah ia sesukamu.\" Maka Nabi shallallahu 'alaihi wasallam pun bersabda: \"Amboi, itu adalah harta yang menguntungkan, itu adalah harta yang menguntungkan! Aku telah mendengar apa yang telah kamu katakan, namun aku melihat sepertinya lebih baik itu engkau sedekahkan untuk kerabat-kerabatmu.\" Lalu Abu Thalhah berkata; \"Wahai Rasulullah, aku akan melakukannya.\" Maka Abu Thalhah pun membagi-bagikan kepada kerabat dan anak-anak pamannya.\" ['Abdullah bin Yusuf] dan [Rauh bin 'Ubadah] berkata; 'Itulah harta yang rabih (menguntungkan). Telah menceritakan kepadaku [Yahya bin Yahya] dia berkata; Aku membaca Hadits [Malik] dengan lafazh; 'Maal Rayih.' (harta yang menguntungkan). Telah menceritakan kepada kami [Muhammad bin 'Abdullah Al Anshari] dia berkata; Telah menceritakan kepadaku [Bapakku] dari [Tsumamah] dari [Anas radliallahu 'anhu] berkata; 'Maka harta itu dibagikan kepada Hassan dan Ubay, dan akupun termasuk kerabat yang paling dekat dengannya namun dia tidak memberikannya kepadaku sedikit pun.'"},"3885":{"ar":"حَدَّثَنِي إِبْرَاهِيمُ بْنُ الْمُنْذِرِ حَدَّثَنَا أَبُو ضَمْرَةَ حَدَّثَنَا مُوسَى بْنُ عُقْبَةَ عَنْ نَافِعٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ الْيَهُودَ جَاءُوا إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِرَجُلٍ مِنْهُمْ وَامْرَأَةٍ قَدْ زَنَيَا فَقَالَ لَهُمْ كَيْفَ تَفْعَلُونَ بِمَنْ زَنَى مِنْكُمْ قَالُوا نُحَمِّمُهُمَا وَنَضْرِبُهُمَا فَقَالَ لَا تَجِدُونَ فِي التَّوْرَاةِ الرَّجْمَ فَقَالُوا لَا نَجِدُ فِيهَا شَيْئًا فَقَالَ لَهُمْ عَبْدُ اللَّهِ بْنُ سَلَامٍ كَذَبْتُمْ فَأْتُوا بِالتَّوْرَاةِ فَاتْلُوهَا إِنْ كُنْتُمْ صَادِقِينَ فَوَضَعَ مِدْرَاسُهَا الَّذِي يُدَرِّسُهَا مِنْهُمْ كَفَّهُ عَلَى آيَةِ الرَّجْمِ فَطَفِقَ يَقْرَأُ مَا دُونَ يَدِهِ وَمَا وَرَاءَهَا وَلَا يَقْرَأُ آيَةَ الرَّجْمِ فَنَزَعَ يَدَهُ عَنْ آيَةِ الرَّجْمِ فَقَالَ مَا هَذِهِ فَلَمَّا رَأَوْا ذَلِكَ قَالُوا هِيَ آيَةُ الرَّجْمِ فَأَمَرَ بِهِمَا فَرُجِمَا قَرِيبًا مِنْ حَيْثُ مَوْضِعُ الْجَنَائِزِ عِنْدَ الْمَسْجِدِ فَرَأَيْتُ صَاحِبَهَا يَحْنِي عَلَيْهَا يَقِيهَا الْحِجَارَةَ","id":"Telah menceritakan kepadaku [Ibrahim bin Al Mundzir] Telah menceritakan kepada kami [Abu Dlamrah]; Telah menceritakan kepada kami [Musa bin 'Uqbah] dari [Nafi'] dari ['Abdullah bin 'Umar radliallahu 'anhu] bahwa orang-orang Yahudi menemui Nabi shallallahu 'alaihi wasallam dengan membawa seorang laki-laki dan seorang perempuan yang telah berzina. Lalu Nabi shallallahu 'alaihi wasallam bertanya kepada mereka: 'Apa yang kalian lakukan kepada orang yang berzina? ' Mereka menjawab; 'Kami mencoret-coret wajah keduanya dengan warna hitam dan memukulnya. Nabi shallallahu 'alaihi wasallam bersabda: 'Apakah kalian tidak menemukan hukuman rajam di dalam Taurat? Mereka menjawab; 'Kami tidak mendapatkannya sedikit pun. Maka Abdullah bin Salam berkata kepada mereka; 'Kalian telah berdusta, datangkanlah Taurat kalian dan bacalah jika kalian orang-orang yang jujur.' Maka mereka pun meletakan kitab yang mereka pelajari dan di antara mereka ada yang menutupinya dengan tangan pada ayat rajam, dengan cepat dia membaca apa yang ada disamping kanan kirinya tanpa membaca ayat rajam. Abdullah Salam pun segera menyingkirkan tangannya, seraya berkata; 'Apa ini? ' Tatkala mereka melihat hal itu, mereka menjawab; 'ini adalah ayat rajam.' Maka Rasulullah shallallahu 'alaihi wasallam menyuruh untuk merajam keduanya di dekat kuburan samping masjid. Kata Abdullah; 'Aku melihat lelakinya melindungi dan menutupi wanitanya dari lemparan batu dengan cara membungkukkan badannya.'"},"3886":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يُوسُفَ عَنْ سُفْيَانَ عَنْ مَيْسَرَةَ عَنْ أَبِي حَازِمٍ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ{ كُنْتُمْ خَيْرَ أُمَّةٍ أُخْرِجَتْ لِلنَّاسِ }قَالَ خَيْرَ النَّاسِ لِلنَّاسِ تَأْتُونَ بِهِمْ فِي السَّلَاسِلِ فِي أَعْنَاقِهِمْ حَتَّى يَدْخُلُوا فِي الْإِسْلَامِ","id":"Telah menceritakan kepada kami [Muhammad bin Yusuf] dari [Sufyan] dari [Maisarah] dari [Abu Hazim] dari [Abu Hurairah radliallahu 'anhu] mengomentari ayat \"Kalian adalah sebaik-baik umat yang diutus kepada seluruh manusia.\" (QS.Ali Imran 110), kata Abu Hurairah; 'Sebaik-baik manusia untuk manusia, adalah kalian membawa mereka dengan dirantai, hingga mereka masuk Islam.'"},"3887":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا سُفْيَانُ قَالَ قَالَ عَمْرٌو سَمِعْتُ جَابِرَ بْنَ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُمَا يَقُولُفِينَا نَزَلَتْ{ إِذْ هَمَّتْ طَائِفَتَانِ مِنْكُمْ أَنْ تَفْشَلَا وَاللَّهُ وَلِيُّهُمَا }قَالَ نَحْنُ الطَّائِفَتَانِ بَنُو حَارِثَةَ وَبَنُو سَلِمَةَ وَمَا نُحِبُّوَقَالَ سُفْيَانُ مَرَّةً وَمَا يَسُرُّنِي أَنَّهَا لَمْ تُنْزَلْ لِقَوْلِ اللَّهِ{ وَاللَّهُ وَلِيُّهُمَا }","id":"Telah menceritakan kepada kami ['Ali bin 'Abdullah] Telah menceritakan kepada kami [Sufyan] berkata; ['Amru] berkata; Aku mendengar [Jabir bin 'Abdullah radliallahu 'anhuma] berkata mengenai firman Allah: ketika dua golongan dari padamu ingin (mundur) karena takut, padahal Allah adalah penolong bagi kedua golongan itu... (Ali Imran: 122). Dia berkata; Kamilah dua kelompok itu, yaitu Bani Haritsah dan Bani Salamah, tidaklah aku menyukainya -sedangkan dalam riwayat lain Sufyan berkata; - dan tidaklah yang membuatku senang kecuali karena ayat itu diturunkan berupa firman Allah; Padahal Allah adalah penolong kedua golongan itu.\""},"3888":{"ar":"حَدَّثَنَا حِبَّانُ بْنُ مُوسَى أَخْبَرَنَا عَبْدُ اللَّهِ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ قَالَ حَدَّثَنِي سَالِمٌ عَنْ أَبِيهِ أَنَّهُسَمِعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا رَفَعَ رَأْسَهُ مِنْ الرُّكُوعِ فِي الرَّكْعَةِ الْآخِرَةِ مِنْ الْفَجْرِ يَقُولُ اللَّهُمَّ الْعَنْ فُلَانًا وَفُلَانًا وَفُلَانًا بَعْدَ مَا يَقُولُ سَمِعَ اللَّهُ لِمَنْ حَمِدَهُ رَبَّنَا وَلَكَ الْحَمْدُ فَأَنْزَلَ اللَّهُ{ لَيْسَ لَكَ مِنْ الْأَمْرِ شَيْءٌ إِلَى قَوْلِهِ فَإِنَّهُمْ ظَالِمُونَ }رَوَاهُ إِسْحَاقُ بْنُ رَاشِدٍ عَنْ الزُّهْرِيِّ","id":"Telah menceritakan kepada kami [Hibban bin Musa] Telah mengabarkan kepada kami ['Abdullah] Telah mengabarkan kepada kami [Ma'mar] dari [Az Zuhri] berkata; Telah menceritakan kepadaku [Salim] dari [Bapaknya] bahwasanya dia mendengar Rasulullah shallallahu 'alaihi wasallam ketika beliau mengangkat kepalanya dari ruku pada raka'at terakhir dari shalat subuh beliau berdoa: \"Ya Allah laknatlah fulan dan fulan.\" yaitu setelah beliau membaca; 'Sami'allah hu Liman Hamidah.' maka Allah menurunkan ayat; \"Tak ada sedikitpun campur tanganmu dalam urusan mereka itu atau Allah menerima taubat mereka, atau mengazab mereka karena sesungguhnya mereka itu orang-orang yang zalim (Ali Imran: 128).\" diriwayatkan oleh [Ishaq bin Rasyid] dari [Az Zuhri]."},"3889":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ حَدَّثَنَا إِبْرَاهِيمُ بْنُ سَعْدٍ حَدَّثَنَا ابْنُ شِهَابٍ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ وَأَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا أَرَادَ أَنْ يَدْعُوَ عَلَى أَحَدٍ أَوْ يَدْعُوَ لِأَحَدٍ قَنَتَ بَعْدَ الرُّكُوعِ فَرُبَّمَا قَالَ إِذَا قَالَ سَمِعَ اللَّهُ لِمَنْ حَمِدَهُ اللَّهُمَّ رَبَّنَا لَكَ الْحَمْدُ اللَّهُمَّ أَنْجِ الْوَلِيدَ بْنَ الْوَلِيدِ وَسَلَمَةَ بْنَ هِشَامٍ وَعَيَّاشَ بْنَ أَبِي رَبِيعَةَ اللَّهُمَّ اشْدُدْ وَطْأَتَكَ عَلَى مُضَرَ وَاجْعَلْهَا سِنِينَ كَسِنِي يُوسُفَ يَجْهَرُ بِذَلِكَ وَكَانَ يَقُولُ فِي بَعْضِ صَلَاتِهِ فِي صَلَاةِ الْفَجْرِ اللَّهُمَّ الْعَنْ فُلَانًا وَفُلَانًا لِأَحْيَاءٍ مِنْ الْعَرَبِ حَتَّى أَنْزَلَ اللَّهُ{ لَيْسَ لَكَ مِنْ الْأَمْرِ شَيْءٌ }الْآيَةَ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] Telah menceritakan kepada kami [Ibrahim bin Sa'ad] Telah menceritakan kepada kami [Ibnu Syihab] dari [Sa'id bin Al Musayyab] dan [Abu Salamah bin 'Abdur Rahman] dari [Abu Hurairah radliallahu 'anhu] bahwa Rasulullah shallallahu 'alaihi wasallam jika ingin mendoakan kecelakaan kepada seseorang atau berdoa keselamatan kepada seseorang beliau selalu qunut setelah rukuk.\" Kira-kira ia berkata; \"Jika beliau mengucapkan: \"SAMI'ALLAHU LIMAN HAMIDAH, \" beliau berdoa: \"Wahai Rabb kami bagi-Mu segala pujian, Ya Allah selamatkanlah Al Walid bin Al Walid, salamah bin Hisyam, dan 'Ayyasy bin Abu Rabi'ah. Ya Allah keraskanlah hukuman-Mu atas Mudlar, dan timpakanlah kepada mereka tahun-tahun paceklik sebagaimana tahun-tahun pada masa Yusuf.\" -beliau mengeraskan bacaan tersebut, - beliau juga membaca pada sebagian shalat yang lainnya, beliau membaca pada shalat subuh: \"Ya Allah, laknatlah si fulan dan si fulan dari penduduk arab.\" Sampai akhirnya Allah Azza Wa Jalla mewahyukan kepada beliau: \"Tak ada sedikitpun campur tanganmu dalam urusan mereka itu atau Allah menerima taubat mereka, atau mengazab mereka karena sesungguhnya mereka itu orang-orang yang zalim (Ali Imran: 128).\""},"3890":{"ar":"حَدَّثَنَا عَمْرُو بْنُ خَالِدٍ حَدَّثَنَا زُهَيْرٌ حَدَّثَنَا أَبُو إِسْحَاقَ قَالَ سَمِعْتُ الْبَرَاءَ بْنَ عَازِبٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَجَعَلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى الرَّجَّالَةِ يَوْمَ أُحُدٍ عَبْدَ اللَّهِ بْنَ جُبَيْرٍ وَأَقْبَلُوا مُنْهَزِمِينَ فَذَاكَ إِذْ يَدْعُوهُمْ الرَّسُولُ فِي أُخْرَاهُمْ وَلَمْ يَبْقَ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ غَيْرُ اثْنَيْ عَشَرَ رَجُلًا","id":"Telah menceritakan kepada kami ['Amru bin Khalid] Telah menceritakan kepada kami [Zuhair] Telah menceritakan kepada kami [Abu Ishaq] berkata; Aku mendengar [Al Bara' bin 'Azib radliallahu 'anhuma] berkata; Nabi shallallahu 'alaihi wasallam menjadikan Abdullah bin Jubair sebagai komandan pasukan yang berjalan kaki pada perang Uhud. Lalu mereka lari berpencaran, itulah yang dimaksud dengan firman Allah: \"Ingatlah) ketika kamu lari dan tidak menoleh kepada seseorangpun, sedang Rasul yang berada di antara kawan-kawanmu yang lain memanggil kamu....\" pada waktu itu tidak ada yang bersama Rasulullah shallallahu 'alaihi wasallam kecuali hanya dua belas orang.'"},"3891":{"ar":"حَدَّثَنَا إِسْحَاقُ بْنُ إِبْرَاهِيمَ بْنِ عَبْدِ الرَّحْمَنِ أَبُو يَعْقُوبَ حَدَّثَنَا حُسَيْنُ بْنُ مُحَمَّدٍ حَدَّثَنَا شَيْبَانُ عَنْ قَتَادَةَ حَدَّثَنَا أَنَسٌ أَنَّ أَبَا طَلْحَةَ قَالَغَشِيَنَا النُّعَاسُ وَنَحْنُ فِي مَصَافِّنَا يَوْمَ أُحُدٍ قَالَ فَجَعَلَ سَيْفِي يَسْقُطُ مِنْ يَدِي وَآخُذُهُ وَيَسْقُطُ وَآخُذُهُ","id":"Telah menceritakan kepada kami [Ishaq bin Ibrahim bin 'Abdur Rahman Abu Ya'qub] Telah menceritakan kepada kami [Hushain bin Muhammad] Telah menceritakan kepada kami [Syaiban] dari [Qatadah] Telah menceritakan kepada kami [Anas] bahwa [Abu Thalhah] kami mendapati rasa kantuk yang sangat pada waktu kami dalam barisan perang Badar, lalu Abu Thalhah berkata, 'sehingga pedangku terjatuh dari tanganku, lalu aku mengambilnya, lalu jatuh kembali dan kembali aku mengambilnya. '"},"3892":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ يُونُسَ أُرَاهُ قَالَ حَدَّثَنَا أَبُو بَكْرٍ عَنْ أَبِي حَصِينٍ عَنْ أَبِي الضُّحَى عَنْ ابْنِ عَبَّاسٍ{ حَسْبُنَا اللَّهُ وَنِعْمَ الْوَكِيلُ }قَالَهَا إِبْرَاهِيمُ عَلَيْهِ السَّلَام حِينَ أُلْقِيَ فِي النَّارِ وَقَالَهَا مُحَمَّدٌ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِينَ قَالُوا{ إِنَّ النَّاسَ قَدْ جَمَعُوا لَكُمْ فَاخْشَوْهُمْ فَزَادَهُمْ إِيمَانًا وَقَالُوا حَسْبُنَا اللَّهُ وَنِعْمَ الْوَكِيلُ }","id":"Telah menceritakan kepada kami [Ahmad bin Yunus] aku melihatnya berkata; Telah menceritakan kepada kami [Abu Bakr] dari [Abu Hashin] dari [Abu Adl Dluha] dari [Ibnu 'Abbas] Hasbunallah wa ni'mal wakil adalah ucapan Ibrahim Alaihis Salam ketika di lemparkan ke api. Juga diucapkan oleh Nabi shallallahu 'alaihi wasallam ketika orang-orang kafir berkata; \"Sesungguhnya manusia telah mengumpulkan pasukan untuk menyerang kamu, karena itu takutlah kepada mereka\", maka perkataan itu menambah keimanan mereka dan mereka menjawab: \"Cukuplah Allah menjadi Penolong kami dan Allah adalah sebaik-baik Pelindung.\""},"3893":{"ar":"حَدَّثَنَا مَالِكُ بْنُ إِسْمَاعِيلَ حَدَّثَنَا إِسْرَائِيلُ عَنْ أَبِي حَصِينٍ عَنْ أَبِي الضُّحَى عَنْ ابْنِ عَبَّاسٍ قَالَكَانَ آخِرَ قَوْلِ إِبْرَاهِيمَ حِينَ أُلْقِيَ فِي النَّارِ حَسْبِيَ اللَّهُ وَنِعْمَ الْوَكِيلُ","id":"Telah menceritakan kepada kami [Malik bin Ismail] Telah menceritakan kepada kami [Israil] dari [Abu Hashin] dari [Abu Adl Dluha] dari [Ibnu 'Abbas] berkata; \"Perkataan terakhir yang diucapkan Ibrahim ketika dia dilemparkan ke api adalah: \"Cukuplah Allah bagiku sebagai sebaik-baik pelindung.\""},"3894":{"ar":"حَدَّثَنِي عَبْدُ اللَّهِ بْنُ مُنِيرٍ سَمِعَ أَبَا النَّضْرِ حَدَّثَنَا عَبْدُ الرَّحْمَنِ هُوَ ابْنُ عَبْدِ اللَّهِ بْنِ دِينَارٍ عَنْ أَبِيهِ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ آتَاهُ اللَّهُ مَالًا فَلَمْ يُؤَدِّ زَكَاتَهُ مُثِّلَ لَهُ مَالُهُ شُجَاعًا أَقْرَعَ لَهُ زَبِيبَتَانِ يُطَوَّقُهُ يَوْمَ الْقِيَامَةِ يَأْخُذُ بِلِهْزِمَتَيْهِ يَعْنِي بِشِدْقَيْهِ يَقُولُ أَنَا مَالُكَ أَنَا كَنْزُكَ ثُمَّ تَلَا هَذِهِ الْآيَةَ{ وَلَا يَحْسِبَنَّ الَّذِينَ يَبْخَلُونَ بِمَا آتَاهُمْ اللَّهُ مِنْ فَضْلِهِ }إِلَى آخِرِ الْآيَةِ","id":"Telah menceritakan kepadaku ['Abdullah bin Munir] dia mendengar [Abu An Nadlr] Telah menceritakan kepada kami ['Abdur Rahman] yaitu Ibnu 'Abdullah bin Dinar dari [Bapaknya] dari [Abu Shalih] dari [Abu Hurairah] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa yang diberi harta oleh Allah -Azza wa Jalla-, lalu ia tidak menunaikan zakatnya, maka hartanya akan diubah pada hari Kiamat seperti seekor ular berkepala putih (karena banyak racunnya) serta memiliki dua titik hitam di atas matanya atau dua taring, memangsa dengan kedua tulang rahangnya pada hari Kiamat, lalu mengatakan, 'Akulah harta simpananmu, akulah harta simpananmu'.\" Kemudian beliau membaca ayat ini: 'Janganlah sekali-kali orang-orang yang bakhil dengan harta yang Allah berikan kepada mereka dari karunia-Nya menyangka.....' hingga akhir ayat."},"3895":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي عُرْوَةُ بْنُ الزُّبَيْرِ أَنَّ أُسَامَةَ بْنَ زَيْدٍ رَضِيَ اللَّهُ عَنْهُمَا أَخْبَرَهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَكِبَ عَلَى حِمَارٍ عَلَى قَطِيفَةٍ فَدَكِيَّةٍ وَأَرْدَفَ أُسَامَةَ بْنَ زَيْدٍ وَرَاءَهُ يَعُودُ سَعْدَ بْنَ عُبَادَةَ فِي بَنِي الْحَارِثِ بْنِ الْخَزْرَجِ قَبْلَ وَقْعَةِ بَدْرٍ قَالَ حَتَّى مَرَّ بِمَجْلِسٍ فِيهِ عَبْدُ اللَّهِ بْنُ أُبَيٍّ ابْنُ سَلُولَ وَذَلِكَ قَبْلَ أَنْ يُسْلِمَ عَبْدُ اللَّهِ بْنُ أُبَيٍّ فَإِذَا فِي الْمَجْلِسِ أَخْلَاطٌ مِنْ الْمُسْلِمِينَ وَالْمُشْرِكِينَ عَبَدَةِ الْأَوْثَانِ وَالْيَهُودِ وَالْمُسْلِمِينَ وَفِي الْمَجْلِسِ عَبْدُ اللَّهِ بْنُ رَوَاحَةَ فَلَمَّا غَشِيَتْ الْمَجْلِسَ عَجَاجَةُ الدَّابَّةِ خَمَّرَ عَبْدُ اللَّهِ بْنُ أُبَيٍّ أَنْفَهُ بِرِدَائِهِ ثُمَّ قَالَ لَا تُغَبِّرُوا عَلَيْنَا فَسَلَّمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَيْهِمْ ثُمَّ وَقَفَ فَنَزَلَ فَدَعَاهُمْ إِلَى اللَّهِ وَقَرَأَ عَلَيْهِمْ الْقُرْآنَ فَقَالَ عَبْدُ اللَّهِ بْنُ أُبَيٍّ ابْنُ سَلُولَ أَيُّهَا الْمَرْءُ إِنَّهُ لَا أَحْسَنَ مِمَّا تَقُولُ إِنْ كَانَ حَقًّا فَلَا تُؤْذِنَا بِهِ فِي مَجْلِسِنَا ارْجِعْ إِلَى رَحْلِكَ فَمَنْ جَاءَكَ فَاقْصُصْ عَلَيْهِ فَقَالَ عَبْدُ اللَّهِ بْنُ رَوَاحَةَ بَلَى يَا رَسُولَ اللَّهِ فَاغْشَنَا بِهِ فِي مَجَالِسِنَا فَإِنَّا نُحِبُّ ذَلِكَ فَاسْتَبَّ الْمُسْلِمُونَ وَالْمُشْرِكُونَ وَالْيَهُودُ حَتَّى كَادُوا يَتَثَاوَرُونَ فَلَمْ يَزَلْ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُخَفِّضُهُمْ حَتَّى سَكَنُوا ثُمَّ رَكِبَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَابَّتَهُ فَسَارَ حَتَّى دَخَلَ عَلَى سَعْدِ بْنِ عُبَادَةَ فَقَالَ لَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا سَعْدُ أَلَمْ تَسْمَعْ مَا قَالَ أَبُو حُبَابٍ يُرِيدُ عَبْدَ اللَّهِ بْنَ أُبَيٍّ قَالَ كَذَا وَكَذَا قَالَ سَعْدُ بْنُ عُبَادَةَ يَا رَسُولَ اللَّهِ اعْفُ عَنْهُ وَاصْفَحْ عَنْهُ فَوَالَّذِي أَنْزَلَ عَلَيْكَ الْكِتَابَ لَقَدْ جَاءَ اللَّهُ بِالْحَقِّ الَّذِي أَنْزَلَ عَلَيْكَ لَقَدْ اصْطَلَحَ أَهْلُ هَذِهِ الْبُحَيْرَةِ عَلَى أَنْ يُتَوِّجُوهُ فَيُعَصِّبُوهُ بِالْعِصَابَةِ فَلَمَّا أَبَى اللَّهُ ذَلِكَ بِالْحَقِّ الَّذِي أَعْطَاكَ اللَّهُ شَرِقَ بِذَلِكَ فَذَلِكَ فَعَلَ بِهِ مَا رَأَيْتَ فَعَفَا عَنْهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَصْحَابُهُ يَعْفُونَ عَنْ الْمُشْرِكِينَ وَأَهْلِ الْكِتَابِ كَمَا أَمَرَهُمْ اللَّهُ وَيَصْبِرُونَ عَلَى الْأَذَى قَالَ اللَّهُ عَزَّ وَجَلَّ{ وَلَتَسْمَعُنَّ مِنْ الَّذِينَ أُوتُوا الْكِتَابَ مِنْ قَبْلِكُمْ وَمِنْ الَّذِينَ أَشْرَكُوا أَذًى كَثِيرًا }الْآيَةَ وَقَالَ اللَّهُ{ وَدَّ كَثِيرٌ مِنْ أَهْلِ الْكِتَابِ لَوْ يَرُدُّونَكُمْ مِنْ بَعْدِ إِيمَانِكُمْ كُفَّارًا حَسَدًا مِنْ عِنْدِ أَنْفُسِهِمْ }إِلَى آخِرِ الْآيَةِ وَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَتَأَوَّلُ الْعَفْوَ مَا أَمَرَهُ اللَّهُ بِهِ حَتَّى أَذِنَ اللَّهُ فِيهِمْ فَلَمَّا غَزَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَدْرًا فَقَتَلَ اللَّهُ بِهِ صَنَادِيدَ كُفَّارِ قُرَيْشٍ قَالَ ابْنُ أُبَيٍّ ابْنُ سَلُولَ وَمَنْ مَعَهُ مِنْ الْمُشْرِكِينَ وَعَبَدَةِ الْأَوْثَانِ هَذَا أَمْرٌ قَدْ تَوَجَّهَ فَبَايَعُوا الرَّسُولَ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى الْإِسْلَامِ فَأَسْلَمُوا","id":"Telah menceritakan kepada kami [Abu Al Yaman] Telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhri] berkata; Telah mengabarkan kepadaku ['Urwah bin Az Zubair] bahwa [Usamah bin Zaid radliallahu 'anhu] telah mengabarkan kepadanya bahwa Rasulullah shallallahu 'alaihi wasallam pernah mengendarai seekor keledai, dilengkapi dengan penutup kaki yang dibuat di Fadak dan aku berada di belakangnya. Nabi shallallahu 'alaihi wasallam pergi untuk berkunjung kepada Sa'ad bin 'Ubadah di Bani Al Harits bin Al Khazraj; kejadian ini berlangsung sebelum perang Badar. Nabi shallallahu 'alaihi wasallam, melewati sekelompok orang, yang di dalamnya ada 'Abdullah bin 'Ubay bin Salul. Dan itu terjadi sebelum 'Abdullah bin 'Ubay masuk Islam. Di dalam kerumunan itu berkumpul orang-orang dari berbagai agama yaitu: orang-orang Muslim, kafir, para penyembah berhala, dan Yahudi. Di sana juga terlihat 'Abdullah bin Rawahah. Ketika debu yang di timbulkan dari keledai (yang dikendarai Nabi shallallahu 'alaihi wasallam) mengenai kerumunan itu, 'Abdullah bin 'Ubay menutup hidungnya dengan bajunya dan berkata; \"Jangan tutupi kami dengan debu.\" Kemudian Rasulullah shallallahu 'alaihi wasallam mengucapkan salam kepada mereka, lalu turun dan mengajak mereka kepada Allah (memeluk agama Islam) dan membacakan kepada mereka Al Qur'an mulia. Mendengar hal itu 'Abdullah bin 'Ubay berkata; 'Wahai ki sanak! Tak ada yang lebih baik daripada yang engkau ucapkan, jika itu benar, kalau begitu jangan mengganggu pertemuan kami. Pulanglah. Bacakan saja kepada orang-orang yang datang kepadamu.' Mendengar itu 'Abdullah bin Rawahah berkata; 'Ya Rasulullah! Bawalah (apa yang ingin Anda sampaikan) kepada kami dalam pertemuan kami, karena kami menyukainya.' Maka orang-orang Muslim, kafir, dan Yahudi saling mencaci maki satu sama lain hingga mereka mau berkelahi. Nabi shallallahu 'alaihi wasallam menenangkan mereka dan mereka semua kembali tenang. Kemudian Nabi shallallahu 'alaihi wasallam menaiki kembali keledainya dan melanjutkan perjalanan hingga sampailah dikediaman Sa'ad bin 'Ubadah. Nabi shallallahu 'alaihi wasallam berkata kepada Sa'ad: 'Apakah engkau mendengar apa yang disampaikan Hubab? ' Yang Nabi shallallahu 'alaihi wasallam maksudkan adalah 'Abdullah bin 'Ubay. 'Ia berkata ini dan itu.' Mendengar itu Sa'ad bin 'Ubadah berkata; 'Ya Rasulullah! Ampuni dan beri maaf dia, karena demi Allah yang memberimu Al Kitab, Allah memberikan kepadamu Kebenaran (Al Qur'an) pada saat penduduk kota ini (Madinah) tengah mencari seseorang untuk memimpin mereka. Tetapi ketika Allah menentang (keputusan) itu melalui Kebenaran (Al Qur'an) yang diberikan kepada Anda, maka ('Abdullah bin 'Ubay) dengki terhadapmu, seperti kelakuannya yang engkau lihat terhadapmu.' Maka Rasulullah shallallahu 'alaihi wasallam memaafkannya, karena Rasulullah shallallahu 'alaihi wasallam dan para sahabatnya memaafkan orang-orang kafir dan para Ahli Kitab sebagaimana yang diperintahkan Allah, dan mereka bersabar terhadap kesalah pahaman. Dan Nabi shallallahu 'alaihi wasallam menegaskan prinsip memberikan ampunan kepada mereka selama Allah memerintahkannya demikian hingga Allah memberikan izin untuk memerangi mereka. Maka ketika Rasulullah shallallahu 'alaihi wasallam bertempur dalam Perang Badar dan Allah membinasakan orang-orang terkemuka Quraisy, Ibnu Ubay bin Salul dan orang-orang kafir serta para penyembah berhala yang berkelompok dengannya berkata; 'Islam telah muncul.' Lalu mereka memberikan baiat mereka (untuk memeluk agama Islam) kepada Rasulullah shallallahu 'alaihi wasallam dan menjadi Muslim."},"3896":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ أَبِي مَرْيَمَ أَخْبَرَنَا مُحَمَّدُ بْنُ جَعْفَرٍ قَالَ حَدَّثَنِي زَيْدُ بْنُ أَسْلَمَ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ رَضِيَ اللَّهُ عَنْهُأَنَّ رِجَالًا مِنْ الْمُنَافِقِينَ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا خَرَجَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى الْغَزْوِ تَخَلَّفُوا عَنْهُ وَفَرِحُوا بِمَقْعَدِهِمْ خِلَافَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَإِذَا قَدِمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اعْتَذَرُوا إِلَيْهِ وَحَلَفُوا وَأَحَبُّوا أَنْ يُحْمَدُوا بِمَا لَمْ يَفْعَلُوا فَنَزَلَتْ{ لَا يَحْسِبَنَّ الَّذِينَ يَفْرَحُونَ بِمَا أَتَوْا وَيُحِبُّونَ أَنْ يُحْمَدُوا بِمَا لَمْ يَفْعَلُوا }الْآيَةَ","id":"Telah menceritakan kepada kami [Sa'id bin Abu Maryam] Telah mengabarkan kepada kami [Muhammad bin Ja'far] berkata; Telah menceritakan kepadaku [Zaid bin Aslam] dari ['Atha bin Yasar] dari [Abu Sa'id Al Khudri radliallahu 'anhu] \"Bahwa beberapa orang munafik pada masa Rasulullah shallallahu 'alaihi wasallam apabila beliau pergi berperang mereka tidak turut berperang dan merasa bangga dengan ketidakpergiannya untuk menyelisihi Rasulullah shallallahu 'alaihi wasallam. Apabila Rasulullah shallallahu 'alaihi wasallam telah kembali (membawa kemenangan dan harta rampasan perang), mereka mengemukakan alasan mereka masing-masing yang menjadikan mereka tidak turut berperang dan menguatkan alasannya dengan sumpah. Kemudian mereka ingin dipuji (seolah-olah merekalah yang pahlawan) padahal mereka tidak berbuat apa-apa. Karena itu turunlah ayat: 'Janganlah sekali-kali kamu menyangka bahwa orang-orang yang gembira dengan apa yang telah mereka kerjakan dan mereka ingin dipuji terhadap perbuatan yang tidak mereka kerjakan, janganlah kamu mengira bahwa mereka akan terlepas dari siksa…' (QS Ali Imraan (3): 88)."},"3897":{"ar":"حَدَّثَنِي إِبْرَاهِيمُ بْنُ مُوسَى أَخْبَرَنَا هِشَامٌ أَنَّ ابْنَ جُرَيْجٍ أَخْبَرَهُمْ عَنْ ابْنِ أَبِي مُلَيْكَةَ أَنَّ عَلْقَمَةَ بْنَ وَقَّاصٍ أَخْبَرَهُأَنَّ مَرْوَانَ قَالَ لِبَوَّابِهِ اذْهَبْ يَا رَافِعُ إِلَى ابْنِ عَبَّاسٍ فَقُلْ لَئِنْ كَانَ كُلُّ امْرِئٍ فَرِحَ بِمَا أُوتِيَ وَأَحَبَّ أَنْ يُحْمَدَ بِمَا لَمْ يَفْعَلْ مُعَذَّبًا لَنُعَذَّبَنَّ أَجْمَعُونَ فَقَالَ ابْنُ عَبَّاسٍ وَمَا لَكُمْ وَلِهَذِهِ إِنَّمَا دَعَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَهُودَ فَسَأَلَهُمْ عَنْ شَيْءٍ فَكَتَمُوهُ إِيَّاهُ وَأَخْبَرُوهُ بِغَيْرِهِ فَأَرَوْهُ أَنْ قَدْ اسْتَحْمَدُوا إِلَيْهِ بِمَا أَخْبَرُوهُ عَنْهُ فِيمَا سَأَلَهُمْ وَفَرِحُوا بِمَا أُوتُوا مِنْ كِتْمَانِهِمْ ثُمَّ قَرَأَ ابْنُ عَبَّاسٍ{ وَإِذْ أَخَذَ اللَّهُ مِيثَاقَ الَّذِينَ أُوتُوا الْكِتَابَ كَذَلِكَ حَتَّى قَوْلِهِ يَفْرَحُونَ بِمَا أَتَوْا وَيُحِبُّونَ أَنْ يُحْمَدُوا بِمَا لَمْ يَفْعَلُوا }تَابَعَهُ عَبْدُ الرَّزَّاقِ عَنْ ابْنِ جُرَيْجٍ ح حَدَّثَنَا ابْنُ مُقَاتِلٍ أَخْبَرَنَا الْحَجَّاجُ عَنْ ابْنِ جُرَيْجٍ أَخْبَرَنِي ابْنُ أَبِي مُلَيْكَةَ عَنْ حُمَيْدِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ عَوْفٍ أَنَّهُ أَخْبَرَهُ أَنَّ مَرْوَانَ بِهَذَا","id":"Telah menceritakan kepadaku [Ibrahim bin Musa] Telah mengabarkan kepada kami [Hisyam] bahwa [Ibnu Juraij] Telah menceritakan kepada mereka dari [Ibnu Abu Mulaikah] bahwa ['Alqamah bin Waqqash] telah mengabarkan kepadanya bahwasannya Marwan berkata kepada penjaga pintunya; \"Wahai Abu Rafi', pergilah menemui Ibnu Abbas, tanyakan kepadanya; 'Apabila setiap orang dari kita akan disiksa karena merasa senang dengan apa yang dia kerjakan dan suka untuk dipuji terhadap apa yang belum dia kerjakan, dengan demikian berarti kita semua akan di adzab? [Ibnu Abbas] berkata; 'Ada apa dengan ayat ini? ' Ayat ini hanya di turunkan mengenai orang Yahudi..\" Yaitu ketika nabi shallallahu 'alaihi wasallam menanyakan kepada mereka tentang sesuatu, namun mereka menyembunyikannya dan mengabarkan hal yang lain. Lalu mereka perlihatkan kepada beliau bahwa mereka berhak mendapat pujian dari apa yang telah mereka kabarkan itu dan mereka senang dengan apa yang telah mereka kerjakan, yaitu sikap mereka yang menyembunyikan sesuatu yang beliau tanyakan.' Lalu Ibnu Abbas membaca ayat; \"Dan (ingatlah), ketika Allah mengambil janji dari orang-orang yang telah diberi (yaitu), \"Hendaklah kamu benar-benar menerangkannya (isi kitab itu) kepada manusia dan janganlah kamu menyembunyikannya.\" (Ali Imran: 187). Dan Ibnu Abbas membaca ayat; \"Dan janganlah sekali-kali kamu mengira bahwa orang yang gembira dengan apa yang telah mereka kerjakan dan mereka suka dipuji atas perbuatan yang tidak mereka lakukan. (Ali Imran: 188). Dan diriwayatkan pula oleh ['Abdur Razzaq] dari [Ibnu Juraij] Demikian juga diriwayatkan dari jalur lainnya, Telah menceritakan kepada kami [Ibnu Muqatil] Telah mengabarkan kepada kami [Al Hajjaj] dari [Ibnu Juraij] Telah mengabarkan kepadaku [Ibnu Abu Mulaikah] dari [Humaid bin 'Abdur Rahman bin 'Auf] bahwasanya ia telah mengabarkan kepadanya mengenai kisah Marwan ini."},"3898":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ أَبِي مَرْيَمَ أَخْبَرَنَا مُحَمَّدُ بْنُ جَعْفَرٍ قَالَ أَخْبَرَنِي شَرِيكُ بْنُ عَبْدِ اللَّهِ بْنِ أَبِي نَمِرٍ عَنْ كُرَيْبٍ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَبِتُّ عِنْدَ خَالَتِي مَيْمُونَةَ فَتَحَدَّثَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَعَ أَهْلِهِ سَاعَةً ثُمَّ رَقَدَ فَلَمَّا كَانَ ثُلُثُ اللَّيْلِ الْآخِرُ قَعَدَ فَنَظَرَ إِلَى السَّمَاءِ فَقَالَ{ إِنَّ فِي خَلْقِ السَّمَوَاتِ وَالْأَرْضِ وَاخْتِلَافِ اللَّيْلِ وَالنَّهَارِ لَآيَاتٍ لِأُولِي الْأَلْبَابِ }ثُمَّ قَامَ فَتَوَضَّأَ وَاسْتَنَّ فَصَلَّى إِحْدَى عَشْرَةَ رَكْعَةً ثُمَّ أَذَّنَ بِلَالٌ فَصَلَّى رَكْعَتَيْنِ ثُمَّ خَرَجَ فَصَلَّى الصُّبْحَ","id":"Telah menceritakan kepada kami [Sa'id bin Abu Maryam] Telah mengabarkan kepada kami [Muhammad bin Ja'far] berkata; Telah mengabarkan kepadaku [Syarik bin 'Abdullah bin Abu Namir] dari [Kuraib] dari [Ibnu 'Abbas radliallahu 'anhuma] dia berkata; suatu ketika aku bermalam di rumah bibiku Maimunah, aku mendengar Rasulullah shallallahu 'alaihi wasallam berbincang-bincang bersama istrinya sesaat. Kemudian beliau tidur. Tatkala tiba waktu sepertiga malam terakhir, beliau duduk dan melihat ke langit lalu beliau membaca; \"Sesungguhnya dalam penciptaan langit dan bumi, dan silih bergantinya malam dan siang terdapat tanda-tanda bagi orang-orang yang berakal.\" (Ali Imran; 190). Lalu beliau berwudlu dan bersiwak, kemudian shalat sebelas raka'at. Setelah mendengar Bilal adzan, beliau shalat dua raka'at kemudian beliau keluar untuk shalat subuh."},"3899":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ عَنْ مَالِكِ بْنِ أَنَسٍ عَنْ مَخْرَمَةَ بْنِ سُلَيْمَانَ عَنْ كُرَيْبٍ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَبِتُّ عِنْدَ خَالَتِي مَيْمُونَةَ فَقُلْتُ لَأَنْظُرَنَّ إِلَى صَلَاةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَطُرِحَتْ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وِسَادَةٌ فَنَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي طُولِهَا فَجَعَلَ يَمْسَحُ النَّوْمَ عَنْ وَجْهِهِ ثُمَّ قَرَأَ الْآيَاتِ الْعَشْرَ الْأَوَاخِرَ مِنْ آلِ عِمْرَانَ حَتَّى خَتَمَ ثُمَّ أَتَى شَنًّا مُعَلَّقًا فَأَخَذَهُ فَتَوَضَّأَ ثُمَّ قَامَ يُصَلِّي فَقُمْتُ فَصَنَعْتُ مِثْلَ مَا صَنَعَ ثُمَّ جِئْتُ فَقُمْتُ إِلَى جَنْبِهِ فَوَضَعَ يَدَهُ عَلَى رَأْسِي ثُمَّ أَخَذَ بِأُذُنِي فَجَعَلَ يَفْتِلُهَا ثُمَّ صَلَّى رَكْعَتَيْنِ ثُمَّ صَلَّى رَكْعَتَيْنِ ثُمَّ صَلَّى رَكْعَتَيْنِ ثُمَّ صَلَّى رَكْعَتَيْنِ ثُمَّ صَلَّى رَكْعَتَيْنِ ثُمَّ صَلَّى رَكْعَتَيْنِ ثُمَّ أَوْتَرَ","id":"Telah menceritakan kepada kami ['Ali bin 'Abdullah] Telah menceritakan kepada kami ['Abdur Rahman bin Mahdi] dari [Malik bin Anas] dari [Makhramah bin Sulaiman] dari [Kuraib] dari [Ibnu 'Abbas radliallahu 'anhuma] ia berkata; Suatu ketika aku menginap di rumah Maimunah, lalu aku berkata; Aku akan melihat shalat Rasulullah. Tiba-tiba Rasulullah shallallahu 'alaihi wasallam diberi bantal dan beliau tidur di bagian sisi panjang. Setelah itu bangun seraya mengusap kantuk dari wajahnya. Lalu beliau membaca sepuluh ayat terakhir surat Ali Imran hingga selesai. kemudian beliau menuju ke geriba yang tergantung, beliau berwudlu darinya dan beliau shalat. Ibnu 'Abbas berkata; Aku pun bangun dan melaksanakan seperti apa yang beliau kerjakan, kemudian aku berdiri di sampingnya, maka beliau meletakkan tangannya di kepalaku dan memegang telinga kananku lalu memilinnya. Beliau shalat dua raka'at, dua raka'at, dua raka'at, dua raka'at, dua raka'at, dua raka'at kemudian beliau melakukan witir."},"3900":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا مَعْنُ بْنُ عِيسَى حَدَّثَنَا مَالِكٌ عَنْ مَخْرَمَةَ بْنِ سُلَيْمَانَ عَنْ كُرَيْبٍ مَوْلَى عَبْدِ اللَّهِ بْنِ عَبَّاسٍ أَنَّ عَبْدَ اللَّهِ بْنَ عَبَّاسٍ أَخْبَرَهُأَنَّهُ بَاتَ عِنْدَ مَيْمُونَةَ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهْيَ خَالَتُهُ قَالَ فَاضْطَجَعْتُ فِي عَرْضِ الْوِسَادَةِ وَاضْطَجَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَهْلُهُ فِي طُولِهَا فَنَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى انْتَصَفَ اللَّيْلُ أَوْ قَبْلَهُ بِقَلِيلٍ أَوْ بَعْدَهُ بِقَلِيلٍ ثُمَّ اسْتَيْقَظَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَجَعَلَ يَمْسَحُ النَّوْمَ عَنْ وَجْهِهِ بِيَدَيْهِ ثُمَّ قَرَأَ الْعَشْرَ الْآيَاتِ الْخَوَاتِمَ مِنْ سُورَةِ آلِ عِمْرَانَ ثُمَّ قَامَ إِلَى شَنٍّ مُعَلَّقَةٍ فَتَوَضَّأَ مِنْهَا فَأَحْسَنَ وُضُوءَهُ ثُمَّ قَامَ يُصَلِّي فَصَنَعْتُ مِثْلَ مَا صَنَعَ ثُمَّ ذَهَبْتُ فَقُمْتُ إِلَى جَنْبِهِ فَوَضَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَدَهُ الْيُمْن��ى عَلَى رَأْسِي وَأَخَذَ بِأُذُنِي بِيَدِهِ الْيُمْنَى يَفْتِلُهَا فَصَلَّى رَكْعَتَيْنِ ثُمَّ رَكْعَتَيْنِ ثُمَّ رَكْعَتَيْنِ ثُمَّ رَكْعَتَيْنِ ثُمَّ رَكْعَتَيْنِ ثُمَّ رَكْعَتَيْنِ ثُمَّ أَوْتَرَ ثُمَّ اضْطَجَعَ حَتَّى جَاءَهُ الْمُؤَذِّنُ فَقَامَ فَصَلَّى رَكْعَتَيْنِ خَفِيفَتَيْنِ ثُمَّ خَرَجَ فَصَلَّى الصُّبْحَ","id":"Telah menceritakan kepada kami ['Ali bin 'Abdullah] Telah menceritakan kepada kami [Ma'an bin 'Isa] Telah menceritakan kepada kami [Malik] dari [Makhramah bin Sulaiman] dari [Kuraib] -budak yang dimerdekakan- 'Abdullah bin 'Abbas bahwa ['Abdullah bin 'Abbas] mengabarkan kepadanya bahwasannya dia pernah menginap di rumah Maimunah isteri Nabi shallallahu 'alaihi wasallam, yaitu bibinya. Ia berkata; Aku berbaring di bantal bagian sisi lebar, sedangkan Rasulullah shallallahu 'alaihi wasallam dan keluarganya tidur di bantal bagian sisi panjang. Rasulullah shallallahu 'alaihi wasallam tidur hingga pertengahan malam, mendekati atau melewati sedikit, kemudian bangun dan duduk seraya mengusap kantuk dari wajahnya dengan tangannya. Kemudian beliau membaca sepuluh ayat terakhir surat Ali Imran, lalu bangun menuju ke geriba yang tergantung, beliau berwudlu darinya dan menyempurnakan wudlunya kemudian beliau shalat. Ibnu 'Abbas berkata; Aku pun bangun dan melaksanakan seperti apa yang beliau kerjakan, kemudian aku berdiri di sampingnya, maka beliau meletakkan tangannya di kepalaku dan memegang telinga kananku lalu memilinnya. Beliau shalat dua raka'at, dua raka'at, dua raka'at, dua raka'at, dua raka'at, dua raka'at kemudian beliau melakukan witir, setelah selesai beliau tidur kembali hingga datang seruan mu`adzin. Kemudian beliau shalat dua raka'at ringan dan keluar untuk melakukan shalat Subuh.\""},"3901":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ عَنْ مَالِكٍ عَنْ مَخْرَمَةَ بْنِ سُلَيْمَانَ عَنْ كُرَيْبٍ مَوْلَى ابْنِ عَبَّاسٍ أَنَّ ابْنَ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا أَخْبَرَهُأَنَّهُ بَاتَ عِنْدَ مَيْمُونَةَ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهْيَ خَالَتُهُ قَالَ فَاضْطَجَعْتُ فِي عَرْضِ الْوِسَادَةِ وَاضْطَجَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَهْلُهُ فِي طُولِهَا فَنَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى إِذَا انْتَصَفَ اللَّيْلُ أَوْ قَبْلَهُ بِقَلِيلٍ أَوْ بَعْدَهُ بِقَلِيلٍ اسْتَيْقَظَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَجَلَسَ يَمْسَحُ النَّوْمَ عَنْ وَجْهِهِ بِيَدِهِ ثُمَّ قَرَأَ الْعَشْرَ الْآيَاتِ الْخَوَاتِمَ مِنْ سُورَةِ آلِ عِمْرَانَ ثُمَّ قَامَ إِلَى شَنٍّ مُعَلَّقَةٍ فَتَوَضَّأَ مِنْهَا فَأَحْسَنَ وُضُوءَهُ ثُمَّ قَامَ يُصَلِّي قَالَ ابْنُ عَبَّاسٍ فَقُمْتُ فَصَنَعْتُ مِثْلَ مَا صَنَعَ ثُمَّ ذَهَبْتُ فَقُمْتُ إِلَى جَنْبِهِ فَوَضَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَدَهُ الْيُمْنَى عَلَى رَأْسِي وَأَخَذَ بِأُذُنِي الْيُمْنَى يَفْتِلُهَا فَصَلَّى رَكْعَتَيْنِ ثُمَّ رَكْعَتَيْنِ ثُمَّ رَكْعَتَيْنِ ثُمَّ رَكْعَتَيْنِ ثُمَّ رَكْعَتَيْنِ ثُمَّ رَكْعَتَيْنِ ثُمَّ أَوْتَرَ ثُمَّ اضْطَجَعَ حَتَّى جَاءَهُ الْمُؤَذِّنُ فَقَامَ فَصَلَّى رَكْعَتَيْنِ خَفِيفَتَيْنِ ثُمَّ خَرَجَ فَصَلَّى الصُّبْحَ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] dari [Malik] dari [Makhramah bin Sulaiman] dari [Kuraib] -budak yang dimerdekakan- Ibnu 'Abbas bahwa [Ibnu 'Abbas radliallahu 'anhu] telah mengabarkan kepadanya bahwasannya dia pernah menginap di rumah Maimunah isteri Nabi shallallahu 'alaihi wasallam, yaitu bibinya. Ia berkata; Aku berbaring di bantal bagian sisi lebar, sedangkan Rasulullah shallallahu 'alaihi wasallam dan keluarganya tidur di bantal bagian sisi panjang. Rasulullah shallallahu 'alaihi wasallam tidur hingga pertengahan malam, mendekati atau melewati sedikit, kemudian bangun dan duduk seraya mengusap kantuk dari wajahnya dengan tangannya. Kemudian beliau membaca sepuluh ayat terakhir dari surat Ali Imran, lalu bangun menuju ke geriba yang tergantung, beliau berwudlu darinya dan menyempurnakan wudlunya kemudian beliau shalat. Ibnu 'Abbas berkata; Aku pun bangun dan melaksanakan seperti apa yang beliau kerjakan, kemudian aku berdiri di sampingnya, maka beliau meletakkan tangannya di kepalaku dan memegang telinga kananku lalu memilinnya. Beliau shalat dua raka'at, dua raka'at, dua raka'at, dua raka'at, dua raka'at, dua raka'at kemudian beliau melakukan witir, setelah selesai beliau tidur kembali hingga datang seruan mu`adzin. Kemudian beliau shalat dua raka'at ringan dan keluar untuk melakukan shalat Subuh.\""},"3902":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ مُوسَى أَخْبَرَنَا هِشَامٌ عَنْ ابْنِ جُرَيْجٍ قَالَ أَخْبَرَنِي هِشَامُ بْنُ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاأَنَّ رَجُلًا كَانَتْ لَهُ يَتِيمَةٌ فَنَكَحَهَا وَكَانَ لَهَا عَذْقٌ وَكَانَ يُمْسِكُهَا عَلَيْهِ وَلَمْ يَكُنْ لَهَا مِنْ نَفْسِهِ شَيْءٌ فَنَزَلَتْ فِيهِ{ وَإِنْ خِفْتُمْ أَنْ لَا تُقْسِطُوا فِي الْيَتَامَى }أَحْسِبُهُ قَالَ كَانَتْ شَرِيكَتَهُ فِي ذَلِكَ الْعَذْقِ وَفِي مَالِهِ","id":"Telah menceritakan kepada kami [Ibrahim bin Musa] Telah mengabarkan kepada kami [Hisyam] dari [Ibnu Juraij] berkata; Telah mengabarkan kepadaku [Hisyam bin 'Urwah] dari [Bapaknya] dari ['Aisyah radliallahu 'anha] bahwa seorang laki-laki memiliki seorang wanita yatim. Lalu dia menikahinya karena wanita itu memiliki kebun kurma. Hingga dia di suruh menjaga kebun itu yang sebenarnya dia tidak mencintai wanita itu. Maka turunlah ayat: \"Dan jika kamu takut tidak akan dapat berlaku adil terhadap (hak-hak) perempuan yang yatim bilamana kamu mengawininya…..\" (An Nisa: 3). Aku mengira Hisyam berkata; Wanita itu dia sertakan dalam mengurus kebun kurma dan hartanya."},"3903":{"ar":"حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا إِبْرَاهِيمُ بْنُ سَعْدٍ عَنْ صَالِحِ بْنِ كَيْسَانَ عَنْ ابْنِ شِهَابٍ قَالَ أَخْبَرَنِي عُرْوَةُ بْنُ الزُّبَيْرِ أَنَّهُ سَأَلَ عَائِشَةَعَنْ قَوْلِ اللَّهِ تَعَالَى{ وَإِنْ خِفْتُمْ أَنْ لَا تُقْسِطُوا فِي الْيَتَامَى }فَقَالَتْ يَا ابْنَ أُخْتِي هَذِهِ الْيَتِيمَةُ تَكُونُ فِي حَجْرِ وَلِيِّهَا تَشْرَكُهُ فِي مَالِهِ وَيُعْجِبُهُ مَالُهَا وَجَمَالُهَا فَيُرِيدُ وَلِيُّهَا أَنْ يَتَزَوَّجَهَا بِغَيْرِ أَنْ يُقْسِطَ فِي صَدَاقِهَا فَيُعْطِيَهَا مِثْلَ مَا يُعْطِيهَا غَيْرُهُ فَنُهُوا عَنْ أَنْ يَنْكِحُوهُنَّ إِلَّا أَنْ يُقْسِطُوا لَهُنَّ وَيَبْلُغُوا لَهُنَّ أَعْلَى سُنَّتِهِنَّ فِي الصَّدَاقِ فَأُمِرُوا أَنْ يَنْكِحُوا مَا طَابَ لَهُمْ مِنْ النِّسَاءِ سِوَاهُنَّ قَالَ عُرْوَةُ قَالَتْ عَائِشَةُ وَإِنَّ النَّاسَ اسْتَفْتَوْا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعْدَ هَذِهِ الْآيَةِ فَأَنْزَلَ اللَّهُ{ وَيَسْتَفْتُونَكَ فِي النِّسَاءِ }قَالَتْ عَائِشَةُ وَقَوْلُ اللَّهِ تَعَالَى فِي آيَةٍ أُخْرَى{ وَتَرْغَبُونَ أَنْ تَنْكِحُوهُنَّ }رَغْبَةُ أَحَدِكُمْ عَنْ يَتِيمَتِهِ حِينَ تَكُونُ قَلِيلَةَ الْمَالِ وَالْجَمَالِ قَالَتْ فَنُهُوا أَنْ يَنْكِحُوا عَنْ مَنْ رَغِبُوا فِي مَالِهِ وَجَمَالِهِ فِي يَتَامَى النِّسَاءِ إِلَّا بِالْقِسْطِ مِنْ أَجْلِ رَغْبَتِهِمْ عَنْهُنَّ إِذَا كُنَّ قَلِيلَاتِ الْمَالِ وَالْجَمَالِ","id":"Telah menceritakan kepada kami ['Abdul 'Aziz bin 'Abdullah] Telah menceritakan kepada kami [Ibrahim bin Sa'ad] dari [Shalih bin Kaisan] dari [Ibnu Syihab] dia berkata; Telah mengabarkan kepadaku ['Urwah bin Az Zubair] bahwasanya ia bertanya kepada ['Aisyah] mengenai firman Allah Azza wa Jalla: 'Jika kalian takut tidak berbuat adil kepada anak yatim.. (An Nisa: 3) Aisyah berkata; 'wahai anak saudariku, yang dimaksud adalah seorang gadis yatim yang berada di peliharaan walinya, ia membantu dalam mengurus hartanya, lalu walinya takjub dengan harta dan kecantikannya hingga ia ingin menikahinya namun tidak bisa berbuat adil dalam maharnya sehingga Ia memberinya seperti yang diberikan oleh orang selainnya. Maka mereka dilarang untuk menikahi gadis-gadis itu kecuali jika berbuat adil dan memberi sebaik-baik mahar kepada mereka, sehingga mereka bisa memperoleh setinggi-tinggi mahar seukuran kondisi yang berlaku. Akhirnya mereka diperintahkan untuk menikahi wanita yang baik selain anak-anak perempuan yatim itu. Urwah berkata; lalu 'Aisyah berkata; sesungguhnya orang-orang meminta fatwa kepada Rasulullah shallallahu 'alaihi wasallam setelah turun ayat tersebut, lalu Allah Azza wa Jalla menurunkan: dan mereka meminta fatwa kepadamu tentang wanita-wanita, katakanlah bahwa Allah memberi fatwa kepada kalian sampai firman Allah: dan kalian ingin menikahi mereka. 'Aisyah berkata; maksudnya, ketika terjadi ketidak senangan seseorang diantara kalian kepada anak yatim yang ia pelihara karena harta dan kecantikannya sedikit, maka mereka dilarang untuk menikahinya karena dorongan niyat untuk menguasai harta gadis-gadis yatim itu. Kecuali jika bisa menegakkan keadilan meskipun ada ketidak senangan kepada mereka."},"3904":{"ar":"حَدَّثَنِي إِسْحَاقُ أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ نُمَيْرٍ حَدَّثَنَا هِشَامٌ عَنْ أَبِيهِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَافِي قَوْلِهِ تَعَالَى{ وَمَنْ كَانَ غَنِيًّا فَلْيَسْتَعْفِفْ وَمَنْ كَانَ فَقِيرًا فَلْيَأْكُلْ بِالْمَعْرُوفِ }أَنَّهَا نَزَلَتْ فِي وَالِي الْيَتِيمِ إِذَا كَانَ فَقِيرًا أَنَّهُ يَأْكُلُ مِنْهُ مَكَانَ قِيَامِهِ عَلَيْهِ بِمَعْرُوفٍ","id":"Telah menceritakan kepadaku [Ishaq] Telah mengabarkan kepada kami ['Abdullah bin Numair] Telah menceritakan kepada kami [Hisyam] dari [Bapaknya] dari ['Aisyah radliallahu 'anha] mengenai firman Allah Ta'ala: \"Barangsiapa (di antara pemelihara itu) mampu, maka hendaklah ia menahan diri (dari memakan harta anak yatim itu) dan barangsiapa yang miskin, maka bolehlah ia makan harta itu menurut yang patut.\" (An Nisaa`: 6) Aisyah berkata: Diturunkan berkenaan dengan wali anak yatim, ia boleh menggunakan dari uangnya bila membutuhkan dikarenakan ia mengurusnya dengan cara yang patut."},"3905":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حُمَيْدٍ أَخْبَرَنَا عُبَيْدُ اللَّهِ الْأَشْجَعِيُّ عَنْ سُفْيَانَ عَنْ الشَّيْبَانِيِّ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا{ وَإِذَا حَضَرَ الْقِسْمَةَ أُولُو الْقُرْبَى وَالْيَتَامَى وَالْمَسَاكِينُ }قَالَ هِيَ مُحْكَمَةٌ وَلَيْسَتْ بِمَنْسُوخَةٍتَابَعَهُ سَعِيدٌ عَنْ ابْنِ عَبَّاسٍ","id":"Telah menceritakan kepada kami [Ahmad bin Humaid] Telah mengabarkan kepada kami ['Ubaidullah Al Asyja'i] dari [Sufyan] dari [Asy Syaibani] dari ['Ikrimah] dari [Ibnu 'Abbas radliallahu 'anhuma] mengenai firman Allah: Dan apabila sewaktu pembagian itu hadir para kerabat, anak yatim dan orang miskin, maka berilah mereka dari harta itu (sekedarnya) dan ucapkanlah kepada mereka perkataan yang baik. Ibnu Abbas berkata; 'Ayat ini ayat muhkamah (jelas hukumnya). Bukan ayat yang dimansukh (dihapus). Dan diriwayatkan pula oleh [Sa'id] dari [Ibnu Abbas]."},"3906":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ مُوسَى حَدَّثَنَا هِشَامٌ أَنَّ ابْنَ جُرَيْجٍ أَخْبَرَهُمْ قَالَ أَخْبَرَنِي ابْنُ الْمُنْكَدِرِ عَنْ جَابِرٍ رَضِيَ اللَّهُ عَنْهُ قَالَعَادَنِي النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَبُو بَكْرٍ فِي بَنِي سَلِمَةَ مَاشِيَيْنِ فَوَجَدَنِي النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا أَعْقِلُ شَيْئًا فَدَعَا بِمَاءٍ فَتَوَضَّأَ مِنْهُ ثُمَّ رَشَّ عَلَيَّ فَأَفَقْتُ فَقُلْتُ مَا تَأْمُرُنِي أَنْ أَصْنَعَ فِي مَالِي يَا رَسُولَ اللَّهِ فَنَزَلَتْ{ يُوصِيكُمْ اللَّهُ فِي أَوْلَادِكُمْ }","id":"Telah menceritakan kepada kami [Ibrahim bin Musa] Telah menceritakan kepada kami [Hisyam] bahwa [Ibnu Juraij] Telah mengabarkan kepada mereka berkata; Telah mengabarkan kepadaku [Ibnu Al Munkadir] dari [Jabir radliallahu 'anhu] berkata; Nabi shallallahu 'alaihi wasallam bersama Abu Bakr menjengukku dengan berjalan kaki ketika aku sakit di bani Salamah. Beliau mendapatkanku dalam keadaan pingsan. Lalu beliau meminta air kemudian beliau berwudlu dengan air itu setelah itu beliau memercikiku hingga aku pun sadar kembali. Lalu aku bertanya; Ya Rasulullah, apa yang engkau perintahkan kepadaku mengenai hartaku? maka turulah ayat: Allah mewasiatkan kalian mengenai anak-anak kalian. (An Nisa: 11)."},"3907":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يُوسُفَ عَنْ وَرْقَاءَ عَنْ ابْنِ أَبِي نَجِيحٍ عَنْ عَطَاءٍ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَكَانَ الْمَالُ لِلْوَلَدِ وَكَانَتْ الْوَصِيَّةُ لِلْوَالِدَيْنِ فَنَسَخَ اللَّهُ مِنْ ذَلِكَ مَا أَحَبَّ فَجَعَلَ لِلذَّكَرِ مِثْلَ حَظِّ الْأُنْثَيَيْنِ وَجَعَلَ لِلْأَبَوَيْنِ لِكُلِّ وَاحِدٍ مِنْهُمَا السُّدُسَ وَالثُّلُثَ وَجَعَلَ لِلْمَرْأَةِ الثُّمُنَ وَالرُّبُعَ وَللزَّوْجِ الشَّطْرَ وَالرُّبُعَ","id":"Telah menceritakan kepada kami [Muhammad bin Yusuf] dari [Warqa] dari [Ibnu Abu Najih] dari ['Atha] dari [Ibnu 'Abbas radliallahu 'anhuma] dia berkata; \"Bahwasanya dahulu harta untuk anak dan wasiat untuk orang tua. Lalu Allah menghapus hal itu sesuai apa yang Ia kehendaki dan mengganti dengan bagian laki-laki seperti bagian dua perempuan, bagian untuk kedua orang tua masing-masing mendapatkan seperenam dan sepertiga, menjadikan untuk isteri seperdelapan dan seperempat, dan untuk suami setengah dan seperempat.\""},"3908":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ مُقَاتِلٍ حَدَّثَنَا أَسْبَاطُ بْنُ مُحَمَّدٍ حَدَّثَنَا الشَّيْبَانِيُّ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَ الشَّيْبَانِيُّ وَذَكَرَهُ أَبُو الْحَسَنِ السُّوَائِيُّ وَلَا أَظُنُّهُ ذَكَرَهُ إِلَّا عَنْ ابْنِ عَبَّاسٍ{ يَا أَيُّهَا الَّذِينَ آمَنُوا لَا يَحِلُّ لَكُمْ أَنْ تَرِثُوا النِّسَاءَ كَرْهًا وَلَا تَعْضُلُوهُنَّ لِتَذْهَبُوا بِبَعْضِ مَا آتَيْتُمُوهُنَّ }قَالَ كَانُوا إِذَا مَاتَ الرَّجُلُ كَانَ أَوْلِيَاؤُهُ أَحَقَّ بِامْرَأَت��هِ إِنْ شَاءَ بَعْضُهُمْ تَزَوَّجَهَا وَإِنْ شَاءُوا زَوَّجُوهَا وَإِنْ شَاءُوا لَمْ يُزَوِّجُوهَا فَهُمْ أَحَقُّ بِهَا مِنْ أَهْلِهَا فَنَزَلَتْ هَذِهِ الْآيَةُ فِي ذَلِكَ","id":"Telah menceritakan kepada kami [Muhammad bin Muqatil] Telah menceritakan kepada kami [Asbath bin Muhammad] Telah menceritakan kepada kami [Asy Syaibani] dari ['Ikrimah] dari [Ibnu 'Abbas] dia berkata; -Asy Syaibani berkata-; juga disebutkan oleh [Abu Al Hasan As Suwai] dan aku tidak mengira dia menyebutkannya kecuali dari [Ibnu 'Abbas] mengenai firman Allah: \"Hai orang-orang yang beriman, tidak halal bagi kamu mempusakai wanita dengan jalan paksa dan janganlah kamu menyusahkan mereka (Annisa: 19). Dahulu apabila seorang suami meninggal, maka wali-nya laki-laki tersebut lebih berhak terhadap istrinya si mayyit, apabila si wali berkehendak untuk menikahi istri si mayyit untuk dirinya maka dia akan menikahinya atau menikahkannya kepada orang lain atau tidak menikahkannya sama sekali. Maka turunlah ayat ini."},"3909":{"ar":"حَدَّثَنِي الصَّلْتُ بْنُ مُحَمَّدٍ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ إِدْرِيسَ عَنْ طَلْحَةَ بْنِ مُصَرِّفٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا{ وَلِكُلٍّ جَعَلْنَا مَوَالِيَ }قَالَ وَرَثَةً{ وَالَّذِينَ عَاقَدَتْ أَيْمَانُكُمْ }كَانَ الْمُهَاجِرُونَ لَمَّا قَدِمُوا الْمَدِينَةَ يَرِثُ الْمُهَاجِرِيُّ الْأَنْصَارِيَّ دُونَ ذَوِي رَحِمِهِ لِلْأُخُوَّةِ الَّتِي آخَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَيْنَهُمْ فَلَمَّا نَزَلَتْ{ وَلِكُلٍّ جَعَلْنَا مَوَالِيَ }نُسِخَتْ ثُمَّ قَالَ{ وَالَّذِينَ عَاقَدَتْ أَيْمَانُكُمْ }مِنْ النَّصْرِ وَالرِّفَادَةِ وَالنَّصِيحَةِ وَقَدْ ذَهَبَ الْمِيرَاثُ وَيُوصِي لَهُسَمِعَ أَبُو أُسَامَةَ إِدْرِيسَ وَسَمِعَ إِدْرِيسُ طَلْحَةَ","id":"Telah menceritakan kepadaku [Ash Shalt bin Muhammad] Telah menceritakan kepada kami [Abu Usamah] dari [Idris] dari [Thalhah bin Musharrif] dari [Sa'id bin Jubair] dari [Ibnu 'Abbas radliallahu 'anhuma] mengenai firman Allah; Bagi tiap-tiap harta peninggalan dari harta….. (An Nisa: 33). Ibnu Abbas berkata; Yaitu dijadikan pewaris. Dan (jika ada) orang-orang yang kamu telah bersumpah setia dengan mereka, maka berilah kepada mereka bagiannya. Dahulu tatkala orang-orang muhajirin datang ke Madinah, orang Muhajirin dapat mewariskan kepada orang Anshar walaupun tidak ada hubungan kekerabatan. Hanya sebatas tali persaudaraan yang telah dilakukan oleh Nabi shallallahu 'alaihi wasallam di antara mereka. Tatkala ayat ini turun: Bagi tiap-tiap harta peninggalan dari harta….. (An Nisa: 33). Maka kebiasaan itu dihapus. Selanjutnya ayat: Dan (jika ada) orang-orang yang kamu telah bersumpah setia dengan mereka, maka berilah kepada mereka bagiannya, hal ini menunjukan bolehnya saling menolong, melayani, memberi nasihat, memberi wasiat selelah dihapuskannya saling mewarisi di antara mereka. Demikian juga Abu Usamah mendengar hal ini dari Idris dan Idris mendengar dari Thalhah."},"3910":{"ar":"حَدَّثَنِي مُحَمَّدُ بْنُ عَبْدِ الْعَزِيزِ حَدَّثَنَا أَبُو عُمَرَ حَفْصُ بْنُ مَيْسَرَةَ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ رَضِيَ اللَّهُ عَنْهُأَنَّ أُنَاسًا فِي زَمَنِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالُوا يَا رَسُولَ اللَّهِ هَلْ نَرَى رَبَّنَا يَوْمَ الْقِيَامَةِ قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَعَمْ هَلْ تُضَارُّونَ فِي رُؤْيَةِ الشَّمْسِ بِالظَّهِيرَةِ ضَوْءٌ لَيْسَ فِيهَا سَحَابٌ قَالُوا لَا قَالَ وَهَلْ تُضَارُّونَ فِي رُؤْيَةِ الْقَمَرِ لَيْلَةَ الْبَدْرِ ضَوْءٌ لَيْسَ فِيهَا سَحَابٌ قَالُوا لَا قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا تُضَارُونَ فِي رُؤْيَةِ اللَّهِ عَزَّ وَجَلَّ يَوْمَ الْقِيَامَةِ إِلَّا كَمَا تُضَارُونَ فِي رُؤْيَةِ أَحَدِهِمَا إِذَا كَانَ يَوْمُ الْقِيَامَةِ أَذَّنَ مُؤَذِّنٌ تَتْبَعُ كُلُّ أُمَّةٍ مَا كَانَتْ تَعْبُدُ فَلَا يَبْقَى مَنْ كَانَ يَعْبُدُ غَيْرَ اللَّهِ مِنْ الْأَصْنَامِ وَالْأَنْصَابِ إِلَّا يَتَسَاقَطُونَ فِي النَّارِ حَتَّى إِذَا لَمْ يَبْقَ إِلَّا مَنْ كَانَ يَعْبُدُ اللَّهَ بَرٌّ أَوْ فَاجِرٌ وَغُبَّرَاتُ أَهْلِ الْكِتَابِ فَيُدْعَى الْيَهُودُ فَيُقَالُ لَهُمْ مَنْ كُنْتُمْ تَعْبُدُونَ قَالُوا كُنَّا نَعْبُدُ عُزَيْرَ ابْنَ اللَّهِ فَيُقَالُ لَهُمْ كَذَبْتُمْ مَا اتَّخَذَ اللَّهُ مِنْ صَاحِبَةٍ وَلَا وَلَدٍ فَمَاذَا تَبْغُونَ فَقَالُوا عَطِشْنَا رَبَّنَا فَاسْقِنَا فَيُشَارُ أَلَا تَرِدُونَ فَيُحْشَرُونَ إِلَى النَّارِ كَأَنَّهَا سَرَابٌ يَحْطِمُ بَعْضُهَا بَعْضًا فَيَتَسَاقَطُونَ فِي النَّارِ ثُمَّ يُدْعَى النَّصَارَى فَيُقَالُ لَهُمْ مَنْ كُنْتُمْ تَعْبُدُونَ قَالُوا كُنَّا نَعْبُدُ الْمَسِيحَ ابْنَ اللَّهِ فَيُقَالُ لَهُمْ كَذَبْتُمْ مَا اتَّخَذَ اللَّهُ مِنْ صَاحِبَةٍ وَلَا وَلَدٍ فَيُقَالُ لَهُمْ مَاذَا تَبْغُونَ فَكَذَلِكَ مِثْلَ الْأَوَّلِ حَتَّى إِذَا لَمْ يَبْقَ إِلَّا مَنْ كَانَ يَعْبُدُ اللَّهَ مِنْ بَرٍّ أَوْ فَاجِرٍ أَتَاهُمْ رَبُّ الْعَالَمِينَ فِي أَدْنَى صُورَةٍ مِنْ الَّتِي رَأَوْهُ فِيهَا فَيُقَالُ مَاذَا تَنْتَظِرُونَ تَتْبَعُ كُلُّ أُمَّةٍ مَا كَانَتْ تَعْبُدُ قَالُوا فَارَقْنَا النَّاسَ فِي الدُّنْيَا عَلَى أَفْقَرِ مَا كُنَّا إِلَيْهِمْ وَلَمْ نُصَاحِبْهُمْ وَنَحْنُ نَنْتَظِرُ رَبَّنَا الَّذِي كُنَّا نَعْبُدُ فَيَقُولُ أَنَا رَبُّكُمْ فَيَقُو��ُونَ لَا نُشْرِكُ بِاللَّهِ شَيْئًا مَرَّتَيْنِ أَوْ ثَلَاثًا","id":"Telah menceritakan kepadaku [Muhammad bin 'Abdul 'Aziz] Telah menceritakan kepada kami [Abu 'Umar Hafsh bin Maisarah] dari [Zaid bin Aslam] dari ['Atha bin Yasar] dari [Sa'id Al Khudri radliallahu 'anhu] dia berkata; sejumlah orang pada masa Rasulullah shallallahu 'alaihi wasallam berkata; 'Ya Rasulullah, apakah kami dapat melihat Allah pada hari kiamat? Nabi shallallahu 'alaihi wasallam menjawab. 'Ya, ' apakah kalian merasa kesulitan melihat matahari yang terang benderang serta tidak ada mendung?\" Mereka berkata: \"Tidak wahai Rasulullah!\" lalu Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apakah kalian merasa kesullitan melihat rembulan pada malam purnama yang tidak ada mendung dibawahnya?\", mereka berkata; \"Tidak, wahai Rasulullah!\" Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya kalian akan melihat-Nya kelak pada hari kiamat tanpa merasa kesulitan sebagaimana kalian melihat salah satu dari keduanya. Pada hari kiamat, sang penyeru akan mengumumkan, setiap umat mengikuti apa yang mereka sembah. Maka mereka yang menyembah selain Allah seperti berhala dan tuhan-tuhan yang lain akan berjatuhan ke neraka. Hingga yang tinggal hanyalah mereka yang menyembah Allah baik orang-orang yang saleh maupun orang yang jahat dan sejumlah orang dari ahlu kitab. Kemudian orang Yahudi akan dipanggil, Allah akan bertanya kepada mereka: Apa yang kamu sembah? Mereka menjawab; 'Kami menyembah Uzair putra Allah. Maka akan dikatakan kepada mereka; 'Kalian adalah para pendusta! Karena Allah tidak pernah mengambil istri atau memilik anak. Apa yang sekarang kalian inginkan? Mereka menjawab; 'Kami sangat haus ya Rabb, maka berilah kami minum. Maka mereka digiring dan ditunjukan, 'Minumlah. Pada saat itulah mereka akan dikumpulkan di dalam api neraka yang bentuknya seperti fatamorgana yang saling merusak satu sama yang lainnya. Kemudian mereka akan ditenggelamkan ke dalam api neraka. Setelah itu orang-orang Nashrani akan dipanggil, Apa yang kamu sembah? Mereka menjawab; 'Yesus putra Allah. Maka dikatakan kepada mereka: 'Kalian adalah para pendusta! Karena Allah tidak pernah mengambil istri atau memilik anak. Apa yang sekarang kalian inginkan? Maka mereka menjawab sebagaimana orang Yahudi dan akan dilemparkan ke dalam api neraka. Kemudian yang tetap tinggal adalah mereka yang hanya beribadah kepada Allah. Baik itu orang saleh atau orang yang berbuat kejahatan. Allah akan mendatangi mereka dalam bentuk yang mendekati gambaran mereka tentang Dia dalam benak mereka. Akan dikatakan kepada mereka; Apa yang kalian tunggu? Setiap bangsa mengikuti tuhan yang disembahnya didunia. Mereka akan menjawab; Kami meninggalkan orang-orang di dunia ketika kami sedang sangat membutuhkan mereka dan kami tidak mengambil mereka sebagai tandingan. Sekarang kami sedang menunggu Rabb kami yang kami sembah. Maka Allah akan berkata; Akulah Rabb kalian, mereka akan senantiasa berkata, sebanyak dua atau tiga kali; 'Kami tidak menyekutukan Allah.'"},"3911":{"ar":"حَدَّثَنَا صَدَقَةُ أَخْبَرَنَا يَحْيَى عَنْ سُفْيَانَ عَنْ سُلَيْمَانَ عَنْ إِبْرَاهِيمَ عَنْ عَبِيدَةَ عَنْ عَبْدِ اللَّهِ قَالَ يَحْيَى بَعْضُ الْحَدِيثِ عَنْ عَمْرِو بْنِ مُرَّةَ قَالَقَالَ لِي النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اقْرَأْ عَلَيَّ قُلْتُ آقْرَأُ عَلَيْكَ وَعَلَيْكَ أُنْزِلَ قَالَ فَإِنِّي أُحِبُّ أَنْ أَسْمَعَهُ مِنْ غَيْرِي فَقَرَأْتُ عَلَيْهِ سُورَةَ النِّسَاءِ حَتَّى بَلَغْتُ{ فَكَيْفَ إِذَا جِئْنَا مِنْ كُلِّ أُمَّةٍ بِشَهِيدٍ وَجِئْنَا بِكَ عَلَى هَؤُلَاءِ شَهِيدًا }قَالَ أَمْسِكْ فَإِذَا عَيْنَاهُ تَذْرِفَانِ","id":"Telah menceritakan kepada kami [Shadaqah] Telah mengabarkan kepada kami [Yahya] dari [Sufyan] dari [Sulaiman] dari [Ibrahim] dari ['Abidah] dari ['Abdullah] berkata; Yahya -sebagian Hadits- dari ['Amru bin Murrah] dia berkata; Nabi shallallahu 'alaihi wasallam bersabda kepadaku: \"Bacakanlah Al Qur'an kepadaku! Aku berkata; Bagaimana aku membacakan kepadamu, padahal Al Qur'an diturunkan kepadamu? Beliau menjawab: \"Sesungguhnya aku suka mendengarkannya dari orang lain.\" Lalu aku membacakan kepada beliau surat An Nisa hingga tatkala sampai ayat; Maka bagaimanakah (halnya orang kafir nanti), apabila Kami mendatangkan seseorang saksi (rasul) dari tiap-tiap umat dan Kami mendatangkan kamu (Muhammad) sebagai saksi atas mereka itu (sebagai umatmu (An Nisa; 41), \" beliau berkata; 'Cukup.' Dan ternyata beliau mencucurkan air mata (menangis)."},"3912":{"ar":"حَدَّثَنِي مُحَمَّدٌ أَخْبَرَنَا عَبْدَةُ عَنْ هِشَامٍ عَنْ أَبِيهِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْهَلَكَتْ قِلَادَةٌ لِأَسْمَاءَ فَبَعَثَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي طَلَبِهَا رِجَالًا فَحَضَرَتْ الصَّلَاةُ وَلَيْسُوا عَلَى وُضُوءٍ وَلَمْ يَجِدُوا مَاءً فَصَلَّوْا وَهُمْ عَلَى غَيْرِ وُضُوءٍ فَأَنْزَلَ اللَّهُ يَعْنِي آيَةَ التَّيَمُّمِ","id":"Telah menceritakan kepadaku [Muhammad] Telah mengabarkan kepada kami ['Abdah] dari [Hisyam] dari [Bapaknya] dari ['Aisyah radliallahu 'anha] berkata; Kalung Asma' pernah hilang, maka Nabi shallallahu 'alaihi wasallam menyuruh beberapa sahabat mencari kalung itu. Lalu datanglah waktu shalat dan mereka dalam keadaan hadats serta mereka tidak mendapatkan air. Lalu mereka shalat tanpa wudlu. Maka Allah Azza wa Jalla menurunkan ayat tentang tayamum.\""},"3913":{"ar":"حَدَّثَنَا صَدَقَةُ بْنُ الْفَضْلِ أَخْبَرَنَا حَجَّاجُ بْنُ مُحَمَّدٍ عَنْ ابْنِ جُرَيْجٍ عَنْ يَعْلَى بْنِ مُسْلِمٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا{ أَطِيعُوا اللَّهَ وَأَطِيعُوا الرَّسُولَ وَأُولِي الْأَمْرِ مِنْكُمْ }قَالَ نَزَلَتْ فِي عَبْدِ اللَّهِ بْنِ حُذَافَةَ بْنِ قَيْسِ بْنِ عَدِيٍّ إِذْ بَعَثَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي سَرِيَّةٍ","id":"Telah menceritakan kepada kami [Shadaqah bin Al Fadll] Telah mengabarkan kepada kami [Hajjaj bin Muhammad] dari [Ibnu Juraij] dari [Ya'la bin Muslim] dari [Sa'id bin Jubair] dari [Ibnu 'Abbas radliallahu 'anhuma] mengenai firman Allah: Ta'atilah kalian kepada Allah dan Rasul-Nya serta kepada pemimpin kalian. Ibnu Abbas berkata; Ayat ini turun berkenaan dengan Abdullah bin Hudzafah bin Qais ketika Nabi shallallahu 'alaihi wasallam mengutusnya dalam sebuah sariyah (peperangan)."},"3914":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ قَالَخَاصَمَ الزُّبَيْرُ رَجُلًا مِنْ الْأَنْصَارِ فِي شَرِيجٍ مِنْ الْحَرَّةِ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اسْقِ يَا زُبَيْرُ ثُمَّ أَرْسِلْ الْمَاءَ إِلَى جَارِكَ فَقَالَ الْأَنْصَارِيُّ يَا رَسُولَ اللَّهِ أَنْ كَانَ ابْنَ عَمَّتِكَ فَتَلَوَّنَ وَجْهُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ قَالَ اسْقِ يَا زُبَيْرُ ثُمَّ احْبِسْ الْمَاءَ حَتَّى يَرْجِعَ إِلَى الْجَدْرِ ثُمَّ أَرْسِلْ الْمَاءَ إِلَى جَارِكَ وَاسْتَوْعَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِلزُّبَيْرِ حَقَّهُ فِي صَرِيحِ الْحُكْمِ حِينَ أَحْفَظَهُ الْأَنْصَارِيُّ كَانَ أَشَارَ عَلَيْهِمَا بِأَمْرٍ لَهُمَا فِيهِ سَعَةٌ قَالَ الزُّبَيْرُ فَمَا أَحْسِبُ هَذِهِ الْآيَاتِ إِلَّا نَزَلَتْ فِي ذَلِكَ{ فَلَا وَرَبِّكَ لَا يُؤْمِنُونَ حَتَّى يُحَكِّمُوكَ فِيمَا شَجَرَ بَيْنَهُمْ }","id":"Telah menceritakan kepada kami ['Ali bin 'Abdullah] Telah menceritakan kepada kami [Muhammad bin Ja'far] Telah mengabarkan kepada kami [Ma'mar] dari [Az Zuhri] dari ['Urwah] berkata; bahwa seorang laki-laki Anshar berselisih dengan Az Zubair mengenai mata air Al Harrah. Rasulullah shallallahu 'alaihi wasallam kemudian bersabda: \"Alirilah kebunmu wahai Zubair, setelah itu berikanlah kepada tetanggamu.\" Tetapi laki-laki Anshar itu marah seraya berkata; \"Wahai Rasulullah, apakah karena ia anak dari pamanmu!\" Maka Wajah Rasulullah shallallahu 'alaihi wasallam memerah, kemudian beliau bersabda: \"Wahai Zubair, airilah kebunmu, setelah itu tahanlah hingga airnya kembali ke dalam tanah kemudian berikanlah kepada tetanggamu!\" Nabi shallallahu 'alaihi wasallam berharap agar Zubair bisa memahami mengenai haknya dengan keputusan yang tegas. Padahal sebelumnya beliau memberikan kemudahan untuk Zubair dan orang Anshar, tapi ketika orang Anshar marah kepada Rasulullah shallallahu 'alaihi wasallam akhirnya beliau memberikan semua bagian kepada Zubair. [Zubair] radliallahu 'anhu berkata; \"Demi Allah, aku mengira bahwa ayat ini tidak turun kecuali berkaitan dengan masalah itu: \"Maka demi Tuhanmu, mereka (pada hakekatnya) tidak beriman hingga mereka menjadikan kamu hakim terhadap perkara yang mereka perselisihkan, Kemudian mereka tidak merasa dalam hati mereka sesuatu keberatan terhadap putusan yang kamu berikan, dan mereka menerima dengan sepenuhnya. (QS; an Nisaa`; 65).\""},"3915":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ حَوْشَبٍ حَدَّثَنَا إِبْرَاهِيمُ بْنُ سَعْدٍ عَنْ أَبِيهِ عَنْ عُرْوَةَ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَا مِنْ نَبِيٍّ يَمْرَضُ إِلَّا خُيِّرَ بَيْنَ الدُّنْيَا وَالْآخِرَةِ وَكَانَ فِي شَكْوَاهُ الَّذِي قُبِضَ فِيهِ أَخَذَتْهُ بُحَّةٌ شَدِيدَةٌ فَسَمِعْتُهُ يَقُولُ{ مَعَ الَّذِينَ أَنْعَمَ اللَّهُ عَلَيْهِمْ مِنْ النَّبِيِّينَ وَالصِّدِّيقِينَ وَالشُّهَدَاءِ وَالصَّالِحِينَ }فَعَلِمْتُ أَنَّهُ خُيِّرَ","id":"Telah menceritakan kepada kami [Muhammad bin 'Abdullah bin Hausyab] Telah menceritakan kepada kami [Ibrahim bin Sa'ad] dari [Bapaknya] dari ['Urwah] dari ['Aisyah radliallahu 'anha] ia berkata; Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidaklah seorang nabi sakit kecuali akan diberi pilihan antara dunia dan akhirat.\" Aisyah berkata; Dan Nabi shallallahu 'alaihi wasallam ketika sakit yang menyebabkan kematiannya, aku mendengar beliau menuturkan dengan terputus-putus, beliau bersabda: \"Bersama orang-orang yang telah Allah beri nikmat kepada mereka, baik dari para nabi, orang-orang yang jujur, orang-orang yang mati syahid, dan orang-orang yang shalih dan mereka itulah sebaik-baik teman.\" Maka aku tahu bahwa waktu itu beliau sedang diberi pilihan."},"3916":{"ar":"حَدَّثَنِي عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ حَدَّثَنَا سُفْيَانُ عَنْ عُبَيْدِ اللَّهِ قَالَ سَمِعْتُ ابْنَ عَبَّاسٍ قَالَكُنْتُ أَنَا وَأُمِّي مِنْ الْمُسْتَضْعَفِينَ مِنْ الرِّجَالِ وَالنِّسَاءِ","id":"Telah menceritakan kepadaku ['Abdullah bin Muhammad] Telah menceritakan kepada kami [Sufyan] dari ['Ubaidillah] dia berkata; Aku mendengar [Ibnu 'Abbas] berkata; Aku bersama Ibuku termasuk dalam ayat; \"mereka yang tertindas baik laki-laki atau wanita.\" (An Nisa: 98)."},"3917":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ أَيُّوبَ عَنْ ابْنِ أَبِي مُلَيْكَةَ أَنَّ ابْنَ عَبَّاسٍتَلَا{ إِلَّا الْمُسْتَضْعَفِينَ مِنْ الرِّجَالِ وَالنِّسَاءِ وَالْوِلْدَانِ }قَالَ كُنْتُ أَنَا وَأُمِّي مِمَّنْ عَذَرَ اللَّهُوَيُذْكَرُ عَنْ ابْنِ عَبَّاسٍ{ حَصِرَتْ }ضَاقَتْ{ تَلْوُوا }أَلْسِنَتَكُمْ بِالشَّهَادَةِ وَقَالَ غَيْرُهُ الْمُرَاغَمُ الْمُهَاجَرُ رَاغَمْتُ هَاجَرْتُ قَوْمِي{ مَوْقُوتًا }مُوَقَّتًا وَقْتَهُ عَلَيْهِمْ","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] Telah menceritakan kepada kami [Hammad bin Zaid] dari [Ayyub] dari [Ibnu Abu Mulaikah] bahwa [Ibnu 'Abbas] membaca ayat; \"kecuali mereka yang tertindas baik laki-laki atau wanita ataupun anak-anak yang tidak mampu berdaya upaya dan tidak mengetahui jalan untuk hijrah.\" (An Nisa: 98) lalu dia berkata; Aku dan Ibuku termasuk orang yang mendapat udzur dari Allah. dan disebutkan pula dari Ibnu Abbas, makna hashirat yaitu 'sempit.' Sedangkan makna TALWUU yaitu 'memutar balikkan lisan kalian dalam bersaksi.' Sedangkan yang lainnya berkata; arti 'Al Muragham' adalah Al Muhajir (orang yang berhijrah). 'Raghamtu' artinya saya berhijrah dari kaumku. Adapun arti MAUQUUTAN (An Nisa: 103). adalah waktunya telah ditentukan bagi mereka."},"3918":{"ar":"حَدَّثَنِي مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا غُنْدَرٌ وَعَبْدُ الرَّحْمَنِ قَالَا حَدَّثَنَا شُعْبَةُ عَنْ عَدِيٍّ عَنْ عَبْدِ اللَّهِ بْنِ يَزِيدَ عَنْ زَيْدِ بْنِ ثَابِتٍ رَضِيَ اللَّهُ عَنْهُ{ فَمَا لَكُمْ فِي الْمُنَافِقِينَ فِئَتَيْنِ }رَجَعَ نَاسٌ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ أُحُدٍ وَكَانَ النَّاسُ فِيهِمْ فِرْقَتَيْنِ فَرِيقٌ يَقُولُ اقْتُلْهُمْ وَفَرِيقٌ يَقُولُ لَا فَنَزَلَتْ{ فَمَا لَكُمْ فِي الْمُنَافِقِينَ فِئَتَيْنِ }وَقَالَ إِنَّهَا طَيْبَةُ تَنْفِي الْخَبَثَ كَمَا تَنْفِي النَّارُ خَبَثَ الْفِضَّةِ","id":"Telah menceritakan kepadaku [Muhammad bin Basysyar] Telah menceritakan kepada kami [Ghundar] dan ['Abdur Rahman] berkata; Telah menceritakan kepada kami [Syu'bah] dari ['Adi] dari ['Abdullah bin Yazid] dari [Zaid bin Tsabit radliallahu 'anhu] bahwa ia berkata mengenai ayat; 'famaa lakum fiil munafiqiin fi`atain' Maka mengapa kamu (terpecah) menjadi dua golongan. Zaid berkata; Beberapa orang dari sahabat Nabi shallallahu 'alaihi wasallam kembali dari perang Uhud, hingga mereka terpecah menjadi dua kelompok yang menyatakan perang dan sekelompok yang menyatakan tidak berperang, lalu turun ayat ini 'famaa lakum fiil munafiqiin fi`atain' juga ia berkata; \"Merekalah orang yang baik, yang telah membersihkan kotoran sebagaimana api membersihkan karat-karat logam.\""},"3919":{"ar":"حَدَّثَنَا آدَمُ بْنُ أَبِي إِيَاسٍ حَدَّثَنَا شُعْبَةُ حَدَّثَنَا مُغِيرَةُ بْنُ النُّعْمَانِ قَالَ سَمِعْتُ سَعِيدَ بْنَ جُبَيْرٍ قَالَآيَةٌ اخْتَلَفَ فِيهَا أَهْلُ الْكُوفَةِ فَرَحَلْتُ فِيهَا إِلَى ابْنِ عَبَّاسٍ فَسَأَلْتُهُ عَنْهَا فَقَالَ نَزَلَتْ هَذِهِ الْآيَةُ{ وَمَنْ يَقْتُلْ مُؤْمِنًا مُتَعَمِّدًا فَجَزَاؤُهُ جَهَنَّمُ }هِيَ آخِرُ مَا نَزَلَ وَمَا نَسَخَهَا شَيْءٌ","id":"Telah menceritakan kepada kami [Adam bin Abu Iyas] Telah menceritakan kepada kami [Syu'bah] Telah menceritakan kepada kami [Mughirah bin An Nu'man] ia berkata; Aku mendengar [Sa'id bin Jubair] berkata; ada sebuah ayat yang menyebabkan penduduk Kufah berselisih tentangnya, maka aku berangkat menemui Ibnu Abbas untuk menanyakan ayat itu. Lalu [Ibnu Abbas] berkata; Yaitu ayat: \"Dan barangsiapa yang membunuh seorang mukmin dengan sengaja maka balasannya ialah Jahannam, kekal ia di dalamnya dan Allah murka kepadanya.\" (An Nisa: 93). Ayat ini adalah ayat yang terakhir turun dari surat An Nisa, tidak ada yang menghapusnya sedikitpun."},"3920":{"ar":"حَدَّثَنِي عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا سُفْيَانُ عَنْ عَمْرٍو عَنْ عَطَاءٍ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا{ وَلَا تَقُولُوا لِمَنْ أَلْقَى إِلَيْكُمْ السَّلَامَ لَسْتَ مُؤْمِنًا }قَالَ قَالَ ابْنُ عَبَّاسٍ كَانَ رَجُلٌ فِي غُنَيْمَةٍ لَهُ فَلَحِقَهُ الْمُسْلِمُونَ فَقَالَ السَّلَامُ عَلَيْكُمْ فَقَتَلُوهُ وَأَخَذُوا غُنَيْمَتَهُ فَأَنْزَلَ اللَّهُ فِي ذَلِكَ إِلَى قَوْلِهِ{ تَبْتَغُونَ عَرَضَ الْحَيَاةِ الدُّنْيَا }تِلْكَ الْغُنَيْمَةُ قَالَ قَرَأَ ابْنُ عَبَّاسٍ السَّلَامَ","id":"Telah menceritakan kepadaku ['Ali bin 'Abdullah] Telah menceritakan kepada kami [Sufyan] dari ['Amru] dari ['Atha] dari [Ibnu 'Abbas radliallahu 'anhuma] mengenai firman Allah: \"Dan janganlah kamu mengatakan kepada orang yang mengucapkan 'salam' kepadamu: 'Kamu bukan seorang mu'min.\" (An Nisaa: 94) Ibnu Abbas berkata; \"Beberapa orang muslim menemui seseorang yang tengah berada dikambing-kambing miliknya lalu ia mengucapkan: Assalaamu 'Alaikum. Namun mereka menangkapnya lalu membunuhnya kemudian mengambil kambing-kambing tersebut, hingga ayat; \"dengan harapan kalian mendapatkan kekayaan dunia, yaitu kambing-kambing itu. Ibnu Abbas membacanya; 'As Salaama.'"},"3921":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ بْنُ عَبْدِ اللَّهِ قَالَ حَدَّثَنِي إِبْرَاهِيمُ بْنُ سَعْدٍ عَنْ صَالِحِ بْنِ كَيْسَانَ عَنْ ابْنِ شِهَابٍ قَالَ حَدَّثَنِي سَهْلُ بْنُ سَعْدٍ السَّاعِدِيُّ أَنَّهُ رَأَى مَرْوَانَ بْنَ الْحَكَمِ فِي الْمَسْجِدِ فَأَقْبَلْتُ حَتَّى جَلَسْتُ إِلَى جَنْبِهِ فَأَخْبَرَنَا أَنَّ زَيْدَ بْنَ ثَابِتٍ أَخْبَرَهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمْلَى عَلَيْهِ{ لَا يَسْتَوِي الْقَاعِدُونَ مِنْ الْمُؤْمِنِينَ }{ وَالْمُجَاهِدُونَ فِي سَبِيلِ اللَّهِ }فَجَاءَهُ ابْنُ أُمِّ مَكْتُومٍ وَهْوَ يُمِلُّهَا عَلَيَّ قَالَ يَا رَسُولَ اللَّهِ وَاللَّهِ لَوْ أَسْتَطِيعُ الْجِهَادَ لَجَاهَدْتُ وَكَانَ أَعْمَى فَأَنْزَلَ اللَّهُ عَلَى رَسُولِهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَفَخِذُهُ عَلَى فَخِذِي فَثَقُلَتْ عَلَيَّ حَتَّى خِفْتُ أَنْ تَرُضَّ فَخِذِي ثُمَّ سُرِّيَ عَنْهُ فَأَنْزَلَ اللَّهُ{ غَيْرَ أُولِي الضَّرَرِ }","id":"Telah menceritakan kepada kami [Isma'il bin 'Abdullah] dia berkata; Telah menceritakan kepadaku [Ibrahim bin Sa'ad] dari [Shalih bin Kaisan] dari [Ibnu Syihab] dia berkata; Telah menceritakan kepadaku [Sahl bin Sa'ad As Sa'idi] bahwasanya dia melihat [Marwan bin Hakam] sedang berada dimasjid maka aku menemuinya dan duduk di sampingnya. Ia mengabarkan kepada kami, dari [Zaid bin Tsabit] bahwa Rasulullah shallallahu 'alaihi wasallam bahwa mendiktekan kepadanya ayat LAA YASTAWIL QAA'IDUUNA MINAL MUKMINIINA WAL MUJAAHIDUUNA FII SABIILILLAAH' 'Tidaklah sama antara orang mukmin yang tidak ikut berperang dan mereka yang berjihad fii sabilillah.' (An Nisa: 95) Kemudian datang kepadanya Ibnu Ummi Maktum dan beliau mendiktekannya kepadaku. Lalu ia berkata; wahai Rasulullah shallallahu 'alaihi wasallam seandainya saya mampu untuk berjihad, niscaya saya akan berjihad. Dan ia adalah orang yang buta, kemudian Allah menurunkan kepada Rasul-Nya shallallahu 'alaihi wasallam dan pahanya berada di atas pahaku hingga terasa berat bagiku hampir aku merasa takut pahaku patah, kemudian terhilangkan kesusahannya, dan Allah 'azza wajalla menurunkan ayat GHAIRU ULIDHDLARAR' 'Kecuali orang-orang yang mempunyai halangan'."},"3922":{"ar":"حَدَّثَنَا حَفْصُ بْنُ عُمَرَ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي إِسْحَاقَ عَنْ الْبَرَاءِ رَضِيَ اللَّهُ عَنْهُ قَالَلَمَّا نَزَلَتْ{ لَا يَسْتَوِي الْقَاعِدُونَ مِنْ الْمُؤْمِنِينَ }دَعَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ زَيْدًا فَكَتَبَهَا فَجَاءَ ابْنُ أُمِّ مَكْتُومٍ فَشَكَا ضَرَارَتَهُ فَأَنْزَلَ اللَّهُ{ غَيْرَ أُولِي الضَّرَرِ }","id":"Telah menceritakan kepada kami [Hafsh bin 'Umar] Telah menceritakan kepada kami [Syu'bah] dari [Abu Ishaq] dari [Al Bara' radliallahu 'anhu] berkata; tatkala turun ayat: LAA YASTAWIL QAA'IDUUNA MINAL MUKMINIINA WAL MUJAAHIDUUNA FII SABIILILLAAH' 'Tidaklah sama antara orang mukmin yang tidak ikut berperang dan mereka yang berjihad fii sabilillah.' (An Nisa: 95) Rasulullah shallallahu 'alaihi wasallam memanggil Zaid, lalu Zaid menulisnya. Kemudian Ummi Maktum datang mengadukan kesulitannya untuk ikut berperang karena buta. Maka Allah menurunkan ayat: GHAIRU ULIDLDLARAR' 'Kecuali orang-orang yang mempunyai halangan'."},"3923":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يُوسُفَ عَنْ إِسْرَائِيلَ عَنْ أَبِي إِسْحَاقَ عَنْ الْبَرَاءِ قَالَلَمَّا نَزَلَتْ{ لَا يَسْتَوِي الْقَاعِدُونَ مِنْ الْمُؤْمِنِينَ }قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ادْعُوا فُلَانًا فَجَاءَهُ وَمَعَهُ الدَّوَاةُ وَاللَّوْحُ أَوْ الْكَتِفُ فَقَالَ اكْتُبْ{ لَا يَسْتَوِي الْقَاعِدُونَ مِنْ الْمُؤْمِنِينَ }{ وَالْمُجَاهِدُونَ فِي سَبِيلِ اللَّهِ }وَخَلْفَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ابْنُ أُمِّ مَكْتُومٍ فَقَالَ يَا رَسُولَ اللَّهِ أَنَا ضَرِيرٌ فَنَزَلَتْ مَكَانَهَا{ لَا يَسْتَوِي الْقَاعِدُونَ مِنْ الْمُؤْمِنِينَ غَيْرَ أُولِي الضَّرَرِ وَالْمُجَاهِدُونَ فِي سَبِيلِ اللَّهِ }","id":"Telah menceritakan kepada kami [Muhammad bin Yusuf] dari [Israil] dari [Abu Ishaq] dari [Al Bara'] dia berkata; LAA YASTAWIL QAA'IDUUNA MINAL MUKMINIINA WAL MUJAAHIDUUNA FII SABIILILLAAH' 'Tidaklah sama antara orang mukmin yang tidak ikut berperang dan mereka yang berjihad fii sabilillah.' (An Nisa: 95), Nabi shallallahu 'alaihi wasallam bersabda: \"Panggilkan si fulan, maka ia datang seraya membawa tempat tinta dan lembaran dari kayu atau tulang. Lalu Nabi shallallahu 'alaihi wasallam bersabda: Tulislah: \"LAA YASTAWIL QAA'IDUUNA MINAL MUKMINIINA WAL MUJAAHIDUUNA FII SABIILILLAAH\" 'Tidaklah sama antara orang mukmin yang tidak ikut berperang dan mereka yang berjihad fii sabilillah.' (An Nisa: 95) sedangkan di belakang Nabi shallallahu 'alaihi wasallam ada Ummi Maktum, lalu dia berkata; Ya Rasulullah, aku ini buta, maka turunlah dalam ayat itu: GHAIRU ULIDLDLARAR' 'Kecuali orang-orang yang mempunyai halangan'."},"3924":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ مُوسَى أَخْبَرَنَا هِشَامٌ أَنَّ ابْنَ جُرَيْجٍ أَخْبَرَهُمْ ح و حَدَّثَنِي إِسْحَاقُ أَخْبَرَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا ابْنُ جُرَيْجٍ أَخْبَرَنِي عَبْدُ الْكَرِيمِ أَنَّ مِقْسَمًا مَوْلَى عَبْدِ اللَّهِ بْنِ الْحَارِثِ أَخْبَرَهُ أَنَّ ابْنَ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا أَخْبَرَهُ{ لَا يَسْتَوِي الْقَاعِدُونَ مِنْ الْمُؤْمِنِينَ }عَنْ بَدْرٍ وَالْخَارِجُونَ إِلَى بَدْرٍ","id":"Telah menceritakan kepada kami [Ibrahim bin Musa] Telah mengabarkan kepada kami [Hisyam] bahwa [Ibnu Juraij] Telah mengabarkan kepada mereka; Demikian juga diriwayatkan dari jalur lainnya, Dan telah menceritakan kepadaku [Ishaq] Telah mengabarkan kepada kami ['Abdur Razzaq] Telah mengabarkan kepada kami [Ibnu Juraij] Telah mengabarkan kepadaku ['Abdul Karim] bahwa [Miqsam] -budak- 'Abdullah bin Al Harits mengabarkan kepadanya dari [Ibnu 'Abbas radliallahu 'anhuma] mengenai ayat: LAA YASTAWIL QAA'IDUUNA MINAL MUKMINIINA WAL MUJAAHIDUUNA FII SABIILILLAAH' 'Tidaklah sama antara orang mukmin yang tidak ikut berperang dan mereka yang berjihad fii sabilillah.' (An Nisa: 95), yaitu yang duduk-duduk tidak ikut perang Badar dan orang-orang yang berangkat untuk berperang."},"3925":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يَزِيدَ الْمُقْرِئُ حَدَّثَنَا حَيْوَةُ وَغَيْرُهُ قَالَا حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ الرَّحْمَنِ أَبُو الْأَسْوَدِ قَالَ قُطِعَ عَلَى أَهْلِ الْمَدِينَةِ بَعْثٌ فَاكْتُتِبْتُ فِيهِ فَلَقِيتُ عِكْرِمَةَ مَوْلَى ابْنِ عَبَّاسٍ فَأَخْبَرْتُهُ فَنَهَانِي عَنْ ذَلِكَ أَشَدَّ النَّهْيِ ثُمَّ قَالَ أَخْبَرَنِي ابْنُ عَبَّاسٍأَنَّ نَاسًا مِنْ الْمُسْلِمِينَ كَانُوا مَعَ الْمُشْرِكِينَ يُكَثِّرُونَ سَوَادَ الْمُشْرِكِينَ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَأْتِي السَّهْمُ فَيُرْمَى بِهِ فَيُصِيبُ أَحَدَهُمْ فَيَقْتُلُهُ أَوْ يُضْرَبُ فَيُقْتَلُ فَأَنْزَلَ اللَّهُ{ إِنَّ الَّذِينَ تَوَفَّاهُمْ الْمَلَائِكَةُ ظَالِمِي أَنْفُسِهِمْ }الْآيَةَرَوَاهُ اللَّيْثُ عَنْ أَبِي الْأَسْوَدِ","id":"Telah menceritakan kepada kami ['Abdullah bin Yazid Al Muqri] Telah menceritakan kepada kami [Haiwah] dan yang lainnya, keduanya berkata; Telah menceritakan kepada kami [Muhammad bin 'Abdur Rahman Abu Al Aswad] berkata; dia berkata; Penduduk Kufah dipaksa untuk mengirim pasukannya memerangi penduduk Syam dan aku disuruh untuk memimpin mereka. Lalu aku bertemu dengan [Ikrimah] -mantan budak dari- Ibnu Abbas maka aku mengabarkan hal itu kepadanya, namun ia sangat melarangku untuk melalukan hal itu. Ia berkata; Telah mengabarkan kepadaku [Ibnu Abbas] bahwa sejumlah kaum muslimin pernah bersama orang-orang Musyrikin hingga menambah jumlah mereka. Lalu anak panah datang dan dilepaskan hingga mengenai salah seorang dari mereka (orang-orang muslim yang berada di tengah-tengah kaum musyrikin) dan membunuhnya atau ditebas hingga terbunuh. Kemudian turunlah ayat: \"Sesungguhnya orang-orang yang diwafatkan malaikat dalam keadaan menganiaya diri sendiri. (An Nisa: 97). diriwayatkan oleh [Al Laits] dari [Abul Aswad]."},"3926":{"ar":"حَدَّثَنَا أَبُو النُّعْمَانِ حَدَّثَنَا حَمَّادٌ عَنْ أَيُّوبَ عَنْ ابْنِ أَبِي مُلَيْكَةَ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا{ إِلَّا الْمُسْتَضْعَفِينَ }قَالَ كَانَتْ أُمِّي مِمَّنْ عَذَرَ اللَّهُ","id":"Telah menceritakan kepada kami [Abu An Nu'man] Telah menceritakan kepada kami [Hammad] dari [Ayyub] dari [Ibnu Abu Mulaikah] dari [Ibnu 'Abbas radliallahu 'anhuma] dia berkata mengenai firman Allah: \"Kecuali mereka yang tertindas baik laki-laki atau wanita.\" (An Nisa: 98). Ibnu Abbas berkata; Ibuku termasuk orang yang mendapatkan udzur dari Allah."},"3927":{"ar":"حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا شَيْبَانُ عَنْ يَحْيَى عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَبَيْنَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي الْعِشَاءَ إِذْ قَالَ سَمِعَ اللَّهُ لِمَنْ حَمِدَهُ ثُمَّ قَالَ قَبْلَ أَنْ يَسْجُدَ اللَّهُمَّ نَجِّ عَيَّاشَ بْنَ أَبِي رَبِيعَةَ اللَّهُمَّ نَجِّ سَلَمَةَ بْنَ هِشَامٍ اللَّهُمَّ نَجِّ الْوَلِيدَ بْنَ الْوَلِيدِ اللَّهُمَّ نَجِّ الْمُسْتَضْعَفِينَ مِنْ الْمُؤْمِنِينَ اللَّهُمَّ اشْدُدْ وَطْأَتَكَ عَلَى مُضَرَ اللَّهُمَّ اجْعَلْهَا سِنِينَ كَسِنِي يُوسُفَ","id":"Telah menceritakan kepada kami [Abu Nu'aim] Telah menceritakan kepada kami [Syaiban] dari [Yahya] dari [Abu Salamah] dari [Abu Hurairah radliallahu 'anhu] berkata; Tatkala Nabi shallallahu 'alaihi wasallam shallallahu 'alaihi wasallam shalat Isya, ketika beliau Shallallahu'alaihi wasallam selesai mengucapkan, \"Sami'allahu liman hamidah (Allah Maha Mendengar terhadap semua yang memuji-Nya). Kemudian beliau mengucapkan doa -sambil berdiri sebelum sujud-, \"Ya Allah, selamatkanlah Ayyasy bin Abu Rabi 'ah, Salamah bin Hisyam, Al Walid bin Al Walid, serta orang-orang lemah dari kalangan kaum mukmin. Ya Allah, timpakan siksaan-Mu kepada Bani Mudhar dan jadikanlah tahun-tahun mereka seperti tahun-tahun Yusuf (penuh penderitaan, paceklik, kekeringan -penerj).\""},"3928":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ مُقَاتِلٍ أَبُو الْحَسَنِ أَخْبَرَنَا حَجَّاجٌ عَنْ ابْنِ جُرَيْجٍ قَالَ أَخْبَرَنِي يَعْلَى عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا{ إِنْ كَانَ بِكُمْ أَذًى مِنْ مَطَرٍ أَوْ كُنْتُمْ مَرْضَى }قَالَ عَبْدُ الرَّحْمَنِ بْنُ عَوْفٍ وَكَانَ جَرِيحًا","id":"Telah menceritakan kepada kami [Muhammad bin Muqatil Abu Al Hasan] Telah mengabarkan kepada kami [Hajjaj] dari [Ibnu Juraij] berkata; Telah mengabarkan kepadaku [Ya'la] dari [Sa'id bin Jubair] dari [Ibnu 'Abbas radliallahu 'anhuma] mengenai firman Allah: Jika kamu mendapat sesuatu kesusahan karena hujan atau karena kamu memang sakit (An Nisa: 102) Abdurrahman bin 'Auf berkata; pada waktu itu beliau dalam keadaan terluka."},"3929":{"ar":"حَدَّثَنَا عُبَيْدُ بْنُ إِسْمَاعِيلَ حَدَّثَنَا أَبُو أُسَامَةَ قَالَ حَدَّثَنَا هِشَامُ بْنُ عُرْوَةَ أَخْبَرَنِي أَبِي عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا{ يَسْتَفْتُونَكَ فِي النِّسَاءِ قُلْ اللَّهُ يُفْتِيكُمْ فِيهِنَّ إِلَى قَوْلِهِ وَتَرْغَبُونَ أَنْ تَنْكِحُوهُنَّ }قَالَتْ عَائِشَةُ هُوَ الرَّجُلُ تَكُونُ عِنْدَهُ الْيَتِيمَةُ هُوَ وَلِيُّهَا وَوَارِثُهَا فَأَشْرَكَتْهُ فِي مَالِهِ حَتَّى فِي الْعَذْقِ فَيَرْغَبُ أَنْ يَنْكِحَهَا وَيَكْرَهُ أَنْ يُزَوِّجَهَا رَجُلًا فَيَشْرَكُهُ فِي مَالِهِ بِمَا شَرِكَتْهُ فَيَعْضُلُهَا فَنَزَلَتْ هَذِهِ الْآيَةُ","id":"Telah menceritakan kepada kami ['Ubaid bin Isma'il] Telah menceritakan kepada kami [Abu Usamah] berkata; Telah menceritakan kepada kami [Hisyam bin 'Urwah] Telah mengabarkan kepadaku [Bapakku] dari ['Aisyah radliallahu 'anhu] mengenai firman Allah: Dan mereka minta fatwa kepadamu tentang para wanita. Katakanlah: \"Allah memberi fatwa kepadamu tentang mereka, dan apa yang dibacakan kepadamu dalam Al Quran (juga memfatwakan) tentang para wanita yatim yang kamu tidak memberikan kepada mereka apa yang ditetapkan untuk mereka, sedang kamu ingin mengawini mereka. (An Nisa: 127). Aisyah berkata; (Ayat ini) diturunkan berkaitan dengan wanita yatim yang ada pada seseorang. Wanita yatim itu menyertakannya dalam hartanya hingga dalam urusan kebun kurmanya, lalu ia ingin menikahinya, ia tidak mau menikahkan wanita yatim itu pada lelaki lain lalu disertakanlah ia dalam mengurus hartanya, hingga ia menyusahkannya dengan tidak menikahinya dan tidak menikahkannya pada lelaki lain. Maka turunlah ayat tersebut."},"3930":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ مُقَاتِلٍ أَخْبَرَنَا عَبْدُ اللَّهِ أَخْبَرَنَا هِشَامُ بْنُ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا{ وَإِنْ امْرَأَةٌ خَافَتْ مِنْ بَعْلِهَا نُشُوزًا أَوْ إِعْرَاضًا }قَالَتْ الرَّجُلُ تَكُونُ عِنْدَهُ الْمَرْأَةُ لَيْسَ بِمُسْتَكْثِرٍ مِنْهَا يُرِيدُ أَنْ يُفَارِقَهَا فَتَقُولُ أَجْعَلُكَ مِنْ شَأْنِي فِي حِلٍّ فَنَزَلَتْ هَذِهِ الْآيَةُ فِي ذَلِكَ","id":"Telah menceritakan kepada kami [Muhammad bin Muqatil] Telah mengabarkan kepada kami ['Abdullah] Telah mengabarkan kepada kami [Hisyam bin 'Urwah] dari [Bapaknya] dari ['Aisyah radliallahu 'anha] mengenai firman Allah: Dan jika seorang wanita khawatir akan nusyuz atau sikap tidak acuh dari suaminya. (An Nisa: 128). Aisyah berkata; ayat ini mengenai seorang laki-laki yang mempunyai istri namun dia tidak terlalu mencintainya dan memberikan hak wanita itu, hingga ia ingin berpisah darinya tanpa mentalaknya. Lalu dia berkata; Kamu akan tetap halal bersamaku. Maka turunlah ayat ini."},"3931":{"ar":"حَدَّثَنَا عُمَرُ بْنُ حَفْصٍ حَدَّثَنَا أَبِي حَدَّثَنَا الْأَعْمَشُ قَالَ حَدَّثَنِي إِبْرَاهِيمُ عَنْ الْأَسْوَدِ قَالَكُنَّا فِي حَلْقَةِ عَبْدِ اللَّهِ فَجَاءَ حُذَيْفَةُ حَتَّى قَامَ عَلَيْنَا فَسَلَّمَ ثُمَّ قَالَ لَقَدْ أُنْزِلَ النِّفَاقُ عَلَى قَوْمٍ خَيْرٍ مِنْكُمْ قَالَ الْأَسْوَدُ سُبْحَانَ اللَّهِ إِنَّ اللَّهَ يَقُولُ{ إِنَّ الْمُنَافِقِينَ فِي اَلدَّرْكِ الْأَسْفَلِ مِنْ النَّارِ }فَتَبَسَّمَ عَبْدُ اللَّهِ وَجَلَسَ حُذَيْفَةُ فِي نَاحِيَةِ الْمَسْجِدِ فَقَامَ عَبْدُ اللَّهِ فَتَفَرَّقَ أَصْحَابُهُ فَرَمَانِي بِالْحَصَا فَأَتَيْتُهُ فَقَالَ حُذَيْفَةُ عَجِبْتُ مِنْ ضَحِكِهِ وَقَدْ عَرَفَ مَا قُلْتُ لَقَدْ أُنْزِلَ النِّفَاقُ عَلَى قَوْمٍ كَانُوا خَيْرًا مِنْكُمْ ثُمَّ تَابُوا فَتَابَ اللَّهُ عَلَيْهِمْ","id":"Telah menceritakan kepada kami ['Umar bin Hafsh] Telah menceritakan kepada kami [Bapakku] Telah menceritakan kepada kami [Al A'masy] dia berkata; Telah menceritakan kepadaku [Ibrahim] dari [Al Aswad] dia berkata; Kami pernah berada di majlis Abdullah, tiba-tiba [Hudzaifah] datang seraya mengucapkan salam, lalu dia berkata sambil berdiri; 'Sungguh telah diturunkan ayat nifak atas suatu kaum yang terbaik dari kalian. Al Aswad berkata; 'Maha Suci Allah, sesungguhnya Allah berfirman: \"Sesunguhnya orang-orang munafik akan berada di dasar neraka yang paling bawah. Maka Abdullah tersenyum dan Hudzaifah pun duduk di pojok mesjid. Tiba-tiba Abdullah berdiri, ketika para sahabatnya sudah pergi. Lalu ia melempariku dengan kerikil-kerikil kecil. Maka aku pun menghampirinya. Hudzaifah berkata; Aku heran dengan ketawanya, sungguh dia telah mengetahui apa yang aku ucapkan mengenai ayat nifak telah diturunkan atas suatu kaum yang terbaik dari kalian lalu mereka bertaubat dan Allah pun menerima taubat mereka.'"},"3932":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ سُفْيَانَ قَالَ حَدَّثَنِي الْأَعْمَشُ عَنْ أَبِي وَائِلٍ عَنْ عَبْدِ اللَّهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَا يَنْبَغِي لِأَحَدٍ أَنْ يَقُولَ أَنَا خَيْرٌ مِنْ يُونُسَ بْنِ مَتَّى","id":"Telah menceritakan kepada kami [Musaddad] Telah menceritakan kepada kami [Yahya] dari [Sufyan] dia berkata; Telah menceritakan kepadaku [Al A'masy] dari [Abu Wail] dari ['Abdullah] dari Nabi shallallahu 'alaihi wasallam bersabda: \"Tidak layak bagi siapapun untuk mengatakan; 'Aku lebih baik dari Yunus bin Mata.'"},"3933":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ سِنَانٍ حَدَّثَنَا فُلَيْحٌ حَدَّثَنَا هِلَالٌ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ قَالَ أَنَا خَيْرٌ مِنْ يُونُسَ بْنِ مَتَّى فَقَدْ كَذَبَ","id":"Telah menceritakan kepada kami [Muhammad bin Sinan] Telah menceritakan kepada kami [Fulaih] Telah menceritakan kepada kami [Hilal] dari ['Atha bin Yasar] dari [Abu Hurairah radliallahu 'anhu] dari Nabi shallallahu 'alaihi wasallam bersabda: \"Barang siapa mengatakan: Aku lebih baik dari Yunus bin Mata, maka sungguh dia telah berdusta.\""},"3934":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي إِسْحَاقَ سَمِعْتُ الْبَرَاءَ رَضِيَ اللَّهُ عَنْهُقَالَ آخِرُ سُورَةٍ نَزَلَتْ بَرَاءَةَ وَآخِرُ آيَةٍ نَزَلَتْ{ يَسْتَفْتُونَكَ قُلْ اللَّهُ يُفْتِيكُمْ فِي الْكَلَالَةِ }","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] Telah menceritakan kepada kami [Syu'bah] dari [Abu Ishaq] Aku mendengar [Al Bara' radliallahu 'anhu] berkata; surat yang terakhir kali turun adalah surat Bara`ah sedangkan ayat yang terakhir kali turun adalah ayat: Mereka meminta fatwa kepadamu (tentang kalalah). Katakanlah: \"Allah memberi fatwa kepadamu tentang kalalah. (An Nisa: 176)."},"3935":{"ar":"حَدَّثَنِي مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ حَدَّثَنَا سُفْيَانُ عَنْ قَيْسٍ عَنْ طَارِقِ بْنِ شِهَابٍقَالَتْ الْيَهُودُ لِعُمَرَ إِنَّكُمْ تَقْرَءُونَ آيَةً لَوْ نَزَلَتْ فِينَا لَاتَّخَذْنَاهَا عِيدًا فَقَالَ عُمَرُ إِنِّي لَأَعْلَمُ حَيْثُ أُنْزِلَتْ وَأَيْنَ أُنْزِلَتْ وَأَيْنَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِينَ أُنْزِلَتْ يَوْمَ عَرَفَةَ وَإِنَّا وَاللَّهِ بِعَرَفَةَ قَالَ سُفْيَانُ وَأَشُكُّ كَانَ يَوْمَ الْجُمُعَةِ أَمْ لَا{ الْيَوْمَ أَكْمَلْتُ لَكُمْ دِينَكُمْ }","id":"Telah menceritakan kepadaku [Muhammad bin Basysyar] Telah menceritakan kepada kami ['Abdur Rahman] Telah menceritakan kepada kami [Sufyan] dari [Qais] dari [Thariq bin Syihab] dia berkata; Orang-orang Yahudi mengatakan kepada Umar; \"Sesungguhnya kalian membaca satu ayat, seandainya ayat itu diturunkan kepada kami, maka hari turunnya ayat tersebut pasti akan kami jadikan hari raya.\" lalu [Umar] menjawab; \"sesungguhnya aku sangat tahu dimana ayat tersebut diturunkan, pada hari apa diturunkan, dan di mana Rasulullah shallallahu 'alaihi wasallam berada ketika ayat tersebut diturunkan, bahwa ayat tersebut diturunkan pada hari Arafah dan kami demi Allah pada waktu itu sedang melaksanakan wukuf di Arafah.\" Sufyan berkata; aku ragu tentang; \"hari Jum'at atau bukan.\" yaitu ayat; \"Pada hari Ini telah Kusempurnakan untuk kamu agamamu, dan telah Ku-cukupkan kepadamu nikmat-Ku, dan telah Ku-ridhai Islam itu jadi agama bagimu.\"(QS Al Ma'idah ayat: 3)."},"3936":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ قَالَ حَدَّثَنِي مَالِكٌ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْقَاسِمِ عَنْ أَبِيهِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْخَرَجْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي بَعْضِ أَسْفَارِهِ حَتَّى إِذَا كُنَّا بِالْبَيْدَاءِ أَوْ بِذَاتِ الْجَيْشِ انْقَطَعَ عِقْدٌ لِي فَأَقَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى الْتِمَاسِهِ وَأَقَامَ النَّاسُ مَعَهُ وَلَيْسُوا عَلَى مَاءٍ وَلَيْسَ مَعَهُمْ مَاءٌ فَأَتَى النَّاسُ إِلَى أَبِي بَكْرٍ الصِّدِّيقِ فَقَالُوا أَلَا تَرَى مَا صَنَعَتْ عَائِشَةُ أَقَامَتْ بِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَبِالنَّاسِ وَلَيْسُوا عَلَى مَاءٍ وَلَيْسَ مَعَهُمْ مَاءٌ فَجَاءَ أَبُو بَكْرٍ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَاضِعٌ رَأْسَهُ عَلَى فَخِذِي قَدْ نَامَ فَقَالَ حَبَسْتِ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالنَّاسَ وَلَيْسُوا عَلَى مَاءٍ وَلَيْسَ مَعَهُمْ مَاءٌ قَالَتْ عَائِشَةُ فَعَاتَبَنِي أَبُو بَكْرٍ وَقَالَ مَا شَاءَ اللَّهُ أَنْ يَقُولَ وَجَعَلَ يَطْعُنُنِي بِيَدِهِ فِي خَاصِرَتِي وَلَا يَمْنَعُنِي مِنْ التَّحَرُّكِ إِلَّا مَكَانُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى فَخِذِي فَقَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى أَصْبَحَ عَلَى غَيْرِ مَاءٍ فَأَنْزَلَ اللَّهُ آيَةَ التَّيَمُّمِ فَتَيَمَّمُوا فَقَالَ أُسَيْدُ بْنُ حُضَيْرٍ مَا هِيَ بِأَوَّلِ بَرَكَتِكُمْ يَا آلَ أَبِي بَكْرٍ قَالَتْ فَبَعَثْنَا الْبَعِيرَ الَّذِي كُنْتُ عَلَيْهِ فَإِذَا الْعِقْدُ تَحْتَهُ","id":"Telah menceritakan kepada kami [Isma'il] dia berkata; Telah menceritakan kepadaku [Malik] dari ['Abdur Rahman bin Al Qasim] dari [Bapaknya] dari ['Aisyah radliallahu 'anha] isteri Nabi shallallahu 'alaihi wasallam berkata; \"Kami pernah bersama Rasulullah Shallallahu'alihi wasallam dalam sebagian perjalanannya, dan saat kami sampai di Al Baida -atau di Dzatuljaisy- kalungku hilang, maka Rasulullah Shallallahu'alihi wasallam berhenti untuk mencarinya dan para sahabat juga ikut bersamanya. Mereka tidak mempunyai air dan juga Rasulullah Shallallahu'alihi wasallam. Para sahabat datang kepada Abu Bakar Radliyallhu'anhu dan berkata, 'Apakah kamu tidak melihat apa yang diperbuat Aisyah?! Ia menghentikan (menahan) Rasulullah Shallallahu'alihi wasallam dan para sahabat, padahal mereka tidak pada tempat yang ada airnya dan mereka juga tidak mempunyai air'. Abu Bakar Radliyallahu'anhu lalu datang (kepadaku) dan Rasulullah Shallallahu'alihi wasallam berbaring meletakkan kepalanya diatas pahaku dan beliau tertidur. Ia berkata, 'Kamu menahan Rasulullah Shallallahu'alihi wasallam dan manusia pada tempat yang tidak ada airnya dan mereka juga tidak mempunyai air?\" Aisyah berkata, \"Abu Bakar mencelaku dan beliau mengatakan sebagaimana yang dikehendaki Allah dan ia menekan lambungku dengan tangannya. Tidak ada yang menghalangiku untuk bergerak kecuali keadaan Rasulullah Shallallahu'alihi wasallam yang berada diatas pahaku! Rasulullah Shallallahu'alihi wasallam tertidur hingga pagi, tanpa ada air. Kemudian Allah Azza wa Jalla menurunkan ayat tayamum, maka mereka pun bertayamum.\" Usaid bin Hudhair berkata; \"Ini bukan keberkahan keluargamu yang pertama wahai keluarga Abu Bakar!\" Aisyah berkata, \"Lalu kami membangunkan unta yang kami tunggangi, dan kalung tersebut ternyata ada dibawahnya."},"3937":{"ar":"حَدَّثَنَا يَحْيَى بْنُ سُلَيْمَانَ قَالَ حَدَّثَنِي ابْنُ وَهْبٍ قَالَ أَخْبَرَنِي عَمْرٌو أَنَّ عَبْدَ الرَّحْمَنِ بْنَ الْقَاسِ��ِ حَدَّثَهُ عَنْ أَبِيهِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاسَقَطَتْ قِلَادَةٌ لِي بِالْبَيْدَاءِ وَنَحْنُ دَاخِلُونَ الْمَدِينَةَ فَأَنَاخَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَنَزَلَ فَثَنَى رَأْسَهُ فِي حَجْرِي رَاقِدًا أَقْبَلَ أَبُو بَكْرٍ فَلَكَزَنِي لَكْزَةً شَدِيدَةً وَقَالَ حَبَسْتِ النَّاسَ فِي قِلَادَةٍ فَبِي الْمَوْتُ لِمَكَانِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَدْ أَوْجَعَنِي ثُمَّ إِنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اسْتَيْقَظَ وَحَضَرَتْ الصُّبْحُ فَالْتُمِسَ الْمَاءُ فَلَمْ يُوجَدْ فَنَزَلَتْ{ يَا أَيُّهَا الَّذِينَ آمَنُوا إِذَا قُمْتُمْ إِلَى الصَّلَاةِ }الْآيَةَ فَقَالَ أُسَيْدُ بْنُ حُضَيْرٍ لَقَدْ بَارَكَ اللَّهُ لِلنَّاسِ فِيكُمْ يَا آلَ أَبِي بَكْرٍ مَا أَنْتُمْ إِلَّا بَرَكَةٌ لَهُمْ","id":"Telah menceritakan kepada kami [Yahya bin Sulaiman] dia berkata; Telah menceritakan kepadaku [Ibnu Wahb] dia berkata; Telah mengabarkan kepadaku ['Amru] bahwa ['Abdur Rahman bin Al Qasim] Telah menceritakan kepadanya dari [Bapaknya] dari ['Aisyah radliallahu 'anha], Kalungku pernah hilang di Baida, yang pada waktu itu kami sudah masuk ke Kota Madinah, maka Rasulullah shallallahu 'alaihi wasallam memberhentikan untanya dan turun. Lalu beliau menyandarkan kepalanya dipangkuan sambil tiduran. Abu Bakr datang kepadaku seraya marah mencelaku, dia berkata; 'Kamu telah menahan orang-orang dari melanjutkan perjalanan kerena mencari kalung.' Aku diam seperti orang mati, karena takut mengganggu Rasulullah shallallahu 'alaihi wasallam, padahal Abu Bakr telah menyakitiku. Kemudian Rasulullah shallallahu 'alaihi wasallam bangun dari tidurnya dan tibalah waktu shalat shubuh, maka beliau mencari air, namun beliau tidak mendapatkannya. Lalu turunlah ayat: Hai orang-orang yang beriman, apabila kamu hendak mengerjakan shalat…. (Al Maidah: 6). Maka Usaid bin Hudlair berkata; 'Sungguh Allah telah memberkahi orang-orang karena kalian wahai keluarga Abu Bakr. Tidaklah kalian berada kecuali telah memberikan keberkahan kepada mereka."},"3938":{"ar":"حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا إِسْرَائِيلُ عَنْ مُخَارِقٍ عَنْ طَارِقِ بْنِ شِهَابٍ سَمِعْتُ ابْنَ مَسْعُودٍ رَضِيَ اللَّهُ عَنْهُ قَالَ شَهِدْتُ مِنْ الْمِقْدَادِ ح و حَدَّثَنِي حَمْدَانُ بْنُ عُمَرَ حَدَّثَنَا أَبُو النَّضْرِ حَدَّثَنَا الْأَشْجَعِيُّ عَنْ سُفْيَانَ عَنْ مُخَارِقٍ عَنْ طَارِقٍ عَنْ عَبْدِ اللَّهِ قَالَقَالَ الْمِقْدَادُ يَوْمَ بَدْرٍ يَا رَسُولَ اللَّهِ إِنَّا لَا نَقُولُ لَكَ كَمَا قَالَتْ بَنُو إِسْرَائِيلَ لِمُوسَى{ فَاذْهَبْ أَنْتَ وَرَبُّكَ فَقَاتِلَا إِنَّا هَا هُنَا قَاعِدُونَ }وَلَكِنْ امْضِ وَنَحْنُ مَعَكَ فَكَأَنَّهُ سُرِّيَ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَوَرَوَاهُ وَكِيعٌ عَنْ سُفْيَانَ عَنْ مُخَارِقٍ عَنْ طَارِقٍ أَنَّ الْمِقْدَادَ قَالَ ذَلِكَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Abu Nu'aim] Telah menceritakan kepada kami [Isra'il] dari [Mukhariq] dari [Thariq bin Syihab]; Aku mendengar [Ibnu Mas'ud radliallahu 'anhu] berkata; Aku menyaksikan dari Miqdad. Demikian juga diriwayatkan dari jalur lainnya, Telah menceritakan kepadaku [Hamdan bin 'Umar] Telah menceritakan kepada kami [Abu An Nadlr] Telah menceritakan kepada kami [Al Asyja'i] dari [Sufyan] dari [Mukhariq] dari [Thariq] dari ['Abdullah] dia berkata; Pada waktu perang Badar Miqdad berkata; 'Ya Rasulullah, Kami tidak mengatakan sebagaimana dikatakan Bani Israil kepada Musa; FADZHAB ANTA WA RABBUKA FAQOTILAA INNA HAAHUNAA QAA'IDUN (Pergilah kamu bersama tuhan kamu untuk berperang, sedangkan kami duduk disini saja). Tetapi kami mengatakan; pergilah dan kami akan ikut bersamamu. Namun seakan-akan perkataan Miqdad itu disembunyikan dari Rasulullah shallallahu 'alaihi wasallam. Dan diriwayatkan pula oleh [Waki'] dari [Sufyan] dari [Mukhariq] dari [Thariq] bahwa Miqdad mengatakan hal itu kepada Nabi shallallahu 'alaihi wasallam."},"3939":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ الْأَنْصَارِيُّ حَدَّثَنَا ابْنُ عَوْنٍ قَالَ حَدَّثَنِي سَلْمَانُ أَبُو رَجَاءٍ مَوْلَى أَبِي قِلَابَةَ عَنْ أَبِي قِلَابَةَ أَنَّهُ كَانَ جَالِسًا خَلْفَ عُمَرَ بْنِ عَبْدِ الْعَزِيزِ فَذَكَرُوا وَذَكَرُوا فَقَالُوا وَقَالُوا قَدْ أَقَادَتْ بِهَا الْخُلَفَاءُ فَالْتَفَتَ إِلَى أَبِي قِلَابَةَ وَهْوَ خَلْفَ ظَهْرِهِ فَقَالَ مَا تَقُولُ يَا عَبْدَ اللَّهِ بْنَ زَيْدٍ أَوْ قَالَ مَا تَقُولُ يَا أَبَا قِلَابَةَ قُلْتُ مَا عَلِمْتُ نَفْسًا حَلَّ قَتْلُهَا فِي الْإِسْلَامِ إِلَّا رَجُلٌ زَنَى بَعْدَ إِحْصَانٍ أَوْ قَتَلَ نَفْسًا بِغَيْرِ نَفْسٍ أَوْ حَارَبَ اللَّهَ وَرَسُولَهُ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ عَنْبَسَةُ حَدَّثَنَا أَنَسٌ بِكَذَا وَكَذَا قُلْتُ إِيَّايَ حَدَّثَ أَنَسٌقَالَ قَدِمَ قَوْمٌ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَكَلَّمُوهُ فَقَالُوا قَدْ اسْتَوْخَمْنَا هَذِهِ الْأَرْضَ فَقَالَ هَذِهِ نَعَمٌ لَنَا تَخْرُجُ فَاخْرُجُوا فِيهَا فَاشْرَبُوا مِنْ أَلْبَانِهَا وَأَبْوَالِهَا فَخَرَجُوا فِيهَا فَشَرِبُوا مِنْ أَبْوَالِهَا وَأَلْبَانِهَا وَاسْتَصَحُّوا وَمَالُوا عَلَى الرَّاعِي فَقَتَلُوهُ وَاطَّرَدُوا النَّعَمَ فَمَا يُسْتَبْطَأُ مِنْ هَؤُلَاءِ قَتَلُوا النَّفْسَ وَحَارَبُوا اللَّهَ وَرَسُولَهُ وَخَوَّفُوا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ سُبْحَانَ اللَّهِ فَقُلْتُ تَتَّهِمُنِيقَالَ حَدَّثَنَا بِهَذَا أَنَسٌ قَالَ وَقَالَ يَا أَهْلَ كَذَا إِنَّكُمْ لَنْ تَزَالُوا بِخَيْرٍ مَا أُبْقِيَ هَذَا فِيكُمْ أَوْ مِثْلُ هَذَا","id":"Telah menceritakan kepada kami ['Ali bin 'Abdullah] Telah menceritakan kepada kami [Muhammad bin 'Abdullah Al Anshari] Telah menceritakan kepada kami [Ibnu 'Aun] dia berkata; Telah menceritakan kepadaku [Salman Abu Raja'] mantan budak Abu Qilabah dari [Abu Qilabah] bahwasanya ia pernah duduk di belakang 'Umar bin 'Abdul 'Aziz lalu mereka berbincang-bincang tentang para khalifah. Abu Qilabah berkata; para khalifah itu telah memimpin. Umar pun menoleh kepadanya -pada waktu itu Abu Qilabah berada dibelakangnya.- seraya berkata; apa yang kamu katakan wahai Abdullah bin Zaid, -atau ia mengatakan-, apa yang kamu katakan wahai Abu Qilabah? Aku menjawab; Aku tidak mengetahui seseorang jiwa boleh dibunuh dalam Islam, kecuali seseorang yang telah menikah kemudian berzina, atau ia membunuh secara tidak benar, atau ia memerangi Allah dan Rasul-Nya shallallahu 'alaihi wasallam. ['Anbasah] berkata; Telah menceritakan kepada kami [Anas] mengenai hal ini dan itu. Aku berkata; dan kepadaku Anas menceritakannya, ia berkata; suatu kaum pernah menemui Nabi shallallahu 'alaihi wasallam seraya berkata; Cuaca kota ini sudah tidak cocok bagi kami. Maka Nabi shallallahu 'alaihi wasallam bersabda: ini ada beberapa hewan ternak milik kami, maka keluarlah kalian dan minumlah dari susu dan air kencingnya. Lalu mereka pun meminum susu dan air kencing unta hingga mereka segar kembali. Lalu mereka mendekati pengembala dan membunuhnya serta mengusir bintang ternaknya. Tak lama kemudian, diantara mereka ada yang membunuh jiwa secara tidak benar, dan memerangi Allah dan Rasu-Nya serta menakut-nakuti Rasulullah shallallahu 'alaihi wasallam. kemudian Umar berkata; Maha suci Allah, lalu berkata; 'Apakah kamu menuduhku? Abu Qilabah berkata; Anas telah menceritakan kepada kami mengenai hal ini, dan dia berkata; wahai penduduk ini (Syam), sesungguhnya kalian akan senantiasa dalam kebaikan selama orang ini ada pada kalian. -atau yang serupa dengan hal itu.-"},"3940":{"ar":"حَدَّثَنِي مُحَمَّدُ بْنُ سَلَامٍ أَخْبَرَنَا الْفَزَارِيُّ عَنْ حُمَيْدٍ عَنْ أَنَسٍ رَضِيَ اللَّهُ عَنْهُ قَالَكَسَرَتْ الرُّبَيِّعُ وَهْيَ عَمَّةُ أَنَسِ بْنِ مَالِكٍ ثَنِيَّةَ جَارِيَةٍ مِنْ الْأَنْصَارِ فَطَلَبَ الْقَوْمُ الْقِصَاصَ فَأَتَوْا النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَمَرَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالْقِصَاصِ فَقَالَ أَنَسُ بْنُ النَّضْرِ عَمُّ أَنَسِ بْنِ مَالِكٍ لَا وَاللَّهِ لَا تُكْسَرُ سِنُّهَا يَا رَسُولَ اللَّهِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا أَنَسُ كِتَابُ اللَّهِ الْقِصَاصُ فَرَضِيَ الْقَوْمُ وَقَبِلُوا الْأَرْشَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ مِنْ عِبَادِ اللَّهِ مَنْ لَوْ أَقْسَمَ عَلَى اللَّهِ لَأَبَرَّهُ","id":"Telah menceritakan kepadaku [Muhammad bin Salam] Telah mengabarkan kepada kami [Al Fazari] dari [Humaid] dari [Anas radliallahu 'anhu] dia berkata; Rubayyi' -bibinya Anas bin Malik- pernah mematahkan gigi seri budak dari Anshar. Lalu kaumnya meminta qishas dengan mendatangi Nabi shallallahu 'alaihi wasallam. Maka Nabi shallallahu 'alaihi wasallam menyuruh untuk mengqishashnya. Anas bin Mudlar -paman Anas bin Malik- berkata; Tidak, demi Allah, jangan engkau patahkan giginya ya Rasulullah. Rasulullah shallallahu 'alaihi wasallam bersabda: 'Wahai Anas, Kitabullah adalah Qishash.' Namun kemudian kaumnya merelakannya dan menerima dendanya. Nabi shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya dari hamba-hamba Allah ada orang yang apabila dia bersumpah atas nama Allah maka ALlah akan mengabulkannya.\""},"3941":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا سُفْيَانُ عَنْ إِسْمَاعِيلَ عَنْ الشَّعْبِيِّ عَنْ مَسْرُوقٍ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْمَنْ حَدَّثَكَ أَنَّ مُحَمَّدًا صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَتَمَ شَيْئًا مِمَّا أَنْزَلَ اللَّهُ عَلَيْهِ فَقَدْ كَذَبَ وَاللَّهُ يَقُولُ{ يَا أَيُّهَا الرَّسُولُ بَلِّغْ مَا أُنْزِلَ إِلَيْكَ مِنْ رَبِّكَ }الْآيَةَ","id":"Telah menceritakan kepada kami [Muhammad bin Yusuf] Telah menceritakan kepada kami [Sufyan] dari [Isma'il] dari [Asy Sya'bi] dari [Masruq] dari ['Aisyah radliallahu 'anhu] dia berkata; 'Siapapun yang berkata bahwa Muhammad shallallahu 'alaihi wasallam menyembunyikan sebagian dari yang telah diwahyukan kepadanya, maka dia telah berdusta. Karena Allah telah berfirman: Wahai Rasul, sampaikanlah apa yang telah diturunkan kepadamu dari Rabbmu.. (Al Maidah: 67)."},"3942":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ سَلَمَةَ حَدَّثَنَا مَالِكُ بْنُ سُعَيْرٍ حَدَّثَنَا هِشَامٌ عَنْ أَبِيهِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاأُنْزِلَتْ هَذِهِ الْآيَةُ{ لَا يُؤَاخِذُكُمْ اللَّهُ بِاللَّغْوِ فِي أَيْمَانِكُمْ }فِي قَوْلِ الرَّجُلِ لَا وَاللَّهِ وَبَلَى وَاللَّهِ","id":"Telah menceritakan kepada kami ['Ali bin Salamah] Telah menceritakan kepada kami [Malik bin Su'air] Telah menceritakan kepada kami [Hisyam] dari [Bapaknya] dari ['Aisyah radliallahu 'anha] Ayat ini: Allah tidak menghukum kamu disebabkan sumpah-sumpahmu yang tidak dimaksud (untuk bersumpah), tetapi Dia menghukum kamu disebabkan sumpah-sumpah yang kamu sengaja.. (Al Maidah: 79), diturunkan berkenaan dengan perkataan seseorang: Tidak demi Allah, iya demi Allah."},"3943":{"ar":"حَدَّثَنَا أَحْمَدُ ابْنُ أَبِي رَجَاءٍ حَدَّثَنَا النَّضْرُ عَنْ هِشَامٍ قَالَ أَخْبَرَنِي أَبِي عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا أَنَّأَبَاهَا كَانَ لَا يَحْنَثُ فِي يَمِينٍ حَتَّى أَنْزَلَ اللَّهُ كَفَّارَةَ الْيَمِينِ قَالَ أَبُو بَكْرٍ لَا أَرَى يَمِينًا أُرَى غَيْرَهَا خَيْرًا مِنْهَا إِلَّا قَبِلْتُ رُخْصَةَ اللَّهِ وَفَعَلْتُ الَّذِي هُوَ خَيْرٌ","id":"Telah menceritakan kepada kami [Ahmad bin Abu Raja'] Telah menceritakan kepada kami [An Nadlr] dari [Hisyam] dia berkata; Telah mengabarkan kepadaku [Bapakku] dari ['Aisyah radliallahu 'anha] bahwa bapaknya tidak pernah berdusta dengan sumpah hingga Allah menurunkan penghapus dosa sumpah. [Abu Bakr] berkata; 'Tidaklah aku memandang suatu sumpah, lantas kulihat lainnya ada yang lebih baik kecuali aku menerima rukhsah (keringanan) yang Allah berikan (membatalkan sumpah) dan aku melakukan yang terbaik.' "},"3944":{"ar":"حَدَّثَنَا عَمْرُو بْنُ عَوْنٍ حَدَّثَنَا خَالِدٌ عَنْ إِسْمَاعِيلَ عَنْ قَيْسٍ عَنْ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُ قَالَكُنَّا نَغْزُو مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلَيْسَ مَعَنَا نِسَاءٌ فَقُلْنَا أَلَا نَخْتَصِي فَنَهَانَا عَنْ ذَلِكَ فَرَخَّصَ لَنَا بَعْدَ ذَلِكَ أَنْ نَتَزَوَّجَ الْمَرْأَةَ بِالثَّوْبِ ثُمَّ قَرَأَ{ يَا أَيُّهَا الَّذِينَ آمَنُوا لَا تُحَرِّمُوا طَيِّبَاتِ مَا أَحَلَّ اللَّهُ لَكُمْ }","id":"Telah menceritakan kepada kami ['Amru bin 'Aun] Telah menceritakan kepada kami [Khalid] dari [Isma'il] dari [Qais] dari ['Abdullah radliallahu 'anhu] dia berkata; Kami pernah berperang bersama Nabi shallallaahu 'alaihi wasallam namun tidak mengikut sertakan istri-istri kami, lalu kami berkata: Wahai Rasulullah, tidakkah kami dikebiri? Namun Nabi shallallaahu 'alaihi wasallam melarang kami melakukannya. tapi setelah itu beliau memberikan keringanan kepada kami untuk menikahi wanita dalam waktu tertentu. lalu beliau membacakan ayat; Hai orang-orang yang beriman, janganlah kamu haramkan apa-apa yang baik yang telah Allah halalkan bagi kamu, dan janganlah kamu melampaui batas. Sesungguhnya Allah tidak menyukai orang-orang yang melampaui batas. (Al Maidah: 87)."},"3945":{"ar":"حَدَّثَنَا إِسْحَاقُ بْنُ إِبْرَاهِيمَ أَخْبَرَنَا مُحَمَّدُ بْنُ بِشْرٍ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ عُمَرَ بْنِ عَبْدِ الْعَزِيزِ قَالَ حَدَّثَنِي نَافِعٌ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا قَالَنَزَلَ تَحْرِيمُ الْخَمْرِ وَإِنَّ فِي الْمَدِينَةِ يَوْمَئِذٍ لَخَمْسَةَ أَشْرِبَةٍ مَا فِيهَا شَرَابُ الْعِنَبِ","id":"Telah menceritakan kepada kami [Ishaq bin Ibrahim] Telah mengabarkan kepada kami [Muhammad bin Basysyar] Telah menceritakan kepada kami ['Abdul 'Aziz bin 'Umar bin 'Abdul 'Aziz] dia berkata; Telah menceritakan kepadaku [Nafi'] dari ['Umar radliallahu 'anhuma] dia berkata; Tatkala turun ayat yang mengharamkan khamr, pada waktu itu di Madinah ada lima gelas yang berisi minuman anggur."},"3946":{"ar":"حَدَّثَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا ابْنُ عُلَيَّةَ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ صُهَيْبٍ قَالَ قَالَ أَنَسُ بْنُ مَالِكٍ رَضِيَ اللَّهُ عَنْهُمَا كَانَ لَنَا خَمْرٌ غَيْرُ فَضِيخِكُمْ هَذَا الَّذِي تُسَمُّونَهُ الْفَضِيخَ فَإِنِّي لَقَائِمٌ أَسْقِي أَبَا طَلْحَةَ وَفُلَانًا وَفُلَانًا إِذْ جَاءَ رَجُلٌ فَقَالَ وَهَلْ بَلَغَكُمْ الْخَبَرُ فَقَالُوا وَمَا ذَاكَ قَالَ حُرِّمَتْ الْخَمْرُ قَالُوا أَهْرِقْ هَذِهِ الْقِلَالَ يَا أَنَسُ قَالَ فَمَا سَأَلُوا عَنْهَا وَلَا رَاجَعُوهَا بَعْدَ خَبَرِ الرَّجُلِ","id":"Telah menceritakan kepada kami [Ya'qub bin Ibrahim] Telah menceritakan kepada kami [Ibnu 'Ulayyah] Telah menceritakan kepada kami ['Abdul 'Aziz bin Shuhaib] dia berkata; [Anas bin Malik radliallahu 'anhu] berkata; 'Kami tidak punya khamr kecuali Fadlikh kalian ini, yang biasa kalian sebut dengan Al Fadlikh. Aku pernah menjadi orang yang memberi minum Abu Thalhah, dan fulan, serta fulan. Lalu datang seseorang berkata; 'Apakah telah sampai kepada kalian suatu kabar? Mereka bertanya; 'Kabar apa itu? Dia menjawab; 'Khamr telah diharamkan.' Mereka berkata; Wahai Anas, bakarlah kendi-kendi ini! Mereka tidak pernah meminta dan kembali kepada memimum khamr lagi setelah mendengar kabar dari orang tadi."},"3947":{"ar":"حَدَّثَنَا صَدَقَةُ بْنُ الْفَضْلِ أَخْبَرَنَا ابْنُ عُيَيْنَةَ عَنْ عَمْرٍو عَنْ جَابِرٍ قَالَصَبَّحَ أُنَاسٌ غَدَاةَ أُحُدٍ الْخَمْرَ فَقُتِلُوا مِنْ يَوْمِهِمْ جَمِيعًا شُهَدَاءَ وَذَلِكَ قَبْلَ تَحْرِيمِهَا","id":"Telah menceritakan kepada kami [Shadaqah bin Fadll] Telah mengabarkan kepada kami [Ibnu 'Uyainah] dari ['Amru] dari [Jabir] dia berkata; Beberapa orang yang berangkat ke Uhud meminum khamr diwaktu pagi, lalu mereka terbunuh semua sebagai syahid, hal itu terjadi sebelum pengharamanan khamr."},"3948":{"ar":"حَدَّثَنَا إِسْحَاقُ بْنُ إِبْرَاهِيمَ الْحَنْظَلِيُّ أَخْبَرَنَا عِيسَى وَابْنُ إِدْرِيسَ عَنْ أَبِي حَيَّانَ عَنْ الشَّعْبِيِّ عَنْ ابْنِ عُمَرَ قَالَ سَمِعْتُ عُمَرَ رَضِيَ اللَّهُ عَنْهُعَلَى مِنْبَرِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ أَمَّا بَعْدُ أَيُّهَا النَّاسُ إِنَّهُ نَزَلَ تَحْرِيمُ الْخَمْرِ وَهْيَ مِنْ خَمْسَةٍ مِنْ الْعِنَبِ وَالتَّمْرِ وَالْعَسَلِ وَالْحِنْطَةِ وَالشَّعِيرِ وَالْخَمْرُ مَا خَامَرَ الْعَقْلَ","id":"Telah menceritakan kepada kami [Ishaq bin Ibrahim Al Handzali] Telah mengabarkan kepada kami ['Isa] dan [Ibnu Idris] dari [Abu Hayyan] dari [Asy Sya'bi] dari [Ibnu 'Umar] dia berkata; Aku mendengar ['Umar radliallahu 'anhu] berkhutbah di atas mimbar Nabi shallallahu 'alaihi wasallam, ia mengatakan; Amma ba'du, \"Wahai manusia! Ketahuilah, sesungguhnya khamer telah diharamkan. Dan ia terbuat dari lima macam (buah); anggur, kurma, madu, terigu, dan gandum. Khamer adalah sesuatu yang menutupi akal.\""},"3949":{"ar":"حَدَّثَنَا أَبُو النُّعْمَانِ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ حَدَّثَنَا ثَابِتٌ عَنْ أَنَسٍ رَضِيَ اللَّهُ عَنْهُ أَنَّ الْخَمْرَ الَّتِي أُهْرِيقَتْ الْفَضِيخُ وَزَادَنِي مُحَمَّدٌ الْبِيكَنْدِيُّ عَنْ أَبِي النُّعْمَانِ قَالَكُنْتُ سَاقِيَ الْقَوْمِ فِي مَنْزِلِ أَبِي طَلْحَةَ فَنَزَلَ تَحْرِيمُ الْخَمْرِ فَأَمَرَ مُنَادِيًا فَنَادَى فَقَالَ أَبُو طَلْحَةَ اخْرُجْ فَانْظُرْ مَا هَذَا الصَّوْتُ قَالَ فَخَرَجْتُ فَقُلْتُ هَذَا مُنَادٍ يُنَادِي أَلَا إِنَّ الْخَمْرَ قَدْ حُرِّمَتْ فَقَالَ لِي اذْهَبْ فَأَهْرِقْهَا قَالَ فَجَرَتْ فِي سِكَكِ الْمَدِينَةِ قَالَ وَكَانَتْ خَمْرُهُمْ يَوْمَئِذٍ الْفَضِيخَ فَقَالَ بَعْضُ الْقَوْمِ قُتِلَ قَوْمٌ وَهْيَ فِي بُطُونِهِمْ قَالَ فَأَنْزَلَ اللَّهُ{ لَيْسَ عَلَى الَّذِينَ آمَنُوا وَعَمِلُوا الصَّالِحَاتِ جُنَاحٌ فِيمَا طَعِمُوا }","id":"Telah menceritakan kepada kami [Abu Nu'man] Telah menceritakan kepada kami [Hammad bin Zaid] Telah menceritakan kepada kami [Tsabit] dari [Anas radliallahu 'anhu] bahwa Khamr adalah yang dihasilkan dengan membakar buah kurma. [Muhammad Al Bikandi] menambahkan dari [Abu Nu'man] dia berkata; Aku adalah orang yang member minum di rumah Abu Thalhah. Lalu turunlah ayat yang mengharamkan Khamr, kemudian disuruhlah seseorang mengumumkannya. Abu Thalhah berkata; keluarlah dan dengarkanlah suara itu. Abu Nu'man berkata; Aku pun keluar lalu ku katakana; 'Orang itu menyerukan bahwa Khamr telah diharamkan. Abu Thalhah berkata kepadaku; pergilah dan bakarlah khamrnya. Anas berkata; Maka kabar ini menyebar hingga ke gang-gang Madinah. Anas bin Malik Radliyalalhu'anhu berkata; arak mereka pada waktu itu adalah terbuat dari fadlikh (minuman yang terbuat dari busr), busr (kurma yang masih muda). Sebagian kaum berkata; sebagian kaum telah telah meninggal sedang arak telah telanjur masuk perut mereka. Anas bin Malik Radliyalalhu'anhu berkata; maka Allah 'azza wajalla menurunkan \"Tidak ada dosa bagi orang-orang yang beriman dan mengerjakan amalan yang saleh karena memakan makanan yang telah mereka makan dahulu... (Al Maidah: 93)."},"3950":{"ar":"حَدَّثَنَا مُنْذِرُ بْنُ الْوَلِيدِ بْنِ عَبْدِ الرَّحْمَنِ الْجَارُودِيُّ حَدَّثَنَا أَبِي حَدَّثَنَا شُعْبَةُ عَنْ مُوسَى بْنِ أَنَسٍ عَنْ أَنَسٍ رَضِيَ اللَّهُ عَنْهُ قَالَخَطَبَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خُطْبَةً مَا سَمِعْتُ مِثْلَهَا قَطُّ قَالَ لَوْ تَعْلَمُونَ مَا أَعْلَمُ لَضَحِكْتُمْ قَلِيلًا وَلَبَكَيْتُمْ كَثِيرًا قَالَ فَغَطَّى أَصْحَابُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وُجُوهَهُمْ لَهُمْ خَنِينٌ فَقَالَ رَجُلٌ مَنْ أَبِي قَالَ فُلَانٌ فَنَزَلَتْ هَذِهِ الْآيَةُ{ لَا تَسْأَلُوا عَنْ أَشْيَاءَ إِنْ تُبْدَ لَكُمْ تَسُؤْكُمْ }رَوَاهُ النَّضْرُ وَرَوْحُ بْنُ عُبَادَةَ عَنْ شُعْبَةَ","id":"Telah menceritakan kepada kami [Mundzir bin Al Walid bin 'Abdur Rahman Al Jarudi] Telah menceritakan kepada kami [Bapakku] Telah menceritakan kepada kami [Syu'bah] dari [Musa bin Anas] dari [Anas radliallahu 'anhu] dia berkata; Rasulullah shallallahu 'alaihi wasallam berkhuthbah dengan khutbah yang belum pernah aku dengar sebelumnya, beliau berkata; \"Seandainya kalian dapat mengetahui apa yang aku ketahui, maka kalian pasti akan sedikit tertawa dan banyak menangis.' Anas berkata; Para sahabat Rasulullah shallallahu 'alaihi wasallam menutupi kepala mereka dan mereka pun terserang sakit sengau hidung.' Setelah itu, 'Ada seorang laki-laki bertanya; 'Siapakah ayah saya? ' Beliau menjawab: 'Ayahmu adalah si fulan.' Maka turunlah ayat yang berikut ini: Hai orang-orang yang beriman, janganlah kamu bertanya tentang segala sesuatu yang apabila dijelaskan kepadamu, maka hal itu akan memberatkanmu. (QS. Al Maa'idah: 101). Diriwayatkan oleh [An Nadlr] dan [Rauh bin Ubadah] dari [Syu'bah]."},"3951":{"ar":"حَدَّثَنَا الْفَضْلُ بْنُ سَهْلٍ حَدَّثَنَا أَبُو النَّضْرِ حَدَّثَنَا أَبُو خَيْثَمَةَ حَدَّثَنَا أَبُو الْجُوَيْرِيَةِ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَكَانَ قَوْمٌ يَسْأَلُونَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اسْتِهْزَاءً فَيَقُولُ الرَّجُلُ مَنْ أَبِي وَيَقُولُ الرَّجُلُ تَضِلُّ نَاقَتُهُ أَيْنَ نَاقَتِي فَأَنْزَلَ اللَّهُ فِيهِمْ هَذِهِ الْآيَةَ{ يَا أَيُّهَا الَّذِينَ آمَنُوا لَا تَسْأَلُوا عَنْ أَشْيَاءَ إِنْ تُبْدَ لَكُمْ تَسُؤْكُمْ }حَتَّى فَرَغَ مِنْ الْآيَةِ كُلِّهَا","id":"Telah menceritakan kepada kami [Al Fadll bin Sahl] Telah menceritakan kepada kami [Abu An Nadlr] Telah menceritakan kepada kami [Abu Khaitsamah] Telah menceritakan kepada kami [Abu Juwairiyah] dari [Ibnu 'Abbas radliallahu 'anhuma] dia berkata; Suatu kaum pernah bertanya kepada Rasulullah shallallahu 'alaihi wasallam sebagai bentuk pengejekan. Seseorang dari mereka berkata; 'Siapa bapakku? ' Seseorang lagi berkata ketika untanya hilang; 'di mana untaku? ' maka Allah menurunkan kepada mereka ayat; Hai orang-orang yang beriman, janganlah kamu bertanya tentang segala sesuatu yang apabila dijelaskan kepadamu, maka hal itu akan memberatkanmu. (QS. Al Maa'idah: 101)."},"3952":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ حَدَّثَنَا إِبْرَاهِيمُ بْنُ سَعْدٍ عَنْ صَالِحِ بْنِ كَيْسَانَ عَنْ ابْنِ شِهَابٍ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ قَالَ الْبَحِيرَةُ الَّتِي يُمْنَعُ دَرُّهَا لِلطَّوَاغِيتِ فَلَا يَحْلُبُهَا أَحَدٌ مِنْ النَّاسِ وَالسَّائِبَةُ كَانُوا يُسَيِّبُونَهَا لِآلِهَتِهِمْ لَا يُحْمَلُ عَلَيْهَا شَيْءٌ قَالَ وَقَالَ أَبُو هُرَيْرَةَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَأَيْتُ عَمْرَو بْنَ عَامِرٍ الْخُزَاعِيَّ يَجُرُّ قُصْبَهُ فِي النَّارِ كَانَ أَوَّلَ مَنْ سَيَّبَ السَّوَائِبَ وَالْوَصِيلَةُ النَّاقَةُ الْبِكْرُ تُبَكِّرُ فِي أَوَّلِ نِتَاجِ الْإِبِلِ ثُمَّ تُثَنِّي بَعْدُ بِأُنْثَى وَكَانُوا يُسَيِّبُونَهَا لِطَوَاغِيتِهِمْ إِنْ وَصَلَتْ إِحْدَاهُمَا بِالْأُخْرَى لَيْسَ بَيْنَهُمَا ذَكَرٌ وَالْحَامِ فَحْلُ الْإِبِلِ يَضْرِبُ الضِّرَابَ الْمَعْدُودَ فَإِذَا قَضَى ضِرَابَهُ وَدَعُوهُ لِلطَّوَاغِيتِ وَأَعْفَوْهُ مِنْ الْحَمْلِ فَلَمْ يُحْمَلْ عَلَيْهِ شَيْءٌ وَسَمَّوْهُ الْحَامِيَو قَالَ لِي أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ سَمِعْتُ سَعِيدًا قَالَ يُخْبِرُهُ بِهَذَا قَالَ وَقَالَ أَبُو هُرَيْرَةَ سَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ وَرَوَاهُ ابْنُ الْهَادِ عَنْ ابْنِ شِهَابٍ عَنْ سَعِيدٍ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ سَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] Telah menceritakan kepada kami [Ibrahim bin Sa'ad] dari [Shalih bin Kaisan] dari [Ibnu Syihab] dari [Sa'id bin Al Musayyab] dia berkata; Bahirah adalah unta yang kantong susunya ditahan untuk berhala-berhala hingga tidak boleh bagi seorang pun memerasnya, sedangkan sa`ibah adalah unta yang mereka sebut untuk tuhan-tuhan mereka tidak boleh diberi beban tunggangan apa pun diatasnya. Ibnu Al Musayyib berkata: [Abu Hurairah] berkata: Rasulullah shallallahu 'alaihi wasallam bersabda: \"Aku melihat Amru bin Amir Al Khuza'i menyeret ususnya dineraka.\" Ia adalah orang pertama yang membuat unta sa`ibah. Sedangkan Al Washilah adalah unta yang masih perawan. Unta itu sengaja dibikin perawan semenjak diperanakan. Setelah itu dijodohkan dengan unta betina lagi. Unta itu mereka suguhkan untuk berhala-berhala mereka. hingga salah satunya bisa menyentuh yang lainnya tanpa ada unta jantan. Sedangkan Unta Haam adalah unta subur, mereka membiarkannya beranak hingga bilangan tertentu. Apabila telah selesai, ia tinggalkan untuk berhala-berhala mereka dan dijaga dari beban apapun hingga tidak boleh ada tunggangan apapun diatasnya. Mereka menamakannya Al Haami. Dan [Abul Yaman] berkata kepadaku; Telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhri]; Aku mendengar [Sa'id] berkata; dia mengabarkan hal ini. perawi berkata; dan [Abu Hurairah] berkata; Aku mendengar Nabi shallallahu 'alaihi wasallam bersabda dengan Hadits yang serupa. Diriwayatkan oleh [Ibnu Al Had] dari [Ibnu Syihab] dari [Sa'id] dari [Abu Hurairah radliallahu 'anhu]; Aku mendengar Nabi shallallahu 'alaihi wasallam."},"3953":{"ar":"حَدَّثَنِي مُحَمَّدُ بْنُ أَبِي يَعْقُوبَ أَبُو عَبْدِ اللَّهِ الْكَرْمَانِيُّ حَدَّثَنَا حَسَّانُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا يُونُسُ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ أَنَّ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَأَيْتُ جَهَنَّمَ يَحْطِمُ بَعْضُهَا بَعْضًا وَرَأَيْتُ عَمْرًا يَجُرُّ قُصْبَهُ وَهْوَ أَوَّلُ مَنْ سَيَّبَ السَّوَائِبَ","id":"Telah menceritakan kepadaku [Muhammad bin Abu Ya'qub Abu 'Abdullah Al Karmani] Telah menceritakan kepada kami [Hassan bin Ibrahim] Telah menceritakan kepada kami [Yunus] dari [Az Zuhri] dari ['Urwah] bahwa ['Aisyah radliallahu 'anhu] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Aku melihat penghuni Jahannam sebagiannya saling mematahkan (menindih) sebagian yang lain dan aku melihat Amru bin Amir Al Khuza'i menyeret ususnya di neraka.\" Ia adalah orang pertama yang membuat unta sa`ibah.\""},"3954":{"ar":"حَدَّثَنَا أَبُو الْوَلِيدِ حَدَّثَنَا شُعْبَةُ أَخْبَرَنَا الْمُغِيرَةُ بْنُ النُّعْمَانِ قَالَ سَمِعْتُ سَعِيدَ بْنَ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَخَطَبَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا أَيُّهَا النَّاسُ إِنَّكُمْ مَحْشُورُونَ إِلَى اللَّهِ حُفَاةً عُرَاةً غُرْلًا ثُمَّ قَالَ{ كَمَا بَدَأْنَا أَوَّلَ خَلْقٍ نُعِيدُهُ وَعْدًا عَلَيْنَا إِنَّا كُنَّا فَاعِلِينَ }إِلَى آخِرِ الْآيَةِ ثُمَّ قَالَ أَلَا وَإِنَّ أَوَّلَ الْخَلَائِقِ يُكْسَى يَوْمَ الْقِيَامَةِ إِبْرَاهِيمُ أَلَا وَإِنَّهُ يُجَاءُ بِرِجَالٍ مِنْ أُمَّتِي فَيُؤْخَذُ بِهِمْ ذَاتَ الشِّمَالِ فَأَقُولُ يَا رَبِّ أُصَيْحَابِي فَيُقَالُ إِنَّكَ لَا تَدْرِي مَا أَحْدَثُوا بَعْدَكَ فَأَقُولُ كَمَا قَالَ الْعَبْدُ الصَّالِحُ{ وَكُنْتُ عَلَيْهِمْ شَهِيدًا مَا دُمْتُ فِيهِمْ فَلَمَّا تَوَفَّيْتَنِي كُنْتَ أَنْتَ الرَّقِيبَ عَلَيْهِمْ وَأَنْتَ عَلَى كُلِّ شَيْءٍ شَهِيدٌ }فَيُقَالُ إِنَّ هَؤُلَاءِ لَمْ يَزَالُوا مُرْتَدِّينَ عَلَى أَعْقَابِهِمْ مُنْذُ فَارَقْتَهُمْ","id":"Telah menceritakan kepada kami [Abu Al Walid] Telah menceritakan kepada kami [Syu'bah] Telah mengabarkan kepada kami [Al Mughirah bin An Nu'man] dia berkata; Aku mendengar [Sa'id bin Jubair] dari [Ibnu 'Abbas radliallahu 'anhuma] dia berkata; Rasulullah shallallahu 'alaihi wasallam berkhutbah beliau bersabda: \"Wahai sekalian manusia, sesungguhnya kalian dikumpulkan menuju Allah dalam keadaan tidak beralas kaki, telanjang dan berkulup (tidak dikhitan). Kemudian beliau bersabda: 'Sebagaimana Kami telah memulai panciptaan pertama begitulah Kami akan mengulanginya. Itulah suatu janji yang pasti kami tepati; Sesungguhnya Kamilah yang akan melaksanakannya.' (Al Anbiyaa`: 104) Ketahuilah, sesungguhnya makhluk pertama yang diberi pakaian pada hari kiamat adalah Ibrahim 'alaihis salaam. Ketahuilah, sesungguhnya beberapa orang dari ummatku akan didatangkan lalu mereka diambil ke golongan kiri, aku berkata: 'Wahai Rabb, sahabat-sahabatku.' Dikatakan: 'Sesungguhnya engkau tidak tahu apa yang mereka perbuat sepeninggalmu.' Lalu aku mengucapkan seperti perkataan seorang hamba shalih: 'Aku menjadi saksi atas mereka selagi aku bersama mereka namun tatkala Engkau wafatkan aku, Engkaulah yang mengawasi mereka dan Engkau Maha menyaksikan terhadap segala sesuatu.' (Al Maa`idah: 117-118) lalu dijawab: Mereka senantiasa kembali ke belakang (murtad) sejak kau tinggalkan mereka.\""},"3955":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ حَدَّثَنَا سُفْيَانُ حَدَّثَنَا الْمُغِيرَةُ بْنُ النُّعْمَانِ قَالَ حَدَّثَنِي سَعِيدُ بْنُ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّكُمْ مَحْشُورُونَ وَإِنَّ نَاسًا يُؤْخَذُ بِهِمْ ذَاتَ الشِّمَالِ فَأَقُولُ كَمَا قَالَ الْعَبْدُ الصَّالِحُ{ وَكُنْتُ عَلَيْهِمْ شَهِيدًا مَا دُمْتُ فِيهِمْ إِلَى قَوْلِهِ الْعَزِيزُ الْحَكِيمُ }","id":"Telah menceritakan kepada kami [Muhammad bin Katsir] Telah menceritakan kepada kami [Sufyan] Telah menceritakan kepada kami [Al Mughirah bin An Nu'man] dia berkata; Telah menceritakan kepadaku [Sa'id bin Jubair] dari [Ibnu 'Abbas] dari Nabi shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya kalian akan dikumpulkan pada hari kiamat, dan sesungguhnya ada orang-orang yang ditarik kekiri. Maka aku aku mengucapkan seperti perkataan seorang hamba shalih: 'Aku menjadi saksi atas mereka selagi aku bersama mereka namun tatkala Engkau wafatkan aku, Engkaulah yang mengawasi mereka dan Engkau Maha menyaksikan terhadap segala sesuatu.' (Al Maa`idah: 117-118)."},"3956":{"ar":"حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا إِبْرَاهِيمُ بْنُ سَعْدٍ عَنْ ابْنِ شِهَابٍ عَنْ سَالِمِ بْنِ عَبْدِ اللَّهِ عَنْ أَبِيهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ{ مَفَاتِحُ الْغَيْبِ }خَمْسٌ{ إِنَّ اللَّهَ عِنْدَهُ عِلْمُ السَّاعَةِ وَيُنْزِلُ الْغَيْثَ وَيَعْلَمُ مَا فِي الْأَرْحَامِ وَمَا تَدْرِي نَفْسٌ مَاذَا تَكْسِبُ غَدًا وَمَا تَدْرِي نَفْسٌ بِأَيِّ أَرْضٍ تَمُوتُ إِنَّ اللَّهَ عَلِيمٌ خَبِيرٌ }","id":"Telah menceritakan kepada kami ['Abdul 'Aziz bin 'Abdullah] Telah menceritakan kepada kami [Ibrahim bin Sa'ad] dari [Ibnu Syihab] dari [Salim bin 'Abdullah] dari [Bapaknya] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kunci-kunci hal yang ghaib itu ada lima, tidak ada yang mengetahuinya kecuali Allah Ta'ala: Sesungguhnya hanya Allah lah yang mengetahui datangnya hari kiamat, dan Dia lah Dzat yang menurunkan hujan, yang mengetahui janin yang ada dalam kandungan, dan jiwa manusia tidak mengetahui apa yang akan dapat diperbuatnya esok hari, dan ia juga tidak tahu di bumi mana dia akan mati, Sesungguhnya Allah adalah Dzat yang Maha Mengetahui.\""},"3957":{"ar":"حَدَّثَنَا أَبُو النُّعْمَانِ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ جَابِرٍ رَضِيَ اللَّهُ عَنْهُ قَالَلَمَّا نَزَلَتْ هَذِهِ الْآيَةُ{ قُلْ هُوَ الْقَادِرُ عَلَى أَنْ يَبْعَثَ عَلَيْكُمْ عَذَابًا مِنْ فَوْقِكُمْ }قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَعُوذُ بِوَجْهِكَ قَالَ{ أَوْ مِنْ تَحْتِ أَرْجُلِكُمْ }قَالَ أَعُوذُ بِوَجْهِكَ{ أَوْ يَلْبِسَكُمْ شِيَعًا وَيُذِيقَ بَعْضَكُمْ بَأْسَ بَعْضٍ }قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَذَا أَهْوَنُ أَوْ هَذَا أَيْسَرُ","id":"Telah menceritakan kepada kami [Abu An Nu'man] Telah menceritakan kepada kami [Hammad bin Zaid] dari ['Amru bin Dinar] dari [Jabir radliallahu 'anhu] dia berkata; tatkala turun ayat: \"Katakanlah: \"Dialah yang berkuasa untuk mengirimkan azab kepadamu dari atas kamu.\" Rasulullah shallallahu 'alaihi wasallam bersabda: \"Saya berlindung dengan Wajah-Mu.\" tatkala turun ayat, \"atau dari bawah kakimu.\" Rasulullah shallallahu 'alaihi wasallam bersabda: \"Saya berlindung dengan Wajah-Mu.\" Tatkala turun ayat: 'Atau dia mencampurkan kamu dalam golongan-golongan (yang saling bertentangan) dan merasakan kepada sebahagian kamu keganasan sebahagian yang lain.' Beliau bersabda: \"Ini adalah lebih ringan dan lebih mudah.\""},"3958":{"ar":"حَدَّثَنِي مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا ابْنُ أَبِي عَدِيٍّ عَنْ شُعْبَةَ عَنْ سُلَيْمَانَ عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ عَنْ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُ قَالَلَمَّا نَزَلَتْ{ وَلَمْ يَلْبِسُوا إِيمَانَهُمْ بِظُلْمٍ }قَالَ أَصْحَابُهُ وَأَيُّنَا لَمْ يَظْلِمْ فَنَزَلَتْ{ إِنَّ الشِّرْكَ لَظُلْمٌ عَظِيمٌ }","id":"Telah menceritakan kepadaku [Muhammad bin Basysyar] Telah menceritakan kepada kami [Ibnu Abu 'Adi] dari [Syu'bah] dari [Sulaiman] dari [Ibrahim] dari ['Alqamah] dari ['Abdullah radliallahu 'anhu] dia berkata; Tatkala turun ayat; \"Orang-orang yang beriman dan tidak mencampur adukkan iman mereka dengan kezaliman… (Al An'am: 82). Para sahabat berkata; 'Mana ada di antara kita yang tidak pernah berbuat zhalim? lalu turunlah ayat: \"sesungguhnya mempersekutukan (Allah) adalah benar-benar kezaliman yang besar.\""},"3959":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا ابْنُ مَهْدِيٍّ حَدَّثَنَا شُعْبَةُ عَنْ قَتَادَةَ عَنْ أَبِي الْعَالِيَةِ قَالَ حَدَّثَنِيابْنُ عَمِّ نَبِيِّكُمْ يَعْنِي ابْنَ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَا يَنْبَغِي لِعَبْدٍ أَنْ يَقُولَ أَنَا خَيْرٌ مِنْ يُونُسَ بْنِ مَتَّى","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] Telah menceritakan kepada kami [Ibnu Mahdi] Telah menceritakan kepada kami [Syu'bah] dari [Qatadah] dari [Abu Al 'Aliyah] dia berkata; Telah menceritakan kepadaku putra paman nabi kalian yaitu [Ibnu Abbas radliallahu 'anhuma] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Tidak layak bagi seorang hamba untuk mengatakan: 'Saya lebih baik daripada Yunus bin Mata'.\""},"3960":{"ar":"حَدَّثَنَا آدَمُ بْنُ أَبِي إِيَاسٍ حَدَّثَنَا شُعْبَةُ أَخْبَرَنَا سَعْدُ بْنُ إِبْرَاهِيمَ قَالَ سَمِعْتُ حُمَيْدَ بْنَ عَبْدِ الرَّحْمَنِ بْنِ عَوْفٍ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَا يَنْبَغِي لِعَبْدٍ أَنْ يَقُولَ أَنَا خَيْرٌ مِنْ يُونُسَ بْنِ مَتَّى","id":"Telah menceritakan kepada kami [Adam bin Abu Iyas] Telah menceritakan kepada kami [Syu'bah] Telah mengabarkan kepada kami [Sa'ad bin Ibrahim] dia berkata; Aku mendengar [Humaid bin 'Adur Rahman bin 'Auf] dari [Abu Hurairah radliallahu 'anhu] dari Nabi shallallahu 'alaihi wasallam bersabda: \"Tidak layak bagi seorang hamba untuk mengatakan: 'Saya lebih baik dari Yunus bin Mata'.\""},"3961":{"ar":"حَدَّثَنِي إِبْرَاهِيمُ بْنُ مُوسَى أَخْبَرَنَا هِشَامٌ أَنَّ ابْنَ جُرَيْجٍ أَخْبَرَهُمْ قَالَ أَخْبَرَنِي سُلَيْمَانُ الْأَحْوَلُ أَنَّ مُجَاهِدًا أَخْبَرَهُ أَنَّهُ سَأَلَ ابْنَ عَبَّاسٍأَفِي ص سَجْدَةٌ فَقَالَ نَعَمْ ثُمَّ تَلَا{ وَوَهَبْنَا لَهُ إِسْحَاقَ وَيَعْقُوبَ إِلَى قَوْلِهِ فَبِهُدَاهُمُ اقْتَدِهْ }ثُمَّ قَالَ هُوَ مِنْهُمْزَادَ يَزِيدُ بْنُ هَارُونَ وَمُحَمَّدُ بْنُ عُبَيْدٍ وَسَهْلُ بْنُ يُوسُفَ عَنْ الْعَوَّامِ عَنْ مُجَاهِدٍ قُلْتُ لِابْنِ عَبَّاسٍ فَقَالَ نَبِيُّكُمْ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِمَّنْ أُمِرَ أَنْ يَقْتَدِيَ بِهِمْ","id":"Telah menceritakan kepadaku [Ibrahim bin Musa] Telah mengabarkan kepada kami [Hisyam] bahwa [Ibnu Juraij] mengabarkan kepada mereka seraya berkata; Telah mengabarkan kepadaku [Sulaiman Al Ahwal], [Mujahid] telah mengabarkan kepadanya bahwasanya ia bertanya kepada [Ibnu 'Abbas]; 'Apakah di dalam surat Shaad terdapat ayat sadjah? ' Ibnu Abbas menjawab; 'Ya.' Lalu dia membaca: Dan Kami telah menganugerahkan Ishak dan Yaqub kepadanya…, hingga ayat: Mereka itulah orang-orang yang telah diberi petunjuk oleh Allah, maka ikutilah petunjuk mereka Al An'am: 84-90). Kemudian Ibnu Abbas berkata; 'Daud termasuk dari mereka. [Yazid bin Harun] dan [Muhammad bin 'Ubaid] serta [Sahl bin Yusuf] menambahkan dari [Al Awwam] dari [Mujahid] Aku bertanya kepada [Ibnu 'Abbas], lalu dia menjawab; 'Nabi kalian shallallahu 'alaihi wasallam adalah termasuk orang yang diperintahkan untuk mengikuti mereka.'"},"3962":{"ar":"حَدَّثَنَا عَمْرُو بْنُ خَالِدٍ حَدَّثَنَا اللَّيْثُ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ قَالَ عَطَاءٌ سَمِعْتُ جَابِرَ بْنَ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُمَاسَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ قَاتَلَ اللَّهُ الْيَهُودَ لَمَّا حَرَّمَ اللَّهُ عَلَيْهِمْ شُحُومَهَا جَمَلُوهُ ثُمَّ بَاعُوهُ فَأَكَلُوهَاوَقَالَ أَبُو عَاصِمٍ حَدَّثَنَا عَبْدُ الْحَمِيدِ حَدَّثَنَا يَزِيدُ كَتَبَ إِلَيَّ عَطَاءٌ سَمِعْتُ جَابِرًا عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِثْلَهُ","id":"Telah menceritakan kepada kami ['Amru bin Khalid] Telah menceritakan kepada kami [Al Laits] dari [Yazid bin Abu Habib] dia berkata; ['Atha] mendengar [Jabir bin 'Abdullah radliallahu 'anhuma] Aku mendengar Nabi shallallahu 'alaihi wasallam bersabda: \"Semoga Allah memerangi orang-orang Yahudi, ketika Allah 'azza wajalla tatkala mengharamkan lemak atas mereka maka mereka mencairkannya kemudian menjualnya dan memakan harganya.\" Dan [Abu 'Ashim] berkata; Telah menceritakan kepada kami ['Abdul Hamid] Telah menceritakan kepada kami [Yazid] bahwa ['Atha] telah menulis kepadaku; Aku mendengar [Jabir] dari Nabi shallallahu 'alaihi wasallam dengan Hadits yang serupa."},"3963":{"ar":"حَدَّثَنَا حَفْصُ بْنُ عُمَرَ حَدَّثَنَا شُعْبَةُ عَنْ عَمْرٍو عَنْ أَبِي وَائِلٍ عَنْ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُ قَالَلَا أَحَدَ أَغْيَرُ مِنْ اللَّهِ وَلِذَلِكَ حَرَّمَ الْفَوَاحِشَ مَا ظَهَرَ مِنْهَا وَمَا بَطَنَ وَلَا شَيْءَ أَحَبُّ إِلَيْهِ الْمَدْحُ مِنْ اللَّهِ وَلِذَلِكَ مَدَحَ نَفْسَهُ قُلْتُ سَمِعْتَهُ مِنْ عَبْدِ اللَّهِ قَالَ نَعَمْ قُلْتُ وَرَفَعَهُ قَالَ نَعَمْ{ وَكِيلٌ }حَفِيظٌ وَمُحِيطٌ بِهِ{ قُبُلًا }جَمْعُ قَبِيلٍ وَالْمَعْنَى أَنَّهُ ضُرُوبٌ لِلْعَذَابِ كُلُّ ضَرْبٍ مِنْهَا قَبِيلٌ{ زُخْرُفَ الْقَوْلِ }كُلُّ شَيْءٍ حَسَّنْتَهُ وَوَشَّيْتَهُ وَهُوَ بَاطِلٌ فَهُوَ زُخْرُفٌ{ وَحَرْثٌ حِجْرٌ }حَرَامٌ وَكُلُّ مَمْنُوعٍ فَهْوَ حِجْرٌ مَحْجُورٌ وَالْحِجْرُ كُلُّ بِنَاءٍ بَنَيْتَهُ وَيُقَالُ لِلْأُنْثَى مِنْ الْخَيْلِ حِجْرٌ وَيُقَالُ لِلْعَقْلِ حِجْرٌ وَحِجًى وَأَمَّا الْحِجْرُ فَمَوْضِعُ ثَمُودَ وَمَا حَجَّرْتَ عَلَيْهِ مِنْ الْأَرْضِ فَهُوَ حِجْرٌ وَمِنْهُ سُمِّيَ حَطِيمُ الْبَيْتِ حِجْرًا كَأَنَّه مُشْتَقٌّ مِنْ مَحْطُومٍ مِثْلُ قَتِيلٍ مِنْ مَقْتُولٍ وَأَمَّا حَجْرُ الْيَمَامَةِ فَهْوَ مَنْزِلٌ","id":"Telah menceritakan kepada kami [Hafsh bin 'Umar] Telah menceritakan kepada kami [Syu'bah] dari ['Amru] dari [Abu Wail] dari ['Abdullah radliallahu 'anhu] dia berkata; \"Tidak ada yang lebih pencemburu dari Allah. Karena itulah Dia mengharamkan segala yang keji baik yang nampak maupun yang tidak nampak. Dan tidak ada yang lebih suka dipuji selain Allah karena itulah Dia memuji diri-Nya.\" lalu aku tanyakan kepadanya; apakah kamu mendengarnya dari Abdullah? Dia menjawab; Ya, secara marfu.' Sedangkan arti WAKIL (Al An'am: 102), adalah penjaga dan yang melindunginya. Sedangkan QUBULAN adalah jama' dari Qabil yang artinya; berbagai macam siksa."},"3964":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ حَدَّثَنَا عَبْدُ الْوَاحِدِ حَدَّثَنَا عُمَارَةُ حَدَّثَنَا أَبُو زُرْعَةَ حَدَّثَنَا أَبُو هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَقُومُ السَّاعَةُ حَتَّى تَطْلُعَ الشَّمْسُ مِنْ مَغْرِبِهَا فَإِذَا رَآهَا النَّاسُ آمَنَ مَنْ عَلَيْهَا فَذَاكَ حِينَ{ لَا يَنْفَعُ نَفْسًا إِيمَانُهَا لَمْ تَكُنْ آمَنَتْ مِنْ قَبْلُ }","id":"Telah menceritakan kepada kami [Musa bin Isma'il] Telah menceritakan kepada kami ['Abdul Wahid] Telah menceritakan kepada kami [Umarah] Telah menceritakan kepada kami [Abu Zur'ah] Telah menceritakan kepada kami [Abu Hurairah radliallahu 'anhu] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak akan terjadi hari kiamat hingga matahari terbit dari sebelah barat. Apabila matahari itu telah terbit, dan orang-orang melihatnya maka mereka semua segera beriman. Itulah maksud firman Allah: Pada hari datangnya ayat (tanda) dari Tuhanmu, tidaklah bermanfaat lagi iman seseorang kepada dirinya sendiri yang belum beriman sebelum itu, atau dia (belum) mengusahakan kebaikan dalam masa imannya. (Al An'am 158)."},"3965":{"ar":"حَدَّثَنِي إِسْحَاقُ أَخْبَرَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ هَمَّامٍ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَقُومُ السَّاعَةُ حَتَّى تَطْلُعَ الشَّمْسُ مِنْ مَغْرِبِهَا فَإِذَا طَلَعَتْ وَرَآهَا النَّاسُ آمَنُوا أَجْمَعُونَ وَذَلِكَ حِينَ لَا يَنْفَعُ نَفْسًا إِيمَانُهَا ثُمَّ قَرَأَ الْآيَةَ","id":"Telah menceritakan kepadaku [Ishaq] Telah mengabarkan kepada kami ['Abdur Razzaq] Telah mengabarkan kepada kami [Ma'mar] dari [Hammam] dari [Abu Hurairah radliallahu 'anhu] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak akan terjadi hari kiamat hingga matahari terbit dari sebelah barat. Apabila matahari itu telah terbit dari barat, dan orang-orang melihatnya maka mereka semua segera beriman. Itulah keimanan yang tidak berguna bagi dirinya. Lalu beliau membaca ayat (yang berkenaan dengan hal itu).\""},"3966":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا شُعْبَةُ عَنْ عَمْرِو بْنِ مُرَّةَ عَنْ أَبِي وَائِلٍ عَنْ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُ قَالَ قُلْتُ أَنْتَ سَمِعْتَ هَذَا مِنْ عَبْدِ اللَّهِ قَالَ نَعَمْ وَرَفَعَهُ قَالَلَا أَحَدَ أَغْيَرُ مِنْ اللَّهِ فَلِذَلِكَ حَرَّمَ الْفَوَاحِشَ مَا ظَهَرَ مِنْهَا وَمَا بَطَنَ وَلَا أَحَدَ أَحَبُّ إِلَيْهِ الْمِدْحَةُ مِنْ اللَّهِ فَلِذَلِكَ مَدَحَ نَفْسَهُ","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] Telah menceritakan kepada kami [Syu'bah] dari ['Amru bin Murrah] dari [Abu Wail] dari ['Abdullah radliallahu 'anhu] dia berkata; apakah kamu mendengarnya dari Abdullah? Dia menjawab; Ya, secara marfu' dia berkata; \"Tidak ada yang lebih pencemburu dari Allah. Karena itulah Dia mengharamkan segala yang keji baik yang nampak maupun yang tidak nampak. Dan tidak ada yang lebih suka dipuji selain Allah karena itulah Dia memuji diri-Nya.\""},"3967":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا سُفْيَانُ عَنْ عَمْرِو بْنِ يَحْيَى الْمَازِنِيِّ عَنْ أَبِيهِ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ رَضِيَ اللَّهُ عَنْهُ قَالَجَاءَ رَجُلٌ مِنْ الْيَهُودِ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ لُطِمَ وَجْهُهُ وَقَالَ يَا مُحَمَّدُ إِنَّ رَجُلًا مِنْ أَصْحَابِكَ مِنْ الْأَنْصَارِ لَطَمَ فِي وَجْهِي قَالَ ادْعُوهُ فَدَعَوْهُ قَالَ لِمَ لَطَمْتَ وَجْهَهُ قَالَ يَا رَسُولَ اللَّهِ إِنِّي مَرَرْتُ بِالْيَهُودِ فَسَمِعْتُهُ يَقُولُ وَالَّذِي اصْطَفَى مُوسَى عَلَى الْبَشَرِ فَقُلْتُ وَعَلَى مُحَمَّدٍ وَأَخَذَتْنِي غَضْبَةٌ فَلَطَمْتُهُ قَالَ لَا تُخَيِّرُونِي مِنْ بَيْنِ الْأَنْبِيَاءِ فَإِنَّ النَّاسَ يَصْعَقُونَ يَوْمَ الْقِيَامَةِ فَأَكُونُ أَوَّلَ مَنْ يُفِيقُ فَإِذَا أَنَا بِمُوسَى آخِذٌ بِقَائِمَةٍ مِنْ قَوَائِمِ الْعَرْشِ فَلَا أَدْرِي أَفَاقَ قَبْلِي أَمْ جُزِيَ بِصَعْقَةِ ا��طُّورِ{ الْمَنَّ وَالسَّلْوَى }","id":"Telah menceritakan kepada kami [Muhammad bin Yusuf] Telah menceritakan kepada kami [Sufyan] dari ['Amru bin Yahya Al Mazini] dari [Bapaknya] dari [Abu Sa'id Al Khudri radliallahu 'anhu] dia berkata; \"Seseorang dari yahudi datang menemui Rasulullah shallallahu 'alaihi wasallam dengan wajah bekas dipukul, lalu ia berkata kepada beliau; \"Ya Muhammad, Aku telah dipukul oleh salah seorang dari sahabatmu dari golongan Anshar, \" lalu Nabi shallallahu 'alaihi wasallam pun bersabda kepadanya panggilkan dia! Mereka pun memanggilnya kemudian Nabi shallallahu 'alaihi wasallam bertanya: \"Kenapa engkau pukul dia?\" ia menjawab; \"Wahai Rasulullah, pada waktu itu aku melewati orang Yahudi, lalu aku mendengar dia berkata; 'Demi Dzat yang telah memilih Musa dari semua manusia.' Maka aku katakan; 'Apakah dari Muhammad juga?, hingga dia membuatku marah, maka aku memukulnya. Nabi shallallahu 'alaihi wasallam bersabda: \"Janganlah kalian melebihkan sebagian nabi dengan sebagian yang lain, sesungguhnya pada hari kiamat manusia dalam keadaan pingsan, lalu aku adalah orang yang pertama kali mengangkat kepalanya dari tanah, namun aku mendapati Musa 'Alaihis Salam telah berada di sisi 'Arsy, aku tidak tahu apakah dia lebih duluan bangun dari pada aku atau dia sudah cukup dengan pingsannya ketika di bukit Thur Al Manna wa Salwa (QS. Al A'raf - 160) hingga tidak pingsan lagi.\""},"3968":{"ar":"حَدَّثَنَا مُسْلِمٌ حَدَّثَنَا شُعْبَةُ عَنْ عَبْدِ الْمَلِكِ عَنْ عَمْرِو بْنِ حُرَيْثٍ عَنْ سَعِيدِ بْنِ زَيْدٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْكَمْأَةُ مِنْ الْمَنِّ وَمَاؤُهَا شِفَاءُ الْعَيْنِ","id":"Telah menceritakan kepada kami [Muslim] Telah menceritakan kepada kami [Syu'bah] dari ['Abdul Malik] dari ['Amru bin Huraits] dari [Sa'id bin Zaid] dari Nabi shallallahu 'alaihi wasallam bersabda: \"Al Kam'ah (cendawan) itu sejenis Manna, airnya adalah obat untuk penyakit mata.\""},"3969":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ حَدَّثَنَا سُلَيْمَانُ بْنُ عَبْدِ الرَّحْمَنِ وَمُوسَى بْنُ هَارُونَ قَالَا حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ الْعَلَاءِ بْنِ زَبْرٍ قَالَ حَدَّثَنِي بُسْرُ بْنُ عُبَيْدِ اللَّهِ قَالَ حَدَّثَنِي أَبُو إِدْرِيسَ الْخَوْلَانِيُّ قَالَ سَمِعْتُ أَبَا الدَّرْدَاءِ يَقُولُكَانَتْ بَيْنَ أَبِي بَكْرٍ وَعُمَرَ مُحَاوَرَةٌ فَأَغْضَبَ أَبُو بَكْرٍ عُمَرَ فَانْصَرَفَ عَنْهُ عُمَرُ مُغْضَبًا فَاتَّبَعَهُ أَبُو بَكْرٍ يَسْأَلُهُ أَنْ يَسْتَغْفِرَ لَهُ فَلَمْ يَفْعَلْ حَتَّى أَغْلَقَ بَابَهُ فِي وَجْهِهِ فَأَقْبَلَ أَبُو بَكْرٍ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَبُو الدَّرْدَاءِ وَنَحْنُ عِنْدَهُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَّا صَاحِبُكُمْ هَذَا فَقَدْ غَامَرَ قَالَ وَنَدِمَ عُمَرُ عَلَى مَا كَانَ مِنْهُ فَأَقْبَلَ حَتَّى سَلَّمَ وَجَلَسَ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَصَّ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْخَبَرَ قَالَ أَبُو الدَّرْدَاءِ وَغَضِبَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَجَعَلَ أَبُو بَكْرٍ يَقُولُ وَاللَّهِ يَا رَسُولَ اللَّهِ لَأَنَا كُنْتُ أَظْلَمَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَلْ أَنْتُمْ تَارِكُونَ لِي صَاحِبِي هَلْ أَنْتُمْ تَارِكُونَ لِي صَاحِبِي إِنِّي قُلْتُ يَا أَيُّهَا النَّاسُ إِنِّي رَسُولُ اللَّهِ إِلَيْكُمْ جَمِيعًا فَقُلْتُمْ كَذَبْتَ وَقَالَ أَبُو بَكْرٍ صَدَقْتَقَالَ أَبُو عَبْد اللَّهِ غَامَرَ سَبَقَ بِالْخَيْرِ","id":"Telah menceritakan kepada kami ['Abdullah] Telah menceritakan kepada kami [Sulaiman bin 'Abdur Rahman] dan [Musa bin Harun] dia berkata; Telah menceritakan kepada kami [Al Walid bin Muslim] Telah menceritakan kepada kami ['Abdullah bin Al A'laa bin Zabr] dia berkata; Telah menceritakan kepadaku [Busr bin 'Ubaidillah] dia berkata; Telah menceritakan kepadaku [Abu Idris Al Khaulani] dia berkata; Aku mendengar [Abu Darda] berkata; Abu Bakr dan Umar pernah berdebat hingga Abu Bakr marah kepada Umar. Umar pun berpaling darinya dalam keadaan marah. Lalu Abu Bakr mengejarnya untuk meminta maaf. Namun Umar tidak memberi maaf hingga ia menutup pintu rumahnya dihadapan Abu Bakr. Abu Bakr kemudian menemui Rasulullah shallallahu 'alaihi wasallam. Abu Darda berkata; pada waktu itu aku berada disamping Rasulullah shallallahu 'alaihi wasallam. kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya temanmu ini telah berbuat baik lebih dahulu.\" Abu Darda berkata; maka Umar menyesal atas apa yang telah dia perbuat. Lalu ia datang dan mengucapkan salam serta duduk di samping Rasulullah shallallahu 'alaihi wasallam seraya menceritakan kepada Rasulullah shallallahu 'alaihi wasallam apa yang telah ia perbuat. Abu Darda berkata; Rasulullah shallallahu 'alaihi wasallam pun marah, hingga Abu Bakr berkata; 'Demi Allah ya Rasulullah, Akulah yang telah berbuat zhalim. Rasulullah shallallahu 'alaihi wasallam bersabda: 'Bukankah kalian pernah meninggalkan sahabatku untukku, Bukankah kalian pernah meninggalkan sahabatku untukku?. Sesungguhnya aku pernah berkata; Wahai sekalian manusia, sesungguhnya aku adalah utusan kepada kalian semua, lalu kalian katakan; 'Anda telah berdusta, namun Abu Bakr berkata; 'Anda benar.' Abu Abdullah berkata; Ghamara artinya; telah berbuat baik lebih dahulu."},"3970":{"ar":"حَدَّثَنَا إِسْحَاقُ أَخْبَرَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ هَمَّامِ بْنِ مُنَبِّهٍ أَنَّهُ سَمِعَ أَبَا هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قِيلَ لِبَنِي إِسْرَائِيلَ{ ادْخُلُوا الْبَابَ سُجَّدًا وَقُولُوا حِطَّةٌ نَغْفِرْ لَكُمْ خَطَايَاكُمْ }فَبَدَّلُوا فَدَخَلُوا يَزْحَفُونَ عَلَى أَسْتَاهِهِمْ وَقَالُوا حَبَّةٌ فِي شَعَرَةٍ","id":"Telah menceritakan kepada kami [Ishaq] Telah mengabarkan kepada kami ['Abdur Razzaq] Telah mengabarkan kepada kami [Ma'mar] dari [Hammam bin Munabbih] bahwasanya aku mendengar [Abu Hurairah radliallahu 'anhu] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Dikatakan kepada Bani Israil: 'Masuklah pintu itu dengan keadaan sujud dan Katakanlah: 'Hitthah' (ampunilah dosa-dosa) niscaya Dia mengampuni kesalahan-kesalahan kalian lalu mereka mengganti (lafazh ucapan itu) dan memasuki pintu itu seraya mereka merangkak di atas pantat-pantat mereka dan mereka berkata: 'Habbah (biji) dalam tepung'.\""},"3971":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي عُبَيْدُ اللَّهِ بْنُ عَبْدِ اللَّهِ بْنِ عُتْبَةَ أَنَّ ابْنَ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَقَدِمَ عُيَيْنَةُ بْنُ حِصْنِ بْنِ حُذَيْفَةَ فَنَزَلَ عَلَى ابْنِ أَخِيهِ الْحُرِّ بْنِ قَيْسٍ وَكَانَ مِنْ النَّفَرِ الَّذِينَ يُدْنِيهِمْ عُمَرُ وَكَانَ الْقُرَّاءُ أَصْحَابَ مَجَالِسِ عُمَرَ وَمُشَاوَرَتِهِ كُهُولًا كَانُوا أَوْ شُبَّانًا فَقَالَ عُيَيْنَةُ لِابْنِ أَخِيهِ يَا ابْنَ أَخِي هَلْ لَكَ وَجْهٌ عِنْدَ هَذَا الْأَمِيرِ فَاسْتَأْذِنْ لِي عَلَيْهِ قَالَ سَأَسْتَأْذِنُ لَكَ عَلَيْهِ قَالَ ابْنُ عَبَّاسٍ فَاسْتَأْذَنَ الْحُرُّ لِعُيَيْنَةَ فَأَذِنَ لَهُ عُمَرُ فَلَمَّا دَخَلَ عَلَيْهِ قَالَ هِيْ يَا ابْنَ الْخَطَّابِ فَوَاللَّهِ مَا تُعْطِينَا الْجَزْلَ وَلَا تَحْكُمُ بَيْنَنَا بِالْعَدْلِ فَغَضِبَ عُمَرُ حَتَّى هَمَّ أَنْ يُوقِعَ بِهِ فَقَالَ لَهُ الْحُرُّ يَا أَمِيرَ الْمُؤْمِنِينَ إِنَّ اللَّهَ تَعَالَى قَالَ لِنَبِيِّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ{ خُذْ الْعَفْوَ وَأْمُرْ بِالْعُرْفِ وَأَعْرِضْ عَنْ الْجَاهِلِينَ }وَإِنَّ هَذَا مِنْ الْجَاهِلِينَ وَاللَّهِ مَا جَاوَزَهَا عُمَرُ حِينَ تَلَاهَا عَلَيْهِ وَكَانَ وَقَّافًا عِنْدَ كِتَابِ اللَّهِ","id":"Telah menceritakan kepada kami [Abu Al Yaman] Telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhri] dia berkata; Telah mengabarkan kepadaku ['Ubaidullah bin 'Abdullah bin 'Utbah] bahwa [Ibnu 'Abbas radliallahu 'anhuma] berkata; Uyainah bin Hishan bin Hudzafah datang, lalu singgah dirumah anak saudaranya yaitu AL Hurr bin Qais. Ia adalah salah seorang yang dekat dengan Umar, salah seorang Qari di Majlis Umar dan dewan syuranya. Baik ketika ia masih muda maupun sudah tua. Uyainah berkata kepada anak saudaranya; Wahai anak saudaraku, apakah kamu ada masalah dengan Amirul Mukminin, izinkanlah aku menemuinya. AL Hurr berkata; Aku akan memintakan izin untukmu. Ibnu Abbas berkata; Maka Al Hurr meminta izin untuk Uyainah agar bisa menemui Umar, Umar pun mengizinkannya. Tatkala ia masuk, ia berkata; Wahai Ibnul Khatthab, Demi Allah, anda tidak memenuhi hak kami, dan tidak bersikap adil kepada kami. Maka Umar pun marah, hampir saja ia akan memukulnya. Lalu Al Hurr berkata kepadanya; Wahai Amirul Mukminin, Sesungguhnya Allah Ta'ala berfirman kepada Nabi shallallahu 'alaihi wasallam: Jadilah engkau pema'af dan suruhlah orang mengerjakan yang ma'ruf, serta berpalinglah dari pada orang-orang yang bodoh. Dan ini terhadap orang-orang yang bodoh. Ibnu Abbas berkata; maka demi Allah, Umar pun tidak menyakitinya ketika ayat itu dibacakan kepadanya. Ia berhenti mendengar Kitabullah."},"3972":{"ar":"حَدَّثَنَا يَحْيَى حَدَّثَنَا وَكِيعٌ عَنْ هِشَامٍ عَنْ أَبِيهِ عَنْ عَبْدِ اللَّهِ بْنِ الزُّبَيْرِ{ خُذْ الْعَفْوَ وَأْمُرْ بِالْعُرْفِ }قَالَ مَا أَنْزَلَ اللَّهُ إِلَّا فِي أَخْلَاقِ النَّاسِ وَقَالَ عَبْدُ اللَّهِ بْنُ بَرَّادٍ حَدَّثَنَا أَبُو أُسَامَةَ حَدَّثَنَا هِشَامٌ عَنْ أَبِيهِ عَنْ عَبْدِ اللَّهِ بْنِ الزُّبَيْرِ قَالَأَمَرَ اللَّهُ نَبِيَّهُ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يَأْخُذَ الْعَفْوَ مِنْ أَخْلَاقِ النَّاسِ أَوْ كَمَا قَالَ","id":"Telah menceritakan kepada kami [Yahya] Telah menceritakan kepada kami [Waki'] dari [Hisyam] dari [Bapaknya] dari ['Abdullah bin Az Zubair] mengenai firman Allah; Jadilah engkau pema'af dan suruhlah orang mengerjakan yang ma'ruf (Al A'raf: 199). Dia berkata; Tidaklah Allah menurunkannya kecuali mengenai akhlak manusia. ['Abdullah bin Barrad] berkata; Telah menceritakan kepada kami [Abu Usamah] Telah menceritakan kepada kami [Hisyam] dari [Bapaknya] dari ['Abdullah bin Az Zubair] dia berkata; 'Allah menyuruh Nabi shallallahu 'alaihi wasallam agar memaafkan kesalahan manusia kepada beliau.' -atau kurang lebih demikianlah apa yang ia katakan.-"},"3973":{"ar":"حَدَّثَنِي مُحَمَّدُ بْنُ عَبْدِ الرَّحِيمِ حَدَّثَنَا سَعِيدُ بْنُ سُلَيْمَانَ أَخْبَرَنَا هُشَيْمٌ أَخْبَرَنَا أَبُو بِشْرٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ قَالَ قُلْتُ لِابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَاسُورَةُ الْأَنْفَالِ قَالَ نَزَلَتْ فِي بَدْرٍالشَّوْكَةُ الْحَدُّ{ مُرْدَفِينَ }فَوْجًا بَعْدَ فَوْجٍ رَدِفَنِي وَأَرْدَفَنِي جَاءَ بَعْدِي{ ذُوقُوا }بَاشِرُوا وَجَرِّبُوا وَلَيْسَ هَذَا مِنْ ذَوْقِ الْفَمِ{ فَيَرْكُمَهُ }يَجْمَعَهُ شَرِّدْ فَرِّقْ{ وَإِنْ جَنَحُوا }طَلَبُوا السِّلْمُ وَالسَّلْمُ وَالسَّلَامُ وَاحِدٌ{ يُثْخِنَ }يَغْلِبَ وَقَالَ مُجَاهِدٌ{ مُكَاءً }إِدْخَالُ أَصَابِعِهِمْ فِي أَفْوَاهِهِمْ{ وَتَصْدِيَةً }الصَّفِيرُ{ لِيُثْبِتُوكَ }لِيَحْبِسُوكَ","id":"Telah menceritakan kepadaku [Muhammad bin 'Abdur Rahim] Telah menceritakan kepada kami [Sa'id bin Sulaiman] Telah mengabarkan kepada kami [Husyaim] Telah mengabarkan kepada kami [Abu Bisyr] dari [Sa'id bin Jubair] dia berkata; Aku bertanya kepada [Ibnu 'Abbas radliallahu 'anhuma] surat Al Anfal, lalu dia menjawab; 'Yaitu surat yang diturunkan di perang Badar. Perang yang penuh onak dan duri. MURDIFIN artinya; datang bertubi-tubi, hingga cukup melelahkanku dan orang yang datang setelahku. DZUQUU, artinya; berilah kabar gembira, dan berusahalah terus. Ini bukan rasa yang bisa diketahui melalui mulut. FAYARKUMUHU artinya; bergabung dan berpencar. WA IN JANAHU artinya jika mereka meminta keselamatan dan keamanan atau berdamai (satu makna). YUSKHINA artinya: kekalahan. Mujahid berkata; arti MUKAA`AN yaitu memasukan jari-jari mereka ke dalam mulut-mulut mereka. Arti TASHDIYAH; suara yang memekakkan. LIYUTSBITUTKA artinya; untuk menahanmu."},"3974":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا وَرْقَاءُ عَنْ ابْنِ أَبِي نَجِيحٍ عَنْ مُجَاهِدٍ عَنْ ابْنِ عَبَّاسٍ{ إِنَّ شَرَّ الدَّوَابِّ عِنْدَ اللَّهِ الصُّمُّ الْبُكْمُ الَّذِينَ لَا يَعْقِلُونَ }قَالَ هُمْ نَفَرٌ مِنْ بَنِي عَبْدِ الدَّارِ","id":"Telah menceritakan kepada kami [Muhammad bin Yusuf] Telah menceritakan kepada kami [Warqa'] dari [Ibnu Abu Najih] dari [Mujahid] dari [Ibnu 'Abbas] mengenai firman Allah: Sesungguhnya binatang (makhluk) yang seburuk-buruknya pada sisi Allah ialah; orang-orang yang pekak dan tuli yang tidak mengerti apa-apapun. mereka adalah beberapa orang dari bani Abdu Daar."},"3975":{"ar":"حَدَّثَنِي إِسْحَاقُ أَخْبَرَنَا رَوْحٌ حَدَّثَنَا شُعْبَةُ عَنْ خُبَيْبِ بْنِ عَبْدِ الرَّحْمَنِ سَمِعْتُ حَفْصَ بْنَ عَاصِمٍ يُحَدِّثُ عَنْ أَبِي سَعِيدِ بْنِ الْمُعَلَّى رَضِيَ اللَّهُ عَنْهُ قَالَكُنْتُ أُصَلِّي فَمَرَّ بِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَدَعَانِي فَلَمْ آتِهِ حَتَّى صَلَّيْتُ ثُمَّ أَتَيْتُهُ فَقَالَ مَا مَنَعَكَ أَنْ تَأْتِيَ أَلَمْ يَقُلْ اللَّهُ{ يَا أَيُّهَا الَّذِينَ آمَنُوا اسْتَجِيبُوا لِلَّهِ وَلِلرَّسُولِ إِذَا دَعَاكُمْ }ثُمَّ قَالَ لَأُعَلِّمَنَّكَ أَعْظَمَ سُورَةٍ فِي الْقُرْآنِ قَبْلَ أَنْ أَخْرُجَ فَذَهَبَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِيَخْرُجَ فَذَكَرْتُ لَهُوَقَالَ مُعَاذٌ حَدَّثَنَا شُعْبَةُ عَنْ خُبَيْبِ بْنِ عَبْدِ الرَّحْمَنِ سَمِعَ حَفْصًا سَمِعَ أَبَا سَعِيدٍ رَجُلًا مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِهَذَا وَقَالَ هِيَ الْحَمْدُ لِلَّهِ رَبِّ الْعَالَمِينَ السَّبْعُ الْمَثَانِي","id":"Telah menceritakan kepadaku [Ishaq] Telah mengabarkan kepada kami [Rauh] Telah menceritakan kepada kami [Syu'bah] dari [Khubaib bin 'Abdur Rahman]; Aku mendengar [Hafsh bin 'Ashim] bercerita dari [Abu Sa'id bin Al Mu'alla radliallahu 'anhu] dia berkata; Suatu saat saya sedang melaksanakan shalat, tiba-tiba Rasulullah shallallahu 'alaihi wasallam lewat dan memanggilku namun saya tidak menjawab panggilannya hingga shalatku selesai. Setelah itu, saya menemui beliau, maka beliau pun bertanya: \"Apa yang menghalangimu untuk mendatangiku? Bukankah Allah 'azza wajalla telah berfirman; 'Hai orang-orang yang beriman, penuhilah seruan Allah dan seruan Rasul apabila Rasul menyeru kamu.' Beliau bersabda lagi: \"Sungguh, saya akan mengajarimu tentang surat yang paling agung yang terdapat di dalam Al Qur`an sebelum kamu keluar dari Masjid.\" Kemudian tatkala beliau hendak keluar aku mengingatkan janji Rasulullah tersebut. Dan [Mu'adz] berkata; Telah menceritakan kepada kami [Syu'bah] dari [Khubaib bin 'Abdur Rahman] dia mendengar [Hafsh] dia mendengar [Abu Sa'id] seorang sahabat Nabi shallallahu 'alaihi wasallam -sebagaimana kisah di atas.- dan dia berkata; yaitu surat; AL HAMDU LILLAHI RABBIL 'AALAMIIN (Segala puji bagi Allah, Rabb semesta Alam), ia adalah As Sab'u Al Matsani (tujuh ayat yang diulang-ulang, surat alfatihah)."},"3976":{"ar":"حَدَّثَنِي أَحْمَدُ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُعَاذٍ حَدَّثَنَا أَبِي حَدَّثَنَا شُعْبَةُ عَنْ عَبْدِ الْحَمِيدِ هُوَ ابْنُ كُرْدِيدٍ صَاحِبُ الزِّيَادِيِّ سَمِعَ أَنَسَ بْنَ مَالِكٍ رَضِيَ اللَّهُ عَنْهُقَالَ أَبُو جَهْلٍ اللَّهُمَّ إِنْ كَانَ هَذَا هُوَ الْحَقَّ مِنْ عِنْدِكَ فَأَمْطِرْ عَلَيْنَا حِجَارَةً مِنْ السَّمَاءِ أَوْ ائْتِنَا بِعَذَابٍ أَلِيمٍ فَنَزَلَتْ{ وَمَا كَانَ اللَّهُ لِيُعَذِّبَهُمْ وَأَنْتَ فِيهِمْ وَمَا كَانَ اللَّهُ مُعَذِّبَهُمْ وَهُمْ يَسْتَغْفِرُونَ وَمَا لَهُمْ أَنْ لَا يُعَذِّبَهُمْ اللَّهُ وَهُمْ يَصُدُّونَ عَنْ الْمَسْجِدِ الْحَرَامِ }الْآيَةَ","id":"Telah menceritakan kepadaku [Ahmad] Telah menceritakan kepada kami ['Ubaidullah bin Mu'adz] Telah menceritakan kepada kami [ayahku] telah menceritakan kepada kami [Syu'bah] dari ['Abdu Hamid] yaitu Ibnu Kurdid sahabat Az Ziyadi, dia mendengar [Anas bin Malik radliallahu 'anhu] berkata; Abu Jahl berkata; \"Ya Allah, jika betul (Al Quran) ini, dialah yang benar dari sisi Engkau, maka hujanilah kami dengan batu dari langit, atau datangkanlah kepada kami azab yang pedih.\" Maka turunlah ayat: Dan Allah sekali-kali tidak akan mengazab mereka, sedang kamu berada di antara mereka. Dan tidaklah (pula) Allah akan mengazab mereka, sedang mereka meminta ampun. Kenapa Allah tidak mengazab mereka padahal mereka menghalangi orang untuk (mendatangi) Masjidil Haram.. (An Anfal: 33-34)."},"3977":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ النَّضْرِ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُعَاذٍ حَدَّثَنَا أَبِي حَدَّثَنَا شُعْبَةُ عَنْ عَبْدِ الْحَمِيدِ صَاحِبِ الزِّيَادِيِّ سَمِعَ أَنَسَ بْنَ مَالِكٍ قَالَقَالَ أَبُو جَهْلٍ اللَّهُمَّ إِنْ كَانَ هَذَا هُوَ الْحَقَّ مِنْ عِنْدِكَ فَأَمْطِرْ عَلَيْنَا حِجَارَةً مِنْ السَّمَاءِ أَوْ ائْتِنَا بِعَذَابٍ أَلِيمٍ فَنَزَلَتْ{ وَمَا كَانَ اللَّهُ لِيُعَذِّبَهُمْ وَأَنْتَ فِيهِمْ وَمَا كَانَ اللَّهُ مُعَذِّبَهُمْ وَهُمْ يَسْتَغْفِرُونَ وَمَا لَهُمْ أَنْ لَا يُعَذِّبَهُمْ اللَّهُ وَهُمْ يَصُدُّونَ عَنْ الْمَسْجِدِ الْحَرَامِ }الْآيَةَ","id":"Telah menceritakan kepada kami [Muhammad bin An Nadlr] Telah menceritakan kepada kami ['Ubaidullah bin Mu'adz] Telah menceritakan kepada kami [Bapakku] Telah menceritakan kepada kami [Syu'bah] dari ['Abdul Hamid] sahabat Az Ziyadi, dia mendengar [Anas bin Malik radliallahu 'anhu] berkata; Abu Jahl berkata; \"Ya Allah, jika betul (Al Quran) ini, dialah yang benar dari sisi Engkau, maka hujanilah kami dengan batu dari langit, atau datangkanlah kepada kami azab yang pedih.\" Maka turunlah ayat: Dan Allah sekali-kali tidak akan mengazab mereka, sedang kamu berada di antara mereka. Dan tidaklah (pula) Allah akan mengazab mereka, sedang mereka meminta ampun. Kenapa Allah tidak mengazab mereka padahal mereka menghalangi orang untuk (mendatangi) Masjidil Haram.. (An Anfal: 33-34)."},"3978":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ عَبْدِ الْعَزِيزِ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يَحْيَى حَدَّثَنَا حَيْوَةُ عَنْ بَكْرِ بْنِ عَمْرٍو عَنْ بُكَيْرٍ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ رَجُلًا جَاءَهُ فَقَالَ يَا أَبَا عَبْدِ الرَّحْمَنِ أَلَا تَسْمَعُ مَا ذَكَرَ اللَّهُ فِي كِتَابِهِ{ وَإِنْ طَائِفَتَانِ مِنْ الْمُؤْمِنِينَ اقْتَتَلُوا }إِلَى آخِرِ الْآيَةِ فَمَا يَمْنَعُكَ أَنْ لَا تُقَاتِلَ كَمَا ذَكَرَ اللَّهُ فِي كِتَابِهِ فَقَالَ يَا ابْنَ أَخِي أَغْتَرُّ بِهَذِهِ الْآيَةِ وَلَا أُقَاتِلُ أَحَبُّ إِلَيَّ مِنْ أَنْ أَغْتَرَّ بِهَذِهِ الْآيَةِ الَّتِي يَقُولُ اللَّهُ تَعَالَى{ وَمَنْ يَقْتُلْ مُؤْمِنًا مُتَعَمِّدًا }إِلَى آخِرِهَا قَالَ فَإِنَّ اللَّهَ يَقُولُ{ وَقَاتِلُوهُمْ حَتَّى لَا تَكُونَ فِتْنَةٌ }قَالَ ابْنُ عُمَرَ قَدْ فَعَلْنَا عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذْ كَانَ الْإِسْلَامُ قَلِيلًا فَكَانَ الرَّجُلُ يُفْتَنُ فِي دِينِهِ إِمَّا يَقْتُلُونَهُ وَإِمَّا يُوثِقُونَهُ حَتَّى كَثُرَ الْإِسْلَامُ فَلَمْ تَكُنْ فِتْنَةٌ فَلَمَّا رَأَى أَنَّهُ لَا يُوَافِقُهُ فِيمَا يُرِيدُ قَالَ فَمَا قَوْلُكَ فِي عَلِيٍّ وَعُثْمَانَ قَالَ ابْنُ عُمَرَ مَا قَوْلِي فِي عَلِيٍّ وَعُثْمَانَ أَمَّا عُثْمَانُ فَكَانَ اللَّهُ قَدْ عَفَا عَنْهُ فَكَرِهْتُمْ أَنْ يَعْفُوَ عَنْهُ وَأَمَّا عَلِيٌّ فَابْنُ عَمِّ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَخَتَنُهُ وَأَشَارَ بِيَدِهِ وَهَذِهِ ابْنَتُهُ أَوْ بِنْتُهُ حَيْثُ تَرَوْنَ","id":"Telah menceritakan kepada kami [Al Hasan bin 'Abdul 'Aziz] Telah menceritakan kepada kami ['Abdullah bin Yahya] Telah menceritakan kepada kami [Haiwah] dari [Bakr bin 'Amru] dari [Bukair] dari [Nafi'] dari [Ibnu 'Umar radliallahu 'anhuma] bahwa seseorang datang kepadanya seraya berkata; 'Wahai Abu Abdurrahman, apakah anda tidak mendengar apa yang Allah sebutkan di dalam kitabnya: Dan kalau ada dua golongan dari mereka yang beriman itu berperang hendaklah kamu damaikan antara keduanya, (Al Hujurat: 9). Lalu apa yang menghalangi anda dari berperang sebagaimana yang telah Allah perintahkan? Ibnu Umar menjawab; 'Wahai anak saudaraku, apakah aku akan menipu dengan ayat ini, tidak berperang bagiku lebih aku sukai dari pada aku harus menipu dengan ayat ini. Bukankah Allah juga berfirman; Dan barangsiapa yang membunuh seorang mukmin dengan sengaja maka balasannya ialah Jahannam… (An Nisa: 93). Selanjutnya orang itu berkata; 'Sesungguhnya Allah berfirman; Dan perangilah mereka, supaya jangan ada fitnah.. (Al Anfal: 39). Ibnu Umar menjawab; 'Kami telah melaksanakannya pada masa Rasulullah shallallahu 'alaihi wasallam yaitu ketika Islam masih sedikit hingga diantara mereka agamanya terancam dan difitnah baik itu di bunuh atau pun di ikat hingga akhirnya Islam semakin besar dan tidak ada fitnah lagi. Tatkala orang itu melihat Ibnu Umar tidak setuju dengan pendapatnya, orang itu bertanya; 'Lalu apa pendapatmu mengenai Ali dan Utsman? Ibnu Umar menjawab; pendapatku tentang Ali dan Utsman; adapun Utsman ia adalah orang yang telah dimaafkan Allah, sedangkan kalian tidak mau memaafkannya. Adapun Ali, maka dia adalah putra paman Rasulullah shallallahu 'alaihi wasallam, dan menantunya -kemudian Ibnu Umar menunjuk dengan tangannya- dan inilah putrinya sebagaimana yang kamu lihat."},"3979":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ يُونُسَ حَدَّثَنَا زُهَيْرٌ حَدَّثَنَا بَيَانٌ أَنَّ وَبَرَةَ حَدَّثَهُ قَالَ حَدَّثَنِي سَعِيدُ بْنُ جُبَيْرٍ قَالَ خَرَجَ عَلَيْنَا أَوْ إِلَيْنَا ابْنُ عُمَرَفَقَالَ رَجُلٌ كَيْفَ تَرَى فِي قِتَالِ الْفِتْنَةِ فَقَالَ وَهَلْ تَدْرِي مَا الْفِتْنَةُ كَانَ مُحَمَّدٌ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُقَاتِلُ الْمُشْرِكِينَ وَكَانَ الدُّخُولُ عَلَيْهِمْ فِتْنَةً وَلَيْسَ كَقِتَالِكُمْ عَلَى الْمُلْكِ","id":"Telah menceritakan kepada kami [Ahmad bin Yunus] Telah menceritakan kepada kami [Zuhair] Telah menceritakan kepada kami [Bayan] bahwa [Wabarah] Telah menceritakan kepadanya dia berkata; Telah menceritakan kepadaku [Sa'id bin Jubair] dia berkata; [Ibnu 'Umar] keluar menemui kami, lalu seseorang bertanya; \"Bagaimana pendapatmu tentang memerangi fitnah? Ibnu Umar menjawab; 'Tahukah kamu apa yang dimaksud fitnah? ' Nabi shallallahu 'alaihi wasallam memerangi orang-orang Musyrik, dan masuk ke dalam golongan mereka adalah fitnah, bukan seperti perang kalian dalam memerangi penguasa.'"},"3980":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا سُفْيَانُ عَنْ عَمْرٍو عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَالَمَّا نَزَلَتْ{ إِنْ يَكُنْ مِنْكُمْ عِشْرُونَ صَابِرُونَ يَغْلِبُوا مِائَتَيْنِ وَإِنْ يَكُنْ مِنْكُمْ مِائَةٌ }فَكُتِبَ عَلَيْهِمْ أَنْ لَا يَفِرَّ وَاحِدٌ مِنْ عَشَرَةٍ فَقَالَ سُفْيَانُ غَيْرَ مَرَّةٍ أَنْ لَا يَفِرَّ عِشْرُونَ مِنْ مِائَتَيْنِ ثُمَّ نَزَلَتْ{ الْآنَ خَفَّفَ اللَّهُ عَنْكُمْ }الْآيَةَ فَكَتَبَ أَنْ لَا يَفِرَّ مِائَةٌ مِنْ مِائَتَيْنِ وَزَادَ سُفْيَانُ مَرَّةً نَزَلَتْ{ حَرِّضْ الْمُؤْمِنِينَ عَلَى الْقِتَالِ إِنْ يَكُنْ مِنْكُمْ عِشْرُونَ صَابِرُونَ }قَالَ سُفْيَانُ وَقَالَ ابْنُ شُبْرُمَةَ وَأُرَى الْأَمْرَ بِالْمَعْرُوفِ وَالنَّهْيَ عَنْ الْمُنْكَرِ مِثْلَ هَذَا","id":"Telah menceritakan kepada kami ['Ali bin 'Abdullah] Telah menceritakan kepada kami [Sufyan] dari ['Amru] dari [Ibnu 'Abbas radliallahu 'anhuma] tatkala turun ayat: Jika ada dua puluh orang yang sabar diantaramu, niscaya mereka akan dapat mengalahkan dua ratus orang musuh. Dan jika ada seratus orang yang sabar diantaramu, niscaya mereka akan dapat mengalahkan seribu dari pada orang kafir… (Al Anfal: 65). Maka diwajibkan kepada mereka tidak ada seorang pun yang lari dari sepuluh orang. Abu Sufyan berkali-kali mengatakan: 'Jangan sampai ada yang lari dua puluh orang dari dua ratus orang.' Kemudian turunlah ayat: Sekarang Allah telah meringankan kepadamu. (Al Anfal: 66). Maka diwajibkan jangan sampai ada yang lari sebanyak seratus orang dari dua ratus orang. Sufyan menambahkan juga; telah turun ayat; Hai Nabi, kobarkanlah semangat para mukmin untuk berperang. Jika ada dua puluh orang yang sabar diantaramu... (Al Anfal: 65). Sufyan berkata; dan Ibnu Syubrumah berkata; 'Aku melihat seperti inilah menyuruh kebaikan dan mencegah kemungkaran.'"},"3981":{"ar":"حَدَّثَنَا يَحْيَى بْنُ عَبْدِ اللَّهِ السُّلَمِيُّ أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ أَخْبَرَنَا جَرِيرُ بْنُ حَازِمٍ قَالَ أَخْبَرَنِي الزُّبَيْرُ بْنُ خِرِّيتٍ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَلَمَّا نَزَلَتْ{ إِنْ يَكُنْ مِنْكُمْ عِشْرُونَ صَابِرُونَ يَغْلِبُوا مِائَتَيْنِ }شَقَّ ذَلِكَ عَلَى الْمُسْلِمِينَ حِينَ فُرِضَ عَلَيْهِمْ أَنْ لَا يَفِرَّ وَاحِدٌ مِنْ عَشَرَةٍ فَجَاءَ التَّخْفِيفُ فَقَالَ{ الْآنَ خَفَّفَ اللَّهُ عَنْكُمْ وَعَلِمَ أَنَّ فِيكُمْ ضُعْفًا فَإِنْ يَكُنْ مِنْكُمْ مِائَةٌ صَابِرَةٌ يَغْلِبُوا مِائَتَيْنِ }قَالَ فَلَمَّا خَفَّفَ اللَّهُ عَنْهُمْ مِنْ الْعِدَّةِ نَقَصَ مِنْ الصَّبْرِ بِقَدْرِ مَا خُفِّفَ عَنْهُمْ","id":"Telah menceritakan kepada kami [Yahya bin 'Abdullah As Sulami] Telah mengabarkan kepada kami ['Abdullah bin Al Mubarak] Telah mengabarkan kepada kami [Jarir bin Hazim] dia berkata; Telah mengabarkan kepadaku [Az Zubair bin Khirrit] dari ['Ikrimah] dari [Ibnu 'Abbas radliallahu 'anhuma] dia berkata; Tatkala turun ayat: Jika ada dua puluh orang yang sabar diantaramu, niscaya mereka akan dapat mengalahkan dua ratus orang musuh. Dan jika ada seratus orang yang sabar diantaramu, niscaya mereka akan dapat mengalahkan seribu dari pada orang kafir… (Al Anfal: 65). Maka hal itu terasa berat bagi kaum muslimin, yaitu ketika diwajibkan kepada mereka tidak ada yang lari seorang pun dari sepuluh orang. Lalu datang keringanan yaitu ayat; Sekarang Allah telah meringankan kepadamu. (Al Anfal: 66). Ibnu Abbas berkata; tatkala Allah meringankan mereka dari jumlah pasukan, maka kesabaran pun menjadi berkurang sesuai keringanan yang diberikan kepada mereka."},"3982":{"ar":"حَدَّثَنَا أَبُو الْوَلِيدِ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي إِسْحَاقَ قَالَ سَمِعْتُ الْبَرَاءَ رَضِيَ اللَّهُ عَنْهُ يَقُولُآخِرُ آيَةٍ نَزَلَتْ{ يَسْتَفْتُونَكَ قُلْ اللَّهُ يُفْتِيكُمْ فِي الْكَلَالَةِ }وَآخِرُ سُورَةٍ نَزَلَتْ بَرَاءَةٌ","id":"Telah menceritakan kepada kami [Abu Al Walid] Telah menceritakan kepada kami [Syu'bah] dari [Abu Ishaq] dia berkata; Aku mendengar [Al Bara' radliallahu 'anhu] berkata; Ayat yang terakhir kali turun adalah ayat: Mereka meminta fatwa kepadamu (tentang kalalah). Katakanlah: \"Allah memberi fatwa kepadamu tentang kalalah. (An Nisa: 176). Sedangkan surat yang terakhir kali turun adalah surat Bara'ah."},"3983":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ عُفَيْرٍ قَالَ حَدَّثَنِي اللَّيْثُ قَالَ حَدَّثَنِي عُقَيْلٌ عَنْ ابْنِ شِهَابٍ وَأَخْبَرَنِي حُمَيْدُ بْنُ عَبْدِ الرَّحْمَنِ أَنَّ أَبَا هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَبَعَثَنِي أَبُو بَكْرٍ فِي تِلْكَ الْحَجَّةِ فِي مُؤَذِّنِينَ بَعَثَهُمْ يَوْمَ النَّحْرِ يُؤَذِّنُونَ بِمِنًى أَنْ لَا يَحُجَّ بَعْدَ الْعَامِ مُشْرِكٌ وَلَا يَطُوفَ بِالْبَيْتِ عُرْيَانٌ قَالَ حُمَيْدُ بْنُ عَبْدِ الرَّحْمَنِ ثُمَّ أَرْدَفَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِعَلِيِّ بْنِ أَبِي طَالِبٍ وَأَمَرَهُ أَنْ يُؤَذِّنَ بِبَرَاءَةَ قَالَ أَبُو هُرَيْرَةَ فَأَذَّنَ مَعَنَا عَلِيٌّ يَوْمَ النَّحْرِ فِي أَهْلِ مِنًى بِبَرَاءَةَ وَأَنْ لَا يَحُجَّ بَعْدَ الْعَامِ مُشْرِكٌ وَلَا يَطُوفَ بِالْبَيْتِ عُرْيَانٌ","id":"Telah menceritakan kepada kami [Sa'id bin 'Ufair] dia berkata; Telah menceritakan kepadaku [Al Laits] dia berkata; Telah menceritakan kepadaku ['Uqail] dari [Ibnu Syihab] Dan telah mengabarkan kepadaku [Humaid bin 'Abdur Rahman] bahwa [Abu Hurairah radliallahu 'anhu] berkata; Abu Bakr mengutusku pada haji tersebut, tepatnya pada hari kurban untuk mengumumkan bersama orang-orang di Mina bahwa tidak boleh orang musyrik melakukan haji setelah tahun tersebut, dan tidak boleh orang telanjang melakukan thawaf di Ka'bah.\" Kemudian Nabi shallallahu 'alaihi wasallam di bonceng oleh Ali bin Abu Thalib, lalu beliau menyuruhnya untuk mengumumkan mengenai ayat Bara'ah. Abu Hurairah berkata; Maka Ali bersama kami mengumumkan di Mina pada hari kurban mengenai ayat Bara'ah dan orang musyrik tidak boleh melakukan haji setelah tahun tersebut, dan orang telanjang tidak boleh melakukan thawaf di Ka'bah.\""},"3984":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ حَدَّثَنَا اللَّيْثُ حَدَّثَنِي عُقَيْلٌ قَالَ ابْنُ شِهَابٍ فَأَخْبَرَنِي حُمَيْدُ بْنُ عَبْدِ الرَّحْمَنِ أَنَّ أَبَا هُرَيْرَةَ قَالَبَعَثَنِي أَبُو بَكْرٍ رَضِيَ اللَّهُ عَنْهُ فِي تِلْكَ الْحَجَّةِ فِي الْمُؤَذِّنِينَ بَعَثَهُمْ يَوْمَ النَّحْرِ يُؤَذِّنُونَ بِمِنًى أَنْ لَا يَحُجَّ بَعْدَ الْعَامِ مُشْرِكٌ وَلَا يَطُوفَ بِالْبَيْتِ عُرْيَانٌ قَالَ حُمَيْدٌ ثُمَّ أَرْدَفَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِعَلِيِّ بْنِ أَبِي طَالِبٍ فَأَمَرَهُ أَنْ يُؤَذِّنَ بِبَرَاءَةَ قَالَ أَبُو هُرَيْرَةَ فَأَذَّنَ مَعَنَا عَلِيٌّ فِي أَهْلِ مِنًى يَوْمَ النَّحْرِ بِبَرَاءَةَ وَأَنْ لَا يَحُجَّ بَعْدَ الْعَامِ مُشْرِكٌ وَلَا يَطُوفَ بِالْبَيْتِ عُرْيَانٌ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] Telah menceritakan kepada kami [Al Laits] Telah menceritakan kepadaku ['Uqail] [Ibnu Syihab] berkata; Maka telah mengabarkan kepadaku [Humaid bin 'Abdur Rahman] bahwa [Abu Hurairah] berkata; Abu Bakr mengutusku pada haji tersebut, tepatnya pada hari kurban untuk mengumumkan bersama orang-orang di Mina bahwa tidak boleh orang musyrik melakukan haji setelah tahun tersebut, dan tidak boleh orang telanjang melakukan thawaf di Ka'bah.\" Kemudian Nabi shallallahu 'alaihi wasallam di bonceng oleh Ali bin Abu Thalib, lalu beliau menyuruhnya untuk mengumumkan mengenai ayat Bara'ah. Abu Hurairah berkata; Maka Ali bersama kami mengumumkan di Mina pada hari kurban mengenai ayat Bara'ah dan orang musyrik tidak boleh melakukan haji setelah tahun tersebut, dan orang telanjang tidak boleh melakukan thawaf di Ka'bah.\""},"3985":{"ar":"حَدَّثَنَا إِسْحَاقُ حَدَّثَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا أَبِي عَنْ صَالِحٍ عَنْ ابْنِ شِهَابٍ أَنَّ حُمَيْدَ بْنَ عَبْدِ الرَّحْمَنِ أَخْبَرَهُ أَنَّ أَبَا هُرَيْرَةَ أَخْبَرَهُأَنَّ أَبَا بَكْرٍ رَضِيَ اللَّهُ عَنْهُ بَعَثَهُ فِي الْحَجَّةِ الَّتِي أَمَّرَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَيْهَا قَبْلَ حَجَّةِ الْوَدَاعِ فِي رَهْطٍ يُؤَذِّنُونَ فِي النَّاسِ أَنْ لَا يَحُجَّنَّ بَعْدَ الْعَامِ مُشْرِكٌ وَلَا يَطُوفَ بِالْبَيْتِ عُرْيَانٌ فَكَانَ حُمَيْدٌ يَقُولُ يَوْمُ النَّحْرِ يَوْمُ الْحَجِّ الْأَكْبَرِ مِنْ أَجْلِ حَدِيثِ أَبِي هُرَيْرَةَ","id":"Telah menceritakan kepada kami [Ishaq] Telah menceritakan kepada kami [Ya'qub bin Ibrahim] Telah menceritakan kepada kami [Bapakku] dari [Shalih] dari [Ibnu Syihab] bahwa [Humaid bin 'Abdur Rahman] Telah mengabarkan kepadanya bahwa bahwa [Abu Hurairah] mengabarkan kepadanya, bahwasanya Abu Bakr pernah mengutusnya saat musim haji, tepatnya saat Rasulullah shallallahu 'alaihi wasallam menunjuk Abu Bakar sebagai amiirul hajj. Itu terjadi sebelum haji wada'. Abu bakar mengutus Abu Hurairah bersama beberapa orang untuk mengumumkan kepada manusia bahwa \"Tidak boleh orang musyrik melakukan haji setelah tahun tersebut, dan tidak boleh orang telanjang melakukan thawaf di Ka'bah.\" Dan Humaid berkata; Hari kurban adalah hari haji akbar menurut Hadits Abu Hurairah."},"3986":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا يَحْيَى حَدَّثَنَا إِسْمَاعِيلُ حَدَّثَنَا زَيْدُ بْنُ وَهْبٍ قَالَ كُنَّا عِنْدَ حُذَيْفَةَ فَقَالَمَا بَقِيَ مِنْ أَصْحَابِ هَذِهِ الْآيَةِ إِلَّا ثَلَاثَةٌ وَلَا مِنْ الْمُنَافِقِينَ إِلَّا أَرْبَعَةٌ فَقَالَ أَعْرَابِيٌّ إِنَّكُمْ أَصْحَابَ مُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تُخْبِرُونَا فَلَا نَدْرِي فَمَا بَالُ هَؤُلَاءِ الَّذِينَ يَبْقُرُونَ بُيُوتَنَا وَيَسْرِقُونَ أَعْلَاقَنَا قَالَ أُولَئِكَ الْفُسَّاقُ أَجَلْ لَمْ يَبْقَ مِنْهُمْ إِلَّا أَرْبَعَةٌ أَحَدُهُمْ شَيْخٌ كَبِيرٌ لَوْ شَرِبَ الْمَاءَ الْبَارِدَ لَمَا وَجَدَ بَرْدَهُ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] Telah menceritakan kepada kami [Yahya] Telah menceritakan kepada kami [Isma'il] Telah menceritakan kepada kami [Zaid bin Wahb] dia berkata; Kami pernah bersama [Hudzaifah], lalu ia berkata; Tidak tersisa orang yang di sebutkan ayat ini (At Taubah: 12) kecuali hanya tiga orang. Dan tidak tersisa dari orang munafik kecuali hanya empat orang. Seorang arab badui berkata; Kalian adalah sahabat Nabi shallallahu 'alaihi wasallam, kami tidak tahu apa yang kalian kabarkan. Lalu bagaimana dengan orang-orang yang merusak rumah-rumah kami dan mencuri perhiasan kami? Hudzaifah menjawab: mereka itu adalah orang-orang yang fasik. Ya, tidak tersisa dari mereka kecuali hanya empat orang, salah satunya seorang yang sudah tua yang seandainya dia minum air dingin tentu dia tidak akan mendapatkan rasa dinginnya."},"3987":{"ar":"حَدَّثَنَا الْحَكَمُ بْنُ نَافِعٍ أَخْبَرَنَا شُعَيْبٌ حَدَّثَنَا أَبُو الزِّنَادِ أَنَّ عَبْدَ الرَّحْمَنِ الْأَعْرَجَ حَدَّثَهُ أَنَّهُ قَالَ حَدَّثَنِي أَبُو هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ أَنَّهُسَمِعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ يَكُونُ كَنْزُ أَحَدِكُمْ يَوْمَ الْقِيَامَةِ شُجَاعًا أَقْرَعَ","id":"Telah menceritakan kepada kami [Al Hakam bin Nafi'] Telah mengabarkan kepada kami [Syu'aib] Telah menceritakan kepada kami [Abu Az Zinad] bahwa ['Abdur Rahman Al A'raj] Telah menceritakan kepadanya bahwasanya dia berkata; Telah menceritakan kepadaku [Abu Hurairah radliallahu 'anhu] bahwa dia mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: 'Pada hari kiamat harta simpanan kalian akan menjadi ular yang ganas.'"},"3988":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا جَرِيرٌ عَنْ حُصَيْنٍ عَنْ زَيْدِ بْنِ وَهْبٍ قَالَ مَرَرْتُ عَلَى أَبِي ذَرٍّبِالرَّبَذَةِ فَقُلْتُ مَا أَنْزَلَكَ بِهَذِهِ الْأَرْضِ قَالَ كُنَّا بِالشَّأْمِ فَقَرَأْتُ{ وَالَّذِينَ يَكْنِزُونَ الذَّهَبَ وَالْفِضَّةَ وَلَا يُنْفِقُونَهَا فِي سَبِيلِ اللَّهِ فَبَشِّرْهُمْ بِعَذَابٍ أَلِيمٍ }قَالَ مُعَاوِيَةُ مَا هَذِهِ فِينَا مَا هَذِهِ إِلَّا فِي أَهْلِ الْكِتَابِ قَالَ قُلْتُ إِنَّهَا لَفِينَا وَفِيهِمْ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] Telah menceritakan kepada kami [Jarir] dari [Hushain] dari [Zaid bin Wahb] dia berkata; Aku melewati [Abu Dzar] ketika dia berada di Rabadzah. Maka aku bertanya kepadanya; Apa yang menyebabkan kamu berada di sini? Dia menjawab; Ketika aku berada di Syam, aku membaca ayat; Dan orang-orang yang menyimpan emas dan perak dan tidak menafkahkannya pada jalan Allah, maka beritahukanlah kepada mereka, (bahwa mereka akan mendapat) siksa yang pedih. (At Taubah: 34). Mu'awiyah berkata; Ayat ini bukan berkenaan dengan kita, tetapi ayat ini berkenaan dengan Ahlu kitab. Abu Dzar berkata; maka aku katakan kepadanya bahwa ayat ini berkenaan dengan kita dan mereka."},"3989":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عَبْدِ الْوَهَّابِ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ أَيُّوبَ عَنْ مُحَمَّدٍ عَنْ ابْنِ أَبِي بَكْرَةَ عَنْ أَبِي بَكْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ الزَّمَانَ قَدْ اسْتَدَارَ كَهَيْئَتِهِ يَوْمَ خَلَقَ اللَّهُ السَّمَوَاتِ وَالْأَرْضَ السَّنَةُ اثْنَا عَشَرَ شَهْرًا مِنْهَا أَرْبَعَةٌ حُرُمٌ ثَلَاثٌ مُتَوَالِيَاتٌ ذُو الْقَعْدَةِ وَذُو الْحِجَّةِ وَالْمُحَرَّمُ وَرَجَبُ مُضَرَ الَّذِي بَيْنَ جُمَادَى وَشَعْبَانَ","id":"Telah menceritakan kepada kami ['Abdullah bin 'Abdul Wahhab] Telah menceritakan kepada kami [Hammad bin Zaid] dari [Ayyub] dari [Muhammad] dari [Ibnu Abu Bakrah] dari [Abu Bakrah] dari Nabi shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya waktu telah berputar sebagaimana mestinya, hal itu ditetapkan pada hari Allah menciptakan langit dan bumi. Dalam setahun ada dua belas bulan, diantaranya ada empat bulan yang mulia. Tiga darinya berturut-turut, yaitu Dzul Qa'dah, Dzul Hijjah, Muharram, dan Rajab yang biasa diagungkan Bani Mudlar yaitu antara Jumadil tsani dan Sya'ban.'"},"3990":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ حَدَّثَنَا حَبَّانُ حَدَّثَنَا هَمَّامٌ حَدَّثَنَا ثَابِتٌ حَدَّثَنَا أَنَسٌ قَالَ حَدَّثَنِي أَبُو بَكْرٍ رَضِيَ اللَّهُ عَنْهُ قَالَكُنْتُ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الْغَارِ فَرَأَيْتُ آثَارَ الْمُشْرِكِينَ قُلْتُ يَا رَسُولَ اللَّهِ لَوْ أَنَّ أَحَدَهُمْ رَفَعَ قَدَمَهُ رَآنَا قَالَ مَا ظَنُّكَ بِاثْنَيْنِ اللَّهُ ثَالِثُهُمَا","id":"Telah menceritakan kepada kami ['Abdullah bin Muhammad] Telah menceritakan kepada kami [Habban] Telah menceritakan kepada kami [Hammam] Telah menceritakan kepada kami [Tsabit] Telah menceritakan kepada kami [Anas] dia berkata; Telah menceritakan kepadaku [Abu Bakr radliallahu 'anhu] dia berkata; Aku pernah bersama Nabi shallallahu 'alaihi wasallam di Gua Hira, lalu aku melihat jejak-jejak orang Musyrikin. Maka aku berkata; Ya Rasulullah, seandainya salah seorang dari mereka mengangkat kakinya tentu dia akan melihat kita. Nabi shallallahu 'alaihi wasallam bersabda: \"Tidakkah engkau beranggapan jika ada dua orang, maka Allah lah yang ketiganya?.\""},"3991":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ حَدَّثَنَا ابْنُ عُيَيْنَةَ عَنْ ابْنِ جُرَيْجٍ عَنْ ابْنِ أَبِي مُلَيْكَةَ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَ��أَنَّهُ قَالَ حِينَ وَقَعَ بَيْنَهُ وَبَيْنَ ابْنِ الزُّبَيْرِ قُلْتُ أَبُوهُ الزُّبَيْرُ وَأُمُّهُ أَسْمَاءُ وَخَالَتُهُ عَائِشَةُ وَجَدُّهُ أَبُو بَكْرٍ وَجَدَّتُهُ صَفِيَّةُفَقُلْتُ لِسُفْيَانَ إِسْنَادُهُ فَقَالَ حَدَّثَنَا فَشَغَلَهُ إِنْسَانٌ وَلَمْ يَقُلْ ابْنُ جُرَيْجٍ","id":"Telah menceritakan kepada kami ['Abdullah bin Muhammad] Telah menceritakan kepada kami [Ibnu 'Uyainah] dari [Ibnu Juraij] dari [Ibnu Abu Mulaikah] dari [Ibnu 'Abbas radliallahu 'anhuma] bahwasanya dia berkata ketika terjadi perselisihan antara dia dengan Ibnu Jubair. Aku berkata; Bapaknya adalah Az Zubair, Ibunya adalah Asma' bibinya adalah Aisyah, kakeknya adalah Abu Bakr, sedangkan neneknya adalah Shafiyyah. Aku berkata kepada Sufyan mengenai sanadnya. Dia berkata; Ibnu Jubair telah menceritakan kepada kami, namun tiba-tiba dia di sibukkan oleh orang lain, dan dia tidak menyebutkan Ibnu Juraij."},"3992":{"ar":"حَدَّثَنِي عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ قَالَ حَدَّثَنِي يَحْيَى بْنُ مَعِينٍ حَدَّثَنَا حَجَّاجٌ قَالَ ابْنُ جُرَيْجٍ قَالَ ابْنُ أَبِي مُلَيْكَةَ وَكَانَ بَيْنَهُمَا شَيْءٌ فَغَدَوْتُ عَلَى ابْنِ عَبَّاسٍفَقُلْتُ أَتُرِيدُ أَنْ تُقَاتِلَ ابْنَ الزُّبَيْرِ فَتُحِلَّ حَرَمَ اللَّهِ فَقَالَ مَعَاذَ اللَّهِ إِنَّ اللَّهَ كَتَبَ ابْنَ الزُّبَيْرِ وَبَنِي أُمَيَّةَ مُحِلِّينَ وَإِنِّي وَاللَّهِ لَا أُحِلُّهُ أَبَدًا قَالَ قَالَ النَّاسُ بَايِعْ لِابْنِ الزُّبَيْرِ فَقُلْتُ وَأَيْنَ بِهَذَا الْأَمْرِ عَنْهُ أَمَّا أَبُوهُ فَحَوَارِيُّ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُرِيدُ الزُّبَيْرَ وَأَمَّا جَدُّهُ فَصَاحِبُ الْغَارِ يُرِيدُ أَبَا بَكْرٍ وَأُمُّهُ فَذَاتُ النِّطَاقِ يُرِيدُ أَسْمَاءَ وَأَمَّا خَالَتُهُ فَأُمُّ الْمُؤْمِنِينَ يُرِيدُ عَائِشَةَ وَأَمَّا عَمَّتُهُ فَزَوْجُ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُرِيدُ خَدِيجَةَ وَأَمَّا عَمَّةُ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَجَدَّتُهُ يُرِيدُ صَفِيَّةَ ثُمَّ عَفِيفٌ فِي الْإِسْلَامِ قَارِئٌ لِلْقُرْآنِ وَاللَّهِ إِنْ وَصَلُونِي وَصَلُونِي مِنْ قَرِيبٍ وَإِنْ رَبُّونِي رَبُّونِي أَكْفَاءٌ كِرَامٌ فَآثَرَ التُّوَيْتَاتِ وَالْأُسَامَاتِ وَالْحُمَيْدَاتِ يُرِيدُ أَبْطُنًا مِنْ بَنِي أَسَدٍ بَنِي تُوَيْتٍ وَبَنِي أُسَامَةَ وَبَنِي أَسَدٍ إِنَّ ابْنَ أَبِي الْعَاصِ بَرَزَ يَمْشِي الْقُدَمِيَّةَ يَعْنِي عَبْدَ الْمَلِكِ بْنَ مَرْوَانَ وَإِنَّهُ لَوَّى ذَنَبَهُ يَعْنِي ابْنَ الزُّبَيْرِ","id":"Telah menceritakan kepadaku [Abdullah bin Muhammad] dia berkata; Telah menceritakan kepadaku [Yahya bin Ma'in] Telah menceritakan kepada kami [Hajjaj] dia berkata; [Ibnu Juraij] berkata; [Ibnu Mulaikah] berkata ketika terjadi perselisihan antara Ibnu Abbas dan Ibnu Zubair; Maka aku pun pergi menemui Ibnu Abbas seraya aku katakan kepadanya; Apakah kamu ingin memerangi Ibnu Zubair yang berarti kamu telah menghalalkan apa yang Allah haramkan? [Ibnu Abbas] berkata; Aku berlindung kepada Allah, sesungguhnya Allah telah mencatat Ibnu Zubair dan Bani Umayyah sebagai orang yang termasuk menghalalkan perang. Dan demi Allah, sesungguhnya aku tidak pernah menghalalkannya sama sekali. Maka orang-orang pun berkata; 'Bai'atlah Ibnu Zubair. Ibnu Mulaikah berkata; siapa lagi kalau bukan dia? Sesungguhnya bapaknya adalah Hawari (penolong) Rasulullah shallallahu 'alaihi wasallam (yaitu Zubair). Kakeknya adalah teman Rasulullah shallallahu 'alaihi wasallam di gua Hira (yaitu Abu Bakr), Ibunya adalah pemilik dua ikat pinggang (yaitu Asma), bibinya adalah Ummul Mukminin (yaitu Aisyah), juga bibinya pula istri Rasulullah shallallahu 'alaihi wasallam (yaitu Khadijah), neneknya adalah Shafiyyah, Ibnu Zubair adalah orang yang mempunyai harga diri dalam Islam, penghafal Qur'an, demi Allah jika aku sambungkan kekerabatannya denganku tentu akan menyambung, dan jika mereka mendidikku, tentu merekalah sebaik-baik orang yang telah mendidikku dengan kemuliaan. Maka sungguh mereka adalah sebaik-baik teladan dari Tautiyat, Usamaat, Humaidaat. Yang dia maksudkan adalah keturunan dari Kabilah bani Asad, bani Tuwait, dan bani Usamah. Sesungguhnya putra Abu Al 'Ash dia nampak berjalan mencari kemuliaan, yaitu Al Malik bin Marwan. Dan dia telah memuji kesalahannya, (yaitu Ibnu Jubair)."},"3993":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عُبَيْدِ بْنِ مَيْمُونٍ حَدَّثَنَا عِيسَى بْنُ يُونُسَ عَنْ عُمَرَ بْنِ سَعِيدٍ قَالَ أَخْبَرَنِي ابْنُ أَبِي مُلَيْكَةَ دَخَلْنَا عَلَى ابْنِ عَبَّاسٍفَقَالَ أَلَا تَعْجَبُونَ لِابْنِ الزُّبَيْرِ قَامَ فِي أَمْرِهِ هَذَا فَقُلْتُ لَأُحَاسِبَنَّ نَفْسِي لَهُ مَا حَاسَبْتُهَا لِأَبِي بَكْرٍ وَلَا لِعُمَرَ وَلَهُمَا كَانَا أَوْلَى بِكُلِّ خَيْرٍ مِنْهُ وَقُلْتُ ابْنُ عَمَّةِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَابْنُ الزُّبَيْرِ وَابْنُ أَبِي بَكْرٍ وَابْنُ أَخِي خَدِيجَةَ وَابْنُ أُخْتِ عَائِشَةَ فَإِذَا هُوَ يَتَعَلَّى عَنِّي وَلَا يُرِيدُ ذَلِكَ فَقُلْتُ مَا كُنْتُ أَظُنُّ أَنِّي أَعْرِضُ هَذَا مِنْ نَفْسِي فَيَدَعُهُ وَمَا أُرَاهُ يُرِيدُ خَيْرًا وَإِنْ كَانَ لَا بُدَّ لَأَنْ يَرُبَّنِي بَنُو عَمِّي أَحَبُّ إِلَيَّ مِنْ أَنْ يَرُبَّنِي غَيْرُهُمْ","id":"Telah menceritakan kepada kami [Muhammad bin 'Ubaid bin Maimun] Telah menceritakan kepada kami ['Isa bin Yunus] dari [Umar bin Sa'id] dia berkata; Telah mengabarkan kepadaku [Ibnu Abu Mulaikah] kami menemui [Ibnu 'Abbas] lalu dia berkata; 'Apakah kalian heran dengan sikap Ibnu Zubair dalam memegang urusannya ini. Maka aku menjawab; Aku akan menyikapinya sebagaimana aku menyikapi Abu Bakar, bukan Umar. Walaupun tentu keduanya lebih utama darinya. Juga aku pun berkata; Ibnu Zubair adalah anak bibi Nabi shallallahu 'alaihi wasallam, putra Zubair, putra Abu Bakr, putra saudara Khadijah, putra saudari Aisyah. Namun Ibnu Abbas malah bangkit menjauh dariku, dia tidak menginginkanku berlebih-lebihan memuji-muji Ibnu Zubair. Maka aku berkata; Aku mengira bahwa aku tidak bisa memalingkan perasaanku ini. Lalu Ibnu Abbas meninggalkannya. Aku lihat tidaklah dia melakukan hal itu kecuali demi kebaikan. Kalaulah aku harus dipimpin oleh Bani Umayyah tentu itu lebih aku sukai dari pada aku dipimpin oleh selain mereka."},"3994":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ أَخْبَرَنَا سُفْيَانُ عَنْ أَبِيهِ عَنْ ابْنِ أَبِي نُعْمٍ عَنْ أَبِي سَعِيدٍ رَضِيَ اللَّهُ عَنْهُ قَالَبُعِثَ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِشَيْءٍ فَقَسَمَهُ بَيْنَ أَرْبَعَةٍ وَقَالَ أَتَأَلَّفُهُمْ فَقَالَ رَجُلٌ مَا عَدَلْتَ فَقَالَ يَخْرُجُ مِنْ ضِئْضِئِ هَذَا قَوْمٌ يَمْرُقُونَ مِنْ الدِّينِ","id":"Telah menceritakan kepada kami [Muhammad bin Katsir] Telah mengabarkan kepada kami [Sufyan] dari [Bapaknya] dari [Ibnu Abu Nu'm] dari [Abu Sa'id radliallahu 'anhu] dia berkata; Beberapa sedekah dikirimkan kepada Nabi shallallahu 'alaihi wasallam lalu beliau membagikannya kepada empat orang seraya berkata; Aku ingin melunakan hati mereka. Seseorang bertanya: 'Engkau tidak adil.' Maka Nabi shallallahu 'alaihi wasallam bersabda: \"Akan datang dari keturunanku suatu kaum, mereka melepaskan din mereka.\""},"3995":{"ar":"حَدَّثَنِي بِشْرُ بْنُ خَالِدٍ أَبُو مُحَمَّدٍ أَخْبَرَنَا مُحَمَّدُ بْنُ جَعْفَرٍ عَنْ شُعْبَةَ عَنْ سُلَيْمَانَ عَنْ أَبِي وَائِلٍ عَنْ أَبِي مَسْعُودٍ قَالَلَمَّا أُمِرْنَا بِالصَّدَقَةِ كُنَّا نَتَحَامَلُ فَجَاءَ أَبُو عَقِيلٍ بِنِصْفِ صَاعٍ وَجَاءَ إِنْسَانٌ بِأَكْثَرَ مِنْهُ فَقَالَ الْمُنَافِقُونَ إِنَّ اللَّهَ لَغَنِيٌّ عَنْ صَدَقَةِ هَذَا وَمَا فَعَلَ هَذَا الْآخَرُ إِلَّا رِئَاءً فَنَزَلَتْ{ الَّذِينَ يَلْمِزُونَ الْمُطَّوِّعِينَ مِنْ الْمُؤْمِنِينَ فِي الصَّدَقَاتِ وَالَّذِينَ لَا يَجِدُونَ إِلَّا جُهْدَهُمْ }الْآيَةَ","id":"Telah menceritakan kepadaku [Bisyr bin Khalid Abu Muhammad]; Telah mengabarkan kepada kami [Muhammad bin Ja'far] dari [Syu'bah] dari [Sulaiman] dari [Abu Wail] dari [Abu Mas'ud] dia berkata; Setelah Rasulullah Shalallahu 'Alaihi Wa Sallam memerintahkan kami untuk bersedekah, maka kami saling membawakan sedekah tersebut agar kami mendapatkan pahala darinya, lalu Abu Uqail bersedekah dengan setengah sha', kemudian datang seseorang dengan membawa lebih banyak dari itu, lalu orang-orang munafik berkata; \" Allah Azza Wa Jalla benar-benar tidak membutuhkan sedekah orang ini, orang ini tidak melakukannya kecuali dengan riya'. Lalu turun ayat: 'Orang-orang munafik itu yaitu orang-orang yang mencela orang-orang mukmin yang memberi sedekah dengan sukarela dan (mencela) orang-orang yang tidak memperoleh (untuk disedekahkan) selain sekadar kesanggupannya.\" (Qs. At Taubah: 79)."},"3996":{"ar":"حَدَّثَنَا إِسْحَاقُ بْنُ إِبْرَاهِيمَ قَالَ قُلْتُ لِأَبِي أُسَامَةَ أَحَدَّثَكُمْ زَائِدَةُ عَنْ سُلَيْمَانَ عَنْ شَقِيقٍ عَنْ أَبِي مَسْعُودٍ الْأَنْصَارِيِّ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَأْمُرُ بِالصَّدَقَةِ فَيَحْتَالُ أَحَدُنَا حَتَّى يَجِيءَ بِالْمُدِّ وَإِنَّ لِأَحَدِهِمْ الْيَوْمَ مِائَةَ أَلْفٍ كَأَنَّهُ يُعَرِّضُ بِنَفْسِهِ","id":"Telah menceritakan kepada kami [Ishaq bin Ibrahim] dia berkata; aku berkata kepada [Abu Usamah] Aku ceritakan kepadamu dari [Zaidah] dari [Sulaiman] dari [Syaqiq] dari [Abu Mas'ud Al Anshari] dia berkata; \"Rasulullah Shalallahu 'Alaihi Wa Sallam pernah memerintahkan kami untuk bersedekah, maka salah seorang dari kami berusaha mencari sesuatu yang bisa disedekahkan, hingga ia datang dengan membawa satu mud -hasil kerja kerasnya- yang ia berikan kepada Rasulullah Shalallahu 'Alaihi Wa Sallam. Sungguh sekarang aku mengetahui seseorang yang memiliki seratus ribu, seakan-akan dia telah menawarkan dirinya sendiri."},"3997":{"ar":"حَدَّثَنِي عُبَيْدُ بْنُ إِسْمَاعِيلَ عَنْ أَبِي أُسَامَةَ عَنْ عُبَيْدِ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا قَالَلَمَّا تُوُفِّيَ عَبْدُ اللَّهِ بْنُ أُبَيٍّ جَاءَ ابْنُهُ عَبْدُ اللَّهِ بْنُ عَبْدِ اللَّهِ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَأَلَهُ أَنْ يُعْطِيَهُ قَمِيصَهُ يُكَفِّنُ فِيهِ أَبَاهُ فَأَعْطَاهُ ثُمَّ سَأَلَهُ أَنْ يُصَلِّيَ عَلَيْهِ فَقَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِيُصَلِّيَ عَلَيْهِ فَقَامَ عُمَرُ فَأَخَذَ بِثَوْبِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ تُصَلِّي عَلَيْهِ وَقَدْ نَهَاكَ رَبُّكَ أَنْ تُصَلِّيَ عَلَيْهِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّمَا خَيَّرَنِي اللَّهُ فَقَالَ{ اسْتَغْفِرْ لَهُمْ أَوْ لَا تَسْتَغْفِرْ لَهُمْ إِنْ تَسْتَغْفِرْ لَهُمْ سَبْعِينَ مَرَّةً }وَسَأَزِيدُهُ عَلَى السَّبْعِينَ قَالَ إِنَّهُ مُنَافِقٌ قَالَ فَصَلَّى عَلَيْهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَنْزَلَ اللَّهُ{ وَلَا تُصَلِّ عَلَى أَحَدٍ مِنْهُمْ مَاتَ أَبَدًا وَلَا تَقُمْ عَلَى قَبْرِهِ }","id":"Telah menceritakan kepadaku ['Ubaid bin Isma'il] dari [Abu Usamah] dari ['Ubaidullah] dari [Nafi'] dari [Ibnu 'Umar radliallahu 'anhuma] dia berkata; \"Ketika Abdullah bin Ubay meninggal dunia. anak laki-lakinya -yaitu Abdulah bin Abdullah- datang kepada Rasulullah shallallahu 'alaihi wasallam seraya memohon kepada beIiau agar sudi memberikan baju beliau kepada Abdullah untuk kain kafan ayahnya, Abdullah bin Ubay bin Salul. Lalu Rasulullah shallallahu 'alaihi wasallam memberikan bajunya kepada Abdullah. setelah itu, Abdullah juga memohon Rasulullah agar beliau berkenan menshalati jenazah ayahnya. Kemudian Rasulullah pun bersiap-siap untuk menshalati jenazah Abdullah bin Ubay, hingga akhirnya Umar berdiri dan menarik baju Rasulullah seraya berkata, \"Ya Rasulullah, apakah engkau akan menshalati jenazah Abdullah bin Ubay sedangkan Allah telah melarang untuk menshalatinya?\" Rasulullah shallallahu 'alaihi wasallam menjawab: \"Sesungguhnya Allah Subhanahu wa Ta'ala telah memberikan pilihan kepadaku.\" Lalu beliau membacakan ayat yang berbunyi; \"Kamu memohonkun ampun bagi orang-orang munafik atau tidak kamu mohonkan ampun bagi mereka, maka hal itu adalah sama saja. sekalipun kamu memohonkan ampun bagi mereka tujuh puluh kali (Qs. At-Taubah 9: 80). Oleh karena itu, aku akan menambah istighfar lebih dari tujuh puluh kali untuknya.\" Umar bin Khaththab berkata, \"Ya Rasulullah, sesungguhnya Ia adalah orang munafik?.\" Tetapi, rupanya Rasulullah shallallahu 'alaihi wasallam tetap saja menshalatinya, hingga Allah menurunkan ayat Al Qur'an: \"Janganlah kamu sekali-kali menshalati jenazah seorang di antara orang-orang munafik dan janganlah kamu berdiri di atas kuburnya.\" (Qs. At-Taubah 9: 84)."},"3998":{"ar":"حَدَّثَنَا يَحْيَى بْنُ بُكَيْرٍ حَدَّثَنَا اللَّيْثُ عَنْ عُقَيْلٍ و قَالَ غَيْرُهُ حَدَّثَنِي اللَّيْثُ حَدَّثَنِي عُقَيْلٌ عَنْ ابْنِ شِهَابٍ قَالَ أَخْبَرَنِي عُبَيْدُ اللَّهِ بْنُ عَبْدِ اللَّهِ عَنْ ابْنِ عَبَّاسٍ عَنْ عُمَرَ بْنِ الْخَطَّابِ رَضِيَ اللَّهُ عَنْهُأَنَّهُ قَالَ لَمَّا مَاتَ عَبْدُ اللَّهِ بْنُ أُبَيٍّ ابْنُ سَلُولَ دُعِيَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِيُصَلِّيَ عَلَيْهِ فَلَمَّا قَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَثَبْتُ إِلَيْهِ فَقُلْتُ يَا رَسُولَ اللَّهِ أَتُصَلِّي عَلَى ابْنِ أُبَيٍّ وَقَدْ قَالَ يَوْمَ كَذَا كَذَا وَكَذَا قَالَ أُعَدِّدُ عَلَيْهِ قَوْلَهُ فَتَبَسَّمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَالَ أَخِّرْ عَنِّي يَا عُمَرُ فَلَمَّا أَكْثَرْتُ عَلَيْهِ قَالَ إِنِّي خُيِّرْتُ فَاخْتَرْتُ لَوْ أَعْلَمُ أَنِّي إِنْ زِدْتُ عَلَى السَّبْعِينَ يُغْفَرْ لَهُ لَزِدْتُ عَلَيْهَا قَالَ فَصَلَّى عَلَيْهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ انْصَرَفَ فَلَمْ يَمْكُثْ إِلَّا يَسِيرًا حَتَّى نَزَلَتْ الْآيَتَانِ مِنْ بَرَاءَةَ{ وَلَا تُصَلِّ عَلَى أَحَدٍ مِنْهُمْ مَاتَ أَبَدًا إِلَى قَوْلِهِ وَهُمْ فَاسِقُونَ }قَالَ فَعَجِبْتُ بَعْدُ مِنْ جُرْأَتِي عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَاللَّهُ وَرَسُولُهُ أَعْلَمُ","id":"Telah menceritakan kepada kami [Yahya bin Bukair] Telah menceritakan kepada kami [Al Laits] dari ['Uqail]. -dan yang lainnya berkata- Telah menceritakan kepadaku Al Laits Telah menceritakan kepadaku Uqail dari [Ibnu Syihab] dia berkata; Telah mengabarkan kepadaku ['Ubaidullah bin 'Abdullah] dari [Ibnu 'Abbas] dari ['Umar bin Al Khaththab radliallahu 'anhu] Tatkala Abdullah bin Ubai bin Salul meninggal dunia, Rasulullah shallallahu 'alaihi wasallam diundang untuk menshalatinya. Setelah Rasulullah shallallahu 'alaihi wasallam berdiri untuk melaksanakan Shalat, aku meloncat ke arah beliau, lalu aku berkata, \"Wahai Rasulullah shallallahu 'alaihi wasallam, kenapa engkau menshalati Ibnu Ubay, padahal ia telah mengatakan di hari ini-itu begini dan begitu?! Aku hitung-hitung kejelekannya, Rasulullah shallallahu 'alaihi wasallam tersenyum seraya bersabda: \"Tundalah -perkataanmu- dariku wahai Umar!\" setelah aku mengulang menyebut-nyebut kejelekannya, beliau bersabda: \" Aku telah diberikan pilihan, aku memilih. Andaikata aku tahu kalau aku menambahnya lebih dari tujuh puluh ia akan diampuni, niscaya aku menambahnya!.\"Lalu Rasulullah shallallahu 'alaihi wasallam melaksanakan shalat atasnya, kemudian beliau pergi dan tidak berada di tempat itu kecuali hanya sejenak, hingga turun dua ayat dari surah Bara'ah, \"(Dan janganlah kamu sekali-kali menshalatkan (jenazah) seorang yang mati di antara mereka, dan janganlah kamu berdiri (mendo'akan) di kuburnya. mereka telah kafir kepada Allah dan RasulNya dan mereka mati dalam keadaan fasik.\" (Qs. At-Taubah: 84). Setelah itu aku heran atas keberanianku terhadap Rasulullah shallallahu 'alaihi wasallam ketika itu. Dan hanya Allah dan Rasul-Nya yang lebih mengatahui.\""},"3999":{"ar":"حَدَّثَنِي إِبْرَاهِيمُ بْنُ الْمُنْذِرِ حَدَّثَنَا أَنَسُ بْنُ عِيَاضٍ عَنْ عُبَيْدِ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاأَنَّهُ قَالَ لَمَّا تُوُفِّيَ عَبْدُ اللَّهِ بْنُ أُبَيٍّ جَاءَ ابْنُهُ عَبْدُ اللَّهِ بْنُ عَبْدِ اللَّهِ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَعْطَاهُ قَمِيصَهُ وَأَمَرَهُ أَنْ يُكَفِّنَهُ فِيهِ ثُمَّ قَامَ يُصَلِّي عَلَيْهِ فَأَخَذَ عُمَرُ بْنُ الْخَطَّابِ بِثَوْبِهِ فَقَالَ تُصَلِّي عَلَيْهِ وَهُوَ مُنَافِقٌ وَقَدْ نَهَاكَ اللَّهُ أَنْ تَسْتَغْفِرَ لَهُمْ قَالَ إِنَّمَا خَيَّرَنِي اللَّهُ أَوْ أَخْبَرَنِي اللَّهُ فَقَالَ{ اسْتَغْفِرْ لَهُمْ أَوْ لَا تَسْتَغْفِرْ لَهُمْ إِنْ تَسْتَغْفِرْ لَهُمْ سَبْعِينَ مَرَّةً فَلَنْ يَغْفِرَ اللَّهُ لَهُمْ }فَقَالَ سَأَزِيدُهُ عَلَى سَبْعِينَ قَالَ فَصَلَّى عَلَيْهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَصَلَّيْنَا مَعَهُ ثُمَّ أَنْزَلَ اللَّهُ عَلَيْهِ{ وَلَا تُصَلِّ عَلَى أَحَدٍ مِنْهُمْ مَاتَ أَبَدًا وَلَا تَقُمْ عَلَى قَبْرِهِ إِنَّهُمْ كَفَرُوا بِاللَّهِ وَرَسُولِهِ وَمَاتُوا وَهُمْ فَاسِقُونَ }","id":"Telah menceritakan kepadaku [Ibrahim bin Al Mundzir] Telah menceritakan kepada kami [Anas bin 'Iyadl] dari ['Ubaidillah] dari [Nafi'] dari [Ibnu 'Umar radliallahu 'anhuma] dia berkata; \"Ketika Abdullah bin Ubay meninggal dunia. anak laki-lakinya -yaitu Abdulah bin Abdullah- datang kepada Rasulullah shallallahu 'alaihi wasallam dan beliau berikan bajunya dan beliau perintahkannya untuk mengafani ayahnya dengan bajunya tersebut. Lalu Rasulullah shallallahu 'alaihi wasallam menshalati jenazah ayah Abdullah bin Abdullah bin Ubbay. Hingga akhirnya Umar menarik baju Rasulullah seraya berkata; \"Ya Rasulullah, apakah engkau akan menshalati jenazah Abdullah bin Ubay sedangkan dia itu orang munafik? Padahal Allah telah melarang engkau memintakan ampun untuknya?\" Rasulullah shallallahu 'alaihi wasallam menjawab: \"Sesungguhnya Allah Subhanahu wa Ta'ala telah memberikan pilihan kepadaku atau mengabariku.\" Lalu beliau membacakan ayat yang berbunyi; \"Kamu memohonkun ampun bagi orang-orang munafik atau tidak kamu mohonkan ampun bagi mereka, maka hal itu adalah sama saja. sekalipun kamu memohonkan ampun bagi mereka tujuh puluh kali sekali-kali Allah tidak akan mengampuni mereka (Qs. At-Taubah 9: 80). Rasulullah shallallahu 'alaihi wasallam bersabda: Aku akan menambah istighfar lebih dari tujuh puluh kali untuknya.\" Maka Rasulullah shallallahu 'alaihi wasallam tetap saja menshalatinya dan kami pun shalat bersamanya hingga Allah menurunkan ayat Al Qur'an: \"Janganlah kamu sekali-kali menshalati jenazah seorang di antara orang-orang munafik dan janganlah kamu berdiri di atas kuburnya, sesungguhnya mereka telah kafir kepada Allah dan Rasul-Nya dan mereka mati dalam keadaan munafiq.\" (Qs. At-Taubah 9: 84)."},"4000":{"ar":"حَدَّثَنَا يَحْيَى حَدَّثَنَا اللَّيْثُ عَنْ عُقَيْلٍ عَنْ ابْنِ شِهَابٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ عَبْدِ اللَّهِ أَنَّ عَبْدَ اللَّهِ بْنَ كَعْبِ بْنِ مَالِكٍ قَالَ سَمِعْتُ كَعْبَ بْنَ مَالِكٍحِينَ تَخَلَّفَ عَنْ تَبُوكَ وَاللَّهِ مَا أَنْعَمَ اللَّهُ عَلَيَّ مِنْ نِعْمَةٍ بَعْدَ إِذْ هَدَانِي أَعْظَمَ مِنْ صِدْقِي رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ لَا أَكُونَ كَذَبْتُهُ فَأَهْلِكَ كَمَا هَلَكَ الَّذِينَ كَذَبُوا حِينَ أُنْزِلَ الْوَحْيُ{ سَيَحْلِفُونَ بِاللَّهِ لَكُمْ إِذَا انْقَلَبْتُمْ إِلَيْهِمْ إِلَى قَوْلِهِ الْفَاسِقِينَ }","id":"Telah menceritakan kepada kami [Yahya] Telah menceritakan kepada kami [Al Laits] dari ['Uqail] dari [Ibnu Syihab] dari ['Abdur Rahman bin 'Abdullah] sesungguhnya [Abdullah bin Ka'ab bin Malik] berkata; Aku mendengar [Ka'ab bin Malik] ketika dia tertinggal dari perang Tabuk; 'Demi Allah, tidak ada nikmat yang telah di berikan Allah kepada saya, setelah Allah menunjukan kepada saya Islam, yang saya anggap lebih besar daripada kejujuranku kepada Rasulullah shallallahu 'alaihi wasallam, Seandainya saya berdusta kepada beliau, maka saya akan celaka sebagaimana orang-orang yang telah berdusta ketika diturunkan wahyu yang berbunyi: 'Kelak mereka akan bersumpah kepadamu dengan nama Allah apabila kamu kembali kepada mereka supaya kamu berpaling dari mereka. Maka berpalinglah kamu dari mereka, karena sesungguhnya mereka itu najis dan tempat mereka adalah jahannam sebagai balasan dari apa yang telah mereka kerjakan. Mereka akan bersumpah kepadamu supaya kamu ridla kepada mereka, maka sesungguhnya Allah tidak ridla kepada orang-orang yang fasik itu.' (Qs. At-taubah (9): 95-96)."}};
